/* ---- Atributos derivados del tipo (ÚNICA fuente de verdad) ----
   Los atributos que un producto pide al venderse dependen SOLO de su tipo.
   No hay override manual: un granizado (pedido) jamás puede pedir salsa/figura.
   momo → sabor+salsa+figura · combo → sabor+salsa · pedido → ninguno. */
function atributosDeTipo(tipo) {
  if (tipo === "pedido") return [];
  if (tipo === "combo") return ["sabor", "salsa"];
  return ["sabor", "salsa", "figura"]; // momo
}
const ATRIBUTO_LABEL = { sabor: "Sabor", salsa: "Salsa", figura: "Figura" };

/* ---- Migraciones entre versiones (no se pierden datos del usuario) ---- */
function normalizeDbShape(d) {
  const s = seedDb();
  const arrayTables = [
    "orders", "order_items", "customers", "products", "production_batches",
    "inventory_items", "inventory_lots", "inventory_movements", "deliveries", "evidences", "claims",
    "benefits", "audit_logs", "production_suggestions", "recipes", "inventory_reservations",
    "users", "campaigns", "creatives", "content_calendar", "creative_results", "content_distributions", "distributionConnectorJobs",
    "brandMediaAssets", "creativeGenerationJobs", "brandMediaUsages", "agencyIntegrations", "creativeConnectorRuns", "agencyMetaConnectorDryRuns",
    "agencyMotionPlans", "agencyMotionRecipes", "agencyMotionObservations", "agencySceneQualityReviews", "agencyPostproductionPackages", "agencyPostproductionExports", "agencyPostproductionWorkers", "agencyPostproductionAudioBindings",
    "agencyBrandGateBindings", "agencyMasterReleases", "agencyMasterReleaseEvents",
    "marketing_ideas", "marketing_guiones", "marketing_mensajes", "marketing_tasks",
  ];
  arrayTables.forEach((k) => {
    if (!Array.isArray(d[k])) d[k] = s[k] || [];
  });
  d.products.forEach((p) => { p.atributos = atributosDeTipo(p.tipo); }); // siempre derivado del tipo; sin override manual
  // Combos reales: cada momo tiene especie (gato/perro). El stock vive a nivel especie; backfill por nombre.
  d.products.forEach((p) => { if (p.tipo === "momo" && p.especie !== "perro" && p.especie !== "gato") p.especie = /perr/i.test(p.nombre || "") ? "perro" : "gato"; });
  d.order_items.forEach((i) => { if (!Array.isArray(i.adiciones)) i.adiciones = []; }); // toppings por línea (retro-compat)
  if (!d.brand_library || typeof d.brand_library !== "object" || Array.isArray(d.brand_library)) {
    d.brand_library = cloneDb(s.brand_library);
  } else {
    d.brand_library = { ...cloneDb(s.brand_library), ...d.brand_library };
    ["frases", "tono", "palabrasSi", "palabrasNo"].forEach((k) => {
      if (!Array.isArray(d.brand_library[k])) d.brand_library[k] = cloneDb(s.brand_library[k] || []);
    });
  }
  if (!d.settings || typeof d.settings !== "object" || Array.isArray(d.settings)) {
    d.settings = cloneDb(s.settings);
  } else {
    d.settings = {
      ...cloneDb(s.settings),
      ...d.settings,
      counters: {
        ...cloneDb(s.settings.counters),
        ...(d.settings.counters && typeof d.settings.counters === "object" && !Array.isArray(d.settings.counters)
          ? d.settings.counters
          : {}),
      },
    };
  }
  ["zonas", "saboresFrutales", "saboresCremosos", "salsas", "rellenos", "figuras", "pagos", "proveedores"].forEach((k) => {
    if (!Array.isArray(d.settings[k])) d.settings[k] = cloneDb(s.settings[k]);
  });
  // figuras evolucionó de string[] a objetos {nombre, especie, gramaje}.
  // Normaliza entradas viejas (localStorage previo) para que .nombre no rompa.
  d.settings.figuras = d.settings.figuras
    .map((f) =>
      typeof f === "string"
        ? { nombre: f, especie: /perr/i.test(f) ? "perro" : "gato", gramaje: "150 g" }
        : { nombre: (f.nombre || "").trim(), especie: f.especie === "perro" ? "perro" : "gato", gramaje: f.gramaje || "150 g" }
    )
    .filter((f) => f.nombre);
  // relleno pasó a valor único fijo ("Cheesecake con ganache"). Migra el default viejo
  // de 2 ítems al canónico, sin pisar personalizaciones del usuario.
  if (Array.isArray(d.settings.rellenos) && d.settings.rellenos.length === 2 &&
      d.settings.rellenos.includes("Cheesecake") && d.settings.rellenos.includes("Ganache")) {
    d.settings.rellenos = ["Cheesecake con ganache"];
  }
  // toppings/adiciones: catálogo de objetos {nombre, precio, insumoId, insumoCant}. Seed si falta; normaliza shape.
  if (!Array.isArray(d.settings.toppings)) d.settings.toppings = cloneDb(s.settings.toppings);
  d.settings.toppings = d.settings.toppings
    .map((t) => typeof t === "string"
      ? { nombre: t, precio: 0, insumoId: "", insumoCant: 1 }
      : { nombre: (t.nombre || "").trim(), precio: +t.precio || 0, insumoId: t.insumoId || "", insumoCant: +t.insumoCant || 1 })
    .filter((t) => t.nombre);
  if (typeof d.settings.pedidoMinimo !== "number") d.settings.pedidoMinimo = s.settings.pedidoMinimo;
  if (typeof d.settings.pautaMensual !== "number") d.settings.pautaMensual = s.settings.pautaMensual;
  if (typeof d.settings.horasCongelacion !== "number") d.settings.horasCongelacion = s.settings.horasCongelacion;
  Object.assign(d.settings, normalizeKitchenDelaySettings(d.settings));
  if (typeof d.settings.politicas !== "string") d.settings.politicas = s.settings.politicas;
  return d;
}

function migrate(d) {
  if (d.version === 1) {
    // #20: v1 se migra en lugar de descartarse; normalizeDbShape (llamado antes) ya completó settings/counters
    d.version = 2;
  }
  if (d.version === 2) {
    const s = seedDb();
    d.recipes = s.recipes;
    d.settings.counters.recipe = 13;
    d.settings.counters.invitem = d.settings.counters.invitem || 14;
    d.version = 3;
  }
  if (d.version === 3) {
    d.inventory_reservations = [];
    d.users = d.users || seedUsers();
    d.settings.counters.reservation = d.settings.counters.reservation || 0;
    d.settings.counters.user = d.settings.counters.user || 3;
    (d.benefits || []).forEach((b) => {
      if (b.tipoBeneficio) return;
      if (/%/.test(b.beneficio)) { b.tipoBeneficio = "descuento_porcentaje"; b.valor = parseInt(b.beneficio) || 0; b.productoGratisId = ""; }
      else if (/gratis/i.test(b.beneficio)) { b.tipoBeneficio = "producto_gratis"; b.valor = 0; b.productoGratisId = /malteada/i.test(b.beneficio) ? "PR11" : /granizado/i.test(b.beneficio) ? "PR13" : ""; }
      else { b.tipoBeneficio = "descuento_valor_fijo"; b.valor = b.valor || 0; b.productoGratisId = ""; }
    });
    (d.orders || []).forEach((o) => {
      if (o.comprobante && !o.pagadoEn && !["Nuevo","Confirmado","Pendiente de pago"].includes(o.estado)) o.pagadoEn = o.fecha + " " + (o.hora || "");
    });
    d.version = 4;
  }
  if (d.version === 4) {
    (d.production_batches || []).forEach((l) => {
      if (l.stockContabilizado === undefined) l.stockContabilizado = l.estado === "Listo";
    });
    d.version = 5;
  }
  if (d.version === 5) {
    if (d.settings.horasCongelacion === undefined) d.settings.horasCongelacion = 10;
    (d.production_batches || []).forEach((l) => {
      if (l.horasCongelacion === undefined) l.horasCongelacion = d.settings.horasCongelacion;
      if (l.inicioCongelacion === undefined) l.inicioCongelacion = l.estado === "Congelando" ? (l.fecha + " 00:00:00") : "";
    });
    d.version = 6;
  }
  if (d.version === 6) {
    // eliminar Efectivo del catálogo de pagos
    d.settings.pagos = (d.settings.pagos || []).filter((p) => p !== "Efectivo");
    // política de no efectivo / no despacho sin pago
    d.settings.politicas = "MOMOS no despacha ningún pedido sin pago confirmado: se requiere comprobante de transferencia (Nequi, Daviplata o Bancolombia) o el pago dentro de la app de Rappi. No se aceptan pagos en efectivo contra entrega. Reclamos por estado del producto: máximo 20 minutos después de recibido, salvo calidad o inocuidad. Un beneficio por pedido, no acumulable, no aplica sobre domicilio.";
    // migrar pedidos antiguos con pago en efectivo
    (d.orders || []).forEach((o) => {
      if (o.pago === "Efectivo") {
        o.pago = o.canal === "Rappi" ? "Rappi (app)" : "Nequi";
        o.comprobante = false;
        if (!o.pagadoEn && !["En ruta","Entregado"].includes(o.estado)) o.estado = "Pendiente de pago";
        o.obs = (o.obs ? o.obs + " · " : "") + "El pago en efectivo fue eliminado por política MOMOS; confirmar pago digital.";
      }
    });
    d.version = 7;
  }
  if (d.version === 7) {
    const s = seedDb();
    d.campaigns = d.campaigns || s.campaigns;
    d.creatives = d.creatives || s.creatives;
    d.content_calendar = d.content_calendar || s.content_calendar;
    d.creative_results = d.creative_results || s.creative_results;
    d.settings.counters.campaign = d.settings.counters.campaign || 4;
    d.settings.counters.creative = d.settings.counters.creative || 8;
    d.settings.counters.calendar = d.settings.counters.calendar || 6;
    d.settings.counters.result = d.settings.counters.result || 5;
    (d.orders || []).forEach((o) => {
      if (o.campaignId === undefined) o.campaignId = "";
      if (o.creativeId === undefined) o.creativeId = "";
      if (o.origenDetalle === undefined) o.origenDetalle = "";
    });
    d.version = 8;
  }
  if (d.version === 8) {
    const s = seedDb();
    d.marketing_ideas = d.marketing_ideas || s.marketing_ideas;
    d.marketing_guiones = d.marketing_guiones || s.marketing_guiones;
    d.marketing_mensajes = d.marketing_mensajes || s.marketing_mensajes;
    d.brand_library = d.brand_library || s.brand_library;
    d.marketing_tasks = d.marketing_tasks || s.marketing_tasks;
    d.settings.counters.idea = d.settings.counters.idea || 12;
    d.settings.counters.guion = d.settings.counters.guion || 5;
    d.settings.counters.mensaje = d.settings.counters.mensaje || 12;
    d.settings.counters.tarea = d.settings.counters.tarea || 8;
    d.settings.counters.frase = d.settings.counters.frase || 6;
    (d.claims || []).forEach((r) => {
      if (r.fecha === undefined) {
        const o = (d.orders || []).find((x) => x.id === r.orderId);
        r.fecha = o ? o.fecha : hoyISO();
      }
      // preparar campos nuevos sin romper datos antiguos (fallback a hEntrega/hReclamo)
      if (r.reclamoEn === undefined) r.reclamoEn = (r.fecha && r.hReclamo && r.hReclamo !== "—") ? (r.fecha + " " + r.hReclamo) : "";
      if (r.entregadoEn === undefined) r.entregadoEn = (r.fecha && r.hEntrega && r.hEntrega !== "—") ? (r.fecha + " " + r.hEntrega) : "";
    });
    (d.production_suggestions || []).forEach((sg) => {
      if (sg.area === undefined) {
        const emp = (d.inventory_items || []).find((i) => i.nombre === sg.producto);
        const esEmpaque = emp || /empaque|caja|bolsa|sticker|vaso|cuchara|lazo|tarjeta/i.test(sg.producto);
        sg.area = esEmpaque ? "Inventario" : "Producción";
        sg.itemId = emp ? emp.id : "";
      }
    });
    d.version = 9;
  }
  if (d.version === 9) {
    // asegurar componentProductIds en las cajas
    ["PR05","PR06","PR07"].forEach((pid) => {
      const p = (d.products || []).find((x) => x.id === pid);
      if (p) p.componentProductIds = ["PR01","PR02"];
    });
    // marca de métricas de cliente en pedidos antiguos
    (d.orders || []).forEach((o) => {
      if (o.metricasClienteActualizadas === undefined) o.metricasClienteActualizadas = o.estado === "Entregado";
    });
    d.version = 10;
  }
  if (d.version === 10) {
    const s = seedDb();
    // A. tablas de crecimiento/marketing
    d.marketing_ideas = d.marketing_ideas || s.marketing_ideas;
    d.marketing_guiones = d.marketing_guiones || s.marketing_guiones;
    d.marketing_mensajes = d.marketing_mensajes || s.marketing_mensajes;
    d.brand_library = d.brand_library || s.brand_library;
    d.marketing_tasks = d.marketing_tasks || s.marketing_tasks;
    // B. counters
    const cnt = d.settings.counters;
    cnt.idea = cnt.idea || 12; cnt.guion = cnt.guion || 5; cnt.mensaje = cnt.mensaje || 12;
    cnt.tarea = cnt.tarea || 8; cnt.frase = cnt.frase || 6;
    // C. eliminar Efectivo del catálogo
    d.settings.pagos = (d.settings.pagos || []).filter((p) => p !== "Efectivo");
    // D. limpiar pedidos
    (d.orders || []).forEach((o) => {
      if (o.metricasClienteActualizadas === undefined) o.metricasClienteActualizadas = o.estado === "Entregado";
      if (o.pago === "Efectivo") {
        o.pago = o.canal === "Rappi" ? "Rappi (app)" : "Nequi";
        o.comprobante = false;
        if (!o.pagadoEn && !["En ruta","Entregado"].includes(o.estado)) o.estado = "Pendiente de pago";
        o.obs = (o.obs ? o.obs + " · " : "") + "Pago en efectivo eliminado por política MOMOS.";
      }
      if (o.canal === "Rappi") { o.pago = "Rappi (app)"; o.domCobrado = 0; o.domCosto = 0; }
      if (o.creativeId && !o.campaignId) {
        const cr = (d.creatives || []).find((x) => x.id === o.creativeId);
        if (cr && cr.campaignId) o.campaignId = cr.campaignId;
      }
      if (o.origenDetalle === undefined) o.origenDetalle = "";
    });
    // E. limpiar domicilios de Rappi
    (d.deliveries || []).forEach((dl) => {
      const o = (d.orders || []).find((x) => x.id === dl.orderId);
      if ((o && o.canal === "Rappi") || dl.proveedor === "Rappi") {
        dl.proveedor = "Rappi"; dl.costoReal = 0; dl.cobrado = 0;
        dl.obs = dl.obs || "Gestionado por la app de Rappi.";
      }
    });
    // F. limpiar calendario
    (d.content_calendar || []).forEach((p) => {
      if (p.creativeId && !p.campaignId) {
        const cr = (d.creatives || []).find((x) => x.id === p.creativeId);
        if (cr && cr.campaignId) p.campaignId = cr.campaignId;
      }
    });
    // G. limpiar reclamos
    (d.claims || []).forEach((r) => {
      if (!r.fecha) {
        const o = (d.orders || []).find((x) => x.id === r.orderId);
        r.fecha = o ? o.fecha : hoyISO();
      }
      if (r.reclamoEn === undefined) r.reclamoEn = (r.fecha && r.hReclamo && r.hReclamo !== "—") ? (r.fecha + " " + r.hReclamo) : "";
      if (r.entregadoEn === undefined) r.entregadoEn = (r.fecha && r.hEntrega && r.hEntrega !== "—") ? (r.fecha + " " + r.hEntrega) : "";
    });
    d.version = 11;
  }
  if (d.version === 11) {
    // Asegurar que todas las campañas tengan estado válido y montos numéricos
    (d.campaigns || []).forEach((c) => {
      if (!c.estado || !CAMP_ESTADOS.includes(c.estado)) c.estado = "Planeada";
      c.gastoReal = Number(c.gastoReal || 0);
      c.presupuesto = Number(c.presupuesto || 0);
    });
    // Blindaje Rappi en pedidos existentes
    (d.orders || []).forEach((o) => {
      if (o.canal === "Rappi") {
        o.pago = "Rappi (app)";
        o.domCobrado = 0;
        o.domCosto = 0;
      }
      if (o.pago === "Efectivo") {
        o.pago = o.canal === "Rappi" ? "Rappi (app)" : "Nequi";
        o.comprobante = false;
        if (!o.pagadoEn && !["En ruta", "Entregado"].includes(o.estado)) {
          o.estado = "Pendiente de pago";
        }
        o.obs = (o.obs ? o.obs + " · " : "") + "Pago en efectivo eliminado por política MOMOS.";
      }
    });
    // Blindaje Rappi en domicilios existentes
    (d.deliveries || []).forEach((dl) => {
      const o = (d.orders || []).find((x) => x.id === dl.orderId);
      if ((o && o.canal === "Rappi") || dl.proveedor === "Rappi") {
        dl.proveedor = "Rappi";
        dl.costoReal = 0;
        dl.cobrado = 0;
        dl.obs = dl.obs || "Gestionado por la app de Rappi.";
      }
    });
    d.version = 12;
  }
  if (d.version === 12) {
    (d.order_items || []).forEach((i) => {
      if (i.costoUnitario === undefined) {
        const p = (d.products || []).find((x) => x.id === i.productId);
        i.costoUnitario = p ? p.costo : 0;
      }
    });
    d.version = 13;
  }
  if (d.version === 13) {
    // Parche v3.1.1: idempotente. Asegura costoUnitario en items (por si vinieran de un backup viejo)
    (d.order_items || []).forEach((i) => {
      if (i.costoUnitario === undefined) {
        const p = (d.products || []).find((x) => x.id === i.productId);
        i.costoUnitario = p ? p.costo : 0;
      }
    });
    d.version = 14;
  }
  if (d.version === 14) {
    // migración idempotente v3.1.2 (sin cambios de datos; solo sella la versión)
    d.version = 15;
  }
  if (d.version === 15) {
    // migración idempotente v3.1.3 (solo sella la versión)
    d.version = 16;
  }
  if (d.version === 16) {
    // Producto terminado: la vida útil empieza al desmoldar y dura 3 días.
    (d.production_batches || []).forEach((l) => {
      const terminado = l.stockContabilizado || ["Listo", "Reservado", "Vendido", "Imperfecto", "Descartado"].includes(l.estado);
      if (!terminado) {
        l.desmoldadoEn = "";
        l.vence = "";
        return;
      }
      const audit = (d.audit_logs || []).find((a) => a.entidad === "Lote" && a.entidadId === l.id && /desmoldado/i.test(a.accion || ""));
      l.desmoldadoEn = l.desmoldadoEn || (audit && audit.fecha) || `${l.fecha} 00:00:00`;
      l.vence = sumarDiasISO(l.desmoldadoEn, 3);
    });
    d.version = 17;
  }
  return d;
}

/* ================================================================
   CAPA DE DATOS — repositorio sobre window.storage
   (misma interfaz que tendría un backend real)
   ================================================================ */

/* Adaptador de almacenamiento: usa window.storage si existe (entorno Claude/artifact),
   y cae a localStorage en un deploy React/Vite normal donde window.storage no está. */
const storage = {
  async get(key) {
    if (typeof window !== "undefined" && window.storage && window.storage.get) return await window.storage.get(key);
    const value = (typeof localStorage !== "undefined") ? localStorage.getItem(key) : null;
    return value ? { value } : null;
  },
  async set(key, value) {
    if (typeof window !== "undefined" && window.storage && window.storage.set) return await window.storage.set(key, value);
    if (typeof localStorage !== "undefined") localStorage.setItem(key, value);
    return true;
  },
  async delete(key) {
    if (typeof window !== "undefined" && window.storage && window.storage.delete) return await window.storage.delete(key);
    if (typeof localStorage !== "undefined") localStorage.removeItem(key);
    return true;
  },
};

async function dbLoad() {
  try {
    const r = await storage.get(DB_KEY);
    if (r && typeof r.value === "string" && r.value.trim().length > 0) {
      const d = JSON.parse(r.value);
      if (!d || typeof d !== "object" || Array.isArray(d) || typeof d.version !== "number") {
        return { _corruptStorage: true };
      }
      if (d.version > DB_VERSION) return { _incompatibleVersion: true, version: d.version };
      if (d.version === DB_VERSION) {
        const before = JSON.stringify(d);
        normalizeDbShape(d);
        if (JSON.stringify(d) !== before) d._migrated = true; // #5: si la normalización cambió el shape, persistir (no dejarlo solo en memoria y decir "guardado")
        return d;
      }
      if (d.version >= 1 && d.version < DB_VERSION) {
        normalizeDbShape(d);        // #15: garantizar settings/counters ANTES de migrar (migrate los asume)
        const m = migrate(d);
        normalizeDbShape(m);
        m._migrated = true;
        return m;
      }
      // versión numérica pero fuera de rango conocido: se trata como corrupto
      return { _corruptStorage: true };
    }
    return null; // lectura OK y sin datos: carga normal de semilla
  } catch (e) {
    // #9: un ERROR de lectura NO es "vacío": nunca devolver null (eso resembraría encima de datos reales)
    console.error("Base local ilegible:", e);
    return { _readError: true };
  }
}

async function dbPersist(db) {
  try { await storage.set(DB_KEY, JSON.stringify(db)); return true; }
  catch (e) { console.error("No se pudo guardar:", e); return false; }
}

async function dbReset() {
  try { await storage.delete(DB_KEY); } catch (e) {}
}

/* ================================================================
   REPOSITORY — única puerta de acceso a datos.
   Hoy: window.storage (todo el estado viaja en `db`).
   Migración a Supabase: reemplazar el CUERPO de cada función por
   llamadas a supabase.from('tabla')… / supabase.storage… sin tocar la UI.
   ================================================================ */
const repo = {
  load: dbLoad,
  persist: dbPersist,
  reset: dbReset,

  // Lecturas
  getOrders: (db, filtro = {}) => db.orders.filter((o) =>
    (!filtro.estado || o.estado === filtro.estado) && (!filtro.desde || o.fecha >= filtro.desde) && (!filtro.hasta || o.fecha <= filtro.hasta)),
  getCustomers: (db) => db.customers,
  getInventory: (db) => db.inventory_items,

  // Escrituras (mutan la copia de db dentro de update(); en Supabase serán insert/update)
  createOrder: (db, order, items) => {
    db.orders.unshift(order);
    items.forEach((it) => db.order_items.push(it));
    return order.id;
  },
  updateOrder: (db, orderId, patch) => {
    const o = db.orders.find((x) => x.id === orderId);
    if (o) Object.assign(o, patch);
    return o;
  },
  updateCustomer: (db, customerId, patch) => {
    const c = db.customers.find((x) => x.id === customerId);
    if (c) Object.assign(c, patch);
    return c;
  },
  updateInventory: (db, itemId, patch) => {
    const i = db.inventory_items.find((x) => x.id === itemId);
    if (i) Object.assign(i, patch);
    return i;
  },
  // En Supabase: subir el archivo a Storage y guardar aquí solo la URL pública
  uploadEvidence: (db, evidence) => {
    db.evidences.push(evidence);
    return evidence.id;
  },
};

/* ---- Helpers de dominio (operan sobre una copia mutable de db) ---- */

function nextId(db, key, prefix, pad = 0) {
  db.settings.counters[key] = (db.settings.counters[key] || 0) + 1;
  const n = db.settings.counters[key];
  return prefix + (pad ? String(n).padStart(pad, "0") : n);
}

function addAudit(db, { user, entidad, entidadId, accion, de = "", a = "" }) {
  db.audit_logs.unshift({ id: nextId(db, "audit", "A"), fecha: hoyISO() + " " + ahoraHora(), user, entidad, entidadId, accion, de, a });
}

const itemsOf = (db, orderId) => db.order_items.filter((i) => i.orderId === orderId);
const evidencesOf = (db, orderId) => db.evidences.filter((e) => e.orderId === orderId);
const tieneEvidencia = (db, orderId, tipo) => evidencesOf(db, orderId).some((e) => e.tipo === tipo && e.url);
// Labels de foto que faltan (con url) para pasar a `estado`; [] = nada pendiente.
function faltanFotosPaso(db, o, estado) {
  return reqFotosPaso(o, estado)
    .filter((req) => !req.tipos.some((t) => tieneEvidencia(db, o.id, t)))
    .map((req) => req.label);
}
const customerOf = (db, id) => db.customers.find((c) => c.id === id) || {};
const productOf = (db, id) => db.products.find((p) => p.id === id);

// Suma de adiciones/toppings de una línea (precio × cantidad de cada adición)
const lineAdiciones = (i) => (Array.isArray(i.adiciones) ? i.adiciones : []);
const lineAdicionesTotal = (i) => lineAdiciones(i).reduce((a, ad) => a + (+ad.precio || 0) * (+ad.cant || 1) * (+i.cant || 1), 0);
// Suma de toppings de los sub-momos de una línea combo en NuevoPedido (aún no persistidos como hijas; cada slot = 1 momo).
const boxesAdicionesTotal = (l) => (l.boxes || []).reduce((s, box) => s + box.reduce((ss, sl) => ss + lineAdicionesTotal({ adiciones: sl.adiciones, cant: 1 }), 0), 0);
// Congela el costo del insumo de cada adición al crear el pedido: el COGS histórico no se mueve si cambia el
// precio del insumo, y sobrevive aunque el insumo se borre. Fallback al costo en vivo (en el read) para filas viejas.
const snapAdiciones = (d, adiciones) => (Array.isArray(adiciones) ? adiciones : []).map((ad) =>
  ad.insumoId ? { ...ad, insumoCosto: +((d.inventory_items.find((x) => x.id === ad.insumoId) || {}).costo) || 0 } : ad);
const orderSubtotal = (db, o) => itemsOf(db, o.id).reduce((s, i) => s + i.precio * i.cant + lineAdicionesTotal(i), 0);
const orderTotal = (db, o) => orderSubtotal(db, o) - (o.descuento || 0) + (o.domCobrado || 0);
// Costo de insumo de las adiciones de una línea (solo las que consumen inventario).
// Topping POR MOMO: escala por la cantidad de la línea (i.cant), igual que reserveInventory →
// el COGS refleja el inventario real gastado. (Costo de insumo en vivo; congelarlo queda para Supabase.)
const lineAdicionesCOGS = (db, i) => lineAdiciones(i).reduce((s, ad) => {
  if (!ad.insumoId) return s;
  const ins = db.inventory_items.find((x) => x.id === ad.insumoId);
  if (!ins) return s;
  return s + (+ad.insumoCant || 0) * (+ad.cant || 1) * (+i.cant || 1) * (+ins.costo || 0);
}, 0);
const orderCOGS = (db, o) => itemsOf(db, o.id).reduce((s, i) => {
  const p = productOf(db, i.productId);
  const costo = i.costoUnitario !== undefined ? i.costoUnitario : (p ? p.costo : 0);
  return s + costo * i.cant + lineAdicionesCOGS(db, i);
}, 0);

// Un pedido cuenta como venta SOLO si tiene pago confirmado y no está en estados previos ni cancelado
const esPedidoCobrado = (o) => !!o.pagadoEn && !["Nuevo","Confirmado","Pendiente de pago","Cancelado"].includes(o.estado);

const momoUnitStock = (db) => db.products.filter((p) => p.tipo === "momo" && p.cat === "Momos Signature").reduce((s, p) => s + (p.stock || 0), 0);

// Sugiere la zona de domicilio a partir del barrio del cliente (busca el barrio en el nombre de la zona)
function sugerirZona(zonas, barrio) {
  if (!barrio) return null;
  const b = barrio.toLowerCase().trim();
  const z = zonas.find((zn) => zn.nombre.toLowerCase().split(/[·\/]/).some((parte) => {
    const p = parte.trim();
    return p && (p.includes(b) || b.includes(p));
  }));
  return z ? z.nombre : null;
}

// Disponibilidad real: unidades con stock, combos calculados por momos + cajas, resto bajo pedido
// Stock de momos que sirven como componentes de un combo (solo los componentProductIds definidos)
function comboComponentStock(db, p) {
  const ids = p.componentProductIds || [];
  const comps = db.products.filter((x) => ids.includes(x.id));
  return comps.reduce((s, x) => s + (x.stock || 0), 0);
}

// --- Combos reales: la figura de cada slot mapea a una ESPECIE, y la especie al momo-componente ---
// El stock de momos vive a nivel especie (PR01 = pool gato, PR02 = pool perro), NO por figura.
function momoEspecie(p) {
  if (!p) return "gato";
  if (p.especie === "perro" || p.especie === "gato") return p.especie;
  return /perr/i.test(p.nombre || "") ? "perro" : "gato"; // retro-compat: deriva del nombre
}
function figuraEspecie(db, nombre) {
  const f = (db.settings.figuras || []).find((x) => x.nombre === nombre);
  return f ? f.especie : "gato";
}
// El momo-componente del combo cuya especie coincide con la figura del slot (descuento exacto).
function componentProductForFigura(db, combo, figuraNombre) {
  const esp = figuraEspecie(db, figuraNombre);
  const comps = (db.products || []).filter((p) => (combo.componentProductIds || []).includes(p.id));
  return comps.find((p) => momoEspecie(p) === esp) || comps[0] || null;
}
// Figuras ofrecibles en un combo: solo las de especies presentes entre sus componentes.
function figurasDeCombo(db, combo) {
  const ids = combo.componentProductIds || [];
  const especies = new Set((db.products || []).filter((p) => ids.includes(p.id)).map((p) => momoEspecie(p)));
  return (db.settings.figuras || []).filter((f) => especies.has(f.especie));
}
// Faltante por ESPECIE de un combo ya compuesto (boxes): demanda por momo-componente vs su stock.
// Necesario porque `availability` mira el POOL combinado, pero reserveInventory descuenta la especie
// EXACTA de cada figura → si el usuario concentra una especie agotada, el pool "alcanza" pero la
// especie no. Devuelve [] si todo alcanza; si no, [{nombre, falta}] por componente corto.
function comboFaltantesEspecie(db, combo, boxes) {
  const demanda = {};
  (boxes || []).forEach((box) => (box || []).forEach((sl) => {
    if (!sl || !sl.figura) return;
    const comp = componentProductForFigura(db, combo, sl.figura);
    if (comp) demanda[comp.id] = (demanda[comp.id] || 0) + 1;
  }));
  const faltas = [];
  Object.keys(demanda).forEach((pid) => {
    const comp = (db.products || []).find((x) => x.id === pid);
    if (comp && demanda[pid] > (comp.stock || 0)) faltas.push({ nombre: comp.nombre, falta: demanda[pid] - (comp.stock || 0) });
  });
  return faltas;
}

function availability(db, p) {
  if (p.tipo === "momo") return p.stock || 0;
  if (p.tipo === "combo") {
    const momos = comboComponentStock(db, p);
    const emp = db.inventory_items.find((i) => i.id === p.empaqueItem);
    return Math.min(Math.floor(momos / p.comboSize), emp ? Math.floor(emp.stock) : 0);
  }
  return Infinity; // se prepara al momento
}

function addMovement(db, { tipo, item, cant, nota }) {
  db.inventory_movements.unshift({ id: nextId(db, "movement", "M"), fecha: hoyISO() + " " + ahoraHora(), tipo, item, cant, nota });
}

/* ---- Estado de congelación de un lote ---- */
function estadoCongelacion(l) {
  if (!l || l.estado !== "Congelando" || !l.inicioCongelacion) return null;
  const h = horasDesde(l.inicioCongelacion);
  if (h === null) return null;
  const objetivo = l.horasCongelacion || 10;
  const restan = objetivo - h;
  return { horas: h, objetivo, restan, listo: restan <= 0 };
}
const fmtHoras = (h) => { const total = Math.round(Math.max(0, h) * 60); const hh = Math.floor(total / 60); const mm = total % 60; return hh + " h" + (mm ? " " + mm + " min" : ""); };

/* ---- Marketing: atribución y métricas ---- */
const ordersDeCampaign = (db, campId) => db.orders.filter((o) => o.campaignId === campId && esPedidoCobrado(o));
const ordersDeCreative = (db, creaId) => db.orders.filter((o) => o.creativeId === creaId && esPedidoCobrado(o));
const ventasDeCampaign = (db, campId) => ordersDeCampaign(db, campId).reduce((s, o) => s + orderTotal(db, o), 0);
const ventasDeCreative = (db, creaId) => ordersDeCreative(db, creaId).reduce((s, o) => s + orderTotal(db, o), 0);
const claveDimensionResultado = (r) => `${r.fecha}|${r.creativeId ? `creative:${r.creativeId}` : `campaign:${r.campaignId || ""}`}`;
const ordenFuenteResultado = (a, b) => (a.fuente === "manual" ? 1 : 0) - (b.fuente === "manual" ? 1 : 0)
  || String(a.fuente || "").localeCompare(String(b.fuente || "")) || String(a.id).localeCompare(String(b.id));
// Resultados guarda métricas de plataforma por día. Pedidos/ventas salen SIEMPRE
// de orders (misma fecha + creativo/campaña), nunca de campos tipeados a mano.
function atribucionDeResultado(db, r) {
  // Un pedido conoce el creativo/campaña, pero no la fuente de métricas. Si
  // conviven manual + MCP para el mismo día, se atribuye solo a una fila para
  // no duplicar pedidos/ventas en tarjetas, CSV, reportes ni recomendaciones.
  const clave = claveDimensionResultado(r);
  const canonico = (db.creative_results || []).filter((x) => claveDimensionResultado(x) === clave).sort(ordenFuenteResultado)[0];
  if (canonico && canonico.id !== r.id) return { pedidos: 0, ventas: 0, contabilizar: false };
  const pedidos = db.orders.filter((o) => {
    if (!esPedidoCobrado(o) || (r.fecha && o.fecha !== r.fecha)) return false;
    if (r.creativeId) return o.creativeId === r.creativeId;
    if (!r.campaignId || o.campaignId !== r.campaignId) return false;
    // Si el pedido tiene creativo y ese creativo posee métricas ese día, su
    // atribución vive en esa dimensión; la fila de campaña solo cubre el resto.
    return !o.creativeId || !(db.creative_results || []).some((x) => x.fecha === r.fecha && x.creativeId === o.creativeId);
  });
  return { pedidos: pedidos.length, ventas: pedidos.reduce((s, o) => s + orderTotal(db, o), 0), contabilizar: true };
}

// Para analítica, fuentes MCP distintas se suman. La captura manual funciona
// como fallback: si ya existe cualquier fuente automática en esa dimensión/día,
// se omite para no duplicar la misma lectura digitada y sincronizada.
function resultadosDePlataforma(db) {
  const raw = db.creative_results || [];
  const elegibles = raw.filter((r) => r.fuente !== "manual"
    || !raw.some((x) => x.fuente !== "manual" && claveDimensionResultado(x) === claveDimensionResultado(r)));
  const grupos = new Map();
  elegibles.forEach((r) => {
    const clave = claveDimensionResultado(r);
    if (!grupos.has(clave)) grupos.set(clave, []);
    grupos.get(clave).push(r);
  });
  return [...grupos.values()].map((filas) => {
    const ordenadas = [...filas].sort(ordenFuenteResultado);
    const base = ordenadas[0];
    const suma = (campo) => filas.reduce((s, x) => s + Number(x[campo] || 0), 0);
    return {
      ...base,
      fuente: [...new Set(filas.map((x) => x.fuente || "manual"))].sort().join(" + "),
      impresiones: suma("impresiones"), alcance: suma("alcance"), clicks: suma("clicks"),
      mensajesWhatsApp: suma("mensajesWhatsApp"), gasto: suma("gasto"),
      notas: filas.map((x) => x.notas).filter(Boolean).join(" · "),
    };
  });
}
function campaignMetrics(db, c) {
  const pedidos = ordersDeCampaign(db, c.id).length;
  const ventas = ventasDeCampaign(db, c.id);
  const gasto = Number(c.gastoReal || 0);
  const cac = pedidos > 0 ? gasto / pedidos : null;
  const roas = gasto > 0 ? ventas / gasto : null;
  const ticket = pedidos > 0 ? ventas / pedidos : 0;
  return { pedidos, ventas, cac, roas, ticket };
}

// Stock disponible del producto foco de una campaña (por nombre)
function stockProductoFoco(db, nombre) {
  if (!nombre) return null;
  const p = db.products.find((x) => x.nombre === nombre);
  if (!p) return null;
  return availability(db, p);
}

// Reglas simples estilo trafficker: recomendaciones en lenguaje claro.
function trafficRecomendaciones(db) {
  const recs = [];
  (db.campaigns || []).forEach((c) => {
    if (c.estado !== "Activa") return;
    const m = campaignMetrics(db, c);
    const stockFoco = stockProductoFoco(db, c.productoFoco);
    if (c.gastoReal > 60000 && m.pedidos === 0) {
      recs.push({ tipo: "pausar", campaignId: c.id, icon: "⏸️", titulo: c.nombre,
        texto: `Gastó ${fmt(c.gastoReal)} y no ha traído pedidos. Te recomendamos pausarla y probar otro contenido.`,
        accion: "pausar", bg: "#F6D4CD", color: "#A03B2A" });
    } else if (c.productoFoco && stockFoco !== null && stockFoco <= 0) {
      recs.push({ tipo: "sinstock", campaignId: c.id, icon: "📦", titulo: c.nombre,
        texto: `Estás promocionando "${c.productoFoco}" pero no tienes stock. Repón antes de seguir invirtiendo.`,
        bg: "#FBE8C8", color: "#96690F" });
    } else if (m.roas !== null && m.roas >= 2 && (stockFoco === null || stockFoco > 0)) {
      const nuevo = Math.round((c.presupuesto || c.gastoReal) * 1.2);
      recs.push({ tipo: "subir", campaignId: c.id, icon: "🚀", titulo: c.nombre,
        texto: `Está rindiendo muy bien (cada peso invertido volvió multiplicado). Sube el presupuesto ~20% (a ${fmt(nuevo)}) para vender más.`,
        accion: "subir", nuevoPresupuesto: nuevo, bg: "#DDEBD9", color: "#3F6B42" });
    }
  });
  resultadosDePlataforma(db).forEach((r) => {
    const atrib = atribucionDeResultado(db, r);
    if (r.mensajesWhatsApp >= 30 && atrib.pedidos <= 3) {
      const cre = db.creatives.find((x) => x.id === r.creativeId);
      recs.push({ tipo: "copy", icon: "✏️", titulo: cre ? cre.titulo : "Contenido",
        texto: `Recibió muchos mensajes (${r.mensajesWhatsApp}) pero pocos pedidos (${atrib.pedidos}). Revisa el precio, la oferta o el mensaje: la gente pregunta pero no compra.`,
        bg: "#FBE8C8", color: "#96690F" });
    }
  });
  return recs;
}

/* ---- Recetas: consumo de insumos por unidad de producto ---- */
const recipeLines = (db, productId) => (db.recipes || []).filter((r) => r.productId === productId);

function recipeCost(db, productId) {
  return recipeLines(db, productId).reduce((s, l) => {
    const it = db.inventory_items.find((i) => i.id === l.itemId);
    return s + (it ? it.costo * l.cantidad : 0);
  }, 0);
}

// Descuenta la receta de `unidades` del inventario. Devuelve lista de faltantes.
function deductRecipe(db, product, unidades, nota, orderId) {
  const faltantes = [];
  recipeLines(db, product.id).forEach((l) => {
    const it = db.inventory_items.find((i) => i.id === l.itemId);
    if (!it) return;
    const req = +(l.cantidad * unidades).toFixed(3);
    const toma = Math.min(it.stock, req);
    it.stock = +(it.stock - toma).toFixed(3);
    if (toma > 0) {
      addMovement(db, { tipo: "Uso en producción", item: it.nombre, cant: "-" + +toma.toFixed(3) + " " + it.unidad, nota });
      // Registrar el consumo REAL como reserva liberable (solo si hay pedido). Así la
      // cancelación devuelve exactamente lo que se sacó, no la cantidad teórica de la receta.
      if (orderId) addReservation(db, orderId, "insumo", it.id, it.nombre, toma);
    }
    if (toma < req) faltantes.push(`${it.nombre} (faltan ${+(req - toma).toFixed(2)} ${it.unidad})`);
  });
  return faltantes;
}

// Reserva de inventario al marcar Pagado: descuenta stock Y registra cada reserva
// en inventory_reservations para poder liberarla si el pedido se cancela.
function addReservation(db, orderId, tipo, refId, nombre, cantidad) {
  if (cantidad <= 0) return;
  db.inventory_reservations.push({ id: nextId(db, "reservation", "RES-"), orderId, tipo, refId, nombre, cantidad, fecha: hoyISO() + " " + ahoraHora(), estado: "Reservada" });
}

function reserveInventory(db, order, user) {
  const faltantes = [];
  itemsOf(db, order.id).forEach((it) => {
    const p = productOf(db, it.productId);
    if (!p) return;
    if (p.tipo === "momo") {
      const toma = Math.min(p.stock, it.cant);
      p.stock -= toma;
      addReservation(db, order.id, "producto", p.id, p.nombre, toma);
      if (toma < it.cant) faltantes.push({ producto: p.nombre, cant: it.cant - toma, area: "Producción" });
    } else if (p.tipo === "combo") {
      // Combos reales: si la caja tiene sub-momos (hijas con parentItemId), cada hija se descuenta
      // sola por la rama "momo" de arriba (especie EXACTA del slot) → se salta el pull genérico.
      // Combo legacy de semilla (sin hijas) → pull genérico del pool de componentes (retrocompat).
      const tieneHijas = itemsOf(db, order.id).some((x) => x.parentItemId === it.id);
      if (!tieneHijas) {
        let necesita = p.comboSize * it.cant;
        const ids = p.componentProductIds || [];
        const comps = db.products.filter((x) => ids.includes(x.id));
        comps.forEach((x) => {
          const toma = Math.min(x.stock, necesita);
          x.stock -= toma; necesita -= toma;
          if (toma > 0) addReservation(db, order.id, "producto", x.id, x.nombre + " (para " + p.nombre + ")", toma);
        });
        if (necesita > 0) faltantes.push({ producto: "Momos para " + p.nombre, cant: necesita, area: "Producción" });
      }
      const emp = db.inventory_items.find((i) => i.id === p.empaqueItem);
      if (emp) {
        const tomaEmp = Math.min(emp.stock, it.cant);
        emp.stock = +(emp.stock - tomaEmp).toFixed(2);
        if (tomaEmp > 0) {
          addReservation(db, order.id, "empaque", emp.id, emp.nombre, tomaEmp);
          addMovement(db, { tipo: "Salida", item: emp.nombre, cant: "-" + tomaEmp + " und", nota: "Reserva pedido " + order.id });
        }
        if (tomaEmp < it.cant) faltantes.push({ producto: emp.nombre, cant: it.cant - tomaEmp, area: "Inventario", itemId: emp.id });
      }
      // #4: extras de receta del combo (tarjeta, etc.) se consumen físicamente Y
      // se REGISTRAN como reserva liberable, para que vuelvan al cancelar (igual que
      // momos y caja). Sin esto, un extra descontado al reservar quedaba perdido.
      recipeLines(db, p.id).forEach((l) => {
        const ex = db.inventory_items.find((i) => i.id === l.itemId);
        if (!ex) return;
        const req = +(l.cantidad * it.cant).toFixed(3);
        const toma = Math.min(ex.stock, req);
        ex.stock = +(ex.stock - toma).toFixed(3);
        if (toma > 0) {
          addReservation(db, order.id, "insumo", ex.id, ex.nombre, toma);
          addMovement(db, { tipo: "Salida", item: ex.nombre, cant: "-" + +toma.toFixed(3) + " " + ex.unidad, nota: "Combo " + order.id });
        }
        if (toma < req) faltantes.push({ producto: ex.nombre, cant: +(req - toma).toFixed(2), area: "Inventario", itemId: ex.id });
      });
    }
  });
  // Adiciones/toppings con insumo ligado: descontar y RESERVAR (liberable al cancelar,
  // igual que los extras de receta). Sin insumoId, la adición solo suma al precio.
  itemsOf(db, order.id).forEach((it) => {
    lineAdiciones(it).forEach((ad) => {
      if (!ad.insumoId) return;
      const ins = db.inventory_items.find((i) => i.id === ad.insumoId);
      if (!ins) return;
      // Topping POR MOMO: consume el insumo por cada unidad de la línea (× it.cant).
      const req = +((+ad.insumoCant || 1) * (+ad.cant || 1) * (+it.cant || 1)).toFixed(3);
      const toma = Math.min(ins.stock, req);
      ins.stock = +(ins.stock - toma).toFixed(3);
      if (toma > 0) {
        addReservation(db, order.id, "insumo", ins.id, ins.nombre + " (adición " + ad.nombre + ")", toma);
        addMovement(db, { tipo: "Salida", item: ins.nombre, cant: "-" + +toma.toFixed(3) + " " + ins.unidad, nota: "Adición " + ad.nombre + " · " + order.id });
      }
      if (toma < req) faltantes.push({ producto: ins.nombre + " (adición " + ad.nombre + ")", cant: +(req - toma).toFixed(2), area: "Inventario", itemId: ins.id });
    });
  });
  faltantes.forEach((f) => {
    db.production_suggestions.unshift({ id: nextId(db, "suggestion", "S-", 2), fecha: hoyISO(), producto: f.producto, cantidad: f.cant, motivo: "Stock insuficiente al reservar", orderId: order.id, estado: "Pendiente", area: f.area || "Producción", itemId: f.itemId || "" });
  });
  const prod = faltantes.filter((f) => f.area !== "Inventario");
  const inv = faltantes.filter((f) => f.area === "Inventario");
  if (prod.length) addAudit(db, { user, entidad: "Producción", entidadId: order.id, accion: "Sugerencia de producción creada", a: prod.map((f) => f.cant + "× " + f.producto).join(", ") });
  if (inv.length) addAudit(db, { user, entidad: "Inventario", entidadId: order.id, accion: "Compra sugerida creada", a: inv.map((f) => f.cant + "× " + f.producto).join(", ") });
  return faltantes;
}

// Liberar reservas de un pedido cancelado: devuelve stock y marca las filas como Liberadas
function releaseReservations(db, orderId, user) {
  let liberadas = 0;
  db.inventory_reservations.filter((r) => r.orderId === orderId && r.estado === "Reservada").forEach((r) => {
    if (r.tipo === "producto") {
      const p = db.products.find((x) => x.id === r.refId);
      if (p) p.stock += r.cantidad;
    } else if (r.tipo === "empaque") {
      const it = db.inventory_items.find((x) => x.id === r.refId);
      if (it) {
        it.stock = +(it.stock + r.cantidad).toFixed(2);
        addMovement(db, { tipo: "Entrada", item: it.nombre, cant: "+" + r.cantidad + " und", nota: "Liberación por cancelación de " + orderId });
      }
    } else if (r.tipo === "insumo") {
      // extras de receta (combo) y, a futuro, adiciones/toppings: vuelven al inventario
      const it = db.inventory_items.find((x) => x.id === r.refId);
      if (it) {
        it.stock = +(it.stock + r.cantidad).toFixed(3);
        addMovement(db, { tipo: "Entrada", item: it.nombre, cant: "+" + r.cantidad + " " + it.unidad, nota: "Liberación por cancelación de " + orderId });
      }
    }
    r.estado = "Liberada";
    r.liberadaEn = hoyISO() + " " + ahoraHora();
    liberadas++;
  });
  if (liberadas) addAudit(db, { user, entidad: "Inventario", entidadId: orderId, accion: "Reservas liberadas", a: liberadas + " reserva(s) devueltas al stock" });
  return liberadas;
}

function consumeReservations(db, orderId) {
  db.inventory_reservations.filter((r) => r.orderId === orderId && r.estado === "Reservada").forEach((r) => { r.estado = "Consumida"; });
}

// Al entregar: actualizar métricas y estado del cliente automáticamente
function updateCustomerAfterDelivery(db, order) {
  const c = db.customers.find((x) => x.id === order.customerId);
  if (!c) return;
  c.ultima = hoyISO();
  c.pedidos += 1;
  c.total += orderTotal(db, order);
  const reclamosCliente = db.claims.filter((r) => r.customerId === c.id).length;
  if (reclamosCliente >= 2) c.estado = "Riesgo por reclamos";
  else if (c.pedidos >= 5 || c.total >= 200000) c.estado = "VIP";
  else if (c.pedidos >= 2) c.estado = "Recurrente";
  else c.estado = "Nuevo";
}

function tieneSelloEmpaque(db, orderId) {
  return evidencesOf(db, orderId).some((e) => EV_SELLO.includes(e.tipo));
}

// Transiciones legales de estado (grafo estricto). Bloquea saltos sin sentido; permite
// avances de a un paso y retrocesos razonables. Cancelado y Reclamo son excepciones
// alcanzables desde cualquier estado. La venta rápida (opts.ventaRapida) es el ÚNICO
// camino que puede saltarse pasos hacia Entregado (entrega en mano).
const TRANSICIONES = {
  "Nuevo": ["Confirmado", "Pendiente de pago", "Pagado"],
  "Confirmado": ["Pendiente de pago", "Pagado", "Nuevo"],
  "Pendiente de pago": ["Pagado", "Confirmado"],
  "Pagado": ["En producción", "Pendiente de pago"],
  "En producción": ["Listo para empaque", "Pagado"],
  "Listo para empaque": ["Empacado", "En producción"],
  "Empacado": ["Listo para despacho", "En ruta", "Listo para empaque"],
  "Listo para despacho": ["En ruta", "Empacado"],
  "En ruta": ["Entregado", "Listo para despacho"],
  "Entregado": [],
  "Reclamo": ["Entregado"],
  "Cancelado": [],
};

// Cambio central de estado: validaciones + audit log + efectos secundarios
function setOrderStatus(db, orderId, estado, user, opts = {}) {
  const o = db.orders.find((x) => x.id === orderId);
  if (!o || o.estado === estado) return { ok: true };

  // Grafo estricto de transiciones: rechazar saltos ilegales. Excepciones: Cancelado y
  // Reclamo (desde cualquier estado) y la venta rápida hacia Entregado (entrega en mano).
  const ventaRapida = !!opts.ventaRapida;
  const legal = (TRANSICIONES[o.estado] || []).includes(estado)
    || estado === "Cancelado" || estado === "Reclamo"
    || (ventaRapida && estado === "Entregado");
  if (!legal) {
    return { ok: false, error: `Transición no permitida: de "${o.estado}" no se puede pasar a "${estado}". Avanzá paso a paso, o usá "Entrega inmediata" si es una venta en mano.` };
  }

  // Ningún estado operativo sin pago confirmado
  if (["En producción","Listo para empaque","Empacado","Listo para despacho","En ruta","Entregado"].includes(estado) && !o.pagadoEn) {
    return { ok: false, error: "MOMOS no produce ni despacha pedidos sin pago confirmado." };
  }

  // Evidencias guiadas por paso: Empacado exige caja abierta + sello (foto con tipo fijo, no dropdown)
  if (estado === "Empacado") {
    const faltan = faltanFotosPaso(db, o, "Empacado");
    if (faltan.length) return { ok: false, error: `El pedido ${orderId} no puede pasar a "Empacado": falta la foto de ${faltan.join(" y ")}.` };
  }

  // Validaciones para despachar: sello + pago + domicilio asignado + costo real (salvo Rappi)
  if (estado === "En ruta") {
    const fallas = [];
    if (!tieneSelloEmpaque(db, orderId)) fallas.push("falta foto de caja cerrada con sello o bolsa sellada");
    if (!o.pagadoEn) fallas.push("el pedido no tiene pago confirmado");
    const dom = db.deliveries.find((x) => x.orderId === orderId && x.estado !== "Cancelado");
    if (!dom) fallas.push("no tiene domicilio asignado (solicítalo en Domicilios)");
    if (o.canal !== "Rappi") {
      const costo = (dom && dom.costoReal > 0) || o.domCosto > 0;
      if (!costo) fallas.push("falta registrar el costo real del domicilio");
    }
    if (fallas.length) return { ok: false, error: `El pedido ${orderId} no puede pasar a "En ruta": ${fallas.join("; ")}.` };
  }

  // Validaciones para marcar Entregado: pagado + sello (salvo Rappi con evidencia de app) + foto de entrega
  if (estado === "Entregado") {
    const fallas = [];
    if (!o.pagadoEn) fallas.push("el pedido no tiene pago confirmado");
    if (o.canal === "Rappi") {
      const tieneApp = evidencesOf(db, orderId).some((e) => e.tipo === "Comprobante de pago" || e.tipo === "Bolsa sellada");
      if (!tieneApp) fallas.push("falta evidencia de la app o de empaque");
    } else if (!ventaRapida && !tieneSelloEmpaque(db, orderId)) {
      fallas.push("falta foto de caja cerrada con sello o bolsa sellada");
    }
    if (!tieneEvidencia(db, orderId, "Entrega")) fallas.push("falta la foto de entrega");
    if (fallas.length) return { ok: false, error: `El pedido ${orderId} no puede marcarse "Entregado": ${fallas.join("; ")}.` };
  }

  // Validaciones para confirmar Pagado: comprobante digital (salvo Rappi, que se paga en su app)
  if (estado === "Pagado") {
    if (o.pago === "Efectivo") return { ok: false, error: `El pedido ${orderId} no puede marcarse "Pagado": MOMOS no acepta efectivo. Cambia la forma de pago a una digital.` };
    if (o.canal !== "Rappi" && o.pago === "Rappi (app)") return { ok: false, error: `El pedido ${orderId} no es de Rappi, así que no puede pagarse con "Rappi (app)". Elige Nequi, Daviplata o Bancolombia.` };
    if (o.canal === "Rappi") {
      if (o.pago !== "Rappi (app)") return { ok: false, error: `El pedido ${orderId} es de Rappi: el pago debe ser "Rappi (app)".` };
    } else {
      const tieneComprobante = evidencesOf(db, orderId).some((e) => e.tipo === "Comprobante de pago" && e.url);
      if (!tieneComprobante) return { ok: false, error: `El pedido ${orderId} no puede marcarse "Pagado" sin subir la foto del comprobante de pago. MOMOS no acepta efectivo ni despacha sin pago confirmado.` };
    }
  }

  const prev = o.estado;
  o.estado = estado;
  addAudit(db, { user, entidad: "Pedido", entidadId: o.id, accion: "Cambio de estado", de: prev, a: estado });

  let faltantes = [];
  let faltInsumos = [];

  if (estado === "Pagado") {
    o.comprobante = true;
    o.pagadoEn = hoyISO() + " " + ahoraHora();
    if (!o.inventarioReservado) { faltantes = reserveInventory(db, o, user); o.inventarioReservado = true; }
    // beneficio Reservado → Usado al confirmar el pago
    if (o.benefitId) {
      const b = db.benefits.find((x) => x.id === o.benefitId);
      if (b && b.estado === "Reservado") {
        b.estado = "Usado";
        addAudit(db, { user, entidad: "Beneficio", entidadId: b.id, accion: "Beneficio usado", a: "Pedido " + o.id });
      }
    }
  }

  // #7: reservar inventario UNA sola vez si el pedido entra a producción/despacho con pago pero sin reserva previa
  // (cubre pedidos que obtuvieron pagadoEn sin pasar por el handler de "Pagado": semilla, migración, retroceso de estado)
  if (["En producción","Listo para empaque","Empacado","Listo para despacho","En ruta","Entregado"].includes(estado) && o.pagadoEn && !o.inventarioReservado) {
    faltantes = reserveInventory(db, o, user);
    o.inventarioReservado = true;
  }

  if (estado === "En producción" && !o.insumosDescontados) {
    itemsOf(db, o.id).forEach((it) => {
      const p = productOf(db, it.productId);
      if (p && p.tipo === "pedido") faltInsumos.push(...deductRecipe(db, p, it.cant, "Pedido " + o.id, o.id));
    });
    o.insumosDescontados = true;
    if (faltInsumos.length) addAudit(db, { user, entidad: "Inventario", entidadId: o.id, accion: "Insumos insuficientes al producir", a: faltInsumos.join(", ") });
  }

  // #4 Red de seguridad de receta: si el pedido llega a "En ruta"/"Entregado" sin haber pasado
  // por "En producción" (venta rápida o un salto), descontar la receta ACÁ para no dejar insumos
  // sin descontar. Con orderId → queda como reserva liberable (reversible al cancelar, fix #1).
  if (["En ruta","Entregado"].includes(estado) && !o.insumosDescontados) {
    itemsOf(db, o.id).forEach((it) => {
      const p = productOf(db, it.productId);
      if (p && p.tipo === "pedido") faltInsumos.push(...deductRecipe(db, p, it.cant, "Pedido " + o.id + " (entrega directa)", o.id));
    });
    o.insumosDescontados = true;
    if (faltInsumos.length) addAudit(db, { user, entidad: "Inventario", entidadId: o.id, accion: "Insumos descontados en entrega directa", a: faltInsumos.join(", ") });
  }

  if (estado === "Cancelado") {
    // liberar reservas de inventario (si aún no se despachó)
    if (!["En ruta","Entregado"].includes(prev)) releaseReservations(db, o.id, user);
    // #3 (fix stock fantasma): los insumos de receta consumidos en "En producción" ahora se
    // registran como reserva tipo:"insumo" (el TOMA REAL) dentro de deductRecipe, así
    // releaseReservations (arriba) ya devolvió EXACTAMENTE lo consumido. Antes acá se
    // recalculaba dev = l.cantidad * it.cant (la receta teórica), inyectando stock que
    // nunca existió cuando el insumo no alcanzaba al producir. Solo reseteamos el flag.
    if (o.insumosDescontados && !["En ruta","Entregado"].includes(prev)) {
      o.insumosDescontados = false;
    }
    // #17: si se cancela un pedido YA entregado, revertir las métricas del cliente (no dejar ventas fantasma)
    if (prev === "Entregado" && o.metricasClienteActualizadas) {
      const c = db.customers.find((x) => x.id === o.customerId);
      if (c) { c.pedidos = Math.max(0, c.pedidos - 1); c.total = Math.max(0, c.total - orderTotal(db, o)); }
      o.metricasClienteActualizadas = false;
    }
    // beneficio: si se cancela antes de En producción, devolverlo a Activo aunque ya estuviera Usado por el pago
    if (o.benefitId) {
      const b = db.benefits.find((x) => x.id === o.benefitId);
      const antesDeProduccion = !["En producción","Listo para empaque","Empacado","Listo para despacho","En ruta","Entregado"].includes(prev);
      if (b && (b.estado === "Reservado" || (b.estado === "Usado" && antesDeProduccion))) {
        const antes = b.estado;
        b.estado = "Activo"; b.pedidoUso = "";
        addAudit(db, { user, entidad: "Beneficio", entidadId: b.id, accion: "Beneficio devuelto al cliente", de: antes, a: "Activo" });
      }
    }
    const dom = db.deliveries.find((x) => x.orderId === o.id && !["Entregado","Cancelado"].includes(x.estado));
    if (dom) dom.estado = "Cancelado";
  }

  if (estado === "En ruta") {
    // 3. sincronizar el domicilio asociado
    const dom = db.deliveries.find((x) => x.orderId === o.id && !["Entregado","Cancelado"].includes(x.estado));
    if (dom && dom.estado !== "En ruta") { dom.estado = "En ruta"; if (!dom.hSalida) dom.hSalida = ahoraHora(); }
  }

  if (estado === "Entregado") {
    consumeReservations(db, o.id);
    if (o.metricasClienteActualizadas !== true) {
      updateCustomerAfterDelivery(db, o);
      o.metricasClienteActualizadas = true;
    }
    const d = db.deliveries.find((x) => x.orderId === o.id && !["Entregado","Cancelado"].includes(x.estado));
    if (d) { d.estado = "Entregado"; d.hEntrega = ahoraHora(); }
  }

  // #14: si el pedido RETROCEDE desde "En ruta" a un estado previo, el domicilio no debe quedar pegado en ruta
  if (prev === "En ruta" && !["En ruta","Entregado","Cancelado"].includes(estado)) {
    const dom = db.deliveries.find((x) => x.orderId === o.id && x.estado === "En ruta");
    if (dom) { dom.estado = "Asignado"; dom.hSalida = ""; }
  }

  return { ok: true, faltantes, faltInsumos };
}

/* ---------------- Exportación CSV ---------------- */

function copiarTexto(texto) {
  try {
    if (navigator.clipboard && navigator.clipboard.writeText) { navigator.clipboard.writeText(texto); return true; }
  } catch (e) {}
  try {
    const ta = document.createElement("textarea");
    ta.value = texto; ta.style.position = "fixed"; ta.style.opacity = "0";
    document.body.appendChild(ta); ta.select(); document.execCommand("copy"); document.body.removeChild(ta);
    return true;
  } catch (e) { return false; }
}

function downloadCSV(nombre, headers, rows) {
  const esc = (v) => `"${String(v ?? "").replace(/"/g, '""')}"`;
  const csv = [headers.map(esc).join(","), ...rows.map((r) => r.map(esc).join(","))].join("\n");
  const blob = new Blob(["\uFEFF" + csv], { type: "text/csv;charset=utf-8" });
  const a = document.createElement("a");
  a.href = URL.createObjectURL(blob);
  a.download = nombre + "-" + hoyISO() + ".csv";
  a.click();
  setTimeout(() => URL.revokeObjectURL(a.href), 2000);
}

/* ---------------- Compresión de imágenes de evidencia ---------------- */

function compressImage(file, maxW = 900, quality = 0.72) {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = () => {
      const img = new Image();
      img.onload = () => {
        const scale = Math.min(1, maxW / img.width);
        const canvas = document.createElement("canvas");
        canvas.width = Math.round(img.width * scale);
        canvas.height = Math.round(img.height * scale);
        canvas.getContext("2d").drawImage(img, 0, 0, canvas.width, canvas.height);
        resolve(canvas.toDataURL("image/jpeg", quality));
      };
      img.onerror = reject;
      img.src = reader.result;
    };
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });
}

/* ================= UI compartida ================= */

function Badge({ label, map }) {
  const s = (map || STATE_STYLE)[label] || { bg: "#EBE6E0", fg: "#7A6E63" };
  return <span style={{ background: s.bg, color: s.fg }} className="inline-block px-2.5 py-0.5 rounded-full text-xs font-bold whitespace-nowrap transition-colors">{label}</span>;
}

function Card({ children, className = "", onClick, style, ...props }) {
  function keyDown(e) {
    if (!onClick || !["Enter", " "].includes(e.key)) return;
    e.preventDefault();
    vibrar("tap");
    onClick(e);
  }
  return (
    <div {...props} onClick={onClick} onKeyDown={keyDown} role={onClick ? "button" : props.role} tabIndex={onClick ? 0 : props.tabIndex}
      style={{ background: T.surface, borderColor: T.border, ...style }}
      className={`rounded-2xl border shadow-sm ${onClick ? "momo-card-action" : ""} ${className}`}>
      {children}
    </div>
  );
}

function CountUp({ value, format }) {
  const target = Number(value) || 0;
  const reduce = typeof window !== "undefined" && window.matchMedia && window.matchMedia("(prefers-reduced-motion: reduce)").matches;
  const [shown, setShown] = useState(reduce ? target : 0);
  const rafRef = useRef(0);
  useEffect(() => {
    if (reduce) { setShown(target); return; }
    const t0 = performance.now();
    const dur = 640;
    const step = (t) => {
      const p = Math.min(1, (t - t0) / dur);
      setShown(target * (1 - Math.pow(1 - p, 3)));
      if (p < 1) rafRef.current = requestAnimationFrame(step);
    };
    setShown(0);
    rafRef.current = requestAnimationFrame(step);
    return () => cancelAnimationFrame(rafRef.current);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [target]);
  const n = Math.round(shown);
  return <>{format ? format(n) : n}</>;
}

function Stat({ icon, label, value, sub, tone, onClick, active }) {
  return (
    <Card className="p-4 flex flex-col gap-1 min-w-0 transition" onClick={onClick}
      aria-pressed={active === undefined ? undefined : !!active}
      style={active ? { borderColor: tone || T.coral, background: "#FFFBF7", boxShadow: `0 0 0 2px ${tone || T.coral}33, 0 10px 22px rgba(84,56,43,.08)` } : undefined}>
      <div className="flex items-center gap-2 text-xs font-bold" style={{ color: T.choco2 }}>
        <span aria-hidden="true">{icon}</span><span className="truncate">{label}</span>
      </div>
      <div className="display text-2xl font-semibold" style={{ color: tone || T.choco, fontVariantNumeric: "tabular-nums" }}>{value}</div>
      {sub && <div className="text-xs" style={{ color: T.choco2 }}>{sub}</div>}
    </Card>
  );
}

function SectionTitle({ children, action }) {
  return (
    <div className="flex items-center justify-between gap-3 mb-3 mt-6 first:mt-0">
      <h2 className="display text-lg font-semibold m-0">{children}</h2>
      {action}
    </div>
  );
}

function WorkScopeTabs({ value, onChange, activeCount, historyCount, activeLabel = "En curso", secondaryLabel = "Historial", activeIcon = "●", secondaryIcon = "◷", ariaLabel = "Vista de trabajo e historial" }) {
  const options = [
    { id: "active", label: activeLabel, count: activeCount, icon: activeIcon },
    { id: "history", label: secondaryLabel, count: historyCount, icon: secondaryIcon },
  ];
  return (
    <div className="inline-flex rounded-2xl border p-1" style={{ borderColor: T.border, background: T.vainilla }} role="tablist" aria-label={ariaLabel}>
      {options.map((option) => {
        const selected = value === option.id;
        return (
          <button key={option.id} type="button" role="tab" aria-selected={selected} onClick={() => onChange(option.id)}
            className="rounded-xl px-3 py-2 text-xs font-extrabold transition flex items-center gap-2"
            style={{ background: selected ? T.surface : "transparent", color: selected ? T.choco : T.choco2, boxShadow: selected ? "0 3px 10px rgba(84,56,43,.10)" : "none" }}>
            <span aria-hidden="true" style={{ color: selected ? T.coral : T.choco2 }}>{option.icon}</span>
            <span>{option.label}</span>
            <span className="min-w-5 h-5 px-1 rounded-full inline-flex items-center justify-center text-[10px]" style={{ background: selected ? T.coralSoft : "rgba(255,255,255,.72)", color: selected ? "#A94D34" : T.choco2 }}>{option.count}</span>
          </button>
        );
      })}
    </div>
  );
}

function textoOperacion(children) {
  if (typeof children !== "string") return "Procesando…";
  const t = children.trim().toLowerCase();
  if (t.includes("foto") || t.includes("evidencia")) return "Procesando foto…";
  if (t.startsWith("crear")) return "Creando…";
  if (t.startsWith("guardar")) return "Guardando…";
  if (t.startsWith("registr")) return "Registrando…";
  if (t.startsWith("actualiz")) return "Actualizando…";
  if (t.startsWith("marcar pagado")) return "Confirmando pago…";
  if (t.startsWith("marcar")) return "Confirmando…";
  if (t.startsWith("pasar a")) return "Cambiando estado…";
  if (t.includes("congelamiento")) return "Iniciando frío…";
  if (t.includes("entrega")) return "Confirmando entrega…";
  if (t.includes("convertir")) return "Convirtiendo…";
  if (t.includes("pausar")) return "Pausando…";
  if (t.includes("programar")) return "Programando…";
  return "Procesando…";
}

function Btn({ children, onClick, kind = "primary", small, disabled, type = "button", managed = false, busy = false, busyText, confirming = false }) {
  const [autoBusy, setAutoBusy] = useState(false);
  const vivoRef = useRef(true);
  useEffect(() => { vivoRef.current = true; return () => { vivoRef.current = false; }; }, []);
  const styles = {
    primary: { background: T.coral, color: "#fff", border: "1px solid " + T.coral },
    soft: { background: T.coralSoft, color: "#A34A2A", border: "1px solid #F3CDBE" },
    ghost: { background: "transparent", color: T.choco, border: "1px solid " + T.border },
    rosa: { background: T.rosa, color: "#8E4B5A", border: "1px solid #E9BFC7" },
    danger: { background: "#F6D4CD", color: "#A03B2A", border: "1px solid #ECBBB1" },
  }[kind];
  const enVuelo = busy || autoBusy;
  const bloqueado = disabled || enVuelo;
  function click(e) {
    if (!onClick || bloqueado) return;
    let result;
    try { result = onClick(e); }
    catch (err) { toast("error", err?.message || "No se pudo completar la acción"); return; }
    if (!managed && result && typeof result.then === "function") {
      setAutoBusy(true);
      Promise.resolve(result)
        .catch((err) => toast("error", err?.message || "No se pudo completar la acción"))
        .finally(() => { if (vivoRef.current) setAutoBusy(false); });
    }
  }
  return (
    <button type={type} onClick={click} disabled={bloqueado} aria-busy={enVuelo || undefined} data-confirming={confirming || undefined}
      style={{ ...styles, opacity: bloqueado ? 0.62 : 1 }}
      className={`momo-btn rounded-xl font-bold ${small ? "px-3 py-1.5 text-xs" : "px-4 py-2.5 text-sm"} focus-visible:outline focus-visible:outline-2 focus-visible:outline-offset-2`}>
      {autoBusy
        ? <span className="inline-flex items-center gap-1.5" aria-live="polite"><span className="momo-busy-spinner inline-block w-3.5 h-3.5 rounded-full border-2 border-current border-t-transparent" aria-hidden="true" />{busyText || textoOperacion(children)}</span>
        : children}
    </button>
  );
}

/* ── Juice v1: feedback táctil de acciones (spec engram momos/juice-v1-spec) ── */
// Vibración háptica: solo Android/Chrome — iOS Safari no soporta la Vibration API,
// ahí el juice queda visual (degradación silenciosa, jamás rompe).
function vibrar(tipo) {
  try {
    if (!("vibrate" in navigator)) return;
    navigator.vibrate(tipo === "ok" ? [30, 60, 30] : tipo === "alert" ? [45, 70, 45] : tipo === "error" ? 120 : 30);
  } catch { /* nunca romper por vibrar */ }
}

// Bus a nivel módulo: toast() se puede llamar desde cualquier componente sin
// enhebrar props por el monolito; <Toasts/> (montado una vez en el shell) se registra.
let _pushToast = null;
function toast(tipo, texto) {
  vibrar(tipo);
  if (_pushToast) _pushToast({ tipo, texto });
}

function Toasts() {
  const [items, setItems] = useState([]);
  const idRef = useRef(0);
  useEffect(() => {
    _pushToast = (t) => {
      const id = ++idRef.current;
      setItems((xs) => [...xs.slice(-2), { ...t, id }]);
      setTimeout(() => setItems((xs) => xs.filter((x) => x.id !== id)), t.tipo === "error" || t.tipo === "alert" ? 6000 : 3500);
    };
    return () => { _pushToast = null; };
  }, []);
  if (!items.length) return null;
  return (
    <div className="fixed left-1/2 -translate-x-1/2 bottom-20 md:bottom-6 z-[60] flex flex-col gap-2 items-center w-[calc(100%-2rem)] max-w-md pointer-events-none" aria-live="polite" aria-atomic="false">
      {items.map((t) => (
        <div key={t.id} className="momo-toast w-full rounded-2xl px-4 py-3 border flex items-center gap-3" role={t.tipo === "error" ? "alert" : "status"}
          style={{ "--toast-life": t.tipo === "error" || t.tipo === "alert" ? "6000ms" : "3500ms", ...(t.tipo === "error"
            ? { background: "#F6D4CD", color: "#A03B2A", borderColor: "#ECBBB1" }
            : t.tipo === "alert"
              ? { background: "#FFF4E0", color: "#7A5410", borderColor: "#E7C078" }
            : { background: "#E3EFE0", color: "#3F6B42", borderColor: "#BFD8BE" }) }}>
          <span className="momo-toast-icon w-8 h-8 rounded-full flex items-center justify-center shrink-0 text-base font-black"
            style={{ background: t.tipo === "error" ? "#fff7f5" : "#fff" }} aria-hidden="true">{t.tipo === "error" ? "!" : t.tipo === "alert" ? "🔔" : "✓"}</span>
          <span className="min-w-0">
            <span className="block text-[10px] uppercase tracking-[.12em] font-extrabold opacity-70">{t.tipo === "error" ? "Revisá esto" : t.tipo === "alert" ? "Aviso de cocina" : "Acción completada"}</span>
            <span className="block text-sm font-bold leading-snug">{t.texto}</span>
          </span>
          <span className="momo-toast-progress" aria-hidden="true" />
        </div>
      ))}
    </div>
  );
}

// Botón que escribe: estado en vuelo (spinner + disabled) + vibración al tocar.
// `confirmar` (irreversibles): primer toque arma la confirmación 4 s, segundo ejecuta.
// El guard real es el ref (el estado es solo feedback visual) — patrón de la casa.
function BtnAsync({ children, onClick, kind, small, disabled, confirmar, textoEnVuelo = "Guardando…" }) {
  const [enVuelo, setEnVuelo] = useState(false);
  const [pideConfirmar, setPideConfirmar] = useState(false);
  const vueloRef = useRef(false);
  const vivoRef = useRef(true);
  // vivo se re-arma en el CUERPO del efecto: bajo StrictMode el ciclo
  // mount→cleanup→remount reusa el ref y un cleanup solo lo dejaría en false.
  useEffect(() => { vivoRef.current = true; return () => { vivoRef.current = false; }; }, []);
  useEffect(() => {
    if (!pideConfirmar) return;
    const t = setTimeout(() => { if (vivoRef.current) setPideConfirmar(false); }, 4000);
    return () => clearTimeout(t);
  }, [pideConfirmar]);
  async function click() {
    if (vueloRef.current) return;
    if (confirmar && !pideConfirmar) { vibrar("tap"); setPideConfirmar(true); return; }
    setPideConfirmar(false);
    vibrar("tap");
    vueloRef.current = true;
    setEnVuelo(true);
    try {
      await onClick();
    } catch (err) {
      toast("error", err?.message || "No se pudo completar la acción");
    } finally {
      vueloRef.current = false;
      if (vivoRef.current) setEnVuelo(false);
    }
  }
  return (
    <Btn managed busy={enVuelo} confirming={pideConfirmar} kind={pideConfirmar ? "danger" : kind} small={small} disabled={disabled} onClick={click}>
      {enVuelo
        ? <span className="inline-flex items-center gap-1.5" aria-live="polite"><span className="momo-busy-spinner inline-block w-3 h-3 rounded-full border-2 border-current border-t-transparent" aria-hidden="true" />{textoEnVuelo}</span>
        : pideConfirmar ? (typeof confirmar === "string" ? confirmar : "¿Seguro? Tocá de nuevo") : children}
    </Btn>
  );
}

const modalStack = [];

function Modal({ title, onClose, children, wide, topLayer = false }) {
  const modalIdRef = useRef(Symbol("momo-modal"));
  const onCloseRef = useRef(onClose);
  onCloseRef.current = onClose;
  useEffect(() => {
    const modalId = modalIdRef.current;
    modalStack.push(modalId);
    function cerrarConEscape(e) {
      if (e.key === "Escape" && modalStack[modalStack.length - 1] === modalId) onCloseRef.current();
    }
    window.addEventListener("keydown", cerrarConEscape);
    return () => {
      window.removeEventListener("keydown", cerrarConEscape);
      const index = modalStack.lastIndexOf(modalId);
      if (index >= 0) modalStack.splice(index, 1);
    };
  }, []);
  return (
    <div className={`fixed inset-0 ${topLayer ? "z-[70]" : "z-50"} flex items-end sm:items-center justify-center p-0 sm:p-6`} role="dialog" aria-modal="true">
      <div className="momo-modal-backdrop absolute inset-0" style={{ background: "rgba(60,40,30,.45)" }} onClick={onClose} />
      <div style={{ background: T.bg }} className={`momo-modal-sheet relative w-full ${wide ? "sm:max-w-3xl" : "sm:max-w-lg"} max-h-[92vh] overflow-y-auto rounded-t-3xl sm:rounded-3xl shadow-xl`}>
        <div className="sticky top-0 z-10 flex items-center justify-between px-5 py-4 border-b" style={{ background: T.bg, borderColor: T.border }}>
          <h3 className="display text-lg font-semibold m-0">{title}</h3>
          <button type="button" onClick={(e) => { e.stopPropagation(); onClose(); }} aria-label="Cerrar" className="momo-btn w-9 h-9 rounded-full font-bold" style={{ background: T.surface, border: "1px solid " + T.border, color: T.choco }}>✕</button>
        </div>
        <div className="p-5">{children}</div>
      </div>
    </div>
  );
}

function GlobalKitchenOrderAlerts({ db, perfil, refrescar, serverDataReady, onOpenProduction, onOpenPacking }) {
  const operationalRoles = normalizeRoles(perfil);
  const operationalRolesKey = operationalRoles.join("|");
  const canSeeKitchenCommands = hasAnyRole(operationalRoles, ["Administrador", "Cocina"]);
  const canSeePackingCommands = hasAnyRole(operationalRoles, ["Administrador", "Empaque"]);
  const orderAlertsEnabled = canReceiveKitchenOrderAlerts(operationalRoles);
  const delayAlertsEnabled = canReceiveKitchenDelayReminders(operationalRoles);
  const incidentAlertsEnabled = Boolean(db?.operationalControlReady);
  const enabled = orderAlertsEnabled || delayAlertsEnabled || incidentAlertsEnabled;
  const [dialogMode, setDialogMode] = useState(null);
  const [incomingAlerts, setIncomingAlerts] = useState([]);
  const [unreadCount, setUnreadCount] = useState(0);
  const [delayClock, setDelayClock] = useState(() => Date.now());
  const knownOrderStatesRef = useRef(new Map());
  const alertsReadyRef = useRef(false);
  const delayReminderKeysRef = useRef(new Set());
  const refreshOrdersRef = useRef(refrescar);
  const watcherNameRef = useRef(null);
  refreshOrdersRef.current = refrescar;
  if (!watcherNameRef.current) watcherNameRef.current = `momoops-global-orders-${voiceCommandKey()}`;

  const catalogs = useMemo(() => ({
    customers: db?.customers || [],
    products: db?.products || [],
    orders: db?.orders || [],
    orderItems: db?.order_items || [],
    auditLogs: db?.audit_logs || [],
  }), [db?.customers, db?.products, db?.orders, db?.order_items, db?.audit_logs]);
  const delayTiming = useMemo(() => normalizeKitchenDelaySettings(db?.settings), [db?.settings]);
  const readyCommands = useMemo(() => canSeeKitchenCommands ? kitchenReadyOrderCommands(catalogs) : [], [canSeeKitchenCommands, catalogs]);
  const packingCommands = useMemo(() => canSeePackingCommands ? (db?.orders || [])
    .filter((order) => order?.id && order.estado === "Listo para empaque")
    .map((order) => ({ ...kitchenOrderAlert(order, catalogs, { eventType: "ready_for_packing" }), date: order.fecha || "", time: order.hora || "" })) : [], [canSeePackingCommands, catalogs, db?.orders]);
  const operationalCommands = useMemo(() => [...readyCommands, ...packingCommands], [readyCommands, packingCommands]);
  const delayReminders = useMemo(() => delayAlertsEnabled ? kitchenDelayedOrderReminders(catalogs, delayClock, delayTiming) : [], [delayAlertsEnabled, catalogs, delayClock, delayTiming]);
  const operationalIncidents = useMemo(() => incidentAlertsEnabled ? (db?.order_incidents || []).filter((incident) => {
    if (incident.status !== "Abierto") return false;
    if (hasAnyRole(operationalRoles, ["Administrador", "Coordinador de pedidos"])) return true;
    if (incident.area === "Recepción") return hasRole(operationalRoles, "Cajero");
    return canOperateStage(operationalRoles, incident.area);
  }) : [], [incidentAlertsEnabled, db?.order_incidents, operationalRolesKey]);

  useEffect(() => {
    const orders = db?.orders || [];
    if (!orderAlertsEnabled || !serverDataReady || !alertsReadyRef.current) {
      knownOrderStatesRef.current = new Map(orders.filter((order) => order?.id).map((order) => [order.id, order.estado || ""]));
      alertsReadyRef.current = Boolean(orderAlertsEnabled && serverDataReady);
      return;
    }

    const detected = kitchenOrderStateEvents(orders, knownOrderStatesRef.current);
    knownOrderStatesRef.current = detected.nextStates;
    const alerts = detected.events.slice().reverse().filter(({ type }) => type === "ready_for_packing"
      ? canSeePackingCommands
      : canSeeKitchenCommands).map(({ order, type }) => {
      const alert = kitchenOrderAlert(order, catalogs, { eventType: type });
      return alert ? {
        ...alert,
        detectedAt: new Date().toLocaleTimeString("es-CO", { hour: "2-digit", minute: "2-digit" }),
      } : null;
    }).filter(Boolean);
    if (!alerts.length) return;

    setIncomingAlerts((current) => [...current, ...alerts]);
    setUnreadCount((current) => current + alerts.length);
    setDialogMode("events");
    const actionable = alerts.filter((alert) => alert.canPrepare || alert.canPack).length;
    toast("alert", alerts.length === 1
      ? alerts[0].canPack ? `Pedido ${alerts[0].orderId} · listo para Empaque` : actionable ? `Pedido ${alerts[0].orderId} pagado · listo para cocina` : `Entró el pedido ${alerts[0].orderId} · revisá la comanda`
      : `Entraron ${alerts.length} avisos operativos · ${actionable} requieren acción`);
  }, [orderAlertsEnabled, canSeeKitchenCommands, canSeePackingCommands, serverDataReady, db?.orders, db?.order_items, db?.customers, db?.products]);

  useEffect(() => {
    if (!delayAlertsEnabled || !serverDataReady) return undefined;
    const timer = setInterval(() => setDelayClock(Date.now()), 60000);
    return () => clearInterval(timer);
  }, [delayAlertsEnabled, serverDataReady]);

  useEffect(() => {
    if (!delayAlertsEnabled || !serverDataReady || !delayReminders.length) return;
    const fresh = delayReminders.filter((reminder) => {
      const key = `${reminder.orderId}:${reminder.state}:${reminder.since}:${reminder.thresholdMinutes}:${reminder.urgentMinutes}:${reminder.repeatMinutes}:${reminder.repeatBucket}`;
      if (delayReminderKeysRef.current.has(key)) return false;
      delayReminderKeysRef.current.add(key);
      return true;
    });
    if (!fresh.length) return;
    setUnreadCount((current) => current + fresh.length);
    setDialogMode("delays");
    const urgent = fresh.filter((reminder) => reminder.urgent);
    const lead = urgent[0] || fresh[0];
    toast(urgent.length ? "error" : "alert", fresh.length === 1
      ? `${lead.orderId} lleva ${lead.elapsedMinutes} min en ${lead.area} · revisalo ahora`
      : `${fresh.length} pedidos demorados · ${urgent.length} urgentes`);
  }, [delayAlertsEnabled, serverDataReady, delayReminders]);

  useEffect(() => {
    if (!enabled || !serverDataReady) return undefined;
    let refreshTimer = null;
    let disposed = false;
    const requestOrderRefresh = () => {
      if (disposed || refreshTimer) return;
      refreshTimer = setTimeout(async () => {
        refreshTimer = null;
        if (disposed) return;
        try { await refreshOrdersRef.current?.(); } catch { /* el sondeo vuelve a intentar */ }
      }, 650);
    };
    const channel = supabase
      .channel(watcherNameRef.current)
      .on("postgres_changes", { event: "*", schema: "public", table: "orders" }, requestOrderRefresh)
      .subscribe();
    const poll = setInterval(async () => {
      if (disposed || document.visibilityState !== "visible") return;
      const { data, error } = await supabase
        .from("orders")
        .select("id,estado,fecha,hora")
        .order("fecha", { ascending: false })
        .order("hora", { ascending: false })
        .limit(25);
      if (!error && (data || []).some((order) => order?.id
        && (!knownOrderStatesRef.current.has(order.id) || knownOrderStatesRef.current.get(order.id) !== (order.estado || "")))) requestOrderRefresh();
    }, 15000);
    return () => {
      disposed = true;
      if (refreshTimer) clearTimeout(refreshTimer);
      clearInterval(poll);
      supabase.removeChannel(channel);
    };
  }, [enabled, serverDataReady]);

  if (!enabled) return null;

  function closeDialog() {
    setDialogMode(null);
    if (dialogMode === "events") setIncomingAlerts([]);
    setUnreadCount(0);
  }

  function openAlertCenter() {
    setDialogMode(operationalIncidents.length ? "incidents" : delayReminders.length ? "delays" : incomingAlerts.length ? "events" : "commands");
    setUnreadCount(0);
  }

  function goToProduction() {
    closeDialog();
    onOpenProduction?.();
  }

  function goToPacking() {
    closeDialog();
    onOpenPacking?.();
  }

  const showsEvents = dialogMode === "events";
  const showsDelays = dialogMode === "delays";
  const showsIncidents = dialogMode === "incidents";
  const urgentDelayCount = delayReminders.filter((reminder) => reminder.urgent).length;
  const delayedKitchenCount = delayReminders.filter((reminder) => reminder.area === "Cocina").length;
  const delayedPackingCount = delayReminders.filter((reminder) => reminder.area === "Empaque").length;
  const visibleCount = unreadCount || operationalCommands.length + delayReminders.length + operationalIncidents.length;
  const buttonTone = operationalIncidents.length || urgentDelayCount
    ? { background: "#A03B2A", borderColor: "#A03B2A", color: "#fff" }
    : delayReminders.length
      ? { background: "#96690F", borderColor: "#96690F", color: "#fff" }
      : operationalCommands.length || unreadCount
        ? { background: T.coral, borderColor: T.coral, color: "#fff" }
        : { background: "#fff", borderColor: T.border, color: T.choco };
  return (
    <>
      <button type="button" onClick={openAlertCenter}
        className="momo-btn momo-kitchen-alert-fab rounded-2xl px-3 py-2.5 border flex items-center gap-2 shadow-lg"
        aria-label={`Abrir seguimiento operativo. ${operationalCommands.length} ${operationalCommands.length === 1 ? "comanda" : "comandas"} requieren acción, ${delayReminders.length} ${delayReminders.length === 1 ? "pedido demorado" : "pedidos demorados"} y ${operationalIncidents.length} ${operationalIncidents.length === 1 ? "novedad abierta" : "novedades abiertas"}${unreadCount ? `; ${unreadCount} ${unreadCount === 1 ? "aviso nuevo" : "avisos nuevos"}` : ""}`}
        style={buttonTone}>
        <span className="text-xl" aria-hidden="true">🔔</span>
        <span className="hidden sm:block text-left leading-tight">
          <span className="block text-[9px] uppercase tracking-[.12em] font-extrabold opacity-75">Seguimiento operativo</span>
          <span className="block text-xs font-extrabold">{operationalIncidents.length ? `${operationalIncidents.length} novedad${operationalIncidents.length === 1 ? "" : "es"}` : urgentDelayCount ? `${urgentDelayCount} urgente${urgentDelayCount === 1 ? "" : "s"}` : delayReminders.length ? `${delayReminders.length} con demora` : operationalCommands.length ? `${operationalCommands.length} por atender` : "Todo al día"}</span>
        </span>
        <span className="min-w-7 h-7 px-2 rounded-full flex items-center justify-center text-xs font-black"
          style={{ background: visibleCount ? "#fff" : T.vainilla, color: urgentDelayCount ? "#A03B2A" : delayReminders.length ? "#96690F" : visibleCount ? T.coral : T.choco2 }}>
          {visibleCount}
        </span>
      </button>

      {dialogMode && (
        <Modal title={showsIncidents ? "⚠️ Novedades que bloquean pedidos" : showsDelays ? "⏱️ Pedidos demorados" : showsEvents ? "🔔 Nuevo aviso operativo" : "🧾 Comandas por atender"} wide topLayer onClose={closeDialog}>
          <div className="rounded-xl p-3 mb-4 border" role="status" aria-live="assertive"
            style={{ background: T.soft, borderColor: T.border, color: T.choco }}>
            <div className="text-[10px] uppercase tracking-[.14em] font-extrabold" style={{ color: T.choco2 }}>{showsIncidents ? "Centro de excepciones" : showsDelays ? "Seguimiento vivo de la operación" : "Relevo entre áreas"}</div>
            <div className="font-bold mt-0.5">{showsIncidents ? "Estas novedades detienen el avance hasta que el área responsable las resuelva." : showsDelays ? "MOMO OPS recuerda las órdenes que no han avanzado a tiempo." : "MOMO OPS conecta Caja, Cocina y Empaque sin perder la comanda."}</div>
            <div className="text-xs font-semibold mt-1" style={{ color: T.choco2 }}>{showsDelays
              ? `Cocina cuenta desde el pago confirmado: avisa a los ${delayTiming.demoraCocinaMin} min y es urgente a los ${delayTiming.demoraCocinaUrgenteMin}; Empaque avisa desde ${delayTiming.demoraEmpaqueMin} min y es urgente desde ${delayTiming.demoraEmpaqueUrgenteMin}. Repite cada ${delayTiming.demoraRepeticionMin} min.`
              : "El aviso no depende de Momobot: Cocina recibe pagos confirmados y Empaque recibe pedidos terminados por Cocina."}</div>
            {showsDelays && <div className="flex flex-wrap gap-1.5 mt-2">
              <span className="rounded-full px-2.5 py-1 text-[10px] font-extrabold" style={{ background: "#DCE7F2", color: "#3E5C7E" }}>Cocina · {delayedKitchenCount}</span>
              <span className="rounded-full px-2.5 py-1 text-[10px] font-extrabold" style={{ background: "#E8E0F2", color: "#63518A" }}>Empaque · {delayedPackingCount}</span>
              {urgentDelayCount > 0 && <span className="rounded-full px-2.5 py-1 text-[10px] font-extrabold" style={{ background: "#F6D4CD", color: "#A03B2A" }}>Urgentes · {urgentDelayCount}</span>}
            </div>}
          </div>

          {showsIncidents ? (
            <div className="space-y-3">
              {operationalIncidents.map((incident) => (
                <Card key={incident.id} className="p-4" style={{ borderColor: "#E3A292" }}>
                  <div className="flex items-start justify-between gap-3">
                    <div><div className="text-[10px] uppercase tracking-[.12em] font-extrabold" style={{ color: "#A03B2A" }}>{incident.area} · {incident.type}</div><div className="display text-lg font-semibold">Pedido {incident.orderId}</div></div>
                    <span className="rounded-full px-2.5 py-1 text-[10px] font-extrabold" style={{ background: "#F8D6CF", color: "#A03B2A" }}>Bloqueado</span>
                  </div>
                  <div className="text-sm font-semibold mt-2">{incident.description}</div>
                  <div className="text-[10px] font-bold mt-1" style={{ color: T.choco2 }}>{incident.createdByName || "Equipo"} · {incident.createdAt}</div>
                  {incident.area === "Cocina" && <div className="mt-3"><Btn small onClick={goToProduction}>Abrir Producción</Btn></div>}
                  {incident.area === "Empaque" && <div className="mt-3"><Btn small onClick={goToPacking}>Abrir Empaque</Btn></div>}
                </Card>
              ))}
            </div>
          ) : showsDelays ? (
            <div className="space-y-3">
              {delayReminders.map((reminder) => (
                <Card key={`${reminder.orderId}-${reminder.state}`} className="p-4">
                  <div className="flex items-start justify-between gap-3">
                    <div className="min-w-0">
                      <div className="text-[10px] uppercase tracking-[.12em] font-extrabold" style={{ color: reminder.urgent ? "#A03B2A" : T.choco2 }}>{reminder.urgent ? "Urgente · actuar ahora" : "Recordatorio · revisar"}</div>
                      <div className="display text-lg font-semibold">Pedido {reminder.orderId}</div>
                      {reminder.customerName && <div className="text-xs font-bold mt-0.5" style={{ color: T.choco2 }}>Cliente: {reminder.customerName}</div>}
                    </div>
                    <div className="text-right shrink-0">
                      <div className="display text-xl font-bold leading-none" style={{ color: reminder.urgent ? "#A03B2A" : T.choco }}>{reminder.elapsedMinutes} min</div>
                      <div className="text-[9px] uppercase tracking-wider font-extrabold max-w-28" style={{ color: T.choco2 }}>{reminder.phase || `en ${reminder.area}`}</div>
                    </div>
                  </div>
                  <div className="mt-2 pl-3 border-l-2" style={{ borderColor: T.rosa }}>
                    <div className="text-[10px] font-bold mb-1" style={{ color: T.choco2 }}>COMANDA</div>
                    <div className="text-sm" style={{ color: T.choco }}>{reminder.content}</div>
                  </div>
                  <div className="text-xs font-extrabold mt-2" style={{ color: reminder.urgent ? "#A03B2A" : T.choco2 }}>{reminder.nextAction}</div>
                </Card>
              ))}
            </div>
          ) : showsEvents ? (
            <div className="space-y-3">
              {incomingAlerts.map((alert, index) => (
                <Card key={`${alert.orderId}-${alert.eventType}-${index}`} className="p-4">
                  <div className="flex items-start justify-between gap-3">
                    <div className="min-w-0">
                      <div className="text-[10px] uppercase tracking-[.12em] font-extrabold"
                        style={{ color: alert.canPrepare ? "#3F6B42" : alert.canPack ? "#A54830" : T.choco2 }}>
                        {alert.eventType === "ready_for_packing" ? "Cocina terminó" : alert.eventType === "paid" ? "Pago confirmado" : "Pedido nuevo"} · {alert.detectedAt}
                      </div>
                      <div className="display text-lg font-semibold mt-0.5">Pedido {alert.orderId}</div>
                      {alert.customerName && <div className="text-xs font-bold mt-0.5" style={{ color: T.choco2 }}>Cliente: {alert.customerName}</div>}
                    </div>
                    <span className="rounded-full px-2.5 py-1 text-[10px] uppercase tracking-wider font-extrabold shrink-0"
                      style={{ background: alert.canPrepare ? "#DDEBD9" : alert.canPack ? "#FBE3DA" : "#FBE8C8", color: alert.canPrepare ? "#3F6B42" : alert.canPack ? "#A54830" : "#96690F" }}>
                      {alert.canPrepare ? "✓ Pagado" : alert.canPack ? "→ Empaque" : alert.state || "Pendiente"}
                    </span>
                  </div>
                  <div className="mt-2 pl-3 border-l-2" style={{ borderColor: T.rosa }}>
                    <div className="text-[10px] font-bold mb-1" style={{ color: T.choco2 }}>COMANDA</div>
                    <div className="text-sm" style={{ color: T.choco }}>{alert.content}</div>
                  </div>
                  <div className="text-xs font-extrabold mt-2" style={{ color: alert.canPrepare ? "#3F6B42" : alert.canPack ? "#A54830" : "#A03B2A" }}>
                    {alert.canPrepare ? "✓ Cocina o Administración pueden iniciar esta comanda." : alert.canPack ? "✓ Empaque o Administración pueden tomarla y confirmar Empacado." : "⏳ Pedido recibido: todavía no preparar hasta confirmar el pago."}
                  </div>
                </Card>
              ))}
            </div>
          ) : operationalCommands.length ? (
            <div className="space-y-3">
              <div className="text-xs font-bold" style={{ color: T.choco2 }}>Ordenadas de la más antigua a la más reciente.</div>
              {operationalCommands.map((command, index) => (
                <Card key={command.orderId} className="p-4">
                  <div className="flex items-start justify-between gap-3">
                    <div className="min-w-0">
                      <div className="text-[10px] uppercase tracking-[.12em] font-extrabold" style={{ color: command.canPack ? "#A54830" : "#3F6B42" }}>Comanda {index + 1} · {command.canPack ? "lista para Empaque" : "lista para Cocina"}</div>
                      <div className="display text-lg font-semibold mt-0.5">Pedido {command.orderId}</div>
                      {command.customerName && <div className="text-xs font-bold mt-0.5" style={{ color: T.choco2 }}>Cliente: {command.customerName}</div>}
                    </div>
                    <span className="rounded-full px-2.5 py-1 text-[10px] uppercase tracking-wider font-extrabold shrink-0" style={{ background: command.canPack ? "#FBE3DA" : "#DDEBD9", color: command.canPack ? "#A54830" : "#3F6B42" }}>{command.canPack ? "→ Empaque" : "✓ Pagado"}</span>
                  </div>
                  <div className="mt-2 pl-3 border-l-2" style={{ borderColor: T.rosa }}>
                    <div className="text-[10px] font-bold mb-1" style={{ color: T.choco2 }}>COMANDA</div>
                    <div className="text-sm" style={{ color: T.choco }}>{command.content}</div>
                  </div>
                  {(command.date || command.time) && <div className="text-[10px] font-bold mt-2" style={{ color: T.choco2 }}>Recibido: {[command.date, command.time].filter(Boolean).join(" · ")}</div>}
                </Card>
              ))}
            </div>
          ) : (
            <div className="rounded-2xl p-7 text-center border" style={{ background: T.soft, borderColor: T.border }}>
              <div className="text-3xl mb-2" aria-hidden="true">✅</div>
              <div className="font-extrabold">No hay comandas pagadas esperando iniciar.</div>
              <div className="text-xs font-semibold mt-1" style={{ color: T.choco2 }}>MOMO OPS abrirá esta ventana apenas entre un pedido nuevo o se confirme su pago.</div>
            </div>
          )}

          <div className="mt-5 flex flex-wrap justify-end gap-2">
            <Btn kind="ghost" onClick={closeDialog}>Entendido</Btn>
            {(readyCommands.length > 0 || delayedKitchenCount > 0) && <Btn onClick={goToProduction}>Ir a Producción</Btn>}
            {(packingCommands.length > 0 || delayedPackingCount > 0) && <Btn onClick={goToPacking}>Ir a Empaque</Btn>}
          </div>
        </Modal>
      )}
    </>
  );
}

function CompactQueueOrderCard({ db, orderId, eyebrow, nextAction, content, tone = T.coral, position, onOpen, footer, timing }) {
  const order = (db.orders || []).find((item) => item.id === orderId);
  if (!order) return null;
  const customer = customerOf(db, order.customerId);
  const lines = buildPackingChecklistLines(orderId, db.order_items || []);
  const topLines = lines.filter((line) => !line.parentItemId);
  return (
    <Card className="momo-queue-item p-4 min-h-[188px] flex flex-col" onClick={onOpen} aria-label={`Abrir detalle del pedido ${orderId}`}>
      <div className="flex items-start justify-between gap-3">
        <div className="min-w-0">
          <div className="text-[10px] uppercase tracking-wider font-extrabold" style={{ color: tone }}>{eyebrow}</div>
          <div className="flex flex-wrap items-center gap-2 mt-1"><h3 className="display text-lg font-semibold m-0">{orderId}</h3><Badge label={order.estado} /></div>
        </div>
        {timing ? <div className="text-right shrink-0">
          {timing.urgent && <div className="text-[8px] uppercase tracking-wider font-black" style={{ color: "#A03B2A" }}>Urgente</div>}
          <div className="display text-xl font-bold leading-none" style={{ color: timing.urgent ? "#A03B2A" : "#96690F" }}>{timing.elapsedMinutes}</div>
          <div className="text-[8px] uppercase font-extrabold" style={{ color: T.choco2 }}>min</div>
        </div> : <span className="w-8 h-8 rounded-full flex items-center justify-center text-xs font-black shrink-0" style={{ background: `${tone}18`, color: tone }}>{position || "›"}</span>}
      </div>
      <div className="text-xs font-semibold mt-1 truncate" style={{ color: T.choco2 }}>{customer.nombre || "Cliente"} · {order.fecha} {order.hora}</div>
      {timing && <div className="mt-2 rounded-xl px-2.5 py-1.5 text-[10px] font-extrabold" style={{ background: timing.urgent ? "#F6D4CD" : "#FFF2D8", color: timing.urgent ? "#A03B2A" : "#7A5410" }}>⏱ {timing.elapsedMinutes} min · {timing.phase || timing.state}</div>}
      <div className="mt-3 text-sm font-bold leading-snug line-clamp-2">{content || topLines.map((line) => line.label).join(" · ") || "Sin contenido registrado"}</div>
      <div className="text-[10px] font-semibold mt-1" style={{ color: T.choco2 }}>{topLines.length} línea{topLines.length === 1 ? "" : "s"} principal{topLines.length === 1 ? "" : "es"} · {lines.length} control{lines.length === 1 ? "" : "es"} exacto{lines.length === 1 ? "" : "s"}</div>
      <div className="mt-auto pt-3 flex items-end justify-between gap-3 border-t" style={{ borderColor: T.border }}>
        <div className="min-w-0"><div className="text-[9px] uppercase tracking-wider font-extrabold" style={{ color: tone }}>Siguiente acción</div><div className="text-[11px] font-bold leading-snug mt-0.5">{nextAction}</div>{footer && <div className="text-[10px] font-semibold mt-1" style={{ color: T.choco2 }}>{footer}</div>}</div>
        <span className="text-lg shrink-0" style={{ color: tone }} aria-hidden="true">›</span>
      </div>
    </Card>
  );
}

function KitchenProductionQueue({ db, onOpenOrder, canStart, canReady }) {
  const [delayClock, setDelayClock] = useState(() => Date.now());
  const [scope, setScope] = useState("active");
  useEffect(() => {
    const timer = setInterval(() => setDelayClock(Date.now()), 60000);
    return () => clearInterval(timer);
  }, []);
  const catalogs = useMemo(() => ({
    customers: db?.customers || [],
    products: db?.products || [],
    orders: db?.orders || [],
    orderItems: db?.order_items || [],
    auditLogs: db?.audit_logs || [],
  }), [db?.customers, db?.products, db?.orders, db?.order_items, db?.audit_logs]);
  const commands = useMemo(() => kitchenReadyOrderCommands(catalogs), [catalogs]);
  const inProduction = useMemo(() => (db?.orders || [])
    .filter((order) => order?.id && order.estado === "En producción")
    .slice()
    .sort((left, right) => `${left.fecha || ""}T${left.hora || ""}`.localeCompare(`${right.fecha || ""}T${right.hora || ""}`))
    .map((order) => ({ ...kitchenOrderAlert(order, catalogs), date: order.fecha || "", time: order.hora || "" })), [db?.orders, catalogs]);
  const delayTiming = useMemo(() => normalizeKitchenDelaySettings(db?.settings), [db?.settings]);
  const delayReminders = useMemo(() => kitchenDelayedOrderReminders(catalogs, delayClock, delayTiming), [catalogs, delayClock, delayTiming]);
  const kitchenDelayReminders = delayReminders.filter((reminder) => reminder.area === "Cocina");
  const timingByOrderId = useMemo(() => new Map(kitchenDelayReminders.map((reminder) => [String(reminder.orderId), reminder])), [kitchenDelayReminders]);

  return (
    <section className="mb-5" aria-labelledby="kitchen-queue-title">
      <div className="flex flex-col sm:flex-row sm:items-end justify-between gap-3 mb-4">
        <div className="min-w-0">
          <h2 id="kitchen-queue-title" className="display text-lg font-semibold m-0">Comandas de Cocina</h2>
          <div className="text-xs font-semibold mt-0.5" style={{ color: T.choco2 }}>Del pago confirmado al relevo con Empaque, sin duplicar pedidos en el panel.</div>
        </div>
        <WorkScopeTabs value={scope} onChange={setScope} activeCount={commands.length} historyCount={inProduction.length}
          activeLabel="Cola por iniciar" secondaryLabel="En preparación" activeIcon="●" secondaryIcon="◷" ariaLabel="Etapa de las comandas de Cocina" />
      </div>

      {scope === "active" ? (
        commands.length ? <div className="grid sm:grid-cols-2 xl:grid-cols-3 gap-3">
          {commands.map((command, index) => (
            <CompactQueueOrderCard key={command.orderId} db={db} orderId={command.orderId}
              eyebrow={index === 0 ? "Siguiente · FIFO" : `En cola · #${index + 1}`}
              position={index + 1} tone={index === 0 ? T.coral : "#8E4B5A"} content={command.content}
              nextAction={canStart ? "Abrir, revisar e iniciar la preparación" : "Consultar la comanda; Cocina confirma el inicio"}
              footer={canStart ? "Dentro encontrás Momobot y la confirmación segura." : "Tu rol no altera el estado."}
              timing={timingByOrderId.get(String(command.orderId))}
              onOpen={() => onOpenOrder?.(command.orderId)} />
          ))}
        </div> : <Empty icon="✅" text="No hay pedidos esperando iniciar. Cuando un pedido quede Pagado aparecerá aquí con figura, sabor y contenido." />
      ) : (
        inProduction.length ? <div className="grid sm:grid-cols-2 xl:grid-cols-3 gap-3">
          {inProduction.map((command) => (
            <CompactQueueOrderCard key={command.orderId} db={db} orderId={command.orderId}
              eyebrow="En preparación" tone="#3E5C7E" content={command.content}
              nextAction={canReady ? "Abrir, completar líneas y entregar a Empaque" : "Consultar el avance de Cocina"}
              footer="Empaque ya puede verlo como pedido en camino."
              timing={timingByOrderId.get(String(command.orderId))}
              onOpen={() => onOpenOrder?.(command.orderId)} />
          ))}
        </div> : <Empty icon="👩‍🍳" text="No hay comandas en preparación. Las órdenes iniciadas por Cocina aparecerán aquí hasta su relevo con Empaque." />
      )}
    </section>
  );
}

function KitchenProductionAssistantFab({ plan, unplannedSuggestions = [], formatAmount, onPlanRun, onPrepare }) {
  const [open, setOpen] = useState(false);
  const actionCount = (plan?.plans?.length || 0) + (plan?.preparationNeeds?.length || 0);
  const preparationNeeds = plan?.preparationNeeds || [];
  const productionPlans = plan?.plans || [];

  useEffect(() => {
    if (!open) return undefined;
    const closeOnEscape = (event) => { if (event.key === "Escape") setOpen(false); };
    window.addEventListener("keydown", closeOnEscape);
    return () => window.removeEventListener("keydown", closeOnEscape);
  }, [open]);

  function choosePlan(selectedPlan) {
    setOpen(false);
    onPlanRun?.(selectedPlan);
  }

  function choosePreparation(need) {
    setOpen(false);
    onPrepare?.(need.subrecipeId, need.recommendedGrams);
  }

  return (
    <div className="momo-kitchen-plan-fab" data-open={open ? "true" : "false"}>
      {!open ? (
        <button type="button" onClick={() => setOpen(true)} aria-expanded="false" aria-controls="asistente-cocina-panel"
          data-testid="kitchen-assistant-fab" title={`Asistente de Cocina · ${actionCount} acciones`}
          className="momo-kitchen-plan-orb w-16 h-16 rounded-full flex items-center justify-center text-2xl text-white"
          style={{ background: "#3F6B42" }} aria-label={`Abrir Asistente de Cocina. ${actionCount} recomendaciones`}>
          <span aria-hidden="true">🧠</span>
          <span className="absolute -right-1 -top-1 min-w-6 h-6 px-1 rounded-full flex items-center justify-center text-[10px] font-black border-2"
            style={{ background: T.surface, color: "#3F6B42", borderColor: "#DDEBD9" }}>{actionCount || "✓"}</span>
        </button>
      ) : (
        <>
          <button type="button" className="fixed inset-0 momo-modal-backdrop cursor-default" onClick={() => setOpen(false)}
            style={{ background: "rgba(47,33,27,.22)" }} aria-label="Cerrar panel del Asistente de Cocina" />
          <Card id="asistente-cocina-panel" role="dialog" aria-modal="true" aria-labelledby="asistente-cocina-title"
            data-testid="kitchen-assistant-panel" className="momo-modal-sheet momo-kitchen-plan-panel relative p-0 overflow-hidden w-[min(94vw,920px)] max-h-[calc(100vh-2rem)] shadow-2xl"
            style={{ background: T.bg }}>
            <div className="flex items-center justify-between gap-3 px-4 sm:px-5 py-3 border-b" style={{ borderColor: T.border, background: T.surface }}>
              <div className="flex items-center gap-3 min-w-0">
                <span className="w-9 h-9 rounded-2xl flex items-center justify-center text-lg shrink-0" style={{ background: "#DDEBD9" }} aria-hidden="true">🧠</span>
                <div className="min-w-0"><div className="text-[9px] uppercase tracking-[.18em] font-extrabold" style={{ color: "#3F6B42" }}>MOMO OPS Intelligence</div><div id="asistente-cocina-title" className="font-extrabold truncate">Asistente de Cocina · plan inteligente</div></div>
              </div>
              <button type="button" onClick={() => setOpen(false)} aria-label="Minimizar Asistente de Cocina" title="Minimizar"
                className="w-8 h-8 rounded-full flex items-center justify-center text-sm font-bold border shrink-0" style={{ background: T.surface, borderColor: T.border, color: T.choco2 }}>✕</button>
            </div>

            <div className="overflow-y-auto max-h-[calc(100vh-5.75rem)]">
              <div className="px-4 sm:px-5 py-4 border-b" style={{ background: T.surface, borderColor: T.border }}>
                <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-4">
                  <div className="flex items-start gap-3 min-w-0"><span className="w-10 h-10 rounded-2xl grid place-items-center text-lg shrink-0" style={{ background: "#DDEBD9" }}>🧠</span><div><div className="flex flex-wrap items-center gap-2"><span className="text-[9px] uppercase tracking-[.16em] font-extrabold" style={{ color: "#3F6B42" }}>Asistente de Cocina MOMOS</span><span className="rounded-full px-2 py-0.5 text-[8px] font-extrabold" style={{ background: "#DDEBD9", color: "#315B35" }}>Revisión humana</span></div><div className="display text-xl font-semibold mt-0.5">Qué preparar ahora</div><div className="text-xs mt-1 max-w-2xl leading-relaxed" style={{ color: T.choco2 }}>MOMO OPS ordenó los pedidos y te muestra únicamente lo que conviene preparar primero.</div></div></div>
                  <div className="grid grid-cols-3 gap-2 shrink-0">
                    {[["Corridas", plan?.summary?.runs || 0], ["Unidades", plan?.summary?.units || 0], ["Preparaciones", plan?.summary?.preparations || 0]].map(([label, value]) => (
                      <div key={label} className="rounded-xl px-3 py-2 text-center min-w-[72px]" style={{ background: "#FFFDFC", border: `1px solid ${T.border}` }}><div className="display text-lg font-semibold">{value}</div><div className="text-[8px] uppercase font-extrabold tracking-wider" style={{ color: T.choco2 }}>{label}</div></div>
                    ))}
                  </div>
                </div>
              </div>

              <div className="grid lg:grid-cols-[1.25fr_.75fr] gap-5 p-4 sm:p-5">
                <div>
                  <div className="flex items-end justify-between gap-3 mb-3"><div><div className="text-[10px] uppercase tracking-[.12em] font-extrabold" style={{ color: T.coral }}>Primero</div><div className="display text-lg font-semibold mt-0.5">Lotes recomendados</div></div><div className="text-[10px] font-semibold text-right hidden sm:block" style={{ color: T.choco2 }}>Pedidos pagados<br />en orden</div></div>
                  <div className="space-y-3">
                    {productionPlans.map((productionPlan) => (
                      <div key={productionPlan.id} className="rounded-2xl border p-4" style={{ borderColor: productionPlan.queueUnits > 0 ? "#E9A18F" : T.border, background: T.surface, boxShadow: "0 2px 5px rgba(84,56,43,.07)" }}>
                        <div className="flex flex-col sm:flex-row sm:items-start justify-between gap-3"><div className="min-w-0 flex-1"><div className="flex flex-wrap items-center gap-2"><span className="display text-xl font-semibold">{productionPlan.flavor}</span><Badge label={productionPlan.source} map={{ "Cola + demanda": { bg: "#FBE8C8", fg: "#96690F" }, "Cola pagada": { bg: "#F3D7DC", fg: "#8E4B5A" }, "Demanda proyectada": { bg: "#DDEBD9", fg: "#3F6B42" } }} /><span className="text-[10px] font-extrabold px-2 py-1 rounded-full" style={{ background: T.vainilla, color: T.choco2 }}>Confianza {productionPlan.confidence}</span></div><div className="text-sm font-extrabold mt-2">Producir {productionPlan.totalUnits}: {productionPlan.variants.map((variant) => `${variant.recommended}× ${variant.figure}`).join(" · ")}</div><div className="text-[11px] font-semibold mt-1" style={{ color: T.choco2 }}>{productionPlan.filling || "Sin relleno"} · {productionPlan.queueUnits} en cola · {productionPlan.availableUnits} disponibles · {productionPlan.inProcessUnits} en proceso</div>{productionPlan.suggestionIds.length > 1 && <div className="rounded-xl px-3 py-2 mt-2 text-[11px] font-bold" style={{ background: "#FFF1D6", color: "#7B5410" }}>🔗 MOMOS agrupó {productionPlan.suggestionIds.length} necesidades compatibles en esta corrida.</div>}{productionPlan.attributedUnits > 0 && <div className="text-[11px] font-bold mt-2" style={{ color: "#3E5C7E" }}>📣 {productionPlan.attributedUnits} venta{productionPlan.attributedUnits === 1 ? "" : "s"} atribuida{productionPlan.attributedUnits === 1 ? "" : "s"} a pauta{productionPlan.adSignals.length ? ` · ${productionPlan.adSignals.join(" · ")}` : ""}</div>}</div><Btn small disabled={!productionPlan.canCreate} onClick={() => choosePlan(productionPlan)}>{productionPlan.suggestionIds.length > 1 ? "Crear corrida agrupada" : "Planear lote"}</Btn></div>
                      </div>
                    ))}
                    {productionPlans.length === 0 && <Empty icon="🧠" text="La cocina está cubierta: todavía no hay demanda exacta para recomendar otra corrida." />}
                    {unplannedSuggestions.length > 0 && <div className="rounded-2xl px-4 py-3 text-xs font-bold" style={{ background: "#FFF0DD", color: "#7B5410" }}>⚠ {unplannedSuggestions.length} recomendación{unplannedSuggestions.length === 1 ? "" : "es"} no {unplannedSuggestions.length === 1 ? "tiene" : "tienen"} sabor o figura exacta. MOMOS OPS no las mezclará hasta completar el pedido.</div>}
                  </div>
                </div>

                <div className="lg:border-l lg:pl-5" style={{ borderColor: T.border }}>
                  <div className="text-[10px] uppercase tracking-[.12em] font-extrabold" style={{ color: T.coral }}>Después</div><div className="display text-lg font-semibold mt-0.5 mb-3">Bases que hacen falta</div>
                  <div className="space-y-2">
                    {preparationNeeds.map((need) => (
                      <div key={need.subrecipeId} className="rounded-2xl border p-3" style={{ borderColor: need.severity === "Crítica" ? "#E9A18F" : T.border, background: T.surface, boxShadow: "0 2px 5px rgba(84,56,43,.07)" }}><div className="flex items-start justify-between gap-2"><div><div className="text-[9px] uppercase font-extrabold" style={{ color: need.severity === "Crítica" ? "#A03B2A" : "#96690F" }}>{need.severity === "Crítica" ? "Hace falta ahora" : "Preparar pronto"}</div><div className="font-extrabold mt-0.5">{need.subrecipeName}</div></div><span className="display text-xl" style={{ color: T.coral }}>{need.recommendedGrams} g</span></div><div className="text-[10px] mt-2" style={{ color: T.choco2 }}>Necesitás {formatAmount(need.unit, need.required)} y hay {formatAmount(need.unit, need.current)} disponibles.</div><div className="flex justify-end mt-3"><Btn small kind="soft" onClick={() => choosePreparation(need)}>Preparar {need.recommendedGrams} g</Btn></div></div>
                    ))}
                    {preparationNeeds.length === 0 && <div className="rounded-2xl px-4 py-4 text-xs font-bold" style={{ background: "#E8F1E5", color: "#315D36" }}>✓ Las elaboraciones vigentes cubren el plan y conservan su stock mínimo.</div>}
                  </div>
                  <div className="rounded-xl px-3 py-2.5 text-[10px] font-semibold mt-3 leading-relaxed" style={{ background: T.vainilla, color: T.choco2 }}>Nada se registra hasta que una persona lo confirme.</div>
                </div>
              </div>
            </div>
          </Card>
        </>
      )}
    </div>
  );
}

function KitchenQuickCommand({ db, order, canStart, canReady, busyOrderId, onStart, onReady, onMomobot, onClose, refrescar, perfil }) {
  const customer = customerOf(db, order.customerId);
  const lines = buildPackingChecklistLines(order.id, db.order_items || []);
  const assignment = activeStageAssignment(order.id, "Cocina", db.order_stage_assignments);
  const incidents = openOrderIncidents(order.id, db.order_incidents);
  const [showIssue, setShowIssue] = useState(false);
  const [issue, setIssue] = useState({ type: "Faltante", orderItemId: "", description: "" });
  const [issueBusy, setIssueBusy] = useState("");
  const [feedback, setFeedback] = useState("");
  const canOperateKitchen = canOperateStage(perfil, "Cocina");
  const quickState = kitchenQuickCommandState({ orderStatus: order.estado, lineCount: lines.length, incidentCount: incidents.length });
  const isPaid = quickState.action === "start";
  const isCooking = quickState.action === "ready";

  async function registerIssue() {
    if (issueBusy || issue.description.trim().length < 3) return;
    setIssueBusy("create"); setFeedback("");
    try {
      await crearIncidentePedido({ order_id: order.id, order_item_id: issue.orderItemId || null, area: "Cocina", type: issue.type, description: issue.description.trim() });
      await refrescar();
      setIssue({ type: "Faltante", orderItemId: "", description: "" });
      setShowIssue(false);
      setFeedback("Novedad registrada. La comanda no podrá salir de Cocina hasta resolverla.");
    } catch (error) { setFeedback(error.message); }
    finally { setIssueBusy(""); }
  }

  async function resolveIssue(incidentId) {
    if (issueBusy) return;
    setIssueBusy(incidentId); setFeedback("");
    try {
      await resolverIncidentePedido(incidentId, "Resuelto y validado desde la comanda rápida de Cocina");
      await refrescar();
      setFeedback("Novedad resuelta. Ya podés terminar la comanda si todo está correcto.");
    } catch (error) { setFeedback(error.message); }
    finally { setIssueBusy(""); }
  }

  return (
    <Modal title={`Comanda ${order.id}`} onClose={onClose} wide>
      <div className="flex flex-col sm:flex-row sm:items-start justify-between gap-3 mb-4">
        <div><div className="flex flex-wrap items-center gap-2"><Badge label={order.estado} /><span className="text-xs font-semibold" style={{ color: T.choco2 }}>{order.fecha} · {order.hora}</span></div><div className="display text-2xl font-semibold mt-2">{customer.nombre || "Cliente"}</div><div className="text-xs font-semibold" style={{ color: T.choco2 }}>{customer.telefono || "Sin teléfono"}{order.obs ? ` · ${order.obs}` : ""}</div></div>
        <div className="rounded-2xl px-3 py-2 border shrink-0" style={{ background: assignment ? "#F2F8F0" : T.vainilla, borderColor: assignment ? "#A7C9A4" : T.border }}><div className="text-[9px] uppercase tracking-wider font-extrabold" style={{ color: assignment ? "#3F6B42" : "#96690F" }}>{assignment ? "Responsable de Cocina" : "Comanda disponible"}</div><div className="text-xs font-bold mt-0.5">{assignment?.user || (isPaid ? "Tomala para empezar" : "Sin responsable")}</div></div>
      </div>

      <div className="rounded-3xl border p-4 sm:p-5" style={{ background: "linear-gradient(135deg,#FFF9F1,#FFFFFF)", borderColor: T.border }}>
        <div className="flex items-start justify-between gap-3 mb-3"><div><div className="text-[10px] uppercase tracking-[.14em] font-extrabold" style={{ color: T.coral }}>Qué debe preparar Cocina</div><div className="display text-xl font-semibold">Revisá y ejecutá esta comanda</div></div><span className="rounded-full px-2.5 py-1 text-[10px] font-extrabold" style={{ background: T.rosa, color: "#7C3F4B" }}>{lines.length} control{lines.length === 1 ? "" : "es"}</span></div>
        <div className="space-y-2">
          {lines.map((line) => <div key={line.id} className="rounded-2xl border px-3 py-3 flex items-start gap-3" style={{ background: "#fff", borderColor: T.border }}><span className="w-7 h-7 rounded-full flex items-center justify-center text-xs shrink-0" style={{ background: line.parentItemId ? T.rosa : T.vainilla }} aria-hidden="true">{line.parentItemId ? "↳" : "✓"}</span><div className="min-w-0"><div className="text-sm font-extrabold">{line.label}</div>{line.detail && <div className="text-[11px] font-semibold mt-0.5" style={{ color: T.choco2 }}>{line.detail}</div>}</div></div>)}
          {!lines.length && <div className="rounded-2xl p-5 text-center text-sm font-bold" style={{ background: T.vainilla }}>La orden no tiene líneas para preparar. Revisala con Coordinación.</div>}
        </div>
      </div>

      {incidents.length > 0 && <div className="mt-4 rounded-2xl border p-4" style={{ background: "#FFF3EF", borderColor: "#E8B7AD" }}><div className="text-[10px] uppercase tracking-wider font-extrabold" style={{ color: "#A03B2A" }}>Comanda pausada · {incidents.length} novedad{incidents.length === 1 ? "" : "es"}</div><div className="space-y-2 mt-2">{incidents.map((incident) => <div key={incident.id} className="rounded-xl bg-white px-3 py-2 flex flex-col sm:flex-row sm:items-center gap-2"><div className="flex-1 text-xs"><b>{incident.type}</b> · {incident.description}</div>{canOperateKitchen && <Btn small kind="ghost" disabled={!!issueBusy} onClick={() => resolveIssue(incident.id)}>{issueBusy === incident.id ? "Resolviendo…" : "Ya está resuelto"}</Btn>}</div>)}</div></div>}

      {showIssue && <div className="mt-4 rounded-2xl border p-4" style={{ background: T.coralSoft, borderColor: "#E8B5A5" }}><div className="flex items-start justify-between gap-3"><div><div className="text-[10px] uppercase tracking-wider font-extrabold" style={{ color: "#A54830" }}>Registrar problema</div><div className="text-sm font-extrabold mt-0.5">MOMO OPS recomienda cómo actuar sin improvisar</div></div><button type="button" onClick={() => setShowIssue(false)} className="text-sm font-black" aria-label="Cerrar problema">×</button></div><div className="grid sm:grid-cols-2 gap-2 mt-3"><select aria-label="Tipo de problema" value={issue.type} onChange={(event) => setIssue({ ...issue, type: event.target.value })} className="rounded-xl border px-3 py-2 text-xs font-bold" style={inputStyle}>{Object.keys(KITCHEN_ISSUE_GUIDANCE).map((type) => <option key={type}>{type}</option>)}</select><select aria-label="Línea afectada" value={issue.orderItemId} onChange={(event) => setIssue({ ...issue, orderItemId: event.target.value })} className="rounded-xl border px-3 py-2 text-xs" style={inputStyle}><option value="">Pedido completo</option>{lines.map((line) => <option key={line.id} value={line.id}>{line.label}</option>)}</select></div><div className="rounded-xl px-3 py-2 mt-2 text-xs font-bold" style={{ background: "#FFF9F1", color: "#7B5410" }}>💡 {KITCHEN_ISSUE_GUIDANCE[issue.type]}</div><textarea value={issue.description} onChange={(event) => setIssue({ ...issue, description: event.target.value })} placeholder="Contá brevemente qué pasó…" rows="3" className="w-full rounded-xl border px-3 py-2 text-sm mt-2" style={inputStyle} /><div className="flex justify-end mt-2"><Btn disabled={issue.description.trim().length < 3 || !!issueBusy} onClick={registerIssue}>{issueBusy === "create" ? "Registrando…" : "Registrar y pausar comanda"}</Btn></div></div>}

      {feedback && <div className="mt-3 rounded-xl px-3 py-2 text-xs font-bold" style={{ background: feedback.toLowerCase().includes("no ") || feedback.toLowerCase().includes("error") ? "#F6D4CD" : "#DDEBD9", color: feedback.toLowerCase().includes("no ") || feedback.toLowerCase().includes("error") ? "#A03B2A" : "#3F6B42" }}>{feedback}</div>}

      {!showIssue && <div className="mt-5 sticky bottom-0 py-3 flex flex-col sm:flex-row sm:items-center justify-between gap-3" style={{ background: T.bg }}>
        <div className="flex flex-wrap items-center gap-x-4 gap-y-2">
          <button type="button" onClick={() => setShowIssue(true)} className="text-xs font-extrabold underline" style={{ color: "#A54830" }}>⚠ Reportar problema</button>
          <button type="button" onClick={onMomobot} className="text-xs font-extrabold underline" style={{ color: T.choco2 }}>🎙️ Pedir ayuda a Momobot</button>
        </div>
        {quickState.disabled && quickState.blockReason
          ? <div className="rounded-xl px-3 py-2 text-xs font-bold sm:max-w-xs" style={{ background: T.vainilla, color: "#7B5410" }}>{quickState.blockReason}</div>
          : <div className="sm:min-w-[250px] [&>button]:w-full">
            {isPaid && <BtnAsync textoEnVuelo="Tomando comanda…" disabled={!canStart || busyOrderId === order.id} onClick={() => onStart(order.id)}>{quickState.label}</BtnAsync>}
            {isCooking && <BtnAsync textoEnVuelo="Entregando a Empaque…" disabled={!canReady || busyOrderId === order.id} onClick={() => onReady(order.id)}>✓ {quickState.label}</BtnAsync>}
          </div>}
      </div>}
    </Modal>
  );
}

function Field({ label, children }) {
  return (
    <label className="momo-field block mb-3">
      <span className="block text-xs font-bold mb-1" style={{ color: T.choco2 }}>{label}</span>
      {children}
    </label>
  );
}

const inputCls = "w-full rounded-xl px-3 py-2.5 text-sm border outline-none focus:ring-2";
const inputStyle = { background: "#fff", borderColor: T.border, color: T.choco };
function Input(props) { return <input {...props} className={inputCls} style={inputStyle} />; }
function Select({ options, ...props }) {
  return (
    <select {...props} className={inputCls} style={inputStyle}>
      {props.placeholder && <option value="">{props.placeholder}</option>}
      {options.map((o) => <option key={o} value={o}>{o}</option>)}
    </select>
  );
}
function MiniSelect({ value, onChange, options, placeholder, disabled }) {
  return (
    <select value={value} onChange={onChange} disabled={disabled} className="rounded-xl px-2 py-2 text-xs border font-semibold" style={{ ...inputStyle, opacity: disabled ? 0.5 : 1 }}>
      {placeholder && <option value="">{placeholder}</option>}
      {options.map((o) => <option key={o} value={o}>{o}</option>)}
    </select>
  );
}

function Empty({ icon, text }) {
  return (
    <Card className="p-8 text-center">
      <div className="text-3xl mb-2" aria-hidden="true">{icon}</div>
      <div className="text-sm font-semibold" style={{ color: T.choco2 }}>{text}</div>
    </Card>
  );
}

function Bars({ data, money }) {
  const max = Math.max(...data.map((d) => d.value), 1);
  return (
    <div className="flex flex-col gap-2">
      {data.map((d, i) => (
        <div key={d.label + i} className="flex items-center gap-2">
          <div className="w-28 sm:w-36 text-xs font-semibold truncate" style={{ color: T.choco2 }}>{d.label}</div>
          <div className="flex-1 h-5 rounded-full overflow-hidden" style={{ background: T.vainilla }}>
            <div className="momo-bar h-full rounded-full" style={{ width: Math.max((d.value / max) * 100, 3) + "%", background: d.color || T.rosaDeep }} />
          </div>
          <div className="w-20 text-right text-xs font-bold">{money ? fmt(d.value) : d.value}</div>
        </div>
      ))}
      {data.length === 0 && <div className="text-xs font-semibold" style={{ color: T.choco2 }}>Sin datos en el rango.</div>}
    </div>
  );
}

/* ================= DASHBOARD ================= */

function Dashboard({ db, go, user }) {
  const [tick, setTick] = useState(0);
  const [assistantCenterOpen, setAssistantCenterOpen] = useState(false);
  useEffect(() => { const t = setInterval(() => setTick((x) => x + 1), 60000); return () => clearInterval(t); }, []);
  const hoy = hoyISO();
  const assistantCenter = useMemo(() => buildAssistantControlCenter(db, {
    today: hoy,
    now: new Date().toISOString(),
    financeFrom: hoy,
    financeTo: hoy,
  }), [db, hoy, tick]);
  const deHoy = db.orders.filter((o) => o.fecha === hoy && o.estado !== "Cancelado");
  const ventasHoy = deHoy.filter(esPedidoCobrado).reduce((s, o) => s + orderTotal(db, o), 0);
  const activos = db.orders.filter((o) => !["Entregado","Cancelado"].includes(o.estado));
  const pendPago = db.orders.filter((o) => ["Nuevo","Confirmado","Pendiente de pago"].includes(o.estado) && !o.pagadoEn);
  const stockBajo = db.inventory_items.filter((i) => i.stock < i.min);
  const porVencer = db.inventory_items.filter((i) => i.vence && diasEntre(hoy, i.vence) <= 5 && diasEntre(hoy, i.vence) >= 0);
  const reclamosAbiertos = db.claims.filter((c) => ["Abierto","En revisión"].includes(c.estado));
  const sugerencias = db.production_suggestions.filter((s) => s.estado === "Pendiente" && s.area !== "Inventario");
  const lotesListos = db.production_batches.filter((l) => { const c = estadoCongelacion(l); return c && c.listo; });

  // Marketing en el dashboard
  const campActivasSinPedidos = (db.campaigns || []).filter((c) => c.estado === "Activa" && ordersDeCampaign(db, c.id).length === 0);
  const creativosPorAprobar = (db.creatives || []).filter((c) => c.estado === "En revisión");
  const pubsHoy = (db.content_calendar || []).filter((p) => p.fecha === hoy);
  const campConMetrics = (db.campaigns || []).map((c) => ({ c, m: campaignMetrics(db, c) }));
  const mejorCampana = [...campConMetrics].filter((x) => x.m.roas !== null).sort((a, b) => b.m.roas - a.m.roas)[0];
  const creativoGanador = (db.creatives || []).find((c) => c.estado === "Ganador");
  const benefsPorCampana = (db.benefits || []).filter((b) => b.estado === "Activo" && /historia|malteada|granizado/i.test(b.condicion + b.beneficio)).length;
  const trafficRecs = trafficRecomendaciones(db);

  // Asistente de marca MOMOS (lenguaje simple)
  const hoyStr = hoy;
  const asistente = (() => {
    const ideas = db.marketing_ideas || [];
    const ideaHoy = [...ideas].sort((a, b) => { const r = { Ganadora: 0, Repetir: 1, Nueva: 2, Usada: 3, Descartada: 4 }; return (r[a.estado] ?? 5) - (r[b.estado] ?? 5); })[0];
    // cliente por contactar: beneficio por vencer, luego inactivo
    let clienteContacto = null;
    const benVence = (db.benefits || []).filter((b) => b.estado === "Activo" && diasEntre(hoyStr, b.vence) <= 3 && b.vence >= hoyStr)[0];
    if (benVence) { const c = db.customers.find((x) => x.id === benVence.customerId); if (c) clienteContacto = { nombre: c.nombre, motivo: "tiene un beneficio por vencer" }; }
    if (!clienteContacto) {
      const inact = db.customers.filter((c) => c.ultima && diasEntre(c.ultima, hoyStr) >= 15).sort((a, b) => diasEntre(b.ultima, hoyStr) - diasEntre(a.ultima, hoyStr))[0];
      if (inact) clienteContacto = { nombre: inact.nombre, motivo: `no compra hace ${diasEntre(inact.ultima, hoyStr)} días` };
    }
    const campRevisar = (db.campaigns || []).map((c) => ({ c, m: campaignMetrics(db, c) })).filter((x) => x.c.estado === "Activa")[0];
    const contenidoRepetir = ideas.find((i) => i.estado === "Ganadora");
    const benefVence = (db.benefits || []).filter((b) => b.estado === "Activo" && b.vence >= hoyStr).sort((a, b) => diasEntre(hoyStr, a.vence) - diasEntre(hoyStr, b.vence))[0];
    const tareaFalta = (db.marketing_tasks || []).filter((t) => t.estado === "Pendiente" && t.fecha === hoyStr)[0];
    return { ideaHoy, clienteContacto, campRevisar, contenidoRepetir, benefVence, tareaFalta };
  })();
  const nuevos = db.customers.filter((c) => c.estado === "Nuevo").length;
  const recurrentes = db.customers.filter((c) => ["Recurrente","VIP"].includes(c.estado)).length;

  const porEstado = ORDER_STATES.map((e) => ({ label: e, value: db.orders.filter((o) => o.estado === e).length })).filter((d) => d.value > 0);
  const porCanal = CANALES.map((c) => ({
    label: c, color: CANAL_STYLE[c].fg,
    value: db.orders.filter((o) => o.canal === c && esPedidoCobrado(o)).reduce((s, o) => s + orderTotal(db, o), 0),
  }));
  const assistantSeverityStyle = {
    critical: { label: "Crítica", bg: "#F6D4CD", fg: "#8F3528" },
    high: { label: "Alta", bg: "#FFF1D6", fg: "#7A5510" },
    medium: { label: "Media", bg: "#DCE7F2", fg: "#3E5C7E" },
    info: { label: "Informativa", bg: "#DDEBD9", fg: "#356239" },
  };

  return (
    <div>
      <SectionTitle>Hoy en la cocina</SectionTitle>
      <div className="grid grid-cols-2 lg:grid-cols-4 gap-3">
        <Stat icon="🧁" label="Ventas del día" value={fmt(ventasHoy)} sub={deHoy.length + " pedidos hoy · toca para ver"} tone={T.coral} onClick={() => go("Pedidos", { desde: hoy, hasta: hoy })} />
        <Stat icon="📦" label="Pedidos activos" value={activos.length} sub="en flujo operativo · toca para ver" onClick={() => go("Pedidos")} />
        <Stat icon="💳" label="Pendientes de pago" value={pendPago.length} sub={fmt(pendPago.reduce((s, o) => s + orderTotal(db, o), 0)) + " · toca para ver"} tone="#96690F" onClick={() => go("Pedidos", { pendientesPago: true })} />
        <Stat icon="⚠️" label="Reclamos abiertos" value={reclamosAbiertos.length} sub="requieren decisión · toca para ver" tone="#A03B2A" onClick={() => go("Reclamos", { claimId: reclamosAbiertos[0] ? reclamosAbiertos[0].id : "" })} />
      </div>

      <Card className="mt-3 overflow-hidden" onClick={() => setAssistantCenterOpen(true)}
        aria-label="Abrir Centro de asistentes MOMOS"
        style={{ background: "linear-gradient(135deg,#FFF8F0 0%,#FFFFFF 55%,#F5EDE4 100%)", borderColor: assistantCenter.summary.health === "Bloqueado" ? "#E6AAA0" : assistantCenter.summary.health === "Atención" ? "#E5C98E" : "#BFD8BA" }}>
        <div className="p-4 sm:p-5 flex flex-col sm:flex-row sm:items-center gap-4">
          <div className="w-12 h-12 rounded-2xl flex items-center justify-center text-xl shrink-0" aria-hidden="true"
            style={{ background: assistantCenter.summary.health === "Bloqueado" ? "#F6D4CD" : assistantCenter.summary.health === "Atención" ? "#FFF1D6" : "#DDEBD9" }}>
            ✦
          </div>
          <div className="min-w-0 flex-1">
            <div className="flex flex-wrap items-center gap-2">
              <div className="text-[10px] uppercase tracking-[.16em] font-extrabold" style={{ color: T.coral }}>MOMOS OPS Intelligence</div>
              <span className="rounded-full px-2.5 py-1 text-[10px] font-extrabold"
                style={{ background: assistantCenter.summary.health === "Bloqueado" ? "#F6D4CD" : assistantCenter.summary.health === "Atención" ? "#FFF1D6" : "#DDEBD9", color: assistantCenter.summary.health === "Bloqueado" ? "#8F3528" : assistantCenter.summary.health === "Atención" ? "#7A5510" : "#356239" }}>
                {assistantCenter.summary.health}
              </span>
            </div>
            <div className="display text-xl font-semibold mt-1">Centro de asistentes MOMOS</div>
            {assistantCenter.primary ? <>
              <div className="text-sm font-extrabold mt-1.5">{assistantCenter.primary.title}</div>
              <div className="text-xs mt-1 leading-relaxed" style={{ color: T.choco2 }}>
                Responsable: {assistantCenter.primary.ownerRoles.join(" / ")} · {assistantCenter.primary.nextAction}
              </div>
            </> : <div className="text-sm font-semibold mt-1.5" style={{ color: "#3F6B42" }}>Los cinco asistentes están al día.</div>}
          </div>
          <div className="grid grid-cols-3 gap-2 shrink-0 text-center">
            {[["Asistentes", assistantCenter.assistants.length], ["Prioridades", assistantCenter.summary.tasks], ["Críticas", assistantCenter.summary.critical]].map(([label, value]) => (
              <div key={label} className="rounded-2xl px-3 py-2 min-w-[70px]" style={{ background: "rgba(255,255,255,.78)", border: `1px solid ${T.border}` }}>
                <div className="display text-lg font-semibold">{value}</div>
                <div className="text-[9px] uppercase font-extrabold" style={{ color: T.choco2 }}>{label}</div>
              </div>
            ))}
          </div>
        </div>
      </Card>

      {sugerencias.length > 0 && (
        <div className="mt-3 text-xs font-bold p-3 rounded-xl" style={{ background: "#DCE7F2", color: "#3E5C7E" }}>
          👩‍🍳 Producción sugerida: {sugerencias.map((s) => `${s.cantidad}× ${s.producto}`).join(" · ")}.{" "}
          <button className="underline" onClick={() => go("Producción")}>Ver en Producción</button>
        </div>
      )}

      {lotesListos.length > 0 && (
        <div className="mt-3 text-xs font-bold p-3 rounded-xl" style={{ background: "#DDEBD9", color: "#3F6B42" }}>
          🧊✅ {lotesListos.length} lote(s) cumplieron su tiempo de congelación y esperan pasar a "Listo": {lotesListos.map((l) => `${l.id} (${[l.producto, l.gramaje, l.sabor].filter(Boolean).join(" · ")})`).join(", ")}.{" "}
          <button className="underline" onClick={() => go("Producción")}>Ir a Producción</button>
        </div>
      )}

      {pubsHoy.length > 0 && (
        <div className="mt-3 text-xs font-bold p-3 rounded-xl" style={{ background: "#F3D7DC", color: "#8E4B5A" }}>
          🗓️ Publicaciones de hoy ({pubsHoy.length}): {pubsHoy.map((p) => `${p.hora} ${p.canal}`).join(" · ")}.{" "}
          <button className="underline" onClick={() => go("Calendario")}>Ver calendario</button>
        </div>
      )}
      {creativosPorAprobar.length > 0 && (
        <div className="mt-3 text-xs font-bold p-3 rounded-xl" style={{ background: "#E8E0F2", color: "#63518A" }}>
          🎨 {creativosPorAprobar.length} creativo(s) esperan aprobación: {creativosPorAprobar.map((c) => c.titulo).join(", ")}.{" "}
          <button className="underline" onClick={() => go("Creativos")}>Revisar</button>
        </div>
      )}
      {campActivasSinPedidos.length > 0 && (
        <div className="mt-3 text-xs font-bold p-3 rounded-xl" style={{ background: "#FBE8C8", color: "#96690F" }}>
          📣 Campañas activas sin pedidos atribuidos: {campActivasSinPedidos.map((c) => c.nombre).join(", ")}.{" "}
          <button className="underline" onClick={() => go("Marketing")}>Ver Marketing</button>
        </div>
      )}
      {(mejorCampana || creativoGanador) && (
        <div className="mt-3 text-xs font-bold p-3 rounded-xl" style={{ background: "#DDEBD9", color: "#3F6B42" }}>
          🏆 {mejorCampana ? `Mejor campaña: ${mejorCampana.c.nombre} (ROAS ${mejorCampana.m.roas.toFixed(1)}x)` : ""}{mejorCampana && creativoGanador ? " · " : ""}{creativoGanador ? `Creativo ganador: ${creativoGanador.titulo}` : ""}{benefsPorCampana > 0 ? ` · ${benefsPorCampana} beneficio(s) por campaña activos` : ""}
        </div>
      )}

      {(user === "Administrador" || user === "Marketing/CRM") && (
        <>
          <SectionTitle>🌱 Asistente de marca MOMOS</SectionTitle>
          <div className="grid grid-cols-2 lg:grid-cols-3 gap-3">
            <Card className="p-3.5" onClick={() => go("Crecimiento")}>
              <div className="text-xs font-bold mb-1" style={{ color: T.coral }}>📱 Qué publicar hoy</div>
              <div className="text-sm font-semibold leading-tight">{asistente.ideaHoy ? asistente.ideaHoy.titulo : "Sin ideas cargadas"}</div>
            </Card>
            <Card className="p-3.5" onClick={() => go("Crecimiento")}>
              <div className="text-xs font-bold mb-1" style={{ color: "#8E4B5A" }}>💬 Cliente para contactar</div>
              <div className="text-sm font-semibold leading-tight">{asistente.clienteContacto ? asistente.clienteContacto.nombre : "Nadie urgente hoy"}</div>
              {asistente.clienteContacto && <div className="text-[11px] mt-0.5" style={{ color: T.choco2 }}>{asistente.clienteContacto.motivo}</div>}
            </Card>
            <Card className="p-3.5" onClick={() => go("Crecimiento")}>
              <div className="text-xs font-bold mb-1" style={{ color: "#3E5C7E" }}>📣 Campaña para revisar</div>
              <div className="text-sm font-semibold leading-tight">{asistente.campRevisar ? asistente.campRevisar.c.nombre : "Sin campañas activas"}</div>
            </Card>
            <Card className="p-3.5" onClick={() => go("Crecimiento")}>
              <div className="text-xs font-bold mb-1" style={{ color: "#3F6B42" }}>🔁 Contenido para repetir</div>
              <div className="text-sm font-semibold leading-tight">{asistente.contenidoRepetir ? asistente.contenidoRepetir.titulo : "Aún sin ganadores"}</div>
            </Card>
            <Card className="p-3.5" onClick={() => go("Beneficios")}>
              <div className="text-xs font-bold mb-1" style={{ color: "#96690F" }}>⏳ Beneficio por vencer</div>
              <div className="text-sm font-semibold leading-tight">{asistente.benefVence ? asistente.benefVence.beneficio : "Ninguno próximo"}</div>
              {asistente.benefVence && <div className="text-[11px] mt-0.5" style={{ color: T.choco2 }}>vence {asistente.benefVence.vence}</div>}
            </Card>
            <Card className="p-3.5" onClick={() => go("Crecimiento")}>
              <div className="text-xs font-bold mb-1" style={{ color: "#63518A" }}>✅ Tarea que falta</div>
              <div className="text-sm font-semibold leading-tight">{asistente.tareaFalta ? asistente.tareaFalta.tarea : "¡Todo al día! 🎉"}</div>
            </Card>
          </div>
          {trafficRecs.length > 0 && (
            <div className="mt-3 text-xs font-bold p-3 rounded-xl" style={{ background: trafficRecs[0].bg, color: trafficRecs[0].color }}>
              {trafficRecs[0].icon} {trafficRecs[0].titulo}: {trafficRecs[0].texto}{" "}
              <button className="underline" onClick={() => go("Crecimiento")}>Ver recomendaciones</button>
            </div>
          )}
        </>
      )}

      <SectionTitle>Alertas</SectionTitle>
      <div className="grid sm:grid-cols-2 gap-3">
        <Card className="p-4">
          <div className="text-xs font-bold mb-2" style={{ color: T.choco2 }}>📉 Inventario bajo mínimo</div>
          {stockBajo.length === 0 ? <div className="text-sm">Todo el stock está por encima del mínimo.</div> :
            stockBajo.map((i) => (
              <button key={i.id} onClick={() => go("Inventario", { itemId: i.id })}
                className="w-full flex justify-between items-center text-sm py-1.5 border-b last:border-0 text-left hover:opacity-70"
                style={{ borderColor: T.border }}>
                <span className="font-semibold">{i.nombre}</span>
                <span className="flex items-center gap-1.5 font-bold" style={{ color: "#A03B2A" }}>{i.stock} / mín {i.min} {i.unidad} <span aria-hidden="true" style={{ color: T.choco2 }}>›</span></span>
              </button>
            ))}
          <div className="mt-3"><Btn small kind="soft" onClick={() => go("Inventario")}>Ir a inventario</Btn></div>
        </Card>
        <Card className="p-4">
          <div className="text-xs font-bold mb-2" style={{ color: T.choco2 }}>🗓️ Vencimientos próximos (5 días)</div>
          {porVencer.length === 0 ? <div className="text-sm">Sin vencimientos cercanos.</div> :
            porVencer.map((i) => (
              <button key={i.id} onClick={() => go("Inventario", { itemId: i.id })}
                className="w-full flex justify-between items-center text-sm py-1.5 border-b last:border-0 text-left hover:opacity-70"
                style={{ borderColor: T.border }}>
                <span className="font-semibold">{i.nombre}</span>
                <span className="flex items-center gap-1.5 font-bold" style={{ color: "#96690F" }}>{i.vence} <span aria-hidden="true" style={{ color: T.choco2 }}>›</span></span>
              </button>
            ))}
          <div className="mt-3 flex gap-2 text-xs font-semibold" style={{ color: T.choco2 }}>
            <span>👤 Nuevos: <b style={{ color: T.choco }}>{nuevos}</b></span><span>·</span>
            <span>💖 Recurrentes/VIP: <b style={{ color: T.choco }}>{recurrentes}</b></span>
          </div>
        </Card>
      </div>

      <SectionTitle>Pedidos por estado</SectionTitle>
      <Card className="p-4"><Bars data={porEstado} /></Card>

      <SectionTitle>Ventas por canal</SectionTitle>
      <Card className="p-4"><Bars data={porCanal} money /></Card>

      <SectionTitle>Disponibilidad real de momos y cajas</SectionTitle>
      <div className="grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-4 gap-3">
        {db.products.filter((p) => p.activo && p.tipo !== "pedido").map((p) => {
          const disp = availability(db, p);
          return (
            <Card key={p.id} className="p-3" onClick={() => go("Producción")}>
              <div className="text-sm font-bold leading-tight">{p.nombre}</div>
              <div className="display text-xl mt-1" style={{ color: disp <= 2 ? "#A03B2A" : T.choco }}>
                {disp} <span className="text-xs font-sans font-semibold" style={{ color: T.choco2 }}>disp.</span>
              </div>
              {p.tipo === "combo" && <div className="text-[10px] font-bold" style={{ color: T.choco2 }}>calculado por momos + cajas</div>}
              {disp <= 2 && <div className="text-xs font-bold mt-0.5" style={{ color: "#A03B2A" }}>Producir / comprar pronto</div>}
            </Card>
          );
        })}
      </div>

      {assistantCenterOpen && (
        <Modal title="Centro de asistentes MOMOS" onClose={() => setAssistantCenterOpen(false)} wide>
          <div className="rounded-3xl p-4 sm:p-5 mb-4" style={{ background: "linear-gradient(135deg,#F8EBDD,#FFFDF9)", border: `1px solid ${T.border}` }}>
            <div className="flex flex-col sm:flex-row sm:items-start gap-4">
              <div className="min-w-0 flex-1">
                <div className="text-[10px] uppercase tracking-[.16em] font-extrabold" style={{ color: T.coral }}>Una prioridad · un responsable · una fuente</div>
                <div className="display text-2xl font-semibold mt-1">{assistantCenter.primary ? assistantCenter.primary.title : "Operación protegida"}</div>
                <div className="text-sm font-semibold mt-2 leading-relaxed" style={{ color: T.choco2 }}>
                  {assistantCenter.primary ? assistantCenter.primary.detail : "No hay tareas pendientes entre Ventas, Cocina, Compras, Empaque, Logística y Finanzas."}
                </div>
              </div>
              <div className="rounded-2xl px-4 py-3 text-center shrink-0" style={{ background: "rgba(255,255,255,.82)" }}>
                <div className="display text-2xl font-semibold">{assistantCenter.summary.tasks}</div>
                <div className="text-[10px] uppercase font-extrabold" style={{ color: T.choco2 }}>prioridades abiertas</div>
              </div>
            </div>
            <div className="mt-4 rounded-2xl px-3 py-2.5 text-xs font-bold" style={{ background: "rgba(255,255,255,.68)", color: T.choco2 }}>
              🛡️ {assistantCenter.policy}
            </div>
          </div>

          <div className="grid grid-cols-2 sm:grid-cols-5 gap-2 mb-5" aria-label="Estado de los asistentes">
            {assistantCenter.assistants.map((row) => (
              <button key={row.id} type="button" onClick={() => { setAssistantCenterOpen(false); go(row.module); }}
                className="rounded-2xl border p-3 text-left transition hover:-translate-y-0.5"
                style={{ background: T.surface, borderColor: row.status === "Bloqueado" ? "#E6AAA0" : row.status === "Atención" ? "#E5C98E" : "#BFD8BA" }}>
                <div className="text-[10px] uppercase font-extrabold leading-tight" style={{ color: T.choco2 }}>{row.name}</div>
                <div className="display text-xl font-semibold mt-1">{row.count}</div>
                <div className="text-[10px] font-extrabold mt-0.5" style={{ color: row.status === "Bloqueado" ? "#8F3528" : row.status === "Atención" ? "#7A5510" : "#356239" }}>{row.status}</div>
              </button>
            ))}
          </div>

          <div className="flex items-center justify-between gap-3 mb-3">
            <div>
              <div className="display text-lg font-semibold">Qué necesita atención</div>
              <div className="text-xs mt-0.5" style={{ color: T.choco2 }}>Ordenado por riesgo operativo, no por el área que lo reportó.</div>
            </div>
            {assistantCenter.summary.blocking > 0 && <span className="rounded-full px-3 py-1 text-[10px] font-extrabold" style={{ background: "#F6D4CD", color: "#8F3528" }}>{assistantCenter.summary.blocking} bloquean</span>}
          </div>

          {assistantCenter.tasks.length === 0 ? (
            <div className="rounded-3xl p-8 text-center" style={{ background: "#DDEBD9", color: "#356239" }}>
              <div className="text-3xl" aria-hidden="true">✓</div>
              <div className="display text-xl font-semibold mt-2">Operación protegida</div>
              <div className="text-sm font-semibold mt-1">Los cinco asistentes están al día y no detectan inconsistencias.</div>
            </div>
          ) : (
            <div className="space-y-3">
              {assistantCenter.tasks.slice(0, 12).map((row) => {
                const tone = assistantSeverityStyle[row.severity] || assistantSeverityStyle.medium;
                return (
                  <div key={row.id} className="rounded-2xl border p-4" style={{ background: T.surface, borderColor: row.blocks ? "#E6AAA0" : T.border }}>
                    <div className="flex flex-col sm:flex-row sm:items-start gap-3">
                      <div className="min-w-0 flex-1">
                        <div className="flex flex-wrap items-center gap-2 mb-1.5">
                          <span className="rounded-full px-2.5 py-1 text-[10px] font-extrabold" style={{ background: tone.bg, color: tone.fg }}>{tone.label}</span>
                          <span className="text-[10px] uppercase font-extrabold" style={{ color: T.coral }}>{row.area}</span>
                          {row.entityId && <span className="text-[10px] font-bold" style={{ color: T.choco2 }}>{row.entityType} {row.entityId}</span>}
                          <span className="text-[10px] font-bold" style={{ color: T.choco2 }}>Confianza {row.confidence.toLowerCase()}</span>
                        </div>
                        <div className="text-sm font-extrabold">{row.title}</div>
                        <div className="text-xs mt-1 leading-relaxed" style={{ color: T.choco2 }}>{row.detail}</div>
                        <div className="mt-2 space-y-1">
                          {row.reasons.map((reason, index) => <div key={`${row.id}-reason-${index}`} className="text-[11px] font-semibold flex gap-2" style={{ color: T.choco2 }}><span aria-hidden="true">•</span><span>{reason}</span></div>)}
                        </div>
                        <div className="mt-3 rounded-xl px-3 py-2 text-xs font-bold" style={{ background: T.vainilla }}>
                          Siguiente paso: {row.nextAction}
                        </div>
                      </div>
                      <div className="sm:w-44 shrink-0">
                        <div className="text-[10px] uppercase font-extrabold" style={{ color: T.choco2 }}>Responsable</div>
                        <div className="text-xs font-extrabold mt-1">{row.ownerRoles.join(" / ")}</div>
                        {row.confirmationRequired && <div className="text-[10px] font-bold mt-2" style={{ color: "#96690F" }}>Confirmación humana obligatoria</div>}
                        <button type="button" onClick={() => { setAssistantCenterOpen(false); go(row.module); }} className="momo-btn w-full rounded-xl px-3 py-2 mt-3 text-xs font-extrabold" style={{ background: T.coral, color: "white" }}>Abrir {row.module}</button>
                      </div>
                    </div>
                  </div>
                );
              })}
              {assistantCenter.tasks.length > 12 && <div className="rounded-2xl px-4 py-3 text-center text-xs font-bold" style={{ background: T.vainilla, color: T.choco2 }}>Se muestran las 12 prioridades más importantes de {assistantCenter.tasks.length}. Cada asistente conserva el detalle completo en su área.</div>}
            </div>
          )}
        </Modal>
      )}
    </div>
  );
}

/* ================= PEDIDOS ================= */

function HistorialOperativo({ db }) {
  const entries = useMemo(() => buildOperationalHistory(db), [db.audit_logs]);
  const [q, setQ] = useState("");
  const [area, setArea] = useState("");
  const [desde, setDesde] = useState("");
  const [hasta, setHasta] = useState("");
  const [limit, setLimit] = useState(50);
  const areas = useMemo(() => [...new Set(entries.map((entry) => entry.area))].sort((a, b) => a.localeCompare(b, "es")), [entries]);
  const filtered = useMemo(() => {
    const query = q.trim().toLocaleLowerCase("es");
    return entries.filter((entry) => {
      const haystack = [entry.area, entry.entity, entry.entityId, entry.action, entry.actor, entry.from, entry.to].join(" ").toLocaleLowerCase("es");
      const day = entry.at.slice(0, 10);
      return (!query || haystack.includes(query))
        && (!area || entry.area === area)
        && (!desde || day >= desde)
        && (!hasta || day <= hasta);
    });
  }, [entries, q, area, desde, hasta]);
  useEffect(() => { setLimit(50); }, [q, area, desde, hasta]);
  const visible = filtered.slice(0, limit);
  const today = hoyISO();
  const todayCount = entries.filter((entry) => entry.at.startsWith(today)).length;
  const actorCount = new Set(entries.map((entry) => entry.actor).filter(Boolean)).size;
  const primerRegistro = entries.reduce((min, e) => (min == null || (e.at && e.at < min) ? e.at : min), null);

  function exportar() {
    downloadCSV("historial-operativo", ["Fecha", "Área", "Entidad", "ID", "Acción", "Antes", "Después", "Responsable"], filtered.map((entry) => [entry.at, entry.area, entry.entity, entry.entityId, entry.action, entry.from, entry.to, entry.actor]));
  }

  return (
    <div>
      <SectionTitle>Historial operativo</SectionTitle>
      <div className="text-xs font-semibold mb-3 -mt-3" style={{ color: T.choco2 }}>
        Consultá qué pasó, en qué área, sobre qué registro y quién lo ejecutó. Nada se borra al salir de una bandeja de trabajo.
      </div>

      <div className="grid grid-cols-2 lg:grid-cols-4 gap-3 mb-4">
        <Stat icon="◷" label="Movimientos" value={entries.length} sub="rastro disponible" tone={T.coral} />
        <Stat icon="●" label="Hoy" value={todayCount} sub="acciones registradas" tone="#3F6B42" />
        <Stat icon="▦" label="Áreas" value={areas.length} sub="fuentes conectadas" tone="#63518A" />
        <Stat icon="♙" label="Responsables" value={actorCount} sub="usuarios en el rastro" tone="#96690F" />
      </div>

      <div className="text-[11px] font-semibold mt-2 mb-3" style={{ color: T.choco2 }}>
        Rastro registrado desde <b style={{ color: T.coral }}>{primerRegistro ? primerRegistro.slice(0, 10) : "—"}</b> hasta hoy.
      </div>

      <div className="momo-segmented-tabs inline-flex max-w-full gap-1 overflow-x-auto p-1.5 mb-4 rounded-2xl" role="tablist" aria-label="Áreas del historial">
        {[["Todas", ""], ...areas.map((a) => [a, a])].map(([label, value]) => {
          const count = value ? entries.filter((e) => e.area === value).length : entries.length;
          const activo = area === value;
          return (
            <button key={label} type="button" role="tab" aria-selected={activo} onClick={() => setArea(value)}
              className="momo-segmented-tab shrink-0 rounded-xl px-3 py-2 text-xs font-bold border-0"
              style={activo ? { background: T.coral, color: "#fff" } : { background: "transparent", color: T.choco2 }}>
              {label} <span className="ml-1 inline-flex min-w-5 h-5 px-1 rounded-full items-center justify-center text-[10px]" style={{ background: activo ? "rgba(255,255,255,.2)" : "#fff" }}>{count}</span>
            </button>
          );
        })}
      </div>

      <Card className="p-3 mb-4">
        <div className="grid sm:grid-cols-2 lg:grid-cols-[minmax(220px,1fr)_150px_150px_auto] gap-2 items-center">
          <input value={q} onChange={(event) => setQ(event.target.value)} placeholder="Buscar pedido, lote, acción o responsable…" className="rounded-xl px-3 py-2 text-sm border outline-none" style={inputStyle} />
          <input type="date" aria-label="Historial desde" value={desde} onChange={(event) => setDesde(event.target.value)} className="rounded-xl px-3 py-2 text-xs border font-bold" style={inputStyle} />
          <input type="date" aria-label="Historial hasta" value={hasta} onChange={(event) => setHasta(event.target.value)} className="rounded-xl px-3 py-2 text-xs border font-bold" style={inputStyle} />
          <Btn small kind="ghost" onClick={exportar}>⬇ CSV</Btn>
        </div>
      </Card>

      <div className="flex items-center justify-between gap-3 mb-3"><div><div className="display text-lg font-semibold">Bitácora consolidada</div><div className="text-xs font-semibold" style={{ color: T.choco2 }}>{filtered.length} movimiento{filtered.length === 1 ? "" : "s"} encontrado{filtered.length === 1 ? "" : "s"}</div></div>{(q || area || desde || hasta) && <button type="button" className="text-xs font-extrabold" style={{ color: T.coral }} onClick={() => { setQ(""); setArea(""); setDesde(""); setHasta(""); }}>Limpiar filtros</button>}</div>
      <Card className="overflow-hidden">
        <div className="divide-y" style={{ borderColor: T.border }}>
          {visible.map((entry) => (
            <div key={entry.id} className="p-3 sm:p-4 flex gap-3 items-start" style={{ borderColor: T.border }}>
              <div className="w-9 h-9 rounded-xl shrink-0 flex items-center justify-center text-sm font-black" style={{ background: entry.area === "Producción" ? "#DCE7F2" : entry.area === "Domicilios" ? "#DDEBD9" : entry.area === "Reclamos" ? "#F6D4CD" : T.vainilla, color: T.choco }}>↻</div>
              <div className="min-w-0 flex-1"><div className="flex flex-wrap items-center gap-2"><span className="text-[10px] uppercase tracking-wider font-extrabold" style={{ color: T.coral }}>{entry.area}</span><span className="text-[10px] font-bold" style={{ color: T.choco2 }}>{entry.entity}{entry.entityId ? ` · ${entry.entityId}` : ""}</span></div><div className="font-bold text-sm mt-0.5">{entry.action}</div>{(entry.from || entry.to) && <div className="text-xs font-semibold mt-1" style={{ color: T.choco2 }}>{entry.from || "—"} <span aria-hidden="true">→</span> <b style={{ color: T.choco }}>{entry.to || "—"}</b></div>}</div>
              <div className="text-right shrink-0"><time className="text-[10px] font-bold block" style={{ color: T.choco2 }}>{entry.at || "Sin fecha"}</time><span className="text-[10px] font-extrabold block mt-1">{entry.actor}</span></div>
            </div>
          ))}
          {!visible.length && <div className="p-10 text-center"><div className="text-3xl mb-2">⌕</div><div className="font-bold">No hay movimientos con esos filtros</div></div>}
        </div>
      </Card>
      {visible.length < filtered.length && <div className="mt-3 text-center"><Btn kind="ghost" onClick={() => setLimit((value) => value + 50)}>Ver 50 movimientos más</Btn></div>}
    </div>
  );
}

function Empaque({ db, update, user, refrescar, perfil }) {
  const [selId, setSelId] = useState(null);
  const [aviso, setAviso] = useState(null);
  const [scope, setScope] = useState("active");
  const verifications = db.packing_verifications || [];
  const packingQueue = buildPackingQueue(db.orders, db.order_dispatch_handoffs);
  const { incoming, pending, packed, handoff: handoffQueue, activeIds: activePackingIds } = packingQueue;
  const history = db.orders
    .filter((order) => isPackingHistoryOrder(order, db) && !activePackingIds.has(order.id))
    .sort((a, b) => `${b.fecha} ${b.hora}`.localeCompare(`${a.fecha} ${a.hora}`));
  const verifiedPending = pending.filter((order) => findPackingVerification(order.id, verifications)).length;
  const selected = selId ? db.orders.find((order) => order.id === selId) : null;

  async function cambiar(orderId, estado, opts) {
    const actual = db.orders.find((order) => order.id === orderId);
    const permiso = orderTransitionPermission(perfil, actual?.estado, estado, { quickSale: !!(opts && opts.ventaRapida) });
    if (!permiso.allowed) {
      setAviso({ titulo: "Este paso pertenece a otra área", texto: permiso.reason });
      return false;
    }
    try {
      await setOrderStatusRemoto(orderId, estado, !!(opts && opts.ventaRapida));
      await refrescar();
      toast("ok", `${orderId} → ${estado}`);
      if (estado !== "Empacado") setSelId(null);
      return true;
    } catch (error) {
      toast("error", error.message);
      return false;
    }
  }

  function OrderPackingCard({ order, index }) {
    const progress = packingStationProgress({
      orderId: order.id,
      orderItems: db.order_items,
      evidences: db.evidences,
      verifications,
    });
    const handoff = dispatchHandoffFor(order.id, db.order_dispatch_handoffs);
    const guide = ["Listo para empaque", "Empacado", "Listo para despacho"].includes(order.estado)
      ? buildPackingGuide({ orderStatus: order.estado, progress, handoff }) : null;
    const incomingOrder = order.estado === "En producción";
    const tone = incomingOrder ? "#3E5C7E" : order.estado === "Empacado" ? "#63518A" : order.estado === "Listo para despacho" ? "#2F6B60" : T.coral;
    const eyebrow = incomingOrder ? "En camino desde Cocina" : order.estado === "Listo para empaque" ? (index === 0 ? "Siguiente · FIFO" : `En cola · #${index + 1}`) : order.estado === "Empacado" ? "Empacado · preparar despacho" : "Relevo a Logística";
    const nextAction = incomingOrder ? "Cocina debe terminar y entregar la comanda" : guide?.nextAction || "Abrir y revisar el pedido";
    const footer = incomingOrder ? "Visible para anticipar caja y espacio; todavía no es accionable." : order.estado === "Listo para empaque" ? `${progress.completedSteps}/3 controles de Empaque completos.` : handoff?.status === "Ofrecido" ? "Paquete ofrecido; espera aceptación de Logística." : "Abrí para ver dirección, etiqueta y relevo.";
    return <CompactQueueOrderCard db={db} orderId={order.id} eyebrow={eyebrow} position={order.estado === "Listo para empaque" ? index + 1 : undefined}
      tone={tone} nextAction={nextAction} footer={footer} onOpen={() => setSelId(order.id)} />;
  }

  return (
    <div>
      <SectionTitle>Verificá la comanda antes de sellar</SectionTitle>
      <div className="text-xs font-semibold mb-3 -mt-3" style={{ color: T.choco2 }}>
        Compará cada producto, figura, sabor y cantidad. La verificación queda registrada con usuario y hora.
      </div>

      <div className="mb-4"><WorkScopeTabs value={scope} onChange={setScope} activeCount={incoming.length + pending.length + packed.length + handoffQueue.length} historyCount={history.length} activeLabel="Cola de Empaque" /></div>

      <div className="grid grid-cols-2 lg:grid-cols-5 gap-3 mb-3">
        <Stat icon="👩‍🍳" label="En Cocina" value={incoming.length} sub="pedidos que vienen en camino" tone="#3E5C7E" />
        <Stat icon="📦" label="Por empacar" value={pending.length} sub="comandas que Cocina entregó" tone={T.coral} />
        <Stat icon="🎁" label="Empacados" value={packed.length} sub="preparan dirección y etiqueta" tone="#63518A" />
        <Stat icon="🤝" label="En relevo" value={handoffQueue.length} sub="esperan a Logística" tone="#2F6B60" />
        <Stat icon="◷" label="Historial" value={history.length} sub="pedidos que ya salieron del área" tone="#3F6B42" onClick={() => setScope("history")} active={scope === "history"} />
      </div>

      {scope === "active" ? <>
      <div className="text-[11px] font-semibold mb-4 flex flex-wrap items-center gap-x-2 gap-y-1" style={{ color: T.choco2 }}>
        <span>En Cocina <b style={{ color: "#3E5C7E" }}>{incoming.length}</b></span>
        <span aria-hidden="true">→</span>
        <span>Cocina entregó <b style={{ color: "#3F6B42" }}>{pending.length}</b></span>
        <span aria-hidden="true">→</span>
        <span><b style={{ color: T.coral }}>{verifiedPending}</b> comparada{verifiedPending === 1 ? "" : "s"} con la orden</span>
        <span aria-hidden="true">→</span>
        <span><b style={{ color: "#63518A" }}>{packed.length}</b> empacada{packed.length === 1 ? "" : "s"}</span>
        <span aria-hidden="true">→</span>
        <span><b style={{ color: "#2F6B60" }}>{handoffQueue.length}</b> en relevo</span>
      </div>

      <SectionTitle>📋 Cola activa para verificar y empacar</SectionTitle>
      <div className="grid sm:grid-cols-2 xl:grid-cols-3 gap-3 mb-5">
        {pending.map((order, index) => <OrderPackingCard key={order.id} order={order} index={index} />)}
        {packed.map((order, index) => <OrderPackingCard key={order.id} order={order} index={index} />)}
        {handoffQueue.map((order, index) => <OrderPackingCard key={order.id} order={order} index={index} />)}
        {!pending.length && !packed.length && !handoffQueue.length && <Card className="p-8 text-center sm:col-span-2 xl:col-span-3"><div className="text-3xl mb-2">✅</div><div className="font-bold">No hay comandas accionables en Empaque</div><div className="text-xs mt-1" style={{ color: T.choco2 }}>Cuando Cocina marque “Listo para empaque”, aparecerán aquí automáticamente.</div></Card>}
      </div>

      {incoming.length > 0 && <>
        <SectionTitle>👩‍🍳 En camino desde Producción</SectionTitle>
        <div className="text-xs font-semibold mb-3 -mt-2" style={{ color: T.choco2 }}>Sirve para anticipar espacio, cajas y carga. Empaque podrá actuar cuando Cocina confirme el relevo.</div>
        <div className="grid sm:grid-cols-2 xl:grid-cols-3 gap-3">{incoming.map((order, index) => <OrderPackingCard key={order.id} order={order} index={index} />)}</div>
      </>}
      </> : <>
        <SectionTitle>◷ Historial de Empaque</SectionTitle>
        <div className="text-xs font-semibold mb-3 -mt-2" style={{ color: T.choco2 }}>Pedidos que ya fueron relevados a Logística o terminaron su recorrido. El historial es de consulta y no altera la operación.</div>
        <div className="grid sm:grid-cols-2 xl:grid-cols-3 gap-3">
          {history.map((order) => {
            const verification = findPackingVerification(order.id, verifications);
            const evidenceCount = evidencesOf(db, order.id).filter((evidence) => evidence.tipo !== "Comprobante de pago").length;
            return <CompactQueueOrderCard key={order.id} db={db} orderId={order.id} eyebrow="Historial de Empaque" tone="#3F6B42"
              nextAction="Consultar detalle y trazabilidad del pedido" footer={`${verification ? "Comanda verificada" : "Sin verificación"} · ${evidenceCount} evidencia${evidenceCount === 1 ? "" : "s"}`}
              onOpen={() => setSelId(order.id)} />;
          })}
          {!history.length && <Empty icon="◷" text="Todavía no hay pedidos en el historial de Empaque." />}
        </div>
      </>}

      {selected && <DetallePedido db={db} o={selected} update={update} user={user} onClose={() => setSelId(null)} cambiar={cambiar} setAviso={setAviso} refrescar={refrescar} perfil={perfil} />}
      {aviso && <Modal title={aviso.titulo} onClose={() => setAviso(null)}><p className="text-sm m-0">{aviso.texto}</p><div className="mt-4"><Btn onClick={() => setAviso(null)}>Entendido</Btn></div></Modal>}
    </div>
  );
}

const TRACE_HEALTH_STYLE = {
  blocked: { bg: "#F6D4CD", color: "#A03B2A", label: "Bloqueado" },
  attention: { bg: "#FBE8C8", color: "#96690F", label: "Requiere atención" },
  complete: { bg: "#DDEBD9", color: "#3F6B42", label: "Finalizado" },
  active: { bg: "#FBE3DA", color: "#E5714E", label: "En curso" },
};
const TRACE_EVENT_ICON = { created: "🧾", audit: "↻", evidence: "📷", assignment: "👤", incident: "⚠", packing: "🎁", delivery: "🛵", handoff: "🤝", claim: "💬", inventory: "📦" };

// Detalle completo de un pedido: se renderiza inline dentro de la fila expandida del acordeón.
// Read-only — reusa el shape de buildOrderTraceability tal cual. labelledBy apunta al botón cabecera.
function DetalleTrazabilidad({ trace, db, onOpen, labelledBy }) {
  const order = trace.order;
  const customer = customerOf(db, order.customerId);
  const health = TRACE_HEALTH_STYLE[traceabilityHealth(trace)] || TRACE_HEALTH_STYLE.active;
  return (
    <div role="region" aria-labelledby={labelledBy} className="momo-trace-open space-y-4 min-w-0 pt-3">
      <Card className="p-4 sm:p-5" style={{ borderColor: health.color + "66" }}>
        <div className="flex flex-col sm:flex-row sm:items-start justify-between gap-3">
          <div><div className="flex flex-wrap items-center gap-2"><h2 className="display text-2xl font-semibold m-0">{order.id}</h2><Badge label={order.estado} /><span className="rounded-full px-2.5 py-1 text-[10px] font-extrabold" style={{ background: health.bg, color: health.color }}>{health.label}</span></div><div className="text-xs font-semibold mt-1" style={{ color: T.choco2 }}>{order.fecha} · {order.hora} · {order.canal}</div></div>
          <Btn small onClick={() => onOpen(order.id)}>Abrir pedido completo</Btn>
        </div>
        <div className="mt-4 pl-3 border-l-2" style={{ borderColor: T.rosa }}>
          <div className="flex justify-between text-xs font-extrabold"><span>{trace.area}</span><span style={{ color: health.color }}>{trace.flow.percent}%</span></div>
          <div className="mt-3 relative" aria-label="Etapas del pedido">
            <div className="absolute left-[6px] right-[6px] top-[6px] h-[2px] rounded-full" style={{ background: "#EEDFCE" }} aria-hidden="true" />
            <div className="absolute left-[6px] top-[6px] h-[2px] rounded-full" style={{ width: `calc((100% - 12px) * ${Math.min(100, Math.max(0, trace.flow.percent)) / 100})`, background: health.color, transition: "width 620ms var(--momo-spring)" }} aria-hidden="true" />
            <div className="relative flex justify-between">
              {["Pago", "Cocina", "Empaque", "Despacho", "Entrega"].map((label, index) => <span key={label} className="w-3 h-3 rounded-full border-2" style={{ background: trace.flow.percent >= index * 25 ? health.color : T.surface, borderColor: trace.flow.percent >= index * 25 ? health.color : "#E4D5C4", transition: "background 400ms ease, border-color 400ms ease" }} aria-hidden="true" />)}
            </div>
            <div className="flex justify-between mt-1.5">
              {["Pago", "Cocina", "Empaque", "Despacho", "Entrega"].map((label, index) => <span key={label} className="text-[9px] font-extrabold" style={{ color: trace.flow.percent >= index * 25 ? health.color : T.choco2 }}>{label}</span>)}
            </div>
          </div>
        </div>
        <div className="mt-3 rounded-xl px-3 py-2 border" style={{ background: trace.openIncidents.length ? "#F6D4CD" : "#E3EFE0", borderColor: trace.openIncidents.length ? "#ECBBB1" : "#BFD8BE" }}><div className="text-[10px] uppercase tracking-wider font-extrabold" style={{ color: trace.openIncidents.length ? "#A03B2A" : "#3F6B42" }}>Siguiente acción</div><div className="text-sm font-bold">{trace.nextAction}</div></div>
      </Card>

      <div className="grid md:grid-cols-2 gap-4">
        <Card className="p-4"><div className="text-[10px] uppercase tracking-wider font-extrabold mb-2" style={{ color: T.choco2 }}>Cliente y destino</div><div className="font-bold">{customer.nombre || "Sin nombre"}</div><div className="text-sm">{customer.telefono || "Sin teléfono"}</div><div className="text-sm mt-1">{order.direccion || customer.direccion || "Sin dirección"}</div><div className="text-xs font-semibold mt-1" style={{ color: T.choco2 }}>{order.barrio || customer.barrio} · {order.zona}</div></Card>
        <Card className="p-4"><div className="text-[10px] uppercase tracking-wider font-extrabold mb-2" style={{ color: T.choco2 }}>Pago y valor</div><div className="flex justify-between text-sm"><span>Total</span><b>{fmt(orderTotal(db, order))}</b></div><div className="flex justify-between text-sm mt-1"><span>Medio</span><b>{order.pago || "Pendiente"}</b></div><div className="flex justify-between text-sm mt-1"><span>Comprobante</span><b style={{ color: order.comprobante ? "#3F6B42" : "#A03B2A" }}>{order.comprobante ? "Recibido ✓" : "Pendiente"}</b></div></Card>
      </div>

      <Card className="p-4">
        <div className="flex items-center justify-between gap-2 mb-3"><div><div className="text-[10px] uppercase tracking-wider font-extrabold" style={{ color: T.choco2 }}>Contenido y control físico</div><div className="display text-lg font-semibold">{trace.items.length} línea{trace.items.length === 1 ? "" : "s"} del pedido</div></div><span className="text-xs font-bold" style={{ color: trace.packing ? "#3F6B42" : T.choco2 }}>{trace.packing ? "Comanda verificada ✓" : "Sin verificación de Empaque"}</span></div>
        <div className="space-y-2">{trace.items.map((item) => {
          const lineProgress = trace.progress.filter((row) => row.orderItemId === item.id);
          return <div key={item.id} className="rounded-xl px-3 py-2 flex flex-col sm:flex-row sm:items-center gap-2" style={{ background: T.soft }}><div className="flex-1"><b className="text-sm">{item.cant}× {item.nombre}</b><div className="text-[11px] font-semibold" style={{ color: T.choco2 }}>{[item.figura, item.sabor, item.salsa, item.relleno].filter(Boolean).join(" · ")}</div></div><div className="flex flex-wrap gap-1">{lineProgress.map((row) => <span key={row.stage} className="rounded-full px-2 py-1 text-[9px] font-extrabold" style={{ background: row.status === "Incidente" ? "#F6D4CD" : row.status === "Listo" || row.status === "Verificado" ? "#DDEBD9" : T.vainilla }}>{row.stage}: {row.status}</span>)}</div></div>;
        })}</div>
      </Card>

      <div className="grid sm:grid-cols-2 lg:grid-cols-4 gap-3">
        {[["Responsable", trace.activeAssignments.map((row) => `${row.stage}: ${row.user || "asignado"}`).join(" · ") || "Sin etapa tomada"], ["Evidencias", `${trace.evidences.length} registradas`], ["Reservas FIFO", `${trace.reservations.length} movimientos`], ["Domicilio", trace.delivery ? `${trace.delivery.proveedor} · ${trace.delivery.estado}` : "Sin solicitud"]].map(([label, value]) => <Card key={label} className="p-3"><div className="text-[9px] uppercase tracking-wider font-extrabold" style={{ color: T.choco2 }}>{label}</div><div className="text-xs font-bold mt-1">{value}</div></Card>)}
      </div>

      <Card className="p-4 sm:p-5">
        <div className="text-[10px] uppercase tracking-[.14em] font-extrabold" style={{ color: T.coral }}>Trazabilidad completa</div><div className="display text-xl font-semibold mb-4">Qué ha pasado con {order.id}</div>
        <div className="relative pl-7 space-y-4 before:absolute before:left-[10px] before:top-2 before:bottom-2 before:w-px before:bg-[#EEDFCE]">
          {trace.events.map((event) => <div key={event.id} className="relative"><span className="absolute -left-7 top-0 w-5 h-5 rounded-full flex items-center justify-center text-[10px]" style={{ background: event.type === "incident" ? "#F6D4CD" : T.vainilla }}>{TRACE_EVENT_ICON[event.type] || "•"}</span><div className="flex flex-col sm:flex-row sm:items-start justify-between gap-1"><div><div className="text-sm font-bold">{event.title}</div>{event.detail && <div className="text-xs font-semibold mt-0.5" style={{ color: T.choco2 }}>{event.detail}</div>}<div className="text-[10px] font-bold mt-1" style={{ color: T.choco2 }}>{event.area}{event.actor ? ` · ${event.actor}` : ""}</div></div><time className="text-[10px] font-bold shrink-0" style={{ color: T.choco2 }}>{event.at || "Sin hora"}</time></div></div>)}
        </div>
      </Card>
    </div>
  );
}

// Buckets accionables de la cabecera: fuente única para conteo, filtro y etiqueta.
const PEDIDO_FOCOS = [
  { key: "seguimiento", icon: "🧾", label: "En seguimiento", sub: "pedidos no terminales", tone: T.coral, match: (t) => !["Entregado", "Cancelado"].includes(t.order.estado) },
  { key: "bloqueados", icon: "⚠️", label: "Bloqueados", sub: "novedades por resolver", tone: "#A03B2A", match: (t) => traceabilityHealth(t) === "blocked" },
  { key: "relevo", icon: "🤝", label: "En relevo", sub: "Empaque → Logística", tone: "#63518A", match: (t) => t.order.estado === "Listo para despacho" },
  { key: "ruta", icon: "🛵", label: "En ruta", sub: "esperan entrega", tone: "#3F6B42", match: (t) => t.order.estado === "En ruta" },
];

// Acordeón de pedidos: fila colapsada con lo esencial; click → despliega el detalle inline.
// Modo normal abre uno a la vez; "Comparar" permite varios abiertos en paralelo.
function PanelTrazabilidadPedidos({ db, orders, onOpen }) {
  const traces = useMemo(() => orders.map((order) => buildOrderTraceability(db, order)).filter(Boolean), [db, orders]);
  const [abiertos, setAbiertos] = useState(() => new Set());
  const [comparar, setComparar] = useState(false);
  const [foco, setFoco] = useState(null);

  // Purga ids abiertos que ya no existen tras un cambio de filtros/pedidos.
  useEffect(() => {
    setAbiertos((prev) => {
      if (!prev.size) return prev;
      const validos = new Set(traces.map((trace) => trace.order.id));
      const next = new Set([...prev].filter((id) => validos.has(id)));
      return next.size === prev.size ? prev : next;
    });
  }, [traces]);

  function toggle(id) {
    setAbiertos((prev) => {
      if (prev.has(id)) { const next = new Set(prev); next.delete(id); return next; }
      return comparar ? new Set(prev).add(id) : new Set([id]);
    });
  }

  const conteos = PEDIDO_FOCOS.map((f) => traces.filter(f.match).length);
  const focoActivo = PEDIDO_FOCOS.find((f) => f.key === foco) || null;
  const mostrados = focoActivo ? traces.filter(focoActivo.match) : traces;

  if (!traces.length) return <Card className="p-8 text-center"><div className="text-3xl mb-2">🔎</div><div className="font-bold">No hay pedidos que coincidan con la búsqueda</div></Card>;

  return (
    <div>
      <div className="grid grid-cols-2 lg:grid-cols-4 gap-3 mb-4">
        {PEDIDO_FOCOS.map((f, i) => (
          <Stat key={f.key} icon={f.icon} label={f.label} value={conteos[i]} sub={f.sub} tone={f.tone}
            active={foco === f.key}
            onClick={(conteos[i] > 0 || foco === f.key) ? () => setFoco((prev) => (prev === f.key ? null : f.key)) : undefined} />
        ))}
      </div>

      <div className="flex flex-wrap items-center justify-between gap-2 mb-3">
        <div className="flex items-center gap-2 min-w-0">
          <div className="text-[10px] uppercase tracking-[.14em] font-extrabold" style={{ color: T.choco2 }}>{focoActivo ? `${focoActivo.label} · ${mostrados.length} de ${traces.length}` : `Pedidos encontrados · ${traces.length}`}</div>
          {focoActivo && <button type="button" onClick={() => setFoco(null)} className="rounded-full px-2.5 py-0.5 text-[10px] font-extrabold border transition" style={{ borderColor: T.border, color: T.choco2, background: T.surface }}>✕ Quitar filtro</button>}
        </div>
        <button type="button" onClick={() => setComparar((v) => !v)} aria-pressed={comparar}
          className="rounded-full px-3 py-1.5 text-[11px] font-extrabold border transition"
          style={{ background: comparar ? T.coral : T.surface, color: comparar ? "#fff" : T.choco2, borderColor: comparar ? T.coral : T.border }}>
          {comparar ? "Comparar ✓" : "Comparar"}
        </button>
      </div>

      <div className="space-y-2">
        {mostrados.map((trace) => {
          const id = trace.order.id;
          const open = abiertos.has(id);
          const traceHealth = TRACE_HEALTH_STYLE[traceabilityHealth(trace)] || TRACE_HEALTH_STYLE.active;
          const traceCustomer = customerOf(db, trace.order.customerId);
          const headerId = `trace-head-${id}`;
          return (
            <Card key={id} data-open={open ? "true" : "false"} className="momo-trace-card p-0 overflow-hidden" style={{ borderColor: open ? "#E9A18C" : T.border }}>
              <button id={headerId} type="button" onClick={() => toggle(id)} aria-expanded={open}
                className="w-full text-left p-3 sm:p-4 flex items-start gap-3 transition"
                style={{ background: open ? T.coralSoft : T.surface }}>
                <span className="momo-trace-chevron shrink-0 mt-0.5 text-lg font-bold leading-none" data-open={open ? "true" : "false"} style={{ color: traceHealth.color }} aria-hidden="true">›</span>
                <div className="min-w-0 flex-1">
                  <div className="flex items-center justify-between gap-2"><b className="text-sm">{id}</b><span className="rounded-full px-2 py-0.5 text-[9px] font-extrabold shrink-0" style={{ background: traceHealth.bg, color: traceHealth.color }}>{traceHealth.label}</span></div>
                  <div className="flex items-center justify-between gap-2 mt-1"><span className="text-xs font-bold truncate">{traceCustomer.nombre || "Cliente sin nombre"}</span><Badge label={trace.order.estado} /></div>
                  <div className="text-[10px] font-semibold mt-1 truncate" style={{ color: T.choco2 }}>{trace.area}</div>
                  <div className="text-[10px] font-bold mt-1 truncate" style={{ color: traceHealth.color }}>{trace.nextAction}</div>
                </div>
              </button>
              {open && <div className="px-3 sm:px-4 pb-4"><DetalleTrazabilidad trace={trace} db={db} onOpen={onOpen} labelledBy={headerId} /></div>}
            </Card>
          );
        })}
        {focoActivo && !mostrados.length && <Card className="p-6 text-center"><div className="text-2xl mb-1">🫙</div><div className="text-sm font-bold">No hay pedidos en «{focoActivo.label}» ahora mismo</div></Card>}
      </div>
    </div>
  );
}

function Pedidos({ db, update, user, focus, refrescar, perfil }) {
  const [modo, setModo] = useState("kanban");
  const [asistenteVentasAbierto, setAsistenteVentasAbierto] = useState(false);
  const orderBuckets = useMemo(() => partitionByActivity(db.orders, isActiveOrder), [db.orders]);
  const [scope, setScope] = useState(() => (focus?.estado && !isActiveOrder({ estado: focus.estado }) ? "history" : "active"));
  const [selId, setSelId] = useState(null);
  const [nuevo, setNuevo] = useState(false);
  const [aviso, setAviso] = useState(null);
  const [verFiltros, setVerFiltros] = useState(!!(focus && (focus.estado || focus.desde || focus.pendientesPago)));
  const [pendPago, setPendPago] = useState(!!(focus && focus.pendientesPago));
  const [f, setF] = useState({ q: "", canal: "", estado: (focus && focus.estado) || "", barrio: "", producto: "", cliente: "", desde: (focus && focus.desde) || "", hasta: (focus && focus.hasta) || "" });
  const puedeCrearPedido = canCreateOrder(perfil);
  const salesAssistant = useMemo(() => buildSalesReceptionAssistant(db, { today: hoyISO() }), [db.orders, db.order_items, db.customers, db.evidences, db.benefits, db.products, db.variantes]);

  const barrios = [...new Set(db.orders.map((o) => o.barrio))];

  const scopeOrders = scope === "active" ? orderBuckets.active : orderBuckets.history;
  const filtrados = scopeOrders.filter((o) => {
    const c = customerOf(db, o.customerId);
    const items = itemsOf(db, o.id);
    const texto = (o.id + " " + (c.nombre || "") + " " + (c.telefono || "")).toLowerCase();
    const cumplePendPago = !pendPago || (["Nuevo","Confirmado","Pendiente de pago"].includes(o.estado) && !o.pagadoEn);
    return cumplePendPago
      && (!f.q || texto.includes(f.q.toLowerCase()))
      && (!f.canal || o.canal === f.canal)
      && (!f.estado || o.estado === f.estado)
      && (!f.barrio || o.barrio === f.barrio)
      && (!f.cliente || o.customerId === f.cliente)
      && (!f.producto || items.some((i) => i.productId === f.producto))
      && (!f.desde || o.fecha >= f.desde)
      && (!f.hasta || o.fecha <= f.hasta);
  });
  const columnasVisibles = scope === "active"
    ? ORDER_STATES.filter((state) => isActiveOrder({ estado: state }))
    : ["Entregado", "Cancelado"];

  // Fase 3: la transición vive en el SERVER (set_order_status con todas las gates). Luego re-fetch.
  async function cambiar(orderId, estado, opts) {
    const actual = db.orders.find((order) => order.id === orderId);
    const permiso = orderTransitionPermission(perfil, actual?.estado, estado, { quickSale: !!(opts && opts.ventaRapida) });
    if (!permiso.allowed) {
      setAviso({ titulo: "Este paso pertenece a otra área", texto: permiso.reason });
      return false;
    }
    let res;
    try {
      if (estado === "Listo para empaque" && db.operationalControlReady) {
        await completarEtapaPedido(orderId, "Cocina");
      }
      res = await setOrderStatusRemoto(orderId, estado, !!(opts && opts.ventaRapida));
    } catch (e) {
      toast("error", e.message);
      return false;
    }
    const faltantes = (res && res.faltantes) || [];
    try {
      await refrescar();
    } catch (e) {
      setAviso({ titulo: "Acción aplicada, vista desactualizada", texto: "El cambio se aplicó correctamente, pero no se pudo actualizar la vista. Recargá la página para ver el estado actual." + (faltantes.length ? " Ojo: había alertas de inventario, revisá Producción." : "") });
      return true;
    }
    toast("ok", estado === "Cancelado" ? `Pedido ${orderId} cancelado` : `${orderId} → ${estado}`);
    if (faltantes.length) {
      const prod = faltantes.filter((x) => x.area !== "Inventario");
      const ins = faltantes.filter((x) => x.area === "Inventario");
      const partes = [];
      if (prod.length) partes.push(`falta producir: ${prod.map((x) => x.cant + "× " + x.producto).join(", ")}`);
      if (ins.length) partes.push(`el inventario no alcanzó para: ${ins.map((x) => x.cant + "× " + x.producto).join(", ")}`);
      setAviso({ titulo: "Inventario insuficiente", texto: `Se reservó lo disponible, pero ${partes.join(" y ")}. Ya quedó la sugerencia en Producción.` });
    }
    return true;
  }

  function exportar() {
    downloadCSV("pedidos",
      ["Pedido","Fecha","Hora","Canal","Cliente","Teléfono","Barrio","Zona","Productos","Subtotal","Descuento","Domicilio cobrado","Costo domicilio","Total","Pago","Estado","Campaña","Creativo","Origen"],
      filtrados.map((o) => {
        const c = customerOf(db, o.customerId);
        const camp = db.campaigns.find((x) => x.id === o.campaignId);
        const cre = db.creatives.find((x) => x.id === o.creativeId);
        return [o.id, o.fecha, o.hora, o.canal, c.nombre, c.telefono, o.barrio, o.zona,
          itemsOf(db, o.id).map((i) => i.cant + "x " + i.nombre + (i.sabor ? " (" + i.sabor + ")" : "") + (i.costoUnitario !== undefined ? " · costo hist. " + fmt(i.costoUnitario) : "")).join(" | "),
          orderSubtotal(db, o), o.descuento, o.domCobrado, o.domCosto, orderTotal(db, o), o.pago, o.estado,
          camp ? camp.nombre : "", cre ? cre.titulo : "", o.origenDetalle || ""];
      }));
  }

  const sel = selId ? db.orders.find((o) => o.id === selId) : null;

  return (
    <div>
      <SectionTitle>Tablero de pedidos</SectionTitle>
      <div className="text-xs font-semibold mb-3 -mt-3" style={{ color: T.choco2 }}>
        Seguí cada pedido desde la agenda hasta la entrega, en tablero, tabla o trazabilidad.
      </div>

      <div className="grid grid-cols-2 lg:grid-cols-4 gap-3">
        <Stat icon="🧾" label="Pedidos" value={db.orders.length} sub="en el sistema" tone={T.coral} />
        <Stat icon="⚙" label="En operación" value={orderBuckets.active.length} sub="en flujo activo" tone="#63518A" />
        <Stat icon="◷" label="En historial" value={orderBuckets.history.length} sub="cerrados o cancelados" tone={T.choco} />
        <Stat icon="💵" label="Ventas (filtro)" value={fmt(filtrados.reduce((s, o) => s + orderTotal(db, o), 0))} sub="según filtros aplicados" tone="#3F6B42" />
      </div>
      <div className="text-[11px] font-semibold mt-2 mb-4" style={{ color: T.choco2 }}>
        <b style={{ color: T.coral }}>{orderBuckets.active.length}</b> en operación de {db.orders.length} pedidos registrados.
      </div>

      <Card className="p-3 mb-3" style={{ borderColor: "#A7C9A4", background: "#F2F8F0" }}>
        <div className="text-[10px] uppercase tracking-[.12em] font-extrabold" style={{ color: "#3F6B42" }}>Responsables del pedido</div>
        <div className="text-xs font-bold mt-1 leading-relaxed">Recepción agenda → Caja/Coordinación confirma pago → Cocina prepara → Empaque alista → Logística despacha y entrega.</div>
        <div className="text-[11px] font-semibold mt-1" style={{ color: T.choco2 }}>Tus roles: <b>{rolesLabel(perfil)}</b> · los permisos de cada área se acumulan.</div>
      </Card>
      <Card className="p-4 mb-3" onClick={() => setAsistenteVentasAbierto(true)} style={{ background: "linear-gradient(135deg,#FFF4EA,#FFFFFF)", borderColor: salesAssistant.summary.evidence || salesAssistant.summary.incomplete ? "#E7B36E" : T.border }}>
        <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-3">
          <div className="flex items-start gap-3 min-w-0">
            <span className="w-10 h-10 rounded-2xl flex items-center justify-center text-xl shrink-0" style={{ background: T.coralSoft }} aria-hidden="true">💬</span>
            <div className="min-w-0"><div className="text-[10px] uppercase tracking-[.14em] font-extrabold" style={{ color: T.coral }}>Asistente de Ventas y Recepción</div><div className="display text-lg font-semibold mt-0.5">{salesAssistant.summary.attention ? `${salesAssistant.summary.attention} ${salesAssistant.summary.attention === 1 ? "conversación" : "conversaciones"} por atender` : "Recepción está al día"}</div><div className="text-xs font-semibold mt-0.5" style={{ color: T.choco2 }}>{salesAssistant.summary.attention ? `${salesAssistant.summary.evidence} comprobante${salesAssistant.summary.evidence === 1 ? "" : "s"} por verificar · ${salesAssistant.summary.incomplete} pedido${salesAssistant.summary.incomplete === 1 ? "" : "s"} incompleto${salesAssistant.summary.incomplete === 1 ? "" : "s"} · ${fmt(salesAssistant.summary.pendingValue)} pendientes` : "No hay pedidos nuevos ni pagos pendientes en la cola."}</div></div>
          </div>
          <span className="text-xs font-extrabold shrink-0" style={{ color: T.coral }}>{salesAssistant.summary.attention ? "Ver siguiente acción ›" : "Ver análisis ›"}</span>
        </div>
      </Card>
      <div className="flex flex-wrap items-center gap-2 mb-3">
        {puedeCrearPedido && <Btn onClick={() => setNuevo(true)}>＋ Agendar pedido</Btn>}
        <WorkScopeTabs value={scope} onChange={(next) => { setScope(next); setPendPago(false); }} activeCount={orderBuckets.active.length} historyCount={orderBuckets.history.length} activeLabel="En operación" />
        <div className="flex rounded-xl overflow-hidden border" style={{ borderColor: T.border }}>
          {[{ id: "kanban", label: "Kanban" }, { id: "tabla", label: "Tabla" }, { id: "control", label: "Control y trazabilidad" }].map((option) => (
            <button key={option.id} onClick={() => setModo(option.id)} className="px-3 py-2 text-xs font-bold"
              style={{ background: modo === option.id ? T.rosa : T.surface, color: modo === option.id ? "#8E4B5A" : T.choco2 }}>{option.label}</button>
          ))}
        </div>
        <input value={f.q} onChange={(e) => setF({ ...f, q: e.target.value })} placeholder="Buscar pedido, cliente o teléfono…"
          className="flex-1 min-w-[170px] rounded-xl px-3 py-2 text-sm border outline-none" style={inputStyle} />
        <Btn small kind="ghost" onClick={() => setVerFiltros(!verFiltros)}>Filtros {(pendPago || Object.values(f).filter((v, i) => i > 0 && v).length > 0) && "●"}</Btn>
        <Btn small kind="ghost" onClick={exportar}>⬇ CSV</Btn>
      </div>

      {verFiltros && (
        <Card className="p-3 mb-4">
          {pendPago && (
            <div className="flex items-center justify-between gap-2 mb-2 px-2.5 py-1.5 rounded-xl" style={{ background: "#FBE8C8" }}>
              <span className="text-xs font-bold" style={{ color: "#96690F" }}>💳 Solo pendientes de pago (Nuevo, Confirmado o Pendiente de pago, sin pago registrado)</span>
              <button onClick={() => setPendPago(false)} className="text-xs font-bold" style={{ color: "#96690F" }}>Quitar ✕</button>
            </div>
          )}
          <div className="grid grid-cols-2 sm:grid-cols-4 gap-2">
          <MiniSelect placeholder="Canal: todos" options={CANALES} value={f.canal} onChange={(e) => setF({ ...f, canal: e.target.value })} />
          <MiniSelect placeholder="Estado: todos" options={ORDER_STATES} value={f.estado} onChange={(e) => { const estado = e.target.value; setF({ ...f, estado }); if (estado) setScope(isActiveOrder({ estado }) ? "active" : "history"); }} />
          <MiniSelect placeholder="Barrio: todos" options={barrios} value={f.barrio} onChange={(e) => setF({ ...f, barrio: e.target.value })} />
          <select value={f.producto} onChange={(e) => setF({ ...f, producto: e.target.value })} className="rounded-xl px-2 py-2 text-xs border font-semibold" style={inputStyle}>
            <option value="">Producto: todos</option>
            {db.products.map((p) => <option key={p.id} value={p.id}>{p.nombre}</option>)}
          </select>
          <select value={f.cliente} onChange={(e) => setF({ ...f, cliente: e.target.value })} className="rounded-xl px-2 py-2 text-xs border font-semibold" style={inputStyle}>
            <option value="">Cliente: todos</option>
            {db.customers.map((c) => <option key={c.id} value={c.id}>{c.nombre}</option>)}
          </select>
          <input type="date" value={f.desde} onChange={(e) => setF({ ...f, desde: e.target.value })} className="rounded-xl px-2 py-2 text-xs border font-semibold" style={inputStyle} aria-label="Desde" />
          <input type="date" value={f.hasta} onChange={(e) => setF({ ...f, hasta: e.target.value })} className="rounded-xl px-2 py-2 text-xs border font-semibold" style={inputStyle} aria-label="Hasta" />
          <Btn small kind="ghost" onClick={() => { setF({ q: f.q, canal: "", estado: "", barrio: "", producto: "", cliente: "", desde: "", hasta: "" }); setPendPago(false); }}>Limpiar</Btn>
          </div>
        </Card>
      )}

      {modo === "control" ? (
        <PanelTrazabilidadPedidos db={db} orders={filtrados} onOpen={setSelId} />
      ) : modo === "kanban" ? (
        <div className="flex gap-3 overflow-x-auto pb-3 -mx-1 px-1">
          {columnasVisibles.map((col) => {
            const enCol = filtrados.filter((o) => o.estado === col);
            return (
              <div key={col} className="w-64 shrink-0">
                <div className="flex items-center justify-between mb-2 px-1">
                  <Badge label={col} /><span className="text-xs font-bold" style={{ color: T.choco2 }}>{enCol.length}</span>
                </div>
                <div className="flex flex-col gap-2 min-h-[60px] rounded-2xl p-2" style={{ background: T.vainilla + "80" }}>
                  {enCol.map((o) => {
                    const c = customerOf(db, o.customerId);
                    return (
                      <Card key={o.id} className="p-3" onClick={() => setSelId(o.id)}>
                        <div className="flex justify-between items-start gap-2">
                          <div className="font-bold text-sm">{o.id}</div>
                          <Badge label={o.canal} map={CANAL_STYLE} />
                        </div>
                        <div className="text-sm font-semibold mt-1 truncate">{c.nombre}</div>
                        <div className="text-xs truncate" style={{ color: T.choco2 }}>{o.barrio} · {o.hora}</div>
                        <div className="text-xs mt-1 truncate" style={{ color: T.choco2 }}>
                          {itemsOf(db, o.id).map((i) => `${i.cant}× ${i.nombre.split(" ").slice(0, 2).join(" ")}`).join(", ")}
                        </div>
                        <div className="flex justify-between items-center mt-2">
                          <span className="display font-semibold" style={{ color: T.coral }}>{fmt(orderTotal(db, o))}</span>
                          {tieneSelloEmpaque(db, o.id) && <span title="Con sello de empaque" className="text-xs">📸</span>}
                        </div>
                      </Card>
                    );
                  })}
                  {enCol.length === 0 && <div className="text-xs text-center py-4 font-semibold" style={{ color: T.choco2 }}>Sin pedidos</div>}
                </div>
              </div>
            );
          })}
        </div>
      ) : (
        <Card className="overflow-x-auto">
          <table className="w-full text-sm min-w-[760px]">
            <thead><tr className="text-left text-xs" style={{ color: T.choco2 }}>
              {["Pedido","Cliente","Canal","Barrio","Total","Pago","Estado",""].map((h) => <th key={h} className="px-3 py-3 font-bold">{h}</th>)}
            </tr></thead>
            <tbody>
              {filtrados.map((o) => {
                const c = customerOf(db, o.customerId);
                return (
                  <tr key={o.id} className="border-t" style={{ borderColor: T.border }}>
                    <td className="px-3 py-2.5 font-bold">{o.id}<div className="text-xs font-normal" style={{ color: T.choco2 }}>{o.fecha} {o.hora}</div></td>
                    <td className="px-3 py-2.5">{c.nombre}<div className="text-xs" style={{ color: T.choco2 }}>{c.telefono}</div></td>
                    <td className="px-3 py-2.5"><Badge label={o.canal} map={CANAL_STYLE} /></td>
                    <td className="px-3 py-2.5">{o.barrio}</td>
                    <td className="px-3 py-2.5 font-bold" style={{ color: T.coral }}>{fmt(orderTotal(db, o))}</td>
                    <td className="px-3 py-2.5 text-xs font-semibold">{o.pago}{o.comprobante ? " ✓" : ""}</td>
                    <td className="px-3 py-2.5"><Badge label={o.estado} /></td>
                    <td className="px-3 py-2.5"><Btn small kind="ghost" onClick={() => setSelId(o.id)}>Abrir</Btn></td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </Card>
      )}

      {asistenteVentasAbierto && (
        <Modal title="Asistente de Ventas y Recepción" onClose={() => setAsistenteVentasAbierto(false)} wide>
          <div className="rounded-3xl border p-4 sm:p-5 mb-4" style={{ background: "linear-gradient(135deg,#FFF4EA,#FFFFFF)", borderColor: T.border }}>
            <div className="text-[10px] uppercase tracking-[.14em] font-extrabold" style={{ color: T.coral }}>Atención priorizada</div>
            <div className="display text-2xl font-semibold mt-1">Qué conversación atender ahora</div>
            <div className="text-sm font-semibold mt-1 max-w-2xl" style={{ color: T.choco2 }}>MOMO OPS reúne datos faltantes, comprobantes, disponibilidad exacta y contexto del cliente. Te recomienda el siguiente paso, pero no confirma pagos, beneficios ni sustituciones sin una persona autorizada.</div>
            <div className="grid grid-cols-2 sm:grid-cols-4 gap-2 mt-4">
              <div className="rounded-2xl bg-white px-3 py-3"><div className="text-[9px] uppercase font-extrabold" style={{ color: T.choco2 }}>En recepción</div><div className="display text-xl mt-0.5" style={{ color: T.coral }}>{salesAssistant.summary.attention}</div></div>
              <div className="rounded-2xl bg-white px-3 py-3"><div className="text-[9px] uppercase font-extrabold" style={{ color: T.choco2 }}>Comprobantes</div><div className="display text-xl mt-0.5" style={{ color: salesAssistant.summary.evidence ? "#3F6B42" : T.choco }}>{salesAssistant.summary.evidence}</div></div>
              <div className="rounded-2xl bg-white px-3 py-3"><div className="text-[9px] uppercase font-extrabold" style={{ color: T.choco2 }}>Incompletos</div><div className="display text-xl mt-0.5" style={{ color: salesAssistant.summary.incomplete ? "#A03B2A" : "#3F6B42" }}>{salesAssistant.summary.incomplete}</div></div>
              <div className="rounded-2xl bg-white px-3 py-3"><div className="text-[9px] uppercase font-extrabold" style={{ color: T.choco2 }}>Valor pendiente</div><div className="display text-lg mt-0.5" style={{ color: "#3F6B42" }}>{fmt(salesAssistant.summary.pendingValue)}</div></div>
            </div>
          </div>

          {salesAssistant.queue.length === 0 ? (
            <div className="rounded-3xl p-8 text-center" style={{ background: "#E5F0E1" }}><div className="text-3xl">✓</div><div className="display text-xl mt-2">Recepción al día</div><div className="text-sm font-semibold mt-1" style={{ color: "#3F6B42" }}>No hay pedidos nuevos, incompletos ni pagos esperando seguimiento.</div></div>
          ) : (
            <div className="space-y-2">
              {salesAssistant.queue.map((row, index) => {
                const stockTone = row.stock.status === "available" ? { bg: "#DDEBD9", fg: "#3F6B42" } : row.stock.status === "shortage" ? { bg: "#F6D4CD", fg: "#A03B2A" } : { bg: T.vainilla, fg: "#7B5410" };
                const waitLabel = row.waitingMinutes >= 60 ? `${Math.floor(row.waitingMinutes / 60)} h ${row.waitingMinutes % 60} min` : `${row.waitingMinutes} min`;
                return <Card key={row.orderId} className="p-4" style={{ borderColor: index === 0 ? "#E59A83" : T.border, background: index === 0 ? "#FFF8F4" : T.surface }}>
                  <div className="flex flex-col sm:flex-row sm:items-start gap-3">
                    <span className="w-8 h-8 rounded-full flex items-center justify-center text-xs font-black shrink-0" style={{ background: index === 0 ? T.coral : T.vainilla, color: index === 0 ? "#fff" : T.choco2 }}>{index + 1}</span>
                    <div className="flex-1 min-w-0">
                      <div className="flex flex-wrap items-center gap-2"><div className="font-extrabold">{row.orderId} · {row.customer.nombre || "Cliente sin nombre"}</div><Badge label={row.order.estado} /><Badge label={row.priority} map={{ Urgente: { bg: "#F6D4CD", fg: "#A03B2A" }, Alta: { bg: "#FBE8C8", fg: "#96690F" }, Normal: { bg: T.vainilla, fg: T.choco2 } }} /></div>
                      <div className="display text-lg font-semibold mt-1">{row.action}</div>
                      <div className="flex flex-wrap gap-1.5 mt-2"><span className="text-[10px] font-extrabold px-2 py-1 rounded-full" style={{ background: stockTone.bg, color: stockTone.fg }}>{row.stock.label}</span><span className="text-[10px] font-extrabold px-2 py-1 rounded-full" style={{ background: "#F2F2F2", color: T.choco2 }}>{fmt(row.total)} · espera {waitLabel}</span>{row.hasEvidence && <span className="text-[10px] font-extrabold px-2 py-1 rounded-full" style={{ background: "#E5F0E1", color: "#3F6B42" }}>Comprobante recibido</span>}</div>
                      {row.missing.length > 0 && <div className="text-[11px] font-bold mt-2" style={{ color: "#A03B2A" }}>Falta: {row.missing.join(" · ")}</div>}
                      {row.customerContext.length > 0 && <div className="text-[11px] font-semibold mt-1" style={{ color: T.choco2 }}>Cliente: {row.customerContext.join(" · ")}</div>}
                      {row.stock.status === "shortage" && <div className="text-[11px] font-semibold mt-1" style={{ color: "#A03B2A" }}>No prometas sustituciones: al pagar se generará la producción exacta faltante.</div>}
                    </div>
                    <div className="shrink-0"><Btn small onClick={() => { setAsistenteVentasAbierto(false); setSelId(row.orderId); }}>Abrir pedido</Btn></div>
                  </div>
                </Card>;
              })}
            </div>
          )}
        </Modal>
      )}

      {sel && <DetallePedido db={db} o={sel} update={update} user={user} onClose={() => setSelId(null)} cambiar={cambiar} setAviso={setAviso} refrescar={refrescar} perfil={perfil} />}
      {nuevo && puedeCrearPedido && <NuevoPedido db={db} update={update} user={user} onClose={() => setNuevo(false)} setAviso={setAviso} refrescar={refrescar} />}
      {aviso && (
        <Modal title={aviso.titulo} onClose={() => setAviso(null)}>
          <p className="text-sm m-0">{aviso.texto}</p>
          <div className="mt-4"><Btn onClick={() => setAviso(null)}>Entendido</Btn></div>
        </Modal>
      )}
    </div>
  );
}

function ControlOperativoPedido({ db, order, perfil, refrescar, setAviso }) {
  const stage = operationalStageForOrder(order);
  const assignment = stage ? activeStageAssignment(order.id, stage, db.order_stage_assignments) : null;
  const lines = stage && stage !== "Logística" ? lineProgressFor(order.id, stage, db.order_items, db.order_line_progress) : [];
  const incidents = openOrderIncidents(order.id, db.order_incidents);
  const handoff = dispatchHandoffFor(order.id, db.order_dispatch_handoffs);
  const allowed = stage && canOperateStage(perfil, stage);
  const owns = assignment && (assignment.userId === perfil?.id || hasRole(perfil, "Administrador"));
  const [busy, setBusy] = useState("");
  const [issueOpen, setIssueOpen] = useState(false);
  const [issue, setIssue] = useState({ type: "Faltante", description: "", orderItemId: "" });

  if (!db.operationalControlReady || !stage) return null;

  async function act(key, action, success) {
    if (busy) return;
    setBusy(key);
    try {
      await action();
      await refrescar();
      toast("ok", success);
    } catch (error) {
      setAviso({ titulo: "No se pudo completar el control operativo", texto: error.message });
    } finally { setBusy(""); }
  }

  const allKitchenReady = stage === "Cocina" && lines.length > 0 && lines.every(({ progress }) => progress.status === "Listo");
  return (
    <div id={`packing-control-${order.id}`} className="rounded-2xl border p-4 mb-4" style={{ background: "linear-gradient(135deg,#FFF9F1,#FFFFFF)", borderColor: T.border }}>
      <div className="flex flex-col sm:flex-row sm:items-start justify-between gap-3">
        <div>
          <div className="text-[10px] uppercase tracking-[.14em] font-extrabold" style={{ color: T.coral }}>Control operativo · {stage}</div>
          <div className="display text-lg font-semibold">{assignment ? `${assignment.user || "Responsable asignado"} tiene esta etapa` : "Etapa disponible para tomar"}</div>
          <div className="text-xs font-semibold mt-1" style={{ color: T.choco2 }}>
            {assignment ? `Tomada ${assignment.claimedAt}. Una sola persona confirma; el equipo puede consultar.` : "Tomarla evita que dos personas procesen la misma orden al tiempo."}
          </div>
        </div>
        <div className="flex flex-wrap gap-2">
          {!assignment && allowed && <Btn small disabled={!!busy} onClick={() => act("claim", () => tomarEtapaPedido(order.id, stage), `${order.id} · ${stage} quedó a tu cargo`)}>Tomar {stage}</Btn>}
          {assignment && owns && <Btn small kind="ghost" disabled={!!busy} onClick={() => act("release", () => liberarEtapaPedido(order.id, stage, "Reasignación operativa"), `${order.id} · etapa liberada`)}>Liberar etapa</Btn>}
          {allowed && <Btn small kind="rosa" disabled={!!busy} onClick={() => setIssueOpen((value) => !value)}>⚠ Registrar novedad</Btn>}
        </div>
      </div>

      {lines.length > 0 && <div className="mt-4 space-y-2">
        {lines.map(({ item, progress }) => (
          <div key={item.id} className="rounded-xl border px-3 py-2 flex flex-col sm:flex-row sm:items-center gap-2" style={{ borderColor: progress.status === "Incidente" ? "#E3A292" : T.border, background: progress.status === "Listo" || progress.status === "Verificado" ? "#F2F8F0" : "#fff" }}>
            <div className="flex-1 min-w-0">
              <div className="text-sm font-bold">{item.cant}× {item.nombre}</div>
              <div className="text-[11px] font-semibold" style={{ color: T.choco2 }}>{[item.figura, item.sabor, item.salsa].filter(Boolean).join(" · ") || "Línea de la orden"}</div>
            </div>
            <span className="rounded-full px-2.5 py-1 text-[10px] font-extrabold" style={{ background: progress.status === "Incidente" ? "#F8D6CF" : progress.status === "Listo" || progress.status === "Verificado" ? "#DDEBD9" : T.vainilla }}>{progress.status}</span>
            {stage === "Cocina" && owns && <select aria-label={`Estado de ${item.nombre}`} value={progress.status} disabled={!!busy}
              onChange={(event) => act(item.id, () => setProgresoLineaPedido(item.id, stage, event.target.value, progress.version || null), `${item.nombre} · ${event.target.value}`)}
              className="rounded-xl border px-2 py-2 text-xs font-bold" style={inputStyle}>
              {STAGE_LINE_STATUSES.Cocina.map((status) => <option key={status}>{status}</option>)}
            </select>}
          </div>
        ))}
        {stage === "Cocina" && owns && <div className="flex items-center justify-between gap-3 pt-1">
          <div className="text-[11px] font-semibold" style={{ color: allKitchenReady ? "#3F6B42" : T.choco2 }}>{lines.filter(({ progress }) => progress.status === "Listo").length}/{lines.length} líneas listas</div>
          {!allKitchenReady && <Btn small disabled={!!busy || incidents.length > 0} onClick={() => act("complete", () => completarEtapaPedido(order.id, "Cocina"), `${order.id} · todas las líneas quedaron listas`)}>Marcar cocina terminada</Btn>}
        </div>}
        {stage === "Empaque" && <div className="text-[11px] font-semibold" style={{ color: T.choco2 }}>Las líneas solo quedan Verificadas al completar la comparación exacta de la comanda; no pueden marcarse manualmente.</div>}
      </div>}

      {issueOpen && <div className="mt-4 rounded-xl p-3 border" style={{ background: T.coralSoft, borderColor: "#E8B5A5" }}>
        <div className="grid sm:grid-cols-3 gap-2">
          <select value={issue.orderItemId} onChange={(e) => setIssue({ ...issue, orderItemId: e.target.value })} className="rounded-xl border px-2 py-2 text-xs" style={inputStyle}>
            <option value="">Pedido completo</option>{lines.map(({ item }) => <option key={item.id} value={item.id}>{item.cant}× {item.nombre}</option>)}
          </select>
          <select value={issue.type} onChange={(e) => setIssue({ ...issue, type: e.target.value })} className="rounded-xl border px-2 py-2 text-xs" style={inputStyle}>
            {["Faltante", "Sustitución", "Preparación equivocada", "Rehacer", "Diferencia de empaque", "Dirección", "Domicilio", "Cliente ausente", "Otro"].map((type) => <option key={type}>{type}</option>)}
          </select>
          <input value={issue.description} onChange={(e) => setIssue({ ...issue, description: e.target.value })} placeholder="¿Qué ocurrió?" className="rounded-xl border px-3 py-2 text-xs" style={inputStyle} />
        </div>
        <div className="flex justify-end mt-2"><Btn small disabled={issue.description.trim().length < 3 || !!busy} onClick={() => act("issue", () => crearIncidentePedido({ order_id: order.id, order_item_id: issue.orderItemId || null, area: stage, type: issue.type, description: issue.description }), `${order.id} · novedad registrada`).then(() => { setIssueOpen(false); setIssue({ type: "Faltante", description: "", orderItemId: "" }); })}>Registrar y bloquear avance</Btn></div>
      </div>}

      {incidents.length > 0 && <div className="mt-3 space-y-2">{incidents.map((incident) => <div key={incident.id} className="rounded-xl px-3 py-2 flex items-center gap-3" style={{ background: "#FBE3DA" }}>
        <div className="flex-1 text-xs"><b>{incident.type}</b> · {incident.description}<div className="text-[10px] font-semibold" style={{ color: T.choco2 }}>{incident.area} · {incident.createdByName || "equipo"} · {incident.createdAt}</div></div>
        {(hasAnyRole(perfil, ["Administrador", "Coordinador de pedidos"]) || canOperateStage(perfil, incident.area)) && <Btn small kind="ghost" disabled={!!busy} onClick={() => act(incident.id, () => resolverIncidentePedido(incident.id, "Resuelto y validado por el área responsable"), `${incident.id} · resuelto`)}>Resolver</Btn>}
      </div>)}</div>}

      {order.estado === "Listo para despacho" && <div className="mt-4 rounded-xl border p-3 flex flex-col sm:flex-row sm:items-center justify-between gap-3" style={{ background: handoff?.status === "Aceptado" ? "#F2F8F0" : "#F7F0FF", borderColor: handoff?.status === "Aceptado" ? "#A7C9A4" : "#D8C8E8" }}>
        <div><div className="text-xs font-extrabold">Relevo físico Empaque → Logística</div><div className="text-[11px] font-semibold" style={{ color: T.choco2 }}>{handoff ? `${handoff.status} · ${handoff.packingUser || "Empaque"}${handoff.logisticsUser ? ` → ${handoff.logisticsUser}` : ""}` : "Empaque debe ofrecer el paquete y Logística aceptarlo antes de iniciar ruta."}</div></div>
        <div className="flex gap-2">
          {canOperateStage(perfil, "Empaque") && (!handoff || handoff.status !== "Aceptado") && <Btn small disabled={!!busy} onClick={() => act("offer", () => ofrecerRelevoDespacho(order.id), `${order.id} · ofrecido a Logística`)}>Ofrecer paquete</Btn>}
          {canOperateStage(perfil, "Logística") && handoff?.status === "Ofrecido" && <Btn small disabled={!!busy} onClick={() => act("accept", () => aceptarRelevoDespacho(order.id), `${order.id} · relevo aceptado`)}>Aceptar paquete</Btn>}
        </div>
      </div>}
    </div>
  );
}

function PackingCopilot({ order, progress, handoff }) {
  const guide = buildPackingGuide({ orderStatus: order.estado, progress, handoff });
  const current = guide.current;
  const topLines = progress.lines.filter((line) => !line.parentItemId);
  const targetByStep = {
    receive: `packing-control-${order.id}`,
    verify: `packing-checklist-${order.id}`,
    "open-photo": `packing-evidence-${order.id}`,
    "seal-photo": `packing-evidence-${order.id}`,
    pack: `packing-actions-${order.id}`,
    handoff: order.estado === "Empacado" ? `packing-delivery-${order.id}` : `packing-control-${order.id}`,
  };
  const actionLabel = {
    receive: "Ir al responsable",
    verify: "Ir a comparar",
    "open-photo": "Ir a la foto",
    "seal-photo": "Ir al sello",
    pack: "Ir a confirmar",
    handoff: order.estado === "Empacado" ? "Preparar etiqueta" : "Ir al relevo",
  };

  function focusCurrentStep() {
    const target = current && document.getElementById(targetByStep[current.key]);
    target?.scrollIntoView({ behavior: "smooth", block: "center" });
  }

  return (
    <div className="rounded-3xl border p-4 sm:p-5 mb-4 overflow-hidden" style={{ background: "linear-gradient(135deg,#FFF7F1 0%,#FFFFFF 58%,#F2F8F0 100%)", borderColor: "#E8CDBD" }}>
      <div className="flex flex-col lg:flex-row lg:items-start justify-between gap-4">
        <div className="min-w-0">
          <div className="text-[10px] uppercase tracking-[.16em] font-extrabold" style={{ color: T.coral }}>Copiloto de Empaque · pedido {order.id}</div>
          <div className="display text-xl sm:text-2xl font-semibold mt-0.5">Una comanda, seis controles, cero suposiciones</div>
          <div className="text-xs font-semibold mt-1 max-w-2xl" style={{ color: T.choco2 }}>Te acompaña desde la entrega de Cocina hasta el relevo físico a Logística. Cada avance usa la verificación y las evidencias oficiales del pedido.</div>
        </div>
        <div className="shrink-0 flex items-center gap-2 rounded-2xl px-3 py-2 border" style={{ background: "#fff", borderColor: guide.complete ? "#A7C9A4" : T.border }}>
          <span className="display text-2xl font-semibold" style={{ color: guide.complete ? "#3F6B42" : T.coral }}>{guide.completed}/{guide.total}</span>
          <span className="text-[10px] font-extrabold leading-tight" style={{ color: T.choco2 }}>{guide.complete ? "RELEVO\nCOMPLETO" : "PASOS\nSEGUROS"}</span>
        </div>
      </div>

      <div className="mt-4 grid grid-cols-2 md:grid-cols-3 xl:grid-cols-6 gap-2" aria-label={`Guía de Empaque para ${order.id}`}>
        {guide.steps.map((step, index) => {
          const done = step.status === "done";
          const active = step.status === "current";
          return <div key={step.key} className="rounded-2xl border px-3 py-3 min-h-[112px]" style={{ background: done ? "#F2F8F0" : active ? T.coralSoft : "#fff", borderColor: done ? "#A7C9A4" : active ? "#E59A83" : T.border, opacity: step.status === "pending" ? .72 : 1 }}>
            <div className="flex items-center justify-between gap-2"><span className="w-7 h-7 rounded-full flex items-center justify-center text-xs font-black" style={{ background: done ? "#3F6B42" : active ? T.coral : T.vainilla, color: done || active ? "#fff" : T.choco2 }}>{done ? "✓" : index + 1}</span><span aria-hidden="true">{step.icon}</span></div>
            <div className="text-xs font-extrabold mt-2 leading-tight">{step.title}</div>
            <div className="text-[10px] font-semibold mt-1 leading-snug" style={{ color: T.choco2 }}>{step.detail}</div>
          </div>;
        })}
      </div>

      <div className="mt-4 grid lg:grid-cols-[1.35fr_.65fr] gap-3">
        <div className="rounded-2xl border px-4 py-3 flex flex-col sm:flex-row sm:items-center justify-between gap-3" style={{ background: guide.complete ? "#E3EFE0" : "#FFF5E2", borderColor: guide.complete ? "#BFD8BE" : "#E7C078" }}>
          <div><div className="text-[10px] uppercase tracking-wider font-extrabold" style={{ color: guide.complete ? "#3F6B42" : "#96690F" }}>{guide.complete ? "Trabajo cerrado" : `Ahora · ${current?.title || "Completado"}`}</div><div className="text-sm font-extrabold mt-0.5">{guide.nextAction}</div></div>
          {!guide.complete && current && <Btn small onClick={focusCurrentStep}>{actionLabel[current.key] || "Continuar"}</Btn>}
        </div>
        <div className="rounded-2xl border px-4 py-3" style={{ background: "#fff", borderColor: T.border }}>
          <div className="text-[10px] uppercase tracking-wider font-extrabold" style={{ color: T.choco2 }}>Contenido esperado</div>
          <div className="text-sm font-extrabold mt-0.5">{topLines.length} línea{topLines.length === 1 ? "" : "s"} principal{topLines.length === 1 ? "" : "es"} · {progress.lines.length} control{progress.lines.length === 1 ? "" : "es"}</div>
          <div className="text-[10px] font-semibold mt-1 line-clamp-2" style={{ color: T.choco2 }}>{topLines.map((line) => line.label).join(" · ") || "La orden no tiene líneas verificables."}</div>
        </div>
      </div>
    </div>
  );
}

function DetallePedido({ db, o, update, user, onClose, cambiar, setAviso, refrescar, perfil, contextActions = null }) {
  const fileRef = useRef(null);
  const tipoSubidaRef = useRef("Comprobante de pago"); // tipo fijo de la subida en curso
  const [tipoEv, setTipoEv] = useState(o.pagadoEn ? "Entrega" : "Comprobante de pago"); // solo para el modo libre (＋ otra foto)
  const [libre, setLibre] = useState(false); // muestra el picker manual para documentales
  const [subiendo, setSubiendo] = useState(false);
  const [foto, setFoto] = useState(null);
  const [enviando, setEnviando] = useState(false); // guarda local: cambiar() y crearReclamo() son async vía props
  const [verificandoEmpaque, setVerificandoEmpaque] = useState(false);
  const [etiquetaDomicilio, setEtiquetaDomicilio] = useState(false);
  const [solicitudDomicilio, setSolicitudDomicilio] = useState(false);
  const [creandoDomicilio, setCreandoDomicilio] = useState(false);
  const [verMasAcciones, setVerMasAcciones] = useState(false);
  const [formDomicilio, setFormDomicilio] = useState(() => ({
    proveedor: db.settings.proveedores[0] || "",
    zona: o.zona || db.settings.zonas[0]?.nombre || "",
    costoReal: "",
    obs: o.obs || "",
  }));
  const c = customerOf(db, o.customerId);
  const evs = evidencesOf(db, o.id);
  const packingLines = buildPackingChecklistLines(o.id, db.order_items);
  const packingVerificationCandidate = findPackingVerification(o.id, db.packing_verifications || []);
  const packingVerification = packingVerificationMatchesLines(packingVerificationCandidate, packingLines) ? packingVerificationCandidate : null;
  const packingProgress = packingStationProgress({ orderId: o.id, orderItems: db.order_items, evidences: db.evidences, verifications: db.packing_verifications || [] });
  const packingHandoff = dispatchHandoffFor(o.id, db.order_dispatch_handoffs);
  const [checkedPackingLines, setCheckedPackingLines] = useState(() => new Set(packingVerification ? packingLines.map((line) => line.id) : []));
  const flujo = { "Nuevo": "Confirmado", "Confirmado": "Pendiente de pago", "Pendiente de pago": "Pagado", "Pagado": "En producción", "En producción": "Listo para empaque", "Listo para empaque": "Empacado", "Empacado": "Listo para despacho", "Listo para despacho": "En ruta", "En ruta": "Entregado" };
  const siguiente = flujo[o.estado];
  const comprobantePagoVinculado = tieneEvidencia(db, o.id, "Comprobante de pago");
  const accionRecepcion = orderIntakePrimaryAction(perfil, o, { hasPaymentEvidence: comprobantePagoVinculado });
  const permisoSiguiente = siguiente ? orderTransitionPermission(perfil, o.estado, siguiente) : null;
  const permisoPago = orderTransitionPermission(perfil, o.estado, "Pagado");
  const permisoEntregaRapida = orderTransitionPermission(perfil, o.estado, "Entregado", { quickSale: true });
  const permisoCancelar = orderTransitionPermission(perfil, o.estado, "Cancelado");
  const permisoReclamo = orderTransitionPermission(perfil, o.estado, "Reclamo");
  const puedeCorregirPago = !accionRecepcion && o.estado === "En producción" && permisoPago.allowed && !comprobantePagoVinculado;
  const puedeEntregaRapida = permisoEntregaRapida.allowed && o.pagadoEn && ["Pagado","En producción","Empacado","Listo para despacho"].includes(o.estado);
  const puedeCrearReclamo = permisoReclamo.allowed && !["Reclamo","Cancelado"].includes(o.estado);
  const puedeCancelarPedido = permisoCancelar.allowed && !["Entregado","Cancelado","Reclamo"].includes(o.estado);
  const hayAccionesSecundarias = puedeCorregirPago || puedeEntregaRapida || puedeCrearReclamo || puedeCancelarPedido;
  const tiposEvidenciaPermitidos = EV_TIPOS.filter((tipo) => orderEvidencePermission(perfil, tipo).allowed);
  const puedeGestionarRelevo = canManageDeliveryHandoff(perfil);
  const domicilioActivo = db.deliveries.find((delivery) => delivery.orderId === o.id && deliveryBlocksNewRequest(delivery));
  const direccionParaCopiar = o.direccion || c.direccion || "";
  const textoDomicilio = [
    `Pedido ${o.id}`,
    `Cliente: ${c.nombre || "Sin nombre"}`,
    `Teléfono: ${c.telefono || "Sin teléfono"}`,
    `Dirección: ${o.direccion || c.direccion || "Sin dirección"}`,
    `Barrio: ${o.barrio || c.barrio || "Sin barrio"}`,
    `Zona: ${o.zona || "Sin zona"}`,
    `Apto/casa/local y referencia: ${o.obs || "Sin referencia adicional"}`,
  ].join("\n");

  useEffect(() => {
    setCheckedPackingLines(new Set(packingVerification ? packingLines.map((line) => line.id) : []));
  }, [o.id, packingVerification?.verifiedAt]);

  const packingChecklistComplete = packingLines.length > 0 && packingLines.every((line) => checkedPackingLines.has(line.id));

  async function confirmarChecklistEmpaque() {
    if (!packingChecklistComplete || verificandoEmpaque) return;
    setVerificandoEmpaque(true);
    try {
      await confirmarVerificacionEmpaque(o.id, packingLines.map((line) => line.id));
      await refrescar();
      toast("ok", `${o.id} · comanda verificada contra la orden`);
    } catch (error) {
      setAviso({ titulo: "No se pudo verificar la comanda", texto: error.message });
    } finally {
      setVerificandoEmpaque(false);
    }
  }

  async function solicitarDomicilioDesdePedido() {
    if (creandoDomicilio || domicilioActivo || o.canal === "Rappi") return;
    setCreandoDomicilio(true);
    try {
      await crearDomicilio(o.id, formDomicilio.proveedor, formDomicilio.zona, Math.max(0, +formDomicilio.costoReal || 0), formDomicilio.obs);
      await refrescar();
      setSolicitudDomicilio(false);
      toast("ok", `${o.id} · domicilio solicitado`);
    } catch (error) {
      setAviso({ titulo: "No se pudo solicitar el domicilio", texto: error.message });
    } finally {
      setCreandoDomicilio(false);
    }
  }

  async function onFile(e) {
    const file = e.target.files && e.target.files[0];
    if (!file) return;
    const tipo = tipoSubidaRef.current;
    const permisoEvidencia = orderEvidencePermission(perfil, tipo);
    if (!permisoEvidencia.allowed) {
      setAviso({ titulo: "Esta foto pertenece a otra área", texto: permisoEvidencia.reason });
      if (fileRef.current) fileRef.current.value = "";
      return;
    }
    setSubiendo(true);
    try {
      const url = await compressImage(file);
      // Fase 3: la foto va al bucket privado + RPC crear_evidencia (id/user/audit server-side)
      await subirEvidencia({ orderId: o.id, tipo, dataUrl: url });
    } catch (err) {
      setAviso({ titulo: "Error al subir", texto: err.message || "No se pudo procesar la imagen. Intenta con otra foto." });
      setSubiendo(false);
      if (fileRef.current) fileRef.current.value = "";
      return;
    }
    if (tipo === "Comprobante de pago" && accionRecepcion?.type === "evidence" && accionRecepcion.autoAdvance && accionRecepcion.allowed) {
      const pagoConfirmado = await cambiar(o.id, accionRecepcion.target);
      if (pagoConfirmado) {
        setSubiendo(false);
        if (fileRef.current) fileRef.current.value = "";
        return;
      }
    }
    try {
      await refrescar();
    } catch (err) {
      setAviso({ titulo: "Acción aplicada, vista desactualizada", texto: "La evidencia se guardó correctamente, pero no se pudo actualizar la vista. Recargá la página para verla." });
    }
    setSubiendo(false);
    if (fileRef.current) fileRef.current.value = "";
  }

  // Dispara la cámara/galería para una foto con su tipo YA FIJO (evidencias guiadas por paso).
  function abrirCamara(tipo) {
    const permiso = orderEvidencePermission(perfil, tipo);
    if (!permiso.allowed) {
      setAviso({ titulo: "Esta foto pertenece a otra área", texto: permiso.reason });
      return;
    }
    tipoSubidaRef.current = tipo;
    if (fileRef.current) fileRef.current.click();
  }

  return (
    <Modal title={`Pedido ${o.id}`} onClose={onClose} wide>
      <div className="flex flex-wrap items-center gap-2 mb-4">
        <Badge label={o.estado} /><Badge label={o.canal} map={CANAL_STYLE} />
        <span className="text-xs font-semibold" style={{ color: T.choco2 }}>{o.fecha} · {o.hora}</span>
      </div>

      {(accionRecepcion || siguiente) && (
        <div className="rounded-2xl border px-4 py-3 mb-4" role="note"
          style={{ background: (accionRecepcion || permisoSiguiente).allowed ? "#F2F8F0" : "#FFF9F1", borderColor: (accionRecepcion || permisoSiguiente).allowed ? "#A7C9A4" : "#E7C078" }}>
          <div className="text-[10px] uppercase tracking-[.12em] font-extrabold" style={{ color: (accionRecepcion || permisoSiguiente).allowed ? "#3F6B42" : "#96690F" }}>{accionRecepcion ? "Una sola acción para avanzar" : "Responsable del siguiente paso"}</div>
          <div className="text-sm font-extrabold mt-0.5">{accionRecepcion ? accionRecepcion.label : `${o.estado} → ${siguiente}: ${permisoSiguiente.ownerLabel}`}</div>
          <div className="text-xs font-semibold mt-1" style={{ color: T.choco2 }}>{accionRecepcion ? accionRecepcion.detail : permisoSiguiente.allowed ? "Tu área puede confirmar este avance cuando termine el trabajo." : "Podés consultar la orden, pero la confirmación queda en manos del área que ejecuta el paso."}</div>
        </div>
      )}

      {["Listo para empaque", "Empacado", "Listo para despacho"].includes(o.estado) && <PackingCopilot order={o} progress={packingProgress} handoff={packingHandoff} />}

      <ControlOperativoPedido db={db} order={o} perfil={perfil} refrescar={refrescar} setAviso={setAviso} />

      <div className="grid sm:grid-cols-2 gap-4">
        <Card className="p-4">
          <div className="text-xs font-bold mb-2" style={{ color: T.choco2 }}>CLIENTE Y ENTREGA</div>
          <div className="text-sm font-bold">{c.nombre}</div>
          <div className="text-sm">{c.telefono} {c.instagram && `· ${c.instagram}`}</div>
          <div className="text-sm mt-1">{o.direccion}</div>
          <div className="text-xs font-semibold mt-1" style={{ color: T.choco2 }}>{o.barrio} · {o.zona}</div>
          {o.obs && <div className="text-xs mt-2 p-2 rounded-lg" style={{ background: T.vainilla }}>📝 {o.obs}</div>}
          {(o.campaignId || o.creativeId || o.origenDetalle) && (() => {
            const camp = db.campaigns.find((c) => c.id === o.campaignId);
            const cre = db.creatives.find((c) => c.id === o.creativeId);
            return (
              <div className="text-xs mt-2 p-2 rounded-lg" style={{ background: "#F3D7DC55" }}>
                📣 {[camp && "Campaña: " + camp.nombre, cre && "Creativo: " + cre.titulo, o.origenDetalle && "Origen: " + o.origenDetalle].filter(Boolean).join(" · ")}
              </div>
            );
          })()}
        </Card>
        <Card className="p-4">
          <div className="text-xs font-bold mb-2" style={{ color: T.choco2 }}>PAGO</div>
          <div className="flex justify-between text-sm py-1"><span>Subtotal productos</span><b>{fmt(orderSubtotal(db, o))}</b></div>
          {o.descuento > 0 && <div className="flex justify-between text-sm py-1" style={{ color: "#3F6B42" }}><span>Beneficio {o.benefitId && `(${o.benefitId})`}</span><b>−{fmt(o.descuento)}</b></div>}
          <div className="flex justify-between text-sm py-1"><span>Domicilio cobrado</span><b>{fmt(o.domCobrado)}</b></div>
          <div className="flex justify-between text-sm py-1 items-center" style={{ color: T.choco2 }}>
            <span>Costo real domicilio</span>
            {o.canal === "Rappi" ? (
              <span className="text-xs font-bold" style={{ color: T.choco2 }}>$0 · Rappi app</span>
            ) : (
              <input type="number" value={o.domCosto || ""} placeholder="registrar"
                onChange={(e) => update((d) => { const x = d.orders.find((y) => y.id === o.id); x.domCosto = +e.target.value || 0; })}
                className="w-24 rounded-lg px-2 py-1 text-xs border text-right font-bold" style={inputStyle} />
            )}
          </div>
          <div className="flex justify-between py-2 mt-1 border-t display text-lg" style={{ borderColor: T.border }}><span>Total</span><b style={{ color: T.coral }}>{fmt(orderTotal(db, o))}</b></div>
          <div className="text-xs font-semibold">{o.pago} {o.canal === "Rappi" ? "· pago en la app" : comprobantePagoVinculado ? "· comprobante vinculado ✓" : "· sin comprobante"}</div>
        </Card>
      </div>

      {puedeGestionarRelevo && ["Listo para empaque", "Empacado", "Listo para despacho"].includes(o.estado) && (
        <div id={`packing-delivery-${o.id}`} className="mt-4 rounded-2xl border p-4" style={{ background: "#FFF9F1", borderColor: T.border }}>
          <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-3">
            <div>
              <div className="text-[10px] uppercase tracking-[.12em] font-extrabold" style={{ color: "#8E4B5A" }}>Relevo a domicilio</div>
              <div className="display text-lg font-semibold">Dirección lista para copiar o etiquetar</div>
              <div className="text-xs font-semibold mt-0.5" style={{ color: T.choco2 }}>{o.direccion || c.direccion || "Falta registrar dirección"} · {c.telefono || "sin teléfono"}</div>
            </div>
            <div className="flex flex-wrap gap-2">
              <Btn small kind="ghost" disabled={!direccionParaCopiar} onClick={() => {
                if (copiarTexto(direccionParaCopiar)) toast("ok", `${o.id} · dirección copiada`);
                else setAviso({ titulo: "No se pudo copiar", texto: "Tu navegador bloqueó el portapapeles. Podés abrir la etiqueta y copiar los datos manualmente." });
              }}>📋 Copiar dirección</Btn>
              <Btn small kind="rosa" onClick={() => setEtiquetaDomicilio(true)}>🖨️ Imprimir etiqueta</Btn>
              {!domicilioActivo && o.canal !== "Rappi" && <Btn small onClick={() => setSolicitudDomicilio(true)}>🛵 Solicitar domicilio</Btn>}
            </div>
          </div>
          <div className="mt-2 text-[11px] font-bold" style={{ color: domicilioActivo ? "#3F6B42" : o.canal === "Rappi" ? "#96690F" : T.choco2 }}>
            {domicilioActivo ? `✓ Domicilio ${domicilioActivo.id} · ${domicilioActivo.proveedor} · ${domicilioActivo.estado}` : o.canal === "Rappi" ? "Rappi gestiona este domicilio desde su aplicación." : "Todavía no hay un domicilio solicitado para esta orden."}
          </div>
        </div>
      )}

      {["Listo para empaque", "Empacado", "Listo para despacho"].includes(o.estado) && (
        <div id={`packing-checklist-${o.id}`} className="mt-4 rounded-2xl border p-4" style={{ background: packingVerification ? "#F2F8F0" : T.soft, borderColor: packingVerification ? "#A7C9A4" : T.border }}>
          <div className="flex flex-wrap items-start justify-between gap-2 mb-3">
            <div>
              <div className="text-[10px] uppercase tracking-[.12em] font-extrabold" style={{ color: packingVerification ? "#3F6B42" : "#A54830" }}>Control de coincidencia</div>
              <div className="display text-lg font-semibold">Orden solicitada vs. contenido recibido</div>
              <div className="text-xs font-semibold mt-0.5" style={{ color: T.choco2 }}>Marcá cada línea únicamente después de verla físicamente en la mesa de Empaque.</div>
            </div>
            <span className="rounded-full px-3 py-1.5 text-[10px] font-extrabold" style={{ background: packingVerification ? "#DDEBD9" : T.vainilla, color: packingVerification ? "#3F6B42" : "#96690F" }}>
              {packingVerification ? "✓ Verificación registrada" : `${checkedPackingLines.size}/${packingLines.length} líneas`}
            </span>
          </div>
          <div className="space-y-2">
            {packingLines.map((line) => (
              <label key={line.id} className="flex items-start gap-3 rounded-xl border px-3 py-2.5 cursor-pointer" style={{ background: checkedPackingLines.has(line.id) ? "#fff" : T.vainilla, borderColor: checkedPackingLines.has(line.id) ? "#A7C9A4" : T.border }}>
                <input type="checkbox" className="mt-1 accent-[#E5714E]" checked={checkedPackingLines.has(line.id)} disabled={Boolean(packingVerification)} onChange={(event) => {
                  setCheckedPackingLines((current) => {
                    const next = new Set(current);
                    if (event.target.checked) next.add(line.id); else next.delete(line.id);
                    return next;
                  });
                }} />
                <span className="min-w-0">
                  <span className="block text-sm font-extrabold">{line.parentItemId ? "↳ " : ""}{line.label}</span>
                  {line.detail && <span className="block text-[11px] font-semibold mt-0.5" style={{ color: T.choco2 }}>{line.detail}</span>}
                </span>
              </label>
            ))}
          </div>
          {packingVerification ? (
            <div className="text-xs font-bold mt-3" style={{ color: "#3F6B42" }}>✓ {packingVerification.user || "Empaque"} confirmó {packingVerification.lineIds?.length || packingLines.length} líneas · {packingVerification.verifiedAt}</div>
          ) : (
            <div className="mt-3">
              <Btn disabled={!packingChecklistComplete || verificandoEmpaque} onClick={confirmarChecklistEmpaque}>{verificandoEmpaque ? "Registrando verificación…" : "Confirmar que todo coincide"}</Btn>
              {!packingChecklistComplete && <div className="text-[10px] font-bold mt-1.5" style={{ color: "#96690F" }}>Faltan {Math.max(0, packingLines.length - checkedPackingLines.size)} línea(s) por comparar.</div>}
            </div>
          )}
        </div>
      )}

      <div id={`packing-content-${o.id}`} className="mt-4">
        <div className="text-xs font-bold mb-2" style={{ color: T.choco2 }}>PRODUCTOS</div>
        {itemsOf(db, o.id).filter((i) => !i.parentItemId).map((i) => {
          const p = productOf(db, i.productId);
          const disp = p ? availability(db, p) : Infinity;
          const sinStock = p && !["Pagado","En producción","Listo para empaque","Empacado","Listo para despacho","En ruta","Entregado"].includes(o.estado) && disp < i.cant;
          const hijas = itemsOf(db, o.id).filter((h) => h.parentItemId === i.id);
          return (
            <Card key={i.id} className="p-3 mb-2">
              <div className="flex justify-between gap-2">
                <div className="text-sm font-bold">{i.cant}× {i.nombre}</div>
                <div className="text-sm font-bold">{fmt(i.precio * i.cant + lineAdicionesTotal(i) + hijas.reduce((s, h) => s + lineAdicionesTotal(h), 0))}</div>
              </div>
              <div className="text-xs mt-0.5" style={{ color: T.choco2 }}>
                {[i.sabor && `Sabor: ${i.sabor}`, i.figura && `Figura: ${i.figura}`, i.salsa && `Salsa: ${i.salsa}`, i.relleno && `Relleno: ${i.relleno}`].filter(Boolean).join(" · ")}
              </div>
              {lineAdiciones(i).length > 0 && (
                <div className="text-xs font-bold mt-1" style={{ color: T.coral }}>
                  🍫 {lineAdiciones(i).map((ad) => ad.nombre + ((ad.cant || 1) > 1 ? ` ×${ad.cant}` : "") + (+ad.precio > 0 ? " (+" + fmt(ad.precio * (ad.cant || 1)) + ")" : " · gratis")).join("  ·  ")}
                </div>
              )}
              {hijas.length > 0 && (() => {
                const cajas = {};
                hijas.forEach((h) => { const n = h.cajaNum || 1; (cajas[n] = cajas[n] || []).push(h); });
                const nums = Object.keys(cajas).map(Number).sort((a, b) => a - b);
                const multi = nums.length > 1;
                return (
                  <div className="mt-2 pl-3 border-l-2" style={{ borderColor: T.rosa }}>
                    <div className="text-[10px] font-bold mb-1" style={{ color: T.choco2 }}>COMPOSICIÓN {multi ? `(${nums.length} cajas) ` : "DE LA CAJA "}(para la cocina)</div>
                    {nums.map((n) => (
                      <div key={n} className={multi ? "mb-1" : ""}>
                        {multi && <div className="text-[10px] font-bold" style={{ color: T.coral }}>Caja {n}</div>}
                        {cajas[n].map((h) => (
                          <div key={h.id} className="text-xs mb-0.5" style={{ color: T.choco2 }}>
                            <span className="font-bold">🐾 {h.figura}</span>{[h.sabor && ` · ${h.sabor}`, h.salsa && ` · ${h.salsa}`, h.cant > 1 && ` · ×${h.cant}`].filter(Boolean).join("")}
                            {lineAdiciones(h).length > 0 && <span className="font-bold" style={{ color: T.coral }}>  ·  🍫 {lineAdiciones(h).map((ad) => ad.nombre + (+ad.precio > 0 ? " (+" + fmt(ad.precio) + ")" : "")).join(", ")}</span>}
                          </div>
                        ))}
                      </div>
                    ))}
                  </div>
                );
              })()}
              {sinStock && <div className="text-xs font-bold mt-1" style={{ color: "#A03B2A" }}>⚠️ Disponibilidad actual: {disp}. Al pagar se reservará lo posible y se sugerirá producción del resto.</div>}
            </Card>
          );
        })}
      </div>

      {(() => {
        /* Variantes 1b: rastro del FIFO — de qué lote físico (desmolde) salió
           cada unidad al pagar. Solo reservas tipo 'producto'; 'Liberada'
           (cancelación) no se muestra porque esa unidad volvió al lote. */
        const rvs = (db.inventory_reservations || []).filter((r) => r.orderId === o.id && r.tipo === "producto" && r.estado !== "Liberada");
        if (!rvs.length) return null;
        const conLote = rvs.filter((r) => r.batchId);
        const sinLote = rvs.filter((r) => !r.batchId);
        return (
          <div className="mt-4">
            <div className="text-xs font-bold mb-2" style={{ color: T.choco2 }}>📦 LOTES ASIGNADOS (FIFO al pagar)</div>
            <Card className="p-3">
              {conLote.map((r) => (
                <div key={r.id} className="flex justify-between gap-2 text-xs py-0.5">
                  <span className="font-bold">{r.cantidad}× {r.nombre}</span>
                  <span className="font-semibold shrink-0" style={{ color: r.estado === "Consumida" ? T.choco2 : "#3F6B42" }}>{r.estado === "Consumida" ? "consumida ✓" : "reservada"}</span>
                </div>
              ))}
              {sinLote.map((r) => (
                <div key={r.id} className="flex justify-between gap-2 text-xs py-0.5" style={{ color: "#8E4B5A" }}>
                  <span className="font-bold">{r.cantidad}× {r.nombre}</span>
                  <span className="font-semibold shrink-0">{r.estado === "Consumida" ? "sin lote (pre-variantes o a pedido) ✓" : "a producir · sin lote"}</span>
                </div>
              ))}
            </Card>
          </div>
        );
      })()}

      <div id={`packing-evidence-${o.id}`} className="mt-4">
        <div className="text-xs font-bold mb-2" style={{ color: T.choco2 }}>EVIDENCIAS ({evs.length})</div>
        <div className="grid grid-cols-3 sm:grid-cols-4 gap-2 mb-3">
          {evs.map((e) => (
            <button key={e.id} onClick={() => e.url && setFoto(e)} className="rounded-xl overflow-hidden border text-left" style={{ borderColor: T.border, background: T.vainilla }}>
              {e.url ? <img src={e.url} alt={e.tipo} className="w-full h-20 object-cover" /> :
                <div className="w-full h-20 flex items-center justify-center text-2xl" aria-hidden="true">📷</div>}
              <div className="px-2 py-1">
                <div className="text-[10px] font-bold leading-tight">{e.tipo}</div>
                <div className="text-[9px]" style={{ color: T.choco2 }}>{e.hora} · {e.user}</div>
              </div>
            </button>
          ))}
        </div>
        {/* Evidencias guiadas por paso: cada objetivo alcanzable pide su(s) foto(s) con tipo YA FIJO */}
        {(() => {
          const objetivos = [];
          const objetivoPrincipal = accionRecepcion?.target || siguiente;
          if (objetivoPrincipal) objetivos.push(objetivoPrincipal);
          const puedePagar = !comprobantePagoVinculado && (o.estado === "Pendiente de pago" || accionRecepcion?.target === "Pagado");
          if (puedePagar && !objetivos.includes("Pagado")) objetivos.push("Pagado");
          const reqs = objetivos.flatMap((estadoObjetivo) => reqFotosPaso(o, estadoObjetivo).map((req) => ({
            ...req,
            estadoObjetivo,
            permiso: orderTransitionPermission(perfil, o.estado, estadoObjetivo),
          })));
          if (!reqs.length) return null;
          return (
            <div className="rounded-xl p-3 mb-3" style={{ background: T.vainilla, border: `1px solid ${T.border}` }}>
              <div className="text-xs font-bold mb-2" style={{ color: T.choco2 }}>📸 Fotos necesarias para avanzar (obligatorias)</div>
              {reqs.map((req) => {
                const hecho = req.tipos.some((t) => tieneEvidencia(db, o.id, t));
                const evidenciaEnAccionPrincipal = accionRecepcion?.type === "evidence" && req.tipos.includes("Comprobante de pago");
                return (
                  <div key={`${req.estadoObjetivo}-${req.label}`} className="flex flex-wrap items-center gap-2 mb-1.5">
                    <span className="text-sm font-semibold" style={{ color: hecho ? "#3F6B42" : "#A03B2A" }}>
                      {hecho ? "✓" : "○"} {req.label} <span className="text-[10px]">· para {req.estadoObjetivo}</span>
                    </span>
                    {!hecho && req.permiso.allowed && !evidenciaEnAccionPrincipal && req.tipos.map((t) => (
                      <Btn key={t} small kind="rosa" disabled={subiendo} onClick={() => abrirCamara(t)}>
                        {subiendo ? "Procesando…" : `📷 ${req.tipos.length > 1 ? t : "Tomar foto"}`}
                      </Btn>
                    ))}
                    {!hecho && req.permiso.allowed && evidenciaEnAccionPrincipal && <span className="text-[10px] font-bold" style={{ color: "#96690F" }}>Usá la acción principal inferior</span>}
                    {!hecho && !req.permiso.allowed && <span className="text-[10px] font-bold" style={{ color: "#96690F" }}>La sube {req.permiso.ownerLabel}</span>}
                  </div>
                );
              })}
            </div>
          );
        })()}

        {siguiente === "En ruta" &&
          <div className="text-xs font-bold mb-2" style={{ color: "#A03B2A" }}>Para pasar a “En ruta” además: pago confirmado, domicilio asignado y costo real registrado (salvo Rappi). El sello ya se capturó en Empacado.</div>}

        <input ref={fileRef} type="file" accept="image/*" capture="environment" className="hidden" onChange={onFile} />
        {tiposEvidenciaPermitidos.length > 0 && !accionRecepcion && <button type="button" onClick={() => {
          if (!libre) setTipoEv(tiposEvidenciaPermitidos.includes(tipoEv) ? tipoEv : tiposEvidenciaPermitidos[0]);
          setLibre((v) => !v);
        }} className="text-xs font-bold underline" style={{ color: T.choco2 }}>
          {libre ? "− ocultar" : "＋ otra foto permitida para mi área"}
        </button>}
        {libre && tiposEvidenciaPermitidos.length > 0 && !accionRecepcion && (
          <div className="flex flex-wrap gap-2 items-center mt-2">
            <MiniSelect options={tiposEvidenciaPermitidos} value={tipoEv} onChange={(e) => setTipoEv(e.target.value)} />
            <Btn small kind="rosa" disabled={subiendo} onClick={() => abrirCamara(tipoEv)}>
              {subiendo ? "Procesando…" : "📷 Subir foto"}
            </Btn>
          </div>
        )}
        <div className="text-[11px] font-semibold mt-2" style={{ color: "#96690F" }}>
          🔒 Las fotos se guardan en Supabase Storage y quedan vinculadas al pedido con usuario, fecha y tipo de evidencia.
        </div>
      </div>

      <div id={`packing-actions-${o.id}`} className="mt-5 flex flex-wrap gap-2 sticky bottom-0 py-3" style={{ background: T.bg }}>
        {contextActions}
        {accionRecepcion?.type === "transition" && accionRecepcion.allowed && <Btn disabled={enviando} onClick={async () => { setEnviando(true); await cambiar(o.id, accionRecepcion.target); setEnviando(false); }}>{accionRecepcion.label}</Btn>}
        {accionRecepcion?.type === "evidence" && accionRecepcion.allowed && <Btn disabled={enviando || subiendo} onClick={() => abrirCamara("Comprobante de pago")}>{subiendo ? "Procesando comprobante…" : accionRecepcion.label}</Btn>}
        {accionRecepcion?.type === "wait" && <Btn disabled>{accionRecepcion.label}</Btn>}
        {!accionRecepcion && siguiente && permisoSiguiente.allowed && (siguiente !== "Empacado" || packingVerification) && <Btn disabled={enviando} onClick={async () => { setEnviando(true); await cambiar(o.id, siguiente); setEnviando(false); }}>Confirmar “{siguiente}” · {permisoSiguiente.ownerLabel}</Btn>}
        {!accionRecepcion && siguiente === "Empacado" && permisoSiguiente.allowed && !packingVerification && <Btn disabled>Primero verificá la comanda completa</Btn>}
        {hayAccionesSecundarias && <button type="button" className="text-xs font-extrabold px-3 py-2 rounded-xl border" style={{ color: T.choco2, borderColor: T.border, background: T.surface }} onClick={() => setVerMasAcciones((current) => !current)}>{verMasAcciones ? "Ocultar opciones" : "Más opciones"}</button>}
        {verMasAcciones && hayAccionesSecundarias && <div className="basis-full flex flex-wrap gap-2 rounded-2xl border p-3" style={{ background: T.soft, borderColor: T.border }}>
        {puedeCorregirPago && <Btn kind="soft" disabled={enviando} onClick={async () => { setEnviando(true); await cambiar(o.id, "Pagado"); setEnviando(false); }}>Corregir pago faltante</Btn>}
        {puedeEntregaRapida && <Btn kind="soft" disabled={enviando} onClick={async () => { setEnviando(true); await cambiar(o.id, "Entregado", { ventaRapida: true }); setEnviando(false); }}>⚡ Entrega inmediata</Btn>}
        {puedeCrearReclamo && (
          <Btn kind="danger" disabled={enviando} onClick={async () => {
            setEnviando(true);
            // Fase 3: crear_reclamo ya transiciona el pedido a 'Reclamo' y audita server-side (no llamar setOrderStatusRemoto aparte).
            try {
              await crearReclamo(o.id, "Reclamo por calidad", "Reclamo creado desde el pedido. Completar detalle.");
            } catch (e) {
              setAviso({ titulo: "Acción no permitida", texto: e.message });
              setEnviando(false);
              return;
            }
            try {
              await refrescar();
            } catch (e) {
              setAviso({ titulo: "Acción aplicada, vista desactualizada", texto: "El reclamo se creó correctamente, pero no se pudo actualizar la vista. Recargá la página para verlo." });
              setEnviando(false);
              return;
            }
            setAviso({ titulo: "Reclamo creado", texto: `Se abrió un caso conectado al pedido ${o.id}. Complétalo en el módulo Reclamos.` });
            setEnviando(false);
          }}>Crear reclamo</Btn>
        )}
        {puedeCancelarPedido && <BtnAsync kind="ghost" confirmar="¿Cancelar el pedido? Tocá de nuevo" textoEnVuelo="Cancelando…" disabled={enviando} onClick={async () => { setEnviando(true); try { await cambiar(o.id, "Cancelado"); } finally { setEnviando(false); } }}>Cancelar pedido</BtnAsync>}
        </div>}
      </div>

      {foto && (
        <Modal title={foto.tipo} onClose={() => setFoto(null)}>
          <img src={foto.url} alt={foto.tipo} className="w-full rounded-2xl" />
          <div className="text-xs font-semibold mt-2" style={{ color: T.choco2 }}>{foto.fecha} {foto.hora} · subida por {foto.user}</div>
        </Modal>
      )}


      {etiquetaDomicilio && (
        <Modal title={`Etiqueta de entrega · ${o.id}`} onClose={() => setEtiquetaDomicilio(false)}>
          <div className="momo-shipping-label rounded-2xl border p-5" style={{ borderColor: T.choco, background: "#fff" }}>
            <div className="flex justify-between items-start gap-4 border-b pb-3 mb-3" style={{ borderColor: T.border }}>
              <div><div className="text-[10px] uppercase tracking-[.18em] font-extrabold">D'MOMOS SWEET LOVE</div><div className="display text-2xl font-bold">Pedido {o.id}</div></div>
              <div className="text-2xl" aria-hidden="true">🐱</div>
            </div>
            <div className="text-lg font-extrabold">{c.nombre || "Cliente"}</div>
            <div className="text-base font-bold mt-1">Tel. {c.telefono || "Sin teléfono"}</div>
            <div className="text-base font-extrabold mt-4">📍 {o.direccion || c.direccion || "Sin dirección"}</div>
            <div className="text-sm font-bold mt-1">{o.barrio || c.barrio || "Sin barrio"} · {o.zona || "Sin zona"}</div>
            <div className="mt-4 rounded-lg border p-3 text-sm font-bold" style={{ borderColor: T.border }}><span className="text-[10px] uppercase block mb-1">Apto / casa / local y referencia</span>{o.obs || "Sin referencia adicional"}</div>
            <div className="text-[10px] font-bold mt-3">Verificá nombre, teléfono y dirección antes de pegar esta etiqueta.</div>
          </div>
          <div className="momo-no-print flex gap-2 mt-4"><Btn onClick={() => window.print()}>Imprimir</Btn><Btn kind="ghost" onClick={() => setEtiquetaDomicilio(false)}>Cerrar</Btn></div>
        </Modal>
      )}

      {solicitudDomicilio && !domicilioActivo && (
        <Modal title={`Solicitar domicilio · ${o.id}`} onClose={() => setSolicitudDomicilio(false)}>
          <div className="rounded-xl p-3 mb-3 text-xs font-bold whitespace-pre-line" style={{ background: T.vainilla }}>{textoDomicilio}</div>
          <Field label="Proveedor"><Select options={db.settings.proveedores} value={formDomicilio.proveedor} onChange={(event) => setFormDomicilio({ ...formDomicilio, proveedor: event.target.value })} /></Field>
          <Field label="Zona"><Select options={db.settings.zonas.map((zona) => zona.nombre)} value={formDomicilio.zona} onChange={(event) => setFormDomicilio({ ...formDomicilio, zona: event.target.value })} /></Field>
          <Field label="Costo real cotizado"><Input type="number" min="0" value={formDomicilio.costoReal} onChange={(event) => setFormDomicilio({ ...formDomicilio, costoReal: event.target.value })} /></Field>
          <Field label="Apto, casa, local o referencia"><Input value={formDomicilio.obs} onChange={(event) => setFormDomicilio({ ...formDomicilio, obs: event.target.value })} placeholder="Torre, apartamento, portería o indicaciones" /></Field>
          <div className="flex gap-2 mt-3"><Btn disabled={creandoDomicilio || !formDomicilio.proveedor || !formDomicilio.zona} onClick={solicitarDomicilioDesdePedido}>{creandoDomicilio ? "Solicitando…" : "Confirmar solicitud"}</Btn><Btn kind="ghost" onClick={() => setSolicitudDomicilio(false)}>Cancelar</Btn></div>
        </Modal>
      )}
    </Modal>
  );
}

function NuevoPedido({ db, update, user, onClose, setAviso, refrescar }) {
  const s = db.settings;
  const idemKeyRef = useRef("ui-" + Math.random().toString(36).slice(2) + "-" + Date.now().toString(36)); // 1 por apertura del form: tolera retries de red
  const enviandoRef = useRef(false);
  const [enviando, setEnviando] = useState(false); // espejo de enviandoRef solo para feedback visual (disabled); el ref sigue siendo el guard real
  const [customerId, setCustomerId] = useState("");
  const [nc, setNc] = useState({ nombre: "", telefono: "", barrio: "" });
  const [canal, setCanal] = useState("WhatsApp");
  const [zona, setZona] = useState(s.zonas[0].nombre);
  const [direccion, setDireccion] = useState("");
  const [pago, setPago] = useState("Nequi");
  const [obs, setObs] = useState("");
  const [campaignId, setCampaignId] = useState("");
  const [creativeId, setCreativeId] = useState("");
  const [origenDetalle, setOrigenDetalle] = useState("");
  const [origenSimple, setOrigenSimple] = useState("");
  const [verAvanzado, setVerAvanzado] = useState(false);
  const [items, setItems] = useState([{ productId: "", sabor: "", salsa: "", relleno: "", figura: "", cant: 1, adiciones: [], boxes: [] }]);
  const [error, setError] = useState("");

  const pagosDisponibles = canal === "Rappi" ? ["Rappi (app)"] : s.pagos.filter((p) => p !== "Rappi (app)");
  const sabores = [...s.saboresFrutales, ...s.saboresCremosos];
  const c = db.customers.find((x) => x.id === customerId);
  const benef = c && db.benefits.find((b) => b.customerId === c.id && b.estado === "Activo" && b.vence >= hoyISO());
  const tarifaZona = (s.zonas.find((z) => z.nombre === zona) || {}).tarifa || 0;
  const tarifa = canal === "Rappi" ? 0 : tarifaZona;

  const lineas = items.map((it) => {
    const p = productOf(db, it.productId);
    // Combos: faltante por ESPECIE según la composición real (boxes), coherente con reserveInventory.
    const faltaEsp = p && p.tipo === "combo" ? comboFaltantesEspecie(db, p, it.boxes) : [];
    const disponibilidadExacta = p && p.tipo === "momo" ? evaluateExactVariantDemand({
      productId: p.id, productName: p.nombre, figure: it.figura, flavor: it.sabor,
      quantity: it.cant, variants: db.variantes || [],
    }) : null;
    const disponibilidadCaja = p && p.tipo === "combo" ? evaluateComboVariantAvailability({ db, combo: p, boxes: it.boxes }) : null;
    const faltantesExactos = disponibilidadCaja?.shortages || (disponibilidadExacta?.complete && disponibilidadExacta.missing > 0 ? [disponibilidadExacta] : []);
    return { ...it, nombre: p ? p.nombre : "", precio: p ? (canal === "Rappi" ? p.precioRappi : p.precio) : 0, disp: p ? availability(db, p) : Infinity, tipo: p ? p.tipo : "", faltaEsp, disponibilidadExacta, disponibilidadCaja, faltantesExactos };
  });
  const subtotal = lineas.reduce((sm, l) => sm + l.precio * l.cant + lineAdicionesTotal(l) + boxesAdicionesTotal(l), 0);

  // Aplicación del beneficio según su tipo (solo si cumple compra mínima)
  const benefAplica = benef && subtotal >= benef.minimo;
  let descuento = 0;
  let productoGratis = null;
  if (benefAplica) {
    if (benef.tipoBeneficio === "descuento_porcentaje") descuento = Math.round(subtotal * (benef.valor / 100));
    else if (benef.tipoBeneficio === "descuento_valor_fijo") descuento = Math.min(benef.valor, subtotal);
    else if (benef.tipoBeneficio === "producto_gratis") productoGratis = productOf(db, benef.productoGratisId);
  }
  const total = subtotal - descuento + tarifa;
  const faltaStock = lineas.filter((l) => l.productId && (l.disp < l.cant || (l.faltaEsp && l.faltaEsp.length > 0) || (l.faltantesExactos && l.faltantesExactos.length > 0)));

  const setItem = (i, campo, valor) => setItems((prev) => prev.map((x, idx) => idx === i ? { ...x, [campo]: valor } : x));
  // Combos con composición POR CAJA: boxes = Array(cant) de Array(comboSize) de {figura,sabor,salsa}.
  const setSlot = (i, boxIdx, slotIdx, campo, valor) => setItems((prev) => prev.map((x, idx) =>
    idx === i ? { ...x, boxes: (x.boxes || []).map((box, bi) => bi === boxIdx ? box.map((sl, si) => si === slotIdx ? { ...sl, [campo]: valor } : sl) : box) } : x));
  // "= mismos momos": copia el slot 0 al resto de esa caja.
  const mismosMomos = (i, boxIdx) => setItems((prev) => prev.map((x, idx) => {
    if (idx !== i) return x;
    return { ...x, boxes: (x.boxes || []).map((box, bi) => bi === boxIdx && box.length ? box.map(() => ({ ...box[0], adiciones: [...(box[0].adiciones || [])] })) : box) };
  }));
  // "Caja 1 → todas": replica la composición de la caja 1 a todas las cajas de la línea.
  const copiarCaja1ATodas = (i) => setItems((prev) => prev.map((x, idx) => {
    if (idx !== i || !(x.boxes || []).length) return x;
    const first = x.boxes[0];
    return { ...x, boxes: x.boxes.map(() => first.map((sl) => ({ ...sl, adiciones: [...(sl.adiciones || [])] }))) };
  }));
  // Cambiar la cantidad de una línea. Para combos, redimensiona `boxes` conservando lo ya compuesto.
  const setCant = (i, prod, nc) => setItems((prev) => prev.map((x, idx) => {
    if (idx !== i) return x;
    const n = Math.max(1, Math.floor(nc) || 1); // cajas/unidades enteras: mantiene boxes.length === cant
    if (prod && prod.tipo === "combo") {
      const size = prod.comboSize || 0;
      const cur = x.boxes || [];
      const boxes = Array.from({ length: n }, (_, b) => cur[b] || Array.from({ length: size }, () => ({ figura: "", sabor: "", salsa: "", adiciones: [] })));
      return { ...x, cant: n, boxes };
    }
    return { ...x, cant: n };
  }));
  const toggleAdicion = (i, top) => setItems((prev) => prev.map((x, idx) => {
    if (idx !== i) return x;
    const cur = Array.isArray(x.adiciones) ? x.adiciones : [];
    const has = cur.some((a) => a.nombre === top.nombre);
    return { ...x, adiciones: has
      ? cur.filter((a) => a.nombre !== top.nombre)
      : [...cur, { nombre: top.nombre, precio: +top.precio || 0, cant: 1, insumoId: top.insumoId || "", insumoCant: +top.insumoCant || 1 }] };
  }));
  // Toppings POR SUB-MOMO: cada slot de la caja lleva sus propias adiciones (mismo shape que la línea).
  const toggleSlotAdicion = (i, boxIdx, slotIdx, top) => setItems((prev) => prev.map((x, idx) => {
    if (idx !== i) return x;
    return { ...x, boxes: (x.boxes || []).map((box, bi) => bi !== boxIdx ? box : box.map((sl, si) => {
      if (si !== slotIdx) return sl;
      const cur = Array.isArray(sl.adiciones) ? sl.adiciones : [];
      const has = cur.some((a) => a.nombre === top.nombre);
      return { ...sl, adiciones: has
        ? cur.filter((a) => a.nombre !== top.nombre)
        : [...cur, { nombre: top.nombre, precio: +top.precio || 0, cant: 1, insumoId: top.insumoId || "", insumoCant: +top.insumoCant || 1 }] };
    })) };
  }));

  async function guardar() {
    if (!customerId && (!nc.nombre || !nc.telefono)) { setError("Selecciona un cliente o registra nombre y teléfono."); return; }
    if (!lineas.some((l) => l.productId)) { setError("Agrega al menos un producto."); return; }
    if (subtotal < s.pedidoMinimo) { setError(`El pedido mínimo es ${fmt(s.pedidoMinimo)} (sin domicilio).`); return; }
    const combosIncompletos = lineas.filter((l) => l.productId && l.tipo === "combo")
      .filter((l) => !(l.boxes || []).length || (l.boxes || []).some((box) => !box.length || box.some((sl) => !sl.figura || !sl.sabor || !sl.salsa)));
    if (combosIncompletos.length) { setError("Completá figura, sabor y salsa en cada momo de cada caja."); return; }
    if (enviandoRef.current) return;
    enviandoRef.current = true;
    setEnviando(true);
    setError("");
    // Fase 3: el pedido nace en el SERVER. crear_pedido calcula precios, snapshotea costos,
    // crea el cliente nuevo, arma padre+hijas de combos, reserva el beneficio y el delivery Rappi.
    const mapAdic = (ads) => (ads || []).map((a) => ({ nombre: a.nombre, precio: +a.precio || 0, cant: +a.cant || 1, insumo_id: a.insumoId || null, insumo_cant: +a.insumoCant || 0 }));
    const payload = {
      customer_id: customerId || null,
      nuevo_cliente: customerId ? null : { nombre: nc.nombre.trim(), telefono: nc.telefono.trim(), barrio: nc.barrio || "", direccion, canal },
      canal, zona: zona || null, barrio: (c && c.barrio) || nc.barrio || "", direccion, pago,
      obs, benefit_id: benefAplica && benef ? benef.id : null,
      campaign_id: campaignId || null, creative_id: creativeId || null, origen_detalle: origenDetalle || "",
      idempotency_key: idemKeyRef.current,
      lineas: items.filter((l) => l.productId).map((l) => {
        const p = productOf(db, l.productId);
        const base = { product_id: l.productId, cant: l.cant, sabor: l.sabor || "", salsa: l.salsa || "", figura: l.figura || "", adiciones: mapAdic(l.adiciones) };
        if (p && p.tipo === "combo") base.boxes = (l.boxes || []).map((box) => box.map((sl) => ({ figura: sl.figura, sabor: sl.sabor, salsa: sl.salsa, adiciones: mapAdic(sl.adiciones) })));
        return base;
      }),
    };
    let res;
    try {
      res = await crearPedido(payload);
    } catch (e) {
      setError(e.message);
      enviandoRef.current = false;
      setEnviando(false);
      return;
    }
    onClose();
    toast("ok", `Pedido ${res.order_id} creado`);
    try {
      await refrescar();
      if (faltaStock.length) setAviso({ titulo: "Pedido creado con alerta", texto: `${res.order_id} creado. Ojo: disponibilidad insuficiente en ${faltaStock.map((l) => l.nombre).join(", ")}. Al marcar pagado se creará la sugerencia de producción.` });
    } catch (e) {
      setAviso({ titulo: "Acción aplicada, vista desactualizada", texto: `${res.order_id} se creó correctamente, pero no se pudo actualizar la vista. Recargá la página para verlo.` });
    }
    enviandoRef.current = false;
    setEnviando(false);
  }

  return (
    <Modal title="Nuevo pedido" onClose={onClose} wide>
      <div className="grid sm:grid-cols-2 gap-x-4">
        <Field label="Cliente existente">
          <select value={customerId} onChange={(e) => {
            const id = e.target.value;
            setCustomerId(id);
            const cli = db.customers.find((x) => x.id === id);
            if (cli) {
              if (cli.direccion) setDireccion(cli.direccion);
              const z = sugerirZona(s.zonas, cli.barrio);
              if (z) setZona(z);
            } else {
              // volvió a "Cliente nuevo": limpiar datos, mantener canal y pago
              setDireccion("");
              setNc({ nombre: "", telefono: "", barrio: "" });
              setZona(s.zonas[0].nombre);
            }
          }} className={inputCls} style={inputStyle}>
            <option value="">— Cliente nuevo —</option>
            {db.customers.map((x) => <option key={x.id} value={x.id}>{x.nombre} · {x.telefono}</option>)}
          </select>
        </Field>
        <Field label="Canal"><Select options={CANALES} value={canal} onChange={(e) => {
          const nuevoCanal = e.target.value;
          setCanal(nuevoCanal);
          setPago(nuevoCanal === "Rappi" ? "Rappi (app)" : "Nequi");
        }} /></Field>
        {!customerId && (<>
          <Field label="Nombre del cliente"><Input value={nc.nombre} onChange={(e) => setNc({ ...nc, nombre: e.target.value })} placeholder="Nombre y apellido" /></Field>
          <Field label="Teléfono / WhatsApp"><Input value={nc.telefono} onChange={(e) => setNc({ ...nc, telefono: e.target.value })} placeholder="3XX XXX XXXX" /></Field>
          <Field label="Barrio"><Input value={nc.barrio} onChange={(e) => setNc({ ...nc, barrio: e.target.value })} placeholder="El Caney, El Ingenio…" /></Field>
        </>)}
        <Field label="Dirección de entrega"><Input value={direccion} onChange={(e) => setDireccion(e.target.value)} placeholder="Dirección completa" /></Field>
        <Field label="Zona de domicilio"><Select options={s.zonas.map((z) => z.nombre)} value={zona} onChange={(e) => setZona(e.target.value)} /></Field>
        <Field label="Forma de pago"><Select options={pagosDisponibles} value={pago} onChange={(e) => setPago(e.target.value)} /></Field>
      </div>

      {benef && (
        <div className="text-xs font-bold p-2.5 rounded-xl mb-3" style={{ background: "#DDEBD9", color: "#3F6B42" }}>
          🎁 {c.nombre} tiene beneficio activo: {benef.beneficio} ({benef.condicion}). Mínimo {fmt(benef.minimo)}.
          {benefAplica
            ? (productoGratis ? ` Se agregará 1 ${productoGratis.nombre} gratis y el beneficio quedará Reservado hasta confirmar el pago.` : " Se aplicará el descuento y el beneficio quedará Reservado hasta confirmar el pago.")
            : " Aún no cumple la compra mínima."}
        </div>
      )}

      {canal === "Rappi" && (
        <div className="text-xs font-semibold mb-3 p-2.5 rounded-xl" style={{ background: T.coralSoft, color: "#A34A2A" }}>
          🛵 Rappi gestiona el domicilio y el pago dentro de su app. MOMOS no cobra domicilio adicional en este pedido.
        </div>
      )}

      <div className="text-xs font-bold mb-2" style={{ color: T.choco2 }}>PRODUCTOS DEL PEDIDO</div>
      {items.map((it, i) => {
        const l = lineas[i];
        const pSel = productOf(db, it.productId);
        const attrs = pSel && Array.isArray(pSel.atributos) ? pSel.atributos : ["sabor", "salsa", "relleno", "figura"];
        return (
          <Card key={i} className="p-3 mb-2">
            <div className="grid grid-cols-2 sm:grid-cols-3 gap-2">
              <div className="col-span-2 sm:col-span-3">
                <select value={it.productId} onChange={(e) => {
                  const pid = e.target.value;
                  const prod = productOf(db, pid);
                  setItems((prev) => prev.map((x, idx) => {
                    if (idx !== i) return x;
                    const boxes = prod && prod.tipo === "combo"
                      ? Array.from({ length: Math.max(1, x.cant || 1) }, () => Array.from({ length: prod.comboSize || 0 }, () => ({ figura: "", sabor: "", salsa: "", adiciones: [] })))
                      : [];
                    return { ...x, productId: pid, boxes };
                  }));
                }} className={inputCls} style={inputStyle}>
                  <option value="">Elegir producto…</option>
                  {db.products.filter((p) => p.activo).map((p) => {
                    const disp = availability(db, p);
                    const stockText = !isFinite(disp) ? "" : p.tipo === "combo" ? ` · hasta ${disp} caja(s) por stock general` : ` · ${disp} disp. generales`;
                    return <option key={p.id} value={p.id}>{p.nombre} · {fmt(canal === "Rappi" ? p.precioRappi : p.precio)}{stockText}</option>;
                  })}
                </select>
              </div>
              {it.productId && pSel && pSel.tipo !== "combo" && attrs.includes("sabor") && <Select placeholder="Sabor" options={sabores} value={it.sabor} onChange={(e) => setItem(i, "sabor", e.target.value)} />}
              {it.productId && pSel && pSel.tipo !== "combo" && attrs.includes("salsa") && <Select placeholder="Salsa" options={s.salsas} value={it.salsa} onChange={(e) => setItem(i, "salsa", e.target.value)} />}
              {it.productId && pSel && pSel.tipo !== "combo" && attrs.includes("relleno") && <Select placeholder="Relleno" options={s.rellenos} value={it.relleno} onChange={(e) => setItem(i, "relleno", e.target.value)} />}
              {it.productId && pSel && pSel.tipo !== "combo" && attrs.includes("figura") && <Select placeholder="Figura" options={(() => { const propias = (db.figuras || []).filter((f) => f.activo && f.productId === it.productId); return (propias.length ? propias : s.figuras).map((f) => f.nombre); })()} value={it.figura} onChange={(e) => setItem(i, "figura", e.target.value)} />}
              <Input type="number" min="1" value={it.cant} onChange={(e) => setCant(i, pSel, Math.max(1, +e.target.value))} />
              <div className="flex items-center justify-between px-1">
                <span className="text-sm font-bold">{fmt(l.precio * l.cant + lineAdicionesTotal(l) + boxesAdicionesTotal(l))}</span>
                {items.length > 1 && <button onClick={() => setItems(items.filter((_, x) => x !== i))} className="text-xs font-bold" style={{ color: "#A03B2A" }}>Quitar</button>}
              </div>
            </div>
            {it.productId && pSel && pSel.tipo !== "combo" && attrs.includes("figura") && (() => {
              /* Disponibilidad por variante EN VIVO: dice si lo que pide el cliente
                 está desmoldado y, si no, qué ofrece el FIFO (mismo orden de decisión
                 que _asignar_variante_fifo en el server: SABOR y FIGURA filtran
                 duro; otra variante nunca sustituye la elegida). */
              const vars = (db.variantes || []).filter((v) => v.productId === it.productId && v.disponibles > 0);
              const chip = (bg, color, texto) => <div className="mt-1 px-2 py-1.5 rounded-lg text-[11px] font-bold" style={{ background: bg, color }}>{texto}</div>;
              const lista = (arr) => arr.map((v) => `${v.figura} · ${v.sabor} (${v.disponibles})`).join(" · ");
              if (!vars.length) return chip("#F3D7DC", "#8E4B5A", "Sin stock verificado por figura y sabor — este pedido requiere producción exacta.");
              if (!it.sabor) return chip("#DCE7F2", "#3E5C7E", `Desmoldado disponible: ${lista(vars)}`);
              const deSabor = vars.filter((v) => v.sabor === it.sabor);
              if (!deSabor.length) return chip("#F3D7DC", "#8E4B5A", `Sin ${it.sabor} desmoldado — hay: ${lista(vars)} · el sabor no se sustituye: se produce a pedido.`);
              if (!it.figura) return chip("#DCE7F2", "#3E5C7E", `${it.sabor} disponible por figura: ${lista(deSabor)}. Elegí la figura para validar.`);
              const exacta = l.disponibilidadExacta;
              if (exacta?.canFulfill) {
                return chip("#DDEBD9", "#3F6B42", `✓ ${exacta.required}× ${it.figura} · ${it.sabor} verificadas · FIFO exacto al pagar${exacta.nextExpiry ? ` · vence ${exacta.nextExpiry}` : ""}`);
              }
              return chip("#F3D7DC", "#8E4B5A", `Solo ${exacta?.available || 0} de ${it.cant} ${it.figura} · ${it.sabor} verificadas. Otra figura no la reemplaza: faltan ${exacta?.missing || it.cant} para producir.`);
            })()}
            {it.productId && pSel && pSel.tipo === "combo" && (() => {
              const boxes = it.boxes || [];
              const multi = boxes.length > 1;
              const figOpts = figurasDeCombo(db, pSel).map((f) => f.nombre);
              return (
                <div className="mt-2 pt-2 border-t" style={{ borderColor: T.border }}>
                  <div className="flex items-center justify-between mb-1.5">
                    <div className="text-[11px] font-bold" style={{ color: T.choco2 }}>🎁 ARMÁ {multi ? `LAS ${boxes.length} CAJAS` : "LA CAJA"} · {pSel.comboSize} momos c/u</div>
                    {multi && <button type="button" onClick={() => copiarCaja1ATodas(i)} className="text-[11px] font-bold" style={{ color: T.coral }}>Caja 1 → todas</button>}
                  </div>
                  <div className="mb-2 px-2.5 py-2 rounded-xl text-[11px] font-bold flex items-center justify-between gap-2" style={{ background: l.disponibilidadCaja?.canFulfill ? "#DDEBD9" : "#F7EAC9", color: l.disponibilidadCaja?.canFulfill ? "#3F6B42" : "#8A6D1F" }}>
                    <span>{l.disponibilidadCaja?.incomplete ? "Completá figura y sabor para validar cada momo" : l.disponibilidadCaja?.canFulfill ? "Composición exacta disponible" : "La caja necesita producción exacta"}</span>
                    <span className="shrink-0">{l.disponibilidadCaja?.covered || 0}/{l.disponibilidadCaja?.slots?.length || 0} verificadas</span>
                  </div>
                  {boxes.map((box, b) => (
                    <div key={b} className={multi ? "mb-2 p-2 rounded-lg" : ""} style={multi ? { background: T.vainilla } : {}}>
                      <div className="flex items-center justify-between mb-1">
                        {multi ? <div className="text-[10px] font-bold" style={{ color: T.choco2 }}>CAJA {b + 1}</div> : <span />}
                        {box.length > 1 && <button type="button" onClick={() => mismosMomos(i, b)} className="text-[10px] font-bold" style={{ color: T.coral }}>= mismos momos</button>}
                      </div>
                      {box.map((sl, si) => (
                        <div key={si} className="mb-1.5">
                          <div className="grid grid-cols-3 gap-1.5">
                            <Select placeholder="Figura" options={figOpts} value={sl.figura} onChange={(e) => setSlot(i, b, si, "figura", e.target.value)} />
                            <Select placeholder="Sabor" options={sabores} value={sl.sabor} onChange={(e) => setSlot(i, b, si, "sabor", e.target.value)} />
                            <Select placeholder="Salsa" options={s.salsas} value={sl.salsa} onChange={(e) => setSlot(i, b, si, "salsa", e.target.value)} />
                          </div>
                          {(() => {
                            const exacta = (l.disponibilidadCaja?.slots || []).find((slot) => slot.boxIndex === b && slot.slotIndex === si);
                            if (!exacta?.complete) return null;
                            return <div className="mt-1 px-2 py-1 rounded-lg text-[10px] font-bold" style={{ background: exacta.covered ? "#E3EFE0" : "#F3D7DC", color: exacta.covered ? "#3F6B42" : "#8E4B5A" }}>{exacta.covered ? `✓ ${exacta.figure} · ${exacta.flavor} disponible · FIFO exacto` : `⚠ ${exacta.figure} · ${exacta.flavor} sin unidad exacta · producir`}</div>;
                          })()}
                          {Array.isArray(s.toppings) && s.toppings.length > 0 && (
                            <div className="flex flex-wrap gap-1 mt-1">
                              {s.toppings.map((top) => {
                                const on = (sl.adiciones || []).some((a) => a.nombre === top.nombre);
                                return (
                                  <button key={top.nombre} type="button" onClick={() => toggleSlotAdicion(i, b, si, top)}
                                    className="text-[10px] font-bold px-2 py-0.5 rounded-full"
                                    style={{ background: on ? T.coral : T.vainilla, color: on ? "#fff" : T.choco2, border: "1px solid " + (on ? T.coral : T.border) }}>
                                    🍫 {top.nombre}{(+top.precio > 0) ? " +" + fmt(top.precio) : ""}
                                  </button>
                                );
                              })}
                            </div>
                          )}
                        </div>
                      ))}
                    </div>
                  ))}
                </div>
              );
            })()}
            {l.productId && l.faltantesExactos && l.faltantesExactos.length > 0 && (
              <div className="text-xs font-bold mt-2 p-2 rounded-xl" style={{ color: "#8E4B5A", background: "#F3D7DC" }}>⚠️ Producción exacta requerida: {l.faltantesExactos.map((f) => `${f.missing}× ${f.figure} · ${f.flavor}`).join(", ")}. El stock anterior u otra figura no cubren esta elección.</div>
            )}
            {it.productId && pSel && pSel.tipo !== "combo" && Array.isArray(s.toppings) && s.toppings.length > 0 && (
              <div className="mt-2 pt-2 border-t" style={{ borderColor: T.border }}>
                <div className="text-[11px] font-bold mb-1" style={{ color: T.choco2 }}>🍫 TOPPINGS (opcional)</div>
                <div className="flex flex-wrap gap-1.5">
                  {s.toppings.map((top) => {
                    const on = (it.adiciones || []).some((a) => a.nombre === top.nombre);
                    return (
                      <button key={top.nombre} type="button" onClick={() => toggleAdicion(i, top)}
                        className="text-[11px] font-bold px-2.5 py-1 rounded-full"
                        style={{ background: on ? T.coral : T.vainilla, color: on ? "#fff" : T.choco2, border: "1px solid " + (on ? T.coral : T.border) }}>
                        {top.nombre}{(+top.precio > 0) ? " +" + fmt(top.precio) : " · gratis"}
                      </button>
                    );
                  })}
                </div>
              </div>
            )}
            {l.productId && (!l.faltantesExactos || l.faltantesExactos.length === 0) && (l.faltaEsp && l.faltaEsp.length > 0) && (
              <div className="text-xs font-bold mt-2" style={{ color: "#A03B2A" }}>⚠️ Faltan momos para esta caja: {l.faltaEsp.map((f) => f.falta + " " + f.nombre).join(", ")}. Se reservará lo posible y se sugerirá producción del resto.</div>
            )}
            {l.productId && l.disp < l.cant && !(l.faltaEsp && l.faltaEsp.length > 0) && (
              <div className="text-xs font-bold mt-2" style={{ color: "#A03B2A" }}>⚠️ Capacidad general: {l.disp}{l.tipo === "combo" ? " caja(s) por momos y empaques" : ""}. Se sugerirá producción del faltante.</div>
            )}
          </Card>
        );
      })}
      <Btn small kind="rosa" onClick={() => setItems([...items, { productId: "", sabor: "", salsa: "", relleno: "", figura: "", cant: 1, adiciones: [], boxes: [] }])}>＋ Agregar otro producto</Btn>

      <Field label="Observaciones"><Input value={obs} onChange={(e) => setObs(e.target.value)} placeholder="Hora deseada, dedicatoria…" /></Field>

      <div className="text-sm font-bold mb-2 mt-1">¿De dónde llegó este pedido?</div>
      <div className="flex flex-wrap gap-2 mb-2">
        {ORIGEN_SIMPLE.map((op) => {
          const activo = origenSimple === op.label;
          return (
            <button key={op.label} type="button" onClick={() => {
              setOrigenSimple(op.label);
              setOrigenDetalle(op.detalle);
            }} className="text-xs font-bold px-3 py-2 rounded-xl" style={{ background: activo ? T.coral : T.vainilla, color: activo ? "#fff" : T.choco2, border: "1px solid " + (activo ? T.coral : T.border) }}>
              {op.label}
            </button>
          );
        })}
      </div>

      <button type="button" onClick={() => setVerAvanzado(!verAvanzado)} className="text-xs font-bold mb-2" style={{ color: T.choco2 }}>
        {verAvanzado ? "▾" : "▸"} Vincular a campaña o publicación (opcional)
      </button>
      {verAvanzado && (
        <div className="grid sm:grid-cols-2 gap-x-4 mb-2">
          <Field label="Campaña">
            <select value={campaignId} onChange={(e) => { setCampaignId(e.target.value); setCreativeId(""); }} className={inputCls} style={inputStyle}>
              <option value="">Sin campaña</option>
              {db.campaigns.map((c) => <option key={c.id} value={c.id}>{c.nombre}</option>)}
            </select>
          </Field>
          <Field label="Publicación / creativo">
            <select value={creativeId} onChange={(e) => {
              const id = e.target.value;
              setCreativeId(id);
              const cr = db.creatives.find((x) => x.id === id);
              if (cr && cr.campaignId) setCampaignId(cr.campaignId);
            }} className={inputCls} style={inputStyle}>
              <option value="">Sin publicación</option>
              {db.creatives.filter((c) => !campaignId || c.campaignId === campaignId).map((c) => <option key={c.id} value={c.id}>{c.titulo}</option>)}
            </select>
          </Field>
        </div>
      )}

      <Card className="p-4 mt-2">
        <div className="flex justify-between text-sm py-0.5"><span>Subtotal</span><b>{fmt(subtotal)}</b></div>
        {descuento > 0 && <div className="flex justify-between text-sm py-0.5" style={{ color: "#3F6B42" }}><span>Beneficio aplicado</span><b>−{fmt(descuento)}</b></div>}
        {productoGratis && <div className="flex justify-between text-sm py-0.5" style={{ color: "#3F6B42" }}><span>🎁 {productoGratis.nombre} (gratis)</span><b>$0</b></div>}
        <div className="flex justify-between text-sm py-0.5"><span>Domicilio ({zona.split("·")[0].trim()})</span><b>{fmt(tarifa)}</b></div>
        <div className="flex justify-between display text-lg pt-2 mt-1 border-t" style={{ borderColor: T.border }}><span>Total</span><b style={{ color: T.coral }}>{fmt(total)}</b></div>
      </Card>

      {error && <div className="text-sm font-bold mt-3 p-2.5 rounded-xl" style={{ background: "#F6D4CD", color: "#A03B2A" }}>{error}</div>}
      <div className="mt-4 flex gap-2">
        <Btn disabled={enviando} onClick={guardar}>Crear pedido</Btn>
        <Btn kind="ghost" onClick={onClose}>Cancelar</Btn>
      </div>
    </Modal>
  );
}

/* ================= PRODUCCIÓN ================= */

const LOTE_ESTADOS = ["En preparación","Congelando","Listo","Reservado","Vendido","Imperfecto","Descartado"];

// Componentes + BOM: agrupación del select de bases por tipo de subreceta.
const PREP_TIPOS = [
  ["mousse_frutal", "Mousses frutales"], ["mousse_cremosa", "Mousses cremosas"],
  ["cheesecake", "Cheesecake"], ["ganache", "Ganache"], ["salsa", "Salsas"], ["crocante", "Crocante"],
];

const VOICE_KITCHEN_EXAMPLE = "Se está preparando 200 gramos de ganache, ingrésalos. Se van a producir 20 Lizis: 3 de limón, 4 de coco, 3 de banano, 5 de Oreo y 5 de Milo. Van a ingresar a congelación, empieza cronómetro.";
const VOICE_PHRASE_BIAS_KEY = "momos-voice-native-phrases";

function nativeVoicePhraseBiasEnabled() {
  try { return window.localStorage.getItem(VOICE_PHRASE_BIAS_KEY) !== "unsupported"; }
  catch { return true; }
}

function rememberUnsupportedVoicePhrases(ref) {
  ref.current = false;
  try { window.localStorage.setItem(VOICE_PHRASE_BIAS_KEY, "unsupported"); } catch { /* el corrector local sigue activo */ }
}

function voiceCommandKey() {
  try { if (crypto && crypto.randomUUID) return "voice-" + crypto.randomUUID(); } catch { /* fallback abajo */ }
  return "voice-" + Date.now().toString(36) + "-" + Math.random().toString(36).slice(2, 10);
}

function voiceOutcomeCount(count, singular, plural) {
  return `${count} ${count === 1 ? singular : plural}`;
}

function voiceOrderItems(madeToOrder) {
  const items = madeToOrder?.items?.length
    ? madeToOrder.items
    : [{ quantity: madeToOrder?.quantity || 0, productName: madeToOrder?.productName || "producto" }];
  return items.map((item) => `${item.quantity} × ${item.productName}`).join("; ");
}

function voiceSummary(draft) {
  const parts = [];
  const preparations = draft.preparations?.length ? draft.preparations : (draft.preparation ? [draft.preparation] : []);
  preparations.forEach((preparation) => parts.push(`preparar ${preparation.nominalGrams} gramos de ${preparation.subrecipeName}${preparation.usage ? `, ${preparation.usage.toLowerCase()}` : ""}`));
  const productions = draft.productions?.length ? draft.productions : (draft.production ? [draft.production] : []);
  productions.forEach((production) => parts.push(`producir ${production.calculatedTotal} ${production.figure}: ${production.runs.map((run) => `${run.quantity} de ${run.flavor}`).join(", ")}`));
  if (draft.madeToOrder) parts.push(`iniciar el pedido ${draft.madeToOrder.orderId}${draft.madeToOrder.customerName ? ` de ${draft.madeToOrder.customerName}` : ""}. La comanda contiene ${draft.madeToOrder.orderContent || voiceOrderItems(draft.madeToOrder)}`);
  if (draft.orderHandoff) parts.push(`marcar el pedido ${draft.orderHandoff.orderId}${draft.orderHandoff.customerName ? ` de ${draft.orderHandoff.customerName}` : ""} como Listo para empaque`);
  if (draft.unmolding) parts.push(`desmoldar el lote ${draft.unmolding.batchId}: ${voiceOutcomeCount(draft.unmolding.perfectas, "perfecta", "perfectas")}, ${voiceOutcomeCount(draft.unmolding.imperfectas, "imperfecta", "imperfectas")} y ${voiceOutcomeCount(draft.unmolding.descartadas, "descartada", "descartadas")}`);
  if (draft.freezeBatchIds?.length) parts.push(`iniciar la congelación de ${draft.freezeBatchIds.length === 1 ? `el lote ${draft.freezeBatchIds[0]}` : `los lotes ${draft.freezeBatchIds.join(", ")}`}`);
  else if (draft.startFreezing) parts.push("iniciar la congelación de los lotes nuevos");
  return "Entendí: " + parts.join("; ") + ". ¿Está correcto?";
}

function VoiceKitchenPanel({ db, perfil, flavors, figures, subrecipes, refrescar, serverDataReady, requestedOrder }) {
  const [transcript, setTranscript] = useState("");
  const [listening, setListening] = useState(false);
  const [speechError, setSpeechError] = useState("");
  const [draft, setDraft] = useState(null);
  const [result, setResult] = useState(null);
  const [replyByVoice, setReplyByVoice] = useState(true);
  const [executionLabel, setExecutionLabel] = useState("Ejecutando…");
  const [executed, setExecuted] = useState(false);
  const [voiceMode, setVoiceMode] = useState("idle");
  const [voiceActivity, setVoiceActivity] = useState("idle");
  const [conversation, setConversation] = useState([]);
  const recognitionRef = useRef(null);
  const recognitionSessionRef = useRef({ active: false, mode: "dictation", baseText: "", currentText: "", starting: false, restartTimer: null, turnTimer: null, watchdogTimer: null, activityTimer: null, restartDelay: 180, failures: 0, generation: 0, attempt: 0 });
  const transcriptRef = useRef("");
  const draftRef = useRef(null);
  const executedRef = useRef(false);
  const executingRef = useRef(false);
  const conversationContextRef = useRef("");
  const conversationTurnsRef = useRef(0);
  const readOnlyTurnsRef = useRef(0);
  const assistantMemoryRef = useRef({ lastTopic: "", lastOrderId: null, lastBatchId: null });
  const speechTokenRef = useRef(0);
  const speechSafetyTimerRef = useRef(null);
  const speechInProgressRef = useRef(false);
  const handsFreeCommandRef = useRef(false);
  const authorizationAttemptRef = useRef(0);
  const knownOrderStatesRef = useRef(new Map((db.orders || []).filter((order) => order?.id).map((order) => [order.id, order.estado || ""])));
  const orderAlertsReadyRef = useRef(false);
  const orderAlertQueueRef = useRef([]);
  const orderAlertSpeakingRef = useRef(false);
  const flushOrderAlertsRef = useRef(null);
  const refreshOrdersRef = useRef(refrescar);
  const orderWatcherNameRef = useRef(null);
  const phraseBiasSupportedRef = useRef(nativeVoicePhraseBiasEnabled());
  const beginRecognitionRef = useRef(null);
  const startVoiceSessionRef = useRef(null);
  const finishDictationRef = useRef(null);
  const handleWakeWordRef = useRef(null);
  const handleVoiceControlRef = useRef(null);
  const handleConversationReplyRef = useRef(null);
  const interpretTranscriptRef = useRef(null);
  const executeCommandRef = useRef(null);
  const commandKeyRef = useRef(null);
  const progressRef = useRef({ bases: new Set(), runs: new Set(), batchIds: [], frozen: new Set(), unmolded: new Set(), orders: new Set(), ordersReady: new Set() });
  const SpeechRecognitionApi = typeof window !== "undefined" ? (window.SpeechRecognition || window.webkitSpeechRecognition) : null;
  const voiceInputAvailable = Boolean(
    SpeechRecognitionApi
    && typeof navigator !== "undefined"
    && navigator.mediaDevices
    && typeof navigator.mediaDevices.getUserMedia === "function",
  );
  refreshOrdersRef.current = refrescar;
  if (!orderWatcherNameRef.current) orderWatcherNameRef.current = `momobot-orders-${voiceCommandKey()}`;
  const voiceCatalogs = useMemo(() => ({
    flavors,
    figures,
    subrecipes,
    figureFillings: db.figura_relleno || [],
    products: db.products || [],
    inventory: db.inventory_items || [],
    inventoryLots: db.inventory_lots || [],
    batches: db.production_batches || [],
    orders: db.orders || [],
    orderItems: db.order_items || [],
    customers: db.customers || [],
    variants: db.variantes || [],
    suggestions: db.production_suggestions || [],
    reservations: db.inventory_reservations || [],
    auditLogs: db.audit_logs || [],
    delaySettings: normalizeKitchenDelaySettings(db.settings || {}),
    extras: [
      ...(db.settings.salsas || []),
      ...(db.settings.rellenos || []),
      ...(db.settings.toppings || []).map((item) => item?.nombre || item).filter(Boolean),
    ],
  }), [db, flavors, figures, subrecipes]);
  const voicePhrases = useMemo(() => kitchenVocabularyPhrases(voiceCatalogs), [voiceCatalogs]);
  const voiceTaskPhrases = useMemo(() => new Set(kitchenTaskVocabularyPhrases()), []);
  const contextSnapshot = useMemo(() => momobotContextSnapshot(voiceCatalogs), [voiceCatalogs]);

  useEffect(() => () => {
    const session = recognitionSessionRef.current;
    session.active = false;
    session.generation += 1;
    if (session.restartTimer) clearTimeout(session.restartTimer);
    if (session.turnTimer) clearTimeout(session.turnTimer);
    if (session.watchdogTimer) clearTimeout(session.watchdogTimer);
    if (session.activityTimer) clearTimeout(session.activityTimer);
    try { recognitionRef.current?.abort(); } catch { /* nada que limpiar */ }
    speechTokenRef.current += 1;
    authorizationAttemptRef.current += 1;
    speechInProgressRef.current = false;
    if (speechSafetyTimerRef.current) clearTimeout(speechSafetyTimerRef.current);
    speechSafetyTimerRef.current = null;
    try { window.speechSynthesis?.cancel(); } catch { /* degradación silenciosa */ }
  }, []);

  const [abierto, setAbierto] = useState(false);

  useEffect(() => {
    if (!requestedOrder?.orderId) return undefined;
    setAbierto(true);
    const command = `Preparar el pedido ${requestedOrder.orderId}`;
    stopVoiceSession({ abort: true, nextMode: "idle" });
    cancelSpeech();
    changeTranscript(command);
    const timer = setTimeout(() => interpretTranscriptRef.current?.(command), 60);
    return () => clearTimeout(timer);
  }, [requestedOrder?.token]);

  useEffect(() => {
    if (!voiceInputAvailable) return undefined;
    let cancelled = false;
    const timer = setTimeout(async () => {
      try {
        if (!navigator.permissions?.query) {
          if (!cancelled) setSpeechError("Tocá “Activar Momobot” una vez para autorizar el micrófono.");
          return;
        }
        const permission = await navigator.permissions.query({ name: "microphone" });
        if (cancelled) return;
        if (canAutoStartMomobot({
          permissionState: permission.state,
          sessionActive: recognitionSessionRef.current.active,
          speechInProgress: speechInProgressRef.current,
          hasDraft: Boolean(draftRef.current),
          authorizing: recognitionSessionRef.current.starting,
        })) startVoiceSessionRef.current?.("standby");
        else if (permission.state === "denied") setSpeechError("El micrófono está bloqueado. Permitilo en el candado de la barra de direcciones y tocá “Activar Momobot”.");
        else setSpeechError("Tocá “Activar Momobot” una vez para conceder el micrófono.");
      } catch {
        if (!cancelled) setSpeechError("Tocá “Activar Momobot” una vez para autorizar el micrófono.");
      }
    }, 420);
    return () => { cancelled = true; clearTimeout(timer); };
  }, [voiceInputAvailable]);

  useEffect(() => {
    const orders = db.orders || [];
    if (!serverDataReady || !orderAlertsReadyRef.current) {
      knownOrderStatesRef.current = new Map(orders.filter((order) => order?.id).map((order) => [order.id, order.estado || ""]));
      if (serverDataReady) orderAlertsReadyRef.current = true;
      return;
    }
    const detected = kitchenOrderStateEvents(orders, knownOrderStatesRef.current);
    knownOrderStatesRef.current = detected.nextStates;
    detected.events.slice().reverse().forEach(({ order, type }) => {
      const alert = kitchenOrderAlert(order, {
        customers: db.customers || [],
        products: db.products || [],
        orderItems: db.order_items || [],
      }, { eventType: type });
      if (!alert) return;
      const enriched = {
        ...alert,
        detectedAt: new Date().toLocaleTimeString("es-CO", { hour: "2-digit", minute: "2-digit" }),
      };
      orderAlertQueueRef.current.push(enriched);
    });
    flushOrderAlertsRef.current?.();
  }, [serverDataReady, db.orders, db.order_items, db.customers, db.products]);

  useEffect(() => {
    if (!serverDataReady) return undefined;
    let refreshTimer = null;
    let disposed = false;
    const requestOrderRefresh = () => {
      if (disposed || refreshTimer) return;
      refreshTimer = setTimeout(async () => {
        refreshTimer = null;
        if (disposed) return;
        try { await refreshOrdersRef.current?.(); } catch { /* el sondeo vuelve a intentar */ }
      }, 650);
    };
    const channel = supabase
      .channel(orderWatcherNameRef.current)
      .on("postgres_changes", { event: "*", schema: "public", table: "orders" }, requestOrderRefresh)
      .subscribe();
    const poll = setInterval(async () => {
      if (disposed || document.visibilityState !== "visible") return;
      const { data, error } = await supabase
        .from("orders")
        .select("id,estado,fecha,hora")
        .order("fecha", { ascending: false })
        .order("hora", { ascending: false })
        .limit(25);
      if (!error && (data || []).some((order) => order?.id
        && (!knownOrderStatesRef.current.has(order.id) || knownOrderStatesRef.current.get(order.id) !== (order.estado || "")))) requestOrderRefresh();
    }, 15000);
    return () => {
      disposed = true;
      if (refreshTimer) clearTimeout(refreshTimer);
      clearInterval(poll);
      supabase.removeChannel(channel);
    };
  }, [serverDataReady]);

  useEffect(() => {
    flushOrderAlertsRef.current?.();
  }, [voiceMode, listening, replyByVoice]);

  function cancelSpeech() {
    speechTokenRef.current += 1;
    speechInProgressRef.current = false;
    if (speechSafetyTimerRef.current) clearTimeout(speechSafetyTimerRef.current);
    speechSafetyTimerRef.current = null;
    try { window.speechSynthesis?.cancel(); } catch { /* degradación silenciosa */ }
  }

  function speak(text, onDone) {
    const done = typeof onDone === "function" ? onDone : null;
    if (!replyByVoice || !text || typeof window === "undefined" || !("speechSynthesis" in window)) {
      done?.();
      return;
    }
    try {
      cancelSpeech();
      const token = speechTokenRef.current;
      const utterance = new SpeechSynthesisUtterance(text);
      let finished = false;
      let safetyTimer = null;
      speechInProgressRef.current = true;
      const finish = () => {
        if (finished) return;
        finished = true;
        speechInProgressRef.current = false;
        if (safetyTimer) clearTimeout(safetyTimer);
        if (speechSafetyTimerRef.current === safetyTimer) speechSafetyTimerRef.current = null;
        if (token !== speechTokenRef.current) return;
        done?.();
        setTimeout(() => flushOrderAlertsRef.current?.(), 0);
      };
      utterance.lang = "es-CO";
      utterance.rate = 0.98;
      utterance.onend = finish;
      utterance.onerror = finish;
      safetyTimer = setTimeout(() => {
        try { window.speechSynthesis.cancel(); } catch { /* el callback igual libera la escucha */ }
        finish();
      }, kitchenSpeechTimeoutMs(text));
      speechSafetyTimerRef.current = safetyTimer;
      window.speechSynthesis.speak(utterance);
    } catch {
      speechInProgressRef.current = false;
      if (speechSafetyTimerRef.current) clearTimeout(speechSafetyTimerRef.current);
      speechSafetyTimerRef.current = null;
      done?.();
      setTimeout(() => flushOrderAlertsRef.current?.(), 0);
    }
  }

  function flushOrderAlerts() {
    if (orderAlertSpeakingRef.current || speechInProgressRef.current || !orderAlertQueueRef.current.length) return;
    const session = recognitionSessionRef.current;
    const inConversation = session.active && session.mode !== "standby";
    const busy = inConversation || ["authorizing", "processing", "executing"].includes(voiceMode);
    if (busy) return;
    const alert = orderAlertQueueRef.current.shift();
    if (!alert) return;
    const resumeStandby = session.active && session.mode === "standby";
    if (resumeStandby) stopVoiceSession({ abort: true, nextMode: "idle" });
    orderAlertSpeakingRef.current = true;
    speak(alert.text, () => {
      orderAlertSpeakingRef.current = false;
      if (resumeStandby) startVoiceSession("standby");
      setTimeout(() => flushOrderAlertsRef.current?.(), 250);
    });
  }

  function addConversationMessage(role, text) {
    const clean = String(text || "").trim();
    if (!clean) return;
    setConversation((current) => [...current, { id: voiceCommandKey(), role, text: clean }].slice(-8));
  }

  function resetVoiceDraft({ keepConversation = false } = {}) {
    setDraft(null);
    draftRef.current = null;
    setResult(null);
    setExecuted(false);
    executedRef.current = false;
    commandKeyRef.current = null;
    progressRef.current = { bases: new Set(), runs: new Set(), batchIds: [], frozen: new Set(), unmolded: new Set(), orders: new Set(), ordersReady: new Set() };
    conversationContextRef.current = "";
    conversationTurnsRef.current = 0;
    handsFreeCommandRef.current = false;
    if (!keepConversation) {
      readOnlyTurnsRef.current = 0;
      setConversation([]);
    }
  }

  function changeTranscript(value, { keepConversation = false } = {}) {
    if (recognitionSessionRef.current.active && recognitionSessionRef.current.mode === "standby") stopVoiceSession();
    const nextValue = String(value || "");
    setTranscript(nextValue);
    transcriptRef.current = nextValue;
    resetVoiceDraft({ keepConversation });
  }

  function stopVoiceSession({ abort = false, nextMode = "idle" } = {}) {
    authorizationAttemptRef.current += 1;
    const session = recognitionSessionRef.current;
    session.active = false;
    session.starting = false;
    session.generation += 1;
    if (session.restartTimer) clearTimeout(session.restartTimer);
    if (session.turnTimer) clearTimeout(session.turnTimer);
    if (session.watchdogTimer) clearTimeout(session.watchdogTimer);
    if (session.activityTimer) clearTimeout(session.activityTimer);
    session.restartTimer = null;
    session.turnTimer = null;
    session.watchdogTimer = null;
    session.activityTimer = null;
    const recognition = recognitionRef.current;
    recognitionRef.current = null;
    try { if (abort) recognition?.abort(); else recognition?.stop(); } catch { /* ya estaba detenida */ }
    setListening(false);
    setVoiceMode(nextMode);
    setVoiceActivity("idle");
  }

  function markVoiceActivity(session, generation, activity) {
    if (!session.active || session.generation !== generation) return;
    if (session.activityTimer) clearTimeout(session.activityTimer);
    setVoiceActivity(activity);
    if (activity === "hearing" || activity === "wake") {
      session.activityTimer = setTimeout(() => {
        if (session.active && session.generation === generation) setVoiceActivity("listening");
      }, activity === "wake" ? kitchenVoicePauseMs("standby") + 250 : 1100);
    }
  }

  function preserveCurrentDictation(session) {
    if (session.mode !== "dictation" || !session.currentText) return;
    session.baseText = [session.baseText, session.currentText].filter(Boolean).join(" ").trim();
    session.currentText = "";
    transcriptRef.current = session.baseText;
    setTranscript(session.baseText);
  }

  function queueRecognitionRestart(session, generation, { delay = 180, abort = true, message = "" } = {}) {
    if (!session.active || session.generation !== generation) return;
    preserveCurrentDictation(session);
    if (session.restartTimer) clearTimeout(session.restartTimer);
    if (session.watchdogTimer) clearTimeout(session.watchdogTimer);
    session.watchdogTimer = null;
    session.starting = false;
    const recognition = recognitionRef.current;
    recognitionRef.current = null;
    setListening(true);
    setVoiceMode(session.mode);
    setVoiceActivity("recovering");
    if (message) setSpeechError(message);
    session.restartTimer = setTimeout(() => {
      session.restartTimer = null;
      if (!session.active || session.generation !== generation) return;
      setVoiceActivity("starting");
      beginRecognitionRef.current?.();
    }, delay);
    if (abort) {
      try { recognition?.abort(); } catch { /* el reinicio vigilado continúa */ }
    }
  }

  function armRecognitionWatchdog(session, generation, attempt, recognition, phase) {
    if (session.watchdogTimer) clearTimeout(session.watchdogTimer);
    session.watchdogTimer = setTimeout(() => {
      if (!session.active || session.generation !== generation || session.attempt !== attempt || recognitionRef.current !== recognition) return;
      queueRecognitionRestart(session, generation, {
        delay: 220,
      });
    }, kitchenRecognitionWatchdogMs(phase));
  }

  async function authorizeAndStartVoiceSession(mode, options = {}) {
    if (!voiceInputAvailable) {
      setVoiceMode("idle");
      setListening(false);
      setSpeechError("Este navegador no permite usar el micrófono con Momobot. Abrí MOMOS OPS en Chrome o Edge.");
      return;
    }
    stopVoiceSession({ abort: true, nextMode: "authorizing" });
    const authorizationAttempt = authorizationAttemptRef.current;
    cancelSpeech();
    setSpeechError("Esperando autorización del micrófono…");
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      stream.getTracks().forEach((track) => track.stop());
      await new Promise((resolve) => setTimeout(resolve, 180));
      if (!isCurrentMomobotAuthorization(authorizationAttempt, authorizationAttemptRef.current)) return;
      setSpeechError("");
      startVoiceSession(mode, options);
    } catch (error) {
      if (!isCurrentMomobotAuthorization(authorizationAttempt, authorizationAttemptRef.current)) return;
      setVoiceMode("idle");
      setListening(false);
      const blocked = error?.name === "NotAllowedError" || error?.name === "SecurityError";
      setSpeechError(blocked
        ? "El micrófono quedó bloqueado. Permitilo en el candado de la barra de direcciones y volvé a tocar “Activar Momobot”."
        : "No pude abrir el micrófono. Revisá que esté conectado y que ninguna otra aplicación lo esté usando.");
    }
  }

  function startVoiceSession(mode, { clearDictation = false } = {}) {
    if (!voiceInputAvailable) {
      setSpeechError("Este navegador no permite usar el micrófono con Momobot. Abrí MOMOS OPS en Chrome o Edge.");
      setVoiceMode("idle");
      return;
    }
    cancelSpeech();
    stopVoiceSession({ abort: true, nextMode: mode });
    if (clearDictation) changeTranscript("");
    const session = recognitionSessionRef.current;
    session.active = true;
    session.mode = mode;
    session.baseText = mode === "dictation" && !clearDictation ? transcriptRef.current.trim() : "";
    session.currentText = "";
    session.failures = 0;
    session.restartDelay = 180;
    if (session.turnTimer) clearTimeout(session.turnTimer);
    session.turnTimer = null;
    session.generation += 1;
    setVoiceMode(mode);
    setListening(true);
    setVoiceActivity("starting");
    setSpeechError("");
    session.restartTimer = setTimeout(() => beginRecognitionRef.current?.(), 80);
  }

  function processActionAlternatives(alternatives) {
    const readOnlyAlternative = alternatives.find((alternative) => kitchenOrderLookupAnswer(alternative?.transcript, voiceCatalogs) || kitchenOrderQueueAnswer(alternative?.transcript, voiceCatalogs));
    if (readOnlyAlternative) {
      interpretTranscriptRef.current?.(readOnlyAlternative.transcript, { handsFree: true, continuation: true, spokenText: readOnlyAlternative.transcript });
      return;
    }
    const controlSelection = selectKitchenVoiceControl(alternatives);
    const heard = controlSelection.transcript || selectKitchenVoiceAlternative(alternatives, voiceCatalogs).transcript;
    const control = controlSelection.control;
    if (controlSelection.ambiguous) {
      setSpeechError("Escuché dos órdenes posibles. Repetí solo confirmar, editar o cancelar.");
      return;
    }
    if (control) {
      handleVoiceControlRef.current?.(control);
      return;
    }
    handleConversationReplyRef.current?.(heard);
  }

  function processFollowupAlternatives(alternatives) {
    const readOnlyAlternative = alternatives.find((alternative) => kitchenOrderLookupAnswer(alternative?.transcript, voiceCatalogs) || kitchenOrderQueueAnswer(alternative?.transcript, voiceCatalogs));
    if (readOnlyAlternative) {
      interpretTranscriptRef.current?.(readOnlyAlternative.transcript, { handsFree: true, continuation: true, spokenText: readOnlyAlternative.transcript });
      return;
    }
    const controlSelection = selectKitchenVoiceControl(alternatives);
    const heard = controlSelection.transcript || selectKitchenVoiceAlternative(alternatives, voiceCatalogs).transcript;
    const control = controlSelection.control;
    if (controlSelection.ambiguous) {
      setSpeechError("Escuché dos órdenes posibles. Repetí una sola respuesta.");
      return;
    }
    if (control) handleVoiceControlRef.current?.(control);
    else handleConversationReplyRef.current?.(heard);
  }

  function recognitionEventAlternatives(event) {
    const groups = [];
    for (let i = event.resultIndex || 0; i < event.results.length; i += 1) {
      const alternatives = [];
      for (let j = 0; j < event.results[i].length; j += 1) {
        alternatives.push({ transcript: event.results[i][j].transcript, confidence: event.results[i][j].confidence });
      }
      if (alternatives.length) groups.push(alternatives);
    }
    return combineKitchenVoiceAlternatives(groups);
  }

  function beginRecognition() {
    const session = recognitionSessionRef.current;
    if (!session.active || session.starting || recognitionRef.current || !SpeechRecognitionApi) return;
    const generation = session.generation;
    session.attempt += 1;
    const attempt = session.attempt;
    session.starting = true;
    try {
      const recognition = new SpeechRecognitionApi();
      recognition.lang = "es-CO";
      recognition.continuous = true;
      recognition.interimResults = true;
      recognition.maxAlternatives = 5;
      try {
        const Phrase = window.SpeechRecognitionPhrase || window.webkitSpeechRecognitionPhrase;
        if (phraseBiasSupportedRef.current && Phrase && "phrases" in recognition) {
          recognition.phrases = voicePhrases.slice(0, 300).map((phrase) => new Phrase(phrase, phrase === "Momobot" || voiceTaskPhrases.has(phrase) ? 10 : 8));
        }
      } catch { rememberUnsupportedVoicePhrases(phraseBiasSupportedRef); }
      recognition.onstart = () => {
        if (recognitionSessionRef.current.generation !== generation || session.attempt !== attempt) return;
        session.starting = false;
        session.failures = 0;
        setListening(true);
        setVoiceActivity("listening");
        setSpeechError("");
        armRecognitionWatchdog(session, generation, attempt, recognition, "listening");
        vibrar("tap");
      };
      const noteAudioActivity = () => {
        if (!session.active || session.generation !== generation || session.attempt !== attempt) return;
        markVoiceActivity(session, generation, "hearing");
        armRecognitionWatchdog(session, generation, attempt, recognition, "listening");
      };
      recognition.onaudiostart = noteAudioActivity;
      recognition.onsoundstart = noteAudioActivity;
      recognition.onspeechstart = noteAudioActivity;
      recognition.onresult = (event) => {
        if (!session.active || session.generation !== generation || session.attempt !== attempt) return;
        session.failures = 0;
        session.restartDelay = 180;
        if (session.turnTimer) clearTimeout(session.turnTimer);
        session.turnTimer = null;
        markVoiceActivity(session, generation, "hearing");
        armRecognitionWatchdog(session, generation, attempt, recognition, "listening");
        if (session.mode === "standby") {
          let pendingWake = null;
          let lastHeard = "";
          let heardFinalWithoutWake = false;
          for (let i = event.resultIndex || 0; i < event.results.length; i += 1) {
            const alternatives = [];
            for (let j = 0; j < event.results[i].length; j += 1) {
              alternatives.push({ transcript: event.results[i][j].transcript, confidence: event.results[i][j].confidence });
            }
            const wakeAlternative = alternatives.find((alternative) => splitKitchenWakeWord(alternative.transcript).woke);
            const heard = wakeAlternative?.transcript || selectKitchenVoiceAlternative(alternatives, voiceCatalogs).transcript;
            const wake = splitKitchenWakeWord(heard);
            lastHeard = heard || lastHeard;
            if (wake.woke) {
              if (event.results[i].isFinal) {
                handleWakeWordRef.current?.(wake.text);
                return;
              }
              pendingWake = wake.text;
              markVoiceActivity(session, generation, "wake");
              setSpeechError("Te oigo. Terminá la frase y hacé una pausa.");
            }
            if (event.results[i].isFinal) {
              const standbySelection = selectKitchenVoiceControl(alternatives);
              const standbyControl = standbySelection.control;
              if (standbySelection.ambiguous) {
                setSpeechError("Escuché dos controles posibles. Repetí solo editar, limpiar o cancelar.");
                return;
              }
              if (standbyControl === "close") {
                handleVoiceControlRef.current?.("close");
                return;
              }
              const hasPendingDraft = Boolean(draftRef.current && !executedRef.current);
              if (hasPendingDraft && ["edit", "cancel", "repeat", "new"].includes(standbyControl)) {
                handleVoiceControlRef.current?.(standbyControl);
                return;
              }
              if (hasPendingDraft && !standbyControl && heard) {
                handleConversationReplyRef.current?.(heard);
                return;
              }
            }
            if (event.results[i].isFinal && !wake.woke) heardFinalWithoutWake = true;
          }
          if (pendingWake !== null) {
            session.turnTimer = setTimeout(() => {
              if (session.active && session.generation === generation && session.mode === "standby") handleWakeWordRef.current?.(pendingWake);
            }, kitchenVoicePauseMs("standby"));
          } else if (heardFinalWithoutWake && lastHeard) {
            setSpeechError(`Sí te oí: “${lastHeard}”. Para abrir un turno, empezá diciendo Momobot.`);
          }
          return;
        }
        if (session.mode === "action") {
          const alternatives = recognitionEventAlternatives(event);
          const lastResult = event.results[event.results.length - 1];
          if (lastResult?.isFinal) {
            processActionAlternatives(alternatives);
            return;
          }
          if (alternatives.length) {
            session.turnTimer = setTimeout(() => processActionAlternatives(alternatives), kitchenVoicePauseMs("action"));
          }
          return;
        }
        if (session.mode === "followup") {
          const alternatives = recognitionEventAlternatives(event);
          const lastResult = event.results[event.results.length - 1];
          if (lastResult?.isFinal) {
            processFollowupAlternatives(alternatives);
            return;
          }
          if (alternatives.length) {
            session.turnTimer = setTimeout(() => processFollowupAlternatives(alternatives), kitchenVoicePauseMs("followup"));
          }
          return;
        }

        setSpeechError("");
        const parts = [];
        for (let i = 0; i < event.results.length; i += 1) {
          const alternatives = [];
          for (let j = 0; j < event.results[i].length; j += 1) {
            alternatives.push({ transcript: event.results[i][j].transcript, confidence: event.results[i][j].confidence });
          }
          const readOnlyAlternative = alternatives.find((alternative) => kitchenOrderLookupAnswer(alternative?.transcript, voiceCatalogs) || kitchenOrderQueueAnswer(alternative?.transcript, voiceCatalogs));
          parts.push(readOnlyAlternative?.transcript || selectKitchenVoiceAlternative(alternatives, voiceCatalogs).transcript);
        }
        session.currentText = parts.join(" ").trim();
        const fullText = [session.baseText, session.currentText].filter(Boolean).join(" ").trim();
        transcriptRef.current = fullText;
        setTranscript(fullText);
        const lastResult = event.results[event.results.length - 1];
        const closure = splitKitchenVoiceClosure(fullText);
        if (lastResult?.isFinal && closure.closed) finishDictationRef.current?.(closure.text);
        else if (fullText) {
          session.turnTimer = setTimeout(() => finishDictationRef.current?.(fullText), kitchenVoicePauseMs("dictation", Boolean(lastResult?.isFinal)));
        }
      };
      recognition.onerror = (event) => {
        if (session.generation !== generation || session.attempt !== attempt) return;
        session.starting = false;
        const errorCode = event.error || "unknown";
        if (errorCode === "aborted" && session.active) {
          if (!session.restartTimer) queueRecognitionRestart(session, generation, { delay: 180, abort: false });
          return;
        }
        if (errorCode === "no-speech" && session.active) {
          const message = session.mode === "standby"
            ? "Momobot sigue atenta. Estoy renovando la escucha para que no se congele."
            : session.mode === "followup"
              ? "No escuché tu respuesta todavía. Momobot sigue atento."
              : session.mode === "action"
                ? "Sigo esperando tu confirmación o corrección."
                : "Sigo escuchando. Termino el turno cuando hagas una pausa.";
          queueRecognitionRestart(session, generation, { delay: 180, message });
          return;
        }
        if (errorCode === "phrases-not-supported" && session.active) {
          rememberUnsupportedVoicePhrases(phraseBiasSupportedRef);
          queueRecognitionRestart(session, generation, {
            delay: 180,
            message: "Este navegador no admite el refuerzo nativo de frases. Momobot continúa con el corrector de vocabulario MOMOS.",
          });
          return;
        }
        if (errorCode === "network" && session.active) {
          session.failures = Math.min(session.failures + 1, 6);
          queueRecognitionRestart(session, generation, {
            delay: Math.min(2400, 350 * session.failures),
            message: "Momobot perdió por un instante el servicio de voz. Sigue reconectando automáticamente…",
          });
          return;
        }
        session.active = false;
        setListening(false);
        setVoiceMode("idle");
        setVoiceActivity("idle");
        const friendly = errorCode === "not-allowed" || errorCode === "service-not-allowed" ? "Para activar Momobot, permití el micrófono y tocá “Activar Momobot” una vez."
          : errorCode === "audio-capture" ? "No encuentro un micrófono disponible. Revisá que esté conectado y permitido."
          : session.mode === "standby" ? `Momobot no pudo quedar en espera (código: ${errorCode}). Tocá “Activar Momobot” para reintentar.`
          : `Se interrumpió el reconocimiento de voz (código: ${errorCode}). Tocá el micrófono para retomarlo.`;
        setSpeechError(friendly);
      };
      recognition.onend = () => {
        if (recognitionRef.current === recognition) recognitionRef.current = null;
        if (session.generation !== generation || session.attempt !== attempt) return;
        session.starting = false;
        if (!session.active) { setListening(false); return; }
        if (session.restartTimer) return;
        const delay = session.restartDelay || 180;
        session.restartDelay = 180;
        queueRecognitionRestart(session, generation, { delay, abort: false });
      };
      recognitionRef.current = recognition;
      recognition.start();
      armRecognitionWatchdog(session, generation, attempt, recognition, "starting");
    } catch (e) {
      session.starting = false;
      recognitionRef.current = null;
      if (session.active && session.generation === generation && session.attempt === attempt && session.failures < 6) {
        session.failures += 1;
        queueRecognitionRestart(session, generation, {
          delay: Math.min(2400, 350 * session.failures),
          abort: false,
          message: `Momobot está reabriendo el micrófono (${session.failures}/6)…`,
        });
        return;
      }
      session.active = false;
      setListening(false);
      setVoiceMode("idle");
      setVoiceActivity("idle");
      setSpeechError("No pude mantener activo el reconocimiento: " + (e?.message || "error del navegador") + ".");
    }
  }

  function finishDictation(value) {
    const cleanText = String(value || "").trim();
    stopVoiceSession({ nextMode: "processing" });
    if (!cleanText) {
      setSpeechError("");
      setVoiceMode("idle");
      speak("Micrófono cerrado. No registré ninguna acción nueva.");
      return;
    }
    transcriptRef.current = cleanText;
    setTranscript(cleanText);
    setTimeout(() => interpretTranscriptRef.current?.(cleanText, { handsFree: true }), 120);
  }

  function handleWakeWord(remainder) {
    stopVoiceSession({ nextMode: "dictation" });
    readOnlyTurnsRef.current = 0;
    setSpeechError("");
    vibrar("tap");
    const closure = splitKitchenVoiceClosure(remainder);
    const control = kitchenVoiceControl(closure.text);
    if (control) {
      handleVoiceControlRef.current?.(control);
      return;
    }
    changeTranscript(closure.text);
    if (closure.text) {
      finishDictation(closure.text);
      return;
    }
    speak("Te oigo, empecemos.", () => startVoiceSession("dictation", { clearDictation: true }));
  }

  function resumeMomobotStandby() {
    if (voiceInputAvailable) startVoiceSession("standby");
  }

  function continueMomobotAfterExecution() {
    setDraft(null);
    draftRef.current = null;
    setExecuted(false);
    executedRef.current = false;
    commandKeyRef.current = null;
    progressRef.current = { bases: new Set(), runs: new Set(), batchIds: [], frozen: new Set(), unmolded: new Set(), orders: new Set(), ordersReady: new Set() };
    conversationContextRef.current = "";
    conversationTurnsRef.current = 0;
    readOnlyTurnsRef.current = 0;
    setTranscript("");
    transcriptRef.current = "";
    startVoiceSession("dictation");
  }

  function handleVoiceControl(control) {
    const currentDraft = draftRef.current;
    stopVoiceSession({ nextMode: control === "confirm" ? "executing" : "idle" });
    setSpeechError("");
    if (control === "confirm") {
      if (executingRef.current) {
        speak("Ya estoy registrando este comando. Esperá un momento.");
        return;
      }
      if (!currentDraft?.canExecute || executedRef.current) {
        speak(executedRef.current ? "Este comando ya fue aplicado." : "Todavía no puedo confirmar. Decí editar para dictar el comando nuevamente.", () => {
          if (!executedRef.current) startVoiceSession("action");
        });
        return;
      }
      executeCommandRef.current?.();
      return;
    }
    if (control === "edit" || control === "new") {
      changeTranscript("");
      speak("Listo, corrijámoslo. Contame nuevamente la tarea con tus palabras; termino el turno cuando hagas una pausa.", () => startVoiceSession("dictation"));
      return;
    }
    if (control === "repeat") {
      const prompt = currentDraft ? kitchenConversationPrompt(currentDraft, voiceCatalogs) : null;
      const summary = currentDraft?.canExecute
        ? voiceSummary(currentDraft) + " Podés decir sí, editar o cancelar."
        : prompt?.text || "Todavía no tengo una tarea para resumir.";
      speak(summary, () => startVoiceSession(currentDraft?.canExecute || !prompt?.recoverable ? "action" : "followup"));
      return;
    }
    if (control === "cancel") {
      changeTranscript("");
      speak("Comando cancelado. No registré nada. Momobot queda en espera.", resumeMomobotStandby);
      return;
    }
    if (control === "close") speak("Micrófono cerrado. El borrador sigue sin registrar.");
  }

  function handleConversationReply(reply) {
    const heard = String(reply || "").trim();
    if (!heard) {
      speak("No alcancé a oír la respuesta. Intentemos otra vez.", () => startVoiceSession("followup"));
      return;
    }
    stopVoiceSession({ nextMode: "processing" });
    const combined = mergeKitchenConversation(conversationContextRef.current || transcriptRef.current, heard, voiceCatalogs);
    transcriptRef.current = combined;
    setTranscript(combined);
    setTimeout(() => interpretTranscriptRef.current?.(combined, { handsFree: true, continuation: true, spokenText: heard }), 100);
  }

  function toggleListening() {
    if (recognitionSessionRef.current.active || listening) {
      stopVoiceSession();
      cancelSpeech();
      return;
    }
    if (draftRef.current && !executedRef.current) startVoiceSession(draftRef.current.canExecute ? "action" : "followup");
    else authorizeAndStartVoiceSession("dictation", { clearDictation: true });
  }

  function interpretTranscript(value, { handsFree = false, continuation = false, spokenText = value } = {}) {
    const queryText = String(spokenText || value || "").trim();
    const readOnlyAnswer = kitchenOrderLookupAnswer(queryText, voiceCatalogs)
      || kitchenOrderQueueAnswer(queryText, voiceCatalogs)
      || momobotContextAnswer(queryText, voiceCatalogs, assistantMemoryRef.current)
      || kitchenOrderLookupAnswer(value, voiceCatalogs)
      || kitchenOrderQueueAnswer(value, voiceCatalogs)
      || momobotContextAnswer(value, voiceCatalogs, assistantMemoryRef.current);
    if (readOnlyAnswer) {
      const pendingDraft = draftRef.current && !executedRef.current ? draftRef.current : null;
      stopVoiceSession({ nextMode: "processing" });
      setSpeechError("");
      setTranscript(queryText);
      transcriptRef.current = queryText;
      setResult({ type: "ok", text: readOnlyAnswer.text, warnings: [] });
      assistantMemoryRef.current = {
        ...assistantMemoryRef.current,
        ...(readOnlyAnswer.memoryPatch || {}),
        ...(readOnlyAnswer.orderId ? { lastTopic: "order", lastOrderId: readOnlyAnswer.orderId } : {}),
        ...(readOnlyAnswer.paidOrderIds?.[0] ? { lastTopic: "order", lastOrderId: readOnlyAnswer.paidOrderIds[0] } : {}),
      };
      addConversationMessage("user", queryText);
      addConversationMessage("assistant", readOnlyAnswer.text);
      readOnlyTurnsRef.current += 1;
      const resumeMode = momobotModeAfterReadOnly({
        handsFree,
        readOnlyTurns: readOnlyTurnsRef.current,
        hasPendingDraft: Boolean(pendingDraft),
        draftCanExecute: Boolean(pendingDraft?.canExecute),
      });
      if (handsFree) speak(readOnlyAnswer.text, resumeMode === "standby" ? resumeMomobotStandby : () => startVoiceSession(resumeMode));
      else setVoiceMode("idle");
      return;
    }
    readOnlyTurnsRef.current = 0;
    handsFreeCommandRef.current = handsFree;
    const next = parseKitchenVoice(value, voiceCatalogs);
    if (!commandKeyRef.current) commandKeyRef.current = voiceCommandKey();
    conversationContextRef.current = String(value || "").trim();
    conversationTurnsRef.current = continuation ? conversationTurnsRef.current + 1 : 0;
    progressRef.current = { bases: new Set(), runs: new Set(), batchIds: [], frozen: new Set(), unmolded: new Set(), orders: new Set(), ordersReady: new Set() };
    setDraft(next);
    draftRef.current = next;
    setResult(null);
    setExecuted(false);
    executedRef.current = false;
    if (handsFree) addConversationMessage("user", spokenText);
    if (next.canExecute) {
      vibrar("tap");
      const message = voiceSummary(next) + (handsFree ? " Podés responder sí, dale, editar o cancelar." : "");
      if (handsFree) addConversationMessage("assistant", message);
      speak(message, handsFree ? () => startVoiceSession("action") : null);
    } else {
      vibrar("error");
      const prompt = kitchenConversationPrompt(next, voiceCatalogs);
      const keepTalking = handsFree && prompt.recoverable && conversationTurnsRef.current < 4;
      const message = keepTalking
        ? prompt.text
        : prompt.recoverable
          ? `${prompt.text} Si preferís empezar de nuevo, decí editar.`
          : prompt.text;
      if (handsFree) addConversationMessage("assistant", message);
      speak(message, handsFree ? () => startVoiceSession(keepTalking ? "followup" : "action") : null);
    }
  }

  function interpretCommand() {
    interpretTranscript(transcriptRef.current || transcript);
  }

  async function executeCommand() {
    const currentDraft = draftRef.current;
    if (!currentDraft?.canExecute || executedRef.current || executingRef.current) return;
    executingRef.current = true;
    stopVoiceSession({ nextMode: "executing" });
    cancelSpeech();
    const key = commandKeyRef.current || voiceCommandKey();
    commandKeyRef.current = key;
    const note = (`[Comando de voz ${key}] ${currentDraft.transcript}`).slice(0, 1800);
    const progress = progressRef.current;
    const applied = [];
    const operationWarnings = [];
    try {
      const preparations = currentDraft.preparations?.length ? currentDraft.preparations : (currentDraft.preparation ? [currentDraft.preparation] : []);
      for (let i = 0; i < preparations.length; i += 1) {
        if (progress.bases.has(i)) continue;
        const preparation = preparations[i];
        setExecutionLabel(`Registrando ${preparation.subrecipeName}…`);
        const response = await producirSubreceta({
          subreceta_id: preparation.subrecipeId,
          gramos_nominales: preparation.nominalGrams,
          gramos_obtenidos: preparation.obtainedGrams,
          resp_user_id: perfil?.id || null,
          obs: note,
          idempotency_key: key + "-base-" + i,
        });
        progress.bases.add(i);
        applied.push(`${preparation.subrecipeName}: ${preparation.obtainedGrams} g`);
        if (Array.isArray(response?.faltantes) && response.faltantes.length) operationWarnings.push(...response.faltantes.map((x) => `${x.insumo}: faltan ${x.faltan} ${x.unidad}`));
      }

      const productions = currentDraft.productions?.length ? currentDraft.productions : (currentDraft.production ? [currentDraft.production] : []);
      if (productions.length) {
        const filling = db.settings.rellenos?.[0];
        if (!filling) throw new Error("No hay un relleno predeterminado configurado para crear las corridas.");
        for (let productionIndex = 0; productionIndex < productions.length; productionIndex += 1) {
          const production = productions[productionIndex];
          for (let runIndex = 0; runIndex < production.runs.length; runIndex += 1) {
            const runKey = `${productionIndex}:${runIndex}`;
            if (progress.runs.has(runKey)) continue;
            const run = production.runs[runIndex];
            setExecutionLabel(`Creando ${run.quantity} ${production.figure} de ${run.flavor}…`);
            const response = await crearCorrida({
              sabor: run.flavor,
              relleno: filling,
              figuras: [{ figura: production.figure, cant: run.quantity }],
              resp_user_id: perfil?.id || null,
              horas_congelacion: db.settings.horasCongelacion || 10,
              obs: note,
              idempotency_key: `${key}-production-${productionIndex}-run-${runIndex}`,
            });
            progress.runs.add(runKey);
            applied.push(`${run.quantity} ${production.figure} de ${run.flavor}`);
            const lots = Array.isArray(response?.lotes) ? response.lotes : [];
            lots.forEach((lot) => {
              const id = lot.batch_id || lot.id;
              if (id && !progress.batchIds.includes(id)) progress.batchIds.push(id);
            });
            if (Array.isArray(response?.faltantes) && response.faltantes.length) operationWarnings.push(...response.faltantes.map((x) => `${x.insumo}: faltan ${x.faltan} ${x.unidad}`));
          }
        }
      }

      if (currentDraft.madeToOrder && !progress.orders.has(currentDraft.madeToOrder.orderId)) {
        const orderPreparation = currentDraft.madeToOrder;
        const sourceOrder = db.orders.find((order) => order.id === orderPreparation.orderId);
        const permission = orderTransitionPermission(perfil, sourceOrder?.estado || "Pagado", "En producción");
        if (!permission.allowed) throw new Error(permission.reason);
        setExecutionLabel(`Iniciando preparación del pedido ${orderPreparation.orderId}…`);
        const response = await setOrderStatusRemoto(orderPreparation.orderId, "En producción");
        progress.orders.add(orderPreparation.orderId);
        applied.push(`${orderPreparation.orderId} en producción · ${voiceOrderItems(orderPreparation)}`);
        if (Array.isArray(response?.faltantes) && response.faltantes.length) {
          operationWarnings.push(`El pedido inició con ${response.faltantes.length} faltante${response.faltantes.length === 1 ? "" : "s"} de inventario. Revisá el detalle del pedido.`);
        }
      }

      if (currentDraft.orderHandoff && !progress.ordersReady.has(currentDraft.orderHandoff.orderId)) {
        const handoff = currentDraft.orderHandoff;
        const sourceOrder = db.orders.find((order) => order.id === handoff.orderId);
        const permission = orderTransitionPermission(perfil, sourceOrder?.estado || "En producción", "Listo para empaque");
        if (!permission.allowed) throw new Error(permission.reason);
        setExecutionLabel(`Entregando el pedido ${handoff.orderId} a Empaque…`);
        if (db.operationalControlReady) await completarEtapaPedido(handoff.orderId, "Cocina");
        await setOrderStatusRemoto(handoff.orderId, "Listo para empaque");
        progress.ordersReady.add(handoff.orderId);
        applied.push(`${handoff.orderId} listo para empaque`);
      }

      if (currentDraft.startFreezing) {
        const freezingTargets = [...new Set([...(currentDraft.freezeBatchIds || []), ...progress.batchIds])];
        if (!freezingTargets.length) throw new Error("No tengo un lote validado para iniciar su congelación.");
        for (let i = 0; i < freezingTargets.length; i += 1) {
          const batchId = freezingTargets[i];
          if (progress.frozen.has(batchId)) continue;
          setExecutionLabel(`Iniciando congelación ${batchId} · ${i + 1}/${freezingTargets.length}…`);
          await empezarCongelamiento(batchId);
          progress.frozen.add(batchId);
        }
        applied.push(`${progress.frozen.size} cronómetro${progress.frozen.size === 1 ? "" : "s"} de congelación`);
      }

      if (currentDraft.unmolding && !progress.unmolded.has(currentDraft.unmolding.batchId)) {
        const outcome = currentDraft.unmolding;
        setExecutionLabel(`Desmoldando ${outcome.batchId}…`);
        await desmoldarLote(outcome.batchId, outcome.perfectas, outcome.imperfectas, outcome.descartadas);
        progress.unmolded.add(outcome.batchId);
        applied.push(`${outcome.batchId} desmoldado: ${voiceOutcomeCount(outcome.perfectas, "perfecta", "perfectas")}, ${voiceOutcomeCount(outcome.imperfectas, "imperfecta", "imperfectas")} y ${voiceOutcomeCount(outcome.descartadas, "descartada", "descartadas")}`);
      }

      setExecutionLabel("Actualizando la cocina…");
      try { await refrescar(); }
      catch { operationWarnings.push("Las acciones se aplicaron, pero la vista no se pudo actualizar. Recargá para verlas."); }
      const uniqueApplied = [...new Set(applied)];
      const text = uniqueApplied.length ? uniqueApplied.join(" · ") : "Comando aplicado";
      setResult({ type: "ok", text, warnings: [...new Set(operationWarnings)] });
      setExecuted(true);
      executedRef.current = true;
      setVoiceMode("idle");
      toast("ok", "Comando de cocina aplicado");
      const nextMode = momobotModeAfterExecution({ handsFree: handsFreeCommandRef.current, voiceAvailable: voiceInputAvailable, succeeded: true });
      if (nextMode === "dictation") {
        const message = "Listo. " + text + ". ¿Qué hacemos después? Si terminaste, decí cierra.";
        addConversationMessage("assistant", message);
        speak(message, continueMomobotAfterExecution);
      } else speak("Listo. " + text + ". Momobot queda en espera.", resumeMomobotStandby);
    } catch (e) {
      const partial = progress.bases.size || progress.runs.size || progress.frozen.size || progress.unmolded.size || progress.orders.size;
      const friendlyError = explainOperationalError(e, { inventory: db.inventory_items || [], subrecipes });
      const detail = (partial ? "Hay pasos ya aplicados y protegidos contra duplicados. " : "") + friendlyError;
      setResult({ type: "error", text: detail, warnings: [] });
      setVoiceMode("idle");
      toast("error", detail);
      speak("No pude completar todo el comando. Revisá el mensaje en pantalla. No inicié pasos posteriores al error.", resumeMomobotStandby);
    } finally {
      executingRef.current = false;
    }
  }

  beginRecognitionRef.current = beginRecognition;
  startVoiceSessionRef.current = startVoiceSession;
  finishDictationRef.current = finishDictation;
  handleWakeWordRef.current = handleWakeWord;
  handleVoiceControlRef.current = handleVoiceControl;
  handleConversationReplyRef.current = handleConversationReply;
  interpretTranscriptRef.current = interpretTranscript;
  executeCommandRef.current = executeCommand;
  flushOrderAlertsRef.current = flushOrderAlerts;

  const voiceStatusLabel = listening
    ? voiceActivity === "recovering" ? "Reconectando oído…"
      : voiceActivity === "starting" ? "Abriendo micrófono…"
        : voiceActivity === "wake" ? "Momobot te oyó · terminá la frase"
          : voiceActivity === "hearing" ? "Te estoy oyendo…"
            : voiceMode === "standby" ? "Atenta · decí “Momobot”"
              : voiceMode === "action" ? "Esperando confirmar o editar"
                : voiceMode === "followup" ? "Escuchando tu respuesta"
                  : "Te escucho · hacé una pausa"
    : voiceMode === "authorizing" ? "Autorizando micrófono…"
      : voiceMode === "processing" ? "Interpretando…"
        : draft && !executed ? "Tocá para dar una orden" : "Tocá para hablar";
  const standbyStatus = voiceActivity === "recovering" ? "↻ Reconectando escucha"
    : voiceActivity === "starting" ? "◌ Abriendo micrófono"
      : voiceActivity === "wake" ? "● Momobot detectada"
        : voiceActivity === "hearing" ? "● Voz detectada"
          : "● Micrófono activo · decí Momobot";

  return (
    <div className="momo-momobot-fab" data-open={abierto ? "true" : "false"}>
      {!abierto ? (
        <button type="button" onClick={() => setAbierto(true)} data-listening={listening}
          className="momo-voice-orb w-16 h-16 rounded-full flex items-center justify-center text-white text-2xl shadow-xl"
          style={{ background: T.coral }} title="MomoBot · copiloto de cocina"
          aria-label={listening ? "Momobot escuchando · abrir copiloto de cocina" : "Abrir Momobot copiloto de cocina"}>
          {listening ? <span className="momo-voice-wave" aria-hidden="true"><i /><i /><i /><i /></span> : "🎙️"}
        </button>
      ) : (
      <Card id="momobot-cocina" data-testid="momobot-panel" className="momo-modal-sheet momo-momobot-panel p-4 w-[min(94vw,720px)] max-h-[82vh] overflow-y-auto shadow-2xl">
      <div className="flex flex-wrap items-center justify-between gap-2 mb-3 pb-3 border-b" style={{ borderColor: T.border }}>
        <div className="flex items-center gap-2">
          <span className="w-8 h-8 rounded-xl flex items-center justify-center text-sm shrink-0" style={{ background: T.coralSoft }} aria-hidden="true">✨</span>
          <div><div className="text-[9px] uppercase tracking-[.18em] font-extrabold" style={{ color: T.coral }}>Asistente de Cocina MOMOS</div><div className="text-sm font-extrabold" style={{ color: T.choco }}>Momobot · manos libres</div></div>
        </div>
        <div className="flex items-center gap-2">
          <span className="rounded-full px-2.5 py-1 text-[9px] font-extrabold" style={{ background: listening ? T.coralSoft : "#DDEBD9", color: listening ? "#A54830" : "#315B35" }}>{listening ? "● Te estoy escuchando" : "✓ Confirmás antes de registrar"}</span>
          <button type="button" onClick={() => setAbierto(false)} aria-label="Minimizar Momobot" title="Minimizar" className="w-7 h-7 rounded-full flex items-center justify-center text-sm font-bold border shrink-0 transition" style={{ background: T.surface, borderColor: T.border, color: T.choco2 }}>✕</button>
        </div>
      </div>
      <div data-testid="momobot-layout" className="momo-momobot-layout">
        <div className="momo-momobot-rail">
          <button type="button" onClick={toggleListening} disabled={voiceMode === "authorizing"} data-listening={listening} aria-pressed={listening}
            className="momo-voice-orb momo-momobot-voice-orb rounded-full flex items-center justify-center text-white font-bold"
            style={{ background: T.coral }} aria-label={listening ? voiceMode === "standby" ? "Desactivar Momobot" : "Cerrar micrófono" : draft && !executed ? "Escuchar una orden de voz" : "Empezar dictado continuo"}>
            {listening ? <span className="momo-voice-wave" aria-hidden="true"><i /><i /><i /><i /></span> : "🎙️"}
          </button>
          <span className="momo-momobot-status text-[10px] font-extrabold uppercase tracking-[.1em]" style={{ color: listening ? "#A03B2A" : T.choco2 }}>
            {voiceStatusLabel}
          </span>
        </div>
        <div className="flex-1 min-w-0">
          <div className="flex flex-wrap items-center justify-between gap-2 mb-1">
            <div>
              <div className="text-[9px] uppercase tracking-[.14em] font-extrabold" style={{ color: T.coral }}>Momobot</div>
              <div className="display momo-momobot-title font-semibold">¿Qué necesitas hacer?</div>
              <div className="text-xs mt-0.5" style={{ color: T.choco2 }}>Decí “Momobot” y hablá natural. Si falta algo te lo preguntará antes de registrar.</div>
              <div className="grid grid-cols-3 gap-2 mt-2 max-w-md">
                {[[listening ? "Activa" : "Lista","Escucha"],[contextSnapshot.paid + contextSnapshot.kitchen + contextSnapshot.packing,"Pedidos"],[contextSnapshot.activeLots,"Lotes"]].map(([value,label]) => <div key={label} className="rounded-xl border px-2.5 py-1.5 text-center" style={{ borderColor: T.border, background: "#FFFDFC" }}><div className="text-xs font-extrabold">{value}</div><div className="text-[8px] uppercase font-extrabold" style={{ color: T.choco2 }}>{label}</div></div>)}
              </div>
              {voiceMode === "standby" && <div className="inline-flex mt-2 rounded-full px-2 py-0.5 text-[9px] font-extrabold" role="status" style={{ background: "#DCE7F2", color: "#3E5C7E" }}>{standbyStatus}</div>}
              {!voiceInputAvailable && <div className="text-[10px] font-extrabold mt-1" style={{ color: "#A03B2A" }}>Este visor no ofrece micrófono para Momobot · abrí la app en Chrome o Edge</div>}
              <div className="mt-2 rounded-xl px-3 py-2 text-[10px] font-semibold" style={{ background: T.vainilla, color: T.choco2 }}>Podés decir: “¿Qué hago ahora?”, “¿Cómo va el lote 31?” o “Prepará 5 Lizis de Oreo”.</div>
            </div>
            <label className="flex items-center gap-1.5 text-[11px] font-bold rounded-full px-3 py-1.5 shrink-0" style={{ color: T.choco2, background: T.surface, border: `1px solid ${T.border}` }}>
              <input type="checkbox" checked={replyByVoice} onChange={(e) => setReplyByVoice(e.target.checked)} /> Responder por voz
            </label>
          </div>
          {conversation.length > 0 && (
            <div className="rounded-2xl p-3 mb-2 space-y-2" aria-live="polite" style={{ background: T.soft, border: `1px solid ${T.border}` }}>
              <div className="text-[10px] font-extrabold uppercase tracking-[.12em]" style={{ color: T.choco2 }}>Conversación con Momobot</div>
              {conversation.map((message) => (
                <div key={message.id} className={`flex ${message.role === "user" ? "justify-end" : "justify-start"}`}>
                  <div className="max-w-[92%] rounded-2xl px-3 py-2 text-xs font-semibold" style={message.role === "user"
                    ? { background: T.rosa, color: "#6D3541" }
                    : { background: T.vainilla, color: T.choco }}>
                    <span className="font-extrabold">{message.role === "user" ? "Cocina" : "Momobot"}: </span>{message.text}
                  </div>
                </div>
              ))}
            </div>
          )}
          <textarea value={transcript} onChange={(e) => changeTranscript(e.target.value)} rows={3}
            className={inputCls + " resize-y"} style={{ ...inputStyle, borderColor: "#EAC8BA", boxShadow: "inset 0 1px 0 rgba(84,56,43,.03)" }}
            placeholder="Ej: Producir 10 Lizis: 4 de limón y 6 de Oreo; después iniciar congelación." aria-label="Comando de cocina" />
          {speechError && <div className="mt-2 text-xs font-bold rounded-xl px-3 py-2" style={{ background: "#FFF4E0", color: "#96690F" }}>{speechError}</div>}
          <div className="flex flex-wrap gap-2 mt-2">
            <Btn small onClick={interpretCommand} disabled={!transcript.trim() || listening || voiceMode === "processing" || voiceMode === "executing"}>Interpretar comando</Btn>
            <Btn small kind="ghost" onClick={() => changeTranscript(VOICE_KITCHEN_EXAMPLE)}>Usar ejemplo</Btn>
            {(transcript || draft || result) && <Btn small kind="ghost" onClick={() => changeTranscript("")}>Limpiar</Btn>}
            {voiceInputAvailable && !listening && voiceMode === "idle" && <Btn small kind="ghost" onClick={() => authorizeAndStartVoiceSession("standby")}>Activar “Momobot”</Btn>}
          </div>
        </div>
      </div>

      {draft && (
        <div className="mt-4 pt-4 border-t" style={{ borderColor: T.border }}>
          <div className="text-xs font-extrabold uppercase tracking-[.12em] mb-2" style={{ color: T.choco2 }}>Esto entendió MOMOS</div>
          {draft.corrections?.length > 0 && (
            <div className="text-xs font-bold rounded-xl px-3 py-2 mb-2" style={{ background: "#E3EFE0", color: "#3F6B42" }}>
              ✓ Afiné vocabulario MOMOS: {draft.corrections.map((item) => `“${item.heard}” → ${item.understoodAs}`).join(" · ")}
            </div>
          )}
          {draft.errors.map((error) => <div key={error} className="text-xs font-bold rounded-xl px-3 py-2 mb-2" style={{ background: "#F6D4CD", color: "#A03B2A" }}>✕ {error}</div>)}
          {draft.warnings.map((warning) => <div key={warning} className="text-xs font-bold rounded-xl px-3 py-2 mb-2" style={{ background: "#FFF4E0", color: "#96690F" }}>△ {warning}</div>)}
          <div className="grid sm:grid-cols-3 gap-2">
            {(draft.preparations?.length ? draft.preparations : (draft.preparation ? [draft.preparation] : [])).map((preparation) => (
              <div key={preparation.subrecipeId} className="rounded-2xl p-3" style={{ background: "#F7ECD9" }}>
                <div className="text-[10px] font-extrabold uppercase tracking-wider" style={{ color: T.choco2 }}>Preparar base</div>
                <div className="font-bold text-sm mt-1">{preparation.subrecipeName}</div>
                <div className="text-xs mt-1">{preparation.nominalGrams} g preparados → {preparation.obtainedGrams} g obtenidos</div>
                {preparation.usage && <div className="text-[10px] font-extrabold mt-1" style={{ color: preparation.usage.includes("Relleno") ? "#8E4B5A" : T.choco2 }}>↳ {preparation.usage}</div>}
              </div>
            ))}
            {(draft.productions?.length ? draft.productions : (draft.production ? [draft.production] : [])).map((production, productionIndex) => (
              <div key={`${production.figure}-${productionIndex}`} className="rounded-2xl p-3" style={{ background: "#F3D7DC" }}>
                <div className="text-[10px] font-extrabold uppercase tracking-wider" style={{ color: "#8E4B5A" }}>Producción · {production.calculatedTotal} total</div>
                <div className="font-bold text-sm mt-1">{production.figure}</div>
                <div className="text-xs mt-1">{production.runs.map((run) => `${run.quantity} ${run.flavor}`).join(" · ")}</div>
              </div>
            ))}
            {draft.madeToOrder && (
              <div className="rounded-2xl p-3" style={{ background: "#F7ECD9" }}>
                <div className="text-[10px] font-extrabold uppercase tracking-wider" style={{ color: "#96690F" }}>Preparación bajo pedido</div>
                <div className="font-bold text-sm mt-1">Pedido {draft.madeToOrder.orderId}{draft.madeToOrder.customerName ? ` · ${draft.madeToOrder.customerName}` : ""}</div>
                <div className="text-xs mt-1">Comanda: {draft.madeToOrder.orderContent || draft.madeToOrder.items.map((item) => `${item.quantity} × ${item.productName}`).join(" · ")}</div>
                <div className="text-[10px] font-extrabold mt-1" style={{ color: "#3F6B42" }}>✓ Orden pagada y contenido verificado</div>
                <div className="text-[10px] font-extrabold mt-1" style={{ color: "#96690F" }}>Al confirmar, el pedido completo pasa a En producción y registra su inicio en Cocina</div>
              </div>
            )}
            {draft.orderHandoff && (
              <div className="rounded-2xl p-3 border" style={{ background: T.vainilla, borderColor: T.border }}>
                <div className="text-[10px] font-extrabold uppercase tracking-wider" style={{ color: "#A54830" }}>Entrega de Cocina a Empaque</div>
                <div className="font-bold text-sm mt-1">Pedido {draft.orderHandoff.orderId}{draft.orderHandoff.customerName ? ` · ${draft.orderHandoff.customerName}` : ""}</div>
                <div className="text-xs mt-1">{draft.orderHandoff.orderContent}</div>
                <div className="text-[10px] font-extrabold mt-2" style={{ color: "#A54830" }}>Al confirmar pasa a Listo para empaque y avisa al equipo de Empaque.</div>
              </div>
            )}
            {draft.startFreezing && (
              <div className="rounded-2xl p-3" style={{ background: T.vainilla }}>
                <div className="text-[10px] font-extrabold uppercase tracking-wider" style={{ color: "#3E5C7E" }}>{draft.production ? "Después" : "Acción sobre lote"}</div>
                <div className="font-bold text-sm mt-1">❄️ Iniciar congelación</div>
                <div className="text-xs mt-1">{draft.freezeBatchIds?.length
                  ? `${draft.freezeBatchIds.join(", ")} · lote${draft.freezeBatchIds.length === 1 ? "" : "s"} existente${draft.freezeBatchIds.length === 1 ? "" : "s"} validado${draft.freezeBatchIds.length === 1 ? "" : "s"}`
                  : "Solo en los lotes que cree este comando"} · objetivo {db.settings.horasCongelacion || 10} h</div>
              </div>
            )}
            {draft.unmolding && (
              <div className="rounded-2xl p-3" style={{ background: T.vainilla }}>
                <div className="text-[10px] font-extrabold uppercase tracking-wider" style={{ color: "#3F6B42" }}>Desmolde · {draft.unmolding.total} total</div>
                <div className="font-bold text-sm mt-1">🧊 {draft.unmolding.batchId}</div>
                <div className="text-xs mt-1">{voiceOutcomeCount(draft.unmolding.perfectas, "perfecta", "perfectas")} · {voiceOutcomeCount(draft.unmolding.imperfectas, "imperfecta", "imperfectas")} · {voiceOutcomeCount(draft.unmolding.descartadas, "descartada", "descartadas")}</div>
                <div className="text-[10px] font-extrabold mt-1" style={{ color: "#3F6B42" }}>Al confirmar pasa a Listo y actualiza el stock</div>
              </div>
            )}
          </div>
          <div className="text-[11px] font-semibold mt-2" style={{ color: T.choco2 }}>Manos libres: respondé “sí”, “dale”, “hazlo”, “editar”, “repetir” o “cancelar”. “Cierra” solo apaga el micrófono. La conversación original quedará en las observaciones.</div>
          <div className="flex flex-wrap gap-2 mt-3">
            <BtnAsync confirmar="¿Ejecutar? Tocá de nuevo" textoEnVuelo={executionLabel} disabled={!draft.canExecute || executed} onClick={executeCommand}>
              {executed ? "Aplicado ✓" : "Confirmar y registrar"}
            </BtnAsync>
            <Btn kind="ghost" onClick={() => { stopVoiceSession(); resetVoiceDraft(); }}>Cancelar</Btn>
          </div>
        </div>
      )}

      {result && (
        <div className="mt-3 rounded-2xl px-4 py-3 text-sm font-bold" role={result.type === "error" ? "alert" : "status"}
          style={result.type === "error" ? { background: "#F6D4CD", color: "#A03B2A" } : { background: "#E3EFE0", color: "#3F6B42" }}>
          {result.type === "error" ? "✕ " : "✓ "}{result.text}
          {result.warnings?.length > 0 && <div className="text-xs mt-2 font-semibold">Atención: {result.warnings.join(" · ")}</div>}
        </div>
      )}

    </Card>
      )}
    </div>
  );
}

function Produccion({ db, update, user, refrescar, perfil, serverDataReady, focus }) {
  const [, setTick] = useState(0);
  useEffect(() => { const t = setInterval(() => setTick((x) => x + 1), 60000); return () => clearInterval(t); }, []);
  const [nuevo, setNuevo] = useState(false);
  const [pre, setPre] = useState(null); // sugerencia que origina la corrida
  const [queueRequest, setQueueRequest] = useState(null);
  const corridaIdemKeyRef = useRef(null); // 1 por apertura del form: tolera retries de red sin duplicar la corrida
  const s = db.settings;
  const sabores = [...s.saboresFrutales, ...s.saboresCremosos];
  // Producción v2: solo figuras activas CON product_id se pueden producir (contrato de RPC punto 4).
  const figurasProducibles = useMemo(() => (db.figuras || []).filter((f) => f.activo && f.productId), [db.figuras]);
  const productoDeFigura = useMemo(() => {
    const map = {};
    figurasProducibles.forEach((f) => { map[f.nombre] = db.products.find((p) => p.id === f.productId); });
    return map;
  }, [figurasProducibles, db.products]);
  const formInicial = () => ({
    sabor: sabores[0], relleno: s.rellenos[0], // salsa NO: se aplica al despacho, a gusto del cliente
    figuras: Object.fromEntries(figurasProducibles.map((f) => [f.nombre, 0])), // nombreFigura → cantidad
    resp: "", horasCongelacion: s.horasCongelacion || 10, obs: "",
  });
  const [form, setForm] = useState(formInicial);
  const [msg, setMsg] = useState("");
  const [registroError, setRegistroError] = useState("");
  const [enviando, setEnviando] = useState(false);
  const [enviandoBatchId, setEnviandoBatchId] = useState(null); // deshabilita solo la card del lote en vuelo
  const [desmolde, setDesmolde] = useState(null); // {batchId, prod, perfectas, imperfectas, descartadas} — mini-modal de conteos
  const [enviandoDesmolde, setEnviandoDesmolde] = useState(false);
  const puedeIniciarPedidos = orderTransitionPermission(perfil, "Pagado", "En producción").allowed;
  const puedeEntregarEmpaque = orderTransitionPermission(perfil, "En producción", "Listo para empaque").allowed;
  const [queueBusyOrderId, setQueueBusyOrderId] = useState(null);
  const [detallePedidoCocinaId, setDetallePedidoCocinaId] = useState(null);
  const detallePedidoCocina = detallePedidoCocinaId ? db.orders.find((order) => order.id === detallePedidoCocinaId) : null;
  const batchBuckets = useMemo(() => partitionByActivity(db.production_batches, isActiveProductionBatch), [db.production_batches]);
  const [scope, setScope] = useState("active");
  const [detalleLoteId, setDetalleLoteId] = useState(null);
  const detalleLote = useMemo(() => (db.production_batches || []).find((lote) => lote.id === detalleLoteId) || null, [db.production_batches, detalleLoteId]);
  const detalleCongelacion = detalleLote ? estadoCongelacion(detalleLote) : null;
  const detalleMerma = detalleLote && detalleLote.prod > 0 ? (detalleLote.imperfectas + detalleLote.descartadas) / detalleLote.prod : 0;

  // ── Componentes + BOM (hito 2): preparar bases/subrecetas ──
  const [prepBase, setPrepBase] = useState(false);
  const prepIdemKeyRef = useRef(null); // 1 por apertura del form (mismo patrón que corridaIdemKeyRef)
  const [prepForm, setPrepForm] = useState({ subrecetaId: "", nominal: 1000, obtenidos: "", obtenidosTocado: false, resp: "", obs: "" });
  const [detallePreparacionId, setDetallePreparacionId] = useState(null);
  const [detalleCantidadFinal, setDetalleCantidadFinal] = useState(300);
  const [enviandoPrep, setEnviandoPrep] = useState(false);
  const subrecetasActivas = useMemo(() => (db.subrecetas || []).filter((sr) => sr.activo), [db.subrecetas]);
  useEffect(() => {
    const subrecipeId = focus?.subrecipeId;
    if (!subrecipeId || !subrecetasActivas.some((subrecipe) => subrecipe.id === subrecipeId)) return;
    abrirPrepararBase(subrecipeId);
  }, [focus?.subrecipeId]);
  const itemDe = useMemo(() => { const m = {}; db.inventory_items.forEach((i) => { m[i.id] = i; }); return m; }, [db.inventory_items]);
  const prepSel = subrecetasActivas.find((sr) => sr.id === prepForm.subrecetaId) || null;
  const detallePreparacion = subrecetasActivas.find((sr) => sr.id === detallePreparacionId) || null;
  const detalleFormula = useMemo(() => calculateSubrecipeBatch({
    subrecipe: detallePreparacion,
    ingredients: db.subreceta_ingredientes || [],
    inventory: db.inventory_items || [],
    desiredOutputGrams: detalleCantidadFinal,
  }), [detallePreparacion, detalleCantidadFinal, db.subreceta_ingredientes, db.inventory_items]);
  function cantidadPreparacionTexto(unidad, cantidad) {
    const value = +cantidad || 0;
    if (unidad === "kg" && value < 1) return `${Math.round(value * 10000) / 10} g`;
    if (unidad === "L" && value < 1) return `${Math.round(value * 10000) / 10} ml`;
    return `${Math.round(value * 10000) / 10000} ${unidad}`.trim();
  }
  // Derivado en vivo: consumo escalado (cantidad × nominal/1000) + costo estimado del batch.
  const prepIngredientes = useMemo(() => {
    if (!prepSel) return [];
    const factor = (+prepForm.nominal || 0) / 1000;
    return (db.subreceta_ingredientes || []).filter((r) => r.subrecetaId === prepSel.id).map((r) => {
      const it = itemDe[r.itemId];
      const req = Math.round(r.cantidad * factor * 10000) / 10000;
      // Texto para cocina: kg/L chicos se leen en g/ml (el descuento real sigue en la unidad del insumo)
      const unidad = it ? it.unidad : "";
      const reqTxt = cantidadPreparacionTexto(unidad, req);
      return { itemId: r.itemId, nombre: it ? it.nombre : r.itemId, unidad, req, reqTxt, alcanza: it ? it.stock >= req : false, costo: it ? req * it.costo : 0 };
    });
  }, [prepSel, prepForm.nominal, db.subreceta_ingredientes, itemDe]);
  const prepCosto = prepIngredientes.reduce((a, x) => a + x.costo, 0);
  const prepObtenidosDefault = prepSel ? Math.round((+prepForm.nominal || 0) * (1 - prepSel.mermaPct / 100) * 10) / 10 : 0;
  const prepObtenidos = prepForm.obtenidosTocado && prepForm.obtenidos !== "" ? prepForm.obtenidos : prepObtenidosDefault;
  const ultimaPrepDe = useMemo(() => {
    const m = {};
    (db.subreceta_producciones || []).forEach((sp) => { if (!m[sp.subrecetaId]) m[sp.subrecetaId] = sp; }); // vienen desc por created_at
    return m;
  }, [db.subreceta_producciones]);

  // Resuelve el nombre libre del form al id del staff activo (RPC exige FK real,
  // no nombre suelto). Sin match → null (resp_user_id es opcional server-side).
  function respUserId(nombre) {
    const n = String(nombre || "").trim().toLowerCase();
    if (!n) return null;
    const u = db.users.find((x) => x.activo && String(x.nombre || "").trim().toLowerCase() === n);
    return u ? u.id : null;
  }

  async function refrescarSilencioso(onFail) {
    try {
      await refrescar();
    } catch (e) {
      onFail();
    }
  }

  const kitchenProductionPlan = useMemo(() => buildKitchenProductionPlan({ ...db, figuras: figurasProducibles }, {
    today: hoyISO(), historyDays: 28, horizonDays: 3,
  }), [db, figurasProducibles]);
  const plannedSuggestionIds = new Set(kitchenProductionPlan.plans.flatMap((plan) => plan.suggestionIds));
  const unplannedSuggestions = (db.production_suggestions || []).filter((suggestion) => suggestion.estado === "Pendiente"
    && suggestion.area !== "Inventario" && !plannedSuggestionIds.has(suggestion.id));

  // Stock operativo: fuente oficial usada por ventas y reservas (products.stock de tipo momo)
  const stockOperativo = useMemo(() =>
    db.products.filter((p) => p.tipo === "momo").map((p) => [p.nombre, p.stock, p.id]),
  [db.products]);

  // v2: con desmolde diferido, "perfectas" vale 0 mientras el lote está en proceso —
  // acá lo que importa es lo PRODUCIDO pendiente/en curso (prod). Se agrupa por
  // producto·sabor·gramaje (sin figura en la key: una corrida puede mezclar figuras
  // que caen en el mismo producto); la figura mostrada se deriva de la composición
  // y si el grupo junta figuras distintas se muestra "varias".
  const enProceso = useMemo(() => {
    const map = {};
    db.production_batches.filter(isActiveProductionBatch).forEach((l) => {
      const k = `${l.producto} · ${l.sabor} · ${l.gramaje}`;
      const figuraLote = Array.isArray(l.figuras) && l.figuras.length ? l.figuras.map((f) => f.figura).join("+") : l.figura;
      if (!map[k]) map[k] = { label: k, producto: l.producto, sabor: l.sabor, gramaje: l.gramaje, figura: figuraLote, cant: 0 };
      else if (map[k].figura !== figuraLote) map[k].figura = "varias";
      map[k].cant += l.prod;
    });
    return Object.values(map).map((e) => ({ ...e, label: `${e.producto} · ${e.sabor} · ${e.figura || "—"} · ${e.gramaje}` }));
  }, [db.production_batches]);

  // Foco de las cards → filtra la lista "Lotes" de abajo (panel accionable, no solo informativo).
  const [foco, setFoco] = useState(null); // {producto} (stock) | {combo:true, producto,sabor,figura,gramaje} (en proceso)
  const lotesPorScope = scope === "active" ? batchBuckets.active : batchBuckets.history;
  const lotesFiltrados = useMemo(() => {
    if (!foco) return lotesPorScope;
    // foco.combo ya no incluye figura en la key (ver enProceso): agrupa por producto·sabor·gramaje.
    return lotesPorScope.filter((l) => foco.combo
      ? l.producto === foco.producto && l.sabor === foco.sabor && l.gramaje === foco.gramaje
      : l.producto === foco.producto);
  }, [lotesPorScope, foco]);
  const focoLabel = foco ? (foco.combo ? `${foco.producto} · ${foco.sabor} · ${foco.figura} · ${foco.gramaje}` : foco.producto) : "";
  function enfocarLotes(next) { setFoco(next); setTimeout(() => { const el = document.getElementById("lotes-produccion"); if (el) el.scrollIntoView({ behavior: "smooth", block: "start" }); }, 0); }

  function alistarPedidoDesdeCola(orderId) {
    if (!puedeIniciarPedidos) {
      setMsg("Solo Cocina o Administración pueden confirmar que un pedido pagado entra a producción.");
      return;
    }
    setQueueRequest({ orderId, token: `${orderId}-${Date.now()}` });
    setTimeout(() => {
      const panel = document.getElementById("momobot-cocina");
      if (panel) panel.scrollIntoView({ behavior: "smooth", block: "start" });
    }, 80);
  }

  async function cambiarPedidoDesdeCocina(orderId, estado) {
    const order = db.orders.find((item) => item.id === orderId);
    const permiso = orderTransitionPermission(perfil, order?.estado, estado);
    if (!permiso.allowed) {
      setMsg(permiso.reason);
      return false;
    }
    setQueueBusyOrderId(orderId);
    // Escritura y refresco en try/catch SEPARADOS: si falla refrescar() no debe
    // reportarse como que falló la transición de estado (juice-v1 regla 4).
    let response;
    try {
      if (estado === "Listo para empaque" && db.operationalControlReady) {
        await completarEtapaPedido(orderId, "Cocina");
      }
      response = await setOrderStatusRemoto(orderId, estado);
    } catch (error) {
      setQueueBusyOrderId(null);
      toast("error", `No se pudo pasar ${orderId} a “${estado}”: ${error.message}`);
      return false;
    }
    const faltantes = Array.isArray(response?.faltantes) ? response.faltantes.length : 0;
    toast("ok", estado === "En producción"
      ? `${orderId} · Cocina inició la preparación${faltantes ? ` con ${faltantes} alerta${faltantes === 1 ? "" : "s"} de inventario` : ""}`
      : `${orderId} · listo para Empaque`);
    try { await refrescar(); } catch { toast("alert", `${orderId} avanzó, pero no se pudo actualizar la vista. Recargá la página.`); }
    setQueueBusyOrderId(null);
    if (estado === "Listo para empaque") setDetallePedidoCocinaId(null);
    return true;
  }

  // Genera una idempotency_key nueva cada vez que el form se abre; los reintentos
  // dentro de la misma apertura reusan la misma key (útil para timeouts de red).
  function abrirNuevaCorrida() {
    corridaIdemKeyRef.current = "corrida-" + Math.random().toString(36).slice(2) + "-" + Date.now().toString(36);
    setForm(formInicial());
    setRegistroError("");
    setNuevo(true);
  }

  function abrirDesdePlanProduccion(plan) {
    if (!plan?.canCreate) {
      setMsg("Esta recomendación no tiene sabor o figura exacta. Revisa el pedido antes de crear la corrida.");
      return;
    }
    const base = formInicial();
    const draft = productionRunDraft(plan, figurasProducibles, s.rellenos[0]);
    corridaIdemKeyRef.current = "corrida-" + Math.random().toString(36).slice(2) + "-" + Date.now().toString(36);
    setForm({ ...base, ...draft, figuras: { ...base.figuras, ...draft.figuras } });
    setRegistroError("");
    setPre({
      id: plan.id, grouped: true, flavor: plan.flavor, filling: plan.filling,
      cantidad: plan.totalUnits, suggestionIds: plan.suggestionIds,
      queueUnits: plan.queueUnits, source: plan.source,
      producto: plan.variants.map((variant) => `${variant.recommended}× ${variant.figure}`).join(" · "),
    });
    setNuevo(true);
  }

  async function registrarCorrida() {
    const figurasElegidas = Object.entries(form.figuras).filter(([, cant]) => +cant > 0).map(([figura, cant]) => ({ figura, cant: +cant }));
    if (!figurasElegidas.length) { setMsg("Elegí al menos una figura con cantidad mayor a 0."); return; }
    const suggestionIds = Array.isArray(pre?.suggestionIds) ? pre.suggestionIds.filter(Boolean) : [];
    const traceNote = suggestionIds.length > 1 ? `Sugerencias agrupadas: ${suggestionIds.join(", ")}` : "";
    const payload = {
      sabor: form.sabor, relleno: form.relleno, figuras: figurasElegidas,
      resp_user_id: respUserId(form.resp), horas_congelacion: +form.horasCongelacion || 10,
      obs: [form.obs, traceNote].filter(Boolean).join(" · "), sugerencia_id: suggestionIds[0] || undefined,
      idempotency_key: corridaIdemKeyRef.current,
    };
    setEnviando(true);
    let resultado;
    try {
      resultado = await crearCorrida(payload);
    } catch (e) {
      const friendlyError = explainOperationalError(e, {
        inventory: db.inventory_items || [],
        subrecipes: db.subrecetas || [],
      });
      setRegistroError(friendlyError);
      toast("error", friendlyError);
      setEnviando(false);
      return;
    }
    const suggestionUpdateFailures = [];
    for (const suggestionId of suggestionIds.slice(1)) {
      try { await setSugerenciaEstado(suggestionId, "Atendida"); }
      catch { suggestionUpdateFailures.push(suggestionId); }
    }
    setRegistroError("");
    setEnviando(false);
    setNuevo(false); setPre(null);
    corridaIdemKeyRef.current = null; // fuerza una key nueva en la próxima apertura (abrirNuevaCorrida)
    toast("ok", `Producción registrada${resultado && resultado.corrida_id ? ` (${resultado.corrida_id})` : ""}`);
    await refrescarSilencioso(() => setMsg("La producción se registró correctamente, pero no se pudo actualizar la vista. Recargá la página para verlo."));
    if (suggestionUpdateFailures.length) {
      setMsg(`La corrida quedó registrada, pero MOMOS OPS no pudo cerrar ${suggestionUpdateFailures.join(", ")}. No crees otro lote: recarga y revisa esas recomendaciones.`);
    }
    const faltantes = resultado && resultado.faltantes;
    if (Array.isArray(faltantes) && faltantes.length) {
      const internos = faltantes.filter((f) => (db.subrecetas || []).some((subrecipe) => subrecipe.itemId === f.item_id));
      const compras = faltantes.filter((f) => !internos.includes(f));
      const acciones = [
        internos.length ? `prepará en Cocina: ${internos.map((f) => `${f.insumo} (faltan ${f.faltan} ${f.unidad})`).join(", ")}` : "",
        compras.length ? `comprá en Inventario: ${compras.map((f) => `${f.insumo} (faltan ${f.faltan} ${f.unidad})`).join(", ")}` : "",
      ].filter(Boolean).join(" · ");
      setMsg(`Producción registrada con faltantes: ${acciones}.`);
    }
  }

  function abrirPrepararBase(requestedSubrecipeId = "", requestedNominal = 1000) {
    const selectedId = typeof requestedSubrecipeId === "string" && subrecetasActivas.some((subrecipe) => subrecipe.id === requestedSubrecipeId)
      ? requestedSubrecipeId
      : (subrecetasActivas[0] ? subrecetasActivas[0].id : "");
    const nominal = +requestedNominal > 0 ? Math.round(+requestedNominal * 10) / 10 : 1000;
    prepIdemKeyRef.current = "subprod-" + Math.random().toString(36).slice(2) + "-" + Date.now().toString(36);
    setPrepForm({ subrecetaId: selectedId, nominal, obtenidos: "", obtenidosTocado: false, resp: "", obs: "" });
    setPrepBase(true);
  }

  async function registrarPreparacion() {
    if (!prepSel) { setMsg("Elegí la base a preparar."); return; }
    if (!(+prepForm.nominal > 0)) { setMsg("Los gramos preparados deben ser mayores a 0."); return; }
    const payload = {
      subreceta_id: prepSel.id,
      gramos_nominales: +prepForm.nominal,
      gramos_obtenidos: +prepObtenidos,
      resp_user_id: respUserId(prepForm.resp),
      obs: prepForm.obs,
      idempotency_key: prepIdemKeyRef.current,
    };
    setEnviandoPrep(true);
    let resultado;
    try {
      resultado = await producirSubreceta(payload);
    } catch (e) {
      toast("error", "No se pudo registrar la preparación: " + e.message);
      setEnviandoPrep(false);
      return;
    }
    setEnviandoPrep(false);
    setPrepBase(false);
    prepIdemKeyRef.current = null; // fuerza key nueva en la próxima apertura
    toast("ok", `${prepSel.nombre} preparado · inventario actualizado`);
    await refrescarSilencioso(() => setMsg("La base se preparó correctamente, pero no se pudo actualizar la vista. Recargá la página para verla."));
    const faltantesPrep = resultado && resultado.faltantes;
    if (Array.isArray(faltantesPrep) && faltantesPrep.length) {
      setMsg(`Base preparada, pero el inventario no alcanzó para: ${faltantesPrep.map((f) => `${f.insumo} (faltan ${f.faltan} ${f.unidad})`).join(", ")}. Registra la compra en Inventario.`);
    }
  }

  // Desmolde diferido: el paso directo a 'Listo' ahora falla en el server sin conteos.
  function abrirDesmolde(l) {
    // Lote MIXTO (plan de 2+ figuras): el server exige conteos POR figura
    // (variantes-v1) — el modal pide el detalle en vez de los 3 totales.
    if ((l.figuras || []).length > 1) {
      setDesmolde({
        batchId: l.id, prod: l.prod,
        figuras: l.figuras.map((f) => ({ figura: f.figura, cant: +f.cant || 0, perfectas: +f.cant || 0, imperfectas: 0, descartadas: 0 })),
      });
      return;
    }
    const cargados = (l.perfectas || 0) + (l.imperfectas || 0) + (l.descartadas || 0);
    setDesmolde(cargados > 0
      ? { batchId: l.id, prod: l.prod, perfectas: l.perfectas, imperfectas: l.imperfectas, descartadas: l.descartadas }
      : { batchId: l.id, prod: l.prod, perfectas: l.prod, imperfectas: 0, descartadas: 0 });
  }

  // Transición a 'Listo': si perfectas+imperfectas+descartadas ya cuadra con prod
  // (lotes viejos ya cuadrados, o re-transiciones post-reversa), el server acepta
  // set_lote_estado directo. Si no cuadra, recién ahí hace falta el modal de desmolde.
  async function marcarListo(l) {
    const cuadra = (l.perfectas || 0) + (l.imperfectas || 0) + (l.descartadas || 0) === l.prod;
    if (!cuadra) { abrirDesmolde(l); return; }
    setEnviandoBatchId(l.id);
    try {
      await setLoteEstado(l.id, "Listo");
    } catch (e) {
      toast("error", "No se pudo cambiar el estado del lote: " + e.message);
      setEnviandoBatchId(null);
      return;
    }
    toast("ok", `${l.id} · listo`);
    await refrescarSilencioso(() => toast("alert", "El estado del lote cambió, pero no se pudo actualizar la vista. Recargá la página."));
    setEnviandoBatchId(null);
  }

  async function confirmarDesmolde() {
    const { batchId, perfectas, imperfectas, descartadas } = desmolde;
    setEnviandoDesmolde(true);
    try {
      if (desmolde.figuras) {
        // Lote mixto: totales = suma del detalle por figura (el server valida la coherencia doble).
        const tot = (k) => desmolde.figuras.reduce((s, f) => s + (+f[k] || 0), 0);
        await desmoldarLote(batchId, tot("perfectas"), tot("imperfectas"), tot("descartadas"),
          desmolde.figuras.map((f) => ({ figura: f.figura, perfectas: +f.perfectas || 0, imperfectas: +f.imperfectas || 0, descartadas: +f.descartadas || 0 })));
      } else {
        await desmoldarLote(batchId, +perfectas || 0, +imperfectas || 0, +descartadas || 0);
      }
    } catch (e) {
      toast("error", "No se pudo registrar el desmolde: " + e.message);
      setEnviandoDesmolde(false);
      return;
    }
    setEnviandoDesmolde(false);
    setDesmolde(null);
    toast("ok", `Lote desmoldado · stock actualizado · vence ${dISO(3)}`);
    await refrescarSilencioso(() => setMsg("El lote se desmoldó correctamente, pero no se pudo actualizar la vista. Recargá la página para verlo."));
  }

  async function iniciarCongelacionLote(lote) {
    setEnviandoBatchId(lote.id);
    try {
      await empezarCongelamiento(lote.id);
    } catch (error) {
      toast("error", "No se pudo empezar el congelamiento: " + error.message);
      setEnviandoBatchId(null);
      return;
    }
    toast("ok", `${lote.id} · congelamiento iniciado`);
    await refrescarSilencioso(() => toast("alert", "El lote empezó a congelar, pero no se pudo actualizar la vista. Recargá la página."));
    setEnviandoBatchId(null);
  }

  async function convertirImperfectasLote(lote) {
    setEnviandoBatchId(lote.id);
    try {
      await convertirImperfectas(lote.id);
    } catch (error) {
      toast("error", "No se pudieron convertir las imperfectas: " + error.message);
      setEnviandoBatchId(null);
      return;
    }
    toast("ok", `${lote.imperfectas} imperfectas del lote ${lote.id} → insumo`);
    await refrescarSilencioso(() => toast("alert", "Las imperfectas se convirtieron, pero no se pudo actualizar la vista. Recargá la página."));
    setEnviandoBatchId(null);
  }

  async function cambiarEstadoLote(lote, nuevoEstado) {
    if (nuevoEstado === "Listo") { await marcarListo(lote); return; }
    setEnviandoBatchId(lote.id);
    try {
      await setLoteEstado(lote.id, nuevoEstado);
    } catch (error) {
      toast("error", "No se pudo cambiar el estado del lote: " + error.message);
      setEnviandoBatchId(null);
      return;
    }
    toast("ok", `${lote.id} → ${nuevoEstado}`);
    await refrescarSilencioso(() => toast("alert", "El estado del lote cambió, pero no se pudo actualizar la vista. Recargá la página."));
    setEnviandoBatchId(null);
  }

  return (
    <div>
      <KitchenProductionQueue
        db={db}
        onOpenOrder={setDetallePedidoCocinaId}
        canStart={puedeIniciarPedidos}
        canReady={puedeEntregarEmpaque}
      />
      {detallePedidoCocina && <KitchenQuickCommand db={db} order={detallePedidoCocina}
        canStart={puedeIniciarPedidos} canReady={puedeEntregarEmpaque} busyOrderId={queueBusyOrderId}
        onStart={(orderId) => cambiarPedidoDesdeCocina(orderId, "En producción")}
        onReady={(orderId) => cambiarPedidoDesdeCocina(orderId, "Listo para empaque")}
        onMomobot={() => { const orderId = detallePedidoCocina.id; setDetallePedidoCocinaId(null); alistarPedidoDesdeCola(orderId); }}
        onClose={() => setDetallePedidoCocinaId(null)} refrescar={refrescar} perfil={perfil} />}
      <VoiceKitchenPanel db={db} perfil={perfil} flavors={sabores} figures={figurasProducibles} subrecipes={subrecetasActivas} refrescar={refrescar} serverDataReady={serverDataReady} requestedOrder={queueRequest} />
      <div className="mb-4 flex gap-2 flex-wrap"><Btn onClick={abrirNuevaCorrida}>＋ Nueva producción</Btn>{subrecetasActivas.length > 0 && <Btn kind="soft" onClick={() => abrirPrepararBase()}>🥣 Preparar elaboración</Btn>}</div>

      <KitchenProductionAssistantFab
        plan={kitchenProductionPlan}
        unplannedSuggestions={unplannedSuggestions}
        formatAmount={cantidadPreparacionTexto}
        onPlanRun={abrirDesdePlanProduccion}
        onPrepare={abrirPrepararBase}
      />

      <SectionTitle>✅ Stock operativo disponible</SectionTitle>
      <div className="text-xs font-semibold mb-2" style={{ color: T.choco2 }}>Fuente oficial usada por ventas y reservas (products.stock). Un lote suma aquí al pasar a "Listo".</div>
      <div className="grid sm:grid-cols-2 lg:grid-cols-3 gap-2 mb-2">
        {stockOperativo.map(([nombre, v, id]) => (
          <Card key={id} className="p-3 flex items-center justify-between gap-2" onClick={() => enfocarLotes({ producto: nombre })}>
            <div className="text-xs font-semibold leading-snug">{nombre}</div>
            <div className="display text-xl shrink-0" style={{ color: v <= 2 ? "#A03B2A" : "#3F6B42" }}>{v}</div>
          </Card>
        ))}
        {stockOperativo.length === 0 && <Empty icon="🍮" text="No hay productos con stock operativo." />}
      </div>

      <SectionTitle>🎯 Disponible por variante (figura + sabor)</SectionTitle>
      <div className="text-xs font-semibold mb-2" style={{ color: T.choco2 }}>Qué figuras exactas hay, por sabor y gramaje, con su vencimiento más próximo. Se llena con cada desmolde por figura (lotes nuevos; los viejos no tienen detalle).</div>
      <div className="grid sm:grid-cols-2 lg:grid-cols-3 gap-2 mb-2">
        {(db.variantes || []).map((v) => (
          <Card key={`${v.productId}·${v.figura}·${v.sabor}·${v.gramajeG}`} className="p-3 flex items-center justify-between gap-2">
            <div className="text-xs font-semibold leading-snug">
              {v.figura} · {v.sabor}
              <div className="text-[10px] mt-0.5 font-semibold" style={{ color: T.choco2 }}>{v.producto}{v.gramajeG != null ? ` · ${v.gramajeG} g` : ""}{v.vence ? ` · vence ${v.vence}` : ""}</div>
            </div>
            <div className="display text-xl shrink-0" style={{ color: v.disponibles > 0 ? "#3F6B42" : "#A03B2A" }}>{v.disponibles}</div>
          </Card>
        ))}
        {(db.variantes || []).length === 0 && <Empty icon="🎯" text="Sin desmoldes por figura todavía — el próximo desmolde llena este panel." />}
      </div>

      {subrecetasActivas.length > 0 && (
        <>
          <SectionTitle>🥣 Elaboraciones internas preparadas</SectionTitle>
          <div className="text-xs font-semibold mb-2" style={{ color: T.choco2 }}>Mousses por sabor, cheesecake, ganache y salsas se elaboran en Cocina: consumen su receta, registran rendimiento y alimentan este stock. Nunca entran como compra.</div>
          <div className="grid sm:grid-cols-2 lg:grid-cols-3 gap-2 mb-2">
            {subrecetasActivas.map((sr) => {
              const it = itemDe[sr.itemId];
              const ult = ultimaPrepDe[sr.id];
              const formulaRows = (db.subreceta_ingredientes || []).filter((row) => row.subrecetaId === sr.id);
              return (
                <Card key={sr.id} aria-label={`Ver receta de ${sr.nombre}`} className="p-3" onClick={() => { setDetalleCantidadFinal(300); setDetallePreparacionId(sr.id); }}>
                  <div className="flex items-center justify-between gap-2">
                    <div className="text-xs font-semibold leading-snug">{sr.nombre}</div>
                    <div className="display text-xl shrink-0" style={{ color: it && it.stock > 0 ? "#3F6B42" : "#A03B2A" }}>{it ? it.stock : "—"}</div>
                  </div>
                  <div className="text-[10px] mt-0.5" style={{ color: T.choco2 }}>
                    {it ? `${it.unidad} · ${fmt(it.costo)}/${it.unidad}` : "sin item de inventario"}{ult ? ` · última: ${ult.creado || ult.fecha}` : ""}
                  </div>
                  <div className="flex items-center justify-between gap-2 mt-2"><span className="text-[10px] font-bold" style={{ color: formulaRows.length ? "#3F6B42" : "#A03B2A" }}>{formulaRows.length ? `${formulaRows.length} insumos en fórmula` : "Sin fórmula cargada"}</span><span className="text-[10px] font-extrabold" style={{ color: T.coral }}>Ver receta ›</span></div>
                </Card>
              );
            })}
          </div>
        </>
      )}

      {detallePreparacion && (
        <Modal title={`Receta · ${detallePreparacion.nombre}`} onClose={() => setDetallePreparacionId(null)} wide>
          <div className="rounded-2xl p-4 mb-3" style={{ background: T.soft, border: `1px solid ${T.border}` }}>
            <div className="flex flex-wrap items-start justify-between gap-3">
              <div><div className="text-[10px] uppercase tracking-[.14em] font-extrabold" style={{ color: T.coral }}>Guía de preparación de cocina</div><div className="display text-xl font-semibold mt-1">{detallePreparacion.nombre}</div><div className="text-xs font-semibold mt-1" style={{ color: T.choco2 }}>Fórmula maestra registrada por cada 1.000 g antes de merma.</div></div>
              <div className="flex flex-wrap gap-2"><span className="text-xs font-bold px-2.5 py-1 rounded-full" style={{ background: T.rosa, color: "#8E4B5A" }}>{detallePreparacion.tipo.replaceAll("_", " ")}</span><span className="text-xs font-bold px-2.5 py-1 rounded-full" style={{ background: detalleFormula.completeFormula ? "#E6F1E3" : "#F6D4CD", color: detalleFormula.completeFormula ? "#3F6B42" : "#A03B2A" }}>{detalleFormula.components.length} insumos</span></div>
            </div>
            <div className="grid sm:grid-cols-[minmax(0,1fr)_220px] gap-3 items-end mt-4">
              <div><label className="text-[10px] uppercase tracking-wider font-extrabold" style={{ color: T.choco2 }}>Cantidad final que Cocina necesita</label><div className="text-xs mt-1" style={{ color: T.choco2 }}>Ejemplo: 300 g de cheesecake ya terminado y utilizable.</div></div>
              <div className="relative"><input type="number" min="1" step="10" value={detalleCantidadFinal} onChange={(event) => setDetalleCantidadFinal(Math.max(0, +event.target.value || 0))} aria-label="Cantidad final deseada en gramos" className="w-full rounded-xl border px-3 py-2.5 pr-10 text-lg font-bold outline-none" style={inputStyle} /><span className="absolute right-3 top-3 text-xs font-extrabold" style={{ color: T.choco2 }}>g</span></div>
            </div>
          </div>

          <div className="grid grid-cols-2 sm:grid-cols-4 gap-2 mb-3">
            {[["Resultado deseado", `${detalleFormula.desiredOutputGrams} g`, T.coral], ["Preparar antes de merma", `${detalleFormula.nominalInputGrams} g`, "#63518A"], ["Merma prevista", `${detalleFormula.wastePct}%`, "#96690F"], ["Costo estimado", fmt(detalleFormula.totalCost), "#3F6B42"]].map(([label, value, color]) => <div key={label} className="rounded-2xl p-3" style={{ background: T.surface, border: `1px solid ${T.border}` }}><div className="text-[10px] uppercase font-extrabold" style={{ color: T.choco2 }}>{label}</div><div className="display text-xl mt-1" style={{ color }}>{value}</div></div>)}
          </div>

          <div className="rounded-2xl overflow-hidden" style={{ background: T.surface, border: `1px solid ${T.border}` }}>
            <div className="flex items-center justify-between gap-3 px-4 py-3" style={{ background: T.vainilla }}><div><div className="text-[10px] uppercase tracking-[.12em] font-extrabold" style={{ color: T.choco2 }}>Ingredientes escalados</div><div className="font-bold text-sm mt-0.5">Cantidades para lograr {detalleFormula.desiredOutputGrams} g finales</div></div><Badge label={detalleFormula.canPrepare ? "Stock suficiente" : "Revisar stock"} map={{ "Stock suficiente": { bg: "#E6F1E3", fg: "#3F6B42" }, "Revisar stock": { bg: "#FBE8C8", fg: "#96690F" } }} /></div>
            {detalleFormula.components.map((component) => (
              <div key={component.itemId} className="grid sm:grid-cols-[minmax(0,1fr)_120px_170px] gap-2 items-center px-4 py-3 border-t" style={{ borderColor: T.border }}>
                <div className="min-w-0"><div className="font-bold text-sm truncate">{component.name}</div><div className="text-[10px] font-semibold mt-0.5" style={{ color: T.choco2 }}>Fórmula base: {cantidadPreparacionTexto(component.unit, component.baseQuantity)} por 1.000 g</div></div>
                <div className="sm:text-right"><div className="display text-lg" style={{ color: T.coral }}>{cantidadPreparacionTexto(component.unit, component.requiredQuantity)}</div><div className="text-[9px] uppercase font-extrabold" style={{ color: T.choco2 }}>usar ahora</div></div>
                <div className="sm:text-right"><span className="inline-block text-[10px] font-extrabold px-2 py-1 rounded-full" style={{ background: component.enough ? "#E6F1E3" : "#F6D4CD", color: component.enough ? "#3F6B42" : "#A03B2A" }}>{component.enough ? "✓" : "✕"} Disponible {cantidadPreparacionTexto(component.unit, component.stock)}</span></div>
              </div>
            ))}
            {!detalleFormula.hasFormula && <div className="p-4 text-sm font-bold" style={{ color: "#A03B2A" }}>Esta preparación todavía no tiene ingredientes asociados. No se puede calcular ni registrar de forma segura.</div>}
          </div>

          {!detalleFormula.canPrepare && detalleFormula.completeFormula && <div className="rounded-xl px-3 py-2.5 mt-3 text-xs font-bold" style={{ background: "#FBE8C8", color: "#96690F" }}>La receta está completa, pero uno o más insumos no alcanzan. Podés abrir el registro para planear la tanda; MOMOS OPS dejará trazado el faltante.</div>}
          <div className="flex flex-wrap justify-end gap-2 mt-4"><Btn kind="ghost" onClick={() => setDetallePreparacionId(null)}>Cerrar</Btn><Btn disabled={!detalleFormula.completeFormula || detalleFormula.desiredOutputGrams <= 0} onClick={() => { const subrecipeId = detallePreparacion.id; const nominal = detalleFormula.nominalInputGrams; setDetallePreparacionId(null); abrirPrepararBase(subrecipeId, nominal); }}>🥣 Preparar esta cantidad</Btn></div>
        </Modal>
      )}

      <SectionTitle>🧊 Lotes en proceso (aún no disponibles)</SectionTitle>
      <div className="text-xs font-semibold mb-2" style={{ color: T.choco2 }}>Congelando o en preparación. No suman al stock operativo hasta pasar a "Listo".</div>
      <div className="grid sm:grid-cols-2 lg:grid-cols-3 gap-2 mb-2">
        {enProceso.map((e) => (
          <Card key={e.label} className="p-3 flex items-center justify-between gap-2" onClick={() => enfocarLotes({ combo: true, producto: e.producto, sabor: e.sabor, figura: e.figura, gramaje: e.gramaje })}>
            <div className="text-xs font-semibold leading-snug">{e.label}</div>
            <div className="display text-xl shrink-0" style={{ color: "#63518A" }}>{e.cant}</div>
          </Card>
        ))}
        {enProceso.length === 0 && <Empty icon="🧊" text="No hay lotes en proceso." />}
      </div>

      <div id="lotes-produccion" />
      <SectionTitle action={<div className="flex flex-wrap items-center justify-end gap-2">{foco && <button type="button" onClick={() => setFoco(null)} className="text-xs font-bold" style={{ color: T.coral }}>✕ Quitar filtro</button>}<WorkScopeTabs value={scope} onChange={(next) => { setScope(next); setFoco(null); }} activeCount={batchBuckets.active.length} historyCount={batchBuckets.history.length} activeLabel="En proceso" /></div>}>{scope === "active" ? "Lotes en proceso" : "Historial de lotes"}</SectionTitle>
      {foco && <div className="text-xs font-bold mb-3 p-2 rounded-lg" style={{ background: T.vainilla, color: T.choco2 }}>Mostrando lotes de: {focoLabel} ({lotesFiltrados.length})</div>}
      <div className="grid sm:grid-cols-2 xl:grid-cols-3 gap-3">
        {lotesFiltrados.map((l) => {
          const cong = estadoCongelacion(l);
          const figuras = Array.isArray(l.figuras) && l.figuras.length ? l.figuras.map((f) => `${f.cant}× ${f.figura}`).join(" · ") : l.figura;
          return (
            <Card key={l.id} aria-label={`Abrir detalle del lote ${l.id}`} className="momo-queue-item p-4" onClick={() => setDetalleLoteId(l.id)}>
              <div className="flex items-start justify-between gap-3">
                <div className="min-w-0">
                  <div className="text-[10px] uppercase tracking-[.12em] font-extrabold" style={{ color: T.choco2 }}>Lote {l.id}</div>
                  <div className="font-bold text-sm mt-1 truncate">{l.producto}</div>
                </div>
                <Badge label={l.estado} />
              </div>
              <div className="flex items-end justify-between gap-3 mt-3">
                <div className="min-w-0">
                  <div className="text-xs font-semibold truncate" style={{ color: T.choco2 }}>{figuras || "Sin figura"} · {l.sabor || "Sin sabor"}</div>
                  <div className="text-[10px] font-semibold mt-1" style={{ color: T.choco2 }}>{l.fecha} · {l.resp || "Sin responsable"}</div>
                </div>
                <div className="text-right shrink-0"><div className="display text-2xl leading-none" style={{ color: T.coral }}>{l.prod || 0}</div><div className="text-[9px] uppercase font-extrabold" style={{ color: T.choco2 }}>unidades</div></div>
              </div>
              {cong && (
                <div className="rounded-2xl p-3 mt-3" style={{ background: cong.listo ? "#E6F1E3" : "#E7EEF6", color: cong.listo ? "#3F6B42" : "#365E87" }}>
                  <div className="flex items-center justify-between gap-3 text-xs font-extrabold"><span>{cong.listo ? "✓ Congelación cumplida" : "❄ Congelando"}</span><span>{fmtHoras(cong.horas)}</span></div>
                  <div className="h-1.5 rounded-full overflow-hidden mt-2" style={{ background: "rgba(255,255,255,.72)" }}><div className="h-full rounded-full" style={{ width: `${Math.min(100, (cong.horas / Math.max(cong.objetivo, 1)) * 100)}%`, background: cong.listo ? "#5E9162" : "#5B82AA" }} /></div>
                  <div className="text-[10px] font-bold mt-1.5">{cong.listo ? `Objetivo ${cong.objetivo} h · listo para desmolde` : `faltan ~${fmtHoras(cong.restan)} de ${cong.objetivo} h`}</div>
                </div>
              )}
              {!cong && <div className="rounded-xl px-3 py-2 mt-3 text-xs font-bold" style={{ background: T.vainilla, color: T.choco2 }}>{l.estado === "En preparación" ? "Pendiente de iniciar congelación" : `Resultado: ${l.perfectas || 0} perfectas`}</div>}
              <div className="text-[11px] font-extrabold mt-3" style={{ color: T.coral }}>Ver información y acciones ›</div>
            </Card>
          );
        })}
        {lotesFiltrados.length === 0 && <div className="text-sm font-semibold p-3 rounded-xl" style={{ background: T.vainilla, color: T.choco2 }}>{scope === "active" ? "No hay lotes activos para este filtro." : "Todavía no hay lotes en el historial para este filtro."}</div>}
      </div>

      {detalleLote && (
        <Modal title={`Lote ${detalleLote.id}`} onClose={() => setDetalleLoteId(null)} wide>
          <div className="flex flex-wrap items-start justify-between gap-3 rounded-2xl p-4 mb-3" style={{ background: T.soft, border: `1px solid ${T.border}` }}>
            <div><div className="text-[10px] uppercase tracking-[.14em] font-extrabold" style={{ color: T.coral }}>Trazabilidad de producción</div><div className="display text-xl font-semibold mt-1">{detalleLote.producto}</div><div className="text-xs font-semibold mt-1" style={{ color: T.choco2 }}>{detalleLote.fecha} · Responsable: {detalleLote.resp || "Sin asignar"}</div></div>
            <div className="flex gap-2 flex-wrap"><Badge label={detalleLote.estado} />{detalleLote.corridaId && <span className="text-xs font-bold px-2.5 py-1 rounded-full" style={{ background: T.vainilla, color: "#63518A" }}>Corrida {detalleLote.corridaId}</span>}</div>
          </div>

          <div className="grid grid-cols-2 sm:grid-cols-4 gap-2 mb-3">
            {[["Producidas", detalleLote.prod || 0, T.coral], ["Perfectas", detalleLote.perfectas || 0, "#3F6B42"], ["Imperfectas", detalleLote.imperfectas || 0, "#96690F"], ["Descartadas", detalleLote.descartadas || 0, "#A03B2A"]].map(([label, value, color]) => <div key={label} className="rounded-2xl p-3" style={{ background: T.surface, border: `1px solid ${T.border}` }}><div className="text-[10px] uppercase font-extrabold" style={{ color: T.choco2 }}>{label}</div><div className="display text-2xl mt-1" style={{ color }}>{value}</div></div>)}
          </div>

          <div className="grid lg:grid-cols-2 gap-3">
            <div className="rounded-2xl p-4" style={{ background: T.surface, border: `1px solid ${T.border}` }}>
              <div className="text-[10px] uppercase tracking-[.12em] font-extrabold mb-3" style={{ color: T.choco2 }}>Composición del lote</div>
              <div className="space-y-2 text-sm">
                <div className="flex justify-between gap-3"><span style={{ color: T.choco2 }}>Figuras</span><b className="text-right">{Array.isArray(detalleLote.figuras) && detalleLote.figuras.length ? detalleLote.figuras.map((f) => `${f.cant}× ${f.figura}`).join(" · ") : (detalleLote.figura || "—")}</b></div>
                <div className="flex justify-between gap-3"><span style={{ color: T.choco2 }}>Sabor</span><b>{detalleLote.sabor || "—"}</b></div>
                <div className="flex justify-between gap-3"><span style={{ color: T.choco2 }}>Relleno</span><b className="text-right">{detalleLote.relleno || "—"}</b></div>
                {detalleLote.salsa && <div className="flex justify-between gap-3"><span style={{ color: T.choco2 }}>Salsa</span><b>{detalleLote.salsa}</b></div>}
                <div className="flex justify-between gap-3"><span style={{ color: T.choco2 }}>Gramaje</span><b>{detalleLote.gramaje || "—"}</b></div>
                {(detalleLote.molde || detalleLote.ubicacion) && <div className="flex justify-between gap-3"><span style={{ color: T.choco2 }}>Molde / ubicación</span><b className="text-right">{[detalleLote.molde, detalleLote.ubicacion].filter(Boolean).join(" · ")}</b></div>}
              </div>
            </div>

            <div className="rounded-2xl p-4" style={{ background: detalleCongelacion ? (detalleCongelacion.listo ? "#E6F1E3" : "#E7EEF6") : T.surface, border: `1px solid ${detalleCongelacion ? (detalleCongelacion.listo ? "#B8D2B2" : "#B8CADE") : T.border}` }}>
              <div className="text-[10px] uppercase tracking-[.12em] font-extrabold" style={{ color: detalleCongelacion?.listo ? "#3F6B42" : "#365E87" }}>Cronómetro de congelación</div>
              {detalleCongelacion ? <><div className="flex items-end justify-between gap-3 mt-2"><div><div className="display text-3xl" style={{ color: detalleCongelacion.listo ? "#3F6B42" : "#365E87" }}>{fmtHoras(detalleCongelacion.horas)}</div><div className="text-xs font-bold mt-1">transcurridas</div></div><div className="text-right text-xs font-bold">Objetivo {detalleCongelacion.objetivo} h<br />{detalleCongelacion.listo ? "Tiempo cumplido" : `Faltan ~${fmtHoras(detalleCongelacion.restan)}`}</div></div><div className="h-2 rounded-full overflow-hidden mt-3" style={{ background: "rgba(255,255,255,.7)" }}><div className="h-full rounded-full" style={{ width: `${Math.min(100, (detalleCongelacion.horas / Math.max(detalleCongelacion.objetivo, 1)) * 100)}%`, background: detalleCongelacion.listo ? "#5E9162" : "#5B82AA" }} /></div><div className="text-xs font-semibold mt-2">Inicio: {detalleLote.inicioCongelacion}</div></> : <div className="text-sm font-semibold mt-3" style={{ color: T.choco2 }}>{detalleLote.estado === "En preparación" ? "El cronómetro todavía no ha iniciado." : "Este lote ya no tiene un cronómetro activo."}</div>}
            </div>

            <div className="rounded-2xl p-4" style={{ background: T.surface, border: `1px solid ${T.border}` }}>
              <div className="text-[10px] uppercase tracking-[.12em] font-extrabold mb-3" style={{ color: T.choco2 }}>Calidad y destino</div>
              <div className="text-sm space-y-2"><div className="flex justify-between gap-3"><span style={{ color: T.choco2 }}>Merma</span><b style={{ color: detalleMerma > 0.15 ? "#A03B2A" : "#3F6B42" }}>{pct(detalleMerma)}{detalleMerma > 0.15 ? " · revisar" : ""}</b></div><div className="flex justify-between gap-3"><span style={{ color: T.choco2 }}>Destino imperfectas</span><b className="text-right">{detalleLote.destino && detalleLote.destino !== "—" ? detalleLote.destino : "Pendiente"}</b></div><div className="flex justify-between gap-3"><span style={{ color: T.choco2 }}>Stock contabilizado</span><b>{detalleLote.stockContabilizado ? "Sí" : "No"}</b></div></div>
            </div>

            <div className="rounded-2xl p-4" style={{ background: T.surface, border: `1px solid ${T.border}` }}>
              <div className="text-[10px] uppercase tracking-[.12em] font-extrabold mb-3" style={{ color: T.choco2 }}>Vencimiento y observaciones</div>
              <div className="text-sm font-bold">{!isActiveProductionBatch(detalleLote) && detalleLote.vence ? `Vence ${detalleLote.vence} · 3 días desde desmolde` : "Vence 3 días después del desmolde"}</div>
              <div className="text-xs mt-3" style={{ color: T.choco2 }}>{detalleLote.obs ? `📝 ${detalleLote.obs}` : "Sin observaciones registradas."}</div>
            </div>
          </div>

          {isActiveProductionBatch(detalleLote) && <div className="flex flex-wrap items-center justify-end gap-2 mt-4 pt-4 border-t" style={{ borderColor: T.border }}>
            {detalleLote.estado === "En preparación" && <BtnAsync small confirmar="❄️ ¿Empezar? Tocá de nuevo" textoEnVuelo="Empezando…" disabled={enviandoBatchId === detalleLote.id} onClick={() => iniciarCongelacionLote(detalleLote)}>❄️ Empezar congelación</BtnAsync>}
            {detalleCongelacion?.listo && <BtnAsync small textoEnVuelo="Listando…" disabled={enviandoBatchId === detalleLote.id} onClick={() => marcarListo(detalleLote)}>Desmoldar y marcar listo</BtnAsync>}
            {detalleLote.imperfectas > 0 && !String(detalleLote.destino).includes("Insumo") && <BtnAsync small kind="soft" confirmar="♻️ ¿Convertir a insumo? Tocá de nuevo" textoEnVuelo="Convirtiendo…" disabled={enviandoBatchId === detalleLote.id} onClick={() => convertirImperfectasLote(detalleLote)}>♻️ Convertir imperfectas</BtnAsync>}
            <MiniSelect options={LOTE_ESTADOS} value={detalleLote.estado} disabled={enviandoBatchId === detalleLote.id} onChange={(event) => cambiarEstadoLote(detalleLote, event.target.value)} />
          </div>}
        </Modal>
      )}

      {nuevo && (() => {
        const totalUnidades = Object.values(form.figuras).reduce((s, c) => s + (+c || 0), 0);
        // Espejo del server: crear_corrida agrupa lotes por (producto, gramaje_g)
        const porLote = {};
        Object.entries(form.figuras).forEach(([figura, cant]) => {
          if (!(+cant > 0)) return;
          const p = productoDeFigura[figura];
          const f = figurasProducibles.find((x) => x.nombre === figura);
          const etiqueta = (p ? p.nombre : figura) + (f?.gramajeG != null ? ` (${f.gramajeG} g)` : "");
          porLote[etiqueta] = (porLote[etiqueta] || 0) + (+cant);
        });
        return (
          <Modal title={pre?.grouped ? `Plan de Cocina · ${pre.flavor}` : "Registrar producción"} onClose={() => { setNuevo(false); setPre(null); setRegistroError(""); }} wide>
            {pre?.grouped && <div className="mb-3 px-3 py-3 rounded-xl text-xs font-bold" style={{ background: "#DDEBD9", color: "#315D36" }}>
              <div className="text-[10px] uppercase tracking-[.12em] font-extrabold">🧠 Corrida agrupada y trazable</div>
              <div className="mt-1">{pre.cantidad} unidades de {pre.flavor}: {pre.producto}.</div>
              <div className="text-[10px] mt-1 opacity-80">{pre.queueUnits > 0 ? `${pre.queueUnits} vienen de la cola pagada` : "Cobertura sugerida por demanda"}{pre.suggestionIds.length > 1 ? ` · cerrará ${pre.suggestionIds.length} recomendaciones juntas` : ""}.</div>
            </div>}
            <div className="grid sm:grid-cols-2 gap-x-4">
              <Field label="Sabor"><Select options={sabores} value={form.sabor} onChange={(e) => setForm({ ...form, sabor: e.target.value })} /></Field>
              <Field label="Relleno"><Select options={s.rellenos} value={form.relleno} onChange={(e) => setForm({ ...form, relleno: e.target.value })} /></Field>
              {/* Salsa NO va acá: se aplica al despacho y la elige el cliente (NuevoPedido) */}
            </div>

            <div className="text-xs font-bold mb-1.5" style={{ color: T.choco2 }}>Cantidad por figura</div>
            <div className="grid sm:grid-cols-2 gap-2 mb-3">
              {figurasProducibles.map((f) => (
                <div key={f.nombre} className="flex items-center justify-between gap-2 p-2.5 rounded-xl" style={{ background: T.vainilla }}>
                  <div className="text-xs font-semibold leading-snug">
                    {f.especie === "perro" ? "🐶" : "🐱"} {f.nombre}
                    <div className="text-[10px] font-normal" style={{ color: T.choco2 }}>{f.gramajeG != null ? `${f.gramajeG} g` : ""}</div>
                  </div>
                  <div className="flex items-center gap-1.5 shrink-0">
                    <button type="button" onClick={() => setForm({ ...form, figuras: { ...form.figuras, [f.nombre]: Math.max(0, (+form.figuras[f.nombre] || 0) - 1) } })} className="w-7 h-7 rounded-full font-bold" style={{ background: "#fff", border: "1px solid " + T.border, color: T.choco }}>−</button>
                    <input type="number" min="0" step="1" value={form.figuras[f.nombre] ?? 0} onChange={(e) => setForm({ ...form, figuras: { ...form.figuras, [f.nombre]: Math.max(0, parseInt(e.target.value, 10) || 0) } })} className="w-12 text-center rounded-lg px-1 py-1 text-sm border" style={inputStyle} />
                    <button type="button" onClick={() => setForm({ ...form, figuras: { ...form.figuras, [f.nombre]: (+form.figuras[f.nombre] || 0) + 1 } })} className="w-7 h-7 rounded-full font-bold" style={{ background: "#fff", border: "1px solid " + T.border, color: T.choco }}>+</button>
                  </div>
                </div>
              ))}
              {figurasProducibles.length === 0 && <Empty icon="🧊" text="No hay figuras activas con producto asignado." />}
            </div>

            <div className="text-xs font-semibold mb-3 p-2.5 rounded-xl" style={{ background: T.vainilla, color: T.choco2 }}>
              Total: <b>{totalUnidades}</b> unidades{Object.keys(porLote).length > 0 && (" · " + Object.entries(porLote).map(([etiqueta, cant]) => `${cant}× ${etiqueta}`).join(" · "))}
              <div className="mt-0.5 text-[10px]">Solo informativo — el server calcula los lotes reales al registrar.</div>
            </div>

            <div className="grid sm:grid-cols-2 gap-x-4">
              <Field label="Responsable"><Select options={db.users.filter((u) => u.activo).map((u) => u.nombre)} value={form.resp} onChange={(e) => setForm({ ...form, resp: e.target.value })} placeholder="Sin responsable" /></Field>
              <Field label="Horas de congelación objetivo"><Input type="number" min="1" step="1" value={form.horasCongelacion} onChange={(e) => setForm({ ...form, horasCongelacion: +e.target.value })} /></Field>
            </div>
            <div className="rounded-xl px-3 py-2.5 mb-3 text-xs font-semibold" style={{ background: "#E8F1E5", color: "#315D36", border: "1px solid #C9DDC4" }}>
              🗓️ El vencimiento no se digita: empieza al confirmar el desmolde y queda sellado automáticamente por 3 días.
            </div>
            <Field label="Observaciones"><Input value={form.obs} onChange={(e) => setForm({ ...form, obs: e.target.value })} /></Field>
            <div className="text-xs font-semibold mb-3" style={{ color: T.choco2 }}>Al registrar: se descuentan los insumos de la receta (por la cantidad producida) y se crea un lote por cada figura elegida. Las piezas perfectas se suman al stock cuando cada lote pase a "Listo" (con desmolde).</div>
            {registroError && <div role="alert" className="rounded-2xl border px-4 py-3 mb-3" style={{ background: "#FFF2EF", borderColor: "#E8B7AD", color: "#8F3528" }}>
              <div className="text-[10px] uppercase tracking-[.12em] font-extrabold">⚠ Stock insuficiente</div>
              <div className="text-sm font-bold mt-1">{registroError}</div>
            </div>}
            <div className="flex gap-2">
              <BtnAsync textoEnVuelo="Registrando…" disabled={enviando || totalUnidades === 0} onClick={registrarCorrida}>Registrar producción</BtnAsync>
              <Btn kind="ghost" disabled={enviando} onClick={() => { setNuevo(false); setPre(null); setRegistroError(""); }}>Cancelar</Btn>
            </div>
          </Modal>
        );
      })()}

      {prepBase && (
        <Modal title="🥣 Preparar elaboración interna" onClose={() => setPrepBase(false)} wide>
          <div className="grid sm:grid-cols-2 gap-x-4">
            <Field label="Base a preparar">
              <select value={prepForm.subrecetaId} onChange={(e) => setPrepForm({ ...prepForm, subrecetaId: e.target.value, obtenidos: "", obtenidosTocado: false })} className="w-full rounded-lg px-2 py-2 text-sm border" style={inputStyle}>
                {PREP_TIPOS.map(([tipo, label]) => {
                  const grupo = subrecetasActivas.filter((sr) => sr.tipo === tipo);
                  return grupo.length ? (
                    <optgroup key={tipo} label={label}>
                      {grupo.map((sr) => <option key={sr.id} value={sr.id}>{sr.nombre}</option>)}
                    </optgroup>
                  ) : null;
                })}
              </select>
            </Field>
            <Field label="Responsable"><Select options={db.users.filter((u) => u.activo).map((u) => u.nombre)} value={prepForm.resp} onChange={(e) => setPrepForm({ ...prepForm, resp: e.target.value })} placeholder="Sin responsable" /></Field>
            <Field label="Gramos preparados (nominal)"><Input type="number" min="1" step="50" value={prepForm.nominal} onChange={(e) => setPrepForm({ ...prepForm, nominal: Math.max(0, +e.target.value || 0), obtenidos: "", obtenidosTocado: false })} /></Field>
            <Field label={`Gramos obtenidos (sugerido ${prepObtenidosDefault} · merma ${prepSel ? prepSel.mermaPct : 0}%)`}><Input type="number" min="0" value={prepObtenidos} onChange={(e) => setPrepForm({ ...prepForm, obtenidos: e.target.value, obtenidosTocado: true })} /></Field>
          </div>
          <Field label="Observaciones"><Input value={prepForm.obs} onChange={(e) => setPrepForm({ ...prepForm, obs: e.target.value })} /></Field>
          {prepSel && (
            <>
              <div className="text-xs font-bold mb-1.5" style={{ color: T.choco2 }}>Ingredientes a consumir ({+prepForm.nominal || 0} g de {prepSel.nombre})</div>
              <div className="mb-3 rounded-xl p-2.5 text-xs" style={{ background: T.vainilla }}>
                {prepIngredientes.map((x) => (
                  <div key={x.itemId} className="flex justify-between gap-2 py-0.5">
                    <span>{x.nombre}</span>
                    <span className="font-semibold" style={{ color: x.alcanza ? T.choco : "#A03B2A" }}>{x.reqTxt}{x.alcanza ? "" : " · ⚠ falta stock"}</span>
                  </div>
                ))}
                {prepIngredientes.length === 0 && <div>Esta base no tiene receta cargada.</div>}
                <div className="flex justify-between gap-2 pt-1.5 mt-1.5 font-bold" style={{ borderTop: "1px solid " + T.border }}>
                  <span>Costo estimado del batch</span><span>{fmt(Math.round(prepCosto))}</span>
                </div>
              </div>
            </>
          )}
          <div className="text-xs font-semibold mb-3" style={{ color: T.choco2 }}>Al registrar: se descuentan los ingredientes por los gramos nominales, y los gramos obtenidos suman al stock de la base con su costo real (WAC). Los faltantes no bloquean: quedan avisados.</div>
          <div className="flex gap-2">
            <BtnAsync textoEnVuelo="Registrando…" disabled={enviandoPrep || !prepSel || !(+prepForm.nominal > 0)} onClick={registrarPreparacion}>Registrar preparación</BtnAsync>
            <Btn kind="ghost" disabled={enviandoPrep} onClick={() => setPrepBase(false)}>Cancelar</Btn>
          </div>
        </Modal>
      )}

      {desmolde && (() => {
        // Lote MIXTO: conteos por figura — cada figura debe cuadrar completa
        // contra su cant del plan (mismo guard que valida el server).
        if (desmolde.figuras) {
          const filaCuadra = (f) => (+f.perfectas || 0) + (+f.imperfectas || 0) + (+f.descartadas || 0) === f.cant;
          const cuadraTodo = desmolde.figuras.every(filaCuadra);
          const setFig = (i, k, v) => setDesmolde({
            ...desmolde,
            figuras: desmolde.figuras.map((f, j) => (j === i ? { ...f, [k]: Math.max(0, parseInt(v, 10) || 0) } : f)),
          });
          return (
            <Modal title={`Desmolde ${desmolde.batchId} · lote mixto`} onClose={() => setDesmolde(null)}>
              <div className="text-sm font-semibold mb-2" style={{ color: T.choco2 }}>Producidas: {desmolde.prod} · este lote combina {desmolde.figuras.length} figuras — contá cada una por separado.</div>
              <div className="text-xs font-bold mb-3 rounded-xl px-3 py-2" style={{ background: "#E8F1E5", color: "#315D36" }}>Al confirmar, el producto terminado vencerá el {dISO(3)}.</div>
              {desmolde.figuras.map((f, i) => (
                <div key={f.figura} className="mb-2 rounded-xl p-2.5" style={{ background: T.vainilla }}>
                  <div className="text-xs font-bold mb-1.5" style={{ color: filaCuadra(f) ? T.choco2 : "#A03B2A" }}>{f.figura} · {f.cant} producidas{filaCuadra(f) ? "" : ` — la suma debe dar ${f.cant}`}</div>
                  <div className="grid grid-cols-3 gap-x-3">
                    <Field label="Perfectas"><Input type="number" min="0" value={f.perfectas} onChange={(e) => setFig(i, "perfectas", e.target.value)} /></Field>
                    <Field label="Imperfectas"><Input type="number" min="0" value={f.imperfectas} onChange={(e) => setFig(i, "imperfectas", e.target.value)} /></Field>
                    <Field label="Descartadas"><Input type="number" min="0" value={f.descartadas} onChange={(e) => setFig(i, "descartadas", e.target.value)} /></Field>
                  </div>
                </div>
              ))}
              <div className="flex gap-2 mt-3">
                <BtnAsync confirmar="¿Desmoldar? Tocá de nuevo" textoEnVuelo="Desmoldando…" disabled={enviandoDesmolde || !cuadraTodo} onClick={confirmarDesmolde}>Confirmar</BtnAsync>
                <Btn kind="ghost" disabled={enviandoDesmolde} onClick={() => setDesmolde(null)}>Cancelar</Btn>
              </div>
            </Modal>
          );
        }
        const suma = (+desmolde.perfectas || 0) + (+desmolde.imperfectas || 0) + (+desmolde.descartadas || 0);
        const cuadra = suma === desmolde.prod;
        return (
          <Modal title={`Desmolde ${desmolde.batchId}`} onClose={() => setDesmolde(null)}>
            <div className="text-sm font-semibold mb-2" style={{ color: T.choco2 }}>Producidas: {desmolde.prod}</div>
            <div className="text-xs font-bold mb-3 rounded-xl px-3 py-2" style={{ background: "#E8F1E5", color: "#315D36" }}>Al confirmar, el producto terminado vencerá el {dISO(3)}.</div>
            <div className="grid sm:grid-cols-3 gap-x-3">
              <Field label="Perfectas"><Input type="number" min="0" value={desmolde.perfectas} onChange={(e) => setDesmolde({ ...desmolde, perfectas: Math.max(0, parseInt(e.target.value, 10) || 0) })} /></Field>
              <Field label="Imperfectas"><Input type="number" min="0" value={desmolde.imperfectas} onChange={(e) => setDesmolde({ ...desmolde, imperfectas: Math.max(0, parseInt(e.target.value, 10) || 0) })} /></Field>
              <Field label="Descartadas"><Input type="number" min="0" value={desmolde.descartadas} onChange={(e) => setDesmolde({ ...desmolde, descartadas: Math.max(0, parseInt(e.target.value, 10) || 0) })} /></Field>
            </div>
            {!cuadra && <div className="text-xs font-bold mb-3" style={{ color: "#A03B2A" }}>La suma ({suma}) debe ser igual a las producidas ({desmolde.prod}).</div>}
            <div className="flex gap-2">
              <BtnAsync confirmar="¿Desmoldar? Tocá de nuevo" textoEnVuelo="Desmoldando…" disabled={enviandoDesmolde || !cuadra} onClick={confirmarDesmolde}>Confirmar</BtnAsync>
              <Btn kind="ghost" disabled={enviandoDesmolde} onClick={() => setDesmolde(null)}>Cancelar</Btn>
            </div>
          </Modal>
        );
      })()}


      {msg && <Modal title="Aviso de producción" onClose={() => setMsg("")}><p className="text-sm m-0">{msg}</p><div className="mt-4"><Btn onClick={() => setMsg("")}>Listo</Btn></div></Modal>}
    </div>
  );
}

/* ================= INVENTARIO TERMINADO ================= */

function InventarioTerminado({ db, go }) {
  const [tab, setTab] = useState("Figuras");
  const [detalleProductoId, setDetalleProductoId] = useState(null);
  const [detalleFiguraNombre, setDetalleFiguraNombre] = useState(null);
  const inventory = useMemo(() => buildFinishedInventory(db), [db]);
  const orderById = useMemo(() => Object.fromEntries((db.orders || []).map((order) => [order.id, order])), [db.orders]);
  const detalleProducto = detalleProductoId ? inventory.products.find((product) => product.id === detalleProductoId) : null;
  const detalleVariantes = detalleProducto ? inventory.variants.filter((variant) => variant.productId === detalleProducto.id) : [];
  const detalleCuarentena = detalleProducto ? inventory.quarantinedVariants.filter((variant) => variant.productId === detalleProducto.id) : [];
  const detalleReservas = detalleProducto ? inventory.reservations.filter((reservation) => reservation.refId === detalleProducto.id || reservation.nombre === detalleProducto.nombre) : [];
  const detalleEnProceso = detalleProducto ? inventory.inProcess.filter((batch) => batch.producto === detalleProducto.nombre) : [];
  const detalleImperfectas = detalleProducto ? inventory.imperfects.filter((batch) => batch.producto === detalleProducto.nombre) : [];
  const detalleFigura = detalleFiguraNombre ? inventory.figureSummaries.find((figure) => figure.figura === detalleFiguraNombre) : null;
  const tabs = [
    ["Figuras", inventory.figureSummaries.length],
    ["Disponibles", inventory.summary.available],
    ["Reservadas", inventory.summary.reserved],
    ["En proceso", inventory.summary.inProcess],
    ["Imperfectas", inventory.summary.imperfectTotal],
  ];
  const exactCoverage = inventory.summary.available > 0
    ? Math.round(inventory.summary.exactAvailable / inventory.summary.available * 100)
    : 0;

  const metrics = [
    { icon: "✓", label: "Disponibles para vender", value: inventory.summary.available, note: inventory.summary.quarantined > 0 ? `stock seguro · ${inventory.summary.quarantined} en cuarentena` : "stock oficial, después de reservas", color: T.coral, wash: "rgba(63,107,66,.12)", iconBg: "#E3EFE0" },
    { icon: "🏷", label: "Reservadas", value: inventory.summary.reserved, note: "separadas para pedidos pagos", color: "#63518A", wash: "rgba(99,81,138,.12)", iconBg: "#E8E0F2" },
    { icon: "❄", label: "En proceso", value: inventory.summary.inProcess, note: "todavía no se pueden vender", color: T.choco, wash: "rgba(62,92,126,.12)", iconBg: "#DCE7F2" },
    { icon: "🥤", label: "Para malteadas", value: inventory.summary.imperfectForShakes, note: "imperfectas con ese destino", color: "#8A4D7A", wash: "rgba(138,77,122,.12)", iconBg: "#F1DFEB" },
    { icon: "♻", label: "Imperfectas pendientes", value: inventory.summary.imperfectPending, note: `${inventory.summary.imperfectReused} ya tienen destino`, color: "#96690F", wash: "rgba(150,105,15,.12)", iconBg: "#FBE8C8" },
  ];

  return (
    <div>
      <SectionTitle>Inventario terminado</SectionTitle>
      <div className="text-xs font-semibold mb-3 -mt-3" style={{ color: T.choco2 }}>
        “Disponibles” es la cifra oficial que usan ventas y reservas. Las reservadas ya fueron descontadas; el detalle por figura y sabor explica ese stock sin duplicarlo.
      </div>

      <div className="grid grid-cols-2 lg:grid-cols-4 gap-3">
        {metrics.map((metric) => (
          <Stat key={metric.label} icon={metric.icon} label={metric.label} value={metric.value} sub={metric.note} tone={metric.color} />
        ))}
      </div>
      <div className="text-[11px] font-semibold mt-2 mb-4" style={{ color: T.choco2 }}>
        Trazabilidad exacta: <b style={{ color: T.coral }}>{exactCoverage}%</b> — {inventory.summary.exactAvailable} de {inventory.summary.available} con figura y sabor.
      </div>
      {(inventory.summary.quarantined > 0 || inventory.summary.reconciliationExcess > 0 || inventory.summary.negativeStockProducts > 0) && (
        <div className="rounded-2xl p-3 mb-4 text-xs font-semibold" role="alert" style={{ background: "#F6D4CD", color: "#7D2D22", border: "1px solid #ECBBB1" }}>
          <div className="font-extrabold mb-1">⚠ Inventario protegido</div>
          {inventory.summary.quarantined > 0 && <div>{inventory.summary.quarantined} unidad(es) vencidas están en cuarentena y no cubren ventas.</div>}
          {inventory.summary.reconciliationExcess > 0 && <div>{inventory.summary.reconciliationBlocked} unidad(es) con detalle físico quedaron bloqueadas: exceden el stock oficial por {inventory.summary.reconciliationExcess}. Reconciliá antes de vender esa variante.</div>}
          {inventory.summary.negativeStockProducts > 0 && <div>{inventory.summary.negativeStockProducts} producto(s) tenían stock negativo; se muestran en cero y requieren revisión.</div>}
        </div>
      )}

      <div className="momo-segmented-tabs inline-flex max-w-full gap-1 overflow-x-auto p-1.5 mb-3 rounded-2xl" role="tablist" aria-label="Vistas del inventario terminado">
        {tabs.map(([name, count]) => (
          <button key={name} type="button" role="tab" aria-selected={tab === name} onClick={() => setTab(name)}
            className="momo-segmented-tab shrink-0 rounded-xl px-3 py-2 text-xs font-bold border-0"
            style={tab === name ? { background: T.coral, color: "#fff" } : { background: "transparent", color: T.choco2 }}>
            {name} <span className="ml-1 inline-flex min-w-5 h-5 px-1 rounded-full items-center justify-center text-[10px]" style={{ background: tab === name ? "rgba(255,255,255,.2)" : "#fff" }}>{count}</span>
          </button>
        ))}
      </div>

      {tab === "Figuras" && (
        <>
          <SectionTitle>Figuras listas y sabores exactos</SectionTitle>
          <div className="text-xs font-semibold mb-3" style={{ color: T.choco2 }}>
            Cada tarjeta suma únicamente producto terminado vigente con figura y sabor verificados. Las imperfectas aparecen aparte y nunca aumentan el stock para venta.
          </div>
          <div className="grid sm:grid-cols-2 lg:grid-cols-3 gap-3 mb-4">
            {inventory.figureSummaries.map((figure) => (
              <Card key={figure.figura} className="momo-queue-item p-4" onClick={() => setDetalleFiguraNombre(figure.figura)} aria-label={`Abrir inventario de la figura ${figure.figura}`}>
                <div className="flex items-start justify-between gap-3">
                  <div>
                    <div className="text-[10px] uppercase tracking-wider font-extrabold" style={{ color: T.coral }}>Figura terminada</div>
                    <div className="display text-xl font-semibold mt-0.5">{figure.figura}</div>
                    <div className="text-[11px] font-semibold mt-1" style={{ color: T.choco2 }}>{figure.flavors.length} {figure.flavors.length === 1 ? "sabor disponible" : "sabores disponibles"}</div>
                  </div>
                  <div className="text-right shrink-0"><div className="display text-3xl" style={{ color: figure.available > 0 ? "#3F6B42" : T.choco2 }}>{figure.available}</div><div className="text-[9px] uppercase font-extrabold" style={{ color: T.choco2 }}>para vender</div></div>
                </div>
                <div className="flex gap-1.5 flex-wrap mt-3">
                  {figure.flavors.map((flavor) => <span key={flavor.sabor} className="text-[10px] font-extrabold px-2 py-1 rounded-full" style={{ background: "#E3EFE0", color: "#315D37" }}>{flavor.sabor} · {flavor.available}</span>)}
                  {figure.flavors.length === 0 && <span className="text-[10px] font-extrabold px-2 py-1 rounded-full" style={{ background: T.vainilla, color: T.choco2 }}>Sin stock vendible exacto</span>}
                </div>
                {(figure.imperfectForShakes > 0 || figure.imperfectPending > 0) && <div className="grid grid-cols-2 gap-2 mt-3">
                  <div className="rounded-xl p-2" style={{ background: "#F1DFEB" }}><div className="text-[9px] uppercase font-extrabold" style={{ color: "#754568" }}>Para malteadas</div><div className="font-extrabold" style={{ color: "#754568" }}>{figure.imperfectForShakes}</div></div>
                  <div className="rounded-xl p-2" style={{ background: "#FBE8C8" }}><div className="text-[9px] uppercase font-extrabold" style={{ color: "#7A5410" }}>Por decidir</div><div className="font-extrabold" style={{ color: "#7A5410" }}>{figure.imperfectPending}</div></div>
                </div>}
                <div className="flex items-center justify-end mt-3 pt-3 border-t text-[11px] font-bold" style={{ borderColor: T.border, color: T.coral }}>Ver sabores, vencimientos e imperfectas ›</div>
              </Card>
            ))}
            {inventory.figureSummaries.length === 0 && <Empty icon="🐾" text="Todavía no hay figuras terminadas con detalle verificable." />}
          </div>
        </>
      )}

      {tab === "Disponibles" && (
        <>
          <SectionTitle>Producto disponible para venta</SectionTitle>
          <div className="grid sm:grid-cols-2 lg:grid-cols-3 gap-3 mb-4">
            {inventory.products.map((product) => {
              const productVariants = inventory.variants.filter((variant) => variant.productId === product.id);
              const coverage = product.available > 0 ? Math.round(product.exactAvailable / product.available * 100) : 0;
              return (
              <Card key={product.id} className="momo-queue-item p-4" onClick={() => setDetalleProductoId(product.id)} aria-label={`Abrir detalle de ${product.nombre}`}>
                <div className="flex items-start justify-between gap-3">
                  <div>
                    <div className="text-[10px] uppercase tracking-wider font-extrabold" style={{ color: product.available <= 2 ? "#A03B2A" : T.choco2 }}>{product.available <= 2 ? "Stock por reponer" : "Disponible ahora"}</div>
                    <div className="text-sm font-bold leading-tight mt-0.5">{product.nombre}</div>
                  </div>
                  <div className="text-right shrink-0"><div className="display text-2xl" style={{ color: product.available <= 2 ? "#A03B2A" : T.coral }}>{product.available}</div><div className="text-[9px] uppercase font-extrabold" style={{ color: T.choco2 }}>unidades</div></div>
                </div>
                <div className="flex gap-1.5 flex-wrap mt-3">
                  <span className="text-[10px] font-extrabold px-2 py-1 rounded-full" style={{ background: product.exactAvailable ? "#E3EFE0" : "#FBE8C8", color: product.exactAvailable ? "#3F6B42" : "#96690F" }}>{product.exactAvailable} exactas</span>
                  <span className="text-[10px] font-extrabold px-2 py-1 rounded-full" style={{ background: T.vainilla, color: T.choco2 }}>{productVariants.length} {productVariants.length === 1 ? "combinación" : "combinaciones"}</span>
                  {product.withoutVariantDetail > 0 && <span className="text-[10px] font-extrabold px-2 py-1 rounded-full" style={{ background: "#FBE8C8", color: "#96690F" }}>{product.withoutVariantDetail} sin detalle</span>}
                </div>
                <div className="flex items-center justify-between gap-3 mt-3 pt-3 border-t text-[11px] font-bold" style={{ borderColor: T.border, color: T.choco2 }}><span>{coverage}% trazabilidad exacta</span><span style={{ color: T.coral }}>Ver figuras y sabores ›</span></div>
              </Card>
            );})}
            {inventory.products.length === 0 && <Empty icon="🍮" text="No hay producto terminado disponible para venta." />}
          </div>
        </>
      )}

      {tab === "Reservadas" && (
        <>
          <SectionTitle>Producto separado para pedidos</SectionTitle>
          <div className="text-xs font-semibold mb-3" style={{ color: T.choco2 }}>
            Estas unidades ya salieron del stock disponible. El lote muestra la asignación FIFO cuando existe trazabilidad física.
          </div>
          {inventory.reservations.length > 0 ? (
            <Card className="overflow-x-auto">
              <table className="w-full text-sm min-w-[680px]">
                <thead><tr className="text-left text-xs" style={{ color: T.choco2 }}>
                  {['Pedido','Producto','Cantidad','Lote / figura','Estado pedido','Reserva'].map((heading) => <th key={heading} className="px-3 py-3 font-bold">{heading}</th>)}
                </tr></thead>
                <tbody>
                  {inventory.reservations.map((reservation) => {
                    const order = orderById[reservation.orderId];
                    return (
                      <tr key={reservation.id} className="border-t" style={{ borderColor: T.border }}>
                        <td className="px-3 py-2 text-xs font-bold">{reservation.orderId}</td>
                        <td className="px-3 py-2 font-semibold">{reservation.nombre}</td>
                        <td className="px-3 py-2 font-bold">{reservation.cantidad}</td>
                        <td className="px-3 py-2 text-xs">{reservation.batchId ? `${reservation.batchId}${reservation.figuraLote ? ` · ${reservation.figuraLote}` : ""}` : "Sin lote detallado"}</td>
                        <td className="px-3 py-2"><Badge label={order?.estado || "Sin pedido"} /></td>
                        <td className="px-3 py-2"><Badge label={reservation.estado} /></td>
                      </tr>
                    );
                  })}
                </tbody>
              </table>
            </Card>
          ) : <Empty icon="🏷️" text="No hay reservas de producto terminado." />}
        </>
      )}

      {tab === "En proceso" && (
        <>
          <SectionTitle action={<Btn small kind="soft" onClick={() => go("Producción")}>Abrir Producción</Btn>}>Lotes que todavía no están disponibles</SectionTitle>
          <div className="grid lg:grid-cols-2 gap-3">
            {inventory.inProcess.map((batch) => (
              <Card key={batch.id} className="p-4">
                <div className="flex justify-between items-start gap-2">
                  <div>
                    <div className="font-bold">{batch.id} · {batch.producto}</div>
                    <div className="text-xs mt-0.5" style={{ color: T.choco2 }}>{batch.sabor} · {batch.gramaje || "sin gramaje"} · vence {batch.vence || "sin fecha"}</div>
                  </div>
                  <Badge label={batch.estado} />
                </div>
                <div className="mt-3 flex justify-between items-baseline gap-2">
                  <span className="text-xs font-bold" style={{ color: T.choco2 }}>Unidades producidas</span>
                  <span className="display text-2xl font-semibold" style={{ color: T.choco }}>{batch.prod || 0}</span>
                </div>
                <div className="text-xs font-semibold mt-2" style={{ color: T.choco2 }}>
                  {Array.isArray(batch.figuras) && batch.figuras.length ? batch.figuras.map((figure) => `${figure.cant}× ${figure.figura}`).join(" · ") : batch.figura || "Sin figura detallada"}
                </div>
              </Card>
            ))}
            {inventory.inProcess.length === 0 && <Empty icon="🧊" text="No hay lotes en preparación, congelación o reserva." />}
          </div>
        </>
      )}

      {tab === "Imperfectas" && (
        <>
          <SectionTitle action={<Btn small kind="soft" onClick={() => go("Producción")}>Gestionar en Producción</Btn>}>Imperfectas y descartadas por lote</SectionTitle>
          <div className="rounded-xl p-3 mb-3 text-xs font-semibold" style={{ background: T.vainilla, color: T.choco2 }}>
            Pendientes: {inventory.summary.imperfectPending} · Reaprovechadas/con destino: {inventory.summary.imperfectReused} · Descartadas: {inventory.summary.discarded}. Las reaprovechadas no se suman al producto disponible para venta.
          </div>
          <div className="grid lg:grid-cols-2 gap-3">
            {inventory.imperfects.map((batch) => (
              <Card key={batch.id} className="p-4">
                <div className="flex justify-between items-start gap-2">
                  <div>
                    <div className="font-bold">{batch.id} · {batch.producto}</div>
                    <div className="text-xs mt-0.5" style={{ color: T.choco2 }}>{batch.figura || "Sin figura"} · {batch.sabor || "Sin sabor"} · {batch.fecha}</div>
                  </div>
                  <Badge label={batch.destinationRegistered ? "Con destino" : "Pendiente"} map={{ "Con destino": { bg: "#DDEBD9", fg: "#3F6B42" }, "Pendiente": { bg: "#FBE8C8", fg: "#96690F" } }} />
                </div>
                <div className="mt-3 pl-3 border-l-2" style={{ borderColor: T.rosa }}>
                  <div className="flex justify-between items-baseline gap-2 text-xs">
                    <span style={{ color: T.choco2 }}>Imperfectas</span>
                    <span className="font-bold" style={{ color: "#96690F" }}>{batch.imperfectas}</span>
                  </div>
                  <div className="flex justify-between items-baseline gap-2 text-xs mt-0.5">
                    <span style={{ color: T.choco2 }}>Descartadas</span>
                    <span className="font-bold" style={{ color: "#A03B2A" }}>{batch.descartadas}</span>
                  </div>
                </div>
                <div className="flex gap-1.5 flex-wrap mt-2">
                  {batch.figureOutcomes.filter((row) => row.imperfectas > 0 || row.descartadas > 0).map((row) => <span key={row.figura} className="text-[10px] font-extrabold px-2 py-1 rounded-full" style={{ background: T.vainilla, color: T.choco2 }}>{row.figura}: {row.imperfectas} imperfectas{row.descartadas ? ` · ${row.descartadas} descartadas` : ""}</span>)}
                </div>
                <div className="text-xs font-bold mt-2" style={{ color: batch.destinationRegistered ? "#3F6B42" : "#96690F" }}>
                  {batch.destinationRegistered ? `Destino: ${batch.destino}` : "Falta definir si se reaprovechan o se descartan."}
                </div>
              </Card>
            ))}
            {inventory.imperfects.length === 0 && <Empty icon="✨" text="No hay imperfectas ni descartadas registradas." />}
          </div>
        </>
      )}

      {detalleFigura && (
        <Modal title={`Figura terminada · ${detalleFigura.figura}`} onClose={() => setDetalleFiguraNombre(null)} wide>
          <div className="flex flex-wrap items-start justify-between gap-3 mb-4">
            <div>
              <div className="text-[10px] uppercase tracking-[.14em] font-extrabold" style={{ color: T.coral }}>Inventario exacto por figura</div>
              <div className="display text-2xl font-semibold mt-0.5">{detalleFigura.figura}</div>
              <div className="text-xs font-semibold mt-1" style={{ color: T.choco2 }}>Sabores vigentes disponibles para vender e imperfectas separadas por destino.</div>
            </div>
            <Badge label={detalleFigura.available > 0 ? "Disponible" : "Sin stock vendible"} map={{ Disponible: { bg: "#DDEBD9", fg: "#3F6B42" }, "Sin stock vendible": { bg: "#FBE8C8", fg: "#96690F" } }} />
          </div>

          <div className="grid grid-cols-2 lg:grid-cols-4 gap-3 mb-4">
            <Stat icon="✓" label="Para vender" value={detalleFigura.available} sub={`${detalleFigura.flavors.length} sabor(es)`} tone="#3F6B42" />
            <Stat icon="🥤" label="Para malteadas" value={detalleFigura.imperfectForShakes} sub="destino ya definido" tone="#8A4D7A" />
            <Stat icon="♻" label="Por decidir" value={detalleFigura.imperfectPending} sub="requieren destino" tone="#96690F" />
            <Stat icon="×" label="Descartadas" value={detalleFigura.discarded} sub="no reutilizables" tone="#A03B2A" />
          </div>

          <Card className="p-4 mb-4" style={{ background: "linear-gradient(135deg,#FFF9F1,#F7ECD9)" }}>
            <div className="flex items-center justify-between gap-3 mb-3"><div><div className="text-[10px] uppercase tracking-[.12em] font-extrabold" style={{ color: T.coral }}>Stock vendible</div><div className="display text-lg font-semibold">Todos los sabores de {detalleFigura.figura}</div></div><span className="text-xs font-extrabold" style={{ color: T.choco2 }}>{detalleFigura.available} unidades</span></div>
            <div className="grid sm:grid-cols-2 gap-2">
              {detalleFigura.flavors.map((flavor) => <div key={flavor.sabor} className="rounded-2xl border p-3 flex items-start justify-between gap-3" style={{ borderColor: T.border, background: T.surface }}><div><div className="text-sm font-extrabold">{flavor.sabor}</div><div className="text-[11px] font-semibold mt-0.5" style={{ color: T.choco2 }}>{flavor.gramajes.length ? flavor.gramajes.map((grams) => `${grams} g`).join(" · ") : "Gramaje sin registrar"}{flavor.nextExpiration ? ` · vence primero ${flavor.nextExpiration}` : ""}</div></div><div className="text-right shrink-0"><div className="display text-2xl" style={{ color: "#3F6B42" }}>{flavor.available}</div><div className="text-[9px] uppercase font-extrabold" style={{ color: T.choco2 }}>disponibles</div></div></div>)}
              {detalleFigura.flavors.length === 0 && <div className="sm:col-span-2 text-sm font-semibold p-3 rounded-xl" style={{ background: T.vainilla, color: T.choco2 }}>No hay sabores vendibles de esta figura.</div>}
            </div>
          </Card>

          <Card className="p-4">
            <div className="flex items-center justify-between gap-3 mb-2"><div><div className="text-[10px] uppercase tracking-[.12em] font-extrabold" style={{ color: "#8A4D7A" }}>Reaprovechamiento</div><div className="display text-lg font-semibold">Imperfectas por sabor y lote</div></div><span className="text-xs font-extrabold" style={{ color: T.choco2 }}>{detalleFigura.imperfectTotal} registradas</span></div>
            <div className="space-y-2">
              {detalleFigura.imperfectBatches.map((batch, index) => <div key={`${batch.id}-${batch.sabor}-${index}`} className="rounded-2xl p-3 flex items-start justify-between gap-3" style={{ background: batch.forShakes ? "#F1DFEB" : batch.destinationRegistered ? "#EDF0E8" : "#FBE8C8" }}><div><div className="text-sm font-extrabold">{batch.sabor} · lote {batch.id}</div><div className="text-[11px] font-semibold mt-0.5" style={{ color: T.choco2 }}>{batch.forShakes ? "Para malteadas y crepas" : batch.destinationRegistered ? `Destino: ${batch.destino}` : "Destino pendiente"}{batch.fecha ? ` · ${batch.fecha}` : ""}</div></div><div className="text-right shrink-0"><div className="display text-2xl" style={{ color: batch.forShakes ? "#8A4D7A" : "#96690F" }}>{batch.imperfectas}</div><div className="text-[9px] uppercase font-extrabold" style={{ color: T.choco2 }}>imperfectas</div>{batch.descartadas > 0 && <div className="text-[9px] font-extrabold mt-0.5" style={{ color: "#A03B2A" }}>{batch.descartadas} descartadas</div>}</div></div>)}
              {detalleFigura.imperfectBatches.length === 0 && <div className="text-sm font-semibold p-3 rounded-xl" style={{ background: T.vainilla, color: T.choco2 }}>Esta figura no tiene imperfectas registradas.</div>}
            </div>
          </Card>
        </Modal>
      )}

      {detalleProducto && (
        <Modal title={`Inventario · ${detalleProducto.nombre}`} onClose={() => setDetalleProductoId(null)} wide>
          <div className="flex flex-wrap items-start justify-between gap-3 mb-4">
            <div>
              <div className="text-[10px] uppercase tracking-[.14em] font-extrabold" style={{ color: T.coral }}>Producto terminado</div>
              <div className="display text-2xl font-semibold mt-0.5">{detalleProducto.nombre}</div>
              <div className="text-xs font-semibold mt-1" style={{ color: T.choco2 }}>Stock oficial después de reservas y cuarentena.</div>
            </div>
            <Badge label={detalleProducto.available > 0 ? "Disponible" : "Sin stock"} map={{ Disponible: { bg: "#DDEBD9", fg: "#3F6B42" }, "Sin stock": { bg: "#F6D4CD", fg: "#A03B2A" } }} />
          </div>

          <div className="grid grid-cols-2 lg:grid-cols-4 gap-3 mb-4">
            <Stat icon="✓" label="Disponibles" value={detalleProducto.available} sub="para nuevas ventas" tone="#3F6B42" />
            <Stat icon="🐾" label="Exactas" value={detalleProducto.exactAvailable} sub="con figura y sabor" tone={T.coral} />
            <Stat icon="◌" label="Sin detalle" value={detalleProducto.withoutVariantDetail} sub="stock legado" tone="#96690F" />
            <Stat icon="🏷" label="Reservadas" value={detalleReservas.reduce((sum, row) => sum + Number(row.cantidad || 0), 0)} sub={`${detalleReservas.length} asignación(es)`} tone="#63518A" />
          </div>

          <Card className="p-4 mb-4" style={{ background: "linear-gradient(135deg,#FFF9F1,#F7ECD9)" }}>
            <div className="flex items-center justify-between gap-3 mb-3"><div><div className="text-[10px] uppercase tracking-[.12em] font-extrabold" style={{ color: T.coral }}>Detalle vendible exacto</div><div className="display text-lg font-semibold">Figuras y sabores disponibles</div></div><span className="text-xs font-extrabold" style={{ color: T.choco2 }}>{detalleVariantes.length} {detalleVariantes.length === 1 ? "combinación" : "combinaciones"}</span></div>
            <div className="grid sm:grid-cols-2 gap-2">
              {detalleVariantes.map((variant) => {
                const days = variant.vence ? diasEntre(hoyISO(), variant.vence) : null;
                return <div key={`${variant.figura}-${variant.sabor}-${variant.gramajeG}`} className="rounded-2xl border p-3 flex items-start justify-between gap-3" style={{ borderColor: days != null && days <= 1 ? "#ECBBB1" : T.border, background: T.surface }}><div><div className="text-sm font-extrabold">{variant.figura} · {variant.sabor || "Sin sabor"}</div><div className="text-[11px] font-semibold mt-0.5" style={{ color: T.choco2 }}>{variant.gramajeG != null ? `${variant.gramajeG} g` : "Gramaje sin registrar"}{variant.vence ? ` · vence ${variant.vence}` : ""}</div></div><div className="text-right shrink-0"><div className="display text-2xl" style={{ color: T.coral }}>{variant.disponibles}</div><div className="text-[9px] uppercase font-extrabold" style={{ color: T.choco2 }}>disponibles</div></div></div>;
              })}
              {detalleVariantes.length === 0 && <div className="sm:col-span-2 rounded-2xl p-4 text-sm font-semibold" style={{ background: "#FBE8C8", color: "#7A5410" }}>Todavía no hay unidades con figura y sabor verificables para este producto. El stock sin detalle no debe prometerse como una combinación exacta.</div>}
            </div>
          </Card>

          {detalleCuarentena.length > 0 && <Card className="p-4 mb-4" style={{ background: "#FFF5F2", borderColor: "#ECBBB1" }}><div className="text-xs font-extrabold" style={{ color: "#A03B2A" }}>Cuarentena por vencimiento</div><div className="space-y-1 mt-2">{detalleCuarentena.map((variant) => <div key={`${variant.figura}-${variant.sabor}-${variant.vence}`} className="text-xs font-semibold">{variant.disponibles}× {variant.figura} · {variant.sabor || "Sin sabor"} · venció {variant.vence}</div>)}</div></Card>}

          <div className="grid lg:grid-cols-2 gap-3">
            <Card className="p-4">
              <div className="text-xs font-extrabold mb-2" style={{ color: T.choco2 }}>RESERVAS ACTIVAS</div>
              <div className="space-y-2">{detalleReservas.map((reservation) => <div key={reservation.id} className="rounded-xl p-2.5 flex items-center justify-between gap-3" style={{ background: T.vainilla }}><div><div className="text-sm font-bold">{reservation.cantidad}× · pedido {reservation.orderId}</div><div className="text-[10px] font-semibold" style={{ color: T.choco2 }}>{reservation.batchId ? `${reservation.batchId}${reservation.figuraLote ? ` · ${reservation.figuraLote}` : ""}` : "Sin lote físico exacto"}</div></div><Badge label={orderById[reservation.orderId]?.estado || "Sin pedido"} /></div>)}{detalleReservas.length === 0 && <div className="text-xs font-semibold" style={{ color: T.choco2 }}>No hay unidades reservadas.</div>}</div>
            </Card>
            <Card className="p-4">
              <div className="text-xs font-extrabold mb-2" style={{ color: T.choco2 }}>LOTES EN PROCESO</div>
              <div className="space-y-2">{detalleEnProceso.map((batch) => <div key={batch.id} className="rounded-xl p-2.5 flex items-center justify-between gap-3" style={{ background: "#EDF3F8" }}><div><div className="text-sm font-bold">{batch.id} · {batch.prod || 0} unidades</div><div className="text-[10px] font-semibold" style={{ color: T.choco2 }}>{batch.sabor || "Sin sabor"} · {Array.isArray(batch.figuras) && batch.figuras.length ? batch.figuras.map((row) => `${row.cant}× ${row.figura}`).join(" · ") : batch.figura || "Sin figura"}</div></div><Badge label={batch.estado} /></div>)}{detalleEnProceso.length === 0 && <div className="text-xs font-semibold" style={{ color: T.choco2 }}>No hay lotes activos de este producto.</div>}</div>
            </Card>
          </div>

          {detalleImperfectas.length > 0 && <Card className="p-4 mt-3"><div className="text-xs font-extrabold mb-2" style={{ color: T.choco2 }}>IMPERFECTAS Y DESCARTADAS</div>{detalleImperfectas.map((batch) => <div key={batch.id} className="flex items-center justify-between gap-3 py-2 border-t first:border-0 text-xs" style={{ borderColor: T.border }}><span className="font-bold">{batch.id} · {batch.figura || "Sin figura"} · {batch.sabor || "Sin sabor"}</span><span style={{ color: T.choco2 }}>{batch.imperfectas} imperfectas · {batch.descartadas} descartadas</span></div>)}</Card>}
        </Modal>
      )}
    </div>
  );
}

/* ================= INVENTARIO DE INSUMOS ================= */

function InventoryScopeTabs({ value, onChange, operationCount, reservationCount, historyCount }) {
  const options = [
    { id: "active", label: "Operación", count: operationCount, icon: "●" },
    { id: "reservations", label: "Reservas", count: reservationCount, icon: "▦" },
    { id: "history", label: "Historial", count: historyCount, icon: "◷" },
  ];
  return (
    <div className="inline-flex max-w-full overflow-x-auto rounded-2xl border p-1" style={{ borderColor: T.border, background: T.vainilla }} role="tablist" aria-label="Operación, reservas e historial de Inventario">
      {options.map((option) => {
        const selected = value === option.id;
        return <button key={option.id} type="button" role="tab" aria-selected={selected} onClick={() => onChange(option.id)} className="rounded-xl px-3 py-2 text-xs font-extrabold transition flex items-center gap-2 shrink-0" style={{ background: selected ? T.surface : "transparent", color: selected ? T.choco : T.choco2, boxShadow: selected ? "0 3px 10px rgba(84,56,43,.10)" : "none" }}><span aria-hidden="true" style={{ color: selected ? T.coral : T.choco2 }}>{option.icon}</span><span>{option.label}</span><span className="min-w-5 h-5 px-1 rounded-full inline-flex items-center justify-center text-[10px]" style={{ background: selected ? T.coralSoft : "rgba(255,255,255,.72)", color: selected ? "#A94D34" : T.choco2 }}>{option.count}</span></button>;
      })}
    </div>
  );
}

function InventoryReservationsPanel({ dashboard, go }) {
  const [filter, setFilter] = useState("");
  const [query, setQuery] = useState("");
  const rowsForFilter = dashboard.reservations.filter((row) => !filter
    || (filter === "product" && row.tipo === "producto")
    || (filter === "supply" && row.tipo !== "producto")
    || (filter === "attention" && row.attention));
  const needle = query.trim().toLocaleLowerCase("es");
  const visibleGroups = dashboard.groups.map((group) => ({
    ...group,
    rows: group.rows.filter((row) => rowsForFilter.includes(row)
      && (!needle || [row.id, row.orderId, row.nombre, row.customerName, row.orderState, row.sourceLabel].join(" ").toLocaleLowerCase("es").includes(needle))),
  })).filter((group) => group.rows.length > 0);
  const visibleRows = visibleGroups.flatMap((group) => group.rows);
  const productCount = dashboard.reservations.filter((row) => row.tipo === "producto").length;
  const supplyCount = dashboard.reservations.length - productCount;

  function ageLabel(hours) {
    if (hours == null) return "antigüedad desconocida";
    if (hours < 1) return "reservada hace menos de 1 h";
    if (hours < 24) return `reservada hace ${hours} h`;
    const days = Math.floor(hours / 24);
    return `reservada hace ${days} día${days === 1 ? "" : "s"}`;
  }

  function exportReservations() {
    downloadCSV("reservas-vigentes", ["Reserva", "Pedido", "Cliente", "Estado pedido", "Tipo", "Ítem", "Cantidad", "Fecha", "Origen", "Antigüedad horas", "Atención"], visibleRows.map((row) => [row.id, row.orderId, row.customerName, row.orderState, row.tipo, row.nombre, row.quantity, row.fecha, row.sourceLabel, row.ageHours, row.attentionReasons.join(" · ")]));
  }

  return (
    <div className="momo-page-enter">
      <Card className="p-4 mb-4" style={{ background: "linear-gradient(135deg,#FFF9F1,#F7ECD9)" }}>
        <div className="grid lg:grid-cols-[1fr_auto] gap-4 items-center">
          <div><div className="text-[10px] uppercase tracking-[.14em] font-extrabold" style={{ color: T.coral }}>Stock comprometido</div><div className="display text-xl font-semibold mt-0.5">¿Qué es una reserva vigente?</div><div className="text-xs font-semibold mt-1 max-w-3xl" style={{ color: T.choco2 }}>Es inventario separado para un pedido pagado. Ya no está disponible para otra venta; si el pedido se cancela se libera, y cuando Cocina o Empaque lo utiliza pasa a Consumida. Aquí detectamos reservas antiguas, sin pedido o ligadas a órdenes ya cerradas.</div></div>
          <div className="flex items-center gap-2 text-[10px] font-extrabold whitespace-nowrap"><span className="rounded-xl px-3 py-2" style={{ background: "#DDEBD9", color: "#3F6B42" }}>RESERVADA</span><span>→</span><span className="rounded-xl px-3 py-2" style={{ background: "#DCE7F2", color: "#3E5C7E" }}>CONSUMIDA</span><span>o</span><span className="rounded-xl px-3 py-2" style={{ background: "#FBE8C8", color: "#96690F" }}>LIBERADA</span></div>
        </div>
      </Card>

      <div className="grid grid-cols-2 lg:grid-cols-4 gap-3 mb-4">
        <Stat icon="▦" label="Reservas vigentes" value={dashboard.summary.reservations} sub="filas comprometidas" tone={T.coral} />
        <Stat icon="🧾" label="Pedidos" value={dashboard.summary.orders} sub="órdenes con stock separado" tone="#3E5C7E" />
        <Stat icon="#" label="Cantidad reservada" value={dashboard.summary.quantity} sub={`${dashboard.summary.exact} con lote físico exacto`} tone="#3F6B42" />
        <Stat icon="△" label="Necesitan revisión" value={dashboard.summary.attention} sub="antiguas o inconsistentes" tone="#A03B2A" />
      </div>

      <Card className="p-3 mb-4">
        <div className="flex flex-wrap items-center gap-2">
          {[["Todas", "", dashboard.summary.reservations], ["Producto terminado", "product", productCount], ["Insumos y empaque", "supply", supplyCount], ["Necesitan revisión", "attention", dashboard.summary.attention]].map(([label, value, count]) => {
            const selected = filter === value;
            return <button key={label} type="button" aria-pressed={selected} onClick={() => setFilter(value)} className="rounded-xl px-3 py-2 text-xs font-extrabold border" style={{ borderColor: selected ? T.coral : T.border, background: selected ? T.coralSoft : T.surface, color: selected ? "#A34A2A" : T.choco2 }}>{label} <span className="ml-1">{count}</span></button>;
          })}
          <input value={query} onChange={(event) => setQuery(event.target.value)} placeholder="Buscar pedido, cliente, ítem o lote…" className="rounded-xl px-3 py-2 text-sm border outline-none min-w-[230px] flex-1" style={inputStyle} />
          <Btn small kind="ghost" onClick={exportReservations}>⬇ CSV</Btn>
        </div>
      </Card>

      <div className="flex items-end justify-between gap-3 mb-3"><div><div className="display text-lg font-semibold">Reservas por pedido</div><div className="text-xs font-semibold" style={{ color: T.choco2 }}>{visibleRows.length} reserva{visibleRows.length === 1 ? "" : "s"} en {visibleGroups.length} pedido{visibleGroups.length === 1 ? "" : "s"}</div></div>{(filter || query) && <button type="button" onClick={() => { setFilter(""); setQuery(""); }} className="text-xs font-extrabold" style={{ color: T.coral }}>Limpiar filtros</button>}</div>
      <div className="grid lg:grid-cols-2 gap-3">
        {visibleGroups.map((group) => (
          <Card key={group.orderId} className="momo-queue-item p-4" style={group.attention ? { borderColor: "#E9A08F", background: "#FFF9F7" } : undefined}>
            <div className="flex items-start justify-between gap-3">
              <div className="min-w-0"><div className="flex flex-wrap items-center gap-2"><span className="display text-lg font-semibold">{group.orderId}</span><Badge label={group.orderState} />{group.attention && <span className="rounded-full px-2 py-0.5 text-[10px] font-extrabold" style={{ background: "#F6D4CD", color: "#A03B2A" }}>Revisar</span>}</div><div className="text-xs font-semibold mt-0.5" style={{ color: T.choco2 }}>{group.customerName} · {ageLabel(group.oldestHours)}</div></div>
              <Btn small kind="ghost" disabled={group.orderId === "Sin pedido"} onClick={() => go?.("Pedidos", { orderId: group.orderId })}>Abrir pedido</Btn>
            </div>
            {group.attention && <div className="rounded-xl px-3 py-2 mt-3 text-xs font-bold" style={{ background: "#F6D4CD", color: "#A03B2A" }}>△ {[...new Set(group.rows.flatMap((row) => row.attentionReasons))].join(" · ")}</div>}
            <div className="mt-3 space-y-2">
              {group.rows.map((row) => (
                <div key={row.id} className="rounded-xl border px-3 py-2.5 flex items-start justify-between gap-3" style={{ borderColor: T.border, background: T.surface }}>
                  <div className="min-w-0"><div className="text-sm font-bold">{row.quantity}× {row.nombre}</div><div className="text-[10px] font-semibold mt-0.5" style={{ color: T.choco2 }}>{row.id} · {row.tipo === "producto" ? "Producto terminado" : "Insumo / empaque"} · {row.sourceLabel}</div></div>
                  <time className="text-[10px] font-bold shrink-0" style={{ color: T.choco2 }}>{row.fecha}</time>
                </div>
              ))}
            </div>
          </Card>
        ))}
        {!visibleGroups.length && <Empty icon="▦" text="No hay reservas vigentes con esos filtros." />}
      </div>
    </div>
  );
}

function InventoryHistoryPanel({ entries, go }) {
  const [query, setQuery] = useState("");
  const [kind, setKind] = useState("");
  const [from, setFrom] = useState("");
  const [to, setTo] = useState("");
  const [limit, setLimit] = useState(50);
  const filtered = useMemo(() => {
    const needle = query.trim().toLocaleLowerCase("es");
    return entries.filter((entry) => {
      const haystack = [entry.sourceId, entry.type, entry.item, entry.orderId, entry.status, entry.note].join(" ").toLocaleLowerCase("es");
      const day = entry.at.slice(0, 10);
      return (!needle || haystack.includes(needle))
        && (!kind || entry.kind === kind)
        && (!from || day >= from)
        && (!to || day <= to);
    });
  }, [entries, query, kind, from, to]);
  useEffect(() => { setLimit(50); }, [query, kind, from, to]);
  const visible = filtered.slice(0, limit);
  const movementCount = entries.filter((entry) => entry.kind === "movement").length;
  const reservationCount = entries.filter((entry) => entry.kind === "reservation").length;
  const wasteCount = entries.filter((entry) => entry.kind === "movement" && entry.type === "Merma").length;

  function exportHistory() {
    downloadCSV("historial-inventario", ["Fecha", "Origen", "ID", "Tipo", "Ítem", "Cantidad", "Pedido", "Estado", "Nota"], filtered.map((entry) => [entry.at, entry.kind === "movement" ? "Movimiento" : "Reserva", entry.sourceId, entry.type, entry.item, entry.quantity, entry.orderId, entry.status, entry.note]));
  }

  const statusMap = {
    Entrada: { bg: "#DDEBD9", fg: "#3F6B42" },
    Salida: { bg: "#DCE7F2", fg: "#3E5C7E" },
    Ajuste: { bg: "#EBE6E0", fg: "#7A6E63" },
    Merma: { bg: "#F6D4CD", fg: "#A03B2A" },
    "Uso en producción": { bg: "#E8E0F2", fg: "#63518A" },
    Consumida: { bg: "#DDEBD9", fg: "#3F6B42" },
    Liberada: { bg: "#FBE8C8", fg: "#96690F" },
  };

  return (
    <div className="momo-page-enter">
      <div className="grid grid-cols-2 lg:grid-cols-4 gap-3 mb-4">
        <Stat icon="◷" label="Registros" value={entries.length} sub="rastro de inventario" tone={T.coral} />
        <Stat icon="↕" label="Movimientos" value={movementCount} sub="entradas, usos y ajustes" tone="#3E5C7E" />
        <Stat icon="▦" label="Reservas cerradas" value={reservationCount} sub="consumidas o liberadas" tone="#3F6B42" />
        <Stat icon="△" label="Mermas" value={wasteCount} sub="retiros trazables" tone="#A03B2A" />
      </div>

      <Card className="p-3 mb-4">
        <div className="flex flex-wrap items-center gap-2 mb-3">
          {[["Todos", ""], ["Movimientos", "movement"], ["Reservas cerradas", "reservation"]].map(([label, value]) => {
            const selected = kind === value;
            const count = value === "movement" ? movementCount : value === "reservation" ? reservationCount : entries.length;
            return <button key={label} type="button" aria-pressed={selected} onClick={() => setKind(value)} className="rounded-xl px-3 py-2 text-xs font-extrabold border" style={{ borderColor: selected ? T.coral : T.border, background: selected ? T.coralSoft : T.surface, color: selected ? "#A34A2A" : T.choco2 }}>{label} <span className="ml-1">{count}</span></button>;
          })}
        </div>
        <div className="grid sm:grid-cols-2 lg:grid-cols-[minmax(220px,1fr)_150px_150px_auto_auto] gap-2 items-center">
          <input value={query} onChange={(event) => setQuery(event.target.value)} placeholder="Buscar insumo, pedido, movimiento o nota…" className="rounded-xl px-3 py-2 text-sm border outline-none" style={inputStyle} />
          <input type="date" aria-label="Inventario desde" value={from} onChange={(event) => setFrom(event.target.value)} className="rounded-xl px-3 py-2 text-xs border font-bold" style={inputStyle} />
          <input type="date" aria-label="Inventario hasta" value={to} onChange={(event) => setTo(event.target.value)} className="rounded-xl px-3 py-2 text-xs border font-bold" style={inputStyle} />
          <Btn small kind="ghost" onClick={exportHistory}>⬇ CSV</Btn>
          <Btn small kind="ghost" onClick={() => go?.("Historial operativo")}>Historial central</Btn>
        </div>
      </Card>

      <div className="flex items-center justify-between gap-3 mb-3">
        <div><div className="display text-lg font-semibold">Bitácora de Inventario</div><div className="text-xs font-semibold" style={{ color: T.choco2 }}>{filtered.length} registro{filtered.length === 1 ? "" : "s"} · nada se elimina al salir de Operación</div></div>
        {(query || kind || from || to) && <button type="button" className="text-xs font-extrabold" style={{ color: T.coral }} onClick={() => { setQuery(""); setKind(""); setFrom(""); setTo(""); }}>Limpiar filtros</button>}
      </div>
      <Card className="overflow-hidden">
        <div className="divide-y" style={{ borderColor: T.border }}>
          {visible.map((entry) => (
            <div key={entry.id} className="p-3 sm:p-4 flex gap-3 items-start" style={{ borderColor: T.border }}>
              <div className="w-10 h-10 rounded-xl shrink-0 flex items-center justify-center text-base font-black" style={{ background: entry.kind === "reservation" ? "#F7ECD9" : entry.type === "Merma" ? "#F6D4CD" : entry.quantity >= 0 ? "#DDEBD9" : "#DCE7F2", color: entry.kind === "reservation" ? "#96690F" : entry.type === "Merma" ? "#A03B2A" : T.choco }}>{entry.kind === "reservation" ? "▦" : entry.quantity >= 0 ? "+" : "−"}</div>
              <div className="min-w-0 flex-1">
                <div className="flex flex-wrap items-center gap-2"><span className="font-bold text-sm">{entry.item}</span><Badge label={entry.status} map={statusMap} /></div>
                <div className="text-xs font-semibold mt-1" style={{ color: T.choco2 }}>{entry.kind === "reservation" ? `Reserva ${entry.sourceId}${entry.orderId ? ` · pedido ${entry.orderId}` : ""}` : `${entry.type} · ${entry.sourceId}`}{entry.note ? ` · ${entry.note}` : ""}</div>
              </div>
              <div className="text-right shrink-0"><div className="display text-lg" style={{ color: entry.quantity < 0 || entry.type === "Merma" ? "#A03B2A" : T.coral, fontVariantNumeric: "tabular-nums" }}>{entry.quantityLabel}</div><time className="text-[10px] font-bold block" style={{ color: T.choco2 }}>{entry.at || "Sin fecha"}</time></div>
            </div>
          ))}
          {!visible.length && <div className="p-10 text-center"><div className="text-3xl mb-2">⌕</div><div className="font-bold">No hay registros con esos filtros</div><div className="text-xs mt-1" style={{ color: T.choco2 }}>Probá otra fecha, tipo o término de búsqueda.</div></div>}
        </div>
      </Card>
      {visible.length < filtered.length && <div className="mt-3 text-center"><Btn kind="ghost" onClick={() => setLimit((value) => value + 50)}>Ver 50 registros más</Btn></div>}
    </div>
  );
}

function Inventario({ db, update, user, focus, refrescar, go }) {
  const [scope, setScope] = useState("active");
  const [asistenteComprasAbierto, setAsistenteComprasAbierto] = useState(false);
  const [detalleInsumoId, setDetalleInsumoId] = useState(null);
  const [mov, setMov] = useState(false);
  const [desecharVencido, setDesecharVencido] = useState(null);
  const [motivoDesecho, setMotivoDesecho] = useState("");
  const [nuevoIns, setNuevoIns] = useState(false);
  const [fi, setFi] = useState({ nombre: "", cat: "", unidad: "und", stock: "", min: "", costoTotal: "", proveedor: "", vence: "", ubicacion: "" });
  const [errIns, setErrIns] = useState("");
  const [form, setForm] = useState({ tipo: "Entrada", item: "", cant: "", precio: "", vence: "", proveedor: "", ubicacion: "", nota: "", suggestionIds: [] });
  const [fCat, setFCat] = useState("");
  const [enviando, setEnviando] = useState(false);
  const [avisoInv, setAvisoInv] = useState(null);
  const [enviandoSugId, setEnviandoSugId] = useState(null);
  const highlightId = focus && focus.itemId;
  const highlightRef = useRef(null);
  useEffect(() => {
    if (highlightRef.current) highlightRef.current.scrollIntoView({ behavior: "smooth", block: "center" });
  }, [highlightId]);
  const cats = [...new Set(db.inventory_items.map((i) => i.cat))];
  // Dominios CERRADOS en Nuevo insumo (regla: dominio finito → cerrado; evita
  // "Lácteos"/"lacteos" duplicadas). Solo Administrador puede ampliar la lista
  // vía la opción centinela "➕ Nueva…" — cocina elige de lo existente.
  const NUEVA_CAT = "➕ Nueva categoría…";
  const NUEVA_UBI = "➕ Nueva ubicación…";
  const ubicacionesInv = [...new Set(db.inventory_items.map((i) => i.ubicacion).filter(Boolean))].sort();
  const lista = db.inventory_items.filter((i) => !fCat || i.cat === fCat);
  const selMovIt = db.inventory_items.find((i) => i.nombre === form.item);
  const selMovSupply = inventorySupplyMode(selMovIt, db.subrecetas || []);

  function abrirPreparacion(item) {
    const supply = inventorySupplyMode(item, db.subrecetas || []);
    if (!supply.subrecipe) return;
    if (!supply.canPrepare) {
      setAvisoInv({ titulo: "Preparación inactiva", texto: `${supply.preparationName} está inactiva en el catálogo de subrecetas. Actívala antes de registrar una tanda.` });
      return;
    }
    go?.("Producción", { subrecipeId: supply.subrecipe.id, itemId: item.id, source: "Inventario" });
  }

  function abrirMovimiento(item, tipo = "Entrada") {
    if (tipo === "Entrada" && inventorySupplyMode(item, db.subrecetas || []).kind === "prepared") {
      abrirPreparacion(item);
      return;
    }
    setForm({
      tipo,
      item: item.nombre,
      cant: "",
      precio: "",
      vence: "",
      proveedor: item.proveedor || "",
      ubicacion: item.ubicacion || "",
      nota: tipo === "Entrada" ? "Compra de inventario" : "",
      suggestionIds: [],
    });
    setMov(true);
  }

  function abrirCompraAsistida(recommendation) {
    const item = db.inventory_items.find((candidate) => candidate.id === recommendation.itemId);
    if (!item) return;
    setForm({
      tipo: "Entrada",
      item: item.nombre,
      cant: String(recommendation.quantity),
      precio: "",
      vence: "",
      proveedor: recommendation.supplier === "Proveedor por definir" ? "" : recommendation.supplier,
      ubicacion: recommendation.location || item.ubicacion || "",
      nota: `Compra sugerida por MOMOS OPS · ${recommendation.reasons.join(" · ")}`,
      suggestionIds: recommendation.suggestionIds || [],
    });
    setAsistenteComprasAbierto(false);
    setMov(true);
  }

  async function refrescarSilencioso(onFail) {
    try {
      await refrescar();
    } catch (e) {
      onFail();
    }
  }

  function exportar() {
    downloadCSV("inventario",
      ["Nombre","Categoría","Unidad","Stock","Mínimo","Costo unitario","Proveedor","Vence","Ubicación"],
      db.inventory_items.map((i) => [i.nombre, i.cat, i.unidad, i.stock, i.min, i.costo, i.proveedor, i.vence, i.ubicacion]));
  }

  const totalInsumos = db.inventory_items.length;
  const bajoMinimo = db.inventory_items.filter((i) => Number(i.min) > 0 && Number(i.stock) <= Number(i.min)).length;
  const porVencerInv = db.inventory_items.filter((i) => {
    if (!i.vence) return false;
    const d = diasEntre(hoyISO(), i.vence);
    return d != null && d <= 7;
  }).length;
  const valorStock = db.inventory_items.reduce((acc, i) => acc + Number(i.stock || 0) * Number(i.costo || 0), 0);
  const reposicionPendiente = db.production_suggestions.filter((s) => s.area === "Inventario" && s.estado === "Pendiente").length;
  const reservationBuckets = useMemo(() => partitionByActivity(db.inventory_reservations || [], isActiveInventoryReservation), [db.inventory_reservations]);
  const activeReservations = useMemo(() => [...reservationBuckets.active].sort((a, b) => String(b.fecha || "").localeCompare(String(a.fecha || ""))), [reservationBuckets.active]);
  const reservationDashboard = useMemo(() => buildActiveReservationDashboard(db), [db.inventory_reservations, db.orders, db.customers]);
  const inventoryHistory = useMemo(() => buildInventoryHistory(db), [db.inventory_movements, db.inventory_reservations]);
  const purchaseAssistant = useMemo(() => buildPurchaseAssistant({
    inventoryItems: db.inventory_items,
    inventoryLots: db.inventory_lots,
    inventoryLotsReady: db.inventoryLotsReady,
    subrecipes: db.subrecetas,
    suggestions: db.production_suggestions,
    movements: db.inventory_movements,
    today: hoyISO(),
  }), [db.inventory_items, db.inventory_lots, db.inventoryLotsReady, db.subrecetas, db.production_suggestions, db.inventory_movements]);
  const activeAttentionCount = bajoMinimo + porVencerInv + reposicionPendiente;
  const detalleInsumo = detalleInsumoId ? db.inventory_items.find((item) => item.id === detalleInsumoId) : null;

  function estadoInsumo(item) {
    const supply = inventorySupplyMode(item, db.subrecetas || []);
    const lotesListos = Boolean(db.inventoryLotsReady);
    const lotSummary = buildIngredientLotSummary(item.id, db.inventory_lots || [], hoyISO());
    const diasVence = item.vence ? diasEntre(hoyISO(), item.vence) : null;
    const vencidoLegacy = diasVence != null && diasVence < 0;
    const vencido = lotesListos ? lotSummary.expiredStock > 0 : vencidoLegacy;
    const todoVencido = lotesListos ? lotSummary.expiredStock > 0 && lotSummary.usableStock === 0 : vencidoLegacy;
    const venceHoy = lotesListos ? lotSummary.usable.some((lot) => lot.status === "Vence hoy") : diasVence === 0;
    const proximoVence = lotesListos ? lotSummary.nextExpiry : item.vence;
    const diasProximo = proximoVence ? diasEntre(hoyISO(), proximoVence) : null;
    return { supply, lotesListos, lotSummary, vencido, todoVencido, venceHoy, proximoVence, vencePronto: diasProximo != null && diasProximo > 0 && diasProximo <= 5, bajo: Number(item.min) > 0 && Number(item.stock) <= Number(item.min) };
  }

  const detalleEstado = detalleInsumo ? estadoInsumo(detalleInsumo) : null;
  const detalleMovimientos = detalleInsumo ? (db.inventory_movements || []).filter((movement) => movement.item === detalleInsumo.nombre).slice(0, 12) : [];
  const detalleReservas = detalleInsumo ? (db.inventory_reservations || []).filter((reservation) => isActiveInventoryReservation(reservation) && (reservation.refId === detalleInsumo.id || reservation.nombre === detalleInsumo.nombre)) : [];

  return (
    <div>
      <SectionTitle action={<InventoryScopeTabs value={scope} onChange={setScope} operationCount={activeAttentionCount} reservationCount={activeReservations.length} historyCount={inventoryHistory.length} />}>Inventario de insumos</SectionTitle>
      <div className="text-xs font-semibold mb-3 -mt-3" style={{ color: T.choco2 }}>
        {scope === "active" ? "Lo que requiere atención ahora: stock, vencimientos y reposición." : scope === "reservations" ? "Stock comprometido por pedidos pagados, con su origen, antigüedad y alertas." : "Movimientos y reservas cerradas, ordenados para consultar sin cargar la operación diaria."}
      </div>

      {scope === "active" ? <>
      <div className="grid grid-cols-2 lg:grid-cols-3 xl:grid-cols-5 gap-3">
        <Stat icon="📦" label="Insumos" value={totalInsumos} sub="en catálogo" tone={T.coral} />
        <Stat icon="⚠️" label="Bajo mínimo" value={bajoMinimo} sub="requieren reposición" tone="#A03B2A" />
        <Stat icon="⏳" label="Por vencer" value={porVencerInv} sub="en 7 días o menos" tone="#96690F" />
        <Stat icon="💰" label="Valor en stock" value={fmt(valorStock)} sub="a costo de compra" tone="#3F6B42" />
      </div>
      <Card className="p-4 mt-3 mb-4" onClick={() => setAsistenteComprasAbierto(true)} style={{ background: "linear-gradient(135deg,#FFF5E8,#FFFFFF)", borderColor: purchaseAssistant.summary.urgent ? "#E7B36E" : T.border }}>
        <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-3">
          <div className="flex items-start gap-3 min-w-0">
            <span className="w-10 h-10 rounded-2xl flex items-center justify-center text-xl shrink-0" style={{ background: T.vainilla }} aria-hidden="true">🛒</span>
            <div className="min-w-0"><div className="text-[10px] uppercase tracking-[.14em] font-extrabold" style={{ color: T.coral }}>Asistente de compras</div><div className="display text-lg font-semibold mt-0.5">{purchaseAssistant.summary.items ? `${purchaseAssistant.summary.items} insumo${purchaseAssistant.summary.items === 1 ? "" : "s"} para revisar` : "No hace falta comprar hoy"}</div><div className="text-xs font-semibold mt-0.5" style={{ color: T.choco2 }}>{purchaseAssistant.summary.items ? `${purchaseAssistant.summary.urgent} urgente${purchaseAssistant.summary.urgent === 1 ? "" : "s"} · presupuesto estimado ${fmt(purchaseAssistant.summary.estimatedCost)} · nunca compra sin tu confirmación` : "El stock utilizable cubre los mínimos y no hay faltantes de pedidos."}</div></div>
          </div>
          <span className="text-xs font-extrabold shrink-0" style={{ color: T.coral }}>{purchaseAssistant.summary.items ? "Ver lista sugerida ›" : "Ver análisis ›"}</span>
        </div>
      </Card>

      <div className="flex flex-wrap items-center gap-2 mb-3">
        <Btn onClick={() => { setFi({ nombre: "", cat: "", unidad: "und", stock: "", min: "", costoTotal: "", proveedor: "", vence: "", ubicacion: "" }); setErrIns(""); setNuevoIns(true); }}>＋ Nuevo insumo</Btn>
        <Btn kind="soft" onClick={() => { setForm({ tipo: "Entrada", item: "", cant: "", precio: "", vence: "", proveedor: "", ubicacion: "", nota: "", suggestionIds: [] }); setMov(true); }}>＋ Registrar movimiento</Btn>
        <Btn small kind="ghost" onClick={exportar}>⬇ CSV</Btn>
      </div>

      <div className="momo-segmented-tabs inline-flex max-w-full gap-1 overflow-x-auto p-1.5 mb-4 rounded-2xl" role="tablist" aria-label="Categorías de insumos">
        {[["Todas", ""], ...cats.map((c) => [c, c])].map(([label, value]) => {
          const count = value ? db.inventory_items.filter((i) => i.cat === value).length : totalInsumos;
          const activo = fCat === value;
          return (
            <button key={label} type="button" role="tab" aria-selected={activo} onClick={() => setFCat(value)}
              className="momo-segmented-tab shrink-0 rounded-xl px-3 py-2 text-xs font-bold border-0"
              style={activo ? { background: T.coral, color: "#fff" } : { background: "transparent", color: T.choco2 }}>
              {label} <span className="ml-1 inline-flex min-w-5 h-5 px-1 rounded-full items-center justify-center text-[10px]" style={{ background: activo ? "rgba(255,255,255,.2)" : "#fff" }}>{count}</span>
            </button>
          );
        })}
      </div>

      {(() => {
        const compras = db.production_suggestions.filter((s) => {
          if (s.area !== "Inventario" || s.estado !== "Pendiente") return false;
          const item = db.inventory_items.find((candidate) => candidate.id === s.itemId || candidate.nombre === s.producto);
          return inventorySupplyMode(item, db.subrecetas || []).kind === "prepared";
        });
        if (compras.length === 0) return null;
        return (
          <div className="mb-4">
            <SectionTitle>🥣 Preparaciones internas pendientes</SectionTitle>
            <div className="grid sm:grid-cols-2 gap-2">
              {compras.map((sg) => {
                const item = db.inventory_items.find((candidate) => candidate.id === sg.itemId || candidate.nombre === sg.producto);
                const supply = inventorySupplyMode(item, db.subrecetas || []);
                return (
                <Card key={sg.id} className="p-3 flex items-center justify-between gap-2">
                  <div className="min-w-0">
                    <div className="text-sm font-bold">{sg.cantidad}× {sg.producto}</div>
                    <div className="text-xs" style={{ color: T.choco2 }}>{supply.kind === "prepared" ? "Preparar en Cocina" : "Comprar a proveedor"} · falta para {sg.orderId ? "pedido " + sg.orderId : "reponer stock"} · {sg.fecha}</div>
                  </div>
                  {supply.kind === "prepared" ? (
                    <Btn small kind="soft" onClick={() => item && abrirPreparacion(item)}>🥣 Preparar</Btn>
                  ) : (
                  <BtnAsync small kind="soft" textoEnVuelo="Marcando…" disabled={enviandoSugId === sg.id} onClick={async () => {
                    setEnviandoSugId(sg.id);
                    try {
                      await setSugerenciaEstado(sg.id, "Atendida");
                    } catch (e) {
                      toast("error", "No se pudo marcar la sugerencia: " + e.message);
                      setEnviandoSugId(null);
                      return;
                    }
                    setEnviandoSugId(null);
                    toast("ok", `✓ ${sg.producto} · compra atendida`);
                    await refrescarSilencioso(() => toast("alert", "La sugerencia se marcó, pero no se pudo actualizar la vista. Recargá la página."));
                  }}>Marcar compra atendida</BtnAsync>
                  )}
                </Card>
                );
              })}
            </div>
          </div>
        );
      })()}

      <div className="grid sm:grid-cols-2 lg:grid-cols-3 gap-3">
        {lista.map((i) => {
          const { supply, lotesListos, lotSummary, vencido, todoVencido, venceHoy, proximoVence, vencePronto, bajo } = estadoInsumo(i);
          const hl = highlightId === i.id;
          return (
            <div key={i.id} ref={hl ? highlightRef : null} className="rounded-2xl" style={hl ? { boxShadow: `0 0 0 3px ${T.coral}` } : undefined}>
            <Card className="momo-queue-item p-4" onClick={() => setDetalleInsumoId(i.id)} aria-label={`Abrir detalle de ${i.nombre}`} style={todoVencido ? { borderColor: "#D66A59", background: "#FFF5F2" } : vencido || venceHoy ? { borderColor: "#E9A45F", background: vencido ? "#FFFAF2" : undefined } : undefined}>
              <div className="flex justify-between items-start gap-2">
                <div className="font-bold text-sm leading-tight">{i.nombre}</div>
                <span className="text-[10px] font-bold px-2 py-0.5 rounded-full shrink-0" style={{ background: T.vainilla, color: T.choco2 }}>{i.cat}</span>
              </div>
              <div className="flex items-end gap-1 mt-2">
                <span className="display text-2xl" style={{ color: bajo ? "#A03B2A" : T.coral }}>{i.stock}</span>
                <span className="text-xs font-semibold mb-1" style={{ color: T.choco2 }}>{i.unidad} · mín {i.min}</span>
              </div>
              <div className="flex gap-1.5 mt-2 flex-wrap">
                {supply.kind === "prepared" && <span className="text-[10px] font-extrabold px-2 py-0.5 rounded-full" style={{ background: "#E8E0F2", color: "#63518A" }}>🥣 Elaboración interna</span>}
                {bajo && <span className="text-[10px] font-bold px-2 py-0.5 rounded-full" style={{ background: "#F6D4CD", color: "#A03B2A" }}>Stock bajo</span>}
                {todoVencido && <span className="text-[10px] font-extrabold px-2 py-0.5 rounded-full" style={{ background: "#A03B2A", color: "#fff" }}>Vencido · no usar</span>}
                {lotesListos && vencido && !todoVencido && <span className="text-[10px] font-extrabold px-2 py-0.5 rounded-full" style={{ background: "#FBE8C8", color: "#96690F" }}>{lotSummary.expiredStock} {i.unidad} en cuarentena</span>}
                {venceHoy && <span className="text-[10px] font-extrabold px-2 py-0.5 rounded-full" style={{ background: "#F6D4CD", color: "#A03B2A" }}>Vence hoy</span>}
                {vencePronto && <span className="text-[10px] font-bold px-2 py-0.5 rounded-full" style={{ background: "#FBE8C8", color: "#96690F" }}>Vence pronto</span>}
                {i.costoEstimado && <span className="text-[10px] font-bold px-2 py-0.5 rounded-full" style={{ background: "#FBE8C8", color: "#96690F" }}>≈ costo estimado</span>}
              </div>
              <div className="flex items-center justify-between gap-3 mt-3 pt-3 border-t text-[11px] font-bold" style={{ borderColor: T.border, color: T.choco2 }}><span>{lotesListos ? `${lotSummary.active.length} lote${lotSummary.active.length === 1 ? "" : "s"}` : "Stock consolidado"}{proximoVence ? ` · próximo ${proximoVence}` : ""}</span><span style={{ color: T.coral }}>Abrir detalle ›</span></div>
            </Card>
            </div>
          );
        })}
      </div>

      <Card className="p-4 mt-5" onClick={() => setScope("reservations")}>
        <div className="flex items-center justify-between gap-4">
          <div><div className="text-[10px] uppercase tracking-[.12em] font-extrabold" style={{ color: T.coral }}>Stock comprometido</div><div className="font-bold mt-0.5">{activeReservations.length} reserva{activeReservations.length === 1 ? "" : "s"} vigente{activeReservations.length === 1 ? "" : "s"} en {reservationDashboard.summary.orders} pedido{reservationDashboard.summary.orders === 1 ? "" : "s"}</div><div className="text-xs font-semibold mt-0.5" style={{ color: T.choco2 }}>Abrí Reservas para consultar lote físico, antigüedad y alertas por pedido.</div></div>
          <span className="text-xl" style={{ color: T.coral }}>›</span>
        </div>
      </Card>
      </> : scope === "reservations" ? <InventoryReservationsPanel dashboard={reservationDashboard} go={go} /> : <InventoryHistoryPanel entries={inventoryHistory} go={go} />}

      {asistenteComprasAbierto && (
        <Modal title="Asistente de compras" onClose={() => setAsistenteComprasAbierto(false)} wide>
          <div className="rounded-3xl border p-4 sm:p-5 mb-4" style={{ background: "linear-gradient(135deg,#FFF5E8,#FFFFFF)", borderColor: T.border }}>
            <div className="text-[10px] uppercase tracking-[.14em] font-extrabold" style={{ color: T.coral }}>Decisión explicable</div>
            <div className="display text-2xl font-semibold mt-1">Qué conviene comprar hoy</div>
            <div className="text-sm font-semibold mt-1 max-w-2xl" style={{ color: T.choco2 }}>MOMO OPS cruza stock utilizable, lotes vencidos, mínimos, consumo reciente y faltantes reales de pedidos. La cantidad queda editable y nada entra al inventario hasta que confirmes la compra física.</div>
            <div className="grid grid-cols-2 sm:grid-cols-4 gap-2 mt-4">
              <div className="rounded-2xl bg-white px-3 py-3"><div className="text-[9px] uppercase font-extrabold" style={{ color: T.choco2 }}>Insumos</div><div className="display text-xl mt-0.5" style={{ color: T.coral }}>{purchaseAssistant.summary.items}</div></div>
              <div className="rounded-2xl bg-white px-3 py-3"><div className="text-[9px] uppercase font-extrabold" style={{ color: T.choco2 }}>Urgentes</div><div className="display text-xl mt-0.5" style={{ color: purchaseAssistant.summary.urgent ? "#A03B2A" : "#3F6B42" }}>{purchaseAssistant.summary.urgent}</div></div>
              <div className="rounded-2xl bg-white px-3 py-3"><div className="text-[9px] uppercase font-extrabold" style={{ color: T.choco2 }}>Proveedores</div><div className="display text-xl mt-0.5">{purchaseAssistant.suppliers.length}</div></div>
              <div className="rounded-2xl bg-white px-3 py-3"><div className="text-[9px] uppercase font-extrabold" style={{ color: T.choco2 }}>Presupuesto</div><div className="display text-lg mt-0.5" style={{ color: "#3F6B42" }}>{fmt(purchaseAssistant.summary.estimatedCost)}</div></div>
            </div>
          </div>

          {purchaseAssistant.recommendations.length === 0 ? (
            <div className="rounded-3xl p-8 text-center" style={{ background: "#E5F0E1" }}><div className="text-3xl">✓</div><div className="display text-xl mt-2">Compras al día</div><div className="text-sm font-semibold mt-1" style={{ color: "#3F6B42" }}>No hay faltantes ni insumos externos por debajo de su cobertura mínima.</div></div>
          ) : (
            <div className="space-y-4">
              {purchaseAssistant.suppliers.map((group) => (
                <Card key={group.supplier} className="p-4">
                  <div className="flex items-start justify-between gap-3 mb-3"><div><div className="text-[10px] uppercase tracking-[.12em] font-extrabold" style={{ color: T.coral }}>Proveedor</div><div className="display text-lg font-semibold">{group.supplier}</div></div><div className="text-right"><div className="text-[9px] uppercase font-extrabold" style={{ color: T.choco2 }}>Estimado</div><div className="font-extrabold" style={{ color: "#3F6B42" }}>{fmt(group.estimatedCost)}</div></div></div>
                  <div className="space-y-2">
                    {group.items.map((recommendation) => (
                      <div key={recommendation.itemId} className="rounded-2xl border p-3 flex flex-col sm:flex-row sm:items-center gap-3" style={{ borderColor: recommendation.priority === "Urgente" ? "#E8B7AD" : T.border, background: recommendation.priority === "Urgente" ? "#FFF7F4" : T.surface }}>
                        <div className="flex-1 min-w-0"><div className="flex flex-wrap items-center gap-2"><div className="font-extrabold">{recommendation.name}</div><Badge label={recommendation.priority} map={{ Urgente: { bg: "#F6D4CD", fg: "#A03B2A" }, Alta: { bg: "#FBE8C8", fg: "#96690F" }, Revisar: { bg: T.vainilla, fg: T.choco2 } }} /></div><div className="text-xs font-bold mt-1" style={{ color: T.choco2 }}>Comprar <b style={{ color: T.coral }}>{recommendation.quantity} {recommendation.unit}</b> · quedan {recommendation.current} · mínimo {recommendation.minimum}</div><div className="text-[11px] font-semibold mt-1" style={{ color: T.choco2 }}>{recommendation.reasons.join(" · ")}</div></div>
                        <div className="flex sm:flex-col sm:items-end justify-between gap-2 shrink-0"><div className="text-xs font-extrabold" style={{ color: "#3F6B42" }}>≈ {fmt(recommendation.estimatedCost)}</div><Btn small onClick={() => abrirCompraAsistida(recommendation)}>Preparar compra</Btn></div>
                      </div>
                    ))}
                  </div>
                </Card>
              ))}
            </div>
          )}
          {purchaseAssistant.summary.internalPending > 0 && <div className="rounded-2xl px-4 py-3 mt-4 text-xs font-bold" style={{ background: "#EEE8F5", color: "#63518A" }}>🥣 {purchaseAssistant.summary.internalPending} faltante{purchaseAssistant.summary.internalPending === 1 ? "" : "s"} corresponde{purchaseAssistant.summary.internalPending === 1 ? "" : "n"} a elaboraciones internas. No aparecen como compra: se atienden preparando una tanda en Cocina.</div>}
          {purchaseAssistant.internalNeedsSetup.length > 0 && <div className="rounded-2xl px-4 py-3 mt-3 text-xs font-bold" style={{ background: "#FFF0DD", color: "#7B5410" }}>⚙ {purchaseAssistant.internalNeedsSetup.map((row) => row.name).join(", ")} {purchaseAssistant.internalNeedsSetup.length === 1 ? "está marcada" : "están marcadas"} como producción propia, pero {purchaseAssistant.internalNeedsSetup.length === 1 ? "le falta" : "les falta"} una fórmula activa. MOMOS OPS no {purchaseAssistant.internalNeedsSetup.length === 1 ? "la" : "las"} enviará a compras hasta corregir esa ficha.</div>}
        </Modal>
      )}

      {detalleInsumo && detalleEstado && (
        <Modal title={`Insumo · ${detalleInsumo.nombre}`} onClose={() => setDetalleInsumoId(null)} wide>
          <div className="flex flex-wrap items-start justify-between gap-3 mb-4">
            <div><div className="text-[10px] uppercase tracking-[.14em] font-extrabold" style={{ color: T.coral }}>{detalleInsumo.cat}</div><div className="display text-2xl font-semibold mt-0.5">{detalleInsumo.nombre}</div><div className="text-xs font-semibold mt-1" style={{ color: T.choco2 }}>{detalleEstado.supply.kind === "prepared" ? "Elaboración interna preparada en Cocina" : "Insumo comprado a proveedor"}</div></div>
            <div className="flex gap-1.5 flex-wrap">{detalleEstado.bajo && <span className="text-[10px] font-extrabold px-2.5 py-1 rounded-full" style={{ background: "#F6D4CD", color: "#A03B2A" }}>Stock bajo</span>}{detalleEstado.todoVencido && <span className="text-[10px] font-extrabold px-2.5 py-1 rounded-full" style={{ background: "#A03B2A", color: "#fff" }}>Vencido · no usar</span>}{detalleEstado.vencePronto && <span className="text-[10px] font-extrabold px-2.5 py-1 rounded-full" style={{ background: "#FBE8C8", color: "#96690F" }}>Vence pronto</span>}</div>
          </div>

          <div className="grid grid-cols-2 lg:grid-cols-4 gap-3 mb-4">
            <Stat icon="📦" label="Stock total" value={`${detalleInsumo.stock} ${detalleInsumo.unidad}`} sub={`mínimo ${detalleInsumo.min}`} tone={detalleEstado.bajo ? "#A03B2A" : T.coral} />
            <Stat icon="✓" label="Stock utilizable" value={`${detalleEstado.lotesListos ? detalleEstado.lotSummary.usableStock : detalleEstado.todoVencido ? 0 : detalleInsumo.stock} ${detalleInsumo.unidad}`} sub="vigente para operación" tone="#3F6B42" />
            <Stat icon="△" label="En cuarentena" value={`${detalleEstado.lotesListos ? detalleEstado.lotSummary.expiredStock : detalleEstado.todoVencido ? detalleInsumo.stock : 0} ${detalleInsumo.unidad}`} sub="vencido, no utilizar" tone="#A03B2A" />
            <Stat icon="▦" label="Reservado" value={detalleReservas.reduce((sum, row) => sum + Number(row.cantidad || 0), 0)} sub={`${detalleReservas.length} pedido(s)`} tone="#63518A" />
          </div>

          <Card className="p-4 mb-4">
            <div className="text-xs font-extrabold mb-3" style={{ color: T.choco2 }}>FICHA DEL INSUMO</div>
            <div className="grid sm:grid-cols-2 lg:grid-cols-4 gap-x-5 gap-y-3 text-xs">
              <div><div className="font-semibold" style={{ color: T.choco2 }}>Costo unitario</div><div className="font-bold mt-0.5">{fmt(detalleInsumo.costo)} / {detalleInsumo.unidad}</div></div>
              <div><div className="font-semibold" style={{ color: T.choco2 }}>Proveedor</div><div className="font-bold mt-0.5">{detalleInsumo.proveedor || "Sin registrar"}</div></div>
              <div><div className="font-semibold" style={{ color: T.choco2 }}>Ubicación</div><div className="font-bold mt-0.5">{detalleInsumo.ubicacion || "Sin registrar"}</div></div>
              <div><div className="font-semibold" style={{ color: T.choco2 }}>Próximo vencimiento</div><div className="font-bold mt-0.5">{detalleEstado.proximoVence || "Sin vencimiento"}</div></div>
            </div>
          </Card>

          <div className="grid lg:grid-cols-[1.05fr_.95fr] gap-3 mb-4">
            <Card className="p-4">
              <div className="flex items-center justify-between gap-3 mb-3"><div><div className="text-xs font-extrabold" style={{ color: T.choco2 }}>LOTES DEL INSUMO</div><div className="text-[10px] font-semibold mt-0.5" style={{ color: T.choco2 }}>FIFO usa primero el lote vigente que vence antes.</div></div><span className="text-xs font-extrabold" style={{ color: T.coral }}>{detalleEstado.lotSummary.active.length}</span></div>
              <div className="space-y-2">{detalleEstado.lotesListos && detalleEstado.lotSummary.active.map((lot) => <div key={lot.id} className="rounded-xl border p-3" style={{ borderColor: lot.status === "Vencido" ? "#ECBBB1" : T.border, background: lot.status === "Vencido" ? "#FFF5F2" : T.surface }}><div className="flex items-start justify-between gap-3"><div><div className="text-sm font-bold">{lot.id} · {lot.available} {detalleInsumo.unidad}</div><div className="text-[10px] font-semibold mt-0.5" style={{ color: T.choco2 }}>{lot.expiresAt ? `Vence ${lot.expiresAt}` : "Sin vencimiento"}{lot.supplier ? ` · ${lot.supplier}` : ""}{lot.location ? ` · ${lot.location}` : ""}</div></div><Badge label={lot.status} map={{ Disponible: { bg: "#DDEBD9", fg: "#3F6B42" }, "Vence hoy": { bg: "#FBE8C8", fg: "#96690F" }, Vencido: { bg: "#F6D4CD", fg: "#A03B2A" } }} /></div>{lot.status === "Vencido" && ["Administrador","Cocina"].includes(user) && <div className="mt-2"><Btn small kind="danger" onClick={() => { setMotivoDesecho(`Vencido desde ${lot.expiresAt}`); setDesecharVencido({ ...lot, itemName: detalleInsumo.nombre, unit: detalleInsumo.unidad }); }}>Desechar este lote</Btn></div>}</div>)}{!detalleEstado.lotesListos && <div className="rounded-xl p-3 text-xs font-semibold" style={{ background: T.vainilla, color: T.choco2 }}>Este insumo conserva stock consolidado anterior a la trazabilidad por lotes.</div>}{detalleEstado.lotesListos && detalleEstado.lotSummary.active.length === 0 && <div className="text-xs font-semibold" style={{ color: T.choco2 }}>No hay lotes con saldo disponible.</div>}</div>
            </Card>

            <Card className="p-4">
              <div className="text-xs font-extrabold mb-3" style={{ color: T.choco2 }}>RESERVAS VIGENTES</div>
              <div className="space-y-2">{detalleReservas.map((reservation) => <div key={reservation.id} className="rounded-xl px-3 py-2.5 flex items-center justify-between gap-3" style={{ background: T.vainilla }}><div><div className="text-sm font-bold">{reservation.cantidad} {detalleInsumo.unidad} · {reservation.orderId}</div><div className="text-[10px] font-semibold" style={{ color: T.choco2 }}>{reservation.id} · {reservation.fecha}</div></div><Badge label={reservation.estado} /></div>)}{detalleReservas.length === 0 && <div className="text-xs font-semibold" style={{ color: T.choco2 }}>No hay stock de este insumo comprometido por pedidos.</div>}</div>
            </Card>
          </div>

          <Card className="p-4 mb-4">
            <div className="flex items-center justify-between gap-3 mb-2"><div><div className="text-xs font-extrabold" style={{ color: T.choco2 }}>MOVIMIENTOS RECIENTES</div><div className="text-[10px] font-semibold mt-0.5" style={{ color: T.choco2 }}>Entradas, usos, ajustes y mermas de este insumo.</div></div><span className="text-xs font-extrabold" style={{ color: T.coral }}>{detalleMovimientos.length}</span></div>
            <div>{detalleMovimientos.map((movement) => <div key={movement.id} className="flex items-start justify-between gap-3 py-2 border-t first:border-0 text-xs" style={{ borderColor: T.border }}><div><div className="font-bold">{movement.tipo} · {movement.cant}</div><div className="text-[10px] font-semibold mt-0.5" style={{ color: T.choco2 }}>{movement.nota || "Sin nota"}</div></div><time className="text-[10px] font-bold shrink-0" style={{ color: T.choco2 }}>{movement.fecha}</time></div>)}{detalleMovimientos.length === 0 && <div className="text-xs font-semibold py-2" style={{ color: T.choco2 }}>Todavía no hay movimientos registrados.</div>}</div>
          </Card>

          <div className="flex flex-wrap gap-2 pt-4 border-t" style={{ borderColor: T.border }}>
            {detalleEstado.supply.kind === "prepared" ? <Btn kind="soft" disabled={!detalleEstado.supply.canPrepare} onClick={() => abrirPreparacion(detalleInsumo)}>🥣 Preparar tanda</Btn> : <Btn kind="soft" onClick={() => abrirMovimiento(detalleInsumo, "Entrada")}>＋ Registrar compra</Btn>}
            <Btn kind="ghost" onClick={() => abrirMovimiento(detalleInsumo, "Ajuste")}>Registrar otro movimiento</Btn>
            {!detalleEstado.lotesListos && detalleEstado.vencido && Number(detalleInsumo.stock) > 0 && ["Administrador","Cocina"].includes(user) && <Btn kind="danger" onClick={() => { setMotivoDesecho(`Vencido desde ${detalleInsumo.vence}`); setDesecharVencido({ itemId: detalleInsumo.id, itemName: detalleInsumo.nombre, available: Number(detalleInsumo.stock), unit: detalleInsumo.unidad, expiresAt: detalleInsumo.vence }); }}>Desechar vencido</Btn>}
          </div>
        </Modal>
      )}

      {nuevoIns && (
        <Modal title="Nuevo insumo" onClose={() => setNuevoIns(false)} wide>
          <div className="grid sm:grid-cols-2 gap-x-4">
            <Field label="Nombre del insumo"><Input value={fi.nombre} onChange={(e) => setFi({ ...fi, nombre: e.target.value })} placeholder="Ej: Pulpa de coco 1 kg" /></Field>
            <Field label="Categoría">
              <Select placeholder="Elegir categoría…" options={[...cats, ...(user === "Administrador" ? [NUEVA_CAT] : [])]} value={fi.cat} onChange={(e) => setFi({ ...fi, cat: e.target.value, catNueva: "" })} />
              {fi.cat === NUEVA_CAT && <Input value={fi.catNueva || ""} onChange={(e) => setFi({ ...fi, catNueva: e.target.value })} placeholder="Nombre de la categoría nueva" />}
            </Field>
            <Field label="Unidad de medida"><Select options={["und","kg","g","L","ml","paquete","docena"]} value={fi.unidad} onChange={(e) => setFi({ ...fi, unidad: e.target.value })} /></Field>
            <Field label="Stock inicial"><Input type="number" min="0" step="0.01" value={fi.stock} onChange={(e) => setFi({ ...fi, stock: e.target.value })} placeholder="Cantidad que entra hoy" /></Field>
            <Field label="Stock mínimo (para alertas)"><Input type="number" min="0" step="0.01" value={fi.min} onChange={(e) => setFi({ ...fi, min: e.target.value })} /></Field>
            <Field label="Costo total de la compra"><Input type="number" min="0" value={fi.costoTotal} onChange={(e) => setFi({ ...fi, costoTotal: e.target.value })} placeholder="Lo que pagaste en total (factura)" /></Field>
            <Field label="Proveedor"><Input value={fi.proveedor} onChange={(e) => setFi({ ...fi, proveedor: e.target.value })} placeholder="Ej: Makro, Galería Alameda" /></Field>
            <Field label="Fecha de vencimiento (opcional)"><Input type="date" value={fi.vence} onChange={(e) => setFi({ ...fi, vence: e.target.value })} /></Field>
            <Field label="Ubicación">
              <Select placeholder="Elegir ubicación…" options={[...ubicacionesInv, ...(user === "Administrador" ? [NUEVA_UBI] : [])]} value={fi.ubicacion} onChange={(e) => setFi({ ...fi, ubicacion: e.target.value, ubiNueva: "" })} />
              {fi.ubicacion === NUEVA_UBI && <Input value={fi.ubiNueva || ""} onChange={(e) => setFi({ ...fi, ubiNueva: e.target.value })} placeholder="Ej: Nevera 1, Congelador A, Estante seco…" />}
            </Field>
          </div>
          {(+fi.costoTotal > 0 && +fi.stock > 0) && (
            <div className="text-xs font-bold mb-3 p-2.5 rounded-xl" style={{ background: "#DDEBD9", color: "#3F6B42" }}>Costo unitario calculado: {fmt(+fi.costoTotal / +fi.stock)} / {fi.unidad}  ·  (costo total ÷ stock inicial)</div>
          )}
          {(+fi.costoTotal > 0 && !(+fi.stock > 0)) && (
            <div className="text-xs font-semibold mb-3" style={{ color: "#A03B2A" }}>Poné el stock inicial (cantidad comprada) para calcular el costo unitario.</div>
          )}
          {errIns && <div className="text-sm font-bold p-2.5 rounded-xl mb-3" style={{ background: "#F6D4CD", color: "#A03B2A" }}>{errIns}</div>}
          <div className="text-xs font-semibold mb-3" style={{ color: T.choco2 }}>El stock inicial quedará registrado como un movimiento de entrada (fecha de compra: hoy).</div>
          <div className="flex gap-2">
            <BtnAsync textoEnVuelo="Creando…" disabled={enviando} onClick={async () => {
              // Centinelas "➕ Nueva…" (solo admin): el valor final sale del input de texto.
              const catFinal = fi.cat === NUEVA_CAT ? (fi.catNueva || "").trim() : fi.cat.trim();
              const ubiFinal = fi.ubicacion === NUEVA_UBI ? (fi.ubiNueva || "").trim() : fi.ubicacion.trim();
              if (!fi.nombre.trim()) { setErrIns("Escribe el nombre del insumo."); return; }
              if (db.inventory_items.some((i) => i.nombre.toLowerCase() === fi.nombre.trim().toLowerCase())) { setErrIns("Ya existe un insumo con ese nombre. Usa “Registrar movimiento” para sumarle stock."); return; }
              if (!catFinal) { setErrIns("Indica la categoría."); return; }
              setErrIns("");
              setEnviando(true);
              const nombreCreado = fi.nombre.trim();
              try {
                await crearInsumo({
                  nombre: nombreCreado, cat: catFinal, unidad: fi.unidad,
                  stock: parseFloat(fi.stock) || 0, minimo: parseFloat(fi.min) || 0,
                  costo_total: +fi.costoTotal || 0, proveedor: fi.proveedor.trim(),
                  vence: fi.vence || null, ubicacion: ubiFinal,
                });
              } catch (e) {
                setErrIns(e.message);
                setEnviando(false);
                return;
              }
              setEnviando(false);
              setNuevoIns(false);
              toast("ok", `✓ Insumo ${nombreCreado} creado`);
              await refrescarSilencioso(() => toast("alert", "El insumo se creó, pero no se pudo actualizar la vista. Recargá la página."));
            }}>Crear insumo</BtnAsync>
            <Btn kind="ghost" disabled={enviando} onClick={() => setNuevoIns(false)}>Cancelar</Btn>
          </div>
        </Modal>
      )}

      {mov && (
        <Modal title={selMovIt ? `Movimiento · ${selMovIt.nombre}` : "Registrar movimiento de inventario"} onClose={() => setMov(false)}>
          <Field label="Tipo"><Select options={["Entrada","Salida","Ajuste","Merma","Uso en producción"]} value={form.tipo} onChange={(e) => {
            const nextType = e.target.value;
            if (nextType === "Entrada" && selMovSupply.kind === "prepared") {
              setMov(false);
              abrirPreparacion(selMovIt);
              return;
            }
            setForm({ ...form, tipo: nextType });
          }} /></Field>
          <Field label="Ítem"><Select placeholder="Elegir ítem…" options={db.inventory_items.map((i) => i.nombre)} value={form.item} onChange={(e) => {
            const nextItem = db.inventory_items.find((item) => item.nombre === e.target.value);
            if (form.tipo === "Entrada" && inventorySupplyMode(nextItem, db.subrecetas || []).kind === "prepared") {
              setMov(false);
              abrirPreparacion(nextItem);
              return;
            }
            setForm({ ...form, item: e.target.value });
          }} /></Field>
          {form.tipo === "Entrada" ? (
            <>
              <Field label={"Cantidad comprada" + (selMovIt ? " (en " + selMovIt.unidad + ")" : "")}>
                <div className="flex items-center gap-2">
                  <Input type="number" min="0" step="0.01" value={form.cant} onChange={(e) => setForm({ ...form, cant: e.target.value })} placeholder="Ej: 3" />
                  <span className="text-sm font-bold px-2.5 py-2 rounded-lg whitespace-nowrap" style={{ background: "#EBE6E0", color: T.choco2 }}>{selMovIt ? selMovIt.unidad : "unidad"}</span>
                </div>
              </Field>
              <Field label="Costo total de la compra"><Input type="number" min="0" value={form.precio} onChange={(e) => setForm({ ...form, precio: e.target.value })} placeholder="Lo que pagaste en total (factura)" /></Field>
              <Field label="Vencimiento de este lote (opcional)"><Input type="date" min={hoyISO()} value={form.vence} onChange={(e) => setForm({ ...form, vence: e.target.value })} /></Field>
              <Field label="Proveedor de este lote"><Input value={form.proveedor} onChange={(e) => setForm({ ...form, proveedor: e.target.value })} /></Field>
              <Field label="Ubicación"><Input value={form.ubicacion} onChange={(e) => setForm({ ...form, ubicacion: e.target.value })} /></Field>
            </>
          ) : (
            <Field label="Cantidad (ej: +5, -0.5)"><Input value={form.cant} onChange={(e) => setForm({ ...form, cant: e.target.value })} /></Field>
          )}
          <Field label="Nota"><Input value={form.nota} onChange={(e) => setForm({ ...form, nota: e.target.value })} placeholder="Pedido, lote o motivo" /></Field>
          {form.tipo === "Entrada" && (
            (selMovIt && +form.cant > 0 && form.precio !== "" && +form.precio >= 0) ? (
              <div className="text-xs font-bold mt-1 p-2.5 rounded-xl" style={{ background: "#DDEBD9", color: "#3F6B42" }}>
                {(() => {
                  const cant = +form.cant, total = +form.precio || 0;
                  if (!(total > 0)) return "Entrada sin costo: solo suma stock, el costo unitario NO cambia (" + fmt(selMovIt.costo || 0) + "/" + selMovIt.unidad + ").";
                  const cc = total / cant;
                  const sn = (selMovIt.stock || 0) + cant;
                  const wac = sn > 0 ? ((selMovIt.stock || 0) * (selMovIt.costo || 0) + cant * cc) / sn : (selMovIt.costo || 0);
                  return "Costo de esta compra: " + fmt(cc) + "/" + selMovIt.unidad + "  ·  Nuevo costo promedio: " + fmt(wac) + "/" + selMovIt.unidad + " (antes " + fmt(selMovIt.costo || 0) + ")";
                })()}
              </div>
            ) : (
              <div className="text-xs font-semibold mt-1" style={{ color: T.choco2 }}>Cargá cantidad comprada y costo total; el costo unitario se recalcula solo (promedio ponderado).</div>
            )
          )}
          <div className="flex gap-2 mt-2">
            <BtnAsync textoEnVuelo="Guardando…" disabled={enviando} onClick={async () => {
              if (!form.item || !form.cant) { setAvisoInv({ titulo: "Faltan datos", texto: "Elegí el insumo e indicá una cantidad." }); return; }
              const cantidadMovimiento = Number(form.cant);
              if (!Number.isFinite(cantidadMovimiento) || cantidadMovimiento === 0) { setAvisoInv({ titulo: "Cantidad inválida", texto: "Ingresá una cantidad numérica distinta de cero." }); return; }
              if (form.tipo === "Entrada" && (!(cantidadMovimiento > 0) || form.precio === "" || !Number.isFinite(Number(form.precio)) || +form.precio < 0)) { setAvisoInv({ titulo: "Entrada inválida", texto: "La cantidad debe ser mayor que cero y el costo total no puede ser negativo." }); return; }
              const it = db.inventory_items.find((i) => i.nombre === form.item);
              if (!it) return;
              if (form.tipo === "Entrada" && inventorySupplyMode(it, db.subrecetas || []).kind === "prepared") {
                setMov(false);
                abrirPreparacion(it);
                return;
              }
              const itemVencido = it.vence && diasEntre(hoyISO(), it.vence) < 0;
              if (itemVencido && ["Salida", "Uso en producción"].includes(form.tipo)) { setAvisoInv({ titulo: "Insumo vencido", texto: `${it.nombre} venció el ${it.vence}. Registrá una Merma para retirarlo; no puede usarse ni salir como inventario válido.` }); return; }
              const tipoMov = form.tipo, nombreMov = it.nombre;
              const suggestionIds = Array.isArray(form.suggestionIds) ? form.suggestionIds : [];
              setEnviando(true);
              try {
                if (form.tipo === "Entrada") {
                  if (db.inventoryLotsReady) {
                    await entradaInsumoLote({ itemId: it.id, cant: +form.cant, costoTotal: +form.precio || 0, vence: form.vence || null, proveedor: form.proveedor, ubicacion: form.ubicacion, nota: form.nota });
                  } else {
                    await entradaInsumo(it.id, +form.cant, +form.precio || 0, form.nota);
                  }
                } else {
                  await movimientoInsumo(it.id, form.tipo, cantidadMovimiento, form.nota);
                }
              } catch (e) {
                toast("error", "No se pudo registrar el movimiento: " + e.message);
                setEnviando(false);
                return;
              }
              if (form.tipo === "Entrada" && suggestionIds.length) {
                try {
                  await Promise.all(suggestionIds.map((suggestionId) => setSugerenciaEstado(suggestionId, "Atendida")));
                } catch (error) {
                  toast("alert", `La compra entró al inventario, pero una sugerencia quedó pendiente: ${error.message}`);
                }
              }
              setEnviando(false);
              setMov(false); setForm({ tipo: "Entrada", item: "", cant: "", precio: "", vence: "", proveedor: "", ubicacion: "", nota: "", suggestionIds: [] });
              toast("ok", `✓ ${tipoMov} registrada · ${nombreMov}`);
              await refrescarSilencioso(() => toast("alert", "El movimiento se registró, pero no se pudo actualizar la vista. Recargá la página."));
            }}>Guardar</BtnAsync>
            <Btn kind="ghost" disabled={enviando} onClick={() => setMov(false)}>Cancelar</Btn>
          </div>
        </Modal>
      )}

      {desecharVencido && (
        <Modal title="Desechar insumo vencido" onClose={() => { if (!enviando) setDesecharVencido(null); }}>
          <div className="rounded-2xl p-4 mb-4" style={{ background: "#FFF1ED", border: "1px solid #E9A08F" }}>
            <div className="text-xs font-extrabold uppercase tracking-[.12em]" style={{ color: "#A03B2A" }}>Merma con trazabilidad</div>
            <div className="display text-xl mt-1" style={{ color: T.choco }}>{desecharVencido.itemName}</div>
            <div className="text-sm mt-1" style={{ color: T.choco2 }}>
              Se retirarán <b>{desecharVencido.available} {desecharVencido.unit}</b> del {desecharVencido.id ? `lote ${desecharVencido.id}, ` : ""}vencido el {desecharVencido.expiresAt}. El insumo seguirá visible y el movimiento quedará en el historial.
            </div>
          </div>
          <Field label="Motivo del desecho"><Input value={motivoDesecho} onChange={(e) => setMotivoDesecho(e.target.value)} placeholder="Ej: olor alterado, vencimiento, cadena de frío" /></Field>
          <div className="flex gap-2 mt-2">
            <BtnAsync kind="danger" textoEnVuelo="Desechando…" disabled={enviando} onClick={async () => {
              const stockActual = Number(desecharVencido.available);
              const nombreDesecho = desecharVencido.nombre;
              if (!(stockActual > 0)) {
                setDesecharVencido(null);
                setAvisoInv({ titulo: "Sin stock para desechar", texto: "Este insumo ya está en cero." });
                return;
              }
              if (!motivoDesecho.trim()) {
                setAvisoInv({ titulo: "Falta el motivo", texto: "Indicá por qué se desecha para conservar la trazabilidad de la merma." });
                return;
              }
              setEnviando(true);
              try {
                if (desecharVencido.id && db.inventoryLotsReady) {
                  await desecharLoteInsumo(desecharVencido.id, motivoDesecho.trim());
                } else {
                  await movimientoInsumo(
                    desecharVencido.itemId,
                    "Merma",
                    -stockActual,
                    `Desecho por vencimiento ${desecharVencido.expiresAt} · ${motivoDesecho.trim()}`,
                  );
                }
              } catch (e) {
                toast("error", "No se pudo desechar el insumo: " + e.message);
                setEnviando(false);
                return;
              }
              setEnviando(false);
              setDesecharVencido(null);
              setMotivoDesecho("");
              toast("ok", `✓ Merma registrada · ${nombreDesecho}`);
              await refrescarSilencioso(() => toast("alert", "El stock quedó retirado, pero no se pudo actualizar la vista. Recargá la página."));
            }}>Confirmar desecho</BtnAsync>
            <Btn kind="ghost" disabled={enviando} onClick={() => setDesecharVencido(null)}>Conservar insumo</Btn>
          </div>
        </Modal>
      )}

      {avisoInv && (
        <Modal title={avisoInv.titulo} onClose={() => setAvisoInv(null)}>
          <p className="text-sm m-0">{avisoInv.texto}</p>
          <div className="mt-4"><Btn onClick={() => setAvisoInv(null)}>Entendido</Btn></div>
        </Modal>
      )}
    </div>
  );
}

/* ================= PRODUCTOS Y MENÚ ================= */

const CAT_EMOJI = { "Momos Signature": "🐱", "Cajas y Combos": "🎁", "Momos Cuchara": "🥄", "Momos Antojos": "🥞", "Momos Bebidas": "🥤" };

function nuevoProductoVacio() {
  return { nombre: "", cat: "Momos Signature", tipo: "momo", especie: "gato", precio: "", precioRappi: "", costo: "", prep: "", frio: true, lejano: false, desc: "", comboSize: "", componentProductIds: [], empaqueItem: "", colchonProduccion: 0 };
}

function Productos({ db, user, refrescar, serverDataReady }) {
  const cats = ["Momos Signature","Cajas y Combos","Momos Cuchara","Momos Antojos","Momos Bebidas"];
  const [detalleProductoId, setDetalleProductoId] = useState(null);
  const [recetaDe, setRecetaDe] = useState(null); // productId con receta abierta
  const [linea, setLinea] = useState({ itemId: "", cantidad: "" });
  const [abrirForm, setAbrirForm] = useState(false);
  const [editandoProd, setEditandoProd] = useState(null);
  const [form, setForm] = useState(nuevoProductoVacio());
  const [errProd, setErrProd] = useState("");
  const [recetaDraft, setRecetaDraft] = useState([]);
  const [recetaSucia, setRecetaSucia] = useState(false);
  const [errReceta, setErrReceta] = useState("");
  const [guardandoReceta, setGuardandoReceta] = useState(false);
  const [fCatProd, setFCatProd] = useState("");

  const prodReceta = recetaDe ? db.products.find((p) => p.id === recetaDe) : null;
  const detalleProducto = detalleProductoId ? db.products.find((p) => p.id === detalleProductoId) : null;
  const puedeEditar = user === "Administrador" && serverDataReady && Boolean(db.productsServerReady);
  const costoRecetaDraft = recetaDraft.reduce((total, line) => {
    const item = db.inventory_items.find((candidate) => candidate.id === line.itemId);
    return total + Number(line.cantidad || 0) * Number(item?.costo || 0);
  }, 0);

  function abrirRecetaProducto(product) {
    setLinea({ itemId: "", cantidad: "" });
    setRecetaDraft(recipeLines(db, product.id).map((line) => ({ ...line })));
    setRecetaSucia(false);
    setErrReceta("");
    setRecetaDe(product.id);
  }

  function abrirEdicionProducto(product) {
    setEditandoProd(product);
    setForm({ nombre: product.nombre, cat: product.cat, tipo: product.tipo, especie: product.especie || "gato", precio: product.precio, precioRappi: product.precioRappi, costo: product.costo, prep: product.prep, frio: !!product.frio, lejano: !!product.lejano, desc: product.desc || "", comboSize: product.comboSize || "", componentProductIds: [...(product.componentProductIds || [])], empaqueItem: product.empaqueItem || "", colchonProduccion: product.colchonProduccion ?? 0 });
    setErrProd("");
    setAbrirForm(true);
  }

  async function cambiarProductoActivo(product) {
    try { await setProductoActivo(product.id, !product.activo); toast("ok", product.activo ? "Producto desactivado del menú." : "Producto activado en el menú."); }
    catch (error) { toast("error", error.message); return; }
    try { await refrescar(); }
    catch { toast("error", "Se actualizó, pero no se pudo refrescar la lista."); }
  }

  function payloadProducto() {
    return {
      nombre: form.nombre.trim(), cat: form.cat, tipo: form.tipo,
      especie: form.tipo === "momo" ? form.especie : null,
      precio: Number(form.precio), precio_rappi: Number(form.precioRappi) || null,
      costo: Number(form.costo), prep: Number(form.prep) || 0,
      frio: Boolean(form.frio), lejano: Boolean(form.lejano), descr: form.desc || "",
      combo_size: form.tipo === "combo" ? Number(form.comboSize) : null,
      component_product_ids: form.tipo === "combo" ? [...(form.componentProductIds || [])] : [],
      empaque_item_id: form.tipo === "combo" ? form.empaqueItem : null,
      colchon_produccion: form.tipo === "momo" ? Number(form.colchonProduccion) || 0 : 0,
    };
  }

  async function guardarNuevo() {
    const nombre = form.nombre.trim();
    if (!nombre) { setErrProd("Falta el nombre"); return; }
    if (!(+form.precio > 0)) { setErrProd("Precio inválido"); return; }
    if (!(+form.costo >= 0)) { setErrProd("Costo inválido"); return; }
    if (form.tipo === "momo" && !["gato","perro"].includes(form.especie)) { setErrProd("Elegí la especie del momo."); return; }
    if (form.tipo === "combo") {
      if (!(+form.comboSize > 0)) { setErrProd("El combo necesita un tamaño (cuántos momos por caja)."); return; }
      if (!(form.componentProductIds || []).length) { setErrProd("Elegí al menos un momo componente."); return; }
      if (!form.empaqueItem) { setErrProd("Elegí la caja (empaque) del combo."); return; }
    }
    try {
      await crearProducto(payloadProducto());
      setAbrirForm(false);
      setErrProd("");
      toast("ok", "Producto creado.");
    } catch (error) { toast("error", error.message); return; }
    try { await refrescar(); }
    catch { toast("error", "Producto creado, pero no se pudo refrescar el catálogo."); }
  }

  async function guardarEdicion() {
    const nombre = form.nombre.trim();
    if (!nombre) { setErrProd("Falta el nombre"); return; }
    if (!(+form.precio > 0)) { setErrProd("Precio inválido"); return; }
    if (!(+form.costo >= 0)) { setErrProd("Costo inválido"); return; }
    if (form.tipo === "momo" && !["gato","perro"].includes(form.especie)) { setErrProd("Elegí la especie del momo."); return; }
    if (form.tipo === "combo") {
      if (!(+form.comboSize > 0)) { setErrProd("El combo necesita un tamaño (cuántos momos por caja)."); return; }
      if (!(form.componentProductIds || []).length) { setErrProd("Elegí al menos un momo componente."); return; }
      if (!form.empaqueItem) { setErrProd("Elegí la caja (empaque) del combo."); return; }
    }
    try {
      await editarProducto(editandoProd.id, payloadProducto());
      setAbrirForm(false);
      setErrProd("");
      toast("ok", "Producto actualizado.");
    } catch (error) { toast("error", error.message); return; }
    try { await refrescar(); }
    catch { toast("error", "Producto actualizado, pero no se pudo refrescar el catálogo."); }
  }

  const totalProductos = db.products.length;
  const productosActivos = db.products.filter((p) => p.activo).length;
  const productosSinReceta = db.products.filter((p) => recipeLines(db, p.id).length === 0).length;

  return (
    <div>
      <SectionTitle>Catálogo de productos</SectionTitle>
      <div className="text-xs font-semibold mb-3 -mt-3" style={{ color: T.choco2 }}>
        🧾 Cada producto puede tener una receta (insumos por unidad). Al registrar un lote o al pasar a "En producción" un producto que se prepara al momento, los insumos se descuentan solos del inventario.
      </div>
      {!puedeEditar && <div className="text-xs font-bold p-2.5 rounded-xl mb-2" style={{ background: T.vainilla, color: T.choco2 }}>{user === "Administrador" && !db.productsServerReady ? "Catálogo en modo consulta hasta aplicar la migración 13 de Productos." : "Catálogo en modo consulta. Solo Administrador puede modificar productos y recetas."}</div>}
      {!abrirForm && errProd && <div className="text-sm font-bold p-2.5 rounded-xl mb-2" style={{ background: "#F6D4CD", color: "#A03B2A" }}>{errProd}</div>}
      <div className="grid grid-cols-2 lg:grid-cols-4 gap-3">
        <Stat icon="🧾" label="Productos" value={totalProductos} sub="en catálogo" tone={T.coral} />
        <Stat icon="✅" label="Activos" value={productosActivos} sub="a la venta" tone="#3F6B42" />
        <Stat icon="⚠️" label="Sin receta" value={productosSinReceta} sub="no descuentan insumos" tone="#96690F" />
        <Stat icon="📈" label="Margen prom." value={totalProductos ? pct(db.products.reduce((s, p) => s + (p.precio - p.costo) / p.precio, 0) / totalProductos) : "—"} sub="precio vs. costo" />
      </div>
      <div className="text-[11px] font-semibold mt-2 mb-4" style={{ color: T.choco2 }}>
        <b style={{ color: T.coral }}>{productosActivos}</b> activos de {totalProductos} · {productosSinReceta} sin receta.
      </div>

      <div className="flex flex-wrap items-center gap-2 mb-3">
        {puedeEditar && <Btn small kind="rosa" onClick={() => { setForm(nuevoProductoVacio()); setEditandoProd(null); setErrProd(""); setAbrirForm(true); }}>＋ Nuevo producto</Btn>}
      </div>

      <div className="momo-segmented-tabs inline-flex max-w-full gap-1 overflow-x-auto p-1.5 mb-4 rounded-2xl" role="tablist" aria-label="Categorías de productos">
        {[["Todas", ""], ...cats.map((c) => [c, c])].map(([label, value]) => {
          const count = value ? db.products.filter((p) => p.cat === value).length : totalProductos;
          const activo = fCatProd === value;
          return (
            <button key={label} type="button" role="tab" aria-selected={activo} onClick={() => setFCatProd(value)}
              className="momo-segmented-tab shrink-0 rounded-xl px-3 py-2 text-xs font-bold border-0"
              style={activo ? { background: T.coral, color: "#fff" } : { background: "transparent", color: T.choco2 }}>
              {value ? `${CAT_EMOJI[value] || ""} ${label}`.trim() : label} <span className="ml-1 inline-flex min-w-5 h-5 px-1 rounded-full items-center justify-center text-[10px]" style={{ background: activo ? "rgba(255,255,255,.2)" : "#fff" }}>{count}</span>
            </button>
          );
        })}
      </div>
      {cats.filter((cat) => !fCatProd || cat === fCatProd).map((cat) => (
        <div key={cat}>
          <SectionTitle>{CAT_EMOJI[cat]} {cat}</SectionTitle>
          <div className="grid sm:grid-cols-2 lg:grid-cols-3 gap-3">
            {db.products.filter((p) => p.cat === cat).map((p) => {
              const margen = (p.precio - p.costo) / p.precio;
              const disp = availability(db, p);
              const recipeCount = recipeLines(db, p.id).length;
              return (
                <Card key={p.id} className={`momo-queue-item p-4 ${!p.activo ? "opacity-60" : ""}`} onClick={() => setDetalleProductoId(p.id)} aria-label={`Abrir detalle de ${p.nombre}`}>
                  <div className="flex items-start justify-between gap-3"><div className="flex items-start gap-2.5 min-w-0"><span className="w-9 h-9 rounded-xl flex items-center justify-center shrink-0 text-lg" style={{ background: T.rosa }} aria-hidden="true">{CAT_EMOJI[cat]}</span><div className="min-w-0"><div className="font-bold text-sm leading-tight">{p.nombre}</div><div className="text-[10px] font-extrabold uppercase tracking-wider mt-1" style={{ color: p.activo ? "#3F6B42" : T.choco2 }}>{p.activo ? "Activo en el menú" : "Fuera del menú"}</div></div></div><div className="display text-lg shrink-0" style={{ color: T.coral }}>{fmt(p.precio)}</div></div>
                  <div className="flex items-end justify-between gap-3 mt-3"><div><div className="text-xs font-bold" style={{ color: margen > 0.6 ? "#3F6B42" : "#96690F" }}>Margen {pct(margen)}</div><div className="text-[11px] font-semibold mt-0.5" style={{ color: T.choco2 }}>{recipeCount ? `Receta con ${recipeCount} insumo${recipeCount === 1 ? "" : "s"}` : "Sin receta registrada"}</div></div><div className="text-right text-xs font-extrabold" style={{ color: isFinite(disp) && disp <= 2 ? "#A03B2A" : T.choco2 }}>{isFinite(disp) ? `${disp} disp.` : "Bajo pedido"}</div></div>
                  <div className="flex items-center justify-between gap-3 mt-3 pt-3 border-t text-[11px] font-bold" style={{ borderColor: T.border, color: T.choco2 }}><span>{p.tipo === "combo" ? "Combo" : p.tipo === "momo" ? "Momo" : "Preparación al momento"}{p.frio ? " · requiere frío" : ""}</span><span style={{ color: T.coral }}>Abrir detalle ›</span></div>
                </Card>
              );
            })}
          </div>
        </div>
      ))}

      {detalleProducto && (() => {
        const lines = recipeLines(db, detalleProducto.id);
        const margen = detalleProducto.precio > 0 ? (detalleProducto.precio - detalleProducto.costo) / detalleProducto.precio : 0;
        const disp = availability(db, detalleProducto);
        const comboProducts = (detalleProducto.componentProductIds || []).map((id) => db.products.find((product) => product.id === id)?.nombre).filter(Boolean);
        const pack = db.inventory_items.find((item) => item.id === detalleProducto.empaqueItem);
        return (
          <Modal title={`Producto · ${detalleProducto.nombre}`} onClose={() => setDetalleProductoId(null)} wide>
            <div className="flex flex-wrap items-start justify-between gap-3 mb-4">
              <div><div className="text-[10px] uppercase tracking-[.14em] font-extrabold" style={{ color: T.coral }}>{CAT_EMOJI[detalleProducto.cat]} {detalleProducto.cat}</div><div className="display text-2xl font-semibold mt-0.5">{detalleProducto.nombre}</div><div className="text-sm font-semibold mt-1 max-w-2xl" style={{ color: T.choco2 }}>{detalleProducto.desc || "Sin descripción comercial registrada."}</div></div>
              <Badge label={detalleProducto.activo ? "Activo" : "Inactivo"} map={{ Activo: { bg: "#DDEBD9", fg: "#3F6B42" }, Inactivo: { bg: "#EBE6E0", fg: "#7A6E63" } }} />
            </div>

            <div className="grid grid-cols-2 lg:grid-cols-4 gap-3 mb-4">
              <Stat icon="$" label="Precio directo" value={fmt(detalleProducto.precio)} sub="precio de venta" tone={T.coral} />
              <Stat icon="R" label="Precio Rappi" value={fmt(detalleProducto.precioRappi)} sub="canal plataforma" tone="#63518A" />
              <Stat icon="◒" label="Costo" value={fmt(detalleProducto.costo)} sub="registrado" tone={T.choco} />
              <Stat icon="↗" label="Margen" value={pct(margen)} sub="precio vs. costo" tone={margen > 0.6 ? "#3F6B42" : "#96690F"} />
            </div>

            <div className="grid lg:grid-cols-[1.05fr_.95fr] gap-3 mb-4">
              <Card className="p-4">
                <div className="text-xs font-extrabold mb-3" style={{ color: T.choco2 }}>OPERACIÓN Y VENTA</div>
                <div className="grid grid-cols-2 gap-x-4 gap-y-3 text-xs">
                  <div><div className="font-semibold" style={{ color: T.choco2 }}>Tipo</div><div className="font-bold mt-0.5">{detalleProducto.tipo === "momo" ? `Momo · ${detalleProducto.especie || "especie sin registrar"}` : detalleProducto.tipo === "combo" ? "Caja / combo" : "Preparación al momento"}</div></div>
                  <div><div className="font-semibold" style={{ color: T.choco2 }}>Disponibilidad</div><div className="font-bold mt-0.5" style={{ color: isFinite(disp) && disp <= 2 ? "#A03B2A" : "#3F6B42" }}>{isFinite(disp) ? `${disp} unidades` : "Bajo pedido"}</div></div>
                  <div><div className="font-semibold" style={{ color: T.choco2 }}>Preparación</div><div className="font-bold mt-0.5">{detalleProducto.prep || 0} min</div></div>
                  <div><div className="font-semibold" style={{ color: T.choco2 }}>Cadena de frío</div><div className="font-bold mt-0.5">{detalleProducto.frio ? "Requerida" : "No requerida"}</div></div>
                  <div><div className="font-semibold" style={{ color: T.choco2 }}>Domicilio lejano</div><div className="font-bold mt-0.5">{detalleProducto.lejano ? "Permitido" : "Solo zona cercana"}</div></div>
                  {detalleProducto.tipo === "momo" && <div><div className="font-semibold" style={{ color: T.choco2 }}>Colchón producción</div><div className="font-bold mt-0.5">{detalleProducto.colchonProduccion || 0} unidades</div></div>}
                </div>
                {detalleProducto.tipo === "combo" && <div className="mt-4 pt-3 border-t" style={{ borderColor: T.border }}><div className="text-[10px] uppercase tracking-wider font-extrabold" style={{ color: T.choco2 }}>Composición permitida</div><div className="text-xs font-bold mt-1">{detalleProducto.comboSize || 0} momos · caja {pack?.nombre || "sin configurar"}</div><div className="text-xs font-semibold mt-1" style={{ color: T.choco2 }}>{comboProducts.join(" · ") || "Sin productos componentes"}</div></div>}
              </Card>

              <Card className="p-4">
                <div className="flex items-start justify-between gap-3 mb-3"><div><div className="text-xs font-extrabold" style={{ color: T.choco2 }}>RECETA POR UNIDAD</div><div className="text-[11px] font-semibold mt-0.5" style={{ color: T.choco2 }}>{lines.length ? `${lines.length} insumo${lines.length === 1 ? "" : "s"} vinculados` : "No descuenta inventario todavía"}</div></div><span className="display text-lg" style={{ color: T.coral }}>{fmt(recipeCost(db, detalleProducto.id))}</span></div>
                <div className="space-y-2">{lines.slice(0, 6).map((line) => { const item = db.inventory_items.find((candidate) => candidate.id === line.itemId); return <div key={line.id || line.itemId} className="rounded-xl px-3 py-2 flex items-center justify-between gap-3 text-xs" style={{ background: T.vainilla }}><span className="font-bold">{item?.nombre || "Insumo no encontrado"}</span><span className="font-extrabold shrink-0" style={{ color: T.choco2 }}>{line.cantidad} {item?.unidad || ""}</span></div>; })}{lines.length === 0 && <div className="rounded-xl p-3 text-xs font-semibold" style={{ background: "#FBE8C8", color: "#7A5410" }}>Falta registrar la receta para tener costo y descuento de inventario trazables.</div>}{lines.length > 6 && <div className="text-[10px] font-bold" style={{ color: T.choco2 }}>＋ {lines.length - 6} insumo(s) más en la receta completa.</div>}</div>
                {lines.length > 0 && <div className="text-[10px] font-bold mt-3" style={{ color: Math.abs(recipeCost(db, detalleProducto.id) - detalleProducto.costo) > detalleProducto.costo * 0.15 ? "#96690F" : "#3F6B42" }}>Costo receta {fmt(recipeCost(db, detalleProducto.id))} · registrado {fmt(detalleProducto.costo)}</div>}
              </Card>
            </div>

            <div className="flex flex-wrap gap-2 pt-4 border-t" style={{ borderColor: T.border }}>
              <Btn kind="rosa" onClick={() => abrirRecetaProducto(detalleProducto)}>🧾 Abrir receta completa</Btn>
              {puedeEditar && <Btn kind="ghost" onClick={() => abrirEdicionProducto(detalleProducto)}>✏️ Editar producto</Btn>}
              {puedeEditar && <BtnAsync kind={detalleProducto.activo ? "ghost" : "soft"} textoEnVuelo={detalleProducto.activo ? "Desactivando…" : "Activando…"} onClick={() => cambiarProductoActivo(detalleProducto)}>{detalleProducto.activo ? "Desactivar del menú" : "Activar en el menú"}</BtnAsync>}
            </div>
          </Modal>
        );
      })()}

      {abrirForm && (
        <Modal title={editandoProd ? "Editar producto" : "Nuevo producto"} onClose={() => setAbrirForm(false)}>
          <Field label="Nombre"><Input value={form.nombre} onChange={(e) => setForm({ ...form, nombre: e.target.value })} /></Field>
          <Field label="Categoría">
            <Select options={cats} value={form.cat} onChange={(e) => setForm({ ...form, cat: e.target.value })} />
          </Field>
          <Field label="Tipo">
            {editandoProd
              ? <Select options={[form.tipo]} value={form.tipo} disabled onChange={() => {}} />
              : <Select options={["momo", "pedido", "combo"]} value={form.tipo} onChange={(e) => setForm((f) => ({ ...f, tipo: e.target.value }))} />}
          </Field>
          {form.tipo === "momo" && <Field label="Especie"><Select options={["gato","perro"]} value={form.especie} onChange={(e) => setForm({ ...form, especie: e.target.value })} /></Field>}
          <div className="grid grid-cols-2 gap-2">
            <Field label="Precio"><Input type="number" min="0" value={form.precio} onChange={(e) => setForm({ ...form, precio: e.target.value })} /></Field>
            <Field label="Precio Rappi"><Input type="number" min="0" value={form.precioRappi} onChange={(e) => setForm({ ...form, precioRappi: e.target.value })} /></Field>
            <Field label="Costo"><Input type="number" min="0" value={form.costo} onChange={(e) => setForm({ ...form, costo: e.target.value })} /></Field>
            <Field label="Prep (min)"><Input type="number" min="0" value={form.prep} onChange={(e) => setForm({ ...form, prep: e.target.value })} /></Field>
          </div>
          <div className="grid grid-cols-2 gap-2">
            <Field label="Requiere frío"><Select options={["Sí", "No"]} value={form.frio ? "Sí" : "No"} onChange={(e) => setForm({ ...form, frio: e.target.value === "Sí" })} /></Field>
            <Field label="Apto domicilio lejano"><Select options={["Sí", "No"]} value={form.lejano ? "Sí" : "No"} onChange={(e) => setForm({ ...form, lejano: e.target.value === "Sí" })} /></Field>
          </div>
          {editandoProd && form.tipo === "momo" && user === "Administrador" && (
            <Field label="🛡️ Colchón de producción (unidades extra por corrida — absorbe imperfectas y mostrador)">
              <Input type="number" min="0" step="1" value={form.colchonProduccion ?? 0} onChange={(e) => setForm({ ...form, colchonProduccion: Math.max(0, parseInt(e.target.value, 10) || 0) })} />
            </Field>
          )}
          <Field label="Descripción"><Input value={form.desc} onChange={(e) => setForm({ ...form, desc: e.target.value })} /></Field>
          {form.tipo === "combo" && (
            <div className="p-3 rounded-xl mb-3" style={{ background: T.vainilla }}>
              <div className="text-xs font-bold mb-2" style={{ color: T.choco2 }}>🎁 CONFIGURACIÓN DEL COMBO</div>
              <div className="grid grid-cols-2 gap-2">
                <Field label="Momos por caja"><Input type="number" min="1" value={form.comboSize} onChange={(e) => setForm({ ...form, comboSize: e.target.value })} /></Field>
                <Field label="Caja (empaque)">
                  <select value={form.empaqueItem} onChange={(e) => setForm({ ...form, empaqueItem: e.target.value })} className={inputCls} style={inputStyle}>
                    <option value="">Elegir caja…</option>
                    {db.inventory_items.filter((i) => i.cat === "Cajas").map((i) => <option key={i.id} value={i.id}>{i.nombre} · {i.stock} und</option>)}
                  </select>
                </Field>
              </div>
              <div className="text-[11px] font-bold mt-1 mb-1" style={{ color: T.choco2 }}>Momos que puede llevar (define las figuras disponibles al armar la caja):</div>
              <div className="flex flex-wrap gap-1.5">
                {db.products.filter((p) => p.tipo === "momo" && p.activo).map((p) => {
                  const on = (form.componentProductIds || []).includes(p.id);
                  return (
                    <button key={p.id} type="button" onClick={() => setForm((f) => {
                      const cur = f.componentProductIds || [];
                      return { ...f, componentProductIds: cur.includes(p.id) ? cur.filter((x) => x !== p.id) : [...cur, p.id] };
                    })} className="text-[11px] font-bold px-2.5 py-1 rounded-full"
                      style={{ background: on ? T.coral : T.surface, color: on ? "#fff" : T.choco2, border: "1px solid " + (on ? T.coral : T.border) }}>
                      {p.nombre} {momoEspecie(p) === "perro" ? "🐶" : "🐱"}
                    </button>
                  );
                })}
              </div>
            </div>
          )}
          <Field label="Atributos que pedirá al vender">
            <div className="flex gap-2 flex-wrap items-center">
              {atributosDeTipo(form.tipo).length === 0
                ? <span className="text-xs font-semibold" style={{ color: T.choco2 }}>Ninguno — se vende tal cual (sin sabor/salsa/figura).</span>
                : atributosDeTipo(form.tipo).map((key) => (
                    <span key={key} className="text-[11px] font-bold px-2.5 py-1 rounded-full" style={{ background: T.vainilla, color: T.choco2 }}>{ATRIBUTO_LABEL[key]}</span>
                  ))}
            </div>
            <div className="text-[11px] font-semibold mt-1.5" style={{ color: T.choco2 }}>
              Se derivan del tipo automáticamente. Un {form.tipo === "pedido" ? "granizado/crepa" : "momo"} no se puede configurar a mano.
            </div>
          </Field>
          {errProd && <div className="text-sm font-bold mb-3" style={{ color: T.coral }}>{errProd}</div>}
          <div className="flex justify-end">
            <BtnAsync kind="rosa" onClick={editandoProd ? guardarEdicion : guardarNuevo}>Guardar</BtnAsync>
          </div>
        </Modal>
      )}

      {prodReceta && (
        <Modal title={`Receta · ${prodReceta.nombre}`} onClose={() => setRecetaDe(null)} wide>
          <div className="text-xs font-semibold mb-3" style={{ color: T.choco2 }}>
            Cantidades por <b>1 unidad</b> de producto. {prodReceta.tipo === "momo" ? "Se descuentan al registrar un lote de producción." : prodReceta.tipo === "pedido" ? "Se descuentan cuando el pedido pasa a \u201cEn producción\u201d." : "Los combos descuentan momos y cajas automáticamente; agrega aquí solo extras (lazo, tarjeta…)."}
          </div>

          {recetaDraft.length === 0 && (
            <div className="text-sm font-semibold mb-3 p-3 rounded-xl" style={{ background: T.vainilla, color: T.choco2 }}>
              Este producto aún no tiene receta. Agrega el primer insumo abajo.
            </div>
          )}

          {recetaDraft.map((l) => {
            const it = db.inventory_items.find((i) => i.id === l.itemId);
            if (!it) return null;
            return (
              <Card key={l.id} className="p-3 mb-2 flex items-center justify-between gap-2 flex-wrap">
                <div className="min-w-0">
                  <div className="text-sm font-bold truncate">{it.nombre}</div>
                  <div className="text-xs" style={{ color: T.choco2 }}>{fmt(it.costo)}/{it.unidad} · stock {it.stock} {it.unidad}</div>
                </div>
                <div className="flex items-center gap-2 shrink-0">
                  <input type="number" min="0" step="0.01" value={l.cantidad}
                    disabled={!puedeEditar}
                    onChange={(e) => { setRecetaDraft((lines) => lines.map((line) => line.itemId === l.itemId ? { ...line, cantidad: e.target.value } : line)); setRecetaSucia(true); }}
                    className="w-20 rounded-xl px-2 py-1.5 text-sm border text-right font-bold" style={inputStyle} aria-label={`Cantidad de ${it.nombre}`} />
                  <span className="text-xs font-bold" style={{ color: T.choco2 }}>{it.unidad}</span>
                  <span className="text-xs font-bold w-16 text-right">{fmt(it.costo * l.cantidad)}</span>
                  {puedeEditar && <button aria-label={`Quitar ${it.nombre}`} onClick={() => { setRecetaDraft((lines) => lines.filter((line) => line.itemId !== l.itemId)); setRecetaSucia(true); }} className="w-7 h-7 rounded-full font-bold text-xs" style={{ background: "#F6D4CD", color: "#A03B2A" }}>✕</button>}
                </div>
              </Card>
            );
          })}

          {puedeEditar && <Card className="p-3 mb-3">
            <div className="text-xs font-bold mb-2" style={{ color: T.choco2 }}>AGREGAR INSUMO A LA RECETA</div>
            <div className="flex flex-wrap gap-2 items-center">
              <select value={linea.itemId} onChange={(e) => setLinea({ ...linea, itemId: e.target.value })} className="flex-1 min-w-[160px] rounded-xl px-2 py-2 text-sm border font-semibold" style={inputStyle}>
                <option value="">Elegir insumo…</option>
                {db.inventory_items.filter((i) => !recetaDraft.some((l) => l.itemId === i.id)).map((i) => (
                  <option key={i.id} value={i.id}>{i.nombre} ({i.unidad})</option>
                ))}
              </select>
              <input type="number" min="0" step="0.01" value={linea.cantidad} onChange={(e) => setLinea({ ...linea, cantidad: e.target.value })}
                placeholder="Cant." className="w-24 rounded-xl px-2 py-2 text-sm border text-right font-bold" style={inputStyle} aria-label="Cantidad por unidad" />
              <Btn small kind="rosa" onClick={() => {
                if (!linea.itemId || !parseFloat(linea.cantidad)) return;
                setRecetaDraft((lines) => [...lines,{ id: `draft-${linea.itemId}`, productId: prodReceta.id, itemId: linea.itemId, cantidad: parseFloat(linea.cantidad) }]);
                setRecetaSucia(true);
                setLinea({ itemId: "", cantidad: "" });
              }}>＋ Agregar</Btn>
            </div>
            <div className="text-[11px] font-semibold mt-2" style={{ color: T.choco2 }}>¿No está el insumo? Créalo primero en Inventario → ＋ Nuevo insumo.</div>
          </Card>}

          {errReceta && <div className="text-sm font-bold p-2.5 rounded-xl mb-3" style={{ background: "#F6D4CD", color: "#A03B2A" }}>{errReceta}</div>}
          {puedeEditar && <div className="flex justify-end mb-3">
            <BtnAsync kind="rosa" disabled={!recetaSucia || guardandoReceta} textoEnVuelo="Guardando receta…" onClick={async () => {
              if (recetaDraft.some((line) => !(Number(line.cantidad)>0))) { setErrReceta("Todas las cantidades deben ser mayores que cero."); return; }
              setGuardandoReceta(true); setErrReceta("");
              try {
                await guardarRecetaProducto(prodReceta.id, recetaDraft);
                setRecetaSucia(false);
                toast("ok", "Receta guardada.");
              } catch (error) { toast("error", error.message); setGuardandoReceta(false); return; }
              try { await refrescar(); }
              catch { toast("error", "Receta guardada, pero no se pudo refrescar."); }
              finally { setGuardandoReceta(false); }
            }}>{recetaSucia ? "Guardar receta" : "Receta guardada ✓"}</BtnAsync>
          </div>}

          <Card className="p-4">
            <div className="flex justify-between items-center text-sm">
              <span className="font-semibold">Costo estimado por receta (1 unidad)</span>
              <b className="display text-lg" style={{ color: T.coral }}>{fmt(costoRecetaDraft)}</b>
            </div>
            <div className="flex justify-between items-center text-xs mt-1" style={{ color: T.choco2 }}>
              <span>Costo registrado del producto</span><b>{fmt(prodReceta.costo)}</b>
            </div>
            {puedeEditar && recetaDraft.length > 0 && Math.round(costoRecetaDraft) !== prodReceta.costo && (
              <div className="mt-3">
                <BtnAsync small kind="soft" disabled={recetaSucia || guardandoReceta} textoEnVuelo="Actualizando costo…" onClick={async () => {
                  setGuardandoReceta(true); setErrReceta("");
                  try { await sincronizarCostoProducto(prodReceta.id); toast("ok", "Costo del producto actualizado."); }
                  catch (error) { toast("error", error.message); setGuardandoReceta(false); return; }
                  try { await refrescar(); }
                  catch { toast("error", "Costo actualizado, pero no se pudo refrescar."); }
                  finally { setGuardandoReceta(false); }
                }}>Actualizar costo del producto con la receta</BtnAsync>
              </div>
            )}
          </Card>
        </Modal>
      )}
    </div>
  );
}

/* ================= DOMICILIOS ================= */

const DOM_ESTADOS = ["Por solicitar","Solicitado","Asignado","En ruta","Entregado","Problema","Cancelado"];

function Domicilios({ db, update, user, refrescar }) {
  const [nuevo, setNuevo] = useState(false);
  const [avisoDom, setAvisoDom] = useState(null);
  const [enviando, setEnviando] = useState(false);
  const s = db.settings;
  const [form, setForm] = useState({ orderId: "", proveedor: s.proveedores[0], costoReal: "", zona: s.zonas[0].nombre, obs: "" });
  const [scope, setScope] = useState("active");
  const deliveryBuckets = useMemo(() => partitionByActivity(db.deliveries, isActiveDelivery), [db.deliveries]);
  const listaDomicilios = scope === "active" ? deliveryBuckets.active : deliveryBuckets.history;

  const subsidio = db.deliveries.reduce((sm, d) => sm + Math.max(0, d.costoReal - d.cobrado), 0);
  const excedente = db.deliveries.reduce((sm, d) => sm + Math.max(0, d.cobrado - d.costoReal), 0);
  const pedidosSinDomicilio = db.orders
    .filter((o) => !["Entregado", "Cancelado"].includes(o.estado))
    .filter((o) => o.canal !== "Rappi")
    .filter((o) => !db.deliveries.some((delivery) => delivery.orderId === o.id && deliveryBlocksNewRequest(delivery)));
  const pendientes = pedidosSinDomicilio.filter((o) => ["Empacado","Listo para despacho"].includes(o.estado));

  function exportar() {
    downloadCSV("domicilios",
      ["ID","Pedido","Proveedor","Zona","Cobrado","Costo real","Diferencia","Solicitud","Salida","Entrega","Código","Estado"],
      listaDomicilios.map((d) => [d.id, d.orderId, d.proveedor, d.zona, d.cobrado, d.costoReal, d.cobrado - d.costoReal, d.hSolicitud, d.hSalida, d.hEntrega, d.codigo, d.estado]));
  }

  return (
    <div>
      <div className="grid grid-cols-2 lg:grid-cols-4 gap-3 mb-4">
        <Stat icon="🛵" label="Domicilios activos" value={deliveryBuckets.active.length} onClick={() => { setScope("active"); setTimeout(() => { const el = document.getElementById("lista-domicilios"); if (el) el.scrollIntoView({ behavior: "smooth", block: "start" }); }, 0); }} active={scope === "active"} />
        <Stat icon="🧾" label="Subsidio acumulado" value={fmt(subsidio)} sub="cobramos menos que el costo" tone="#A03B2A" />
        <Stat icon="💰" label="Excedente cobrado" value={fmt(excedente)} sub="cobramos más que el costo" tone="#3F6B42" />
        <Stat icon="📦" label="Listos sin domicilio" value={pendientes.length} sub="pedidos por solicitar" tone={pendientes.length ? "#96690F" : undefined} />
      </div>

      <div className="mb-4 flex flex-wrap gap-2">
        <Btn onClick={() => { setForm((actual) => ({ ...actual, orderId: "" })); setNuevo(true); }}>＋ Solicitar domicilio</Btn>
        <WorkScopeTabs value={scope} onChange={setScope} activeCount={deliveryBuckets.active.length} historyCount={deliveryBuckets.history.length} activeLabel="En seguimiento" />
        <Btn small kind="ghost" onClick={exportar}>⬇ CSV</Btn>
      </div>

      {pendientes.length > 0 && (
        <div className="text-xs font-bold p-2.5 rounded-xl mb-3" style={{ background: "#FBE8C8", color: "#96690F" }}>
          ⏰ Pedidos listos esperando domicilio: {pendientes.map((o) => o.id).join(", ")}
        </div>
      )}

      <div id="lista-domicilios" />
      <SectionTitle>{scope === "active" ? "Entregas en seguimiento" : "Historial de domicilios"}</SectionTitle>
      <div className="grid lg:grid-cols-2 gap-3">
        {listaDomicilios.map((d) => {
          const dif = d.cobrado - d.costoReal;
          return (
            <Card key={d.id} className="p-4">
              <div className="flex justify-between items-start gap-2">
                <div>
                  <div className="font-bold">{d.id} · Pedido {d.orderId}</div>
                  <div className="text-xs" style={{ color: T.choco2 }}>{d.proveedor} · {d.zona} · Código {d.codigo || "—"}</div>
                </div>
                <Badge label={d.estado} />
              </div>
              <div className="grid grid-cols-3 gap-2 mt-3 text-center">
                {[["Solicitud", d.hSolicitud || "—"], ["Salida", d.hSalida || "—"], ["Entrega", d.hEntrega || "—"]].map(([l, v]) => (
                  <div key={l} className="rounded-xl py-1.5" style={{ background: T.vainilla }}>
                    <div className="text-sm font-bold">{v}</div>
                    <div className="text-[10px] font-bold" style={{ color: T.choco2 }}>{l}</div>
                  </div>
                ))}
              </div>
              <div className="flex flex-wrap justify-between items-center gap-2 mt-3">
                <div className="text-xs font-semibold" style={{ color: T.choco2 }}>
                  Cobrado {fmt(d.cobrado)} · Costo {fmt(d.costoReal)} ·{" "}
                  <b style={{ color: dif < 0 ? "#A03B2A" : "#3F6B42" }}>{dif < 0 ? `subsidio ${fmt(-dif)}` : dif > 0 ? `excedente ${fmt(dif)}` : "sin diferencia"}</b>
                </div>
                <MiniSelect options={DOM_ESTADOS} value={d.estado} disabled={enviando || scope === "history"} onChange={async (e) => {
                  const nuevo = e.target.value;
                  setEnviando(true);
                  // "En ruta"/"Entregado" son dominio del PEDIDO: set_order_status sincroniza pedido+domicilio+sellos server-side.
                  if (nuevo === "En ruta" || nuevo === "Entregado") {
                    try {
                      await setOrderStatusRemoto(d.orderId, nuevo);
                    } catch (err) {
                      setAvisoDom({ titulo: "No se puede despachar todavía", texto: err.message });
                      setEnviando(false);
                      return;
                    }
                    try {
                      await refrescar();
                    } catch (err) {
                      setAvisoDom({ titulo: "Acción aplicada, vista desactualizada", texto: "El domicilio se actualizó correctamente, pero no se pudo actualizar la vista. Recargá la página para verlo." });
                    }
                    setEnviando(false);
                    return;
                  }
                  try {
                    await actualizarDomicilio(d.id, { estado: nuevo });
                  } catch (err) {
                    setAvisoDom({ titulo: "No se pudo actualizar el domicilio", texto: err.message });
                    setEnviando(false);
                    return;
                  }
                  try {
                    await refrescar();
                  } catch (err) {
                    setAvisoDom({ titulo: "Acción aplicada, vista desactualizada", texto: "El domicilio se actualizó correctamente, pero no se pudo actualizar la vista. Recargá la página para verlo." });
                  }
                  setEnviando(false);
                }} />
              </div>
              {d.obs && <div className="text-xs mt-2" style={{ color: T.choco2 }}>📝 {d.obs}</div>}
            </Card>
          );
        })}
        {!listaDomicilios.length && <Empty icon={scope === "active" ? "🛵" : "◷"} text={scope === "active" ? "No hay domicilios activos." : "Todavía no hay domicilios entregados o cancelados."} />}
      </div>

      {nuevo && (
        <Modal title="Solicitar domicilio" onClose={() => setNuevo(false)}>
          <Field label="Pedido">
            <Select placeholder="Elegir pedido…" options={pedidosSinDomicilio.map((o) => o.id)} value={form.orderId} onChange={(e) => {
              const o = db.orders.find((x) => x.id === e.target.value);
              setForm({ ...form, orderId: e.target.value, zona: o ? o.zona : form.zona });
            }} />
          </Field>
          <Field label="Proveedor"><Select options={s.proveedores} value={form.proveedor} onChange={(e) => setForm({ ...form, proveedor: e.target.value })} /></Field>
          <Field label="Zona"><Select options={s.zonas.map((z) => z.nombre)} value={form.zona} onChange={(e) => setForm({ ...form, zona: e.target.value })} /></Field>
          <Field label="Costo real cotizado"><Input type="number" min="0" value={form.costoReal} onChange={(e) => setForm({ ...form, costoReal: e.target.value })} /></Field>
          <Field label="Observaciones"><Input value={form.obs} onChange={(e) => setForm({ ...form, obs: e.target.value })} /></Field>
          <div className="flex gap-2 mt-2">
            <Btn disabled={enviando} onClick={async () => {
              if (!form.orderId) return;
              setEnviando(true);
              try {
                await crearDomicilio(form.orderId, form.proveedor, form.zona, Math.max(0, +form.costoReal || 0), form.obs);
              } catch (e) {
                setAvisoDom({ titulo: "No se pudo solicitar el domicilio", texto: e.message });
                setEnviando(false);
                return;
              }
              try {
                await refrescar();
              } catch (e) {
                setAvisoDom({ titulo: "Acción aplicada, vista desactualizada", texto: "El domicilio se solicitó correctamente, pero no se pudo actualizar la vista. Recargá la página para verlo." });
                setEnviando(false);
                setNuevo(false);
                return;
              }
              setEnviando(false);
              setNuevo(false);
            }}>Solicitar</Btn>
            <Btn kind="ghost" onClick={() => setNuevo(false)}>Cancelar</Btn>
          </div>
        </Modal>
      )}

      {avisoDom && (
        <Modal title={avisoDom.titulo} onClose={() => setAvisoDom(null)}>
          <p className="text-sm m-0">{avisoDom.texto}</p>
          <div className="mt-4"><Btn onClick={() => setAvisoDom(null)}>Entendido</Btn></div>
        </Modal>
      )}
    </div>
  );
}

/* ================= RECLAMOS ================= */

const RECLAMO_TIPOS = ["Producto faltante","Producto equivocado","Daño en entrega","Producto derretido","Error de sabor","Inconformidad de sabor","Retraso","Reclamo dudoso","Reclamo por calidad"];

function minutosEntre(a, b) {
  if (!a || !b || a === "—") return null;
  const [h1, m1] = a.split(":").map(Number); const [h2, m2] = b.split(":").map(Number);
  return (h2 * 60 + m2) - (h1 * 60 + m1);
}

// Minutos reales entre entrega y reclamo. Usa entregadoEn/reclamoEn (con fecha y hora);
// si faltan, cae al cálculo por horas hEntrega/hReclamo.
function minutosReclamo(r) {
  const ent = selloAMs(r.entregadoEn);
  const rec = selloAMs(r.reclamoEn);
  if (ent && rec) return Math.round((rec - ent) / 60000);
  return minutosEntre(r.hEntrega, r.hReclamo);
}

function Reclamos({ db, update, user, focus, refrescar }) {
  const [sel, setSel] = useState(null);
  const [aviso, setAviso] = useState(null);
  const [enviando, setEnviando] = useState(false);
  const claimBuckets = useMemo(() => partitionByActivity(db.claims, isActiveClaim), [db.claims]);
  const [scope, setScope] = useState(() => {
    const highlighted = focus?.claimId && db.claims.find((claim) => claim.id === focus.claimId);
    return highlighted && !isActiveClaim(highlighted) ? "history" : "active";
  });
  const listaReclamos = scope === "active" ? claimBuckets.active : claimBuckets.history;
  const highlightId = focus && focus.claimId;
  const highlightRef = useRef(null);
  useEffect(() => {
    if (highlightRef.current) highlightRef.current.scrollIntoView({ behavior: "smooth", block: "center" });
  }, [highlightId]);
  return (
    <div>
      <div className="text-xs font-bold p-2.5 rounded-xl mb-4" style={{ background: T.vainilla, color: T.choco2 }}>
        📋 Política: reclamos por estado del producto se aceptan máximo 20 minutos después de recibido, salvo calidad o inocuidad.
      </div>
      <div className="mb-4"><WorkScopeTabs value={scope} onChange={setScope} activeCount={claimBuckets.active.length} historyCount={claimBuckets.history.length} activeLabel="Casos activos" /></div>
      <SectionTitle>{scope === "active" ? "Casos por resolver" : "Historial de reclamos"}</SectionTitle>
      <div className="grid lg:grid-cols-2 gap-3">
        {listaReclamos.map((r) => {
          const c = customerOf(db, r.customerId);
          const min = minutosReclamo(r);
          const previos = db.claims.filter((x) => x.customerId === r.customerId && x.id !== r.id).length;
          const fuera = min !== null && min > 20;
          const hl = highlightId === r.id;
          return (
            <div key={r.id} ref={hl ? highlightRef : null} className="rounded-2xl" style={hl ? { boxShadow: `0 0 0 3px ${T.coral}` } : undefined}>
            <Card className="p-4">
              <div className="flex justify-between items-start gap-2">
                <div>
                  <div className="font-bold">{r.id} · {r.tipo}</div>
                  <div className="text-xs" style={{ color: T.choco2 }}>Pedido {r.orderId} · {c.nombre}</div>
                </div>
                <Badge label={r.estado} />
              </div>
              <div className="text-sm mt-2">{r.desc}</div>
              <div className="flex flex-wrap gap-1.5 mt-2">
                {min !== null && (
                  <span className="text-[10px] font-bold px-2 py-0.5 rounded-full" style={{ background: fuera ? "#F6D4CD" : "#DDEBD9", color: fuera ? "#A03B2A" : "#3F6B42" }}>
                    ⏱️ {min} min después de la entrega {fuera && "· fuera de ventana"}
                  </span>
                )}
                {previos > 0 && <span className="text-[10px] font-bold px-2 py-0.5 rounded-full" style={{ background: "#FBE8C8", color: "#96690F" }}>Cliente con {previos} reclamo(s) anterior(es)</span>}
                {r.evidencia && <span className="text-[10px] font-bold px-2 py-0.5 rounded-full" style={{ background: T.vainilla, color: T.choco2 }}>📷 {r.evidencia}</span>}
              </div>
              {r.decision && <div className="text-xs mt-2"><b>Decisión:</b> {r.decision}</div>}
              {r.solucion && <div className="text-xs mt-1"><b>Solución:</b> {r.solucion} {r.costo > 0 && `(costo ${fmt(r.costo)})`}</div>}
              <div className="flex gap-2 mt-3 items-center flex-wrap">
                <MiniSelect options={["Abierto","En revisión","Aprobado","Rechazado","Compensado","Cerrado"]} value={r.estado} disabled={enviando || scope === "history"} onChange={async (e) => {
                  const estado = e.target.value;
                  setEnviando(true);
                  try {
                    await setReclamoEstado(r.id, estado);
                  } catch (err) {
                    setAviso({ titulo: "Acción no permitida", texto: err.message });
                    setEnviando(false);
                    return;
                  }
                  try {
                    await refrescar();
                  } catch (err) {
                    setAviso({ titulo: "Acción aplicada, vista desactualizada", texto: "El estado del caso se actualizó correctamente, pero no se pudo actualizar la vista. Recargá la página para verlo." });
                  }
                  setEnviando(false);
                }} />
                {scope === "active" ? <Btn small kind="ghost" onClick={() => setSel({ ...r })}>Editar caso</Btn> : <span className="text-[10px] font-bold" style={{ color: T.choco2 }}>Caso cerrado · solo consulta</span>}
              </div>
            </Card>
            </div>
          );
        })}
        {listaReclamos.length === 0 && <Empty icon={scope === "active" ? "🎉" : "◷"} text={scope === "active" ? "Sin reclamos activos." : "Todavía no hay reclamos cerrados."} />}
      </div>

      {sel && (
        <Modal title={`Editar ${sel.id}`} onClose={() => setSel(null)}>
          <Field label="Tipo de reclamo"><Select options={RECLAMO_TIPOS} value={sel.tipo} onChange={(e) => setSel({ ...sel, tipo: e.target.value })} /></Field>
          <Field label="Descripción"><Input value={sel.desc} onChange={(e) => setSel({ ...sel, desc: e.target.value })} /></Field>
          <Field label="Hora de entrega (HH:MM)"><Input value={sel.hEntrega} onChange={(e) => setSel({ ...sel, hEntrega: e.target.value })} /></Field>
          <Field label="Responsable interno"><Input value={sel.resp} onChange={(e) => setSel({ ...sel, resp: e.target.value })} /></Field>
          <Field label="Decisión"><Input value={sel.decision} onChange={(e) => setSel({ ...sel, decision: e.target.value })} /></Field>
          <Field label="Solución dada"><Input value={sel.solucion} onChange={(e) => setSel({ ...sel, solucion: e.target.value })} /></Field>
          <Field label="Costo de la solución"><Input type="number" value={sel.costo} onChange={(e) => setSel({ ...sel, costo: +e.target.value })} /></Field>
          <div className="flex gap-2 mt-2">
            <Btn disabled={enviando} onClick={async () => {
              const hEntrega = sel.hEntrega && sel.hEntrega !== "—" ? sel.hEntrega : "";
              setEnviando(true);
              try {
                await editarReclamo(sel.id, { tipo: sel.tipo, descr: sel.desc, resp: sel.resp, decision: sel.decision, solucion: sel.solucion, costo: sel.costo, h_entrega: hEntrega });
              } catch (e) {
                setAviso({ titulo: "Acción no permitida", texto: e.message });
                setEnviando(false);
                return;
              }
              try {
                await refrescar();
              } catch (e) {
                setAviso({ titulo: "Acción aplicada, vista desactualizada", texto: "El caso se guardó correctamente, pero no se pudo actualizar la vista. Recargá la página para verlo." });
                setEnviando(false);
                setSel(null);
                return;
              }
              setEnviando(false);
              setSel(null);
            }}>Guardar caso</Btn>
            <Btn kind="ghost" onClick={() => setSel(null)}>Cancelar</Btn>
          </div>
        </Modal>
      )}
      {aviso && (
        <Modal title={aviso.titulo} onClose={() => setAviso(null)}>
          <p className="text-sm m-0">{aviso.texto}</p>
          <div className="mt-4"><Btn onClick={() => setAviso(null)}>Entendido</Btn></div>
        </Modal>
      )}
    </div>
  );
}

/* ================= CLIENTES / CRM ================= */

const ESTADOS_CLIENTE = ["Nuevo", "Recurrente", "VIP", "Inactivo", "Riesgo por reclamos"];

function Clientes({ db, update, user, refrescar }) {
  const [q, setQ] = useState("");
  const [sel, setSel] = useState(null);
  const [detalleVista, setDetalleVista] = useState("resumen");
  const [form, setForm] = useState(null); // null = cerrado; objeto = alta/edición
  const [err, setErr] = useState("");
  const [aviso, setAviso] = useState(null);
  const [enviando, setEnviando] = useState(false);
  const [crmForm, setCrmForm] = useState(null);
  const hoy = hoyISO();

  function abrirNuevo() {
    setErr(""); setSel(null);
    setForm({ id: null, nombre: "", telefono: "", instagram: "", canal: "WhatsApp", barrio: "", direccion: "", cumple: "", favoritos: "", estado: "Nuevo", notas: "" });
  }
  function abrirEdicion(c) {
    setErr(""); setSel(null);
    setForm({ id: c.id, nombre: c.nombre || "", telefono: c.telefono || "", instagram: c.instagram || "", canal: c.canal || "WhatsApp", barrio: c.barrio || "", direccion: c.direccion || "", cumple: c.cumple || "", favoritos: c.favoritos || "", estado: c.estado || "Nuevo", notas: c.notas || "" });
  }
  async function guardarCliente() {
    const nombre = form.nombre.trim();
    const telefono = form.telefono.trim();
    if (!nombre || !telefono) { setErr("Nombre y teléfono son obligatorios."); return; }
    const campos = { nombre, telefono, instagram: form.instagram.trim(), canal: form.canal, barrio: form.barrio.trim(), direccion: form.direccion.trim(), cumple: form.cumple, favoritos: form.favoritos.trim(), estado: form.estado, notas: form.notas.trim() };
    setEnviando(true);
    try {
      await upsertCliente(form.id || null, campos);
    } catch (e) {
      setErr(e.message);
      setEnviando(false);
      return;
    }
    try {
      await refrescar();
    } catch (e) {
      setAviso({ titulo: "Acción aplicada, vista desactualizada", texto: "El cliente se guardó correctamente, pero no se pudo actualizar la vista. Recargá la página para verlo." });
      setEnviando(false);
      setForm(null);
      return;
    }
    setEnviando(false);
    setForm(null);
  }
  const lista = db.customers.filter((c) => (c.nombre + c.telefono + (c.barrio || "")).toLowerCase().includes(q.toLowerCase()));
  const crm = sel ? buildCustomerCrm(db, sel.id, hoy) : null;
  const clientesConCompra = db.customers.filter((cliente) => (cliente.pedidos || 0) > 0).length;
  const clientesRecurrentes = db.customers.filter((cliente) => (cliente.pedidos || 0) >= 2).length;
  const clientesPorReactivar = db.customers.filter((cliente) => cliente.ultima && diasEntre(cliente.ultima, hoy) >= 15).length;

  function abrirDetalleCliente(cliente) {
    setDetalleVista("resumen");
    setSel(cliente);
  }

  async function ejecutarCrm(action) {
    setEnviando(true); setErr("");
    try { await action(); await refrescar(); setCrmForm(null); }
    catch (e) { setErr(e.message); }
    finally { setEnviando(false); }
  }

  const alertas = [];
  db.customers.forEach((c) => {
    if (c.ultima) {
      const dias = diasEntre(c.ultima, hoy);
      if (dias >= 30) alertas.push([`🚨 ${c.nombre} no compra hace ${dias} días`, "#A03B2A", "#F6D4CD"]);
      else if (dias >= 15) alertas.push([`💤 ${c.nombre} no compra hace ${dias} días`, "#96690F", "#FBE8C8"]);
    }
    if (c.cumple) {
      const [mm, dd] = c.cumple.split("-").map(Number);
      const prox = new Date(); prox.setMonth(mm - 1, dd);
      if (prox < new Date()) prox.setFullYear(prox.getFullYear() + 1);
      const faltan = Math.round((prox - new Date()) / 86400000);
      if (faltan <= 15) alertas.push([`🎂 ${c.nombre} cumple años en ${faltan} día(s)`, "#8E4B5A", "#F3D7DC"]);
    }
  });
  db.benefits.filter((b) => b.estado === "Activo" && diasEntre(hoy, b.vence) <= 3).forEach((b) => {
    const c = customerOf(db, b.customerId);
    if (c.nombre) alertas.push([`⏳ Beneficio de ${c.nombre} (${b.beneficio}) vence el ${b.vence}`, "#63518A", "#E8E0F2"]);
  });

  function exportar() {
    downloadCSV("clientes",
      ["Nombre","Teléfono","Instagram","Barrio","Dirección","Canal","Primera compra","Última compra","Total","Pedidos","Ticket promedio","Cumpleaños","Favoritos","Estado"],
      db.customers.map((c) => [c.nombre, c.telefono, c.instagram, c.barrio, c.direccion, c.canal, c.primera, c.ultima, c.total, c.pedidos, Math.round(c.total / Math.max(c.pedidos, 1)), c.cumple, c.favoritos, c.estado]));
  }

  return (
    <div>
      <SectionTitle action={<div className="flex gap-2"><Btn small kind="rosa" onClick={abrirNuevo}>＋ Nuevo cliente</Btn><Btn small kind="ghost" onClick={exportar}>⬇ CSV</Btn></div>}>Alertas de CRM</SectionTitle>
      <div className="grid grid-cols-2 lg:grid-cols-4 gap-3 mb-4">
        <Stat icon="💗" label="Clientes" value={db.customers.length} sub="fichas registradas" />
        <Stat icon="🛍️" label="Con compra" value={clientesConCompra} sub="historial comercial" tone="#3F6B42" />
        <Stat icon="🔁" label="Recurrentes" value={clientesRecurrentes} sub="dos compras o más" tone="#63518A" />
        <Stat icon="💬" label="Por reactivar" value={clientesPorReactivar} sub="15 días o más" tone={clientesPorReactivar ? "#96690F" : "#3F6B42"} />
      </div>
      <div className="flex flex-col gap-1.5 mb-4">
        {alertas.slice(0, 4).map(([t, fg, bg], i) => <div key={i} className="text-xs font-bold px-3 py-2 rounded-xl" style={{ background: bg, color: fg }}>{t}</div>)}
        {alertas.length > 4 && <div className="text-xs font-bold px-3 py-2 rounded-xl" style={{ background: T.vainilla, color: T.choco2 }}>+ {alertas.length - 4} alertas adicionales disponibles dentro de las fichas CRM.</div>}
        {alertas.length === 0 && <div className="text-sm" style={{ color: T.choco2 }}>Sin alertas activas.</div>}
      </div>

      <input value={q} onChange={(e) => setQ(e.target.value)} placeholder="Buscar por nombre, teléfono o barrio…"
        className="w-full rounded-xl px-3 py-2.5 text-sm border outline-none mb-3" style={inputStyle} />

      <SectionTitle>Directorio de clientes</SectionTitle>
      <div className="grid sm:grid-cols-2 lg:grid-cols-3 gap-3">
        {lista.map((c) => (
          <Card key={c.id} aria-label={`Abrir ficha CRM de ${c.nombre}`} className="p-4" onClick={() => abrirDetalleCliente(c)}>
            <div className="flex justify-between items-start gap-2">
              <div className="flex items-center gap-2.5 min-w-0">
                <div className="w-10 h-10 rounded-full flex items-center justify-center display text-base shrink-0" style={{ background: T.rosa, color: "#8E4B5A" }}>
                  {c.nombre.split(" ").map((w) => w[0]).slice(0, 2).join("")}
                </div>
                <div className="min-w-0">
                  <div className="font-bold text-sm truncate">{c.nombre}</div>
                  <div className="text-xs truncate" style={{ color: T.choco2 }}>{c.telefono} · {c.barrio}</div>
                </div>
              </div>
              <Badge label={c.estado} />
            </div>
            <div className="grid grid-cols-2 gap-2 mt-3">
              <div className="rounded-xl px-3 py-2" style={{ background: T.vainilla }}><div className="text-[10px] uppercase font-extrabold" style={{ color: T.choco2 }}>Compras</div><div className="display text-lg mt-0.5">{c.pedidos || 0}</div></div>
              <div className="rounded-xl px-3 py-2" style={{ background: T.vainilla }}><div className="text-[10px] uppercase font-extrabold" style={{ color: T.choco2 }}>Valor cliente</div><div className="font-bold text-sm mt-1 truncate">{fmt(c.total || 0)}</div></div>
            </div>
            <div className="flex items-center justify-between gap-3 mt-3"><div className="text-[11px] font-semibold truncate" style={{ color: T.choco2 }}>{c.ultima ? `Última compra ${c.ultima}` : "Lead sin compras"}</div><Badge label={c.canal || "WhatsApp"} map={CANAL_STYLE} /></div>
            <div className="text-[11px] font-extrabold mt-3" style={{ color: T.coral }}>Abrir ficha CRM ›</div>
          </Card>
        ))}
        {lista.length === 0 && <div className="sm:col-span-2 lg:col-span-3"><Empty icon="💗" text="No encontramos clientes con esa búsqueda." /></div>}
      </div>

      {sel && (
        <Modal title={`Cliente · ${sel.nombre}`} onClose={() => setSel(null)} wide>
          {!db.crmServerReady && <div className="text-xs font-bold p-2.5 rounded-xl mb-3" style={{ background: "#FBE8C8", color: "#96690F" }}>CRM en modo consulta. Aplicá la migración 15 para registrar contactos, activaciones y preferencias.</div>}
          {/* Tira de identidad — plana, dentro de la paleta */}
          <div className="momo-trace-open flex items-center gap-3 rounded-2xl p-3 mb-3" style={{ background: T.soft, border: `1px solid ${T.border}`, animationDelay: "20ms" }}>
            <div className="w-11 h-11 rounded-full flex items-center justify-center display text-lg shrink-0" style={{ background: T.vainilla, color: T.rosaDeep, boxShadow: "inset 0 0 0 1px rgba(196,128,142,.2)" }}>
              {(sel.nombre || "·").split(" ").map((w) => w[0]).slice(0, 2).join("")}
            </div>
            <div className="min-w-0">
              <div className="flex gap-1.5 flex-wrap"><Badge label={sel.estado} /><Badge label={sel.canal} map={CANAL_STYLE} /></div>
              {(sel.telefono || sel.barrio) && <div className="text-xs font-semibold mt-1 truncate" style={{ color: T.choco2, fontVariantNumeric: "tabular-nums" }}>{sel.telefono}{sel.telefono && sel.barrio ? " · " : ""}{sel.barrio}</div>}
            </div>
          </div>
          {/* Métricas — tiles planos vainilla con count-up */}
          <div className="grid grid-cols-2 sm:grid-cols-4 gap-2 mb-3">
            {[["Compras", <CountUp value={crm.purchases} />], ["Valor cliente", <CountUp value={crm.spend} format={fmt} />], ["Ticket", <CountUp value={crm.averageTicket} format={fmt} />], ["Ficha", <CountUp value={crmCompleteness(crm)} format={(v) => `${v}%`} />]].map(([label, node], i) => (
              <div key={label} className="momo-crm-tile momo-trace-open rounded-xl p-2 text-center" style={{ background: T.vainilla, animationDelay: `${70 + i * 55}ms` }}>
                <div className="display font-semibold text-base" style={{ fontVariantNumeric: "tabular-nums" }}>{node}</div>
                <div className="text-[10px] font-bold" style={{ color: T.choco2 }}>{label}</div>
              </div>
            ))}
          </div>
          <div role="tablist" aria-label="Secciones de la ficha CRM" className="flex flex-wrap gap-1.5 p-1.5 rounded-2xl mb-3" style={{ background: T.vainilla }}>
            {[["resumen", "Resumen"], ["compras", `Pedidos ${crm.orders.length}`], ["seguimiento", `Relación ${crm.contacts.length + crm.activations.length + db.benefits.filter((benefit) => benefit.customerId === sel.id).length + db.claims.filter((claim) => claim.customerId === sel.id).length}`]].map(([value, label]) => (
              <button key={value} type="button" role="tab" aria-selected={detalleVista === value} onClick={() => setDetalleVista(value)} className="rounded-xl px-3 py-2 text-xs font-extrabold" style={{ background: detalleVista === value ? T.coral : "transparent", color: detalleVista === value ? "white" : T.choco2 }}>{label}</button>
            ))}
          </div>
          {detalleVista === "resumen" && <>
          {/* Siguiente mejor acción — colores originales, sin cambios */}
          <div className="momo-trace-open p-3 rounded-2xl mb-3" style={{ background: crm.nextAction.type === "blocked" ? "#F6D4CD" : "#E6F1E3", border: `1px solid ${crm.nextAction.type === "blocked" ? "#E8A697" : "#B8D2B2"}`, animationDelay: "290ms" }}>
            <div className="text-[10px] uppercase tracking-wider font-extrabold" style={{ color: crm.nextAction.type === "blocked" ? "#A03B2A" : "#3F6B42" }}>Siguiente mejor acción</div>
            <div className="font-bold text-sm mt-0.5">{crm.nextAction.label}</div><div className="text-xs mt-0.5">{crm.nextAction.detail}</div>
          </div>
          {/* Contacto — sin duplicar métricas (tel movido a la tira; total/ticket ya en métricas) */}
          <div className="momo-trace-open text-sm space-y-1.5 rounded-2xl p-3 mb-3" style={{ background: T.soft, border: `1px solid ${T.border}`, animationDelay: "330ms" }}>
            <div>📍 {sel.direccion} ({sel.barrio})</div>
            <div style={{ fontVariantNumeric: "tabular-nums" }}>🗓️ {crm.firstPurchase ? <>Primera compra <b>{crm.firstPurchase}</b> · última <b>{crm.lastPurchase}</b></> : <span style={{ color: T.choco2 }}>Sin compras entregadas aún (lead)</span>}</div>
            {sel.instagram && <div>📸 {sel.instagram}</div>}
            {sel.cumple && <div>🎂 Cumpleaños: {sel.cumple}</div>}
            {sel.favoritos && <div>💗 {sel.favoritos}</div>}
          </div>
          <div className="momo-trace-open mt-3" style={{ animationDelay: "370ms" }}>
            <div className="text-xs font-bold mb-1" style={{ color: T.choco2 }}>GUSTOS REALES SEGÚN COMPRAS</div>
            {crm.automaticFavorites.length ? <div className="flex flex-wrap gap-1.5">{crm.automaticFavorites.map((favorite) => <span key={favorite.label} className="text-xs font-bold px-2.5 py-1 rounded-full inline-flex items-center gap-1.5" style={{ background: T.rosa, color: "#8E4B5A" }}>{favorite.label} <span style={{ background: "rgba(255,255,255,.6)", borderRadius: "999px", padding: "0 6px", fontVariantNumeric: "tabular-nums" }}>{favorite.quantity}</span></span>)}</div> : <div className="text-sm" style={{ color: T.choco2 }}>Aún no hay compras entregadas para aprender sus gustos.</div>}
          </div>
          {sel.notas && <div className="text-xs mt-3 p-2.5 rounded-xl" style={{ background: T.vainilla }}>📝 {sel.notas}</div>}
          </>}
          {detalleVista === "compras" && <>
          <div className="momo-trace-open mt-3" style={{ animationDelay: "410ms" }}>
            <div className="text-xs font-bold mb-1" style={{ color: T.choco2 }}>HISTORIAL DE PEDIDOS</div>
            {crm.orders.map((order) => <div key={order.id} className="momo-crm-row flex justify-between gap-3 text-sm px-2 py-2 border-b last:border-0" style={{ borderColor: T.border }}><div className="min-w-0"><b>{order.id}</b> · <span style={{ fontVariantNumeric: "tabular-nums" }}>{order.fecha}</span><div className="text-xs" style={{ color: T.choco2 }}>{order.itemsCrm.map((item) => `${item.cant}× ${item.nombre}${item.figura ? ` ${item.figura}` : ""}${item.sabor ? ` de ${item.sabor}` : ""}`).join("; ") || "Sin líneas"}</div></div><div className="text-right shrink-0"><Badge label={order.estado} /><div className="text-xs font-bold mt-1" style={{ fontVariantNumeric: "tabular-nums" }}>{fmt(order.totalCrm)}</div></div></div>)}
            {!crm.orders.length && <div className="text-sm" style={{ color: T.choco2 }}>Sin pedidos todavía.</div>}
          </div>
          </>}
          {detalleVista === "seguimiento" && <>
          <div className="mt-3">
            <div className="text-xs font-bold mb-1" style={{ color: T.choco2 }}>SEGUIMIENTO COMERCIAL</div>
            {crm.contacts.map((contact) => <div key={contact.id} className="text-sm py-2 border-b last:border-0" style={{ borderColor: T.border }}><div className="flex justify-between gap-2"><b>{contact.channel} · {contact.reason}</b><Badge label={contact.outcome} /></div><div className="text-xs" style={{ color: T.choco2 }}>{contact.createdAt}{contact.createdByName ? ` · ${contact.createdByName}` : ""}{contact.followUpOn ? ` · seguimiento ${contact.followUpOn}` : ""}</div></div>)}
            {!crm.contacts.length && <div className="text-sm" style={{ color: T.choco2 }}>Sin contactos registrados.</div>}
          </div>
          <div className="mt-3">
            <div className="text-xs font-bold mb-1" style={{ color: T.choco2 }}>ACTIVACIONES PUNTUALES</div>
            {crm.activations.map((activation) => <div key={activation.id} className="text-sm py-2 border-b last:border-0" style={{ borderColor: T.border }}><div className="flex justify-between gap-2"><div><b>{activation.title}</b><div className="text-xs" style={{ color: T.choco2 }}>{activation.type}{activation.expiresOn ? ` · vence ${activation.expiresOn}` : ""}{activation.convertedOrderId ? ` · pedido ${activation.convertedOrderId}` : ""}</div></div><div className="flex items-center gap-2"><Badge label={activation.status} />{!activation.convertedOrderId && <Btn small kind="ghost" onClick={() => { setErr(""); setCrmForm({ type: "conversion", activationId: activation.id, orderId: "" }); }}>Atribuir pedido</Btn>}</div></div></div>)}
            {!crm.activations.length && <div className="text-sm" style={{ color: T.choco2 }}>Sin activaciones creadas.</div>}
          </div>
          <div className="mt-3">
            <div className="text-xs font-bold mb-1" style={{ color: T.choco2 }}>BENEFICIOS</div>
            {db.benefits.filter((b) => b.customerId === sel.id).map((b) => (
              <div key={b.id} className="flex justify-between items-center text-sm py-1.5 border-b last:border-0" style={{ borderColor: T.border }}>
                <span>🎁 {b.beneficio} <span className="text-xs" style={{ color: T.choco2 }}>· vence {b.vence}{b.pedidoUso && ` · usado en ${b.pedidoUso}`}</span></span><Badge label={b.estado} />
              </div>
            ))}
            {db.benefits.filter((b) => b.customerId === sel.id).length === 0 && <div className="text-sm" style={{ color: T.choco2 }}>Sin beneficios.</div>}
          </div>
          <div className="mt-3">
            <div className="text-xs font-bold mb-1" style={{ color: T.choco2 }}>RECLAMOS</div>
            {db.claims.filter((r) => r.customerId === sel.id).map((r) => (
              <div key={r.id} className="flex justify-between items-center text-sm py-1.5 border-b last:border-0" style={{ borderColor: T.border }}>
                <span>{r.id} · {r.tipo}</span><Badge label={r.estado} />
              </div>
            ))}
            {db.claims.filter((r) => r.customerId === sel.id).length === 0 && <div className="text-sm" style={{ color: T.choco2 }}>Sin reclamos. 💛</div>}
          </div>
          </>}
          <div className="mt-4 flex justify-end gap-2 flex-wrap">
            <Btn small kind="soft" disabled={!db.crmServerReady} onClick={() => { setErr(""); setCrmForm({ type: "preferences", contactAllowed: crm.profile.contactAllowed !== false, preferredChannel: crm.profile.preferredChannel || "WhatsApp", acquisitionSource: crm.profile.acquisitionSource || "", contactReason: crm.profile.contactReason || "" }); }}>Preferencias</Btn>
            <Btn small kind="soft" disabled={!db.crmServerReady || crm.profile.contactAllowed === false} onClick={() => { setErr(""); setCrmForm({ type: "contact", channel: crm.profile.preferredChannel === "No contactar" ? "WhatsApp" : (crm.profile.preferredChannel || "WhatsApp"), reason: crm.nextAction.label, outcome: "Enviado", notes: "", followUpOn: "" }); }}>Registrar contacto</Btn>
            <Btn small kind="soft" disabled={!db.crmServerReady || crm.profile.contactAllowed === false} onClick={() => { setErr(""); setCrmForm({ type: "activation", activationType: crm.nextAction.type === "reactivation" ? "Reactivación" : "Seguimiento", title: crm.nextAction.label, message: crm.nextAction.detail, expiresOn: dISO(7) }); }}>Nueva activación</Btn>
            <Btn small kind="rosa" onClick={() => abrirEdicion(sel)}>✏️ Editar cliente</Btn>
          </div>
        </Modal>
      )}

      {sel && crmForm?.type === "preferences" && (
        <Modal title="Preferencias de contacto" onClose={() => setCrmForm(null)}>
          <label className="flex items-center gap-2 text-sm font-bold mb-3"><input type="checkbox" checked={crmForm.contactAllowed} onChange={(e) => setCrmForm({ ...crmForm, contactAllowed: e.target.checked, preferredChannel: e.target.checked ? "WhatsApp" : "No contactar" })} /> Puede recibir mensajes comerciales</label>
          <Field label="Canal preferido"><Select options={["WhatsApp","Instagram","Llamada","No contactar"]} value={crmForm.preferredChannel} onChange={(e) => setCrmForm({ ...crmForm, preferredChannel: e.target.value, contactAllowed: e.target.value !== "No contactar" })} /></Field>
          <Field label="Cómo llegó"><Input value={crmForm.acquisitionSource} onChange={(e) => setCrmForm({ ...crmForm, acquisitionSource: e.target.value })} placeholder="Instagram, referido, Rappi…" /></Field>
          {!crmForm.contactAllowed && <Field label="Motivo de no contacto"><Input value={crmForm.contactReason} onChange={(e) => setCrmForm({ ...crmForm, contactReason: e.target.value })} /></Field>}
          {err && <div className="text-sm font-bold mb-2" style={{ color: T.coral }}>{err}</div>}
          <div className="flex justify-end gap-2"><Btn kind="ghost" onClick={() => setCrmForm(null)}>Cancelar</Btn><Btn disabled={enviando} onClick={() => ejecutarCrm(() => guardarPreferenciasCliente(sel.id, { contact_allowed: crmForm.contactAllowed, preferred_channel: crmForm.preferredChannel, acquisition_source: crmForm.acquisitionSource, contact_reason: crmForm.contactReason }))}>Guardar</Btn></div>
        </Modal>
      )}
      {sel && crmForm?.type === "contact" && (
        <Modal title="Registrar contacto" onClose={() => setCrmForm(null)}>
          <Field label="Canal"><Select options={["WhatsApp","Instagram","Llamada","Presencial","Otro"]} value={crmForm.channel} onChange={(e) => setCrmForm({ ...crmForm, channel: e.target.value })} /></Field>
          <Field label="Motivo"><Input value={crmForm.reason} onChange={(e) => setCrmForm({ ...crmForm, reason: e.target.value })} /></Field>
          <Field label="Resultado"><Select options={["Pendiente","Enviado","Respondió","Interesado","No interesado","No respondió","Venta"]} value={crmForm.outcome} onChange={(e) => setCrmForm({ ...crmForm, outcome: e.target.value })} /></Field>
          <Field label="Próximo seguimiento"><Input type="date" value={crmForm.followUpOn} onChange={(e) => setCrmForm({ ...crmForm, followUpOn: e.target.value })} /></Field>
          <Field label="Notas"><Input value={crmForm.notes} onChange={(e) => setCrmForm({ ...crmForm, notes: e.target.value })} /></Field>
          {err && <div className="text-sm font-bold mb-2" style={{ color: T.coral }}>{err}</div>}
          <div className="flex justify-end gap-2"><Btn kind="ghost" onClick={() => setCrmForm(null)}>Cancelar</Btn><Btn disabled={enviando || crmForm.reason.trim().length < 3} onClick={() => ejecutarCrm(() => registrarContactoCliente({ customer_id: sel.id, channel: crmForm.channel, reason: crmForm.reason, outcome: crmForm.outcome, notes: crmForm.notes, follow_up_on: crmForm.followUpOn }))}>Registrar</Btn></div>
        </Modal>
      )}
      {sel && crmForm?.type === "activation" && (
        <Modal title="Nueva activación puntual" onClose={() => setCrmForm(null)}>
          <Field label="Tipo"><Select options={["Reactivación","Cumpleaños","Fidelización","Seguimiento","Recuperación","Otro"]} value={crmForm.activationType} onChange={(e) => setCrmForm({ ...crmForm, activationType: e.target.value })} /></Field>
          <Field label="Objetivo"><Input value={crmForm.title} onChange={(e) => setCrmForm({ ...crmForm, title: e.target.value })} /></Field>
          <Field label="Mensaje sugerido"><textarea value={crmForm.message} onChange={(e) => setCrmForm({ ...crmForm, message: e.target.value })} className={`${inputCls} min-h-24`} style={inputStyle} /></Field>
          <Field label="Vence"><Input type="date" value={crmForm.expiresOn} onChange={(e) => setCrmForm({ ...crmForm, expiresOn: e.target.value })} /></Field>
          {err && <div className="text-sm font-bold mb-2" style={{ color: T.coral }}>{err}</div>}
          <div className="flex justify-end gap-2"><Btn kind="ghost" onClick={() => setCrmForm(null)}>Cancelar</Btn><Btn disabled={enviando || crmForm.title.trim().length < 3} onClick={() => ejecutarCrm(() => crearActivacionCliente({ customer_id: sel.id, type: crmForm.activationType, title: crmForm.title, message: crmForm.message, expires_on: crmForm.expiresOn }))}>Crear activación</Btn></div>
        </Modal>
      )}
      {sel && crmForm?.type === "conversion" && (
        <Modal title="Atribuir conversión" onClose={() => setCrmForm(null)}>
          <div className="text-xs font-semibold p-2.5 rounded-xl mb-3" style={{ background: T.vainilla, color: T.choco2 }}>Elegí un pedido real del mismo cliente. El servidor rechazará pedidos cancelados, ajenos o ya atribuidos.</div>
          <Field label="Pedido convertido">
            <select value={crmForm.orderId} onChange={(e) => setCrmForm({ ...crmForm, orderId: e.target.value })} className={inputCls} style={inputStyle}>
              <option value="">Elegir pedido…</option>
              {crm.orders.filter((order) => order.estado !== "Cancelado").map((order) => <option key={order.id} value={order.id}>{order.id} · {order.fecha} · {order.estado} · {fmt(order.totalCrm)}</option>)}
            </select>
          </Field>
          {err && <div className="text-sm font-bold mb-2" style={{ color: T.coral }}>{err}</div>}
          <div className="flex justify-end gap-2"><Btn kind="ghost" onClick={() => setCrmForm(null)}>Cancelar</Btn><Btn disabled={enviando || !crmForm.orderId} onClick={() => ejecutarCrm(() => convertirActivacionCliente(crmForm.activationId, crmForm.orderId))}>Confirmar conversión</Btn></div>
        </Modal>
      )}

      {form && (
        <Modal title={form.id ? "Editar cliente" : "Nuevo cliente (lead)"} onClose={() => setForm(null)}>
          {!form.id && (
            <div className="text-xs font-semibold p-2.5 rounded-xl mb-3" style={{ background: T.vainilla, color: T.choco2 }}>
              Alta manual de un prospecto/lead antes de su primer pedido. Las métricas (pedidos, total) arrancan en 0 y se llenan solas cuando compre.
            </div>
          )}
          <div className="grid grid-cols-2 gap-2">
            <Field label="Nombre *"><Input value={form.nombre} onChange={(e) => setForm({ ...form, nombre: e.target.value })} /></Field>
            <Field label="Teléfono *"><Input value={form.telefono} onChange={(e) => setForm({ ...form, telefono: e.target.value })} /></Field>
          </div>
          <div className="grid grid-cols-2 gap-2">
            <Field label="Instagram"><Input value={form.instagram} onChange={(e) => setForm({ ...form, instagram: e.target.value })} placeholder="@usuario" /></Field>
            <Field label="Canal"><Select options={CANALES} value={form.canal} onChange={(e) => setForm({ ...form, canal: e.target.value })} /></Field>
          </div>
          <div className="grid grid-cols-2 gap-2">
            <Field label="Barrio"><Input value={form.barrio} onChange={(e) => setForm({ ...form, barrio: e.target.value })} /></Field>
            <Field label="Dirección"><Input value={form.direccion} onChange={(e) => setForm({ ...form, direccion: e.target.value })} /></Field>
          </div>
          <div className="grid grid-cols-2 gap-2">
            <Field label="Cumpleaños"><Input type="date" value={form.cumple ? "2000-" + form.cumple : ""} onChange={(e) => setForm({ ...form, cumple: e.target.value ? e.target.value.slice(5) : "" })} /></Field>
            <Field label="Estado"><Select options={ESTADOS_CLIENTE} value={form.estado} onChange={(e) => setForm({ ...form, estado: e.target.value })} /></Field>
          </div>
          <Field label="Favoritos"><Input value={form.favoritos} onChange={(e) => setForm({ ...form, favoritos: e.target.value })} placeholder="Ej: Maracuyá · Gatito" /></Field>
          <Field label="Notas"><Input value={form.notas} onChange={(e) => setForm({ ...form, notas: e.target.value })} /></Field>
          {err && <div className="text-sm font-bold mb-3" style={{ color: T.coral }}>{err}</div>}
          <div className="flex justify-end gap-2">
            <Btn kind="ghost" onClick={() => setForm(null)}>Cancelar</Btn>
            <Btn kind="rosa" disabled={enviando} onClick={guardarCliente}>Guardar</Btn>
          </div>
        </Modal>
      )}
      {aviso && (
        <Modal title={aviso.titulo} onClose={() => setAviso(null)}>
          <p className="text-sm m-0">{aviso.texto}</p>
          <div className="mt-4"><Btn onClick={() => setAviso(null)}>Entendido</Btn></div>
        </Modal>
      )}
    </div>
  );
}

/* ================= BENEFICIOS ================= */

const TIPOS_BENEFICIO = [
  { tipo: "descuento_porcentaje", label: "Descuento %" },
  { tipo: "descuento_valor_fijo", label: "Descuento valor fijo ($)" },
  { tipo: "producto_gratis", label: "Producto gratis" },
];

function labelBeneficio(b, db) {
  if (b.tipoBeneficio === "descuento_porcentaje") return b.valor + "% descuento";
  if (b.tipoBeneficio === "descuento_valor_fijo") return fmt(b.valor) + " de descuento";
  const p = productOf(db, b.productoGratisId);
  return (p ? p.nombre : "Producto") + " gratis";
}

function Beneficios({ db, update, user, refrescar }) {
  const [nuevo, setNuevo] = useState(false);
  const [form, setForm] = useState({ customerId: "", tipoBeneficio: "descuento_porcentaje", valor: 20, productoGratisId: "PR11", condicion: "Historia en Instagram", minimo: 30000, vence: dISO(15), obs: "" });
  const [error, setError] = useState("");
  const [enviando, setEnviando] = useState(false);

  return (
    <div>
      <div className="text-xs font-bold p-2.5 rounded-xl mb-4" style={{ background: T.vainilla, color: T.choco2 }}>
        Ciclo del beneficio: <b>Activo</b> → <b>Reservado</b> (al crear el pedido) → <b>Usado</b> (al confirmar el pago). Si el pedido se cancela, vuelve a Activo. Un beneficio por pedido, no acumulable, no aplica sobre el domicilio.
      </div>
      <div className="mb-4"><Btn onClick={() => setNuevo(true)}>＋ Activar beneficio</Btn></div>
      <div className="grid sm:grid-cols-2 gap-3">
        {db.benefits.map((b) => {
          const c = customerOf(db, b.customerId);
          const vencido = b.estado === "Activo" && b.vence < hoyISO();
          return (
            <Card key={b.id} className="p-4">
              <div className="flex justify-between items-start gap-2">
                <div>
                  <div className="font-bold text-sm">🎁 {labelBeneficio(b, db)}</div>
                  <div className="text-xs" style={{ color: T.choco2 }}>{c.nombre} · {b.condicion}</div>
                </div>
                <Badge label={vencido ? "Vencido" : b.estado} />
              </div>
              <div className="text-xs mt-2" style={{ color: T.choco2 }}>
                Mínimo {fmt(b.minimo)} · activado {b.activacion} · vence <b style={{ color: diasEntre(hoyISO(), b.vence) <= 3 && b.estado === "Activo" ? "#A03B2A" : T.choco2 }}>{b.vence}</b>
                {b.pedidoUso && <> · pedido <b>{b.pedidoUso}</b></>}
              </div>
              {b.estado === "Reservado" && <div className="text-xs font-bold mt-1.5" style={{ color: "#63518A" }}>⏳ Reservado: pasará a Usado cuando el pedido {b.pedidoUso} se marque pagado, o volverá a Activo si se cancela.</div>}
              {b.obs && <div className="text-xs mt-1.5">📝 {b.obs}</div>}
              {b.estado === "Activo" && (
                <div className="text-[11px] font-semibold mt-2" style={{ color: T.choco2 }}>Se reserva al crear el pedido y se marca usado al confirmar el pago; no requiere ajuste manual.</div>
              )}
            </Card>
          );
        })}
      </div>

      {nuevo && (
        <Modal title="Activar beneficio" onClose={() => setNuevo(false)}>
          <Field label="Cliente">
            <select value={form.customerId} onChange={(e) => setForm({ ...form, customerId: e.target.value })} className={inputCls} style={inputStyle}>
              <option value="">Elegir cliente…</option>
              {db.customers.map((c) => <option key={c.id} value={c.id}>{c.nombre}</option>)}
            </select>
          </Field>
          <Field label="Tipo de beneficio">
            <select value={form.tipoBeneficio} onChange={(e) => setForm({ ...form, tipoBeneficio: e.target.value })} className={inputCls} style={inputStyle}>
              {TIPOS_BENEFICIO.map((t) => <option key={t.tipo} value={t.tipo}>{t.label}</option>)}
            </select>
          </Field>
          {form.tipoBeneficio === "descuento_porcentaje" && (
            <Field label="Porcentaje de descuento"><Input type="number" min="1" max="100" value={form.valor} onChange={(e) => setForm({ ...form, valor: +e.target.value })} /></Field>
          )}
          {form.tipoBeneficio === "descuento_valor_fijo" && (
            <Field label="Valor del descuento ($)"><Input type="number" min="0" value={form.valor} onChange={(e) => setForm({ ...form, valor: +e.target.value })} /></Field>
          )}
          {form.tipoBeneficio === "producto_gratis" && (
            <Field label="Producto gratis">
              <select value={form.productoGratisId} onChange={(e) => setForm({ ...form, productoGratisId: e.target.value })} className={inputCls} style={inputStyle}>
                {db.products.filter((p) => p.activo).map((p) => <option key={p.id} value={p.id}>{p.nombre}</option>)}
              </select>
            </Field>
          )}
          <Field label="Condición"><Input value={form.condicion} onChange={(e) => setForm({ ...form, condicion: e.target.value })} placeholder="Historia, referido, cumpleaños, Club Sweet Love…" /></Field>
          <Field label="Compra mínima"><Input type="number" value={form.minimo} onChange={(e) => setForm({ ...form, minimo: +e.target.value })} /></Field>
          <Field label="Vence"><Input type="date" value={form.vence} onChange={(e) => setForm({ ...form, vence: e.target.value })} /></Field>
          <Field label="Observaciones"><Input value={form.obs} onChange={(e) => setForm({ ...form, obs: e.target.value })} /></Field>
          {!db.crmServerReady && <div className="text-xs font-bold mb-2" style={{ color: "#A03B2A" }}>Aplicá la migración 15 para activar beneficios de forma persistente y auditada.</div>}
          {error && <div className="text-sm font-bold mb-2" style={{ color: T.coral }}>{error}</div>}
          <div className="flex gap-2 mt-2">
            <Btn disabled={!db.crmServerReady || enviando || !form.customerId} onClick={async () => {
              setError(""); setEnviando(true);
              try {
                await activarBeneficioCliente({ customer_id: form.customerId, tipo_beneficio: form.tipoBeneficio, valor: form.valor, producto_gratis_id: form.tipoBeneficio === "producto_gratis" ? form.productoGratisId : "", condicion: form.condicion, minimo: form.minimo, vence: form.vence, obs: form.obs });
                await refrescar(); setNuevo(false);
              } catch (e) { setError(e.message); }
              finally { setEnviando(false); }
            }}>Activar</Btn>
            <Btn kind="ghost" onClick={() => setNuevo(false)}>Cancelar</Btn>
          </div>
        </Modal>
      )}
    </div>
  );
}

/* ================= FINANZAS ================= */

function Finanzas({ db, update, user }) {
  const [desde, setDesde] = useState(dISO(-30));
  const [hasta, setHasta] = useState(hoyISO());
  const [asistenteAbierto, setAsistenteAbierto] = useState(false);
  const financeAssistant = useMemo(() => buildOperationalFinance(db, { from: desde, to: hasta }), [db, desde, hasta]);

  const enRango = db.orders.filter((o) => o.fecha >= desde && o.fecha <= hasta);
  const vendidos = enRango.filter(esPedidoCobrado);

  const ventasProductos = vendidos.reduce((s, o) => s + orderSubtotal(db, o) - (o.descuento || 0), 0);
  const cogs = vendidos.reduce((s, o) => s + orderCOGS(db, o), 0);
  const margenBruto = ventasProductos - cogs;
  const domCobrado = vendidos.reduce((s, o) => s + (o.domCobrado || 0), 0);
  const domCosto = vendidos.reduce((s, o) => s + (o.domCosto || 0), 0);
  const subsidio = vendidos.reduce((s, o) => s + Math.max(0, (o.domCosto || 0) - (o.domCobrado || 0)), 0);
  const costoReclamos = db.claims.filter((r) => {
    if (!["Aprobado","Compensado"].includes(r.estado)) return false;
    const o = db.orders.find((x) => x.id === r.orderId);
    const f = r.fecha || (o ? o.fecha : null);
    return f && f >= desde && f <= hasta;
  }).reduce((s, r) => s + (r.costo || 0), 0);
  const pautaMensual = db.settings.pautaMensual || 0;
  const diasRango = Math.max(1, diasEntre(desde, hasta) + 1);
  const pauta = Math.round(pautaMensual / 30 * diasRango);
  const utilidad = margenBruto + (domCobrado - domCosto) - pauta - costoReclamos;

  function exportar() {
    downloadCSV("finanzas",
      ["Concepto","Valor"],
      [["Rango", desde + " a " + hasta],
       ["Ventas de producto (con descuentos)", ventasProductos],
       ["Costo estimado de producto (COGS)", cogs],
       ["Margen bruto", margenBruto],
       ["Domicilio cobrado", domCobrado],
       ["Costo real de domicilios", domCosto],
       ["Subsidio de domicilios", subsidio],
       ["Costo de reclamos compensados", costoReclamos],
       ["Pauta prorrateada del rango (" + diasRango + " días)", pauta],
       ["Utilidad estimada", utilidad]]);
  }

  const linea = (label, valor, opts = {}) => (
    <div className="flex justify-between items-center text-sm py-2 border-b last:border-0" style={{ borderColor: T.border }}>
      <span className={opts.strong ? "font-bold" : "font-semibold"} style={{ color: opts.muted ? T.choco2 : T.choco }}>{label}</span>
      <b style={{ color: opts.color || T.choco }}>{opts.raw ? valor : fmt(valor)}</b>
    </div>
  );

  return (
    <div>
      <SectionTitle>Finanzas operativas</SectionTitle>
      <div className="text-xs font-semibold mb-3 -mt-3" style={{ color: T.choco2 }}>
        Conciliá cobros, soportes, costos y excepciones antes de dar el periodo por cerrado.
      </div>
      <div className="flex flex-wrap items-center gap-2 mb-4">
        <span className="text-xs font-bold" style={{ color: T.choco2 }}>Rango:</span>
        <input type="date" value={desde} onChange={(e) => setDesde(e.target.value)} className="rounded-xl px-2 py-2 text-xs border font-semibold" style={inputStyle} aria-label="Desde" />
        <input type="date" value={hasta} onChange={(e) => setHasta(e.target.value)} className="rounded-xl px-2 py-2 text-xs border font-semibold" style={inputStyle} aria-label="Hasta" />
        <Btn small kind="ghost" onClick={exportar}>⬇ CSV</Btn>
      </div>

      <Card className="p-4 mb-4" onClick={() => setAsistenteAbierto(true)} style={{ background: "linear-gradient(135deg,#FFF4EA,#FFFFFF)", borderColor: financeAssistant.summary.blocking ? "#E7B36E" : "#A7C9A4" }}>
        <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-3">
          <div className="flex items-start gap-3 min-w-0">
            <span className="w-11 h-11 rounded-2xl flex items-center justify-center text-xl shrink-0" style={{ background: financeAssistant.summary.blocking ? T.coralSoft : "#E5F0E1" }} aria-hidden="true">🧾</span>
            <div className="min-w-0">
              <div className="text-[10px] uppercase tracking-[.14em] font-extrabold" style={{ color: financeAssistant.summary.blocking ? T.coral : "#3F6B42" }}>Asistente de cierre financiero</div>
              <div className="display text-xl font-semibold mt-0.5">{financeAssistant.summary.closeReady ? "Periodo listo para conciliar" : `${financeAssistant.summary.blocking} control${financeAssistant.summary.blocking === 1 ? "" : "es"} antes del cierre`}</div>
              <div className="text-xs font-semibold mt-1" style={{ color: T.choco2 }}>{fmt(financeAssistant.summary.grossCollected)} cobrados en MOMO OPS · {fmt(financeAssistant.summary.pendingValue)} por cobrar · {financeAssistant.summary.exceptions} observaciones totales</div>
            </div>
          </div>
          <span className="text-xs font-extrabold shrink-0" style={{ color: T.coral }}>{financeAssistant.summary.closeReady ? "Ver conciliación ›" : "Revisar pendientes ›"}</span>
        </div>
      </Card>

      <div className="grid grid-cols-2 lg:grid-cols-4 gap-3 mb-4">
        <Stat icon="💵" label="Ventas de producto" value={fmt(ventasProductos)} sub={vendidos.length + " pedidos cobrados"} tone={T.coral} />
        <Stat icon="🧾" label="Costo de producto" value={fmt(cogs)} sub="estimado por receta" />
        <Stat icon="📈" label="Margen bruto" value={fmt(margenBruto)} sub={ventasProductos ? pct(margenBruto / ventasProductos) + " de las ventas" : "—"} tone="#3F6B42" />
        <Stat icon="✨" label="Utilidad estimada" value={fmt(utilidad)} sub="tras domicilios, pauta y reclamos" tone={utilidad >= 0 ? "#3F6B42" : "#A03B2A"} />
      </div>

      <div className="grid lg:grid-cols-3 gap-3 mb-4">
        <Card className="p-4 lg:col-span-2">
          <div className="flex items-start justify-between gap-3 mb-2"><div><div className="text-[10px] uppercase tracking-[.12em] font-extrabold" style={{ color: T.coral }}>Cobros para conciliar</div><div className="display text-lg font-semibold">Separados por medio de pago</div></div><div className="text-right"><div className="display text-xl font-semibold" style={{ color: "#3F6B42" }}>{fmt(financeAssistant.summary.grossCollected)}</div><div className="text-[10px] font-bold" style={{ color: T.choco2 }}>bruto registrado</div></div></div>
          {financeAssistant.payments.length ? financeAssistant.payments.map((row) => (
            <div key={row.method} className="flex justify-between items-center py-2 border-t" style={{ borderColor: T.border }}><div><div className="text-sm font-bold">{row.method}</div><div className="text-[10px] font-semibold" style={{ color: T.choco2 }}>{row.orders} pedido{row.orders === 1 ? "" : "s"} · comparar con extracto</div></div><div className="font-extrabold">{fmt(row.amount)}</div></div>
          )) : <div className="text-sm font-semibold py-4" style={{ color: T.choco2 }}>No hay cobros confirmados en este rango.</div>}
        </Card>
        <Card className="p-4">
          <div className="text-[10px] uppercase tracking-[.12em] font-extrabold" style={{ color: T.coral }}>Caja operativa documentada</div>
          <div className="display text-lg font-semibold mb-2">Movimientos que sí conocemos</div>
          {linea("Compras de inventario", financeAssistant.summary.inventoryPurchases, { color: "#A03B2A" })}
          {linea("Pauta con métricas", financeAssistant.summary.platformSpend, { color: "#A03B2A" })}
          {linea("Costos de domicilios", financeAssistant.summary.deliveryCosts, { color: "#A03B2A" })}
          {linea("Resultado operativo documentado", financeAssistant.summary.operatingResult, { strong: true, color: financeAssistant.summary.operatingResult >= 0 ? "#3F6B42" : "#A03B2A" })}
          <div className="text-[10px] font-semibold mt-2 leading-relaxed" style={{ color: T.choco2 }}>No es saldo bancario: faltan nómina, servicios, impuestos, comisiones y otros egresos que aún no tienen libro en MOMO OPS.</div>
        </Card>
      </div>

      <div className="grid lg:grid-cols-2 gap-3">
        <Card className="p-4">
          <div className="text-xs font-bold mb-2" style={{ color: T.choco2 }}>ESTADO DE RESULTADOS SIMPLE</div>
          {linea("Ventas de producto (con descuentos aplicados)", ventasProductos)}
          {linea("− Costo estimado de producto", cogs, { color: "#A03B2A" })}
          {linea("= Margen bruto", margenBruto, { strong: true, color: "#3F6B42" })}
          {linea("+ Domicilio cobrado a clientes", domCobrado)}
          {linea("− Costo real de domicilios", domCosto, { color: "#A03B2A" })}
          {linea("− Costo de reclamos compensados", costoReclamos, { color: "#A03B2A" })}
          {linea(`− Pauta prorrateada del rango (${diasRango} días)`, pauta, { color: "#A03B2A" })}
          {linea("= Utilidad estimada del periodo", utilidad, { strong: true, color: utilidad >= 0 ? "#3F6B42" : "#A03B2A" })}
        </Card>
        <div className="flex flex-col gap-3">
          <Card className="p-4">
            <div className="text-xs font-bold mb-2" style={{ color: T.choco2 }}>DOMICILIOS EN EL RANGO</div>
            {linea("Cobrado a clientes", domCobrado)}
            {linea("Costo real pagado", domCosto)}
            {linea("Subsidio (pedidos donde costó más de lo cobrado)", subsidio, { color: "#A03B2A" })}
          </Card>
          <Card className="p-4">
            <div className="text-xs font-bold mb-2" style={{ color: T.choco2 }}>PAUTA PUBLICITARIA (asignación manual mensual)</div>
            <div className="flex items-center gap-2">
              <span className="text-xs font-bold" style={{ color: T.choco2 }}>$</span>
              <input type="number" value={pautaMensual} onChange={(e) => update((d) => {
                d.settings.pautaMensual = +e.target.value || 0;
                addAudit(d, { user, entidad: "Configuración", entidadId: "pauta", accion: "Pauta actualizada", a: fmt(+e.target.value || 0) });
              })} className="flex-1 rounded-xl px-3 py-2 text-sm border font-bold" style={inputStyle} />
            </div>
            <div className="text-xs mt-2" style={{ color: T.choco2 }}>Valor mensual. En la utilidad se descuenta solo la parte proporcional a los {diasRango} días del rango ({fmt(pauta)}). Registra aquí lo invertido en Meta Ads, influencers o volantes.</div>
          </Card>
        </div>
      </div>

      {asistenteAbierto && (
        <Modal title="Asistente de cierre financiero" onClose={() => setAsistenteAbierto(false)} wide>
          <div className="rounded-3xl border p-4 sm:p-5 mb-4" style={{ background: "linear-gradient(135deg,#FFF4EA,#FFFFFF)", borderColor: T.border }}>
            <div className="text-[10px] uppercase tracking-[.14em] font-extrabold" style={{ color: T.coral }}>Control del periodo · {desde} a {hasta}</div>
            <div className="display text-2xl font-semibold mt-1">{financeAssistant.summary.closeReady ? "Los datos están listos para conciliar" : "Qué debe revisar Finanzas ahora"}</div>
            <div className="text-sm font-semibold mt-1 max-w-3xl" style={{ color: T.choco2 }}>MOMO OPS cruza pedido, pago, evidencia, costo histórico, domicilio y reclamo. Señala diferencias, pero no confirma pagos, devuelve dinero ni inventa un saldo bancario.</div>
            <div className="grid grid-cols-2 sm:grid-cols-4 gap-2 mt-4">
              <div className="rounded-2xl bg-white px-3 py-3"><div className="text-[9px] uppercase font-extrabold" style={{ color: T.choco2 }}>Cobrado bruto</div><div className="display text-lg mt-0.5" style={{ color: "#3F6B42" }}>{fmt(financeAssistant.summary.grossCollected)}</div></div>
              <div className="rounded-2xl bg-white px-3 py-3"><div className="text-[9px] uppercase font-extrabold" style={{ color: T.choco2 }}>Por cobrar</div><div className="display text-lg mt-0.5" style={{ color: "#96690F" }}>{fmt(financeAssistant.summary.pendingValue)}</div></div>
              <div className="rounded-2xl bg-white px-3 py-3"><div className="text-[9px] uppercase font-extrabold" style={{ color: T.choco2 }}>Bloquean cierre</div><div className="display text-xl mt-0.5" style={{ color: financeAssistant.summary.blocking ? "#A03B2A" : "#3F6B42" }}>{financeAssistant.summary.blocking}</div></div>
              <div className="rounded-2xl bg-white px-3 py-3"><div className="text-[9px] uppercase font-extrabold" style={{ color: T.choco2 }}>Resultado documentado</div><div className="display text-lg mt-0.5" style={{ color: financeAssistant.summary.operatingResult >= 0 ? "#3F6B42" : "#A03B2A" }}>{fmt(financeAssistant.summary.operatingResult)}</div></div>
            </div>
          </div>

          {financeAssistant.queue.length === 0 ? (
            <div className="rounded-3xl p-8 text-center mb-4" style={{ background: "#E5F0E1" }}><div className="text-3xl">✓</div><div className="display text-xl mt-2">Sin excepciones internas</div><div className="text-sm font-semibold mt-1" style={{ color: "#3F6B42" }}>Ya podés comparar los cobros por medio de pago contra sus extractos externos.</div></div>
          ) : (
            <div className="space-y-2 mb-4">
              {financeAssistant.queue.map((task, index) => {
                const tone = task.severity === "critical" ? { bg: "#F6D4CD", fg: "#A03B2A", label: "Crítico" } : task.severity === "high" ? { bg: "#FBE8C8", fg: "#96690F", label: "Antes de cerrar" } : { bg: T.vainilla, fg: T.choco2, label: "Revisar" };
                return <Card key={task.id} className="p-4" style={{ borderColor: index === 0 ? "#E59A83" : T.border, background: index === 0 ? "#FFF8F4" : T.surface }}>
                  <div className="flex items-start gap-3"><span className="w-8 h-8 rounded-full flex items-center justify-center text-xs font-black shrink-0" style={{ background: index === 0 ? T.coral : T.vainilla, color: index === 0 ? "#fff" : T.choco2 }}>{index + 1}</span><div className="flex-1 min-w-0"><div className="flex flex-wrap items-center gap-2"><span className="text-[10px] font-extrabold px-2 py-1 rounded-full" style={{ background: tone.bg, color: tone.fg }}>{tone.label}</span><span className="text-[10px] uppercase tracking-wider font-extrabold" style={{ color: T.choco2 }}>{task.category}</span>{task.orderId && <span className="text-xs font-bold">{task.orderId}</span>}</div><div className="display text-lg font-semibold mt-1">{task.title}</div><div className="text-xs font-semibold mt-1" style={{ color: T.choco2 }}>{task.detail}</div><div className="text-xs font-bold mt-2" style={{ color: task.blocksClose ? "#A03B2A" : "#3F6B42" }}>Siguiente paso: {task.action}</div></div>{task.amount > 0 && <div className="font-extrabold shrink-0" style={{ color: T.coral }}>{fmt(task.amount)}</div>}</div>
                </Card>;
              })}
            </div>
          )}

          <div className="grid md:grid-cols-2 gap-3">
            <Card className="p-4"><div className="text-[10px] uppercase tracking-wider font-extrabold mb-2" style={{ color: T.coral }}>Conciliación externa pendiente</div>{financeAssistant.payments.length ? financeAssistant.payments.map((row) => <div key={row.method} className="flex justify-between text-sm py-2 border-t first:border-0" style={{ borderColor: T.border }}><span className="font-bold">{row.method} · {row.orders}</span><b>{fmt(row.amount)}</b></div>) : <div className="text-sm" style={{ color: T.choco2 }}>Sin cobros para conciliar.</div>}</Card>
            <Card className="p-4"><div className="text-[10px] uppercase tracking-wider font-extrabold mb-2" style={{ color: T.coral }}>Límites de esta lectura</div>{financeAssistant.caveats.map((note) => <div key={note} className="text-xs font-semibold py-1.5 leading-relaxed" style={{ color: T.choco2 }}>• {note}</div>)}</Card>
          </div>
        </Modal>
      )}
    </div>
  );
}

/* ================= REPORTES ================= */

function Reportes({ db }) {
  const [desde, setDesde] = useState(dISO(-14));
  const [hasta, setHasta] = useState(hoyISO());
  const validos = db.orders.filter((o) => esPedidoCobrado(o) && o.fecha >= desde && o.fecha <= hasta);

  const porDia = {};
  validos.forEach((o) => { porDia[o.fecha] = (porDia[o.fecha] || 0) + orderTotal(db, o); });
  const ventasDia = Object.entries(porDia).sort((a, b) => a[0] < b[0] ? -1 : 1)
    .map(([label, value]) => ({ label: label.slice(5), value, color: label === hoyISO() ? T.coral : undefined }));

  const porProducto = {}, porSabor = {}, porFigura = {}, porBarrio = {}, porCategoria = {};
  validos.forEach((o) => {
    porBarrio[o.barrio] = (porBarrio[o.barrio] || 0) + orderTotal(db, o);
    itemsOf(db, o.id).forEach((i) => {
      porProducto[i.nombre] = (porProducto[i.nombre] || 0) + i.cant;
      if (i.sabor) porSabor[i.sabor] = (porSabor[i.sabor] || 0) + i.cant;
      if (i.figura) porFigura[i.figura.split(" ")[0]] = (porFigura[i.figura.split(" ")[0]] || 0) + i.cant;
      const p = productOf(db, i.productId);
      if (p) porCategoria[p.cat] = (porCategoria[p.cat] || 0) + i.precio * i.cant;
    });
  });
  const top = (obj, n = 6) => Object.entries(obj).sort((a, b) => b[1] - a[1]).slice(0, n).map(([label, value]) => ({ label, value }));

  const ticket = Math.round(validos.reduce((s, o) => s + orderTotal(db, o), 0) / Math.max(validos.length, 1));
  const idsValidos = new Set(validos.map((o) => o.id));
  const deliveriesValidos = db.deliveries.filter((d) => idsValidos.has(d.orderId));
  const subsidio = deliveriesValidos.reduce((s, d) => s + Math.max(0, d.costoReal - d.cobrado), 0);
  const costoDomTotal = deliveriesValidos.reduce((s, d) => s + d.costoReal, 0);
  const mermaProm = db.production_batches.reduce((s, l) => s + (l.imperfectas + l.descartadas) / Math.max(l.prod, 1), 0) / Math.max(db.production_batches.length, 1);
  const recuperadas = db.production_batches.filter((l) => String(l.destino).includes("Insumo") || String(l.destino).includes("Prueba")).reduce((s, l) => s + l.imperfectas, 0);
  const nuevos = db.customers.filter((c) => diasEntre(c.primera, hoyISO()) <= 10).length;
  const recurr = db.customers.filter((c) => c.pedidos >= 2).length;
  const recompra = recurr / Math.max(db.customers.length, 1);
  const benefUsados = db.benefits.filter((b) => b.estado === "Usado").length;

  const reclamosCanal = {};
  db.claims.forEach((r) => {
    if (!r.fecha || r.fecha < desde || r.fecha > hasta) return;
    const o = db.orders.find((x) => x.id === r.orderId);
    const canal = o ? o.canal : "Otro";
    reclamosCanal[canal] = (reclamosCanal[canal] || 0) + 1;
  });

  const margenes = db.products.filter((p) => p.activo).map((p) => ({ label: p.nombre, value: Math.round(((p.precio - p.costo) / p.precio) * 100) })).sort((a, b) => b.value - a.value).slice(0, 8);

  function exportar() {
    downloadCSV("reporte-resumen",
      ["Indicador","Valor"],
      [["Rango", desde + " a " + hasta], ["Pedidos", validos.length], ["Ticket promedio", ticket],
       ["Costo real domicilios", costoDomTotal], ["Subsidio domicilios", subsidio],
       ["Merma promedio %", Math.round(mermaProm * 100)], ["Piezas recuperadas", recuperadas],
       ["Clientes nuevos (10 días)", nuevos], ["Clientes recurrentes", recurr],
       ["Recompra %", Math.round(recompra * 100)], ["Beneficios usados", benefUsados],
       ...top(porProducto, 10).map((d) => ["Producto: " + d.label, d.value]),
       ...top(porSabor, 10).map((d) => ["Sabor: " + d.label, d.value])]);
  }

  return (
    <div>
      <div className="flex flex-wrap items-center gap-2 mb-4">
        <span className="text-xs font-bold" style={{ color: T.choco2 }}>Rango:</span>
        <input type="date" value={desde} onChange={(e) => setDesde(e.target.value)} className="rounded-xl px-2 py-2 text-xs border font-semibold" style={inputStyle} aria-label="Desde" />
        <input type="date" value={hasta} onChange={(e) => setHasta(e.target.value)} className="rounded-xl px-2 py-2 text-xs border font-semibold" style={inputStyle} aria-label="Hasta" />
        <Btn small kind="ghost" onClick={exportar}>⬇ CSV</Btn>
      </div>

      <div className="grid grid-cols-2 lg:grid-cols-4 gap-3 mb-2">
        <Stat icon="🎯" label="Ticket promedio" value={fmt(ticket)} />
        <Stat icon="🛵" label="Costo real domicilios" value={fmt(costoDomTotal)} sub={`subsidio ${fmt(subsidio)}`} tone="#96690F" />
        <Stat icon="🔁" label="Recompra" value={pct(recompra)} sub={`${recurr} de ${db.customers.length} clientes`} tone="#3F6B42" />
        <Stat icon="♻️" label="Piezas recuperadas" value={recuperadas} sub={`merma promedio ${pct(mermaProm)}`} />
      </div>
      <div className="grid grid-cols-2 lg:grid-cols-4 gap-3">
        <Stat icon="🆕" label="Clientes nuevos (10 días)" value={nuevos} />
        <Stat icon="💖" label="Clientes recurrentes" value={recurr} />
        <Stat icon="🎁" label="Beneficios usados" value={benefUsados} sub={`${db.benefits.filter((b) => b.estado === "Activo").length} activos`} />
        <Stat icon="⚠️" label="Reclamos totales" value={db.claims.length} />
      </div>

      <SectionTitle>Ventas por día</SectionTitle>
      <Card className="p-4"><Bars data={ventasDia} money /></Card>

      <div className="grid lg:grid-cols-2 gap-3 mt-3">
        <Card className="p-4"><div className="text-xs font-bold mb-3" style={{ color: T.choco2 }}>VENTAS POR CATEGORÍA</div><Bars data={top(porCategoria)} money /></Card>
        <Card className="p-4"><div className="text-xs font-bold mb-3" style={{ color: T.choco2 }}>PRODUCTOS MÁS VENDIDOS (unidades)</div><Bars data={top(porProducto)} /></Card>
        <Card className="p-4"><div className="text-xs font-bold mb-3" style={{ color: T.choco2 }}>SABORES MÁS VENDIDOS</div><Bars data={top(porSabor)} /></Card>
        <Card className="p-4"><div className="text-xs font-bold mb-3" style={{ color: T.choco2 }}>FIGURAS MÁS VENDIDAS</div><Bars data={top(porFigura)} /></Card>
        <Card className="p-4"><div className="text-xs font-bold mb-3" style={{ color: T.choco2 }}>VENTAS POR BARRIO</div><Bars data={top(porBarrio)} money /></Card>
        <Card className="p-4"><div className="text-xs font-bold mb-3" style={{ color: T.choco2 }}>RECLAMOS POR CANAL</div><Bars data={Object.entries(reclamosCanal).map(([label, value]) => ({ label, value }))} /></Card>
      </div>

      <SectionTitle>Margen estimado por producto (%)</SectionTitle>
      <Card className="p-4"><Bars data={margenes} /></Card>

      <SectionTitle>Merma por lote (%)</SectionTitle>
      <Card className="p-4">
        <Bars data={db.production_batches.map((l) => ({ label: l.id + " " + l.sabor, value: Math.round(((l.imperfectas + l.descartadas) / Math.max(l.prod, 1)) * 100), color: T.rosaDeep }))} />
      </Card>

      {(() => {
        const campM = (db.campaigns || []).map((c) => ({ c, m: campaignMetrics(db, c) }));
        const creM = (db.creatives || []).map((cr) => ({ cr, pedidos: ordersDeCreative(db, cr.id).length, ventas: ventasDeCreative(db, cr.id) }));
        const ganadores = (db.creatives || []).filter((c) => c.estado === "Ganador");
        // conversión por canal de marketing desde resultados
        const canalConv = {};
        resultadosDePlataforma(db).forEach((r) => {
          const atrib = atribucionDeResultado(db, r);
          const cre = db.creatives.find((x) => x.id === r.creativeId);
          const canal = cre ? cre.canal : "Otro";
          if (!canalConv[canal]) canalConv[canal] = { msg: 0, ped: 0 };
          canalConv[canal].msg += r.mensajesWhatsApp;
          canalConv[canal].ped += atrib.pedidos;
        });
        const bajaRent = campM.filter((x) => x.m.roas !== null && x.m.roas < 1);
        return (
          <>
            <SectionTitle>📣 Marketing · ventas y pedidos por campaña</SectionTitle>
            <div className="grid lg:grid-cols-2 gap-3">
              <Card className="p-4"><div className="text-xs font-bold mb-3" style={{ color: T.choco2 }}>VENTAS POR CAMPAÑA</div><Bars data={campM.filter((x) => x.m.ventas > 0).map((x) => ({ label: x.c.nombre, value: x.m.ventas })).sort((a, b) => b.value - a.value)} money /></Card>
              <Card className="p-4"><div className="text-xs font-bold mb-3" style={{ color: T.choco2 }}>PEDIDOS POR CAMPAÑA</div><Bars data={campM.filter((x) => x.m.pedidos > 0).map((x) => ({ label: x.c.nombre, value: x.m.pedidos })).sort((a, b) => b.value - a.value)} /></Card>
              <Card className="p-4"><div className="text-xs font-bold mb-3" style={{ color: T.choco2 }}>ROAS POR CAMPAÑA</div><Bars data={campM.filter((x) => x.m.roas !== null).map((x) => ({ label: x.c.nombre, value: +x.m.roas.toFixed(2), color: x.m.roas >= 1 ? "#3F6B42" : "#A03B2A" })).sort((a, b) => b.value - a.value)} /></Card>
              <Card className="p-4"><div className="text-xs font-bold mb-3" style={{ color: T.choco2 }}>CAC POR CAMPAÑA</div><Bars data={campM.filter((x) => x.m.cac !== null).map((x) => ({ label: x.c.nombre, value: Math.round(x.m.cac), color: "#96690F" })).sort((a, b) => a.value - b.value)} money /></Card>
              <Card className="p-4"><div className="text-xs font-bold mb-3" style={{ color: T.choco2 }}>TICKET PROMEDIO POR CAMPAÑA</div><Bars data={campM.filter((x) => x.m.pedidos > 0).map((x) => ({ label: x.c.nombre, value: Math.round(x.m.ticket) })).sort((a, b) => b.value - a.value)} money /></Card>
              <Card className="p-4"><div className="text-xs font-bold mb-3" style={{ color: T.choco2 }}>PEDIDOS POR CREATIVO</div><Bars data={creM.filter((x) => x.pedidos > 0).map((x) => ({ label: x.cr.titulo, value: x.pedidos, color: T.rosaDeep })).sort((a, b) => b.value - a.value)} /></Card>
              <Card className="p-4"><div className="text-xs font-bold mb-3" style={{ color: T.choco2 }}>VENTAS POR CREATIVO</div><Bars data={creM.filter((x) => x.ventas > 0).map((x) => ({ label: x.cr.titulo, value: x.ventas })).sort((a, b) => b.value - a.value)} money /></Card>
              <Card className="p-4"><div className="text-xs font-bold mb-3" style={{ color: T.choco2 }}>CANALES CON MEJOR CONVERSIÓN WA→PEDIDO</div><Bars data={Object.entries(canalConv).filter(([, v]) => v.msg > 0).map(([k, v]) => ({ label: k, value: Math.round((v.ped / v.msg) * 100) }))} /></Card>
            </div>

            <SectionTitle>🏆 Creativos ganadores</SectionTitle>
            <Card className="p-4">
              {ganadores.length === 0 ? <div className="text-sm" style={{ color: T.choco2 }}>Aún no hay creativos marcados como ganadores.</div> :
                ganadores.map((c) => (
                  <div key={c.id} className="flex justify-between items-center py-1.5 border-b last:border-0" style={{ borderColor: T.border }}>
                    <span className="text-sm font-semibold">🎨 {c.titulo}</span>
                    <span className="text-xs font-bold" style={{ color: "#3F6B42" }}>{ordersDeCreative(db, c.id).length} pedidos · {fmt(ventasDeCreative(db, c.id))}</span>
                  </div>
                ))}
            </Card>

            {bajaRent.length > 0 && (
              <>
                <SectionTitle>⚠️ Campañas con baja rentabilidad (ROAS &lt; 1)</SectionTitle>
                <Card className="p-4">
                  {bajaRent.map((x) => (
                    <div key={x.c.id} className="flex justify-between items-center py-1.5 border-b last:border-0" style={{ borderColor: T.border }}>
                      <span className="text-sm font-semibold">{x.c.nombre}</span>
                      <span className="text-xs font-bold" style={{ color: "#A03B2A" }}>ROAS {x.m.roas.toFixed(2)}x · gasto {fmt(x.c.gastoReal)} · ventas {fmt(x.m.ventas)}</span>
                    </div>
                  ))}
                </Card>
              </>
            )}
          </>
        );
      })()}
    </div>
  );
}

/* ================= CONFIGURACIÓN ================= */

function Configuracion({ db, update, user, resetear, restaurarBackup, refrescar }) {
  const [nuevoItem, setNuevoItem] = useState({});
  const [confirmar, setConfirmar] = useState(false);
  const [nuevoUser, setNuevoUser] = useState({ nombre: "", email: "", rol: "Cocina" });
  const [userMsg, setUserMsg] = useState("");
  const [enviandoUser, setEnviandoUser] = useState(false);
  const [backupMsg, setBackupMsg] = useState("");
  const [nuevaFig, setNuevaFig] = useState({ nombre: "", especie: "gato", gramaje: "150 g" });
  const [nuevoTop, setNuevoTop] = useState({ nombre: "", precio: "", insumoId: "" });
  const s = db.settings;
  const [delayDraft, setDelayDraft] = useState(() => normalizeKitchenDelaySettings(s));
  const [delayMsg, setDelayMsg] = useState("");
  const [guardandoDemoras, setGuardandoDemoras] = useState(false);
  const listas = [
    ["saboresFrutales", "Sabores frutales"], ["saboresCremosos", "Sabores cremosos"],
    ["rellenos", "Rellenos"], ["salsas", "Salsas"],
    ["pagos", "Métodos de pago"], ["proveedores", "Proveedores de domicilio"],
  ];

  useEffect(() => {
    setDelayDraft(normalizeKitchenDelaySettings(s));
  }, [s.demoraCocinaMin, s.demoraCocinaUrgenteMin, s.demoraEmpaqueMin, s.demoraEmpaqueUrgenteMin, s.demoraRepeticionMin]);

  async function guardarTiemposDemora() {
    if (guardandoDemoras) return;
    const values = Object.fromEntries(Object.entries(delayDraft).map(([key, value]) => [key, Number(value)]));
    if (Object.values(values).some((value) => !Number.isInteger(value) || value < 1)) {
      setDelayMsg("⚠️ Todos los tiempos deben ser minutos enteros mayores que cero.");
      return;
    }
    if (values.demoraCocinaUrgenteMin < values.demoraCocinaMin || values.demoraEmpaqueUrgenteMin < values.demoraEmpaqueMin) {
      setDelayMsg("⚠️ El tiempo urgente no puede ser menor que el primer aviso de su área.");
      return;
    }
    const next = normalizeKitchenDelaySettings(values);
    setGuardandoDemoras(true);
    setDelayMsg("");
    try {
      await guardarConfiguracionDemoras(next);
      update((d) => {
        Object.assign(d.settings, next);
        addAudit(d, { user, entidad: "Configuración", entidadId: "demoras_pedidos", accion: "Tiempos actualizados", a: `Cocina ${next.demoraCocinaMin}/${next.demoraCocinaUrgenteMin} · Empaque ${next.demoraEmpaqueMin}/${next.demoraEmpaqueUrgenteMin} · cada ${next.demoraRepeticionMin} min` });
      });
      setDelayDraft(next);
      setDelayMsg("✓ Tiempos guardados para todos los equipos.");
      toast("ok", "Tiempos de pedidos demorados actualizados");
      try { await refrescar?.(); } catch { /* la copia local ya refleja el cambio guardado */ }
    } catch (error) {
      setDelayMsg("⚠️ No se pudieron guardar los tiempos: " + error.message);
    } finally {
      setGuardandoDemoras(false);
    }
  }

  function agregar(k) {
    const v = (nuevoItem[k] || "").trim();
    if (!v) return;
    // política MOMOS: no se permite "Efectivo" como método de pago
    if (k === "pagos" && v.toLowerCase() === "efectivo") {
      setNuevoItem((prev) => ({ ...prev, [k]: "" }));
      return;
    }
    update((d) => {
      if (d.settings[k].includes(v)) return;
      d.settings[k] = [...d.settings[k], v];
      addAudit(d, { user, entidad: "Configuración", entidadId: k, accion: "Ítem agregado", a: v });
    });
    setNuevoItem((prev) => ({ ...prev, [k]: "" }));
  }

  function agregarFigura() {
    const nombre = (nuevaFig.nombre || "").trim();
    if (!nombre) return;
    update((d) => {
      if (d.settings.figuras.some((f) => f.nombre.toLowerCase() === nombre.toLowerCase())) return;
      d.settings.figuras = [...d.settings.figuras, {
        nombre,
        especie: nuevaFig.especie === "perro" ? "perro" : "gato",
        gramaje: (nuevaFig.gramaje || "150 g").trim(),
      }];
      addAudit(d, { user, entidad: "Configuración", entidadId: "figuras", accion: "Figura agregada", a: nombre });
    });
    setNuevaFig({ nombre: "", especie: "gato", gramaje: "150 g" });
  }

  function agregarTopping() {
    const nombre = (nuevoTop.nombre || "").trim();
    if (!nombre) return;
    update((d) => {
      if (d.settings.toppings.some((t) => t.nombre.toLowerCase() === nombre.toLowerCase())) return;
      d.settings.toppings = [...d.settings.toppings, {
        nombre,
        precio: +nuevoTop.precio || 0,
        insumoId: nuevoTop.insumoId || "",
        insumoCant: 1,
      }];
      addAudit(d, { user, entidad: "Configuración", entidadId: "toppings", accion: "Topping agregado", a: nombre });
    });
    setNuevoTop({ nombre: "", precio: "", insumoId: "" });
  }

  return (
    <div>
      <SectionTitle>Zonas y tarifas de domicilio</SectionTitle>
      <Card className="p-4">
        {s.zonas.map((z, i) => (
          <div key={z.nombre} className="flex items-center justify-between gap-3 py-2 border-b last:border-0" style={{ borderColor: T.border }}>
            <span className="text-sm font-semibold">{z.nombre}</span>
            <div className="flex items-center gap-1">
              <span className="text-xs font-bold" style={{ color: T.choco2 }}>$</span>
              <input type="number" value={z.tarifa} onChange={(e) => update((d) => { d.settings.zonas[i].tarifa = +e.target.value; })}
                className="w-24 rounded-xl px-2 py-1.5 text-sm border text-right font-bold" style={inputStyle} />
            </div>
          </div>
        ))}
        <div className="flex items-center justify-between gap-3 pt-3 mt-1 border-t" style={{ borderColor: T.border }}>
          <span className="text-sm font-semibold">Pedido mínimo (sin domicilio)</span>
          <div className="flex items-center gap-1">
            <span className="text-xs font-bold" style={{ color: T.choco2 }}>$</span>
            <input type="number" value={s.pedidoMinimo} onChange={(e) => update((d) => { d.settings.pedidoMinimo = +e.target.value; })}
              className="w-24 rounded-xl px-2 py-1.5 text-sm border text-right font-bold" style={inputStyle} />
          </div>
        </div>
        <div className="flex items-center justify-between gap-3 pt-3 mt-1 border-t" style={{ borderColor: T.border }}>
          <span className="text-sm font-semibold">Horas de congelación objetivo (por defecto)</span>
          <div className="flex items-center gap-1">
            <input type="number" min="1" value={s.horasCongelacion || 10} onChange={(e) => update((d) => { d.settings.horasCongelacion = +e.target.value; })}
              className="w-24 rounded-xl px-2 py-1.5 text-sm border text-right font-bold" style={inputStyle} />
            <span className="text-xs font-bold" style={{ color: T.choco2 }}>h</span>
          </div>
        </div>
      </Card>

      <SectionTitle>⏱️ Tiempos de pedidos demorados</SectionTitle>
      <Card className="p-4" style={{ background: "linear-gradient(145deg, #fff, #FFF9F1)" }}>
        <div className="flex items-start gap-3 mb-4">
          <span className="w-10 h-10 rounded-2xl flex items-center justify-center text-lg shrink-0" style={{ background: T.coralSoft, color: T.coral }} aria-hidden="true">⏱</span>
          <div>
            <div className="text-sm font-bold">Ritmo operativo por área</div>
            <div className="text-xs font-semibold mt-0.5 leading-relaxed" style={{ color: T.choco2 }}>
              Define cuándo Momo Ops avisa, cuándo escala una orden a urgente y cada cuánto vuelve a recordarla. Los cambios se comparten con Cocina, Empaque y Administración.
            </div>
          </div>
        </div>
        <div className="grid lg:grid-cols-[1fr_1fr_.72fr] gap-3">
          <div className="rounded-2xl border p-3" style={{ background: T.soft, borderColor: T.border }}>
            <div className="flex items-center gap-2 mb-3"><span className="w-8 h-8 rounded-xl flex items-center justify-center" style={{ background: T.rosa }} aria-hidden="true">👩‍🍳</span><div><div className="text-sm font-bold">Cocina</div><div className="text-[10px] font-semibold" style={{ color: T.choco2 }}>Preparación del pedido</div></div></div>
            <div className="grid sm:grid-cols-2 gap-3">
              <Field label="Primer aviso">
                <div className="flex items-center gap-2"><Input type="number" min="1" step="1" value={delayDraft.demoraCocinaMin} onChange={(e) => setDelayDraft((current) => ({ ...current, demoraCocinaMin: e.target.value }))} /><span className="text-xs font-bold">min</span></div>
              </Field>
              <Field label="Urgente desde">
                <div className="flex items-center gap-2"><Input type="number" min="1" step="1" value={delayDraft.demoraCocinaUrgenteMin} onChange={(e) => setDelayDraft((current) => ({ ...current, demoraCocinaUrgenteMin: e.target.value }))} /><span className="text-xs font-bold">min</span></div>
              </Field>
            </div>
            <div className="text-[10px] font-bold rounded-xl px-2.5 py-2" style={{ background: T.rosa, color: "#7C3F4B" }}>Aviso a los {delayDraft.demoraCocinaMin} min → urgente a los {delayDraft.demoraCocinaUrgenteMin} min</div>
          </div>
          <div className="rounded-2xl border p-3" style={{ background: T.soft, borderColor: T.border }}>
            <div className="flex items-center gap-2 mb-3"><span className="w-8 h-8 rounded-xl flex items-center justify-center" style={{ background: "#DCE7F2" }} aria-hidden="true">📦</span><div><div className="text-sm font-bold">Empaque</div><div className="text-[10px] font-semibold" style={{ color: T.choco2 }}>Alistamiento y sello</div></div></div>
            <div className="grid sm:grid-cols-2 gap-3">
              <Field label="Primer aviso">
                <div className="flex items-center gap-2"><Input type="number" min="1" step="1" value={delayDraft.demoraEmpaqueMin} onChange={(e) => setDelayDraft((current) => ({ ...current, demoraEmpaqueMin: e.target.value }))} /><span className="text-xs font-bold">min</span></div>
              </Field>
              <Field label="Urgente desde">
                <div className="flex items-center gap-2"><Input type="number" min="1" step="1" value={delayDraft.demoraEmpaqueUrgenteMin} onChange={(e) => setDelayDraft((current) => ({ ...current, demoraEmpaqueUrgenteMin: e.target.value }))} /><span className="text-xs font-bold">min</span></div>
              </Field>
            </div>
            <div className="text-[10px] font-bold rounded-xl px-2.5 py-2" style={{ background: "#DCE7F2", color: "#3E5C7E" }}>Aviso a los {delayDraft.demoraEmpaqueMin} min → urgente a los {delayDraft.demoraEmpaqueUrgenteMin} min</div>
          </div>
          <div className="rounded-2xl border p-3 flex flex-col" style={{ background: T.vainilla, borderColor: T.border }}>
            <div className="flex items-center gap-2 mb-3"><span className="w-8 h-8 rounded-xl flex items-center justify-center" style={{ background: "#fff" }} aria-hidden="true">🔔</span><div><div className="text-sm font-bold">Repetición</div><div className="text-[10px] font-semibold" style={{ color: T.choco2 }}>Mientras siga detenido</div></div></div>
            <Field label="Recordar cada">
              <div className="flex items-center gap-2"><Input type="number" min="1" step="1" value={delayDraft.demoraRepeticionMin} onChange={(e) => setDelayDraft((current) => ({ ...current, demoraRepeticionMin: e.target.value }))} /><span className="text-xs font-bold">min</span></div>
            </Field>
            <div className="text-[10px] font-semibold mt-auto" style={{ color: T.choco2 }}>Evita que una orden urgente quede olvidada.</div>
          </div>
        </div>
        <div className="flex flex-wrap items-center gap-3 mt-4 pt-4 border-t" style={{ borderColor: T.border }}>
          <Btn onClick={guardarTiemposDemora} disabled={guardandoDemoras}>{guardandoDemoras ? "Guardando…" : "Guardar tiempos"}</Btn>
          <div className="text-[10px] font-bold rounded-full px-3 py-1.5" style={{ background: "#E3EFE0", color: "#3F6B42" }}>✓ Se aplican en todos los equipos</div>
          {delayMsg && <span className="text-xs font-bold" role="status" style={{ color: delayMsg.startsWith("⚠️") ? "#A03B2A" : "#3F6B42" }}>{delayMsg}</span>}
        </div>
      </Card>

      <SectionTitle>Catálogos del negocio</SectionTitle>
      <div className="grid sm:grid-cols-2 gap-3">
        {listas.map(([k, titulo]) => (
          <Card key={k} className="p-4">
            <div className="text-xs font-bold mb-2" style={{ color: T.choco2 }}>{titulo.toUpperCase()}</div>
            <div className="flex flex-wrap gap-1.5 mb-3">
              {s[k].map((v) => (
                <span key={v} className="text-xs font-semibold px-2.5 py-1 rounded-full flex items-center gap-1.5" style={{ background: T.rosa, color: "#8E4B5A" }}>
                  {v}
                  <button aria-label={`Quitar ${v}`} onClick={() => update((d) => { d.settings[k] = d.settings[k].filter((x) => x !== v); })} className="font-bold opacity-70">✕</button>
                </span>
              ))}
            </div>
            <div className="flex gap-2">
              <input value={nuevoItem[k] || ""} onChange={(e) => setNuevoItem((prev) => ({ ...prev, [k]: e.target.value }))}
                onKeyDown={(e) => e.key === "Enter" && agregar(k)} placeholder="Agregar…"
                className="flex-1 rounded-xl px-3 py-2 text-sm border outline-none" style={inputStyle} />
              <Btn small kind="rosa" onClick={() => agregar(k)}>＋</Btn>
            </div>
          </Card>
        ))}
      </div>

      <SectionTitle>Figuras (catálogo)</SectionTitle>
      <Card className="p-4">
        <div className="text-xs font-semibold mb-3" style={{ color: T.choco2 }}>
          La figura es la <b>forma</b> (nombre · especie · gramaje). El sabor es aparte: cualquier figura se ofrece en los 11 sabores.
        </div>
        {s.figuras.map((f, i) => (
          <div key={f.nombre} className="flex items-center justify-between gap-3 py-2 border-b last:border-0" style={{ borderColor: T.border }}>
            <div className="flex items-center gap-2 min-w-0">
              <span className="text-sm font-bold truncate">{f.nombre}</span>
              <Badge label={f.especie === "perro" ? "🐶 perro" : "🐱 gato"} />
            </div>
            <div className="flex items-center gap-2 shrink-0">
              <input value={f.gramaje} onChange={(e) => update((d) => { d.settings.figuras[i].gramaje = e.target.value; })}
                className="w-20 rounded-xl px-2 py-1.5 text-sm border text-right font-semibold" style={inputStyle} />
              <button aria-label={`Quitar ${f.nombre}`} onClick={() => update((d) => {
                d.settings.figuras = d.settings.figuras.filter((x) => x.nombre !== f.nombre);
                addAudit(d, { user, entidad: "Configuración", entidadId: "figuras", accion: "Figura eliminada", a: f.nombre });
              })} className="font-bold opacity-60 text-sm">✕</button>
            </div>
          </div>
        ))}
        <div className="flex flex-wrap gap-2 pt-3 items-center">
          <input value={nuevaFig.nombre} onChange={(e) => setNuevaFig({ ...nuevaFig, nombre: e.target.value })}
            onKeyDown={(e) => e.key === "Enter" && agregarFigura()} placeholder="Nombre (ej. Lizi)"
            className="flex-1 min-w-[120px] rounded-xl px-3 py-2 text-sm border outline-none" style={inputStyle} />
          <div className="w-28"><Select options={["gato", "perro"]} value={nuevaFig.especie} onChange={(e) => setNuevaFig({ ...nuevaFig, especie: e.target.value })} /></div>
          <input value={nuevaFig.gramaje} onChange={(e) => setNuevaFig({ ...nuevaFig, gramaje: e.target.value })}
            onKeyDown={(e) => e.key === "Enter" && agregarFigura()} placeholder="150 g"
            className="w-24 rounded-xl px-3 py-2 text-sm border outline-none" style={inputStyle} />
          <Btn small kind="rosa" onClick={agregarFigura}>＋ Figura</Btn>
        </div>
      </Card>

      <SectionTitle>Toppings / adiciones (catálogo)</SectionTitle>
      <Card className="p-4">
        <div className="text-xs font-semibold mb-3" style={{ color: T.choco2 }}>
          Un topping se agrega a la línea del pedido y <b>suma al total</b>. Precio <b>$0 = gratis</b> (incluido); mayor a 0 = extra pago.
          Si lo ligás a un insumo, se <b>descuenta del inventario</b> al vender y <b>vuelve</b> si el pedido se cancela.
        </div>
        {s.toppings.map((t, i) => (
          <div key={t.nombre} className="flex items-center justify-between gap-2 py-2 border-b last:border-0" style={{ borderColor: T.border }}>
            <div className="flex items-center gap-2 min-w-0 flex-1">
              <span className="text-sm font-bold truncate">{t.nombre}</span>
              {(+t.precio > 0)
                ? <Badge label={"+" + fmt(t.precio)} />
                : <span className="text-[10px] font-bold px-2 py-0.5 rounded-full" style={{ background: "#DDEBD9", color: "#3F6B42" }}>gratis</span>}
            </div>
            <div className="flex items-center gap-1.5 shrink-0">
              <span className="text-xs font-bold" style={{ color: T.choco2 }}>$</span>
              <input type="number" min="0" value={t.precio} onChange={(e) => update((d) => { d.settings.toppings[i].precio = +e.target.value || 0; })}
                className="w-20 rounded-xl px-2 py-1.5 text-sm border text-right font-semibold" style={inputStyle} />
              <select value={t.insumoId || ""} onChange={(e) => update((d) => { d.settings.toppings[i].insumoId = e.target.value; })}
                className="rounded-xl px-2 py-1.5 text-xs border font-semibold max-w-[130px]" style={inputStyle}>
                <option value="">— sin insumo —</option>
                {db.inventory_items.map((it) => <option key={it.id} value={it.id}>{it.nombre}</option>)}
              </select>
              <button aria-label={`Quitar ${t.nombre}`} onClick={() => update((d) => {
                d.settings.toppings = d.settings.toppings.filter((x) => x.nombre !== t.nombre);
                addAudit(d, { user, entidad: "Configuración", entidadId: "toppings", accion: "Topping eliminado", a: t.nombre });
              })} className="font-bold opacity-60 text-sm">✕</button>
            </div>
          </div>
        ))}
        <div className="flex flex-wrap gap-2 pt-3 items-center">
          <input value={nuevoTop.nombre} onChange={(e) => setNuevoTop({ ...nuevoTop, nombre: e.target.value })}
            onKeyDown={(e) => e.key === "Enter" && agregarTopping()} placeholder="Nombre (ej. Chispas)"
            className="flex-1 min-w-[120px] rounded-xl px-3 py-2 text-sm border outline-none" style={inputStyle} />
          <div className="flex items-center gap-1">
            <span className="text-xs font-bold" style={{ color: T.choco2 }}>$</span>
            <input type="number" min="0" value={nuevoTop.precio} onChange={(e) => setNuevoTop({ ...nuevoTop, precio: e.target.value })}
              onKeyDown={(e) => e.key === "Enter" && agregarTopping()} placeholder="0 = gratis"
              className="w-24 rounded-xl px-3 py-2 text-sm border outline-none" style={inputStyle} />
          </div>
          <select value={nuevoTop.insumoId} onChange={(e) => setNuevoTop({ ...nuevoTop, insumoId: e.target.value })}
            className="rounded-xl px-2 py-2 text-xs border font-semibold" style={inputStyle}>
            <option value="">— sin insumo —</option>
            {db.inventory_items.map((it) => <option key={it.id} value={it.id}>{it.nombre}</option>)}
          </select>
          <Btn small kind="rosa" onClick={agregarTopping}>＋ Topping</Btn>
        </div>
      </Card>

      <SectionTitle>Usuarios (users · roles · permissions)</SectionTitle>
      <Card className="p-4">
        <div className="text-xs font-semibold mb-3" style={{ color: T.choco2 }}>
          Cada persona conserva un rol principal y puede acumular otros. Momo Ops une sus permisos sin duplicar el correo ni la cuenta de acceso.
        </div>
        {!db.multipleRolesReady && <div className="rounded-2xl px-3 py-2.5 mb-3 text-xs font-bold" style={{ background: "#FFF2D8", color: "#8A5D08", border: "1px solid #EDD4A8" }} role="status">
          Aplicá la migración 21 de roles múltiples para asignar más de un área a la misma persona. La administración actual sigue funcionando con un rol por usuario.
        </div>}
        {db.users.map((u) => {
          const userRoles = normalizeRoles(u);
          return <div key={u.id} className="flex flex-col sm:flex-row sm:items-center justify-between gap-3 py-3 border-b" style={{ borderColor: T.border, opacity: u.activo ? 1 : 0.55 }}>
            <div className="min-w-0 flex-1">
              <div className="text-sm font-bold truncate">{u.nombre} <span className="text-xs font-semibold" style={{ color: T.choco2 }}>· {u.email}</span></div>
              <div className="flex flex-wrap gap-1.5 mt-2">
                {userRoles.map((role) => <span key={role} className="inline-flex items-center gap-1.5 rounded-full px-2.5 py-1 text-[10px] font-extrabold" style={{ background: role === u.rol ? T.coralSoft : "#F4E8D3", color: role === u.rol ? "#923F2D" : T.choco2 }} title={PERMISOS_POR_ROL[role]}>
                  {role}{role === u.rol && <span className="opacity-70">· principal</span>}
                  {db.multipleRolesReady && userRoles.length > 1 && <button type="button" className="font-black opacity-70 hover:opacity-100" aria-label={`Quitar rol ${role} a ${u.nombre}`} onClick={async () => {
                    if (enviandoUser) return;
                    setEnviandoUser(true); setUserMsg("");
                    try {
                      const result = await quitarRolUsuario(u.id, role);
                      await refrescar();
                      setUserMsg(`Rol ${role} retirado de ${u.nombre}. Rol principal: ${result.rol}.`);
                    } catch (error) {
                      setUserMsg("⚠️ " + error.message);
                    } finally {
                      setEnviandoUser(false);
                    }
                  }}>×</button>}
                </span>)}
              </div>
              <div className="text-[10px] mt-1.5 leading-relaxed" style={{ color: T.choco2 }}>{userRoles.map((role) => PERMISOS_POR_ROL[role]).filter(Boolean).join(" · ")}</div>
            </div>
            <div className="flex items-center gap-2 shrink-0">
              <Badge label={u.activo ? "Activo" : "Inactivo"} />
              <Btn small kind="ghost" onClick={async () => {
                if (enviandoUser) return;
                setEnviandoUser(true); setUserMsg("");
                try {
                  await setUserActivo(u.id, !u.activo);
                  await refrescar();
                } catch (e) {
                  setUserMsg("⚠️ " + e.message);
                } finally {
                  setEnviandoUser(false);
                }
              }}>{u.activo ? "Desactivar" : "Activar"}</Btn>
            </div>
          </div>;
        })}
        <div className="flex flex-wrap gap-2 pt-3 items-center">
          <input value={nuevoUser.nombre} onChange={(e) => setNuevoUser({ ...nuevoUser, nombre: e.target.value })} placeholder="Nombre"
            className="flex-1 min-w-[110px] rounded-xl px-3 py-2 text-sm border outline-none" style={inputStyle} />
          <input value={nuevoUser.email} onChange={(e) => setNuevoUser({ ...nuevoUser, email: e.target.value })} placeholder="Correo"
            className="flex-1 min-w-[130px] rounded-xl px-3 py-2 text-sm border outline-none" style={inputStyle} />
          <MiniSelect options={ROLES} value={nuevoUser.rol} onChange={(e) => setNuevoUser({ ...nuevoUser, rol: e.target.value })} />
          <Btn small kind="rosa" onClick={async () => {
            if (!nuevoUser.nombre.trim() || !nuevoUser.email.trim() || enviandoUser) return;
            setEnviandoUser(true); setUserMsg("");
            let r;
            try {
              r = await crearUsuarioStaff(nuevoUser.nombre, nuevoUser.email, nuevoUser.rol);
            } catch (e) {
              setUserMsg("⚠️ " + e.message);
              setEnviandoUser(false);
              return;
            }
            setNuevoUser({ nombre: "", email: "", rol: "Cocina" });
            try {
              await refrescar();
              setUserMsg(r.creado === undefined
                ? `Usuario ${r.id} creado con el rol ${nuevoUser.rol}.`
                : r.creado
                  ? `Usuario ${r.id} creado con el rol ${nuevoUser.rol}. Falta vincular su cuenta de acceso.`
                  : r.agregado
                    ? `${nuevoUser.rol} agregado al usuario ${r.id}. Ya puede operar ambas áreas con la misma cuenta.`
                    : `${nuevoUser.rol} ya estaba asignado al usuario ${r.id}; no se duplicó nada.`);
            } catch {
              setUserMsg(`El cambio sobre ${r.id} se guardó, pero no se pudo actualizar la vista. Recargá la página.`);
            }
            setEnviandoUser(false);
          }}>＋ Crear o asignar rol</Btn>
        </div>
        {userMsg && <div className="text-xs font-bold mt-2" style={{ color: userMsg.startsWith("⚠️") ? "#A03B2A" : "#3F6B42" }}>{userMsg}</div>}
      </Card>

      <SectionTitle>Políticas comerciales</SectionTitle>
      <Card className="p-4">
        <textarea rows={3} value={s.politicas} onChange={(e) => update((d) => { d.settings.politicas = e.target.value; })}
          className="w-full rounded-xl px-3 py-2.5 text-sm border outline-none resize-y" style={{ ...inputStyle, fontFamily: "inherit" }} />
      </Card>

      <SectionTitle>Registro de actividad (audit log)</SectionTitle>
      <Card className="overflow-x-auto">
        <table className="w-full text-sm min-w-[620px]">
          <thead><tr className="text-left text-xs" style={{ color: T.choco2 }}>
            {["Fecha","Usuario","Entidad","Acción","De → A"].map((h) => <th key={h} className="px-3 py-3 font-bold">{h}</th>)}
          </tr></thead>
          <tbody>
            {db.audit_logs.slice(0, 30).map((a) => (
              <tr key={a.id} className="border-t" style={{ borderColor: T.border }}>
                <td className="px-3 py-2 text-xs whitespace-nowrap">{a.fecha}</td>
                <td className="px-3 py-2 text-xs font-bold">{a.user}</td>
                <td className="px-3 py-2 text-xs">{a.entidad} {a.entidadId}</td>
                <td className="px-3 py-2 text-xs font-semibold">{a.accion}</td>
                <td className="px-3 py-2 text-xs" style={{ color: T.choco2 }}>{a.de ? `${a.de} → ${a.a}` : a.a}</td>
              </tr>
            ))}
          </tbody>
        </table>
      </Card>
      <div className="mt-2"><Btn small kind="ghost" onClick={() => downloadCSV("audit-log", ["Fecha","Usuario","Entidad","ID","Acción","De","A"], db.audit_logs.map((a) => [a.fecha, a.user, a.entidad, a.entidadId, a.accion, a.de, a.a]))}>⬇ Exportar audit log</Btn></div>

      <SectionTitle>Datos</SectionTitle>
      <Card className="p-4 mb-3">
        <div className="text-sm font-semibold mb-1">💾 Backup diario</div>
        <div className="text-xs mb-3" style={{ color: T.choco2 }}>
          Descarga las tablas principales en archivos CSV (pedidos, items, clientes, inventario, movimientos, domicilios, evidencias, reclamos, beneficios, producción, reservas y audit log) más un respaldo completo en JSON. Hazlo al cierre de cada día.
        </div>
        <div className="flex flex-wrap gap-2">
          <Btn small onClick={() => {
            const tablas = [
              ["pedidos", ["Pedido","Fecha","Hora","Canal","ClienteId","Barrio","Zona","Subtotal","Descuento","Dom cobrado","Dom costo","Total","Pago","Pagado en","Estado","Beneficio"],
                db.orders.map((o) => [o.id, o.fecha, o.hora, o.canal, o.customerId, o.barrio, o.zona, orderSubtotal(db, o), o.descuento, o.domCobrado, o.domCosto, orderTotal(db, o), o.pago, o.pagadoEn || "", o.estado, o.benefitId])],
              ["items", ["Id","Pedido","Padre (caja)","Caja #","Producto","Sabor","Salsa","Relleno","Figura","Cant","Precio","Costo unitario histórico","Adiciones","Total adiciones","Costo insumo adiciones"],
                db.order_items.map((i) => [i.id, i.orderId, i.parentItemId || "", i.cajaNum || "", i.nombre, i.sabor, i.salsa, i.relleno, i.figura, i.cant, i.precio, i.costoUnitario ?? "",
                  lineAdiciones(i).map((ad) => `${ad.nombre}×${ad.cant || 1} (+${(+ad.precio || 0) * (+ad.cant || 1)})`).join(" · "),
                  lineAdicionesTotal(i), lineAdicionesCOGS(db, i)])],
              ["clientes", ["Id","Nombre","Teléfono","Instagram","Barrio","Dirección","Canal","Primera","Última","Total","Pedidos","Cumple","Estado"],
                db.customers.map((c) => [c.id, c.nombre, c.telefono, c.instagram, c.barrio, c.direccion, c.canal, c.primera, c.ultima, c.total, c.pedidos, c.cumple, c.estado])],
              ["inventario", ["Id","Nombre","Categoría","Unidad","Stock","Mínimo","Costo","Proveedor","Vence","Ubicación"],
                db.inventory_items.map((i) => [i.id, i.nombre, i.cat, i.unidad, i.stock, i.min, i.costo, i.proveedor, i.vence, i.ubicacion])],
              ["movimientos", ["Id","Fecha","Tipo","Ítem","Cantidad","Nota"],
                db.inventory_movements.map((m) => [m.id, m.fecha, m.tipo, m.item, m.cant, m.nota])],
              ["domicilios", ["Id","Pedido","Proveedor","Zona","Cobrado","Costo","Solicitud","Salida","Entrega","Código","Estado"],
                db.deliveries.map((d) => [d.id, d.orderId, d.proveedor, d.zona, d.cobrado, d.costoReal, d.hSolicitud, d.hSalida, d.hEntrega, d.codigo, d.estado])],
              ["evidencias", ["Id","Pedido","Tipo","Fecha","Hora","Usuario","Tiene foto"],
                db.evidences.map((e) => [e.id, e.orderId, e.tipo, e.fecha, e.hora, e.user, e.url ? "Sí" : "No"])],
              ["reclamos", ["Id","Fecha","Pedido","ClienteId","Tipo","H entrega","H reclamo","Entregado en","Reclamo en","Decisión","Solución","Costo","Estado","Descripción","Evidencia"],
                db.claims.map((r) => [r.id, r.fecha || "", r.orderId, r.customerId, r.tipo, r.hEntrega, r.hReclamo, r.entregadoEn || "", r.reclamoEn || "", r.decision, r.solucion, r.costo, r.estado, r.desc || "", r.evidencia || ""])],
              ["beneficios", ["Id","ClienteId","Beneficio","Tipo","Valor","Producto gratis","Mínimo","Activación","Vence","Estado","Pedido"],
                db.benefits.map((b) => [b.id, b.customerId, b.beneficio, b.tipoBeneficio, b.valor, b.productoGratisId, b.minimo, b.activacion, b.vence, b.estado, b.pedidoUso])],
              ["produccion", ["Lote","Fecha","Producto","Figura","Sabor","Gramaje","Producidas","Perfectas","Imperfectas","Descartadas","Destino","Resp","Desmoldado","Vence","Estado","Horas congelación","Inicio congelación","Stock contabilizado"],
                db.production_batches.map((l) => [l.id, l.fecha, l.producto, l.figura, l.sabor, l.gramaje, l.prod, l.perfectas, l.imperfectas, l.descartadas, l.destino, l.resp, l.desmoldadoEn || "", l.vence, l.estado, l.horasCongelacion || "", l.inicioCongelacion || "", l.stockContabilizado ? "Sí" : "No"])],
              ["reservas", ["Id","Pedido","Tipo","Referencia","Cantidad","Fecha","Estado"],
                db.inventory_reservations.map((r) => [r.id, r.orderId, r.tipo, r.nombre, r.cantidad, r.fecha, r.estado])],
              ["campanas", ["Id","Nombre","Canal","Objetivo","Producto","Oferta","Inicio","Fin","Presupuesto","Gasto real","Estado","Responsable"],
                db.campaigns.map((c) => [c.id, c.nombre, c.canal, c.objetivo, c.productoFoco, c.oferta, c.fechaInicio, c.fechaFin, c.presupuesto, c.gastoReal, c.estado, c.responsable])],
              ["creativos", ["Id","Campaña","Título","Canal","Formato","Producto","Hook","Estado","Responsable","Entrega"],
                db.creatives.map((c) => [c.id, c.campaignId, c.titulo, c.canal, c.formato, c.productoFoco, c.hook, c.estado, c.responsable, c.fechaEntrega])],
              ["calendario", ["Id","Fecha","Hora","Canal","Campaña","Creativo","Título","Estado"],
                db.content_calendar.map((p) => [p.id, p.fecha, p.hora, p.canal, p.campaignId, p.creativeId, p.titulo, p.estado])],
              ["resultados-creativos", ["Id","Creativo","Campaña","Fecha","Impresiones","Alcance","Clicks","Mensajes WA","Pedidos","Ventas","Gasto"],
                db.creative_results.map((r) => { const a = atribucionDeResultado(db, r); return [r.id, r.creativeId, r.campaignId, r.fecha, r.impresiones, r.alcance, r.clicks, r.mensajesWhatsApp, a.contabilizar ? a.pedidos : "", a.contabilizar ? a.ventas : "", r.gasto]; })],
              ["ideas-marketing", ["Id","Título","Categoría","Objetivo","Producto","Copy","Guion","Canal","Estado"],
                (db.marketing_ideas || []).map((i) => [i.id, i.titulo, i.cat, i.objetivo, i.productoSugerido, i.copy, i.guionCorto, i.canal, i.estado])],
              ["guiones-marketing", ["Id","Título","Duración","Producto","Objetivo","Dificultad","Escena 1","Escena 2","Escena 3","Escena 4","Texto pantalla","Audio"],
                (db.marketing_guiones || []).map((g) => [g.id, g.titulo, g.duracion, g.productoFoco, g.objetivo, g.dificultad, g.escena1, g.escena2, g.escena3, g.escena4, g.textoPantalla, g.audio])],
              ["mensajes-whatsapp", ["Id","Tipo","Texto"],
                (db.marketing_mensajes || []).map((m) => [m.id, m.tipo, m.texto])],
              ["tareas-marketing", ["Id","Tarea","Fecha","Estado","Responsable"],
                (db.marketing_tasks || []).map((t) => [t.id, t.tarea, t.fecha, t.estado, t.responsable])],
              ["biblioteca-marca", ["Tipo","Valor"],
                [
                  ...((db.brand_library && db.brand_library.frases) || []).map((v) => ["Frase", v]),
                  ...((db.brand_library && db.brand_library.tono) || []).map((v) => ["Tono", v]),
                  ...((db.brand_library && db.brand_library.palabrasSi) || []).map((v) => ["Palabra sí", v]),
                  ...((db.brand_library && db.brand_library.palabrasNo) || []).map((v) => ["Palabra no", v]),
                ]],
              ["audit-log", ["Fecha","Usuario","Entidad","Id","Acción","De","A"],
                db.audit_logs.map((a) => [a.fecha, a.user, a.entidad, a.entidadId, a.accion, a.de, a.a])],
            ];
            tablas.forEach(([nombre, headers, rows], i) => setTimeout(() => downloadCSV("momos-" + nombre, headers, rows), i * 450));
            setBackupMsg(`Descargando ${tablas.length} archivos CSV… revisa tu carpeta de descargas.`);
          }}>⬇ Backup en CSV (todas las tablas)</Btn>
          <Btn small kind="ghost" onClick={() => {
            const blob = new Blob([JSON.stringify(db)], { type: "application/json" });
            const a = document.createElement("a");
            a.href = URL.createObjectURL(blob);
            a.download = "momos-backup-completo-" + hoyISO() + ".json";
            a.click();
            setTimeout(() => URL.revokeObjectURL(a.href), 2000);
            setBackupMsg("Respaldo JSON completo descargado (incluye fotos).");
          }}>⬇ Respaldo completo JSON</Btn>
        </div>
        <div className="mt-3 pt-3 border-t" style={{ borderColor: T.border }}>
          <div className="text-xs font-semibold mb-1.5" style={{ color: T.choco2 }}>♻️ Restaurar desde un respaldo JSON</div>
          <input type="file" accept="application/json" className="text-xs" onChange={(e) => {
            const file = e.target.files && e.target.files[0];
            if (!file) return;
            const reader = new FileReader();
            reader.onload = async () => {
              try {
                const data = JSON.parse(reader.result);
                if (!data || typeof data !== "object") { setBackupMsg("❌ El archivo no es un respaldo válido de MOMOS."); return; }
                if (data.version && data.version > DB_VERSION) { setBackupMsg("❌ Este backup pertenece a una versión más nueva de MOMOS OPS."); return; }
                const arraysReq = ["orders","order_items","customers","products"];
                const faltanArray = arraysReq.filter((t) => !Array.isArray(data[t]));
                if (faltanArray.length) { setBackupMsg("❌ El archivo no es un respaldo válido de MOMOS (tablas dañadas: " + faltanArray.join(", ") + ")."); return; }
                if (!data.settings || typeof data.settings !== "object" || Array.isArray(data.settings)) { setBackupMsg("❌ El archivo no es un respaldo válido de MOMOS (falta la configuración)."); return; }
                await restaurarBackup(data);
                setBackupMsg("Backup restaurado correctamente.");
              } catch (err) {
                setBackupMsg("❌ No se pudo restaurar: " + (err && err.message ? err.message : "formato inválido") + ".");
              }
            };
            reader.readAsText(file);
            e.target.value = "";
          }} />
          <div className="text-[11px] mt-1" style={{ color: T.choco2 }}>Reemplaza todos los datos actuales por los del archivo. Descarga antes un respaldo por si acaso.</div>
        </div>
        {backupMsg && <div className="text-xs font-bold mt-2" style={{ color: "#3F6B42" }}>{backupMsg}</div>}
      </Card>

      <Card className="p-4 mb-3">
        <div className="text-sm font-semibold mb-1">📷 Almacenamiento de fotos</div>
        <div className="text-xs font-bold p-2.5 rounded-xl" style={{ background: "#FBE8C8", color: "#96690F" }}>
          Las evidencias fotográficas se guardan en el bucket privado de <b>Supabase Storage</b>.
          Cada archivo queda ligado al pedido y al paso operativo correspondiente; las vistas temporales usan enlaces firmados que vencen automáticamente.
        </div>
      </Card>

      <Card className="p-4">
        <div className="text-sm font-semibold mb-2">Reiniciar datos de ejemplo</div>
        <div className="text-xs mb-3" style={{ color: T.choco2 }}>Borra todos los datos guardados y vuelve a cargar los datos de ejemplo de El Caney. Esta acción no se puede deshacer.</div>
        {!confirmar ? <Btn small kind="danger" onClick={() => setConfirmar(true)}>Reiniciar datos…</Btn> : (
          <div className="flex gap-2">
            <Btn small kind="danger" onClick={resetear}>Sí, borrar y reiniciar</Btn>
            <Btn small kind="ghost" onClick={() => setConfirmar(false)}>Cancelar</Btn>
          </div>
        )}
      </Card>
    </div>
  );
}


/* ================= MARKETING 📣 ================= */

function Marketing({ db, update, user, refrescar }) {
  const [nueva, setNueva] = useState(false);
  const [sel, setSel] = useState(null);
  const [form, setForm] = useState({ nombre: "", canal: "Instagram", objetivo: "Ventas", productoFoco: "", oferta: "", fechaInicio: hoyISO(), fechaFin: dISO(15), presupuesto: 0, gastoReal: 0, estado: "Planeada", responsable: "Marketing", notas: "" });

  const activas = db.campaigns.filter((c) => c.estado === "Activa");
  const totalPresup = db.campaigns.reduce((s, c) => s + (c.presupuesto || 0), 0);
  const totalGasto = db.campaigns.reduce((s, c) => s + (c.gastoReal || 0), 0);
  const conMetrics = db.campaigns.map((c) => ({ c, m: campaignMetrics(db, c) }));
  const mejores = [...conMetrics].filter((x) => x.m.roas !== null).sort((a, b) => b.m.roas - a.m.roas);
  const sinVentas = conMetrics.filter((x) => x.m.pedidos === 0 && x.c.estado !== "Planeada");

  function exportar() {
    downloadCSV("campanas",
      ["Id","Nombre","Canal","Objetivo","Producto foco","Oferta","Inicio","Fin","Presupuesto","Gasto real","Pedidos atrib.","Ventas atrib.","CAC","ROAS","Estado","Responsable"],
      conMetrics.map(({ c, m }) => [c.id, c.nombre, c.canal, c.objetivo, c.productoFoco, c.oferta, c.fechaInicio, c.fechaFin, c.presupuesto, c.gastoReal, m.pedidos, m.ventas, m.cac ? Math.round(m.cac) : "", m.roas ? m.roas.toFixed(2) : "", c.estado, c.responsable]));
  }

  // Fase 3 · Hito 2: la campaña nace en el SERVER (crear_campana). productoFoco (nombre) → id.
  async function guardar() {
    if (!form.nombre.trim()) { toast("error", "Falta el nombre de la campaña"); return; }
    const prodId = form.productoFoco ? (db.products.find((p) => p.nombre === form.productoFoco)?.id || null) : null;
    let res;
    try {
      res = await crearCampana({
        nombre: form.nombre, canal: form.canal, objetivo: form.objetivo,
        producto_foco_id: prodId, oferta: form.oferta,
        fecha_inicio: form.fechaInicio, fecha_fin: form.fechaFin,
        presupuesto: form.presupuesto, gasto_real: form.gastoReal,
        estado: form.estado, responsable: form.responsable, notas: form.notas,
      });
    } catch (e) { toast("error", e.message); return; }
    setNueva(false);
    setForm({ nombre: "", canal: "Instagram", objetivo: "Ventas", productoFoco: "", oferta: "", fechaInicio: hoyISO(), fechaFin: dISO(15), presupuesto: 0, gastoReal: 0, estado: "Planeada", responsable: "Marketing", notas: "" });
    toast("ok", `Campaña ${res.id} creada`);
    try { await refrescar(); } catch { toast("error", "Campaña creada; recargá para verla"); }
  }

  return (
    <div>
      <div className="grid grid-cols-2 lg:grid-cols-4 gap-3 mb-4">
        <Stat icon="📣" label="Campañas activas" value={activas.length} sub={db.campaigns.length + " en total"} tone={T.coral} />
        <Stat icon="💵" label="Presupuesto total" value={fmt(totalPresup)} sub={"gastado " + fmt(totalGasto)} />
        <Stat icon="🛒" label="Pedidos atribuidos" value={conMetrics.reduce((s, x) => s + x.m.pedidos, 0)} sub="con venta confirmada" tone="#3F6B42" />
        <Stat icon="📈" label="Ventas atribuidas" value={fmt(conMetrics.reduce((s, x) => s + x.m.ventas, 0))} sub="por campañas" tone="#3F6B42" />
      </div>

      <div className="flex flex-wrap gap-2 mb-4">
        <Btn onClick={() => setNueva(true)}>＋ Nueva campaña</Btn>
        <Btn small kind="ghost" onClick={exportar}>⬇ CSV</Btn>
      </div>

      {sinVentas.length > 0 && (
        <div className="text-xs font-bold p-2.5 rounded-xl mb-3" style={{ background: "#FBE8C8", color: "#96690F" }}>
          ⚠️ Campañas activas/finalizadas sin ventas atribuidas: {sinVentas.map((x) => x.c.nombre).join(", ")}
        </div>
      )}

      <SectionTitle>Campañas</SectionTitle>
      <div className="grid lg:grid-cols-2 gap-3">
        {conMetrics.map(({ c, m }) => {
          const usoPresup = c.presupuesto > 0 ? (c.gastoReal / c.presupuesto) : 0;
          return (
            <Card key={c.id} className="p-4" onClick={() => setSel(c)}>
              <div className="flex justify-between items-start gap-2">
                <div className="min-w-0">
                  <div className="font-bold text-sm truncate">{c.nombre}</div>
                  <div className="text-xs" style={{ color: T.choco2 }}>{c.objetivo} · {c.productoFoco || "sin producto foco"}</div>
                </div>
                <div className="flex flex-col items-end gap-1 shrink-0">
                  <Badge label={c.estado} />
                  <Badge label={c.canal} map={MK_CANAL_STYLE} />
                </div>
              </div>
              {c.oferta && <div className="text-xs mt-2 p-1.5 rounded-lg" style={{ background: T.vainilla }}>🎁 {c.oferta}</div>}
              <div className="mt-2">
                <div className="flex justify-between text-[11px] font-bold mb-1" style={{ color: T.choco2 }}>
                  <span>Presupuesto {fmt(c.presupuesto)}</span><span>Gasto {fmt(c.gastoReal)}</span>
                </div>
                <div className="h-2 rounded-full overflow-hidden" style={{ background: T.vainilla }}>
                  <div className="h-full rounded-full" style={{ width: Math.max(0, Math.min(100, usoPresup * 100)) + "%", background: usoPresup > 1 ? "#A03B2A" : T.rosaDeep }} />
                </div>
              </div>
              <div className="grid grid-cols-4 gap-2 mt-3 text-center">
                {[["Pedidos", m.pedidos, T.choco], ["Ventas", fmt(m.ventas), "#3F6B42"], ["CAC", m.cac !== null ? fmt(m.cac) : "—", "#96690F"], ["ROAS", m.roas !== null ? m.roas.toFixed(1) + "x" : "—", m.roas >= 1 ? "#3F6B42" : "#A03B2A"]].map(([lab, v, col]) => (
                  <div key={lab} className="rounded-xl py-2" style={{ background: T.vainilla }}>
                    <div className="text-sm font-bold truncate px-0.5" style={{ color: col }}>{v}</div>
                    <div className="text-[10px] font-bold" style={{ color: T.choco2 }}>{lab}</div>
                  </div>
                ))}
              </div>
              <div className="text-[11px] mt-2" style={{ color: T.choco2 }}>{c.fechaInicio} → {c.fechaFin} · {c.responsable}</div>
            </Card>
          );
        })}
      </div>

      {mejores.length > 0 && (
        <>
          <SectionTitle>🏆 Mejores campañas por ROAS</SectionTitle>
          <Card className="p-4"><Bars data={mejores.slice(0, 5).map((x) => ({ label: x.c.nombre, value: +x.m.roas.toFixed(2), color: T.rosaDeep }))} /></Card>
        </>
      )}

      {nueva && (
        <Modal title="Nueva campaña" onClose={() => setNueva(false)} wide>
          <div className="grid sm:grid-cols-2 gap-x-4">
            <Field label="Nombre"><Input value={form.nombre} onChange={(e) => setForm({ ...form, nombre: e.target.value })} placeholder="Ej: Lanzamiento Gatitos" /></Field>
            <Field label="Canal"><Select options={MK_CANALES} value={form.canal} onChange={(e) => setForm({ ...form, canal: e.target.value })} /></Field>
            <Field label="Objetivo"><Select options={MK_OBJETIVOS} value={form.objetivo} onChange={(e) => setForm({ ...form, objetivo: e.target.value })} /></Field>
            <Field label="Producto foco"><Select placeholder="Sin producto foco" options={db.products.map((p) => p.nombre)} value={form.productoFoco} onChange={(e) => setForm({ ...form, productoFoco: e.target.value })} /></Field>
            <Field label="Oferta"><Input value={form.oferta} onChange={(e) => setForm({ ...form, oferta: e.target.value })} placeholder="Ej: 2x1, envío gratis…" /></Field>
            <Field label="Responsable"><Input value={form.responsable} onChange={(e) => setForm({ ...form, responsable: e.target.value })} /></Field>
            <Field label="Fecha inicio"><Input type="date" value={form.fechaInicio} onChange={(e) => setForm({ ...form, fechaInicio: e.target.value })} /></Field>
            <Field label="Fecha fin"><Input type="date" value={form.fechaFin} onChange={(e) => setForm({ ...form, fechaFin: e.target.value })} /></Field>
            <Field label="Presupuesto"><Input type="number" value={form.presupuesto} onChange={(e) => setForm({ ...form, presupuesto: +e.target.value })} /></Field>
            <Field label="Gasto real"><Input type="number" value={form.gastoReal} onChange={(e) => setForm({ ...form, gastoReal: +e.target.value })} /></Field>
            <Field label="Estado"><Select options={CAMP_ESTADOS} value={form.estado} onChange={(e) => setForm({ ...form, estado: e.target.value })} /></Field>
          </div>
          <Field label="Notas"><Input value={form.notas} onChange={(e) => setForm({ ...form, notas: e.target.value })} /></Field>
          <div className="flex gap-2 mt-2"><BtnAsync onClick={guardar} textoEnVuelo="Creando…">Crear campaña</BtnAsync><Btn kind="ghost" onClick={() => setNueva(false)}>Cancelar</Btn></div>
        </Modal>
      )}

      {sel && (
        <Modal title={sel.nombre} onClose={() => setSel(null)} wide>
          <div className="flex flex-wrap gap-2 mb-3"><Badge label={sel.estado} /><Badge label={sel.canal} map={MK_CANAL_STYLE} /><span className="text-xs font-semibold" style={{ color: T.choco2 }}>{sel.objetivo}</span></div>
          <div className="grid sm:grid-cols-2 gap-x-4">
            <Field label="Estado">
              <select value={sel.estado} onChange={(e) => setSel({ ...sel, estado: e.target.value })} className={inputCls} style={inputStyle}>{CAMP_ESTADOS.map((s) => <option key={s}>{s}</option>)}</select>
            </Field>
            {/* String crudo (no +coerción): vaciar el input queda '' y el PATCH lo OMITE — no pisa a 0. */}
            <Field label="Gasto real"><Input type="number" value={sel.gastoReal} onChange={(e) => setSel({ ...sel, gastoReal: e.target.value })} /></Field>
            <Field label="Presupuesto"><Input type="number" value={sel.presupuesto} onChange={(e) => setSel({ ...sel, presupuesto: e.target.value })} /></Field>
            <Field label="Oferta"><Input value={sel.oferta} onChange={(e) => setSel({ ...sel, oferta: e.target.value })} /></Field>
          </div>
          <Field label="Notas"><Input value={sel.notas} onChange={(e) => setSel({ ...sel, notas: e.target.value })} /></Field>
          <div className="text-xs font-semibold mb-3 p-2.5 rounded-xl" style={{ background: T.vainilla, color: T.choco2 }}>
            Creativos de esta campaña: {db.creatives.filter((cr) => cr.campaignId === sel.id).length} · Pedidos atribuidos: {ordersDeCampaign(db, sel.id).length}
          </div>
          <div className="flex gap-2">
            <BtnAsync onClick={async () => {
              // PATCH por DIFF: solo las claves que cambiaron respecto del valor hidratado (el
              // resto — nombre, canal, foco, fechas — queda intacto server-side). Los numéricos
              // van solo si quedaron con un número válido: vaciar el input NO pisa el dato a 0.
              const orig = db.campaigns.find((x) => x.id === sel.id) || sel;
              const patch = {};
              if (sel.estado !== orig.estado) patch.estado = sel.estado;
              if (sel.oferta !== orig.oferta) patch.oferta = sel.oferta;
              if (sel.notas !== orig.notas) patch.notas = sel.notas;
              if (String(sel.presupuesto).trim() !== "" && !Number.isNaN(+sel.presupuesto) && +sel.presupuesto !== orig.presupuesto) patch.presupuesto = +sel.presupuesto;
              if (String(sel.gastoReal).trim() !== "" && !Number.isNaN(+sel.gastoReal) && +sel.gastoReal !== orig.gastoReal) patch.gasto_real = +sel.gastoReal;
              if (Object.keys(patch).length === 0) { setSel(null); toast("ok", "Sin cambios"); return; }
              let res;
              try {
                res = await editarCampana(sel.id, patch);
              } catch (e) { toast("error", e.message); return; }
              setSel(null);
              toast("ok", res.cambio_estado ? `Campaña → ${sel.estado}` : "Campaña actualizada");
              try { await refrescar(); } catch { toast("error", "Guardado; recargá para verlo"); }
            }}>Guardar</BtnAsync>
            <Btn kind="ghost" onClick={() => setSel(null)}>Cancelar</Btn>
          </div>
        </Modal>
      )}
    </div>
  );
}

/* ================= CREATIVOS 🎨 ================= */

function Creativos({ db, refrescar }) {
  const [nuevo, setNuevo] = useState(false);
  const [sel, setSel] = useState(null);
  const [selBase, setSelBase] = useState(null);
  const [fEstado, setFEstado] = useState("");
  const vacio = { campaignId: "", titulo: "", canal: "Instagram", formato: "Reel", productoFoco: "", figuraFoco: "", saborFoco: "", hook: "", copy: "", guion: "", estado: "Idea", responsable: "Marketing", fechaEntrega: dISO(3), assetUrl: "", notas: "" };
  const [form, setForm] = useState(vacio);
  const sabores = [...db.settings.saboresFrutales, ...db.settings.saboresCremosos];

  const grupos = [["Idea","Ideas pendientes"],["En diseño","En diseño"],["En revisión","En revisión"],["Aprobado","Aprobados"],["Publicado","Publicados"],["Ganador","Ganadores"]];
  const lista = db.creatives.filter((c) => !fEstado || c.estado === fEstado);

  function exportar() {
    downloadCSV("creativos",
      ["Id","Campaña","Título","Canal","Formato","Producto","Figura","Sabor","Hook","Estado","Responsable","Entrega"],
      db.creatives.map((c) => { const camp = db.campaigns.find((x) => x.id === c.campaignId); return [c.id, camp ? camp.nombre : "", c.titulo, c.canal, c.formato, c.productoFoco, c.figuraFoco, c.saborFoco, c.hook, c.estado, c.responsable, c.fechaEntrega]; }));
  }

  function payloadCreativo(f) {
    const prodId = f.productoFoco ? (db.products.find((p) => p.nombre === f.productoFoco)?.id || null) : null;
    return {
      campaign_id: f.campaignId || null, titulo: f.titulo, canal: f.canal, formato: f.formato,
      producto_foco_id: prodId, figura: f.figuraFoco || null, sabor: f.saborFoco || null,
      hook: f.hook, copy: f.copy, guion: f.guion, estado: f.estado,
      responsable: f.responsable, fecha_entrega: f.fechaEntrega || null,
      asset_url: f.assetUrl, notas: f.notas,
    };
  }

  async function guardar() {
    if (!form.titulo.trim()) { toast("error", "Falta el título del creativo"); return; }
    let res;
    try { res = await crearCreativo(payloadCreativo(form)); }
    catch (e) { toast("error", e.message); return; }
    setNuevo(false); setForm(vacio);
    toast("ok", `Creativo ${res.id} creado`);
    try { await refrescar(); } catch { toast("error", "Creativo creado; recargá para verlo"); }
  }

  async function guardarEdicion() {
    // El baseline queda congelado al abrir el modal. Comparar contra el polling
    // más reciente podría reenviar valores viejos y pisar cambios de otro equipo.
    const orig = selBase || sel;
    const antes = payloadCreativo(orig);
    const despues = payloadCreativo(sel);
    const patch = {};
    Object.keys(despues).forEach((k) => { if (despues[k] !== antes[k]) patch[k] = despues[k]; });
    if (!Object.keys(patch).length) { setSel(null); setSelBase(null); toast("ok", "Sin cambios"); return; }
    let res;
    try { res = await editarCreativo(sel.id, patch); }
    catch (e) { toast("error", e.message); return; }
    setSel(null); setSelBase(null);
    toast("ok", res.cambio_estado ? `Creativo → ${sel.estado}` : "Creativo actualizado");
    try { await refrescar(); } catch { toast("error", "Guardado; recargá para verlo"); }
  }

  async function crearPostDesdeCreativo() {
    let res;
    try {
      res = await crearPublicacion({
        fecha: hoyISO(), hora: "12:00", canal: sel.canal,
        creative_id: sel.id, titulo: sel.titulo, copy_final: sel.copy || "",
        estado: "Programado", url_publicacion: "", notas: "Creado desde Creativos",
      });
    } catch (e) { toast("error", e.message); return; }
    setSel(null); setSelBase(null);
    toast("ok", `Publicación ${res.id} creada`);
    try { await refrescar(); } catch { toast("error", "Publicación creada; recargá para verla"); }
  }

  return (
    <div>
      <div className="grid grid-cols-3 lg:grid-cols-6 gap-2 mb-4">
        {grupos.map(([est, lab]) => (
          <Card key={est} className="p-3 text-center" onClick={() => setFEstado(fEstado === est ? "" : est)}>
            <div className="display text-xl" style={{ color: est === "Ganador" ? "#8E4B5A" : est === "Publicado" ? "#2F6B60" : T.choco }}>{db.creatives.filter((c) => c.estado === est).length}</div>
            <div className="text-[10px] font-bold leading-tight" style={{ color: T.choco2 }}>{lab}</div>
          </Card>
        ))}
      </div>

      <div className="flex flex-wrap gap-2 mb-4">
        <Btn onClick={() => setNuevo(true)}>＋ Nuevo creativo</Btn>
        <Btn small kind="ghost" onClick={exportar}>⬇ CSV</Btn>
        {fEstado && <Btn small kind="ghost" onClick={() => setFEstado("")}>Ver todos ({db.creatives.length})</Btn>}
      </div>

      <div className="grid sm:grid-cols-2 lg:grid-cols-3 gap-3">
        {lista.map((c) => {
          const camp = db.campaigns.find((x) => x.id === c.campaignId);
          const pedidos = ordersDeCreative(db, c.id).length;
          return (
            <Card key={c.id} className="p-4" onClick={() => { setSel({ ...c }); setSelBase({ ...c }); }}>
              <div className="flex justify-between items-start gap-2">
                <div className="min-w-0">
                  <div className="font-bold text-sm leading-tight">{c.titulo}</div>
                  <div className="text-[11px] mt-0.5" style={{ color: T.choco2 }}>{c.formato} · {camp ? camp.nombre : "sin campaña"}</div>
                </div>
                <Badge label={c.estado} />
              </div>
              {c.hook && <div className="text-xs mt-2 italic p-2 rounded-lg" style={{ background: T.vainilla, color: T.choco }}>“{c.hook}”</div>}
              <div className="flex flex-wrap gap-1.5 mt-2">
                <Badge label={c.canal} map={MK_CANAL_STYLE} />
                {c.productoFoco && <span className="text-[10px] font-bold px-2 py-0.5 rounded-full" style={{ background: T.vainilla, color: T.choco2 }}>{c.productoFoco}</span>}
              </div>
              <div className="flex justify-between items-center mt-2 text-[11px] font-semibold" style={{ color: T.choco2 }}>
                <span>{c.responsable} · entrega {c.fechaEntrega}</span>
                {pedidos > 0 && <span style={{ color: "#3F6B42" }}>{pedidos} pedido(s)</span>}
              </div>
            </Card>
          );
        })}
        {lista.length === 0 && <Empty icon="🎨" text="No hay creativos en este estado." />}
      </div>

      {(nuevo || sel) && (
        <Modal title={sel ? sel.titulo : "Nuevo creativo"} onClose={() => { setNuevo(false); setSel(null); setSelBase(null); }} wide>
          {(() => { const f = sel || form; const setF = sel ? setSel : setForm;
            return (
              <>
                {sel && selBase && sel.estado !== selBase.estado && (
                  <div className="flex flex-wrap items-center gap-2 mb-3 px-3 py-2 rounded-xl text-xs font-bold" style={{ background: "#FFF1D6", color: "#7A5510" }} role="status">
                    <span>Cambio listo para guardar</span>
                    <Badge label={selBase.estado} />
                    <span aria-hidden="true">→</span>
                    <Badge label={sel.estado} />
                  </div>
                )}
                <div className="grid sm:grid-cols-2 gap-x-4">
                  <Field label="Título"><Input value={f.titulo} onChange={(e) => setF({ ...f, titulo: e.target.value })} placeholder="Nombre interno del creativo" /></Field>
                  <Field label="Campaña">
                    <select value={f.campaignId} onChange={(e) => setF({ ...f, campaignId: e.target.value })} className={inputCls} style={inputStyle}>
                      <option value="">Sin campaña</option>
                      {db.campaigns.map((c) => <option key={c.id} value={c.id}>{c.nombre}</option>)}
                    </select>
                  </Field>
                  <Field label="Canal"><Select options={MK_CANALES} value={f.canal} onChange={(e) => setF({ ...f, canal: e.target.value })} /></Field>
                  <Field label="Formato"><Select options={MK_FORMATOS} value={f.formato} onChange={(e) => setF({ ...f, formato: e.target.value })} /></Field>
                  <Field label="Producto foco"><Select placeholder="—" options={db.products.map((p) => p.nombre)} value={f.productoFoco} onChange={(e) => setF({ ...f, productoFoco: e.target.value })} /></Field>
                  <Field label="Figura foco"><Select placeholder="—" options={db.settings.figuras.map((x) => x.nombre)} value={f.figuraFoco} onChange={(e) => setF({ ...f, figuraFoco: e.target.value })} /></Field>
                  <Field label="Sabor foco"><Select placeholder="—" options={sabores} value={f.saborFoco} onChange={(e) => setF({ ...f, saborFoco: e.target.value })} /></Field>
                  <Field label="Estado"><Select options={CREA_ESTADOS} value={f.estado} onChange={(e) => setF({ ...f, estado: e.target.value })} /></Field>
                  <Field label="Responsable"><Input value={f.responsable} onChange={(e) => setF({ ...f, responsable: e.target.value })} /></Field>
                  <Field label="Fecha de entrega"><Input type="date" value={f.fechaEntrega} onChange={(e) => setF({ ...f, fechaEntrega: e.target.value })} /></Field>
                </div>
                <Field label="Hook (gancho)"><Input value={f.hook} onChange={(e) => setF({ ...f, hook: e.target.value })} placeholder="La frase que detiene el scroll" /></Field>
                <Field label="Copy">
                  <textarea rows={2} value={f.copy} onChange={(e) => setF({ ...f, copy: e.target.value })} className="w-full rounded-xl px-3 py-2.5 text-sm border outline-none resize-y" style={{ ...inputStyle, fontFamily: "inherit" }} placeholder="Texto de la publicación" />
                </Field>
                <Field label="Guion">
                  <textarea rows={2} value={f.guion} onChange={(e) => setF({ ...f, guion: e.target.value })} className="w-full rounded-xl px-3 py-2.5 text-sm border outline-none resize-y" style={{ ...inputStyle, fontFamily: "inherit" }} placeholder="Escenas o pasos del video" />
                </Field>
                <Field label="URL del asset (opcional)"><Input value={f.assetUrl} onChange={(e) => setF({ ...f, assetUrl: e.target.value })} placeholder="Link a Drive, Canva…" /></Field>
                <Field label="Notas"><Input value={f.notas} onChange={(e) => setF({ ...f, notas: e.target.value })} /></Field>
                <div className="flex gap-2 mt-2 flex-wrap">
                  {sel ? (
                    <BtnAsync onClick={guardarEdicion}>Guardar</BtnAsync>
                  ) : (
                    <BtnAsync onClick={guardar} textoEnVuelo="Creando…">Crear creativo</BtnAsync>
                  )}
                  {sel && ["Aprobado","Publicado","Ganador"].includes(sel.estado) && (
                    <BtnAsync kind="soft" onClick={crearPostDesdeCreativo} textoEnVuelo="Creando…">🗓️ Crear publicación</BtnAsync>
                  )}
                  <Btn kind="ghost" onClick={() => { setNuevo(false); setSel(null); setSelBase(null); }}>Cancelar</Btn>
                </div>
              </>
            );
          })()}
        </Modal>
      )}
    </div>
  );
}

/* ================= CALENDARIO 🗓️ ================= */

function Calendario({ db, refrescar }) {
  const [nueva, setNueva] = useState(false);
  const [vista, setVista] = useState(() => {
    const requested = window.sessionStorage.getItem("momos:calendar-view");
    window.sessionStorage.removeItem("momos:calendar-view");
    return requested === "Distribución" ? requested : "Activas";
  });
  const [distributionDraft, setDistributionDraft] = useState(null);
  const vacio = { fecha: hoyISO(), hora: "12:00", canal: "Instagram", campaignId: "", creativeId: "", titulo: "", copyFinal: "", estado: "Pendiente", urlPublicacion: "", notas: "" };
  const [form, setForm] = useState(vacio);
  const cambiosRef = useRef(new Set());
  const [estadosPendientes, setEstadosPendientes] = useState({});
  const vivoRef = useRef(true);
  useEffect(() => { vivoRef.current = true; return () => { vivoRef.current = false; }; }, []);

  const commercialCalendar = useMemo(() => buildCommercialCalendar(db, hoyISO()), [db]);
  const distributionRoom = useMemo(() => buildDistributionRoom(db, hoyISO(), new Date().toLocaleTimeString("en-GB", { timeZone: "America/Bogota", hour: "2-digit", minute: "2-digit" })), [db]);
  const distributionQueue = useMemo(() => distributionRoom.queue.map((item) => enrichDistributionWithDispatch(item, db)), [distributionRoom, db]);
  const formScheduleGuard = useMemo(() => form.creativeId
    ? calendarTransitionGuard({ ...form, id: "CAL-DRAFT", estado: "Pendiente" }, "Programado", db, hoyISO())
    : null, [form, db]);
  const semana = commercialCalendar.weekDates;
  const pubs = vista === "Activas" ? commercialCalendar.active : commercialCalendar.history;
  const todos = [...db.content_calendar].sort((a, b) => `${a.fecha}${a.hora}${a.id}`.localeCompare(`${b.fecha}${b.hora}${b.id}`));

  function exportar() {
    downloadCSV("calendario",
      ["Id","Fecha","Hora","Canal","Campaña","Creativo","Título","Estado","URL"],
      todos.map((p) => { const camp = db.campaigns.find((x) => x.id === p.campaignId); const cre = db.creatives.find((x) => x.id === p.creativeId); return [p.id, p.fecha, p.hora, p.canal, camp ? camp.nombre : "", cre ? cre.titulo : "", p.titulo, p.estado, p.urlPublicacion]; }));
  }

  function planificarCreativo(creative) {
    setForm({ ...vacio, ...buildPostDraftFromCreative(creative, db, hoyISO()) });
    setNueva(true);
  }

  function abrirPreparacion(item) {
    const checklist = {};
    distributionChecklistFor(item.post, db).forEach((step) => { checklist[step.key] = item.run?.checklist?.[step.key] === true; });
    setDistributionDraft({ mode: "prepare", item, checklist, notes: item.run?.notes || "", externalUrl: "", externalPostId: "", reason: "" });
  }

  function abrirCierre(item, mode = "publish") {
    setDistributionDraft({ mode, item, checklist: item.run?.checklist || {}, notes: "", externalUrl: item.dispatch?.job?.externalUrl || item.run?.externalUrl || "", externalPostId: item.dispatch?.job?.providerJobId || item.run?.externalPostId || "", reason: item.run?.failureReason || "" });
  }

  async function autorizarSalidaConector(item) {
    const eligibility = item.dispatch?.eligibility;
    if (!eligibility?.allowed) { toast("error", eligibility?.reasons?.[0] || "El conector todavía no está listo."); return; }
    try {
      const result = await autorizarDespachoDistribucion(item.post.id, eligibility.mode);
      toast("ok", result.duplicate ? `El despacho ya estaba ${result.status}` : `${eligibility.provider} autorizado · MOMO OPS lo enviará una sola vez`);
      await refrescar();
    } catch (error) { toast("error", error.message); }
  }

  async function reintentarSalidaConector(item) {
    const job = item.dispatch?.job;
    if (!job) return;
    try { await reintentarDespachoDistribucion(job.id); toast("ok", "Nuevo intento autorizado con una clave idempotente nueva"); await refrescar(); }
    catch (error) { toast("error", error.message); }
  }

  async function guardarPreparacionComercial() {
    const draft = distributionDraft;
    if (!draft) return;
    if (!db.distributionServerReady) { toast("error", "Aplicá la migración 19 para guardar la distribución trazable."); return; }
    const guard = validateDistributionAction("prepare", draft.item.post, db, draft.item.run, {}, hoyISO());
    if (!guard.allowed) { toast("error", guard.reasons[0]); return; }
    try {
      const res = await guardarPreparacionDistribucion(draft.item.post.id, draft.checklist, draft.notes);
      toast("ok", res.status === "Lista" ? "Checklist completo · salida Lista para aprobación" : "Preparación guardada");
      setDistributionDraft(null); await refrescar();
    } catch (error) { toast("error", error.message); }
  }

  async function aprobarSalidaComercial(item) {
    if (!db.distributionServerReady) { toast("error", "Aplicá la migración 19 para aprobar distribuciones."); return; }
    const guard = validateDistributionAction("approve", item.post, db, item.run, {}, hoyISO());
    if (!guard.allowed) { toast("error", guard.reasons[0]); return; }
    try { await aprobarDistribucion(item.post.id); toast("ok", "Salida aprobada · lista para publicar en su horario"); await refrescar(); }
    catch (error) { toast("error", error.message); }
  }

  async function cerrarSalidaComercial() {
    const draft = distributionDraft;
    if (!draft) return;
    if (!db.distributionServerReady) { toast("error", "Aplicá la migración 19 para cerrar distribuciones."); return; }
    const action = draft.mode === "fail" ? "fail" : "publish";
    const payload = action === "fail" ? { reason: draft.reason } : { externalUrl: draft.externalUrl, externalPostId: draft.externalPostId };
    const guard = validateDistributionAction(action, draft.item.post, db, draft.item.run, payload, hoyISO(), new Date().toLocaleTimeString("en-GB", { timeZone: "America/Bogota", hour: "2-digit", minute: "2-digit" }));
    if (!guard.allowed) { toast("error", guard.reasons[0]); return; }
    try {
      await cerrarDistribucionPublicacion(draft.item.post.id, action === "fail" ? "Fallida" : "Publicada", draft.externalUrl, draft.externalPostId, action === "fail" ? draft.reason : draft.notes);
      toast("ok", action === "fail" ? "Fallo registrado sin perder trazabilidad" : "Publicación cerrada con evidencia externa");
      setDistributionDraft(null); await refrescar();
    } catch (error) { toast("error", error.message); }
  }

  async function guardar() {
    if (!form.titulo.trim()) { toast("error", "Falta el título de la publicación"); return; }
    if (form.estado === "Programado" && formScheduleGuard && !formScheduleGuard.allowed) { toast("error", formScheduleGuard.reasons[0]); return; }
    let res;
    try {
      res = await crearPublicacion({
        fecha: form.fecha, hora: form.hora, canal: form.canal,
        campaign_id: form.campaignId || null, creative_id: form.creativeId || null,
        titulo: form.titulo, copy_final: form.copyFinal, estado: form.estado,
        url_publicacion: form.urlPublicacion, notas: form.notas,
      });
    } catch (e) { toast("error", e.message); return; }
    setNueva(false); setForm(vacio);
    toast("ok", `Publicación ${res.id} creada`);
    try { await refrescar(); } catch { toast("error", "Publicación creada; recargá para verla"); }
  }

  async function cambiarEstado(p, estado) {
    if (cambiosRef.current.has(p.id) || estado === p.estado) return;
    if (db.distributionServerReady && estado === "Publicado") { toast("error", "Publicá y registrá la evidencia desde la pestaña Distribución."); return; }
    if (db.distributionServerReady && estado === "No publicado" && db.content_distributions.some((run) => run.postId === p.id)) { toast("error", "La salida preparada debe cerrarse como fallo desde Distribución."); return; }
    const guard = calendarTransitionGuard(p, estado, db, hoyISO());
    if (!guard.allowed) { toast("error", guard.reasons[0]); return; }
    cambiosRef.current.add(p.id);
    setEstadosPendientes((actuales) => ({ ...actuales, [p.id]: estado }));
    try {
      let res;
      try { res = await setPublicacionEstado(p.id, estado); }
      catch (e) { toast("error", e.message); return; }
      toast("ok", res.cambio ? `Publicación → ${estado}` : "Sin cambios");
      try { await refrescar(); } catch { toast("error", "Guardado; recargá para verlo"); }
    } finally {
      cambiosRef.current.delete(p.id);
      if (vivoRef.current) setEstadosPendientes((actuales) => {
        const siguientes = { ...actuales };
        delete siguientes[p.id];
        return siguientes;
      });
    }
  }

  return (
    <div>
      <SectionTitle action={
        <div className="inline-flex items-center gap-2 rounded-full px-3 py-1.5 shrink-0" style={{ background: T.soft, border: `1px solid ${T.border}` }}>
          <span className="display font-semibold" style={{ color: T.coral, fontVariantNumeric: "tabular-nums" }}>{commercialCalendar.summary.readyToday}/{commercialCalendar.summary.today}</span>
          <span className="text-xs font-bold" style={{ color: T.choco2 }}>listas hoy</span>
        </div>
      }>Calendario inteligente MOMOS</SectionTitle>
      <div className="text-xs font-semibold mb-4 -mt-3" style={{ color: T.choco2 }}>Ordena la semana, valida marca y stock, y muestra exactamente qué debe ejecutar Marketing.</div>

      <div className="grid grid-cols-2 lg:grid-cols-4 gap-3 mb-4">
        <Stat icon="🗓️" label="Activas esta semana" value={<CountUp value={commercialCalendar.summary.scheduledWeek} />} tone={T.coral} />
        <Stat icon="⛔" label="Bloqueadas" value={<CountUp value={commercialCalendar.summary.blocked} />} sub="requieren corrección" tone="#A03B2A" />
        <Stat icon="⏰" label="Vencidas" value={<CountUp value={commercialCalendar.summary.overdue} />} sub="sin cerrar" tone="#96690F" />
        <Stat icon="✦" label="Por programar" value={<CountUp value={commercialCalendar.summary.unscheduledApproved} />} sub="creativos aprobados" tone="#3F6B42" />
      </div>

      {commercialCalendar.summary.blocked > 0 && <div className="rounded-2xl px-4 py-3 mb-4 flex items-start gap-3" style={{ background: "#FFF1ED", color: "#A03B2A", border: "1px solid #F0C1B8" }} role="alert"><span className="text-lg">⚠</span><div><div className="text-sm font-extrabold">{commercialCalendar.summary.blocked} publicación(es) no deberían programarse todavía</div><div className="text-xs mt-0.5">Revisá aprobación del creativo, copy, canal, campaña y disponibilidad antes de continuar.</div></div></div>}

      {commercialCalendar.agenda.length > 0 && <>
        <SectionTitle>Agenda priorizada de Marketing</SectionTitle>
        <div className="grid md:grid-cols-2 xl:grid-cols-3 gap-3 mb-4">
          {commercialCalendar.agenda.slice(0, 6).map((item) => <div key={item.id} className="rounded-2xl border p-4" style={{ borderColor: item.post.preflight.ready ? T.border : "#E8B7AD", background: item.post.preflight.ready ? "#fff" : "#FFF6F3" }}>
            <div className="flex items-start justify-between gap-2"><div className="text-[10px] uppercase tracking-wider font-extrabold" style={{ color: item.priority >= 90 ? "#A03B2A" : T.coral }}>{item.action}</div><Badge label={item.post.estado} /></div>
            <div className="font-bold text-sm mt-1">{item.post.titulo}</div>
            <div className="text-xs mt-1" style={{ color: T.choco2 }}>{item.post.fecha} · {item.post.hora} · {item.post.canal}</div>
            {!item.post.preflight.ready && <div className="text-[11px] font-bold mt-2" style={{ color: "#A03B2A" }}>⛔ {item.post.preflight.errors[0]?.message}</div>}
          </div>)}
        </div>
      </>}

      {commercialCalendar.planningQueue.length > 0 && <>
        <SectionTitle>Creativos aprobados esperando fecha</SectionTitle>
        <div className="flex gap-3 overflow-x-auto pb-3 mb-2">
          {commercialCalendar.planningQueue.slice(0, 8).map(({ creative, draft, preflight }) => <div key={creative.id} className="w-72 shrink-0 rounded-2xl border p-4" style={{ borderColor: preflight.ready ? T.border : "#E8B7AD", background: T.soft }}>
            <div className="flex justify-between gap-2"><div className="text-[10px] uppercase tracking-wider font-extrabold" style={{ color: T.coral }}>{creative.formato} · {creative.canal}</div><Badge label={creative.estado} /></div>
            <div className="display font-semibold mt-1">{creative.titulo}</div>
            <div className="text-xs mt-1 mb-3" style={{ color: T.choco2 }}>Sugerencia: {draft.fecha} · {draft.hora}</div>
            <Btn small kind={preflight.ready ? "primary" : "ghost"} onClick={() => planificarCreativo(creative)}>{preflight.ready ? "Planificar" : "Revisar borrador"}</Btn>
          </div>)}
        </div>
      </>}

      <div className="flex flex-wrap items-center justify-between gap-3 mb-4">
        <div className="momo-segmented-tabs inline-flex gap-1 p-1.5 rounded-2xl" role="tablist" aria-label="Bandejas del calendario">
          {["Activas","Distribución","Historial"].map((tab) => <button key={tab} type="button" role="tab" aria-selected={vista === tab} onClick={() => setVista(tab)} className="rounded-xl border-0 px-4 py-2 text-xs font-extrabold" style={{ background: vista === tab ? T.coral : "transparent", color: vista === tab ? "#fff" : T.choco2 }}>{tab} <span className="ml-1 opacity-75">{tab === "Activas" ? commercialCalendar.active.length : tab === "Distribución" ? distributionRoom.queue.length : commercialCalendar.history.length}</span></button>)}
        </div>
        <div className="flex gap-2"><Btn onClick={() => { setForm(vacio); setNueva(true); }}>＋ Nueva publicación</Btn>
        <Btn small kind="ghost" onClick={exportar}>⬇ CSV</Btn>
        </div>
      </div>

      <SectionTitle>{vista === "Activas" ? "Bandeja activa por día" : vista === "Distribución" ? "Sala de distribución comercial" : "Historial de publicaciones"}</SectionTitle>
      {vista === "Activas" ? <div className="flex gap-3 overflow-x-auto pb-3 -mx-1 px-1">
        {semana.map((dia, i) => {
          const delDia = pubs.filter((p) => p.fecha === dia);
          const esHoy = dia === hoyISO();
          return (
            <div key={dia} className="momo-trace-open w-56 shrink-0" style={{ animationDelay: `${i * 55}ms` }}>
              <div className="flex items-center justify-between mb-2 px-1">
                <span className="text-xs font-bold" style={{ color: esHoy ? T.coral : T.choco2 }}>{new Date(dia + "T12:00:00").toLocaleDateString("es-CO", { weekday: "short", day: "numeric" })}{esHoy && " · hoy"}</span>
                <span className="text-xs font-bold" style={{ color: T.choco2, fontVariantNumeric: "tabular-nums" }}>{delDia.length}</span>
              </div>
              <div className="flex flex-col gap-2 min-h-[60px] rounded-2xl p-2" style={{ background: esHoy ? T.vainilla : T.vainilla + "80", border: esHoy ? `1.5px solid ${T.coral}40` : "1.5px solid transparent" }}>
                {delDia.map((p) => {
                  const cre = db.creatives.find((x) => x.id === p.creativeId);
                  const estadoPendiente = estadosPendientes[p.id];
                  return (
                    <Card key={p.id} className="momo-cal-card p-2.5">
                      <div className="flex justify-between items-start gap-1">
                        <span className="text-xs font-bold" style={{ fontVariantNumeric: "tabular-nums" }}>{p.hora}</span>
                        <Badge label={p.canal} map={MK_CANAL_STYLE} />
                      </div>
                      <div className="text-xs font-semibold mt-1 leading-tight">{p.titulo}</div>
                      {cre && <div className="text-[10px] mt-0.5" style={{ color: T.choco2 }}>🎨 {cre.titulo}</div>}
                      <div className="mt-2 rounded-lg px-2 py-1.5 text-[10px] font-bold" style={{ background: p.preflight.ready ? "#E8F1E4" : "#F6D4CD", color: p.preflight.ready ? "#3F6B42" : "#A03B2A" }}>{p.preflight.ready ? "✓ Preflight completo" : `⛔ ${p.preflight.errors[0]?.message}`}</div>
                      <select value={estadoPendiente ?? p.estado} disabled={Boolean(estadoPendiente)} onChange={(e) => cambiarEstado(p, e.target.value)} className="mt-2 w-full rounded-lg px-1.5 py-1 text-[11px] border font-bold disabled:opacity-60" style={inputStyle}>
                        {(db.distributionServerReady ? CAL_ESTADOS.filter((state) => state !== "Publicado") : CAL_ESTADOS).map((s) => <option key={s}>{s}</option>)}
                      </select>
                      {estadoPendiente && (
                        <div className="flex items-center justify-center gap-1.5 mt-1.5 text-[10px] font-bold" style={{ color: "#96690F" }} role="status">
                          <span className="inline-block w-2.5 h-2.5 rounded-full border-2 border-current border-t-transparent animate-spin" aria-hidden="true" />
                          Guardando → {estadoPendiente}
                        </div>
                      )}
                    </Card>
                  );
                })}
                {delDia.length === 0 && <div className="text-[11px] text-center py-3 font-semibold" style={{ color: T.choco2 }}>Sin publicaciones</div>}
              </div>
            </div>
          );
        })}
      </div> : vista === "Distribución" ? <div id="agency-distribution-room" className="scroll-mt-24">
        {!db.distributionServerReady && <div className="rounded-2xl px-4 py-3 mb-4 flex items-start gap-3" style={{ background: "#FFF5E4", border: "1px solid #EDD4A8", color: "#7B5410" }} role="status"><span className="text-lg">🛡️</span><div><div className="text-sm font-extrabold">Vista previa protegida</div><div className="text-xs mt-0.5">Aplicá la migración 19 para guardar checklist, aprobación humana y evidencia externa.</div></div></div>}
        {db.distributionServerReady && !db.distributionConnectorReady && <div className="rounded-2xl px-4 py-3 mb-4 flex items-start gap-3" style={{ background: "#FFF5E4", border: "1px solid #EDD4A8", color: "#7B5410" }} role="status"><span className="text-lg">🔌</span><div><div className="text-sm font-extrabold">Distribución manual activa</div><div className="text-xs mt-0.5">La migración 29 habilita la cola protegida para Meta y borradores de TikTok; hasta entonces el registro manual sigue disponible.</div></div></div>}
        <div className="grid grid-cols-2 lg:grid-cols-5 gap-2.5 mb-4">
          <Stat icon="⏱️" label="Deben salir" value={<CountUp value={distributionRoom.summary.due} />} tone={T.coral} />
          <Stat icon="✓" label="Aprobadas" value={<CountUp value={distributionRoom.summary.ready} />} tone="#3F6B42" />
          <Stat icon="👀" label="Por aprobar" value={<CountUp value={distributionRoom.summary.awaitingApproval} />} tone="#3E5C7E" />
          <Stat icon="⛔" label="Bloqueadas" value={<CountUp value={distributionRoom.summary.blocked} />} tone="#A03B2A" />
          <Stat icon="📊" label="Sin métricas" value={<CountUp value={distributionRoom.summary.needsMetrics} />} tone="#96690F" />
        </div>
        <div className="grid lg:grid-cols-2 gap-3">
          {distributionQueue.map((item) => <div key={item.post.id} className="rounded-[22px] border p-4" style={{ borderColor: item.blocked ? "#E8B7AD" : T.border, background: item.blocked ? "#FFF8F5" : "#fff", boxShadow: "0 8px 24px rgba(91,58,43,.06)" }}>
            <div className="flex items-start justify-between gap-3"><div><div className="text-[10px] uppercase tracking-[.14em] font-extrabold" style={{ color: item.due ? T.coral : T.choco2 }}>{item.post.fecha} · {item.post.hora} · {item.post.canal}</div><div className="display font-semibold text-lg mt-1">{item.post.titulo}</div><div className="mt-1 inline-flex rounded-full px-2 py-1 text-[9px] font-extrabold" style={{ background: item.contentMode === "Pauta" ? "#FFF1D8" : "#E8F1E4", color: item.contentMode === "Pauta" ? "#7B5410" : "#3F6B42" }}>{item.contentMode === "Pauta" ? "📣 PAUTA · CONVERSIÓN" : "🌱 ORGÁNICO · COMUNIDAD"}</div></div><Badge label={item.run?.status || item.post.estado} /></div>
            <div className="mt-3 rounded-2xl p-3" style={{ background: T.soft }}>
              <div className="flex justify-between gap-2 text-xs font-bold"><span>Checklist operativo</span><span style={{ color: item.readiness.checklistComplete ? "#3F6B42" : T.coral }}>{item.readiness.checked}/{item.readiness.total}</span></div>
              <div className="h-1.5 rounded-full mt-2 overflow-hidden" style={{ background: "#E9DCCB" }}><div className="h-full rounded-full" style={{ width: `${item.readiness.total ? (item.readiness.checked / item.readiness.total) * 100 : 0}%`, background: item.readiness.checklistComplete ? "#5F8A61" : T.coral }} /></div>
            </div>
            <div className="mt-3 text-sm font-extrabold" style={{ color: item.blocked ? "#A03B2A" : T.choco }}>→ {item.action}</div>
            {item.readiness.errors[0] && <div className="text-[11px] mt-1" style={{ color: "#A03B2A" }}>{item.readiness.errors[0]}</div>}
            {item.run?.failureReason && <div className="text-xs mt-2 rounded-xl px-3 py-2" style={{ background: "#F6D4CD", color: "#8D3427" }}>Último fallo: {item.run.failureReason}</div>}
            {item.dispatch?.presentation && <div className="mt-3 rounded-2xl px-3 py-2.5" style={{ background: item.dispatch.job.status === "Incierto" ? "#FFF1ED" : item.dispatch.job.status === "Publicado" ? "#E8F1E4" : "#E9F0F7", color: item.dispatch.job.status === "Incierto" ? "#A03B2A" : item.dispatch.job.status === "Publicado" ? "#3F6B42" : "#3E5C7E" }}><div className="text-xs font-extrabold">{item.dispatch.presentation.label}</div><div className="text-[10px] mt-0.5">{item.dispatch.presentation.help} · intento {item.dispatch.job.attempt}</div></div>}
            <div className="flex flex-wrap gap-2 mt-4">
              {["Preparar salida","Completar checklist","Marcar lista"].includes(item.action) && <Btn small onClick={() => abrirPreparacion(item)} disabled={!item.readiness.readyToPrepare || !db.distributionServerReady}>Abrir checklist</Btn>}
              {item.action === "Aprobar salida" && <BtnAsync small onClick={() => aprobarSalidaComercial(item)} disabled={!db.distributionServerReady} textoEnVuelo="Aprobando…">Aprobar salida</BtnAsync>}
              {["Autorizar envío por Meta","Autorizar borrador TikTok"].includes(item.action) && <BtnAsync small onClick={() => autorizarSalidaConector(item)} textoEnVuelo="Autorizando…">{item.action}</BtnAsync>}
              {item.action === "Publicar y registrar evidencia" && <Btn small onClick={() => abrirCierre(item, "publish")} disabled={!db.distributionServerReady}>Registrar publicación manual</Btn>}
              {item.dispatch?.job?.status === "Fallido" && <BtnAsync small onClick={() => reintentarSalidaConector(item)} textoEnVuelo="Autorizando…">Reintentar conector</BtnAsync>}
              {item.dispatch?.job?.status === "Fallido" && <Btn small kind="ghost" onClick={() => abrirCierre(item, "publish")}>Registrar manualmente</Btn>}
              {item.dispatch?.job?.status === "Borrador listo" && <Btn small onClick={() => abrirCierre(item, "publish")}>Registrar publicación final</Btn>}
              {item.action === "Esperar horario" && <span className="rounded-xl px-3 py-2 text-xs font-bold" style={{ background: "#E9F0F7", color: "#3E5C7E" }}>Programada · todavía no ejecutar</span>}
              {item.action === "Revisar fallo" && <span className="rounded-xl px-3 py-2 text-xs font-bold" style={{ background: "#F6D4CD", color: "#A03B2A" }}>Volvé a Pendiente y reprogramá para reintentar</span>}
              {!item.dispatch?.job && item.run && !["Publicada","Cancelada","Fallida"].includes(item.run.status) && <Btn small kind="ghost" onClick={() => abrirCierre(item, "fail")} disabled={!db.distributionServerReady}>Registrar fallo</Btn>}
            </div>
            {!item.dispatch?.job && item.run?.status === "Aprobada" && item.dispatch?.eligibility?.provider && !item.dispatch.eligibility.allowed && <div className="text-[10px] mt-2" style={{ color: T.choco2 }}>Conector no disponible: {item.dispatch.eligibility.reasons[0]} Podés registrar la publicación manualmente.</div>}
          </div>)}
          {distributionQueue.length === 0 && <Empty icon="🚀" text="No hay publicaciones pendientes de distribución." />}
        </div>
        {distributionRoom.needsMetrics.length > 0 && <div className="rounded-2xl px-4 py-3 mt-4" style={{ background: "#FFF5E4", color: "#7B5410" }}><b>{distributionRoom.needsMetrics.length} publicación(es)</b> ya salieron y esperan captura de métricas en Resultados.</div>}
      </div> : <div className="grid md:grid-cols-2 xl:grid-cols-3 gap-3">
        {pubs.map((p) => {
          const cre = db.creatives.find((creativeItem) => creativeItem.id === p.creativeId);
          return <div key={p.id} className="rounded-2xl border p-4" style={{ borderColor: T.border, background: "#fff" }}>
            <div className="flex items-start justify-between gap-2"><div><div className="text-[10px] uppercase tracking-wider font-extrabold" style={{ color: T.choco2 }}>{p.fecha} · {p.hora} · {p.canal}</div><div className="font-bold text-sm mt-1">{p.titulo}</div></div><Badge label={p.estado} /></div>
            {cre && <div className="text-xs mt-2" style={{ color: T.choco2 }}>🎨 {cre.titulo}</div>}
            {p.copyFinal && <div className="text-xs mt-2 line-clamp-2">{p.copyFinal}</div>}
            <div className="text-[10px] font-semibold mt-3" style={{ color: p.urlPublicacion || p.externalPostId ? "#3F6B42" : "#96690F" }}>{p.urlPublicacion || p.externalPostId ? "✓ Evidencia externa registrada" : "Sin enlace externo registrado"}</div>
          </div>;
        })}
        {pubs.length === 0 && <Empty icon="🗓️" text="Todavía no hay publicaciones cerradas en el historial." />}
      </div>}

      {nueva && (
        <Modal title="Nueva publicación" onClose={() => setNueva(false)} wide>
          <div className="grid sm:grid-cols-2 gap-x-4">
            <Field label="Título"><Input value={form.titulo} onChange={(e) => setForm({ ...form, titulo: e.target.value })} placeholder="Ej: Reel gatitos lunes" /></Field>
            <Field label="Canal"><Select options={MK_CANALES} value={form.canal} onChange={(e) => setForm({ ...form, canal: e.target.value })} /></Field>
            <Field label="Fecha"><Input type="date" value={form.fecha} onChange={(e) => setForm({ ...form, fecha: e.target.value })} /></Field>
            <Field label="Hora"><Input value={form.hora} onChange={(e) => setForm({ ...form, hora: e.target.value })} placeholder="HH:MM" /></Field>
            <Field label="Campaña">
              <select value={form.campaignId} onChange={(e) => setForm({ ...form, campaignId: e.target.value, creativeId: "" })} className={inputCls} style={inputStyle}>
                <option value="">Sin campaña</option>
                {db.campaigns.map((c) => <option key={c.id} value={c.id}>{c.nombre}</option>)}
              </select>
            </Field>
            <Field label="Creativo">
              <select value={form.creativeId} onChange={(e) => {
                const id = e.target.value;
                const cr = db.creatives.find((x) => x.id === id);
                const draft = cr ? buildPostDraftFromCreative(cr, db, hoyISO()) : null;
                setForm(draft ? { ...form, ...draft } : { ...form, creativeId: "" });
              }} className={inputCls} style={inputStyle}>
                <option value="">Sin creativo</option>
                {db.creatives.filter((c) => !form.campaignId || c.campaignId === form.campaignId).map((c) => <option key={c.id} value={c.id}>{c.titulo}</option>)}
              </select>
            </Field>
            <Field label="Guardar como"><Select options={["Pendiente","Programado"]} value={form.estado} onChange={(e) => setForm({ ...form, estado: e.target.value })} /></Field>
          </div>
          {form.creativeId && <div className="rounded-2xl px-4 py-3 mb-3 text-xs font-bold" style={{ background: formScheduleGuard?.allowed ? "#E8F1E4" : "#F6D4CD", color: formScheduleGuard?.allowed ? "#3F6B42" : "#A03B2A" }}>{formScheduleGuard?.allowed ? "✓ Creativo, copy, campaña, canal y disponibilidad listos para programar." : `⛔ ${formScheduleGuard?.reasons[0] || "Falta completar el preflight."}`}</div>}
          <Field label="Copy final">
            <textarea rows={2} value={form.copyFinal} onChange={(e) => setForm({ ...form, copyFinal: e.target.value })} className="w-full rounded-xl px-3 py-2.5 text-sm border outline-none resize-y" style={{ ...inputStyle, fontFamily: "inherit" }} />
          </Field>
          <Field label="Notas"><Input value={form.notas} onChange={(e) => setForm({ ...form, notas: e.target.value })} /></Field>
          <div className="flex gap-2 mt-2"><BtnAsync onClick={guardar} textoEnVuelo="Creando…">Crear publicación</BtnAsync><Btn kind="ghost" onClick={() => setNueva(false)}>Cancelar</Btn></div>
        </Modal>
      )}

      {distributionDraft && distributionDraft.mode === "prepare" && (
        <Modal title={`Preparar salida · ${distributionDraft.item.post.id}`} onClose={() => setDistributionDraft(null)} wide>
          <div className="rounded-2xl p-4 mb-4" style={{ background: "linear-gradient(135deg,#FFF4EE,#F7E8D5)", border: `1px solid ${T.border}` }}>
            <div className="text-[10px] uppercase tracking-wider font-extrabold" style={{ color: T.coral }}>{distributionDraft.item.post.canal} · {distributionDraft.item.post.fecha} {distributionDraft.item.post.hora}</div>
            <div className="display text-xl font-semibold mt-1">{distributionDraft.item.post.titulo}</div>
            <div className="text-xs mt-1" style={{ color: T.choco2 }}>Este checklist no publica nada: deja la salida lista para una aprobación humana separada.</div>
          </div>
          <div className="space-y-2 mb-4">
            {distributionChecklistFor(distributionDraft.item.post, db).map((step) => <label key={step.key} className="flex items-start gap-3 rounded-2xl border px-4 py-3 cursor-pointer" style={{ borderColor: distributionDraft.checklist[step.key] ? "#A8C7A4" : T.border, background: distributionDraft.checklist[step.key] ? "#EFF6EC" : "#fff" }}>
              <input type="checkbox" checked={distributionDraft.checklist[step.key] === true} onChange={(event) => setDistributionDraft({ ...distributionDraft, checklist: { ...distributionDraft.checklist, [step.key]: event.target.checked } })} className="mt-0.5 w-4 h-4" />
              <span className="text-sm font-bold">{step.label}</span>
            </label>)}
          </div>
          <Field label="Notas de preparación"><Input value={distributionDraft.notes} onChange={(event) => setDistributionDraft({ ...distributionDraft, notes: event.target.value })} placeholder="Decisiones, cambios o detalles para quien aprueba" /></Field>
          <div className="flex gap-2 mt-3"><BtnAsync onClick={guardarPreparacionComercial} textoEnVuelo="Guardando…">Guardar preparación</BtnAsync><Btn kind="ghost" onClick={() => setDistributionDraft(null)}>Cancelar</Btn></div>
        </Modal>
      )}

      {distributionDraft && ["publish","fail"].includes(distributionDraft.mode) && (
        <Modal title={distributionDraft.mode === "publish" ? `Registrar publicación · ${distributionDraft.item.post.id}` : `Registrar fallo · ${distributionDraft.item.post.id}`} onClose={() => setDistributionDraft(null)} wide>
          {distributionDraft.mode === "publish" ? <>
            <div className="rounded-2xl px-4 py-3 mb-4 text-sm font-bold" style={{ background: "#E8F1E4", color: "#3F6B42" }}>✓ Salida aprobada. Confirmá la evidencia después de publicarla en {distributionDraft.item.post.canal}.</div>
            <Field label="URL pública"><Input value={distributionDraft.externalUrl} onChange={(event) => setDistributionDraft({ ...distributionDraft, externalUrl: event.target.value })} placeholder="https://instagram.com/p/..." /></Field>
            <Field label="ID externo (si la plataforma lo muestra)"><Input value={distributionDraft.externalPostId} onChange={(event) => setDistributionDraft({ ...distributionDraft, externalPostId: event.target.value })} placeholder="Ej: IG-123456" /></Field>
            <Field label="Nota de ejecución"><Input value={distributionDraft.notes} onChange={(event) => setDistributionDraft({ ...distributionDraft, notes: event.target.value })} placeholder="Publicada sin cambios / ajuste realizado" /></Field>
          </> : <>
            <div className="rounded-2xl px-4 py-3 mb-4 text-sm" style={{ background: "#FFF1ED", color: "#A03B2A" }}><b>La publicación quedará “No publicada”.</b> El motivo se conserva para corregir y reprogramar sin ocultar el fallo.</div>
            <Field label="Motivo obligatorio"><textarea rows={3} value={distributionDraft.reason} onChange={(event) => setDistributionDraft({ ...distributionDraft, reason: event.target.value })} className="w-full rounded-xl px-3 py-2.5 text-sm border outline-none resize-y" style={{ ...inputStyle, fontFamily: "inherit" }} placeholder="Ej: la plataforma rechazó el formato del archivo" /></Field>
          </>}
          <div className="flex gap-2 mt-3"><BtnAsync onClick={cerrarSalidaComercial} textoEnVuelo="Registrando…">{distributionDraft.mode === "publish" ? "Confirmar publicación" : "Guardar fallo"}</BtnAsync><Btn kind="ghost" onClick={() => setDistributionDraft(null)}>Cancelar</Btn></div>
        </Modal>
      )}
    </div>
  );
}

/* ================= RESULTADOS CREATIVOS 📊 ================= */

function ResultadosCreativos({ db, refrescar }) {
  const [nuevo, setNuevo] = useState(false);
  const vacio = { creativeId: "", fecha: hoyISO(), impresiones: 0, alcance: 0, clicks: 0, mensajesWhatsApp: 0, gasto: 0, notas: "" };
  const [form, setForm] = useState(vacio);
  const existente = db.creative_results.find((r) => r.fuente === "manual" && r.creativeId === form.creativeId && r.fecha === form.fecha);
  const resultados = resultadosDePlataforma(db);
  const numeroPreview = (valor) => {
    if (String(valor).trim() === "") return null;
    const numero = Number(valor);
    return Number.isFinite(numero) && numero >= 0 ? numero : null;
  };
  const previewImpresiones = numeroPreview(form.impresiones);
  const previewClicks = numeroPreview(form.clicks);
  const previewMensajes = numeroPreview(form.mensajesWhatsApp);
  const previewGasto = numeroPreview(form.gasto);
  const previewCtr = previewImpresiones > 0 && previewClicks !== null ? previewClicks / previewImpresiones : null;
  const previewCostoMsg = previewMensajes > 0 && previewGasto !== null ? previewGasto / previewMensajes : null;

  function cargarDia(creativeId, fecha) {
    const r = db.creative_results.find((x) => x.fuente === "manual" && x.creativeId === creativeId && x.fecha === fecha);
    setForm(r ? {
      creativeId, fecha, impresiones: r.impresiones, alcance: r.alcance, clicks: r.clicks,
      mensajesWhatsApp: r.mensajesWhatsApp, gasto: r.gasto, notas: r.notas || "",
    } : { ...vacio, creativeId, fecha });
  }

  const metric = (r) => {
    const atrib = atribucionDeResultado(db, r);
    return {
      ...atrib,
      ctr: r.impresiones > 0 ? r.clicks / r.impresiones : null,
      costoMsg: r.mensajesWhatsApp > 0 ? r.gasto / r.mensajesWhatsApp : null,
      cac: atrib.contabilizar && atrib.pedidos > 0 ? r.gasto / atrib.pedidos : null,
      roas: atrib.contabilizar && r.gasto > 0 ? atrib.ventas / r.gasto : null,
      conv: atrib.contabilizar && r.mensajesWhatsApp > 0 ? atrib.pedidos / r.mensajesWhatsApp : null,
    };
  };

  function exportar() {
    downloadCSV("resultados-creativos",
      ["Id","Creativo","Campaña","Fecha","Impresiones","Alcance","Clicks","CTR","Mensajes WA","Costo/msg","Pedidos","CAC","Ventas","Gasto","ROAS","Conv WA→pedido"],
      resultados.map((r) => { const cre = db.creatives.find((x) => x.id === r.creativeId); const camp = db.campaigns.find((x) => x.id === r.campaignId); const m = metric(r); return [r.id, cre ? cre.titulo : "", camp ? camp.nombre : "", r.fecha, r.impresiones, r.alcance, r.clicks, m.ctr ? (m.ctr * 100).toFixed(2) + "%" : "", r.mensajesWhatsApp, m.costoMsg ? Math.round(m.costoMsg) : "", m.contabilizar ? m.pedidos : "", m.cac ? Math.round(m.cac) : "", m.contabilizar ? m.ventas : "", r.gasto, m.roas ? m.roas.toFixed(2) : "", m.conv ? (m.conv * 100).toFixed(1) + "%" : ""]; }));
  }

  async function guardar() {
    if (!form.creativeId) { toast("error", "Elegí un creativo"); return; }
    const campos = ["impresiones", "alcance", "clicks", "mensajesWhatsApp", "gasto"];
    if (campos.some((k) => String(form[k]).trim() === "")) {
      toast("error", "Completá todas las métricas; un campo vacío no se guarda como cero"); return;
    }
    if (campos.some((k) => !Number.isFinite(Number(form[k])) || Number(form[k]) < 0)) {
      toast("error", "Las métricas deben ser números iguales o mayores a cero"); return;
    }
    // Impresiones/alcance/clicks/mensajes son integer en la RPC: un decimal la haría
    // rechazar ('10.5'::integer). Se ataja acá con el mismo mensaje que devuelve el server.
    if (["impresiones", "alcance", "clicks", "mensajesWhatsApp"].some((k) => !Number.isInteger(Number(form[k])))) {
      toast("error", "Impresiones, alcance, clicks y mensajes deben ser números enteros"); return;
    }
    let res;
    try {
      res = await registrarMetricasCreativo({
        creative_id: form.creativeId, fecha: form.fecha,
        impresiones: Number(form.impresiones), alcance: Number(form.alcance), clicks: Number(form.clicks),
        mensajes_wa: Number(form.mensajesWhatsApp), gasto: Number(form.gasto), notas: form.notas,
      });
    } catch (e) { toast("error", e.message); return; }
    setNuevo(false); setForm(vacio);
    toast("ok", res.actualizado ? "Métricas del día actualizadas" : "Métricas registradas");
    try { await refrescar(); } catch { toast("error", "Métricas guardadas; recargá para verlas"); }
  }

  return (
    <div>
      <div className="flex flex-wrap gap-2 mb-4">
        <Btn onClick={() => { setForm(vacio); setNuevo(true); }}>＋ Registrar métricas</Btn>
        <Btn small kind="ghost" onClick={exportar}>⬇ CSV</Btn>
      </div>

      <div className="text-xs font-bold p-2.5 rounded-xl mb-3" style={{ background: "#DCE7F2", color: "#3E5C7E" }}>
        Pedidos y ventas se calculan desde los pedidos atribuidos del servidor. Acá solo registrás métricas de la plataforma.
      </div>

      <div className="grid lg:grid-cols-2 gap-3">
        {resultados.map((r) => {
          const cre = db.creatives.find((x) => x.id === r.creativeId);
          const camp = db.campaigns.find((x) => x.id === r.campaignId);
          const m = metric(r);
          return (
            <Card key={r.id} className="p-4">
              <div className="flex justify-between items-start gap-2">
                <div className="min-w-0">
                  <div className="font-bold text-sm truncate">{cre ? cre.titulo : (r.creativeId ? "Creativo eliminado" : "Métricas de campaña")}</div>
                  <div className="text-[11px]" style={{ color: T.choco2 }}>{camp ? camp.nombre : "—"} · {r.fecha} · {r.fuente || "manual"}</div>
                </div>
                <div className="text-right shrink-0">
                  <div className="display text-lg" style={{ color: m.roas >= 1 ? "#3F6B42" : "#A03B2A" }}>{m.roas !== null ? m.roas.toFixed(1) + "x" : "—"}</div>
                  <div className="text-[10px] font-bold" style={{ color: T.choco2 }}>ROAS</div>
                </div>
              </div>
              <div className="grid grid-cols-3 gap-2 mt-3 text-center">
                {[["CTR", m.ctr !== null ? (m.ctr * 100).toFixed(1) + "%" : "—"], ["Costo/msg", m.costoMsg !== null ? fmt(m.costoMsg) : "—"], ["CAC", m.contabilizar && m.cac !== null ? fmt(m.cac) : "—"], ["Mensajes", r.mensajesWhatsApp], ["Pedidos", m.contabilizar ? m.pedidos : "—"], ["Conv WA", m.contabilizar && m.conv !== null ? (m.conv * 100).toFixed(0) + "%" : "—"]].map(([lab, v]) => (
                  <div key={lab} className="rounded-xl py-1.5" style={{ background: T.vainilla }}>
                    <div className="text-xs font-bold truncate px-0.5">{v}</div>
                    <div className="text-[10px] font-bold" style={{ color: T.choco2 }}>{lab}</div>
                  </div>
                ))}
              </div>
              <div className="flex justify-between text-[11px] font-semibold mt-2" style={{ color: T.choco2 }}>
                <span>👁️ {milCO(r.impresiones)} impres. · {milCO(r.alcance)} alcance</span>
                <span>💵 {m.contabilizar ? fmt(m.ventas) : "atribución en otra fuente"} / gasto {fmt(r.gasto)}</span>
              </div>
              {r.notas && <div className="text-xs mt-1.5" style={{ color: T.choco2 }}>📝 {r.notas}</div>}
            </Card>
          );
        })}
        {resultados.length === 0 && <Empty icon="📊" text="Sin resultados registrados." />}
      </div>

      {nuevo && (
        <Modal title={existente ? "Actualizar métricas del día" : "Registrar métricas de creativo"} onClose={() => setNuevo(false)} wide>
          <Field label="Creativo">
            <select value={form.creativeId} onChange={(e) => cargarDia(e.target.value, form.fecha)} className={inputCls} style={inputStyle}>
              <option value="">Elegir creativo…</option>
              {db.creatives.map((c) => <option key={c.id} value={c.id}>{c.titulo}</option>)}
            </select>
          </Field>
          {existente && (
            <div className="text-xs font-bold px-3 py-2 rounded-xl mb-3" style={{ background: "#DCE7F2", color: "#3E5C7E" }} role="status">
              Ya existe una captura manual para este creativo y día. Al guardar se actualiza; no se duplica.
            </div>
          )}
          <div className="grid grid-cols-2 sm:grid-cols-3 gap-x-4">
            <Field label="Fecha"><Input type="date" value={form.fecha} onChange={(e) => cargarDia(form.creativeId, e.target.value)} /></Field>
            <Field label="Impresiones"><Input type="number" step="1" min="0" value={form.impresiones} onChange={(e) => setForm({ ...form, impresiones: e.target.value })} /></Field>
            <Field label="Alcance"><Input type="number" step="1" min="0" value={form.alcance} onChange={(e) => setForm({ ...form, alcance: e.target.value })} /></Field>
            <Field label="Clicks"><Input type="number" step="1" min="0" value={form.clicks} onChange={(e) => setForm({ ...form, clicks: e.target.value })} /></Field>
            <Field label="Mensajes WhatsApp"><Input type="number" step="1" min="0" value={form.mensajesWhatsApp} onChange={(e) => setForm({ ...form, mensajesWhatsApp: e.target.value })} /></Field>
            <Field label="Gasto"><Input type="number" step="any" min="0" value={form.gasto} onChange={(e) => setForm({ ...form, gasto: e.target.value })} /></Field>
          </div>
          <div className="rounded-2xl p-3 mb-3" style={{ background: T.vainilla, border: `1px solid ${T.border}` }} aria-live="polite">
            <div className="flex items-center justify-between gap-2 mb-2">
              <span className="text-xs font-bold">Vista previa de plataforma</span>
              <span className="text-[10px] font-semibold" style={{ color: T.choco2 }}>se actualiza al escribir</span>
            </div>
            <div className="grid grid-cols-3 gap-2 text-center">
              {[
                ["CTR", previewCtr !== null ? `${(previewCtr * 100).toFixed(1)}%` : "—"],
                ["Costo/msg", previewCostoMsg !== null ? fmt(previewCostoMsg) : "—"],
                ["Gasto", previewGasto !== null ? fmt(previewGasto) : "—"],
              ].map(([label, value]) => (
                <div key={label} className="rounded-xl px-1 py-2" style={{ background: T.surface }}>
                  <div className="text-sm font-bold truncate">{value}</div>
                  <div className="text-[10px] font-bold" style={{ color: T.choco2 }}>{label}</div>
                </div>
              ))}
            </div>
          </div>
          <Field label="Notas"><Input value={form.notas} onChange={(e) => setForm({ ...form, notas: e.target.value })} /></Field>
          <div className="flex gap-2 mt-2"><BtnAsync onClick={guardar}>{existente ? "Actualizar métricas" : "Guardar métricas"}</BtnAsync><Btn kind="ghost" onClick={() => setNuevo(false)}>Cancelar</Btn></div>
        </Modal>
      )}
    </div>
  );
}


/* ================= CRECIMIENTO MOMOS 🌱 =================
   Asistente diario de marca en lenguaje simple.
   Traduce campañas, creativos y resultados a "qué hacer hoy". */

// Botón de copiar con feedback visual
function CopyBtn({ texto, label = "Copiar texto" }) {
  const [ok, setOk] = useState(false);
  return (
    <Btn small kind="rosa" onClick={() => { if (copiarTexto(texto)) { setOk(true); setTimeout(() => setOk(false), 1500); } }}>
      {ok ? "¡Copiado! ✓" : "📋 " + label}
    </Btn>
  );
}

// Traduce resultados técnicos a lenguaje simple
function resultadoSimple(m) {
  if (m.pedidos === 0) return { texto: "Todavía no ha generado pedidos. Dale unos días o prueba otro contenido.", tono: "#96690F", bg: "#FBE8C8" };
  if (m.roas !== null && m.roas >= 2) return { texto: `Funcionó muy bien: generó ${m.pedidos} pedido(s) y rindió el dinero invertido.`, tono: "#3F6B42", bg: "#DDEBD9" };
  if (m.roas !== null && m.roas >= 1) return { texto: `Funcionó bien: generó ${m.pedidos} pedido(s).`, tono: "#3F6B42", bg: "#DDEBD9" };
  return { texto: `Funcionó regular: gastó más de lo que vendió. Revisa el precio o el mensaje, o prueba otro creativo.`, tono: "#A03B2A", bg: "#F6D4CD" };
}

function AgencyBrandStudio({ db, user, refrescar }) {
  const ready = Boolean(db.brandMediaReady);
  const productionReady = Boolean(db.creativeProductionReady);
  const reviewReady = Boolean(db.creativeReviewReady);
  const iterationReady = Boolean(db.creativeIterationReady);
  const canWrite = ["Administrador", "Marketing/CRM"].includes(user);
  const library = useMemo(() => buildBrandMediaLibrary(db, hoyISO()), [db]);
  const productionQueue = useMemo(() => buildCreativeProductionQueue(db), [db]);
  const integrationCenter = useMemo(() => buildAgencyIntegrationCenter(db, new Date()), [db]);
  const canConfigureIntegrations = hasRole(user, "Administrador");
  const [section, setSection] = useState("Biblioteca");
  const [query, setQuery] = useState("");
  const [mediaFilter, setMediaFilter] = useState("");
  const [showArchived, setShowArchived] = useState(false);
  const [uploadOpen, setUploadOpen] = useState(false);
  const [file, setFile] = useState(null);
  const emptyAssetForm = {
    name: "", mediaType: "Video", source: "MOMOS", productId: "", figure: "", flavor: "",
    shotType: "Producto", orientation: "Vertical", containsPeople: false, rightsStatus: "Propio",
    rightsExpiresAt: "", aiUseAllowed: true, tags: "", notes: "",
  };
  const [assetForm, setAssetForm] = useState(emptyAssetForm);
  const [studio, setStudio] = useState({
    creativeId: "", briefId: "", operation: "Componer", provider: "Por conectar",
    targetChannel: "Instagram", targetFormat: "Reel 9:16", assetIds: [], instructions: "",
  });
  const [authorizationJob, setAuthorizationJob] = useState(null);
  const [authorizationCap, setAuthorizationCap] = useState("30000");
  const [reviewJob, setReviewJob] = useState(null);
  const [reviewDecision, setReviewDecision] = useState("Aprobada");
  const [reviewFeedback, setReviewFeedback] = useState("");
  const [integrationEdit, setIntegrationEdit] = useState(null);
  const visibleAssets = useMemo(() => searchBrandMediaAssets(library, query, {
    mediaType: mediaFilter, status: showArchived ? "" : "Activo",
  }), [library, query, mediaFilter, showArchived]);
  const studioDraft = useMemo(() => buildCreativeStudioDraft(studio, db, hoyISO()), [studio, db]);

  function chooseFile(selected) {
    setFile(selected || null);
    if (!selected) return;
    const mediaType = selected.type.startsWith("video/") ? "Video"
      : selected.type.startsWith("audio/") ? "Audio"
        : selected.type === "application/pdf" ? "Diseño" : "Foto";
    const orientation = mediaType === "Audio" ? "Audio" : mediaType === "Diseño" ? "Documento" : "Vertical";
    setAssetForm((current) => ({
      ...current, mediaType, orientation,
      name: current.name || selected.name.replace(/\.[^.]+$/, "").replace(/[-_]+/g, " ").trim(),
    }));
  }

  async function saveAsset() {
    try {
      if (!ready) throw new Error("Aplicá primero la migración 20 de Biblioteca Creativa.");
      if (!canWrite) throw new Error("Solo Administración o Marketing/CRM pueden registrar originales de marca.");
      await subirActivoMarca(file, {
        name: assetForm.name, media_type: assetForm.mediaType, source: assetForm.source,
        product_id: assetForm.productId || null, figure: assetForm.figure, flavor: assetForm.flavor,
        shot_type: assetForm.shotType, orientation: assetForm.orientation,
        contains_people: assetForm.containsPeople, rights_status: assetForm.rightsStatus,
        rights_expires_at: assetForm.rightsExpiresAt || null, ai_use_allowed: assetForm.aiUseAllowed,
        allowed_channels: [], tags: assetForm.tags.split(",").map((tag) => tag.trim()).filter(Boolean), notes: assetForm.notes,
      });
      setUploadOpen(false); setFile(null); setAssetForm(emptyAssetForm);
      toast("ok", "Original protegido y catalogado en la Biblioteca MOMOS");
      await refrescar();
    } catch (error) { toast("error", error.message); }
  }

  async function archiveAsset(asset) {
    const reason = window.prompt(`¿Por qué vas a archivar "${asset.name}"? El original no se borrará.`, "");
    if (!reason) return;
    try {
      await archivarActivoMarca(asset.id, reason);
      toast("ok", "Activo archivado; su historial y usos permanecen intactos");
      await refrescar();
    } catch (error) { toast("error", error.message); }
  }

  function toggleStudioAsset(assetId) {
    setStudio((current) => ({
      ...current,
      assetIds: current.assetIds.some((id) => String(id) === String(assetId))
        ? current.assetIds.filter((id) => String(id) !== String(assetId))
        : [...current.assetIds, assetId],
    }));
  }

  async function prepareJob() {
    try {
      if (!ready) throw new Error("Aplicá primero la migración 20 de Biblioteca Creativa.");
      const freshDraft = buildCreativeStudioDraft(studio, db, hoyISO());
      if (!freshDraft.audit.passed) throw new Error(freshDraft.audit.errors[0]);
      const prompt = [freshDraft.prompt, studio.instructions.trim()].filter(Boolean).join(" Instrucciones adicionales: ");
      await crearTrabajoCreativo({
        creative_id: studio.creativeId || null, brief_id: studio.briefId || null,
        operation: freshDraft.operation, provider: studio.provider,
        input_asset_ids: freshDraft.assets.map((asset) => asset.id),
        target_channel: freshDraft.channel, target_format: freshDraft.format,
        prompt, negative_prompt: freshDraft.negativePrompt,
        output_spec: { ...freshDraft.spec, output_mode: "new_asset", preserve_originals: true },
      });
      setStudio((current) => ({ ...current, assetIds: [], instructions: "" }));
      toast("ok", ["Higgsfield", "Kling"].includes(studio.provider)
        ? `Trabajo ${studio.provider} preparado y auditado; revisá y autorizá su tope antes de enviarlo`
        : "Trabajo creativo preparado con originales y marca congelados");
      await refrescar();
    } catch (error) { toast("error", error.message); }
  }

  async function authorizeJob() {
    try {
      const guard = creativeAuthorizationGuard(authorizationJob, { maxCostCop: authorizationCap }, db, hoyISO());
      if (!guard.allowed) throw new Error(guard.reasons[0]);
      await autorizarTrabajoCreativo(authorizationJob.id, guard.maxCostCop);
      setAuthorizationJob(null);
      toast("ok", "Trabajo autorizado con tope protegido; queda listo para el conector del motor");
      await refrescar();
    } catch (error) { toast("error", error.message); }
  }

  async function cancelJob(job) {
    const reason = window.prompt(`Motivo para cancelar el trabajo #${job.id}`, "");
    if (!reason) return;
    try {
      await cancelarTrabajoCreativo(job.id, reason);
      toast("ok", "Trabajo creativo cancelado sin borrar su trazabilidad");
      await refrescar();
    } catch (error) { toast("error", error.message); }
  }

  async function retryJob(job) {
    try {
      await reintentarTrabajoCreativo(job.id);
      toast("ok", "Trabajo devuelto a revisión antes de autorizar un nuevo intento");
      await refrescar();
    } catch (error) { toast("error", error.message); }
  }

  function openOutputReview(job) {
    setReviewJob(job);
    setReviewDecision("Aprobada");
    setReviewFeedback("");
  }

  async function saveOutputReview() {
    try {
      if (!reviewReady) throw new Error("Aplicá primero la migración 26 de Revisión Creativa.");
      if (!reviewJob?.outputAsset) throw new Error("La salida no tiene un archivo verificable.");
      if (["Cambios solicitados", "Descartada"].includes(reviewDecision) && reviewFeedback.trim().length < 5) {
        throw new Error("Explicá qué debe cambiar o por qué se descarta.");
      }
      await revisarSalidaCreativa(reviewJob.id, reviewDecision, reviewFeedback.trim());
      setReviewJob(null);
      setReviewFeedback("");
      toast("ok", reviewDecision === "Aprobada"
        ? "Archivo aprobado para uso humano; todavía no está publicado"
        : reviewDecision === "Descartada"
          ? "Salida descartada y archivada con trazabilidad"
          : "Cambios registrados; el archivo original permanece protegido");
      await refrescar();
    } catch (error) { toast("error", error.message); }
  }

  async function createCorrectedVersion(job) {
    try {
      if (!iterationReady) throw new Error("Aplicá primero la migración 27 de Versiones Creativas.");
      const result = await crearRevisionSalidaCreativa(job.id);
      toast("ok", `Versión ${result.revision_number} preparada; requiere un nuevo tope antes de generar`);
      await refrescar();
    } catch (error) { toast("error", error.message); }
  }

  async function saveIntegrationReference() {
    try {
      if (!integrationCenter.ready) throw new Error("Aplicá primero la migración 23 de Integraciones de Agencia.");
      await guardarReferenciaIntegracionAgencia({
        provider: integrationEdit.provider, environment: integrationEdit.environment,
        account_label: integrationEdit.accountLabel, external_account_id: integrationEdit.externalAccountId,
      });
      setIntegrationEdit(null);
      toast("ok", "Referencia guardada. El secreto sigue protegido en el servidor.");
      await refrescar();
    } catch (error) { toast("error", error.message); }
  }

  async function pauseIntegration(integration) {
    const reason = window.prompt(`¿Por qué vas a pausar ${integration.provider}? Los trabajos quedarán en espera.`, "Mantenimiento controlado");
    if (!reason) return;
    try {
      await pausarIntegracionAgencia(integration.provider, reason);
      toast("ok", `${integration.provider} quedó pausado sin perder su trazabilidad`);
      await refrescar();
    } catch (error) { toast("error", error.message); }
  }

  const mediaIcon = { Foto: "📷", Video: "🎬", Audio: "🎧", Logo: "✶", "Diseño": "🎨" };
  const summaryCards = [
    ["Originales", library.summary.total, "Archivo privado"],
    ["Listos para IA", library.summary.readyForAi, "Derechos vigentes"],
    ["Por revisar", library.summary.rightsPending, "Permiso o vigencia"],
    ["Productos cubiertos", library.summary.productsCovered, "Con toma real"],
  ];

  return (
    <div className="mt-7 mb-6 rounded-[28px] overflow-hidden border shadow-sm" style={{ borderColor: "#D9C2AE", background: "linear-gradient(145deg,#FFF,#FFF9F2)" }}>
      <div className="px-4 sm:px-5 py-4 border-b flex flex-col lg:flex-row lg:items-center justify-between gap-3" style={{ borderColor: T.border, background: "linear-gradient(135deg,#FFF3EA,#F9E7DE)" }}>
        <div className="flex items-center gap-3">
          <div className="w-11 h-11 rounded-2xl grid place-items-center text-xl shadow-sm" style={{ background: T.surface, color: T.coral }}>✦</div>
          <div><div className="text-[9px] font-extrabold tracking-[.18em] uppercase" style={{ color: T.coral }}>MOMOS BRAND INTELLIGENCE</div><div className="display text-xl font-semibold">Biblioteca + Estudio Creativo</div><div className="text-xs" style={{ color: T.choco2 }}>Originales, producción e integraciones externas bajo una sola trazabilidad.</div></div>
        </div>
        <div className="flex flex-wrap gap-2">
          {["Biblioteca", "Estudio", "Producción", "Integraciones"].map((item) => <button key={item} type="button" onClick={() => setSection(item)} className="rounded-full border px-3 py-2 text-[11px] font-extrabold" style={{ borderColor: section === item ? T.coral : T.border, background: section === item ? T.coral : "#fff", color: section === item ? "#fff" : T.choco }}>{item}</button>)}
          <Btn small disabled={!ready || !canWrite} onClick={() => setUploadOpen(true)}>＋ Subir original</Btn>
        </div>
      </div>

      {!ready && <div className="m-4 rounded-2xl px-4 py-3 text-sm font-bold" style={{ background: "#FFF2D8", color: "#7A5410" }}>🛡️ Vista protegida preparada. Aplicá <code>biblioteca-creativa-v1.sql</code> para habilitar archivos privados, derechos y trabajos trazables.</div>}

      {section === "Biblioteca" ? <div className="p-4 sm:p-5">
        <div className="grid grid-cols-2 lg:grid-cols-4 gap-2 mb-4">
          {summaryCards.map(([label, value, sub]) => <div key={label} className="rounded-2xl border p-3" style={{ borderColor: T.border, background: T.soft }}><div className="text-[9px] uppercase tracking-wider font-extrabold" style={{ color: T.choco2 }}>{label}</div><div className="display text-2xl font-semibold" style={{ color: T.coral }}>{value}</div><div className="text-[10px]" style={{ color: T.choco2 }}>{sub}</div></div>)}
        </div>
        <div className="flex flex-col md:flex-row gap-2 mb-4">
          <Input value={query} onChange={(event) => setQuery(event.target.value)} placeholder="Buscar por producto, sabor, figura, toma o etiqueta…" aria-label="Buscar activos de marca" />
          <select className={`${inputCls} md:max-w-[190px]`} style={inputStyle} value={mediaFilter} onChange={(event) => setMediaFilter(event.target.value)} aria-label="Filtrar tipo de activo"><option value="">Todos los formatos</option>{BRAND_MEDIA_TYPES.map((type) => <option key={type}>{type}</option>)}</select>
          <label className="shrink-0 rounded-xl border px-3 py-2.5 text-xs font-bold flex items-center gap-2" style={{ borderColor: T.border, background: "#fff" }}><input type="checkbox" checked={showArchived} onChange={(event) => setShowArchived(event.target.checked)} /> Ver archivados</label>
        </div>
        {visibleAssets.length ? <div className="grid sm:grid-cols-2 xl:grid-cols-3 gap-3">
          {visibleAssets.map((asset) => {
            const blocked = !asset.readiness.ready || asset.duplicate;
            const problem = asset.duplicate ? "Archivo duplicado" : asset.readiness.reasons[0];
            return <article key={asset.id} className="rounded-3xl overflow-hidden border shadow-sm" style={{ borderColor: blocked ? "#E6B7AE" : T.border, background: "#fff" }}>
              <div className="h-40 grid place-items-center overflow-hidden" style={{ background: "linear-gradient(135deg,#F9ECDD,#F3D7DC)" }}>
                {asset.mediaType === "Foto" || asset.mediaType === "Logo" || asset.mediaType === "Diseño" && asset.mimeType?.startsWith("image/")
                  ? <img src={asset.url} alt={asset.name} className="w-full h-full object-cover" />
                  : asset.mediaType === "Video" ? <video src={asset.url} className="w-full h-full object-cover" preload="metadata" muted controls />
                    : asset.mediaType === "Audio" ? <div className="px-4 w-full text-center"><div className="text-4xl mb-3">🎧</div><audio src={asset.url} controls className="w-full" /></div>
                      : <div className="text-4xl">{mediaIcon[asset.mediaType] || "✦"}</div>}
              </div>
              <div className="p-4">
                <div className="flex items-start justify-between gap-2"><div><div className="text-[9px] uppercase tracking-wider font-extrabold" style={{ color: T.coral }}>{asset.mediaType} · {asset.source}</div><div className="font-extrabold leading-tight">{asset.name}</div></div><Badge label={asset.status} /></div>
                <div className="text-xs mt-2" style={{ color: T.choco2 }}>{[asset.productName, asset.figure, asset.flavor, asset.shotType].filter(Boolean).join(" · ") || "Recurso general de marca"}</div>
                <div className="flex flex-wrap gap-1.5 mt-3"><span className="rounded-full px-2 py-1 text-[9px] font-extrabold" style={{ background: blocked ? "#F6D4CD" : "#DDEBD9", color: blocked ? "#A03B2A" : "#315B35" }}>{blocked ? `⚠ ${problem}` : "✓ Listo para IA"}</span><span className="rounded-full px-2 py-1 text-[9px] font-extrabold" style={{ background: T.vainilla }}>{asset.rightsStatus}</span>{asset.containsPeople && <span className="rounded-full px-2 py-1 text-[9px] font-extrabold" style={{ background: T.rosa }}>Con personas</span>}</div>
                {asset.status === "Activo" && canWrite && <button type="button" onClick={() => archiveAsset(asset)} className="mt-3 border-0 bg-transparent p-0 text-[10px] font-bold underline" style={{ color: T.choco2 }}>Archivar sin borrar</button>}
              </div>
            </article>;
          })}
        </div> : <Empty icon="🖼️" text={ready ? "No hay activos que coincidan. Subí fotos, videos, audios, logos o diseños originales de MOMOS." : "La biblioteca aparecerá aquí cuando se aplique la migración 20."} />}
      </div> : section === "Estudio" ? <div className="p-4 sm:p-5">
        <div className="grid lg:grid-cols-[minmax(0,1fr)_minmax(310px,.75fr)] gap-4">
          <div>
            <div className="rounded-3xl border p-4 mb-4" style={{ borderColor: T.border, background: T.soft }}>
              <div className="text-[10px] uppercase tracking-[.14em] font-extrabold mb-3" style={{ color: T.coral }}>01 · Encargo creativo trazable</div>
              <div className="grid sm:grid-cols-2 gap-3"><Field label="Creativo base"><select className={inputCls} style={inputStyle} value={studio.creativeId} onChange={(event) => setStudio({ ...studio, creativeId: event.target.value })}><option value="">Sin creativo</option>{(db.creatives || []).map((creative) => <option key={creative.id} value={creative.id}>{creative.titulo}</option>)}</select></Field><Field label="Brief aprobado o en curso"><select className={inputCls} style={inputStyle} value={studio.briefId} onChange={(event) => setStudio({ ...studio, briefId: event.target.value })}><option value="">Sin brief</option>{(db.agencyBriefs || []).map((brief) => <option key={brief.id} value={brief.id}>#{brief.id} · {brief.title}</option>)}</select></Field></div>
              <div className="grid sm:grid-cols-2 gap-3"><Field label="Operación"><Select options={BRAND_STUDIO_OPERATIONS} value={studio.operation} onChange={(event) => setStudio({ ...studio, operation: event.target.value })} /></Field><Field label="Motor"><Select options={CREATIVE_PROVIDERS} value={studio.provider} onChange={(event) => setStudio({ ...studio, provider: event.target.value })} /></Field></div>
              <div className="grid sm:grid-cols-2 gap-3"><Field label="Canal"><Select options={["Instagram","TikTok","Facebook","WhatsApp","Multicanal"]} value={studio.targetChannel} onChange={(event) => setStudio({ ...studio, targetChannel: event.target.value })} /></Field><Field label="Formato"><Select options={BRAND_STUDIO_FORMATS} value={studio.targetFormat} onChange={(event) => setStudio({ ...studio, targetFormat: event.target.value })} /></Field></div>
              <Field label="Instrucciones adicionales (opcional)"><textarea className={inputCls} style={inputStyle} rows="3" value={studio.instructions} onChange={(event) => setStudio({ ...studio, instructions: event.target.value })} placeholder="Ej. conservar el close-up real, agregar fondo de cocina cálido y cerrar con logo…" /></Field>
            </div>

            <div className="rounded-3xl border p-4" style={{ borderColor: T.border }}>
              <div className="flex items-end justify-between gap-3 mb-3"><div><div className="text-[10px] uppercase tracking-[.14em] font-extrabold" style={{ color: T.coral }}>02 · Fuentes reales</div><div className="display text-lg font-semibold">Elegí qué material puede usar</div></div><span className="rounded-full px-2.5 py-1 text-[10px] font-extrabold" style={{ background: T.vainilla }}>{studio.assetIds.length} elegido(s)</span></div>
              {library.readyForAi.length ? <div className="grid sm:grid-cols-2 gap-2 max-h-[420px] overflow-y-auto pr-1">{library.readyForAi.map((asset) => {
                const selected = studio.assetIds.some((id) => String(id) === String(asset.id));
                return <button key={asset.id} type="button" onClick={() => toggleStudioAsset(asset.id)} className="rounded-2xl border p-2.5 text-left flex gap-3" style={{ borderColor: selected ? T.coral : T.border, background: selected ? T.coralSoft : "#fff" }}>
                  <div className="w-14 h-14 rounded-xl overflow-hidden shrink-0 grid place-items-center" style={{ background: T.vainilla }}>{asset.url && ["Foto","Logo"].includes(asset.mediaType) ? <img src={asset.url} alt="" className="w-full h-full object-cover" /> : <span className="text-xl">{mediaIcon[asset.mediaType] || "✦"}</span>}</div>
                  <span className="min-w-0"><span className="block text-[9px] uppercase font-extrabold" style={{ color: T.coral }}>{selected ? "✓ SELECCIONADO" : asset.mediaType}</span><span className="block text-xs font-extrabold truncate">{asset.name}</span><span className="block text-[10px] truncate" style={{ color: T.choco2 }}>{asset.productName || "Recurso de marca"} {asset.flavor ? `· ${asset.flavor}` : ""}</span></span>
                </button>;
              })}</div> : <div className="rounded-2xl px-4 py-5 text-sm text-center" style={{ background: T.vainilla, color: T.choco2 }}>Primero registrá originales con derechos vigentes y permiso para IA.</div>}
            </div>
          </div>

          <div>
            <div className="rounded-3xl p-4 sticky top-24" style={{ background: "linear-gradient(145deg,#4A3028,#7C493A)", color: "#fff" }}>
              <div className="text-[9px] uppercase tracking-[.18em] font-extrabold opacity-70">03 · Control antes de generar</div>
              <div className="display text-xl font-semibold mt-1">{studioDraft.title}</div>
              <div className="text-xs opacity-75 mt-1">{studioDraft.operation} · {studioDraft.format} · salida siempre nueva</div>
              <div className="grid grid-cols-2 gap-2 my-4"><div className="rounded-2xl p-3" style={{ background: "rgba(255,255,255,.1)" }}><div className="text-[8px] uppercase font-extrabold opacity-65">Fuentes</div><div className="display text-xl">{studioDraft.assets.length}</div></div><div className="rounded-2xl p-3" style={{ background: "rgba(255,255,255,.1)" }}><div className="text-[8px] uppercase font-extrabold opacity-65">Salida</div><div className="text-sm font-extrabold">{studioDraft.spec.width}×{studioDraft.spec.height}</div></div></div>
              {studioDraft.audit.errors.length > 0 && <div className="rounded-2xl p-3 mb-3 text-xs font-bold" style={{ background: "#F6D4CD", color: "#A03B2A" }}>⛔ {studioDraft.audit.errors.join(" · ")}</div>}
              {studioDraft.audit.warnings.length > 0 && <div className="rounded-2xl p-3 mb-3 text-xs font-bold" style={{ background: "#FFF2D8", color: "#7A5410" }}>⚠ {studioDraft.audit.warnings.join(" · ")}</div>}
              {studioDraft.audit.passed && <div className="rounded-2xl p-3 mb-3 text-xs font-bold" style={{ background: "#DDEBD9", color: "#315B35" }}>✓ Derechos, producto real, marca y formato validados.</div>}
              <div className="rounded-2xl p-3 mb-3 text-[11px] leading-relaxed" style={{ background: "rgba(255,255,255,.1)" }}>{studioDraft.prompt}</div>
              {["Higgsfield", "Kling"].includes(studio.provider) && <div className="text-[10px] mb-3 opacity-80">{studio.provider} queda seleccionado como proveedor. Preparar conserva las fuentes y el brief; nada se envía hasta la autorización humana y la validación del conector privado.</div>}
              <BtnAsync onClick={prepareJob} disabled={!ready || !canWrite || !studioDraft.audit.passed} textoEnVuelo="Protegiendo trabajo…">Preparar trabajo creativo</BtnAsync>
            </div>
          </div>
        </div>

        {(db.creativeGenerationJobs || []).length > 0 && <div className="mt-5"><SectionTitle>Trabajos recientes del estudio</SectionTitle><div className="grid md:grid-cols-2 gap-2">{db.creativeGenerationJobs.slice(0, 6).map((job) => <div key={job.id} className="rounded-2xl border p-3 flex items-center gap-3" style={{ borderColor: T.border, background: "#fff" }}><div className="w-10 h-10 rounded-xl grid place-items-center" style={{ background: T.vainilla }}>✶</div><div className="flex-1 min-w-0"><div className="text-[9px] uppercase font-extrabold" style={{ color: T.coral }}>TRABAJO #{job.id} · {job.provider}</div><div className="text-sm font-extrabold truncate">{job.operation} · {job.targetFormat}</div><div className="text-[10px]" style={{ color: T.choco2 }}>{job.inputAssetIds.length} fuente(s) · {job.createdAt}</div></div><Badge label={job.status} /></div>)}</div></div>}
      </div> : section === "Producción" ? <div className="p-4 sm:p-5">
        <div className="flex flex-col lg:flex-row lg:items-end justify-between gap-3 mb-4">
          <div><div className="text-[10px] uppercase tracking-[.14em] font-extrabold" style={{ color: T.coral }}>Cola protegida del estudio</div><div className="display text-2xl font-semibold">De la idea al archivo revisable</div><div className="text-sm" style={{ color: T.choco2 }}>Cada trabajo conserva fuentes, marca, motor, tope de costo y aprobación humana. Autorizar no publica nada.</div></div>
          <Btn small kind="soft" onClick={() => setSection("Estudio")}>＋ Preparar trabajo</Btn>
        </div>
        {!productionReady && <div className="rounded-2xl px-4 py-3 mb-4 text-sm font-bold" style={{ background: "#FFF2D8", color: "#7A5410" }}>🛡️ La cola ya está diseñada, pero falta aplicar la migración 22 de Producción Creativa para autorizar costos y conectar motores sin exponer secretos.</div>}
        {!reviewReady && productionQueue.summary.completed > 0 && <div className="rounded-2xl px-4 py-3 mb-4 text-sm font-bold" style={{ background: "#FFF2D8", color: "#7A5410" }}>✦ Hay salidas privadas esperando decisión. Aplicá <code>revision-creativa-v1.sql</code> para aprobar, pedir cambios o descartar sin publicar automáticamente.</div>}
        {!iterationReady && productionQueue.summary.changesRequested > 0 && <div className="rounded-2xl px-4 py-3 mb-4 text-sm font-bold" style={{ background: "#FFF2D8", color: "#7A5410" }}>↻ Hay correcciones esperando nueva versión. Aplicá <code>versiones-creativas-v1.sql</code> para conservar el original y preparar otro intento sin heredar gasto.</div>}
        <div className="grid grid-cols-2 lg:grid-cols-6 gap-2 mb-5">
          {[["Por autorizar",productionQueue.summary.prepared],["Autorizados",productionQueue.summary.authorized],["Generando",productionQueue.summary.running],["Con novedad",productionQueue.summary.failed],["Por revisar",productionQueue.summary.pendingReview],["Aprobados",productionQueue.summary.approved]].map(([label,value]) => <div key={label} className="rounded-2xl border p-3" style={{ borderColor: T.border, background: T.soft }}><div className="text-[9px] uppercase tracking-wider font-extrabold" style={{ color: T.choco2 }}>{label}</div><div className="display text-2xl font-semibold" style={{ color: label === "Aprobados" ? "#3F6B42" : T.coral }}>{value}</div></div>)}
        </div>
        {productionQueue.active.length ? <div className="grid lg:grid-cols-2 gap-3">{productionQueue.active.map((job) => {
          const creative = (db.creatives || []).find((item) => item.id === job.creativeId);
          const execution = agencyProviderExecutionGuard(job.provider, db, new Date());
          return <article key={job.id} className="rounded-3xl border p-4" style={{ borderColor: job.status === "Fallido" ? "#E6B7AE" : T.border, background: "#fff" }}>
            <div className="flex items-start justify-between gap-3"><div><div className="text-[9px] uppercase tracking-wider font-extrabold" style={{ color: T.coral }}>TRABAJO #{job.id} · {job.provider}{job.revisionNumber > 1 ? ` · V${job.revisionNumber}` : ""}</div><div className="display text-lg font-semibold">{creative?.titulo || job.operation}</div><div className="text-xs mt-0.5" style={{ color: T.choco2 }}>{job.targetFormat} · {job.inputAssetIds.length} fuente(s){job.revisionOfJobId ? ` · corrige #${job.revisionOfJobId}` : ""}</div></div><Badge label={job.status} /></div>
            <div className="mt-3 pl-3 border-l-2 text-xs space-y-1" style={{ borderColor: T.rosa }}><div><b>Motor sugerido:</b> {job.recommendedProvider}</div><div><b>Tope protegido:</b> {job.maxCostCop ? fmt(job.maxCostCop) : "Sin autorizar"}</div>{job.outputSpec?.revision_feedback && <div><b>Cambio solicitado:</b> {job.outputSpec.revision_feedback}</div>}{job.errorMessage && <div style={{ color: "#A03B2A" }}><b>Novedad:</b> {job.errorMessage}</div>}</div>
            <div className="mt-4 flex flex-wrap gap-2">
              {job.status === "Preparado" && <BtnAsync small disabled={!productionReady || !canWrite || job.provider === "Por conectar"} onClick={() => { setAuthorizationJob(job); setAuthorizationCap(String(job.maxCostCop || 30000)); }}>Autorizar con tope</BtnAsync>}
              {job.status === "Fallido" && <BtnAsync small kind="soft" disabled={!productionReady || !canWrite} onClick={() => retryJob(job)}>Revisar y reintentar</BtnAsync>}
              {["Preparado","Autorizado","Fallido"].includes(job.status) && <BtnAsync small kind="ghost" disabled={!productionReady || !canWrite} onClick={() => cancelJob(job)}>Cancelar trabajo</BtnAsync>}
              {job.status === "Autorizado" && <span className="rounded-full px-3 py-2 text-[10px] font-extrabold" style={{ background: execution.allowed ? "#DDEBD9" : "#FFF2D8", color: execution.allowed ? "#315B35" : "#7A5410" }}>{execution.allowed ? "Conector activo · listo para ejecutar" : `En espera · ${execution.reasons[0] || "conector pendiente"}`}</span>}
              {job.status === "En generación" && <span className="rounded-full px-3 py-2 text-[10px] font-extrabold" style={{ background: T.vainilla, color: T.choco }}>Motor trabajando · intento {job.attemptCount || 1}</span>}
            </div>
          </article>;
        })}</div> : <Empty icon="✶" text="No hay trabajos creativos activos. Prepará uno desde Estudio con sus fuentes reales y formato." />}
        {productionQueue.history.length > 0 && <div className="mt-5">
          <div className="flex items-end justify-between gap-3 mb-3"><div><SectionTitle>Revisión e historial creativo</SectionTitle><div className="text-xs" style={{ color: T.choco2 }}>La aprobación habilita el uso del archivo, pero nunca lo publica ni autoriza reutilización con IA por sí sola.</div></div><span className="rounded-full px-3 py-1.5 text-[10px] font-extrabold" style={{ background: T.vainilla }}>{productionQueue.history.length} salida(s)</span></div>
          <div className="grid md:grid-cols-2 xl:grid-cols-3 gap-3">{productionQueue.history.slice(0, 12).map((job) => <article key={job.id} className="rounded-3xl border overflow-hidden shadow-sm" style={{ borderColor: job.reviewStatus === "Pendiente" ? "#E6B7AE" : T.border, background: "#fff" }}>
            {job.outputAsset?.url && <div className="h-44 overflow-hidden grid place-items-center" style={{ background: "linear-gradient(135deg,#F9ECDD,#F3D7DC)" }}>{job.outputAsset.mimeType?.startsWith("video/") ? <video src={job.outputAsset.url} controls muted preload="metadata" className="w-full h-full object-cover" /> : <img src={job.outputAsset.url} alt={job.outputAsset.name || `Salida ${job.id}`} className="w-full h-full object-cover" />}</div>}
            <div className="p-4"><div className="flex items-start justify-between gap-2"><div><div className="text-[9px] uppercase tracking-wider font-extrabold" style={{ color: T.coral }}>TRABAJO #{job.id} · {job.provider}{job.revisionNumber > 1 ? ` · V${job.revisionNumber}` : ""}</div><div className="display text-lg font-semibold">{job.operation}</div>{job.revisionOfJobId && <div className="text-[10px]" style={{ color: T.choco2 }}>Corrección del trabajo #{job.revisionOfJobId}</div>}</div><Badge label={job.reviewStatus === "No aplica" ? job.status : job.reviewStatus} /></div>
              <div className="grid grid-cols-2 gap-2 my-3"><div className="rounded-xl px-3 py-2" style={{ background: T.vainilla }}><div className="text-[8px] uppercase font-extrabold" style={{ color: T.choco2 }}>Costo real</div><div className="font-extrabold">{fmt(job.generationCost || 0)}</div></div><div className="rounded-xl px-3 py-2" style={{ background: T.vainilla }}><div className="text-[8px] uppercase font-extrabold" style={{ color: T.choco2 }}>Formato</div><div className="font-extrabold text-xs">{job.targetFormat}</div></div></div>
              {job.outputReviewFeedback && <div className="rounded-xl px-3 py-2 mb-3 text-xs" style={{ background: job.reviewStatus === "Aprobada" ? "#DDEBD9" : "#FFF2D8" }}><b>Decisión:</b> {job.outputReviewFeedback}</div>}
              <div className="flex flex-wrap gap-2">{job.outputAsset?.url && <a href={job.outputAsset.url} target="_blank" rel="noreferrer" className="rounded-xl border px-3 py-2 text-xs font-bold" style={{ borderColor: T.border, color: T.choco }}>Ver archivo</a>}{job.status === "Completado" && job.reviewStatus === "Pendiente" && <Btn small disabled={!reviewReady || !canWrite} onClick={() => openOutputReview(job)}>Revisar salida</Btn>}{job.reviewStatus === "Cambios solicitados" && !job.revisionJob && <BtnAsync small kind="soft" disabled={!iterationReady || !canWrite} onClick={() => createCorrectedVersion(job)}>Crear versión corregida</BtnAsync>}{job.revisionJob && <span className="rounded-xl px-3 py-2 text-[10px] font-extrabold" style={{ background: "#DDEBD9", color: "#315B35" }}>Versión {job.revisionJob.revisionNumber} · {job.revisionJob.status}</span>}</div>
            </div>
          </article>)}</div>
        </div>}
      </div> : <div className="p-4 sm:p-5">
        <div className="flex flex-col lg:flex-row lg:items-end justify-between gap-3 mb-4">
          <div><div className="text-[10px] uppercase tracking-[.14em] font-extrabold" style={{ color: T.coral }}>Centro de integraciones</div><div className="display text-2xl font-semibold">Qué puede ejecutar Agencia MOMOS ahora</div><div className="text-sm max-w-2xl" style={{ color: T.choco2 }}>MOMO OPS muestra la cuenta, salud y último contacto de cada motor. Los tokens nunca llegan a esta pantalla ni se guardan en tablas públicas.</div></div>
          <span className="rounded-full px-3 py-2 text-[10px] font-extrabold" style={{ background: integrationCenter.summary.needsAttention ? "#F6D4CD" : "#DDEBD9", color: integrationCenter.summary.needsAttention ? "#A03B2A" : "#315B35" }}>{integrationCenter.summary.operational} de {integrationCenter.summary.total} operativas</span>
        </div>
        {!integrationCenter.ready && <div className="rounded-2xl px-4 py-3 mb-4 text-sm font-bold" style={{ background: "#FFF2D8", color: "#7A5410" }}>🛡️ Aplicá <code>integraciones-agencia-v1.sql</code> después de la migración 22. Hasta entonces ningún proveedor externo se considera conectado.</div>}
        {integrationCenter.ready && !db.higgsfieldConnectorReady && <div className="rounded-2xl px-4 py-3 mb-4 text-sm font-bold" style={{ background: "#FFF2D8", color: "#7A5410" }}>✦ Higgsfield sigue en modo protegido. Aplicá <code>higgsfield-conector-v1.sql</code> para instalar el worker privado, el costo máximo y la conciliación de resultados.</div>}
        {integrationCenter.ready && !db.klingConnectorReady && <div className="rounded-2xl px-4 py-3 mb-4 text-sm font-bold" style={{ background: "#FFF2D8", color: "#7A5410" }}>◆ Kling está preparado pero cerrado. Aplicá <code>kling-conector-v1.sql</code> para habilitar API Key privada, costo protegido, idempotencia y conciliación.</div>}
        <div className="grid grid-cols-2 lg:grid-cols-4 gap-2 mb-5">
          {[["Operativas",integrationCenter.summary.operational,"Heartbeat ≤ 30 min"],["Requieren atención",integrationCenter.summary.needsAttention,"Error o trabajo detenido"],["Trabajo esperando",integrationCenter.summary.waiting,"Autorizado, no ejecutado"],["Piezas generadas",integrationCenter.summary.completed,`${integrationCenter.summary.failed} intentos fallidos`]].map(([label,value,sub]) => <div key={label} className="momo-metric-card rounded-2xl border p-3" style={{ borderColor: T.border, background: T.soft, "--metric-tone": label === "Requieren atención" ? "#C4808E" : T.coral }}><div className="text-[9px] uppercase tracking-wider font-extrabold" style={{ color: T.choco2 }}>{label}</div><div className="display text-2xl font-semibold" style={{ color: label === "Piezas generadas" ? "#3F6B42" : T.coral }}>{value}</div><div className="text-[10px]" style={{ color: T.choco2 }}>{sub}</div></div>)}
        </div>
        <div className="grid lg:grid-cols-2 gap-3">
          {integrationCenter.integrations.map((integration) => {
            const tone = integration.operational ? { border: "#B8D3B2", bg: "#F4FAF2", fg: "#315B35" }
              : integration.status === "Con error" || integration.needsAttention ? { border: "#E6B7AE", bg: "#FFF7F4", fg: "#A03B2A" }
                : { border: T.border, bg: "#fff", fg: "#7A5410" };
            return <article key={integration.provider} className="rounded-3xl border p-4 shadow-sm" style={{ borderColor: tone.border, background: tone.bg }}>
              <div className="flex items-start gap-3"><div className="w-11 h-11 shrink-0 rounded-2xl grid place-items-center text-xl" style={{ background: integration.operational ? "#DDEBD9" : T.vainilla, color: tone.fg }}>{integration.icon}</div><div className="flex-1 min-w-0"><div className="flex items-start justify-between gap-2"><div><div className="text-[9px] uppercase tracking-wider font-extrabold" style={{ color: T.coral }}>{integration.kind}</div><div className="display text-lg font-semibold">{integration.provider}</div></div><span className="rounded-full px-2.5 py-1 text-[9px] font-extrabold" style={{ background: integration.operational ? "#DDEBD9" : integration.status === "Con error" ? "#F6D4CD" : "#FFF2D8", color: tone.fg }}>{integration.operational ? "● OPERATIVA" : integration.status.toUpperCase()}</span></div><p className="text-xs mt-1 mb-0" style={{ color: T.choco2 }}>{integration.purpose}</p></div></div>
              <div className="grid grid-cols-2 gap-2 my-3"><div className="rounded-2xl px-3 py-2" style={{ background: "rgba(255,255,255,.7)" }}><div className="text-[8px] uppercase font-extrabold" style={{ color: T.choco2 }}>Cuenta</div><div className="text-xs font-extrabold truncate">{integration.accountLabel || "Sin referencia"}</div><div className="text-[9px]" style={{ color: T.choco2 }}>{integration.environment}</div></div><div className="rounded-2xl px-3 py-2" style={{ background: "rgba(255,255,255,.7)" }}><div className="text-[8px] uppercase font-extrabold" style={{ color: T.choco2 }}>Salud privada</div><div className="text-xs font-extrabold">{integration.heartbeatMinutes == null ? "Sin heartbeat" : `Hace ${integration.heartbeatMinutes} min`}</div><div className="text-[9px]" style={{ color: integration.secretConfigured ? "#315B35" : "#A03B2A" }}>{integration.secretConfigured ? (integration.provider === "Kling" ? "API Key confirmada" : "Autenticación confirmada") : "Autenticación pendiente"}</div></div></div>
              <div className="flex flex-wrap gap-1.5">{integration.capabilities.map((capability) => <span key={capability} className="rounded-full px-2 py-1 text-[9px] font-bold" style={{ background: T.vainilla }}>{capability}</span>)}{integration.waiting > 0 && <span className="rounded-full px-2 py-1 text-[9px] font-extrabold" style={{ background: "#F3D7DC", color: "#8E4B5A" }}>{integration.waiting} esperando</span>}</div>
              {["Higgsfield", "Kling"].includes(integration.provider) && integration.bridgeInstalled && <div className="rounded-2xl px-3 py-2 mt-3 grid grid-cols-3 gap-2" style={{ background: "rgba(255,255,255,.72)" }}><div><div className="text-[8px] uppercase font-extrabold" style={{ color: T.choco2 }}>Worker</div><div className="text-[10px] font-bold truncate">{integration.workerVersion || "Sin versión"}</div></div><div><div className="text-[8px] uppercase font-extrabold" style={{ color: T.choco2 }}>Último intento</div><div className="text-[10px] font-bold">{integration.lastRun?.state || "Sin trabajos"}</div></div><div><div className="text-[8px] uppercase font-extrabold" style={{ color: T.choco2 }}>Costo</div><div className="text-[10px] font-bold">{integration.lastRun ? fmt(integration.lastRun.actualCostCop || integration.lastRun.estimatedCostCop || 0) : "—"}</div></div></div>}
              {!integration.operational && <div className="rounded-2xl px-3 py-2 mt-3 text-[11px] font-bold" style={{ background: integration.needsAttention ? "#F6D4CD" : "#FFF2D8", color: tone.fg }}>Siguiente paso: {integration.reasons[0]}</div>}
              <div className="flex flex-wrap gap-2 mt-3"><Btn small kind="soft" disabled={!integrationCenter.ready || !canConfigureIntegrations} onClick={() => setIntegrationEdit({ provider: integration.provider, environment: integration.environment, accountLabel: integration.accountLabel, externalAccountId: integration.externalAccountId })}>{integration.accountLabel ? "Editar referencia" : "Configurar cuenta"}</Btn>{integration.status === "Activa" && <Btn small kind="ghost" disabled={!canConfigureIntegrations} onClick={() => pauseIntegration(integration)}>Pausar</Btn>}</div>
            </article>;
          })}
        </div>
        <div className="rounded-2xl px-4 py-3 mt-4 text-xs" style={{ background: "#E5EEF7", color: "#315A7D" }}><b>Activación segura:</b> Administración solo identifica aquí la cuenta. Kling usa una API Key y los demás proveedores su autenticación correspondiente, siempre en el runtime privado. MOMO OPS exige heartbeat reciente, tope de costo y revisión humana antes de publicar.</div>
      </div>}

      {integrationEdit && <Modal title={`Configurar ${integrationEdit.provider}`} onClose={() => setIntegrationEdit(null)} topLayer>
        <div className="rounded-2xl px-4 py-3 mb-4 text-sm" style={{ background: "#E5EEF7", color: "#315A7D" }}><b>Acá no se pegan tokens, API Keys ni contraseñas.</b> Solo identificamos la cuenta que MOMO OPS debe usar. La credencial se configura después en el runtime privado del worker.</div>
        <div className="grid sm:grid-cols-2 gap-3"><Field label="Proveedor"><Input value={integrationEdit.provider} disabled /></Field><Field label="Entorno"><Select options={AGENCY_INTEGRATION_ENVIRONMENTS} value={integrationEdit.environment} onChange={(event) => setIntegrationEdit({ ...integrationEdit, environment: event.target.value })} /></Field></div>
        <Field label="Nombre visible de la cuenta"><Input value={integrationEdit.accountLabel} onChange={(event) => setIntegrationEdit({ ...integrationEdit, accountLabel: event.target.value })} placeholder="Ej. Instagram D'Momos Sweet Love" /></Field>
        <Field label="ID externo de cuenta (opcional)"><Input value={integrationEdit.externalAccountId} onChange={(event) => setIntegrationEdit({ ...integrationEdit, externalAccountId: event.target.value })} placeholder="ID entregado por el proveedor" /></Field>
        <div className="rounded-2xl px-3 py-2 mb-4 text-xs" style={{ background: T.vainilla }}><b>Guardar no activa el conector.</b> El estado cambiará a Activa únicamente cuando el servidor compruebe la credencial y logre contactar al proveedor.</div>
        <div className="flex flex-wrap gap-2"><BtnAsync onClick={saveIntegrationReference} disabled={integrationEdit.accountLabel.trim().length < 2} textoEnVuelo="Protegiendo referencia…">Guardar referencia</BtnAsync><Btn kind="ghost" onClick={() => setIntegrationEdit(null)}>Cancelar</Btn></div>
      </Modal>}

      {reviewJob && <Modal title={`Revisar salida #${reviewJob.id}`} onClose={() => setReviewJob(null)} wide topLayer>
        <div className="grid lg:grid-cols-[1.2fr_.8fr] gap-4">
          <div className="rounded-3xl overflow-hidden border min-h-[280px] grid place-items-center" style={{ borderColor: T.border, background: "linear-gradient(135deg,#F9ECDD,#F3D7DC)" }}>{reviewJob.outputAsset?.mimeType?.startsWith("video/") ? <video src={reviewJob.outputAsset.url} controls autoPlay muted className="w-full max-h-[520px] object-contain" /> : reviewJob.outputAsset?.url ? <img src={reviewJob.outputAsset.url} alt="Salida a revisar" className="w-full max-h-[520px] object-contain" /> : <span>Archivo no disponible</span>}</div>
          <div><div className="text-[10px] uppercase tracking-wider font-extrabold" style={{ color: T.coral }}>Decisión humana obligatoria</div><div className="display text-2xl font-semibold mt-1">¿Esta pieza representa a MOMOS?</div><p className="text-sm mt-2" style={{ color: T.choco2 }}>Revisá producto, colores, toppings, empaque, continuidad y cualquier texto visible. Esta decisión queda sellada con usuario y fecha.</p>
            <div className="rounded-2xl p-3 my-3 text-xs" style={{ background: T.vainilla }}><b>{reviewJob.provider}</b> · {reviewJob.targetFormat}<br />Costo real {fmt(reviewJob.generationCost || 0)} · tope {fmt(reviewJob.maxCostCop || 0)}</div>
            <Field label="Decisión"><Select options={["Aprobada","Cambios solicitados","Descartada"]} value={reviewDecision} onChange={(event) => setReviewDecision(event.target.value)} /></Field>
            <Field label={reviewDecision === "Aprobada" ? "Observación de aprobación (opcional)" : "Explicación obligatoria"}><textarea className={inputCls} style={inputStyle} rows="4" value={reviewFeedback} onChange={(event) => setReviewFeedback(event.target.value)} placeholder={reviewDecision === "Cambios solicitados" ? "Ej. conservar la forma del Momo y reducir el movimiento de cámara…" : reviewDecision === "Descartada" ? "Explicá por qué esta salida no debe usarse…" : "Ej. Producto y colores verificados…"} /></Field>
            <div className="rounded-2xl px-3 py-2 mb-4 text-[11px] font-bold" style={{ background: "#E5EEF7", color: "#315A7D" }}>Aprobar permite usar el archivo en el siguiente paso comercial. No lo publica, no crea pauta y no concede reutilización automática con IA.</div>
            <div className="flex flex-wrap gap-2"><BtnAsync confirmar onClick={saveOutputReview} disabled={["Cambios solicitados","Descartada"].includes(reviewDecision) && reviewFeedback.trim().length < 5}>Guardar decisión protegida</BtnAsync><Btn kind="ghost" onClick={() => setReviewJob(null)}>Volver</Btn></div>
          </div>
        </div>
      </Modal>}

      {authorizationJob && <Modal title={`Autorizar trabajo #${authorizationJob.id}`} onClose={() => setAuthorizationJob(null)} topLayer>
        <div className="rounded-2xl px-4 py-3 mb-4 text-sm" style={{ background: T.vainilla }}><b>Confirmación humana obligatoria.</b> El motor no podrá superar este tope. La salida quedará En revisión y nunca se publicará sola.</div>
        <div className="grid sm:grid-cols-2 gap-3"><Field label="Motor"><Input value={authorizationJob.provider} disabled /></Field><Field label="Tope máximo (COP)"><Input type="number" min="0" step="1000" value={authorizationCap} onChange={(event) => setAuthorizationCap(event.target.value)} /></Field></div>
        {(() => { const guard = creativeAuthorizationGuard(authorizationJob, { maxCostCop: authorizationCap }, db, hoyISO()); return !guard.allowed && <div className="rounded-2xl px-3 py-2 mb-3 text-xs font-bold" style={{ background: "#F6D4CD", color: "#A03B2A" }}>⛔ {guard.reasons.join(" ")}</div>; })()}
        <div className="flex gap-2"><BtnAsync onClick={authorizeJob} confirmar disabled={!creativeAuthorizationGuard(authorizationJob, { maxCostCop: authorizationCap }, db, hoyISO()).allowed} textoEnVuelo="Autorizando…">Autorizar gasto protegido</BtnAsync><Btn kind="ghost" onClick={() => setAuthorizationJob(null)}>Volver</Btn></div>
      </Modal>}

      {uploadOpen && <Modal title="Nuevo original de marca" onClose={() => { setUploadOpen(false); setFile(null); }} wide topLayer>
        <div className="rounded-2xl p-3 mb-4 text-xs" style={{ background: T.vainilla }}><b>El original nunca se sobrescribe.</b> MOMO OPS guardará su huella digital, procedencia, permisos y cada uso creativo posterior.</div>
        <Field label="Archivo original (máximo 100 MB)"><input type="file" accept="image/jpeg,image/png,image/webp,image/gif,video/mp4,video/quicktime,video/webm,audio/mpeg,audio/mp4,audio/wav,application/pdf" onChange={(event) => chooseFile(event.target.files?.[0])} className="w-full rounded-2xl border p-3 text-sm" style={{ borderColor: T.border, background: "#fff" }} /></Field>
        {file && <div className="rounded-xl px-3 py-2 mb-3 text-xs font-bold" style={{ background: "#E8F1E4", color: "#315B35" }}>{file.name} · {(file.size / 1024 / 1024).toFixed(1)} MB · se verificará con SHA-256</div>}
        <div className="grid sm:grid-cols-2 gap-3"><Field label="Nombre descriptivo"><Input value={assetForm.name} onChange={(event) => setAssetForm({ ...assetForm, name: event.target.value })} placeholder="Ej. Max Oreo · close-up cuchara" /></Field><Field label="Tipo"><Select options={BRAND_MEDIA_TYPES} value={assetForm.mediaType} onChange={(event) => setAssetForm({ ...assetForm, mediaType: event.target.value })} /></Field></div>
        <div className="grid sm:grid-cols-2 gap-3"><Field label="Producto relacionado"><select className={inputCls} style={inputStyle} value={assetForm.productId} onChange={(event) => setAssetForm({ ...assetForm, productId: event.target.value })}><option value="">Recurso general de marca</option>{(db.products || []).filter((product) => product.activo !== false).map((product) => <option key={product.id} value={product.id}>{product.nombre}</option>)}</select></Field><Field label="Orientación"><Select options={["Vertical","Horizontal","Cuadrado","Audio","Documento"]} value={assetForm.orientation} onChange={(event) => setAssetForm({ ...assetForm, orientation: event.target.value })} /></Field></div>
        <div className="grid sm:grid-cols-3 gap-3"><Field label="Figura"><Input value={assetForm.figure} onChange={(event) => setAssetForm({ ...assetForm, figure: event.target.value })} placeholder="Max, Lizi…" /></Field><Field label="Sabor"><Input value={assetForm.flavor} onChange={(event) => setAssetForm({ ...assetForm, flavor: event.target.value })} placeholder="Oreo, Coco…" /></Field><Field label="Tipo de toma"><Input value={assetForm.shotType} onChange={(event) => setAssetForm({ ...assetForm, shotType: event.target.value })} placeholder="Close-up, cocina…" /></Field></div>
        <div className="grid sm:grid-cols-2 gap-3"><Field label="Derechos"><Select options={BRAND_MEDIA_RIGHTS} value={assetForm.rightsStatus} onChange={(event) => setAssetForm({ ...assetForm, rightsStatus: event.target.value })} /></Field><Field label="Vencimiento del permiso (opcional)"><Input type="date" value={assetForm.rightsExpiresAt} onChange={(event) => setAssetForm({ ...assetForm, rightsExpiresAt: event.target.value })} /></Field></div>
        <div className="rounded-2xl border px-3 py-2 mb-3" style={{ borderColor: T.border }}><label className="flex gap-2 items-start text-sm font-bold"><input type="checkbox" className="mt-1" checked={assetForm.containsPeople} onChange={(event) => setAssetForm({ ...assetForm, containsPeople: event.target.checked })} /><span>El archivo muestra personas<span className="block text-[10px] font-normal" style={{ color: T.choco2 }}>Para usarlo con IA, los derechos deben quedar en Autorizado.</span></span></label><label className="flex gap-2 items-start text-sm font-bold mt-2"><input type="checkbox" className="mt-1" checked={assetForm.aiUseAllowed} onChange={(event) => setAssetForm({ ...assetForm, aiUseAllowed: event.target.checked })} /><span>Permitir edición o generación con IA<span className="block text-[10px] font-normal" style={{ color: T.choco2 }}>El original sigue privado y no se modifica.</span></span></label></div>
        {assetForm.containsPeople && assetForm.rightsStatus !== "Autorizado" && <div className="rounded-2xl px-3 py-2 mb-3 text-xs font-bold" style={{ background: "#FFF2D8", color: "#7A5410" }}>⚠ Se puede catalogar, pero el servidor bloqueará su uso con IA hasta registrar autorización explícita.</div>}
        <Field label="Etiquetas separadas por coma"><Input value={assetForm.tags} onChange={(event) => setAssetForm({ ...assetForm, tags: event.target.value })} placeholder="oreo, close-up, cuchara, fondo rosa" /></Field>
        <Field label="Notas y alcance del permiso"><textarea className={inputCls} style={inputStyle} rows="3" value={assetForm.notes} onChange={(event) => setAssetForm({ ...assetForm, notes: event.target.value })} /></Field>
        <div className="flex flex-wrap gap-2"><BtnAsync onClick={saveAsset} disabled={!file || assetForm.name.trim().length < 3} textoEnVuelo="Protegiendo original…">Guardar original trazable</BtnAsync><Btn kind="ghost" onClick={() => { setUploadOpen(false); setFile(null); }}>Cancelar</Btn></div>
      </Modal>}
    </div>
  );
}

function AgencyCollaborationDesk({ db, refrescar }) {
  const desk = useMemo(() => buildAgencyCollaborationDesk(db), [db]);
  const [openForm, setOpenForm] = useState(false);
  const [activeRoomId, setActiveRoomId] = useState(null);
  const [sourceKey, setSourceKey] = useState("");
  const [objective, setObjective] = useState("");
  const [entryType, setEntryType] = useState("Aporte");
  const [entryBody, setEntryBody] = useState("");
  const [contractForm, setContractForm] = useState({
    concept: "", audience: "", channel: "Instagram", primaryKpi: "Beneficio incremental",
    contentMode: "Orgánico", contentGoal: "Construir deseo y conversación alrededor de MOMOS", modePrimaryMetric: "Retención",
    humanIntent: "", callToAction: "", mustInclude: "", mustAvoid: "",
  });
  const [approvalNote, setApprovalNote] = useState("");
  const [contractEditing, setContractEditing] = useState(false);
  const linkedDecisions = new Set((db.agencyCollaborationRooms || []).map((room) => String(room.decisionId || "")).filter(Boolean));
  const linkedBriefs = new Set((db.agencyCollaborationRooms || []).map((room) => String(room.briefId || "")).filter(Boolean));
  const sources = useMemo(() => [
    ...(db.agencyDecisions || []).filter((item) => item.status === "Aprobada" && !linkedDecisions.has(String(item.id))).map((item) => ({ ...item, kind: "decision", key: `decision-${item.id}`, label: `Decisión #${item.id} · ${item.title}` })),
    ...(db.agencyBriefs || []).filter((item) => ["Aprobado", "En producción"].includes(item.status) && !linkedBriefs.has(String(item.id))).map((item) => ({ ...item, kind: "brief", key: `brief-${item.id}`, label: `Brief #${item.id} · ${item.title}` })),
  ], [db.agencyDecisions, db.agencyBriefs, db.agencyCollaborationRooms]);
  const activeRoom = desk.rooms.find((room) => String(room.id) === String(activeRoomId)) || null;
  const activeEntries = activeRoom ? (db.agencyCollaborationEntries || []).filter((entry) => String(entry.roomId) === String(activeRoom.id)) : [];
  const activeContracts = activeRoom ? (db.agencyCreativeContracts || []).filter((contract) => String(contract.roomId) === String(activeRoom.id)).sort((a, b) => Number(b.version || 0) - Number(a.version || 0)) : [];
  const latestContract = activeContracts.find((contract) => contract.status !== "Sustituido") || null;

  function startRoom() {
    const first = sources[0];
    setSourceKey(first?.key || "");
    setObjective(first?.rationale || first?.insight || "Convertir esta oportunidad en una acción creativa rentable y fiel a MOMOS.");
    setOpenForm(true);
  }

  async function createRoom() {
    const source = sources.find((item) => item.key === sourceKey);
    if (!source) throw new Error("Elegí una decisión o brief aprobado.");
    const result = await abrirMesaAgencia(agencyRoomPayload(source, objective));
    setOpenForm(false);
    setActiveRoomId(result.room_id);
    toast("ok", result.duplicate ? "La mesa ya existía; abrimos su conversación." : "Mesa cooperativa abierta con contexto sellado.");
    await refrescar();
  }

  async function addHumanEntry() {
    if (!activeRoom || entryBody.trim().length < 3) throw new Error("Escribí el criterio que querés aportar.");
    await agregarAporteMesaAgencia(activeRoom.id, `human-${activeRoom.id}-${Date.now()}`, entryType, entryBody.trim(), { ui: "agency-collaboration-desk" });
    setEntryBody("");
    toast("ok", "Tu criterio quedó firmado en la mesa.");
    await refrescar();
  }

  async function prepareContract() {
    if (!activeRoom) return;
    const result = await prepararContratoCreativo(activeRoom.id, agencyContractDirection(contractForm, activeRoom), agencyContractConstraints(contractForm));
    setContractEditing(false);
    toast("ok", result.duplicate ? "Ese contrato ya estaba sellado." : "Contrato creativo preparado; falta aprobación humana.");
    await refrescar();
  }

  async function approveContract() {
    if (!latestContract) return;
    await aprobarContratoCreativo(latestContract.id, approvalNote || "Aprobación humana desde la Mesa de Agencia MOMOS");
    setApprovalNote("");
    toast("ok", "Contrato creativo aprobado. No generó, gastó ni publicó nada.");
    await refrescar();
  }

  const statusTone = (status) => status === "Aprobado" ? { bg: "#DDEBD9", fg: "#315B35" } : status === "En revisión" ? { bg: "#FFF2D8", fg: "#7A5410" } : { bg: "#E5EEF7", fg: "#315A7D" };

  return <div className="rounded-[26px] border overflow-hidden mb-6 shadow-sm" style={{ borderColor: T.border, background: T.surface }}>
    <div className="p-4 sm:p-5 flex flex-col lg:flex-row lg:items-center justify-between gap-4 border-b" style={{ borderColor: T.border, background: T.surface, color: T.choco }}>
      <div className="flex items-start gap-3"><div className="w-11 h-11 rounded-2xl grid place-items-center text-xl shrink-0" style={{ background: T.coralSoft }}>✦</div><div><div className="text-[9px] font-extrabold uppercase tracking-[.18em]" style={{ color: T.coral }}>Equipo MOMOS</div><div className="display text-xl font-semibold">Mesa de trabajo creativo</div><div className="text-xs max-w-2xl" style={{ color: T.choco2 }}>MOMOS reúne los datos y la propuesta; vos aportás el criterio de marca antes de crear una pieza.</div></div></div>
      <div className="flex items-center gap-2"><div className="grid grid-cols-2 gap-2">{[["Mesas",desk.summary.open],["Acuerdos",desk.summary.approved]].map(([label,value]) => <div key={label} className="rounded-2xl border px-3 py-2 min-w-[72px] text-center" style={{ borderColor: T.border, background: T.vainilla }}><div className="display text-lg font-semibold">{value}</div><div className="text-[8px] uppercase font-extrabold" style={{ color: T.choco2 }}>{label}</div></div>)}</div><Btn small kind="soft" disabled={!db.agencyCollaborationReady || sources.length === 0} onClick={startRoom}>＋ Abrir mesa</Btn></div>
    </div>
    {!db.agencyCollaborationReady ? <div className="px-4 py-3 text-xs font-bold" style={{ background: "#FFF2D8", color: "#7A5410" }}>Aplicá <code>mesa-agencia-v1.sql</code> después de la migración 29. Hasta entonces no se puede sellar la colaboración.</div> : <>
      <div className="grid grid-cols-2 md:grid-cols-4 gap-2 p-3 border-b" style={{ borderColor: T.border, background: "#FFF8F1" }}>
        {[["Abiertas",desk.summary.open],["Falta humano",desk.summary.waitingForHuman],["Falta agente",desk.summary.waitingForAgent],["Por aprobar",desk.summary.pendingApproval]].map(([label,value]) => <div key={label} className="rounded-2xl border px-3 py-2" style={{ borderColor: T.border, background: "#fff" }}><div className="text-[8px] uppercase font-extrabold" style={{ color: T.choco2 }}>{label}</div><div className="display text-xl font-semibold">{value}</div></div>)}
      </div>
      {desk.open.length === 0 ? <div className="p-4 text-sm" style={{ color: T.choco2 }}><b style={{ color: T.choco }}>No hay mesas abiertas.</b> Elegí una decisión o brief aprobado para reunir la data, el criterio humano y la propuesta del agente.</div> : <div className="p-3 grid lg:grid-cols-2 gap-2">
        {desk.open.slice(0, 6).map((room) => <button type="button" key={room.id} onClick={() => setActiveRoomId(room.id)} className="text-left rounded-2xl border p-3 transition hover:-translate-y-0.5" style={{ borderColor: room.readiness.readyForContract ? "#B8D3B2" : T.border, background: room.readiness.readyForContract ? "#F4FAF2" : "#FFF9F2" }}>
          <div className="flex items-start justify-between gap-2"><div><div className="text-[9px] uppercase tracking-wider font-extrabold" style={{ color: T.coral }}>Mesa #{room.id} · {room.status}</div><div className="font-extrabold text-sm">{room.title}</div></div><span className="rounded-full px-2 py-1 text-[9px] font-extrabold" style={{ background: room.readiness.readyForContract ? "#DDEBD9" : "#FFF2D8", color: room.readiness.readyForContract ? "#315B35" : "#7A5410" }}>{room.readiness.readyForContract ? "ACUERDO POSIBLE" : "EN CONVERSACIÓN"}</span></div>
          <p className="text-[11px] my-2 line-clamp-2" style={{ color: T.choco2 }}>{room.objective}</p><div className="flex gap-1.5"><span className="rounded-full px-2 py-1 text-[9px] font-bold" style={{ background: "#F3D7DC" }}>Humano {room.readiness.humanCount}</span><span className="rounded-full px-2 py-1 text-[9px] font-bold" style={{ background: "#E5EEF7" }}>Agente {room.readiness.agentCount}</span><span className="rounded-full px-2 py-1 text-[9px] font-bold" style={{ background: T.vainilla }}>Contrato {room.readiness.hasApprovedContract ? "aprobado" : "pendiente"}</span></div>
        </button>)}
      </div>}
    </>}
    <div className="px-4 py-2.5 border-t text-[10px] font-semibold" style={{ borderColor: T.border, color: T.choco2 }}>La mesa no ejecuta herramientas. El contrato aprobado será la entrada gobernada de generación, revisión humana y distribución.</div>

    {openForm && <Modal title="Abrir Mesa cooperativa" onClose={() => setOpenForm(false)} topLayer>
      <div className="rounded-2xl px-4 py-3 mb-4 text-sm" style={{ background: T.vainilla }}><b>El contexto comercial se captura ahora y queda inmutable.</b> Nuevos datos requerirán una nueva mesa o una versión posterior del contrato.</div>
      <Field label="Oportunidad aprobada"><select className={inputCls} style={inputStyle} value={sourceKey} onChange={(event) => { const next = sources.find((item) => item.key === event.target.value); setSourceKey(event.target.value); if (next) setObjective(next.rationale || next.insight || objective); }}><option value="">Elegí una fuente…</option>{sources.map((source) => <option key={source.key} value={source.key}>{source.label}</option>)}</select></Field>
      <Field label="Objetivo de la mesa"><textarea className={inputCls} style={inputStyle} rows="4" value={objective} onChange={(event) => setObjective(event.target.value)} /></Field>
      <div className="flex gap-2"><BtnAsync onClick={createRoom} disabled={!sourceKey || objective.trim().length < 5}>Abrir con contexto sellado</BtnAsync><Btn kind="ghost" onClick={() => setOpenForm(false)}>Cancelar</Btn></div>
    </Modal>}

    {activeRoom && <Modal title={`Mesa #${activeRoom.id} · ${activeRoom.title}`} onClose={() => setActiveRoomId(null)} wide topLayer>
      <div className="rounded-2xl px-4 py-3 mb-4" style={{ background: "#F5E9D8" }}><div className="text-[9px] uppercase font-extrabold" style={{ color: T.coral }}>Objetivo sellado</div><div className="text-sm font-bold">{activeRoom.objective}</div><div className="text-[9px] mt-1" style={{ color: T.choco2 }}>Huella {String(activeRoom.contextFingerprint || "").slice(0, 12)} · este contexto no se puede reemplazar.</div></div>
      <div className="grid lg:grid-cols-[1.05fr_.95fr] gap-4">
        <div><div className="text-[10px] uppercase tracking-wider font-extrabold mb-2" style={{ color: T.choco2 }}>Conversación trazable</div><div className="rounded-3xl border p-3 min-h-[220px] max-h-[420px] overflow-y-auto space-y-2" style={{ borderColor: T.border, background: "#FFFAF5" }}>
          {activeEntries.length === 0 && <div className="text-sm p-3" style={{ color: T.choco2 }}>Empezá dejando el criterio humano de marca. El agente se incorpora mediante el Orquestador/MCP seguro.</div>}
          {activeEntries.map((entry) => <div key={entry.id} className={`flex ${entry.authorKind === "Humano" ? "justify-end" : "justify-start"}`}><div className="rounded-2xl px-3 py-2 max-w-[88%]" style={{ background: entry.authorKind === "Humano" ? "#F3D7DC" : entry.authorKind === "Agente" ? "#E5EEF7" : T.vainilla }}><div className="text-[8px] uppercase font-extrabold" style={{ color: entry.authorKind === "Humano" ? "#8E4B5A" : "#315A7D" }}>{entry.authorKind} · {entry.entryType}{entry.agentName ? ` · ${entry.agentName}` : ""}</div><div className="text-xs leading-relaxed">{entry.body}</div><div className="text-[8px] mt-1 opacity-60">{entry.createdAt} · {String(entry.fingerprint || "").slice(0, 8)}</div></div></div>)}
        </div>
          {!["Cerrada","Cancelada"].includes(activeRoom.status) && <div className="rounded-2xl border p-3 mt-3" style={{ borderColor: T.border }}><div className="grid sm:grid-cols-[160px_1fr] gap-2"><Select options={AGENCY_COLLABORATION_ENTRY_TYPES} value={entryType} onChange={(event) => setEntryType(event.target.value)} /><textarea className={inputCls} style={inputStyle} rows="3" value={entryBody} onChange={(event) => setEntryBody(event.target.value)} placeholder="Tu intención, objeción o decisión de marca…" /></div><BtnAsync small onClick={addHumanEntry} disabled={entryBody.trim().length < 3}>Firmar aporte humano</BtnAsync></div>}
        </div>
        <div><div className="text-[10px] uppercase tracking-wider font-extrabold mb-2" style={{ color: T.choco2 }}>Contrato creativo</div>
          {!activeRoom.readiness.readyForContract && <div className="rounded-2xl px-3 py-2 mb-3 text-xs font-bold" style={{ background: "#FFF2D8", color: "#7A5410" }}>{activeRoom.readiness.reasons.join(" ")} El agente solo puede firmar su lado mediante el canal MCP protegido.</div>}
          {latestContract && !contractEditing ? <div className="rounded-3xl border p-4 mb-3" style={{ borderColor: statusTone(latestContract.status).fg, background: statusTone(latestContract.status).bg }}><div className="flex justify-between gap-2"><div><div className="text-[9px] uppercase font-extrabold">Versión {latestContract.version} · {latestContract.sealedPayload?.creative_direction?.content_mode || "Modo pendiente"}</div><div className="display text-lg font-semibold">{latestContract.sealedPayload?.creative_direction?.concept || "Contrato creativo MOMOS"}</div></div><span className="rounded-full bg-white/70 px-2 py-1 h-fit text-[9px] font-extrabold">{latestContract.status}</span></div><div className="text-xs mt-2"><b>Norte comercial:</b> {latestContract.sealedPayload?.primary_kpi}<br /><b>Métrica del contenido:</b> {latestContract.sealedPayload?.creative_direction?.mode_primary_metric || "Pendiente"}<br /><b>Canal:</b> {latestContract.sealedPayload?.creative_direction?.channel}<br /><b>Huella:</b> {String(latestContract.fingerprint || "").slice(0, 12)}</div>{latestContract.status === "En revisión" && <><Field label="Nota de aprobación"><Input value={approvalNote} onChange={(event) => setApprovalNote(event.target.value)} placeholder="Qué validaste como dueño de marca" /></Field><div className="flex flex-wrap gap-2"><BtnAsync confirmar onClick={approveContract}>Aprobar contrato humano + agente</BtnAsync><Btn small kind="ghost" onClick={() => setContractEditing(true)}>Preparar nueva versión</Btn></div></>}</div> : <div className="space-y-2"><Field label="Concepto acordado"><Input value={contractForm.concept} onChange={(event) => setContractForm({ ...contractForm, concept: event.target.value })} placeholder="La idea central que debe recordar el cliente" /></Field><div className="grid sm:grid-cols-2 gap-2"><Field label="Audiencia"><Input value={contractForm.audience} onChange={(event) => setContractForm({ ...contractForm, audience: event.target.value })} /></Field><Field label="Canal"><Input value={contractForm.channel} onChange={(event) => setContractForm({ ...contractForm, channel: event.target.value })} /></Field></div><div className="grid sm:grid-cols-2 gap-2"><Field label="Tipo de contenido"><Select options={AGENCY_CONTENT_MODES} value={contractForm.contentMode} onChange={(event) => { const contentMode = event.target.value; setContractForm({ ...contractForm, contentMode, modePrimaryMetric: AGENCY_MODE_METRICS[contentMode][0] }); }} /></Field><Field label="Métrica propia del contenido"><Select options={AGENCY_MODE_METRICS[contractForm.contentMode]} value={contractForm.modePrimaryMetric} onChange={(event) => setContractForm({ ...contractForm, modePrimaryMetric: event.target.value })} /></Field></div><div className="rounded-2xl px-3 py-2 text-[10px] font-semibold" style={{ background: contractForm.contentMode === "Pauta" ? "#FFF1D8" : "#E8F1E4", color: contractForm.contentMode === "Pauta" ? "#7B5410" : "#3F6B42" }}>{contractForm.contentMode === "Pauta" ? "Pauta: vender de forma medible con oferta, audiencia, stock, atribución y CTA claros." : "Orgánico: ganar atención, afinidad y conversación; la venta asistida se mide aparte y nunca se presume."}</div><Field label="Objetivo de esta pieza"><Input value={contractForm.contentGoal} onChange={(event) => setContractForm({ ...contractForm, contentGoal: event.target.value })} /></Field><Field label="Norte comercial de MOMOS"><Select options={AGENCY_CONTRACT_KPIS} value={contractForm.primaryKpi} onChange={(event) => setContractForm({ ...contractForm, primaryKpi: event.target.value })} /></Field><Field label="Intención humana de marca"><textarea className={inputCls} style={inputStyle} rows="2" value={contractForm.humanIntent} onChange={(event) => setContractForm({ ...contractForm, humanIntent: event.target.value })} /></Field><Field label="Llamado a la acción"><Input value={contractForm.callToAction} onChange={(event) => setContractForm({ ...contractForm, callToAction: event.target.value })} /></Field><div className="grid sm:grid-cols-2 gap-2"><Field label="Debe incluir"><textarea className={inputCls} style={inputStyle} rows="2" value={contractForm.mustInclude} onChange={(event) => setContractForm({ ...contractForm, mustInclude: event.target.value })} /></Field><Field label="Debe evitar"><textarea className={inputCls} style={inputStyle} rows="2" value={contractForm.mustAvoid} onChange={(event) => setContractForm({ ...contractForm, mustAvoid: event.target.value })} /></Field></div><div className="flex gap-2"><BtnAsync onClick={prepareContract} disabled={!activeRoom.readiness.readyForContract || contractForm.concept.trim().length < 3 || contractForm.audience.trim().length < 3 || contractForm.contentGoal.trim().length < 3 || contractForm.humanIntent.trim().length < 3}>Preparar contrato sellado</BtnAsync>{latestContract && <Btn kind="ghost" onClick={() => setContractEditing(false)}>Conservar versión {latestContract.version}</Btn>}</div></div>}
          <div className="rounded-2xl px-3 py-2 mt-3 text-[10px] font-semibold" style={{ background: "#E5EEF7", color: "#315A7D" }}>Aprobar este contrato no llama a Kling, no crea pauta y no publica. Solo fija la intención compartida para los siguientes motores.</div>
        </div>
      </div>
    </Modal>}
  </div>;
}

function AgencyRetentionLab({ db, refrescar }) {
  const center = useMemo(() => buildAgencyRetentionCenter(db), [db]);
  const [contractId, setContractId] = useState("");
  const [formOpen, setFormOpen] = useState(false);
  const [reviewNotes, setReviewNotes] = useState({});
  const [form, setForm] = useState({ platform: "Instagram Reels", duration: 15, title: "", audience: "", promise: "", payoff: "", callToAction: "", controlHook: "", challengerHook: "", openingVisual: "", proof: "" });

  function openScript(contract) {
    const direction = contract.sealedPayload?.creative_direction || {};
    const concept = direction.concept || "Mostrar un Momo real de forma irresistible";
    setContractId(String(contract.id));
    setForm({
      platform: "Instagram Reels", duration: 15, title: `Guion de retención · ${concept}`,
      audience: direction.audience || "Personas que disfrutan postres premium en Cali",
      promise: `Vas a descubrir por qué ${concept.toLowerCase()}.`, payoff: "La demostración real cierra exactamente la promesa del inicio.",
      callToAction: direction.call_to_action || "Pedí tu Momo", controlHook: concept,
      challengerHook: `Esperá a ver el centro de este Momo.`, openingVisual: "Producto real y reconocible en el primer fotograma.",
      proof: "La cámara muestra el producto real y su textura; no se inventan beneficios.",
    });
    setFormOpen(true);
  }

  async function saveScript() {
    const contract = (db.agencyCreativeContracts || []).find((item) => String(item.id) === String(contractId));
    if (!contract) throw new Error("El contrato creativo ya no está disponible.");
    const duration = Math.max(5, Number(form.duration || 15));
    const hookEnd = Math.min(3, Math.max(1.5, duration * 0.2));
    const proofEnd = Math.max(hookEnd + 1, duration - Math.max(1, duration * 0.2));
    const scores = { clarity: 2, relevance: 2, specificity: 2, proof: 2, novelty: 1, payoff_fit: 2, brand_fit: 2, honesty: 2 };
    const payload = retentionScriptPayload({
      title: form.title, platform: form.platform, targetDurationSec: duration, audience: form.audience,
      objective: contract.sealedPayload?.creative_direction?.primary_kpi || "Beneficio incremental",
      promise: form.promise, payoff: form.payoff, callToAction: form.callToAction,
      evidencePlan: { product_real: true, approved_contract_fingerprint: contract.fingerprint, no_unapproved_claims: true },
      hooks: [
        { variantKey: "A", label: "Control", mechanism: "Resultado primero", hookText: form.controlHook, openingVisual: form.openingVisual, proof: form.proof, scores, selected: true },
        { variantKey: "B", label: "Retador", mechanism: "Pregunta", hookText: form.challengerHook, openingVisual: form.openingVisual, proof: form.proof, scores, selected: false },
      ],
      beatMap: [
        { label: "Hook y promesa", startSec: 0, endSec: hookEnd, visual: form.openingVisual, audio: form.controlHook, purpose: "Detener el scroll mostrando relevancia." },
        { label: "Prueba y desarrollo", startSec: hookEnd, endSec: proofEnd, visual: form.proof, audio: form.promise, purpose: "Demostrar sin esconder el producto." },
        { label: "Payoff y CTA", startSec: proofEnd, endSec: duration, visual: form.payoff, audio: `${form.payoff} ${form.callToAction}`, purpose: "Cerrar el loop antes de pedir la acción." },
      ],
      loops: [{ loopKey: "L1", question: form.promise, openSec: 0, closeSec: Math.max(hookEnd + 0.5, duration - 1), payoff: form.payoff }],
    }, contract);
    const result = await prepararGuionRetencion(payload);
    setFormOpen(false); toast("ok", `Guion V${result.version || 1} sellado para revisión humana; no generó ni publicó.`); await refrescar();
  }

  async function resolveScript(script, decision) {
    const note = String(reviewNotes[script.id] || "").trim();
    if (!note) { toast("alert", decision === "Aprobar" ? "Escribí qué verificaste antes de aprobar." : "Escribí qué debe corregirse antes de devolver."); return; }
    await resolverGuionRetencion(script.id, decision, note);
    setReviewNotes((current) => ({ ...current, [script.id]: "" }));
    toast("ok", decision === "Aprobar" ? "Guion aprobado. Generación, pauta y publicación siguen separadas." : "Guion devuelto con aprendizaje trazable.");
    await refrescar();
  }

  async function createExperiment(script) {
    const hooks = center.hooks.filter((hook) => String(hook.scriptId) === String(script.id));
    const control = hooks.find((hook) => hook.selected) || hooks[0]; const challenger = hooks.find((hook) => hook.id !== control?.id);
    if (!control || !challenger) throw new Error("El guion necesita control y retador.");
    const hypothesis = window.prompt("Hipótesis A/B — cambiaremos únicamente el hook:", `“${control.hookText}” retendrá mejor a los 3 segundos que “${challenger.hookText}”.`) || "";
    if (hypothesis.trim().length < 10) return;
    await crearExperimentoRetencion({
      experiment_key: `retention-${script.id}-${Date.now()}`, script_id: script.id, control_hook_id: control.id, challenger_hook_id: challenger.id,
      declared_variable: "Hook", hypothesis, primary_metric: "Retención 3 s",
      guardrails: { same_product: true, same_offer: true, same_cta: true, same_audience: true, human_winner_required: true },
    });
    toast("ok", "Experimento A/B planificado. No publicó ni autorizó pauta."); await refrescar();
  }

  async function closeExperiment(experiment, resolution, winnerHookId = null) {
    const note = window.prompt(resolution === "Ganador" ? "Documentá muestra, atribución y criterio del ganador:" : "¿Por qué el resultado permanece inconcluso?",
      resolution === "Ganador" ? "Ambos brazos superan la muestra mínima y la atribución corresponde a esta versión exacta." : "La muestra o la diferencia no permiten declarar ganador.") || "";
    if (!note) return;
    await cerrarExperimentoRetencion(experiment.id, resolution, winnerHookId, note);
    toast("ok", resolution === "Ganador" ? "Ganador sellado por decisión humana; no se escaló automáticamente." : "Ambigüedad conservada como aprendizaje válido.");
    await refrescar();
  }

  return <div className="rounded-[26px] border overflow-hidden mb-6 shadow-sm" style={{ borderColor: "#D7C5B2", background: "#FFFDFC" }}>
    <div className="p-4 sm:p-5 flex flex-col lg:flex-row lg:items-center justify-between gap-4" style={{ background: "linear-gradient(135deg,#6C3F24,#A55A35)", color: "#fff" }}>
      <div><div className="text-[9px] font-extrabold uppercase tracking-[.18em] opacity-75">Contrato → atención → aprendizaje económico</div><div className="display text-xl font-semibold">Laboratorio de retención MOMOS</div><div className="text-xs opacity-85 max-w-2xl">Versiona hooks, cierra cada loop y mide la publicación exacta. El cerebro propone; el humano aprueba; una muestra insuficiente nunca se convierte en “ganador”.</div></div>
      <div className="grid grid-cols-4 gap-2 shrink-0">{[["Borradores",center.summary.drafts],["Por revisar",center.summary.pending],["Aprobados",center.summary.approved],["A/B activos",center.summary.activeExperiments]].map(([label,value]) => <div key={label} className="rounded-2xl px-2.5 py-2 min-w-[64px] text-center" style={{ background: "rgba(255,255,255,.12)" }}><div className="display text-lg font-semibold">{value}</div><div className="text-[7px] uppercase font-extrabold opacity-70">{label}</div></div>)}</div>
    </div>
    {!db.agencyRetentionReady ? <div className="px-4 py-3 text-xs font-bold" style={{ background: "#FFF2D8", color: "#7A5410" }}>Aplicá <code>retencion-aprendizaje-v1.sql</code>. Hasta entonces los hooks y resultados no quedarán versionados.</div> : <>
      <div className="p-4 border-b" style={{ borderColor: T.border }}>
        <div className="flex flex-wrap items-center justify-between gap-2 mb-3"><div><div className="text-[9px] uppercase font-extrabold" style={{ color: T.coral }}>Arquitectura antes de generar</div><div className="font-extrabold text-sm">Promesa, demostración, payoff y CTA</div></div></div>
        <div className="grid lg:grid-cols-2 gap-2">
          {center.eligibleContracts.map((contract) => <article key={contract.id} className="rounded-2xl border p-3 flex items-center gap-3" style={{ borderColor: "#B8D3B2", background: "#F4FAF1" }}><div className="flex-1"><div className="text-[9px] uppercase font-extrabold" style={{ color: "#315B35" }}>Contrato #{contract.id} aprobado</div><div className="font-extrabold text-sm">{contract.sealedPayload?.creative_direction?.concept || contract.contractKey}</div><div className="text-[10px]" style={{ color: T.choco2 }}>Todavía no tiene guion de retención activo.</div></div><Btn small onClick={() => openScript(contract)}>Diseñar guion</Btn></article>)}
          {center.pending.map((script) => <article key={script.id} className="rounded-2xl border p-3" style={{ borderColor: "#E8C98B", background: "#FFF7E8" }}><div className="flex items-start justify-between gap-2"><div><div className="text-[9px] uppercase font-extrabold" style={{ color: T.coral }}>V{script.version} · {script.platform} · {script.sourceKind}</div><div className="font-extrabold text-sm">{script.title}</div></div><span className="rounded-full px-2 py-1 text-[9px] font-extrabold" style={{ background: "#FBE8C8", color: "#8B5A08" }}>En revisión</span></div><div className="text-[10px] my-2" style={{ color: T.choco2 }}><b>Promesa:</b> {script.promise}<br /><b>Payoff:</b> {script.payoff}</div>{!script.architecture.ready && <div className="rounded-xl px-2 py-1.5 text-[10px] mb-2" style={{ background: "#F6D4CD", color: "#A03B2A" }}>× {script.architecture.reasons[0]}</div>}<Input aria-label={`Nota de revisión del guion V${script.version}`} value={reviewNotes[script.id] || ""} onChange={(event) => setReviewNotes((current) => ({ ...current, [script.id]: event.target.value }))} placeholder="Qué verificaste o qué debe corregirse" /><div className="flex gap-2 mt-2"><BtnAsync small confirmar disabled={!script.architecture.ready || !String(reviewNotes[script.id] || "").trim()} onClick={() => resolveScript(script, "Aprobar")}>Aprobar guion</BtnAsync><BtnAsync small kind="ghost" disabled={!String(reviewNotes[script.id] || "").trim()} onClick={() => resolveScript(script, "Devolver")}>Devolver</BtnAsync></div></article>)}
          {center.approved.map((script) => { const experiment = center.experiments.find((item) => String(item.scriptId) === String(script.id) && !["Cerrado","Inconcluso","Cancelado"].includes(item.status)); const contract = (db.agencyCreativeContracts || []).find((item) => String(item.id) === String(script.contractId)); return <article key={script.id} className="rounded-2xl border p-3" style={{ borderColor: T.border, background: "#FFF9F2" }}><div className="flex items-start justify-between gap-2"><div><div className="text-[9px] uppercase font-extrabold" style={{ color: "#315B35" }}>Aprobado · V{script.version} · {script.targetDurationSec}s</div><div className="font-extrabold text-sm">{script.title}</div></div><span className="rounded-full px-2 py-1 text-[9px] font-extrabold" style={{ background: "#DDEBD9", color: "#315B35" }}>No publicado</span></div><div className="text-[10px] my-2" style={{ color: T.choco2 }}>{script.promise} → {script.payoff}</div><div className="flex flex-wrap gap-2">{!experiment ? <BtnAsync small onClick={() => createExperiment(script)}>Planear A/B de hook</BtnAsync> : <div className="rounded-xl px-2.5 py-2 text-[10px] font-bold" style={{ background: "#E5EEF7", color: "#315A7D" }}>Experimento #{experiment.id} · {experiment.status} · variable única: {experiment.declaredVariable}</div>}{contract && !experiment && <Btn small kind="ghost" onClick={() => openScript(contract)}>Preparar nueva versión</Btn>}</div></article>; })}
        </div>
      </div>
      {center.experiments.length > 0 && <div className="p-4"><div className="text-[9px] uppercase font-extrabold mb-2" style={{ color: T.coral }}>Aprendizaje por versión exacta</div><div className="grid lg:grid-cols-2 gap-2">{center.experiments.slice(0, 8).map((experiment) => { const controlSample = center.measurements.filter((item) => String(item.experimentId) === String(experiment.id) && String(item.hookId) === String(experiment.controlHookId)).reduce((sum,item) => sum + item.sampleSize, 0); const challengerSample = center.measurements.filter((item) => String(item.experimentId) === String(experiment.id) && String(item.hookId) === String(experiment.challengerHookId)).reduce((sum,item) => sum + item.sampleSize, 0); const ready = Math.min(controlSample, challengerSample) >= 100; return <article key={experiment.id} className="rounded-2xl border p-3" style={{ borderColor: T.border, background: "#FFF9F2" }}><div className="flex items-start justify-between gap-2"><div><div className="text-[9px] uppercase font-extrabold" style={{ color: T.coral }}>A/B #{experiment.id} · {experiment.primaryMetric}</div><div className="font-extrabold text-sm">{experiment.hypothesis}</div></div><span className="rounded-full px-2 py-1 text-[9px] font-extrabold" style={{ background: ready ? "#DDEBD9" : "#FBE8C8", color: ready ? "#315B35" : "#8B5A08" }}>{experiment.status}</span></div><div className="text-[10px] my-2" style={{ color: T.choco2 }}>Muestra A {controlSample} · B {challengerSample} · mínimo 100 por brazo</div>{["Planificado","Activo"].includes(experiment.status) && <div className="flex flex-wrap gap-2"><BtnAsync small disabled={!ready} onClick={() => closeExperiment(experiment, "Ganador", experiment.controlHookId)}>Gana A</BtnAsync><BtnAsync small disabled={!ready} onClick={() => closeExperiment(experiment, "Ganador", experiment.challengerHookId)}>Gana B</BtnAsync><BtnAsync small kind="ghost" onClick={() => closeExperiment(experiment, "Inconcluso")}>Inconcluso</BtnAsync></div>}</article>; })}</div></div>}
    </>}
    <div className="px-4 py-2.5 border-t text-[10px] font-semibold" style={{ borderColor: T.border, color: T.choco2 }}>Preparar y aprobar cuesta $0: generación, pauta y publicación conservan sus gates separados. Las métricas entran por RPC/conector y no pueden reescribirse.</div>
    {formOpen && <Modal title="Arquitectura de retención" onClose={() => setFormOpen(false)} wide topLayer>
      <div className="rounded-2xl px-3 py-2 mb-3 text-xs" style={{ background: T.vainilla }}><b>Primero el guion.</b> Abrimos una pregunta, la demostramos y la cerramos antes del CTA. Se guardan control y retador; solo cambiaremos el hook.</div>
      <div className="grid sm:grid-cols-2 gap-2"><Field label="Canal"><Select options={RETENTION_PLATFORMS} value={form.platform} onChange={(event) => setForm({ ...form, platform: event.target.value })} /></Field><Field label="Duración objetivo (s)"><Input type="number" min="5" max="180" value={form.duration} onChange={(event) => setForm({ ...form, duration: event.target.value })} /></Field></div>
      <Field label="Título"><Input value={form.title} onChange={(event) => setForm({ ...form, title: event.target.value })} /></Field><Field label="Audiencia"><Input value={form.audience} onChange={(event) => setForm({ ...form, audience: event.target.value })} /></Field>
      <Field label="Promesa que abre el loop"><textarea className={inputCls} style={inputStyle} rows="2" value={form.promise} onChange={(event) => setForm({ ...form, promise: event.target.value })} /></Field><Field label="Payoff real que lo cierra"><textarea className={inputCls} style={inputStyle} rows="2" value={form.payoff} onChange={(event) => setForm({ ...form, payoff: event.target.value })} /></Field>
      <div className="grid sm:grid-cols-2 gap-2"><Field label="Hook A · control"><textarea className={inputCls} style={inputStyle} rows="2" value={form.controlHook} onChange={(event) => setForm({ ...form, controlHook: event.target.value })} /></Field><Field label="Hook B · retador"><textarea className={inputCls} style={inputStyle} rows="2" value={form.challengerHook} onChange={(event) => setForm({ ...form, challengerHook: event.target.value })} /></Field></div>
      <Field label="Primer fotograma"><Input value={form.openingVisual} onChange={(event) => setForm({ ...form, openingVisual: event.target.value })} /></Field><Field label="Prueba visible"><Input value={form.proof} onChange={(event) => setForm({ ...form, proof: event.target.value })} /></Field><Field label="CTA"><Input value={form.callToAction} onChange={(event) => setForm({ ...form, callToAction: event.target.value })} /></Field>
      <div className="flex gap-2"><BtnAsync confirmar onClick={saveScript} disabled={[form.title,form.audience,form.promise,form.payoff,form.callToAction,form.controlHook,form.challengerHook,form.openingVisual,form.proof].some((value) => !String(value).trim())}>Sellar para revisión</BtnAsync><Btn kind="ghost" onClick={() => setFormOpen(false)}>Cancelar</Btn></div>
    </Modal>}
  </div>;
}

function AgencyLoopLearningDesk({ db, refrescar }) {
  const center = useMemo(() => buildAgencyLoopLearningCenter(db), [db]);

  async function prepare(candidate) {
    await prepararDiagnosticoRetencion(loopDiagnosticPayload(candidate));
    toast("ok", "Diagnóstico sellado para revisión humana. No generó, pautó ni publicó.");
    await refrescar();
  }

  async function resolve(diagnostic, decision) {
    const note = window.prompt(
      decision === "Aprobar" ? "¿Qué evidencia y alcance verificaste antes de convertirlo en aprendizaje?" : "¿Qué debe revisar el cerebro de Agencia?",
      decision === "Aprobar"
        ? "Validé la curva exacta, el beat señalado y que la hipótesis aplica solo a esta plataforma, audiencia y duración."
        : "Reformular la hipótesis sin presentar asociación temporal como causalidad.",
    ) || "";
    if (!note.trim()) return;
    await resolverDiagnosticoRetencion(diagnostic.id, decision, note);
    toast("ok", decision === "Aprobar" ? "Aprendizaje aprobado con alcance exacto; no se escaló automáticamente." : "Diagnóstico devuelto con una corrección trazable.");
    await refrescar();
  }

  const tone = (drop) => Number(drop) >= 15 ? { bg: "#F8DDD7", fg: "#A03B2A" }
    : Number(drop) >= 5 ? { bg: "#FFF0CE", fg: "#8B5A08" } : { bg: "#E3EFE0", fg: "#315B35" };

  return <section className="rounded-[26px] border overflow-hidden mb-6 shadow-sm" style={{ borderColor: "#D7C5B2", background: "#FFFDFC" }}>
    <div className="p-4 sm:p-5 border-b flex flex-col lg:flex-row lg:items-center justify-between gap-3" style={{ borderColor: T.border, background: "#FFF9F2" }}>
      <div className="flex items-start gap-3"><div className="w-10 h-10 rounded-2xl grid place-items-center text-lg shrink-0" style={{ background: "#F3D7DC" }}>↗</div><div>
        <div className="text-[9px] font-extrabold uppercase tracking-[.18em]" style={{ color: T.coral }}>Curva → beat → hipótesis → aprendizaje</div>
        <div className="display text-xl font-semibold">Sala de aprendizaje de loops</div>
        <div className="text-xs max-w-2xl" style={{ color: T.choco2 }}>Localiza dónde cae la atención, conserva cada loop y propone una sola variable. Una asociación temporal nunca se presenta como causa.</div>
      </div></div>
      <div className="grid grid-cols-3 gap-2 shrink-0">{[["Listos",center.summary.ready],["Por revisar",center.summary.pending],["Aprendizajes",center.summary.learnings]].map(([label,value]) => <div key={label} className="rounded-2xl border px-3 py-2 min-w-[74px] text-center" style={{ borderColor: T.border, background: "#fff" }}><div className="display text-lg font-semibold">{value}</div><div className="text-[8px] uppercase font-extrabold" style={{ color: T.choco2 }}>{label}</div></div>)}</div>
    </div>
    {!db.agencyLoopLearningReady ? <div className="px-4 py-3 text-xs font-bold" style={{ background: "#FFF2D8", color: "#7A5410" }}>Aplicá <code>experiencia-loops-retencion-v1.sql</code> después del Hito 34. Los resultados existentes permanecen intactos.</div> : <div className="p-4 space-y-5">
      <div>
        <div className="flex items-center justify-between gap-2 mb-2"><div><div className="text-[9px] uppercase font-extrabold" style={{ color: T.coral }}>Evidencia nueva</div><div className="font-extrabold text-sm">Mediciones exactas por diagnosticar</div></div><span className="rounded-full px-2 py-1 text-[9px] font-extrabold" style={{ background: "#E5EEF7", color: "#315A7D" }}>Mínimo 100 observaciones</span></div>
        {center.candidates.length === 0 ? <div className="rounded-2xl border px-3 py-3 text-xs" style={{ borderColor: T.border, color: T.choco2 }}>No hay mediciones nuevas. Cuando una variante tenga curva completa, MOMO OPS la ubicará sobre el guion exacto.</div> : <div className="grid xl:grid-cols-2 gap-3">{center.candidates.slice(0, 6).map((candidate) => <article key={candidate.measurementId} className="rounded-2xl border p-3" style={{ borderColor: candidate.ready ? "#D7C5B2" : "#E8C98B", background: "#fff" }}>
          <div className="flex items-start justify-between gap-2"><div><div className="text-[9px] uppercase font-extrabold" style={{ color: T.coral }}>Medición #{candidate.measurementId} · muestra {candidate.sampleSize}</div><div className="font-extrabold text-sm">{candidate.testedVariable} · cobertura {candidate.confidence}</div></div><span className="rounded-full px-2 py-1 text-[8px] font-extrabold shrink-0" style={{ background: "#F3D7DC", color: "#8E4B5A" }}>NO CAUSAL</span></div>
          {candidate.ready ? <><div className="text-[10px] my-2 leading-relaxed" style={{ color: T.choco2 }}>{candidate.primarySignal}</div><div className="grid gap-1.5">{candidate.beats.map((beat) => { const beatTone = tone(beat.dropPp); return <div key={`${candidate.measurementId}-${beat.beat}`} className="grid grid-cols-[1fr_auto_auto] gap-2 items-center rounded-xl px-2.5 py-2" style={{ background: "#FFF9F2" }}><div><div className="text-[10px] font-extrabold">{beat.label}</div><div className="text-[8px]" style={{ color: T.choco2 }}>{beat.startSec}s → {beat.endSec}s</div></div><div className="text-[9px] font-bold">{Math.round(beat.startPct * 100)}% → {Math.round(beat.endPct * 100)}%</div><span className="rounded-full px-2 py-1 text-[8px] font-extrabold" style={{ background: beatTone.bg, color: beatTone.fg }}>{beat.dropPp} pp</span></div>; })}</div><div className="mt-3 flex items-center justify-between gap-3"><div className="text-[9px]" style={{ color: T.choco2 }}>Una sola variable · mismo producto, oferta, audiencia y duración</div><BtnAsync small onClick={() => prepare(candidate)}>Preparar diagnóstico</BtnAsync></div></> : <div className="rounded-xl px-2.5 py-2 text-[10px] mt-2" style={{ background: "#FFF2D8", color: "#7A5410" }}>{candidate.reasons[0]}</div>}
        </article>)}</div>}
      </div>

      {center.pending.length > 0 && <div><div className="text-[9px] uppercase font-extrabold mb-2" style={{ color: T.coral }}>Decisión cooperativa · revisión humana</div><div className="grid xl:grid-cols-2 gap-3">{center.pending.map((diagnostic) => <article key={diagnostic.id} className="rounded-2xl border p-3" style={{ borderColor: "#E8C98B", background: "#FFF9F2" }}><div className="flex items-start justify-between gap-2"><div><div className="text-[9px] uppercase font-extrabold" style={{ color: "#8B5A08" }}>Diagnóstico #{diagnostic.id} · {diagnostic.sourceKind}</div><div className="font-extrabold text-sm">Probar: {diagnostic.testedVariable}</div></div><span className="rounded-full px-2 py-1 text-[8px] font-extrabold" style={{ background: "#FBE8C8", color: "#8B5A08" }}>En revisión</span></div><div className="text-[10px] mt-2" style={{ color: T.choco2 }}>{diagnostic.primarySignal}</div><div className="rounded-xl px-2.5 py-2 my-2 text-[10px]" style={{ background: "#fff" }}><b>Hipótesis:</b> {diagnostic.hypothesis}<br /><b>Siguiente prueba:</b> {diagnostic.recommendation}</div><div className="flex gap-2"><BtnAsync small confirmar onClick={() => resolve(diagnostic,"Aprobar")}>Aprobar aprendizaje</BtnAsync><BtnAsync small kind="ghost" onClick={() => resolve(diagnostic,"Devolver")}>Devolver</BtnAsync></div></article>)}</div></div>}

      {center.learnings.length > 0 && <div><div className="text-[9px] uppercase font-extrabold mb-2" style={{ color: "#315B35" }}>Memoria aprobada de MOMOS</div><div className="grid xl:grid-cols-2 gap-3">{center.learnings.slice(0, 8).map((learning) => <article key={learning.id} className="rounded-2xl border p-3" style={{ borderColor: "#B8D3B2", background: "#F5FAF3" }}><div className="text-[9px] uppercase font-extrabold" style={{ color: "#315B35" }}>{learning.platform} · {learning.targetDurationSec}s · {learning.testedVariable}</div><div className="text-xs font-semibold mt-1">{learning.statement}</div><div className="text-[9px] mt-2" style={{ color: T.choco2 }}>Alcance exacto: {learning.audience} · aprobado {learning.approvedAt}</div></article>)}</div></div>}
    </div>}
    <div className="px-4 py-2.5 border-t text-[10px] font-semibold" style={{ borderColor: T.border, color: T.choco2 }}>Este aprendizaje alimentará futuros guiones; nunca cambia campañas, genera contenido o publica por sí solo.</div>
  </section>;
}

function AgencySceneStudio({ db, refrescar }) {
  const studio = useMemo(() => buildAgencySceneStudio(db), [db]);
  const [createOpen, setCreateOpen] = useState(false);
  const [selectedId, setSelectedId] = useState(null);
  const [contractId, setContractId] = useState("");
  const [boardForm, setBoardForm] = useState({
    title: "", channel: "Instagram", format: "Reel", aspectRatio: "9:16", targetDurationSec: 15,
    hook: "", payoff: "", callToAction: "Pedí el tuyo", visualThesis: "", estimatedCostCop: 0,
  });
  const emptyShot = (number = 1) => ({
    shotNumber: number, title: "", purpose: "", durationSec: 3, subject: "", action: "", physics: "",
    environment: "", camera: "", lighting: "", audio: "", onScreenText: "", continuityIn: "",
    continuityOut: "", avoid: "", assetIds: [], estimatedCostCop: 0,
  });
  const [shotForm, setShotForm] = useState(emptyShot());
  const [shotEditing, setShotEditing] = useState(false);
  const [storyboardReviewNote, setStoryboardReviewNote] = useState("");
  const selected = studio.storyboards.find((item) => String(item.id) === String(selectedId)) || null;
  const authorizedAssets = (db.brandMediaAssets || []).filter((asset) => asset.status === "Activo"
    && asset.rightsStatus === "Autorizado" && asset.aiUseAllowed);

  function startStoryboard() {
    const contract = studio.eligibleContracts[0];
    setContractId(contract ? String(contract.id) : "");
    setBoardForm({
      title: contract?.sealedPayload?.creative_direction?.concept || "", channel: "Instagram", format: "Reel",
      aspectRatio: "9:16", targetDurationSec: 15, hook: "", payoff: "",
      callToAction: contract?.sealedPayload?.creative_direction?.call_to_action || "Pedí el tuyo",
      visualThesis: "Producto real, iluminación cálida y lenguaje visual MOMOS.", estimatedCostCop: 0,
    });
    setCreateOpen(true);
  }

  async function createStoryboard() {
    const contract = studio.eligibleContracts.find((item) => String(item.id) === String(contractId));
    if (!contract) throw new Error("Elegí un contrato creativo aprobado.");
    const result = await crearStoryboardAgencia(storyboardPayload(boardForm, contract));
    setCreateOpen(false); setSelectedId(result.storyboard_id);
    toast("ok", result.duplicate ? "Ese storyboard ya estaba sellado." : "Storyboard abierto. Todavía no generó ni gastó nada.");
    await refrescar();
  }

  function newShot() {
    const next = (selected?.readiness?.activeShots?.length || 0) + 1;
    setShotForm(emptyShot(next)); setShotEditing(true);
  }

  function editShot(shot) {
    const payload = shot.payload || {};
    setShotForm({
      shotNumber: shot.shotNumber, title: shot.title, purpose: shot.purpose, durationSec: shot.durationSec,
      subject: payload.subject || "", action: payload.action || "", physics: payload.physics || "",
      environment: payload.environment || "", camera: payload.camera || "", lighting: payload.lighting || "",
      audio: payload.audio || "", onScreenText: payload.on_screen_text || "", continuityIn: payload.continuity_in || "",
      continuityOut: payload.continuity_out || "", avoid: payload.avoid || "", assetIds: shot.assetIds || [],
      estimatedCostCop: shot.estimatedCostCop || 0,
    });
    setShotEditing(true);
  }

  async function saveShot() {
    if (!selected) return;
    const result = await guardarTomaStoryboard(shotPayload(shotForm, selected));
    setShotEditing(false);
    toast("ok", result.duplicate ? "La toma ya estaba guardada." : `Toma ${shotForm.shotNumber} versionada y sellada.`);
    await refrescar();
  }

  async function submitStoryboard() {
    if (!selected) return;
    await enviarStoryboardRevision(selected.id);
    toast("ok", "Storyboard enviado a revisión humana. No inició generación.");
    await refrescar();
  }

  async function resolveStoryboard(decision) {
    if (!selected) return;
    const note = storyboardReviewNote.trim();
    if (!note) { toast("alert", decision === "Aprobar" ? "Escribí qué verificaste antes de aprobar la dirección." : "Escribí qué toma o continuidad debe corregirse."); return; }
    await resolverStoryboardAgencia(selected.id, decision, note);
    setStoryboardReviewNote("");
    toast("ok", decision === "Aprobar" ? "Storyboard aprobado. Aún no llamó a ningún proveedor." : "Storyboard devuelto a edición con trazabilidad.");
    await refrescar();
  }

  const statusTone = (status) => status === "Aprobado" ? { bg: "#DDEBD9", fg: "#315B35" }
    : status === "En revisión" ? { bg: "#E5EEF7", fg: "#315A7D" } : { bg: "#FFF2D8", fg: "#7A5410" };
  const money = (value) => fmt(Math.round(Number(value || 0)));

  return <div className="rounded-[26px] border overflow-hidden mb-6 shadow-sm" style={{ borderColor: "#D7C5B2", background: "#FFFDFC" }}>
    <div className="p-4 sm:p-5 flex flex-col lg:flex-row lg:items-center justify-between gap-4" style={{ background: "linear-gradient(135deg,#315A57,#47766C)", color: "#fff" }}>
      <div className="flex items-start gap-3"><div className="w-11 h-11 rounded-2xl grid place-items-center text-xl shrink-0" style={{ background: "rgba(255,255,255,.15)" }}>🎬</div><div><div className="text-[9px] font-extrabold uppercase tracking-[.18em] opacity-75">Contrato aprobado → dirección por tomas</div><div className="display text-xl font-semibold">Estudio creativo MOMOS</div><div className="text-xs opacity-85 max-w-2xl">Guion visual, retención, física, continuidad, activos y costo quedan revisables antes de llamar a Kling, Higgsfield o cualquier motor.</div></div></div>
      <div className="flex items-center gap-2"><div className="grid grid-cols-3 gap-2">{[["Borrador",studio.summary.drafting],["Revisión",studio.summary.reviewing],["Tomas",studio.summary.shots]].map(([label,value]) => <div key={label} className="rounded-2xl px-3 py-2 min-w-[68px] text-center" style={{ background: "rgba(255,255,255,.13)" }}><div className="display text-lg font-semibold">{value}</div><div className="text-[8px] uppercase font-extrabold opacity-70">{label}</div></div>)}</div><Btn small kind="soft" onClick={startStoryboard} disabled={!db.agencySceneStudioReady || studio.eligibleContracts.length === 0}>＋ Nuevo storyboard</Btn></div>
    </div>
    {!db.agencySceneStudioReady ? <div className="px-4 py-3 text-xs font-bold" style={{ background: "#FFF2D8", color: "#7A5410" }}>Aplicá <code>estudio-escenas-v1.sql</code> después de la Mesa de Agencia. El Estudio permanecerá apagado hasta que el servidor confirme el contrato.</div>
      : studio.storyboards.length === 0 ? <div className="p-4 text-sm" style={{ color: T.choco2 }}><b style={{ color: T.choco }}>Todavía no hay storyboards.</b> Aprobá primero un contrato en la Mesa cooperativa; luego convertí ese acuerdo en tomas verificables.</div>
        : <div className="p-3 grid lg:grid-cols-2 gap-2">{studio.storyboards.slice(0, 8).map((board) => { const tone = statusTone(board.status); return <button type="button" key={board.id} onClick={() => setSelectedId(board.id)} className="text-left rounded-2xl border p-3 transition hover:-translate-y-0.5" style={{ borderColor: board.readiness.ready ? "#B8D3B2" : T.border, background: "#FFF9F2" }}>
          <div className="flex items-start justify-between gap-2"><div><div className="text-[9px] uppercase font-extrabold tracking-wider" style={{ color: T.coral }}>Storyboard #{board.id} · V{board.version}</div><div className="font-extrabold text-sm">{board.title}</div></div><span className="rounded-full px-2 py-1 text-[9px] font-extrabold" style={{ background: tone.bg, color: tone.fg }}>{board.status}</span></div>
          <div className="flex flex-wrap gap-1.5 my-2"><span className="rounded-full px-2 py-1 text-[9px] font-bold" style={{ background: "#E5EEF7" }}>{board.channel} · {board.format}</span><span className="rounded-full px-2 py-1 text-[9px] font-bold" style={{ background: T.vainilla }}>{board.aspectRatio} · {board.targetDurationSec}s</span><span className="rounded-full px-2 py-1 text-[9px] font-bold" style={{ background: "#F3D7DC" }}>{board.readiness.activeShots.length} toma(s)</span></div>
          <div className="text-[10px]" style={{ color: T.choco2 }}>{board.readiness.ready ? `Listo para revisión · ${money(board.readiness.estimatedCostCop)} estimados` : board.readiness.reasons[0]}</div>
        </button>; })}</div>}
    <div className="px-4 py-2.5 border-t text-[10px] font-semibold" style={{ borderColor: T.border, color: T.choco2 }}>Separación de responsabilidades: el Estudio diseña y aprueba; el siguiente hito autorizará qué motor puede ejecutar cada toma y con qué tope.</div>

    {createOpen && <Modal title="Abrir storyboard desde contrato aprobado" onClose={() => setCreateOpen(false)} wide topLayer>
      <div className="rounded-2xl px-4 py-3 mb-4 text-sm" style={{ background: T.vainilla }}><b>Primero fijamos la película en papel.</b> Hook, payoff y CTA se sellan aquí; ninguna llamada externa ocurre al guardar.</div>
      <Field label="Contrato creativo"><select className={inputCls} style={inputStyle} value={contractId} onChange={(event) => setContractId(event.target.value)}><option value="">Elegí un contrato…</option>{studio.eligibleContracts.map((contract) => <option key={contract.id} value={contract.id}>Contrato #{contract.id} · {contract.sealedPayload?.creative_direction?.concept || `Versión ${contract.version}`}</option>)}</select></Field>
      <Field label="Nombre de la pieza"><Input value={boardForm.title} onChange={(event) => setBoardForm({ ...boardForm, title: event.target.value })} /></Field>
      <div className="grid sm:grid-cols-4 gap-2"><Field label="Canal"><Select options={STORYBOARD_CHANNELS} value={boardForm.channel} onChange={(event) => setBoardForm({ ...boardForm, channel: event.target.value })} /></Field><Field label="Formato"><Select options={STORYBOARD_FORMATS} value={boardForm.format} onChange={(event) => setBoardForm({ ...boardForm, format: event.target.value })} /></Field><Field label="Proporción"><Select options={STORYBOARD_ASPECT_RATIOS} value={boardForm.aspectRatio} onChange={(event) => setBoardForm({ ...boardForm, aspectRatio: event.target.value })} /></Field><Field label="Duración (s)"><Input type="number" min="1" max="600" value={boardForm.targetDurationSec} onChange={(event) => setBoardForm({ ...boardForm, targetDurationSec: event.target.value })} /></Field></div>
      <div className="grid sm:grid-cols-2 gap-2"><Field label="Hook · promesa abierta"><textarea className={inputCls} style={inputStyle} rows="2" value={boardForm.hook} onChange={(event) => setBoardForm({ ...boardForm, hook: event.target.value })} /></Field><Field label="Payoff · respuesta"><textarea className={inputCls} style={inputStyle} rows="2" value={boardForm.payoff} onChange={(event) => setBoardForm({ ...boardForm, payoff: event.target.value })} /></Field></div>
      <Field label="Llamado a la acción"><Input value={boardForm.callToAction} onChange={(event) => setBoardForm({ ...boardForm, callToAction: event.target.value })} /></Field>
      <Field label="Tesis visual"><textarea className={inputCls} style={inputStyle} rows="2" value={boardForm.visualThesis} onChange={(event) => setBoardForm({ ...boardForm, visualThesis: event.target.value })} /></Field>
      <Field label="Costo total estimado (COP, informativo)"><Input type="number" min="0" value={boardForm.estimatedCostCop} onChange={(event) => setBoardForm({ ...boardForm, estimatedCostCop: event.target.value })} /></Field>
      <div className="flex gap-2"><BtnAsync onClick={createStoryboard} disabled={!contractId || boardForm.title.trim().length < 3 || boardForm.hook.trim().length < 2 || boardForm.payoff.trim().length < 2 || boardForm.callToAction.trim().length < 2}>Sellar storyboard</BtnAsync><Btn kind="ghost" onClick={() => setCreateOpen(false)}>Cancelar</Btn></div>
    </Modal>}

    {selected && <Modal title={`Storyboard #${selected.id} · ${selected.title}`} onClose={() => { setSelectedId(null); setShotEditing(false); }} wide topLayer>
      <div className="grid lg:grid-cols-[1fr_300px] gap-4">
        <div><div className="flex flex-wrap items-center justify-between gap-2 mb-3"><div><div className="text-[9px] uppercase font-extrabold" style={{ color: T.coral }}>{selected.channel} · {selected.format} · {selected.aspectRatio}</div><div className="display text-lg font-semibold">{selected.targetDurationSec}s de historia dirigida</div></div>{selected.status === "Borrador" && <Btn small onClick={newShot}>＋ Agregar toma</Btn>}</div>
          <div className="space-y-2">{selected.readiness.activeShots.length === 0 ? <div className="rounded-2xl border p-4 text-sm" style={{ borderColor: T.border, color: T.choco2 }}>Empezá con la toma 1. Cada toma necesita sujeto, acción, cámara y una salida de continuidad para que la siguiente escena sepa dónde retomar.</div> : selected.readiness.activeShots.map((shot) => <button type="button" key={shot.id} onClick={() => selected.status === "Borrador" && editShot(shot)} className="w-full text-left rounded-2xl border p-3" style={{ borderColor: T.border, background: "#FFF9F2" }}><div className="flex items-start justify-between gap-2"><div><div className="text-[9px] uppercase font-extrabold" style={{ color: T.coral }}>Toma {shot.shotNumber} · R{shot.revision} · {shot.durationSec}s</div><div className="font-extrabold text-sm">{shot.title}</div></div><span className="text-[10px] font-bold">{money(shot.estimatedCostCop)}</span></div><div className="text-[11px] mt-1" style={{ color: T.choco2 }}>{shot.purpose}</div><div className="rounded-xl px-2 py-1.5 mt-2 text-[10px]" style={{ background: "#E5EEF7", color: "#315A7D" }}>{shot.payload?.camera} → {shot.payload?.continuity_out}</div></button>)}</div>
        </div>
        <aside><div className="rounded-3xl p-4 border mb-3" style={{ borderColor: selected.readiness.ready ? "#B8D3B2" : "#E8C98B", background: selected.readiness.ready ? "#F4FAF2" : "#FFF8E8" }}><div className="text-[9px] uppercase font-extrabold">Control antes de generar</div><div className="display text-xl font-semibold">{selected.readiness.totalDurationSec.toFixed(1)} / {selected.targetDurationSec}s</div><div className="text-xs mb-2">{selected.readiness.activeShots.length} toma(s) · {money(selected.readiness.estimatedCostCop)}</div>{selected.readiness.reasons.map((reason) => <div key={reason} className="text-[10px] mb-1">• {reason}</div>)}</div>
          <div className="rounded-2xl px-3 py-2 mb-3 text-[10px]" style={{ background: T.vainilla }}><b>Hook:</b> {selected.creativeBrief?.hook}<br /><b>Payoff:</b> {selected.creativeBrief?.payoff}<br /><b>CTA:</b> {selected.creativeBrief?.call_to_action}</div>
          {selected.status === "Borrador" && <BtnAsync onClick={submitStoryboard} disabled={!selected.readiness.ready}>Enviar a revisión humana</BtnAsync>}
          {selected.status === "En revisión" && <div className="flex flex-col gap-2"><Input aria-label="Nota de revisión del storyboard" value={storyboardReviewNote} onChange={(event) => setStoryboardReviewNote(event.target.value)} placeholder="Qué verificaste o qué debe corregirse" /><BtnAsync confirmar disabled={!storyboardReviewNote.trim()} onClick={() => resolveStoryboard("Aprobar")}>Aprobar dirección</BtnAsync><BtnAsync kind="ghost" disabled={!storyboardReviewNote.trim()} onClick={() => resolveStoryboard("Devolver")}>Devolver a edición</BtnAsync></div>}
          {selected.status === "Aprobado" && <div className="rounded-2xl px-3 py-3 text-xs font-bold" style={{ background: "#DDEBD9", color: "#315B35" }}>✓ Dirección aprobada y sellada. No se ha generado ni publicado ninguna toma.</div>}
        </aside>
      </div>
      {shotEditing && selected.status === "Borrador" && <div className="rounded-3xl border p-4 mt-5" style={{ borderColor: "#D7C5B2", background: "#FFFAF5" }}><div className="flex items-center justify-between gap-2 mb-3"><div><div className="text-[9px] uppercase font-extrabold" style={{ color: T.coral }}>Dirección verificable</div><div className="display text-lg font-semibold">Toma {shotForm.shotNumber}</div></div><Btn small kind="ghost" onClick={() => setShotEditing(false)}>Cerrar editor</Btn></div>
        <div className="grid sm:grid-cols-3 gap-2"><Field label="Número"><Input type="number" min="1" value={shotForm.shotNumber} onChange={(event) => setShotForm({ ...shotForm, shotNumber: event.target.value })} /></Field><Field label="Duración (s)"><Input type="number" min="0.1" step="0.1" value={shotForm.durationSec} onChange={(event) => setShotForm({ ...shotForm, durationSec: event.target.value })} /></Field><Field label="Costo estimado"><Input type="number" min="0" value={shotForm.estimatedCostCop} onChange={(event) => setShotForm({ ...shotForm, estimatedCostCop: event.target.value })} /></Field></div>
        <div className="grid sm:grid-cols-2 gap-2"><Field label="Título"><Input value={shotForm.title} onChange={(event) => setShotForm({ ...shotForm, title: event.target.value })} /></Field><Field label="Propósito"><Input value={shotForm.purpose} onChange={(event) => setShotForm({ ...shotForm, purpose: event.target.value })} /></Field><Field label="Sujeto"><Input value={shotForm.subject} onChange={(event) => setShotForm({ ...shotForm, subject: event.target.value })} /></Field><Field label="Acción"><Input value={shotForm.action} onChange={(event) => setShotForm({ ...shotForm, action: event.target.value })} /></Field><Field label="Física y movimiento"><Input value={shotForm.physics} onChange={(event) => setShotForm({ ...shotForm, physics: event.target.value })} /></Field><Field label="Entorno"><Input value={shotForm.environment} onChange={(event) => setShotForm({ ...shotForm, environment: event.target.value })} /></Field><Field label="Cámara"><Input value={shotForm.camera} onChange={(event) => setShotForm({ ...shotForm, camera: event.target.value })} /></Field><Field label="Iluminación"><Input value={shotForm.lighting} onChange={(event) => setShotForm({ ...shotForm, lighting: event.target.value })} /></Field><Field label="Audio"><Input value={shotForm.audio} onChange={(event) => setShotForm({ ...shotForm, audio: event.target.value })} /></Field><Field label="Texto en pantalla"><Input value={shotForm.onScreenText} onChange={(event) => setShotForm({ ...shotForm, onScreenText: event.target.value })} /></Field><Field label="Continuidad de entrada"><Input value={shotForm.continuityIn} onChange={(event) => setShotForm({ ...shotForm, continuityIn: event.target.value })} /></Field><Field label="Continuidad de salida"><Input value={shotForm.continuityOut} onChange={(event) => setShotForm({ ...shotForm, continuityOut: event.target.value })} /></Field></div>
        <Field label="Evitar"><Input value={shotForm.avoid} onChange={(event) => setShotForm({ ...shotForm, avoid: event.target.value })} placeholder="Deformaciones, texto ilegible, producto distinto…" /></Field>
        {authorizedAssets.length > 0 && <Field label="Referencias de marca autorizadas"><div className="flex flex-wrap gap-2">{authorizedAssets.slice(0, 20).map((asset) => { const checked = shotForm.assetIds.includes(Number(asset.id)); return <label key={asset.id} className="rounded-full px-3 py-2 text-[10px] font-bold cursor-pointer" style={{ background: checked ? "#DDEBD9" : T.vainilla }}><input type="checkbox" className="mr-1" checked={checked} onChange={() => setShotForm({ ...shotForm, assetIds: checked ? shotForm.assetIds.filter((id) => id !== Number(asset.id)) : [...shotForm.assetIds, Number(asset.id)] })} />{asset.name}</label>; })}</div></Field>}
        <BtnAsync onClick={saveShot} disabled={shotForm.title.trim().length < 2 || shotForm.purpose.trim().length < 2 || shotForm.subject.trim().length < 2 || shotForm.action.trim().length < 2 || shotForm.camera.trim().length < 2 || shotForm.continuityOut.trim().length < 2}>Guardar revisión de toma</BtnAsync>
      </div>}
    </Modal>}
  </div>;
}

function AgencyMotionExperience({ db, refrescar }) {
  const center = useMemo(() => buildAgencyMotionCenter(db), [db]);
  const [boardId, setBoardId] = useState("");
  const [selections, setSelections] = useState({});
  const [reviewNotes, setReviewNotes] = useState({});
  const board = center.eligibleStoryboards.find((item) => String(item.id) === String(boardId)) || null;
  const draft = useMemo(() => board
    ? buildMotionPlanDraft(board, db.agencyStoryboardShots || [], selections)
    : null, [board, db.agencyStoryboardShots, selections]);

  async function prepare() {
    if (!db.agencyMotionReady) throw new Error("Aplicá la migración 36 de Dirección de motion.");
    if (!draft?.ready) throw new Error(draft?.reasons?.[0] || "La dirección de motion todavía no está lista.");
    const result = await prepararPlanMotion(motionPlanPayload(draft, "MOMO OPS Motion Director"));
    setBoardId(""); setSelections({});
    toast("ok", result.duplicate
      ? "Esa dirección ya estaba sellada."
      : "Dirección de cámara y luz preparada para revisión. No generó, gastó ni publicó.");
    await refrescar();
  }

  async function resolve(plan, decision) {
    const note = String(reviewNotes[plan.id] || "").trim();
    if (!note) throw new Error(decision === "Aprobar"
      ? "Escribí qué verificaste antes de aprobar la dirección."
      : "Escribí qué debe corregirse por toma.");
    await resolverPlanMotion(plan.id, decision, note);
    setReviewNotes((current) => { const next = { ...current }; delete next[plan.id]; return next; });
    toast("ok", decision === "Aprobar"
      ? "Motion aprobado: el Enrutador ya puede asignar motores y topes. Aún no se generó nada."
      : "Plan devuelto con corrección trazable.");
    await refrescar();
  }

  const planTone = (status) => status === "Aprobado" ? { bg: "#DDEBD9", fg: "#315B35" }
    : status === "En revisión" ? { bg: "#FFF0CE", fg: "#8B5A08" } : { bg: "#F3D7DC", fg: "#8E4B5A" };

  return <section className="rounded-[26px] border overflow-hidden mb-6 shadow-sm" style={{ borderColor: "#D7C5B2", background: "#FFFDFC" }}>
    <div className="p-4 sm:p-5 flex flex-col lg:flex-row lg:items-center justify-between gap-4" style={{ background: "linear-gradient(135deg,#7C3F2D,#B86445)", color: "#fff" }}>
      <div className="flex items-start gap-3"><div className="w-11 h-11 rounded-2xl grid place-items-center text-xl shrink-0" style={{ background: "rgba(255,255,255,.15)" }}>🎥</div><div>
        <div className="text-[9px] font-extrabold uppercase tracking-[.18em] opacity-75">Storyboard → cámara, luz, física y continuidad</div>
        <div className="display text-xl font-semibold">Dirección de motion MOMOS</div>
        <div className="text-xs opacity-85 max-w-2xl">Define por qué se mueve la cámara, cómo responde la materia y qué debe conservar el corte. El humano elige una propuesta por toma antes de permitir el Enrutador.</div>
      </div></div>
      <div className="grid grid-cols-4 gap-2 shrink-0">{[["Por dirigir",center.summary.eligible],["Revisión",center.summary.reviewing],["Aprobados",center.summary.approved],["Aprendizajes",center.summary.observations]].map(([label,value]) => <div key={label} className="rounded-2xl px-2.5 py-2 min-w-[64px] text-center" style={{ background: "rgba(255,255,255,.13)" }}><div className="display text-lg font-semibold">{value}</div><div className="text-[7px] uppercase font-extrabold opacity-70">{label}</div></div>)}</div>
    </div>
    {!db.agencyMotionReady ? <div className="px-4 py-3 text-xs font-bold" style={{ background: "#FFF2D8", color: "#7A5410" }}>Aplicá <code>experiencia-motion-v1.sql</code> después del Hito 35. Hasta entonces el Enrutador no recibirá recetas de cámara aprobadas.</div> : <>
      {center.eligibleStoryboards.length > 0 && <div className="p-4 border-b" style={{ borderColor: T.border }}>
        <div className="flex flex-wrap items-end gap-2 mb-3"><Field label="Storyboard aprobado sin motion"><select className={inputCls} style={{ ...inputStyle, minWidth: 300 }} value={boardId} onChange={(event) => { setBoardId(event.target.value); setSelections({}); }}><option value="">Elegí una pieza…</option>{center.eligibleStoryboards.map((item) => <option key={item.id} value={item.id}>#{item.id} · {item.title} · {item.channel}</option>)}</select></Field>{draft && <div className="pb-3 text-[10px] font-bold" style={{ color: draft.ready ? "#315B35" : "#A03B2A" }}>{draft.ready ? `● ${draft.shotRecipes.length} tomas cubiertas · $0 comprometidos` : `× ${draft.reasons[0]}`}</div>}</div>
        {draft && <div className="space-y-3">{draft.shotRecipes.map(({ shot, proposals, selected }) => <article key={shot.id} className="rounded-2xl border p-3" style={{ borderColor: T.border, background: "#FFF9F2" }}>
          <div className="flex flex-col xl:flex-row xl:items-start justify-between gap-3"><div className="min-w-0"><div className="text-[9px] uppercase font-extrabold" style={{ color: T.coral }}>Toma {shot.shotNumber} · {selected?.intent?.narrativeJob}</div><div className="font-extrabold text-sm">{shot.title}</div><div className="text-[10px] mt-1" style={{ color: T.choco2 }}>Una intención · un movimiento principal · una fuente de luz motivada.</div></div>
            <div className="flex flex-wrap gap-2">{proposals.map((proposal) => <button type="button" key={proposal.proposalKey} onClick={() => setSelections((current) => ({ ...current, [shot.id]: proposal.proposalKey }))} className="rounded-xl border px-3 py-2 text-left transition" style={{ borderColor: proposal.selected ? T.coral : T.border, background: proposal.selected ? "#F8E0D8" : "#fff" }}><div className="text-[10px] font-extrabold">{proposal.label}</div><div className="text-[8px]" style={{ color: T.choco2 }}>{proposal.cameraPath.rigFeel} · {proposal.handheldProfile.mode}</div></button>)}</div>
          </div>
          {selected && <div className="grid md:grid-cols-4 gap-2 mt-3 text-[10px]"><div className="rounded-xl p-2.5" style={{ background: "#F5E8D2" }}><b>Cámara</b><br />{selected.cameraPath.primaryMove}<br /><span style={{ color: T.choco2 }}>Inercia {selected.cameraPath.acceleration}; {selected.cameraPath.settle}.</span></div><div className="rounded-xl p-2.5" style={{ background: "#F6E6D9" }}><b>Luz y sombra</b><br />{selected.lightingMap.motivatedSource}<br /><span style={{ color: T.choco2 }}>{selected.lightingMap.shadowBehavior}</span></div><div className="rounded-xl p-2.5" style={{ background: "#E7EFE5" }}><b>Física</b><br />{selected.physics.contact}<br /><span style={{ color: T.choco2 }}>{selected.physics.weightResistance}</span></div><div className="rounded-xl p-2.5" style={{ background: "#E7EDF2" }}><b>Siguiente corte</b><br />{selected.transitionToNext.type}<br /><span style={{ color: T.choco2 }}>{selected.transitionToNext.intentionalChange}</span></div></div>}
        </article>)}<div className="rounded-2xl px-3 py-3 flex flex-wrap items-center justify-between gap-3" style={{ background: T.vainilla }}><div className="text-xs"><b>{draft.grammarPrimary}</b>{draft.grammarSecondary !== draft.grammarPrimary ? ` + ${draft.grammarSecondary}` : ""}<div className="text-[9px]" style={{ color: T.choco2 }}>Costo preliminar informativo {fmt(draft.estimatedPreviewCostCop)} · preparar cuesta $0.</div></div><BtnAsync onClick={prepare} disabled={!draft.ready}>Sellar dirección para revisión</BtnAsync></div></div>}
      </div>}
      <div className="p-3 grid lg:grid-cols-2 gap-2">{center.plans.slice(0, 8).map((plan) => { const tone = planTone(plan.status); const note = reviewNotes[plan.id] || ""; return <article key={plan.id} className="rounded-2xl border p-3" style={{ borderColor: plan.status === "En revisión" ? "#E8C98B" : T.border, background: "#FFF9F2" }}><div className="flex items-start justify-between gap-2"><div><div className="text-[9px] uppercase font-extrabold" style={{ color: T.coral }}>Motion #{plan.id} · V{plan.version}</div><div className="font-extrabold text-sm">{plan.storyboard?.title || `Storyboard #${plan.storyboardId}`}</div></div><span className="rounded-full px-2 py-1 text-[9px] font-extrabold" style={{ background: tone.bg, color: tone.fg }}>{plan.status}</span></div><div className="flex flex-wrap gap-1.5 my-2">{plan.recipes.map((recipe) => <span key={recipe.id} className="rounded-full px-2 py-1 text-[9px] font-bold" style={{ background: "#F5E8D2" }}>T{recipe.shotNumber} · {recipe.selectedRecipe?.intent?.narrative_job || recipe.selectedKey}</span>)}</div><div className="text-[10px] mb-2" style={{ color: T.choco2 }}>{plan.grammarPrimary} · huella {plan.fingerprint?.slice(0, 8)} · {plan.recipes.length} receta(s)</div>{plan.status === "En revisión" && <div className="space-y-2"><textarea className={inputCls} style={{ ...inputStyle, minHeight: 72 }} value={note} onChange={(event) => setReviewNotes((current) => ({ ...current, [plan.id]: event.target.value }))} placeholder="Qué verificaste o qué debe corregirse por toma…" aria-label={`Nota de revisión motion ${plan.id}`} /><div className="flex gap-2"><BtnAsync small confirmar disabled={!note.trim()} onClick={() => resolve(plan,"Aprobar")}>Aprobar motion</BtnAsync><BtnAsync small kind="ghost" disabled={!note.trim()} onClick={() => resolve(plan,"Devolver")}>Devolver</BtnAsync></div></div>}{plan.status === "Aprobado" && <div className="rounded-xl px-2.5 py-2 text-[10px] font-bold" style={{ background: "#DDEBD9", color: "#315B35" }}>✓ Enrutador habilitado · generación y publicación siguen bloqueadas</div>}</article>; })}{center.plans.length === 0 && center.eligibleStoryboards.length === 0 && <div className="p-2 text-sm" style={{ color: T.choco2 }}><b style={{ color: T.choco }}>Sin piezas pendientes.</b> Cuando el Estudio apruebe un storyboard aparecerá aquí.</div>}</div>
    </>}
    <div className="px-4 py-2.5 border-t text-[10px] font-semibold" style={{ borderColor: T.border, color: T.choco2 }}>Contrato seguro: aprobar motion cuesta $0 y no llama motores. El Enrutador consume únicamente la receta seleccionada y sellada de cada toma.</div>
  </section>;
}

function AgencySceneRouter({ db, refrescar }) {
  const center = useMemo(() => buildAgencySceneRouter(db), [db]);
  const [boardId, setBoardId] = useState("");
  const [overrides, setOverrides] = useState({});
  const board = center.eligibleStoryboards.find((item) => String(item.id) === String(boardId)) || null;
  const draft = useMemo(() => board
    ? buildSceneRoutingDraft(board, db.agencyStoryboardShots || [], db, overrides)
    : null, [board, db, overrides]);

  function patchRoute(shotId, values) {
    setOverrides((current) => ({ ...current, [shotId]: { ...(current[shotId] || {}), ...values } }));
  }

  async function prepareRoutes() {
    if (!db.agencySceneRouterReady) throw new Error("Aplicá la migración 32 del Enrutador de escenas.");
    if (!draft?.ready) throw new Error(draft?.reasons?.[0] || "El plan no está listo.");
    const result = await prepararEnrutamientoEscenas(sceneRoutingPayload(draft, "MOMO OPS Router"));
    setBoardId(""); setOverrides({});
    toast("ok", result.duplicate ? "Ese enrutamiento ya estaba sellado." : "Ruta preparada. Ningún motor fue llamado todavía.");
    await refrescar();
  }

  async function resolvePlan(plan, decision) {
    const note = decision === "Descartar"
      ? (window.prompt("¿Por qué descartamos este enrutamiento?", "Se ajustará la dirección o el costo") || "")
      : "Autorización humana de motores y topes por escena";
    if (!note) return;
    const result = await resolverEnrutamientoEscenas(plan.id, decision, note);
    toast("ok", decision === "Autorizar"
      ? `${result.job_ids?.length || 0} toma(s) autorizadas para la cola privada. Aún no se publicó nada.`
      : "Enrutamiento descartado con trazabilidad.");
    await refrescar();
  }

  return <div className="rounded-[26px] border overflow-hidden mb-6 shadow-sm" style={{ borderColor: "#D7C5B2", background: "#FFFDFC" }}>
    <div className="p-4 sm:p-5 flex flex-col lg:flex-row lg:items-center justify-between gap-4" style={{ background: "linear-gradient(135deg,#243D37,#355E53)", color: "#fff" }}>
      <div><div className="text-[9px] font-extrabold uppercase tracking-[.18em] opacity-75">Motion aprobado → motor controlado</div><div className="display text-xl font-semibold">Enrutador de escenas MOMOS</div><div className="text-xs opacity-80 max-w-2xl">Consume la cámara y luz ya aprobadas, elige el motor por capacidad y sella costo y riesgo por toma. Los workers ejecutan después; publicar sigue siendo otro paso.</div></div>
      <div className="grid grid-cols-3 gap-2 shrink-0">{[["Por autorizar",center.summary.prepared],["Autorizados",center.summary.authorized],["Trabajos",center.summary.jobs]].map(([label,value]) => <div key={label} className="rounded-2xl px-3 py-2 min-w-[74px] text-center" style={{ background: "rgba(255,255,255,.12)" }}><div className="display text-lg font-semibold">{value}</div><div className="text-[8px] uppercase font-extrabold opacity-70">{label}</div></div>)}</div>
    </div>
    {!db.agencySceneRouterReady ? <div className="px-4 py-3 text-xs font-bold" style={{ background: "#FFF2D8", color: "#7A5410" }}>Aplicá <code>enrutador-escenas-v1.sql</code>. Hasta entonces MOMO OPS no creará trabajos desde storyboards.</div> : <>
      <div className="p-4 border-b" style={{ borderColor: T.border }}>
        <div className="flex flex-wrap items-end gap-2"><Field label="Storyboard + motion aprobados"><select className={inputCls} style={{ ...inputStyle, minWidth: 280 }} value={boardId} onChange={(event) => { setBoardId(event.target.value); setOverrides({}); }}><option value="">Elegí una pieza dirigida sin enrutar…</option>{center.eligibleStoryboards.map((item) => <option key={item.id} value={item.id}>#{item.id} · {item.title} · {item.channel}</option>)}</select></Field>{draft && <div className="pb-3 text-[10px] font-bold" style={{ color: draft.operational ? "#315B35" : "#9A5B16" }}>{draft.operational ? "● Motores disponibles ahora" : `● Plan documentable; ${draft.operationalReasons[0] || "conector no disponible"}`}</div>}</div>
        {draft && <div className="space-y-2 mt-1">{draft.routes.map((route) => <article key={route.shotId} className="rounded-2xl border p-3" style={{ borderColor: T.border, background: "#FFF9F2" }}>
          <div className="grid lg:grid-cols-[1fr_160px_140px_140px] gap-2 items-end"><div><div className="text-[9px] uppercase font-extrabold" style={{ color: T.coral }}>Toma {route.shotNumber} · riesgo {route.riskLevel}</div><div className="font-extrabold text-sm">{route.title}</div><div className="text-[10px]" style={{ color: T.choco2 }}>{route.capability} · {route.rationale}</div></div><Field label="Motor"><Select options={SCENE_ROUTE_PROVIDERS} value={route.provider} onChange={(event) => patchRoute(route.shotId, { provider: event.target.value })} /></Field><Field label="Estimado COP"><Input type="number" min="1" value={route.estimatedCostCop || ""} onChange={(event) => patchRoute(route.shotId, { estimatedCostCop: event.target.value })} /></Field><Field label="Tope COP"><Input type="number" min="1" value={route.maxCostCop || ""} onChange={(event) => patchRoute(route.shotId, { maxCostCop: event.target.value })} /></Field></div>
        </article>)}<div className="flex flex-wrap items-center justify-between gap-2 rounded-2xl px-3 py-3" style={{ background: T.vainilla }}><div className="text-xs"><b>{draft.routes.length} toma(s)</b> · estimado {fmt(draft.totalEstimatedCostCop)} · tope {fmt(draft.totalCostCapCop)}{draft.reasons.map((reason) => <div key={reason} className="text-red-700">× {reason}</div>)}</div><BtnAsync onClick={prepareRoutes} disabled={!draft.ready}>Sellar ruta multimotor</BtnAsync></div></div>}
      </div>
      <div className="p-3 grid lg:grid-cols-2 gap-2">{center.plans.slice(0, 8).map((plan) => { const routes = plan.snapshot?.routes || []; const tone = statusTone(plan.status); return <article key={plan.id} className="rounded-2xl border p-3" style={{ borderColor: plan.status === "Preparado" ? "#E8C98B" : T.border, background: "#FFF9F2" }}><div className="flex items-start justify-between gap-2"><div><div className="text-[9px] uppercase font-extrabold" style={{ color: T.coral }}>Ruta #{plan.id} · V{plan.version}</div><div className="font-extrabold text-sm">{plan.storyboard?.title || `Storyboard #${plan.storyboardId}`}</div></div><span className="rounded-full px-2 py-1 text-[9px] font-extrabold" style={{ background: tone.bg, color: tone.fg }}>{plan.status}</span></div><div className="flex flex-wrap gap-1 my-2">{routes.map((route) => <span key={route.shot_id} className="rounded-full px-2 py-1 text-[9px] font-bold" style={{ background: route.provider === "Kling" ? "#E5EEF7" : "#F3D7DC" }}>T{route.shot_number} · {route.provider}</span>)}</div><div className="text-[10px] mb-2" style={{ color: T.choco2 }}>Estimado {fmt(plan.totalEstimatedCostCop)} · tope humano {fmt(plan.totalCostCapCop)} · huella {plan.fingerprint?.slice(0, 8)}</div>{plan.status === "Preparado" && <div className="flex gap-2"><BtnAsync small confirmar onClick={() => resolvePlan(plan, "Autorizar")}>Autorizar {routes.length} toma(s)</BtnAsync><BtnAsync small kind="ghost" onClick={() => resolvePlan(plan, "Descartar")}>Descartar</BtnAsync></div>}{plan.status === "Autorizado" && <div className="rounded-xl px-2.5 py-2 text-[10px] font-bold" style={{ background: "#DDEBD9", color: "#315B35" }}>✓ {plan.jobIds.length} trabajo(s) en colas privadas · publicación: bloqueada</div>}</article>; })}{center.plans.length === 0 && <div className="p-2 text-sm" style={{ color: T.choco2 }}><b style={{ color: T.choco }}>No hay rutas selladas.</b> Aprobá un storyboard y asigná su motor por toma.</div>}</div>
    </>}
    <div className="px-4 py-2.5 border-t text-[10px] font-semibold" style={{ borderColor: T.border, color: T.choco2 }}>Arquitectura segura: preparar no gasta; autorizar crea la cola atómicamente; el worker genera; Revisión Creativa decide; Distribución publica por separado.</div>
  </div>;
}

function AgencyQualityControl({ db, refrescar }) {
  const center = useMemo(() => buildAgencyQualityCenter(db), [db]);
  const exportCenter = useMemo(() => buildPostproductionExportCenter(db), [db]);
  const exportWorker = (db.agencyPostproductionWorkers || [])[0] || null;
  const [reviewJob, setReviewJob] = useState(null);
  const [scores, setScores] = useState(() => Object.fromEntries(AGENCY_QUALITY_CRITERIA.map(({ key }) => [key, 2])));
  const [failureType, setFailureType] = useState("Fallo técnico");
  const [note, setNote] = useState("");
  const [continuity, setContinuity] = useState("");
  const [audioByPackage, setAudioByPackage] = useState({});
  const today = new Date().toISOString().slice(0, 10);
  const audioAssets = useMemo(() => (db.brandMediaAssets || []).filter((asset) => asset.mediaType === "Audio" && asset.status === "Activo"
    && ["Propio", "Autorizado"].includes(asset.rightsStatus) && (!asset.rightsExpiresAt || asset.rightsExpiresAt >= today)
    && ["audio/mpeg", "audio/mp4", "audio/wav"].includes(asset.mimeType) && asset.storagePath && /^[0-9a-f]{64}$/i.test(asset.contentHash || "")
    && Number(asset.sizeBytes) > 0 && Number(asset.durationSeconds) > 0 && Number(asset.durationSeconds) <= 1800), [db.brandMediaAssets, today]);
  const outputAsset = reviewJob ? (db.brandMediaAssets || []).find((item) => String(item.id) === String(reviewJob.outputAssetId)) : null;
  const rightsValid = Boolean(outputAsset && outputAsset.status === "Activo" && outputAsset.rightsStatus === "Autorizado");
  const evaluation = useMemo(() => evaluateSceneQuality(scores, rightsValid), [scores, rightsValid]);

  function openReview(job) {
    const shot = (db.agencyStoryboardShots || []).find((item) => String(item.id) === String(job.outputSpec?.storyboard_shot_id));
    setReviewJob(job); setScores(Object.fromEntries(AGENCY_QUALITY_CRITERIA.map(({ key }) => [key, 2])));
    setFailureType("Fallo técnico"); setNote("");
    setContinuity(shot?.payload?.continuity_out ? `La salida conserva: ${shot.payload.continuity_out}` : "Entrada y salida comparadas contra el storyboard");
  }

  async function saveQualityReview() {
    const payload = sceneQualityReviewPayload(reviewJob, scores, {
      rightsValid, failureType, reviewNote: note || (evaluation.approved ? "Producto, marca, física y continuidad verificados" : "La toma requiere una nueva versión"),
      continuityObservation: continuity, findings: evaluation.reasons,
    });
    const result = await registrarRevisionCalidadEscena(payload);
    setReviewJob(null);
    toast(result.status === "Aprobada" ? "ok" : "alert", result.status === "Aprobada"
      ? `Toma aprobada para postproducción · ${result.score_total}/22.`
      : `Toma clasificada como ${result.failure_type}; no entrará al corte.`);
    await refrescar();
  }

  async function resolveAgentReview(review, decision) {
    const failure = decision === "Aprobar" ? "Pendiente" : "Fallo técnico";
    const resolution = window.prompt(decision === "Aprobar" ? "¿Qué verificaste antes de aprobar?" : "¿Qué debe corregirse?",
      decision === "Aprobar" ? "Producto, física, luz y continuidad verificados" : "Corregir la salida antes de regenerar") || "";
    if (!resolution) return;
    await resolverRevisionCalidadEscena(review.id, decision, failure, resolution);
    toast("ok", decision === "Aprobar" ? "Control del agente aprobado por humano." : "Hallazgo del agente clasificado y devuelto.");
    await refrescar();
  }

  const packageCandidates = useMemo(() => (db.agencySceneRoutingPlans || []).filter((plan) => plan.status === "Autorizado").map((plan) => {
    const storyboard = (db.agencyStoryboards || []).find((item) => String(item.id) === String(plan.storyboardId));
    const activeShots = (db.agencyStoryboardShots || []).filter((shot) => String(shot.storyboardId) === String(plan.storyboardId) && shot.status === "Vigente");
    const approved = center.approved.filter((review) => String(review.routingPlanId) === String(plan.id));
    const alreadyPackaged = center.packages.some((item) => String(item.routingPlanId) === String(plan.id) && !["Devuelto", "Anulado"].includes(item.status));
    return { plan, storyboard, activeShots, approved, ready: Boolean(storyboard) && activeShots.length > 0 && approved.length === activeShots.length && !alreadyPackaged };
  }).filter((item) => item.ready), [db.agencySceneRoutingPlans, db.agencyStoryboards, db.agencyStoryboardShots, center.approved, center.packages]);

  async function preparePackage(candidate) {
    const payload = postproductionPackagePayload(candidate.storyboard, candidate.plan, candidate.approved);
    const result = await prepararPaquetePostproduccion(payload);
    toast("ok", `${candidate.approved.length} toma(s) selladas para postproducción. Falta aprobación del corte.`);
    if (result.duplicate) toast("alert", "Ese paquete ya existía; no se duplicó.");
    await refrescar();
  }

  async function resolvePackage(item, decision) {
    const noteText = window.prompt(decision === "Aprobar" ? "¿Qué validaste en el corte final?" : "¿Qué debe corregir postproducción?",
      decision === "Aprobar" ? "Orden, audio, subtítulos, color y continuidad verificados" : "Ajustar el corte antes de aprobar") || "";
    if (!noteText) return;
    await resolverPaquetePostproduccion(item.id, decision, noteText);
    toast("ok", decision === "Aprobar" ? "Corte aprobado. Publicación y pauta siguen bloqueadas." : "Corte devuelto con instrucciones trazables.");
    await refrescar();
  }

  async function authorizeExport(pkg) {
    const selectedId = audioByPackage[String(pkg.id)] || "";
    const audioAsset = audioAssetsForPackage(pkg).find((asset) => String(asset.id) === String(selectedId)) || null;
    const payload = postproductionExportPayload(pkg, { audioAsset });
    const result = await autorizarExportacionPostproduccion(payload);
    toast("ok", result.duplicate
      ? "La exportación ya estaba autorizada; no se duplicó."
      : `Máster autorizado con audio ${audioAsset ? `de Biblioteca · ${audioAsset.name}` : "original de las tomas"}. Aún no existe archivo ni publicación.`);
    await refrescar();
  }

  function audioAssetsForPackage(pkg) {
    const channel = String(pkg.storyboard?.channel || pkg.snapshot?.export_spec?.channel || "").trim().toLowerCase();
    return audioAssets.filter((asset) => {
      const allowed = Array.isArray(asset.allowedChannels) ? asset.allowedChannels.map((item) => String(item).trim().toLowerCase()) : [];
      return allowed.length === 0 || allowed.includes(channel) || allowed.includes("todos") || allowed.includes("all");
    });
  }

  async function resolveMaster(item, decision) {
    const evaluation = evaluatePostproductionMaster(item, item.outputAsset);
    if (decision === "Aprobar" && !evaluation.approved) {
      toast("alert", evaluation.reasons[0] || "El máster no supera el control técnico.");
      return;
    }
    const suggested = decision === "Aprobar"
      ? "Resolución, FPS, audio, color, peso y continuidad verificados"
      : "Corregir el máster antes de enviarlo a Distribución";
    const noteText = window.prompt(decision === "Aprobar" ? "¿Qué verificaste en el máster?" : "¿Qué debe corregirse?", suggested) || "";
    if (noteText.trim().length < 5) return;
    await resolverControlMasterPostproduccion(item.id, decision, noteText.trim());
    toast("ok", decision === "Aprobar" ? "Máster aprobado. Distribución y publicación siguen siendo pasos separados." : "Máster rechazado con corrección trazable.");
    await refrescar();
  }

  async function retryExport(item) {
    const noteText = window.prompt("¿Por qué es seguro reintentar este fallo definitivo?", "FFmpeg no produjo archivo; reintentar con el mismo contrato sellado") || "";
    if (noteText.trim().length < 5) return;
    await reintentarExportacionPostproduccion(item.id, noteText.trim());
    toast("ok", "Reintento autorizado. Los resultados inciertos nunca se reenvían.");
    await refrescar();
  }

  return <div className="rounded-[26px] border overflow-hidden mb-6 shadow-sm" style={{ borderColor: "#D7C5B2", background: "#FFFDFC" }}>
    <div className="p-4 sm:p-5 flex flex-col lg:flex-row lg:items-center justify-between gap-4" style={{ background: "linear-gradient(135deg,#5B2947,#7A3D5D)", color: "#fff" }}>
      <div><div className="text-[9px] font-extrabold uppercase tracking-[.18em] opacity-75">Salida generada → corte verificable</div><div className="display text-xl font-semibold">Calidad y postproducción MOMOS</div><div className="text-xs opacity-80 max-w-2xl">Protege producto, marca, física, cámara, luz y continuidad. Una falla crítica no se promedia y ningún corte autoriza publicación.</div></div>
      <div className="grid grid-cols-4 gap-2 shrink-0">{[["Por revisar",center.summary.waiting + center.summary.pending],["Aprobadas",center.summary.approved],["Cortes",center.summary.packagesApproved],["Másters",exportCenter.summary.approved]].map(([label,value]) => <div key={label} className="rounded-2xl px-3 py-2 min-w-[70px] text-center" style={{ background: "rgba(255,255,255,.12)" }}><div className="display text-lg font-semibold">{value}</div><div className="text-[8px] uppercase font-extrabold opacity-70">{label}</div></div>)}</div>
    </div>
    {!db.agencyQualityReady ? <div className="px-4 py-3 text-xs font-bold" style={{ background: "#FFF2D8", color: "#7A5410" }}>Aplicá <code>calidad-postproduccion-v1.sql</code>. La generación sigue disponible, pero ninguna salida se declarará lista para corte.</div> : <>
      <div className="p-4 border-b" style={{ borderColor: T.border }}>
        <div className="text-[9px] uppercase font-extrabold mb-2" style={{ color: T.coral }}>Control por toma</div>
        <div className="grid lg:grid-cols-2 gap-2">{center.eligibleJobs.map((job) => { const shot = (db.agencyStoryboardShots || []).find((item) => String(item.id) === String(job.outputSpec?.storyboard_shot_id)); return <article key={job.id} className="rounded-2xl border p-3 flex items-center gap-3" style={{ borderColor: T.border, background: "#FFF9F2" }}><div className="w-10 h-10 rounded-xl grid place-items-center" style={{ background: "#F3D7DC" }}>◉</div><div className="flex-1 min-w-0"><div className="text-[9px] uppercase font-extrabold" style={{ color: T.coral }}>Toma {shot?.shotNumber || "?"} · {job.provider}</div><div className="font-extrabold text-sm truncate">{shot?.title || job.operation}</div><div className="text-[10px]" style={{ color: T.choco2 }}>Salida #{job.outputAssetId} · revisión creativa aprobada</div></div><Btn small onClick={() => openReview(job)}>Evaluar toma</Btn></article>; })}
          {center.eligibleJobs.length === 0 && center.pending.length === 0 && <div className="text-sm p-2" style={{ color: T.choco2 }}><b style={{ color: T.choco }}>No hay salidas esperando control.</b> Aparecerán cuando el motor complete una toma y pase la revisión creativa humana.</div>}
        </div>
        {center.pending.length > 0 && <div className="mt-3 space-y-2">{center.pending.map((review) => <article key={review.id} className="rounded-2xl border p-3 flex flex-wrap items-center gap-2" style={{ borderColor: "#E8C98B", background: "#FFF7E8" }}><div className="flex-1"><div className="text-[9px] uppercase font-extrabold">Propuesta del agente · toma {review.shot?.shotNumber}</div><div className="text-sm font-extrabold">{review.scoreTotal}/22 · requiere decisión humana</div></div><BtnAsync small confirmar onClick={() => resolveAgentReview(review, "Aprobar")}>Aprobar</BtnAsync><BtnAsync small kind="ghost" onClick={() => resolveAgentReview(review, "Rechazar")}>Clasificar falla</BtnAsync></article>)}</div>}
      </div>
      <div className="p-4 border-b" style={{ borderColor: T.border }}><div className="flex flex-wrap items-center justify-between gap-2 mb-2"><div><div className="text-[9px] uppercase font-extrabold" style={{ color: T.coral }}>Postproducción</div><div className="font-extrabold text-sm">Tomas, audio, subtítulos y decisiones de corte</div></div></div>
        <div className="grid lg:grid-cols-2 gap-2">{packageCandidates.map((candidate) => <article key={candidate.plan.id} className="rounded-2xl border p-3 flex items-center gap-3" style={{ borderColor: "#B8D3B2", background: "#F4FAF1" }}><div className="flex-1"><div className="text-[9px] uppercase font-extrabold" style={{ color: "#315B35" }}>{candidate.approved.length} toma(s) aprobadas</div><div className="font-extrabold text-sm">{candidate.storyboard.title}</div><div className="text-[10px]" style={{ color: T.choco2 }}>Cobertura exacta · lista para preparar corte</div></div><BtnAsync small onClick={() => preparePackage(candidate)}>Preparar corte</BtnAsync></article>)}
          {center.packages.map((item) => { const tone = statusTone(item.status); return <article key={item.id} className="rounded-2xl border p-3" style={{ borderColor: T.border, background: "#FFF9F2" }}><div className="flex items-start justify-between gap-2"><div><div className="text-[9px] uppercase font-extrabold" style={{ color: T.coral }}>Paquete #{item.id} · V{item.version}</div><div className="font-extrabold text-sm">{item.storyboard?.title || `Storyboard #${item.storyboardId}`}</div></div><span className="rounded-full px-2 py-1 text-[9px] font-extrabold" style={{ background: tone.bg, color: tone.fg }}>{item.status}</span></div><div className="text-[10px] my-2" style={{ color: T.choco2 }}>{item.snapshot?.selections?.length || 0} tomas · publicación bloqueada · huella {item.fingerprint?.slice(0, 8)}</div>{item.status === "Preparado" && <div className="flex gap-2"><BtnAsync small confirmar onClick={() => resolvePackage(item, "Aprobar")}>Aprobar corte final</BtnAsync><BtnAsync small kind="ghost" onClick={() => resolvePackage(item, "Devolver")}>Devolver</BtnAsync></div>}</article>; })}
        </div>
      </div>
      <div className="p-4 border-b" style={{ borderColor: T.border, background: "#FBF7F1" }}>
        <div className="flex flex-wrap items-start justify-between gap-2 mb-3"><div><div className="text-[9px] uppercase font-extrabold" style={{ color: T.coral }}>Exportación verificable</div><div className="font-extrabold text-sm">Del corte aprobado al archivo máster real</div><div className="text-[10px]" style={{ color: T.choco2 }}>MP4 · H.264 · AAC · BT.709 · hash y probe técnico · revisión humana final</div></div>
          {db.agencyPostproductionExportReady && <span className="rounded-full px-2.5 py-1 text-[9px] font-extrabold" style={{ background: exportWorker?.ffmpegAvailable ? "#DDEBD9" : "#FFF2D8", color: exportWorker?.ffmpegAvailable ? "#315B35" : "#7A5410" }}>{exportWorker?.ffmpegAvailable ? `Worker disponible · ${exportWorker.version}` : "Worker pendiente · no hay FFmpeg activo"}</span>}
        </div>
        {!db.agencyPostproductionExportReady ? <div className="rounded-2xl px-3 py-3 text-xs font-bold" style={{ background: "#FFF2D8", color: "#7A5410" }}>Aplicá <code>postproduccion-exportacion-v1.sql</code>. Hasta entonces un corte aprobado no puede declararse archivo final.</div> : <div className="grid lg:grid-cols-2 gap-2">
          {exportCenter.candidates.map((pkg) => <article key={`candidate-${pkg.id}`} className="rounded-2xl border p-3" style={{ borderColor: "#B8D3B2", background: "#F4FAF1" }}><div className="flex flex-col sm:flex-row sm:items-end gap-3"><div className="flex-1"><div className="text-[9px] uppercase font-extrabold" style={{ color: "#315B35" }}>Corte #{pkg.id} · V{pkg.version} aprobado</div><div className="font-extrabold text-sm">Autorizar máster operativo</div><div className="text-[10px] mb-2" style={{ color: T.choco2 }}>Elegí audio original o una pista vigente de la Biblioteca. La mezcla queda sellada y no publica.</div><label className="text-[9px] uppercase font-extrabold" style={{ color: T.choco2 }}>Audio del máster</label><select className={`${inputCls} mt-1`} style={inputStyle} value={audioByPackage[String(pkg.id)] || ""} onChange={(event) => setAudioByPackage((current) => ({ ...current, [String(pkg.id)]: event.target.value }))} disabled={!db.agencyPostproductionAudioReady}><option value="">Audio original de las tomas</option>{audioAssetsForPackage(pkg).map((asset) => <option key={asset.id} value={asset.id}>{asset.name}{asset.rightsExpiresAt ? ` · vence ${asset.rightsExpiresAt}` : " · sin vencimiento"}</option>)}</select>{!db.agencyPostproductionAudioReady && <div className="text-[9px] mt-1 font-bold" style={{ color: "#A66A00" }}>Aplicá audio-postproduccion-v1.sql para sellar la pista.</div>}</div><BtnAsync small onClick={() => authorizeExport(pkg)} disabled={!db.agencyPostproductionAudioReady}>Autorizar exportación</BtnAsync></div></article>)}
          {exportCenter.exports.map((item) => { const tone = statusTone(item.status); const evaluation = item.status === "Exportada" ? evaluatePostproductionMaster(item, item.outputAsset) : null; const audioLabel = item.audioBinding?.mode === "Biblioteca" ? ((db.brandMediaAssets || []).find((asset) => String(asset.id) === String(item.audioBinding.assetId))?.name || `Pista #${item.audioBinding.assetId}`) : "Audio original"; return <article key={item.id} className="rounded-2xl border p-3" style={{ borderColor: ["Fallida", "Incierta", "Rechazada"].includes(item.status) ? "#E9AAA0" : T.border, background: "#FFFDFC" }}><div className="flex items-start justify-between gap-2"><div><div className="text-[9px] uppercase font-extrabold" style={{ color: T.coral }}>Exportación #{item.id} · intento {item.attempts}</div><div className="font-extrabold text-sm">{item.package?.storyboard?.title || `Paquete #${item.packageId}`}</div></div><span className="rounded-full px-2 py-1 text-[9px] font-extrabold" style={{ background: tone.bg, color: tone.fg }}>{item.status}</span></div><div className="text-[10px] my-2" style={{ color: T.choco2 }}>{item.snapshot?.export_spec?.width}×{item.snapshot?.export_spec?.height} · {item.snapshot?.export_spec?.fps} FPS · {audioLabel} · huella {item.fingerprint?.slice(0, 8)}</div>{item.errorMessage && <div className="rounded-xl px-2.5 py-2 text-[10px] mb-2" style={{ background: "#F9D8D1", color: "#A03B2A" }}>{item.errorMessage}</div>}{item.status === "Autorizada" && <div className="rounded-xl px-2.5 py-2 text-[10px] font-bold" style={{ background: exportWorker?.ffmpegAvailable ? "#DDEBD9" : "#FFF2D8", color: exportWorker?.ffmpegAvailable ? "#315B35" : "#7A5410" }}>{exportWorker?.ffmpegAvailable ? "En cola privada · worker FFmpeg disponible." : "En cola privada · activá el worker FFmpeg para procesarla."}</div>}{item.status === "Exportada" && <><div className="rounded-xl px-2.5 py-2 text-[10px] mb-2" style={{ background: evaluation?.approved ? "#DDEBD9" : "#F9D8D1", color: evaluation?.approved ? "#315B35" : "#A03B2A" }}>{evaluation?.approved ? "✓ Archivo y probe coinciden; falta decisión humana." : `× ${evaluation?.reasons?.[0] || "No supera el QA técnico."}`}</div><div className="flex gap-2"><BtnAsync small confirmar disabled={!evaluation?.approved} onClick={() => resolveMaster(item, "Aprobar")}>Aprobar máster</BtnAsync><BtnAsync small kind="ghost" onClick={() => resolveMaster(item, "Rechazar")}>Rechazar</BtnAsync></div></>}{item.status === "Fallida" && <BtnAsync small kind="ghost" onClick={() => retryExport(item)}>Reintentar fallo definitivo</BtnAsync>}{item.status === "Incierta" && <div className="text-[10px] font-extrabold" style={{ color: "#A03B2A" }}>Bloqueada: conciliar antes de cualquier reenvío.</div>}</article>; })}
          {exportCenter.candidates.length === 0 && exportCenter.exports.length === 0 && <div className="p-2 text-sm" style={{ color: T.choco2 }}><b style={{ color: T.choco }}>Todavía no hay cortes listos para exportar.</b> Primero aprobá el paquete completo de postproducción.</div>}
        </div>}
      </div>
    </>}
    <div className="px-4 py-2.5 border-t text-[10px] font-semibold" style={{ borderColor: T.border, color: T.choco2 }}>El corte aprobado sigue separado de Distribución Comercial: no publica, no pauta y no gasta.</div>
    {reviewJob && <Modal title="Control de calidad de la toma" onClose={() => setReviewJob(null)} wide topLayer>
      <div className="rounded-2xl p-3 mb-3 text-xs" style={{ background: T.vainilla }}><b>Trabajo #{reviewJob.id} · salida #{reviewJob.outputAssetId}</b><br />Puntaje {evaluation.total}/22 · {evaluation.approved ? "cumple el umbral" : evaluation.reasons[0]}</div>
      {outputAsset?.url && (outputAsset.mediaType === "Video" ? <video src={outputAsset.url} controls className="w-full max-h-72 rounded-2xl bg-black mb-3" /> : <img src={outputAsset.url} alt={outputAsset.name} className="w-full max-h-72 object-contain rounded-2xl mb-3" />)}
      <div className="grid sm:grid-cols-2 gap-2">{AGENCY_QUALITY_CRITERIA.map((criterion) => <Field key={criterion.key} label={`${criterion.label}${criterion.critical ? " · crítica" : ""}`}><Select options={["0 · falla", "1 · deriva menor", "2 · exacto"]} value={`${scores[criterion.key]} · ${scores[criterion.key] === 0 ? "falla" : scores[criterion.key] === 1 ? "deriva menor" : "exacto"}`} onChange={(event) => setScores({ ...scores, [criterion.key]: Number(event.target.value.slice(0, 1)) })} /></Field>)}</div>
      {!evaluation.approved && <Field label="Tipo de corrección"><Select options={AGENCY_QUALITY_FAILURE_TYPES.filter((item) => item !== "Aprobada")} value={failureType} onChange={(event) => setFailureType(event.target.value)} /></Field>}
      <Field label="Continuidad observada"><textarea className={inputCls} style={inputStyle} rows="2" value={continuity} onChange={(event) => setContinuity(event.target.value)} /></Field>
      <Field label={evaluation.approved ? "Nota de aprobación" : "Qué debe corregirse"}><textarea className={inputCls} style={inputStyle} rows="3" value={note} onChange={(event) => setNote(event.target.value)} /></Field>
      <div className="flex gap-2"><BtnAsync confirmar onClick={saveQualityReview} disabled={continuity.trim().length < 3 || (!evaluation.approved && note.trim().length < 5)}>{evaluation.approved ? "Aprobar para postproducción" : `Sellar ${failureType.toLowerCase()}`}</BtnAsync><Btn kind="ghost" onClick={() => setReviewJob(null)}>Cancelar</Btn></div>
    </Modal>}
  </div>;
}

function AgencyMetaObservatory({ db, refrescar }) {
  const activePolicy = (db.agencyMetaPolicies || []).find((item) => item.status === "Activa");
  const center = useMemo(() => buildAgencyMetaCenter(db, activePolicy), [db, activePolicy]);
  const [expanded, setExpanded] = useState(null);
  const money = (value) => fmt(Math.round(Number(value || 0)));
  const percent = (value) => value == null ? "—" : `${Number(value).toFixed(2)}%`;

  async function prepare(snapshot) {
    await prepararDiagnosticoMeta(snapshot.id, "Diagnóstico determinístico preparado desde el Observatorio Meta para revisión humana.");
    toast("ok", "Diagnóstico 3Q preparado. No se publicó ni cambió presupuesto.");
    await refrescar();
  }

  async function resolve(diagnostic, decision) {
    const defaultNote = decision === "Aprobar"
      ? "Revisé hechos, atribución, píxel y acciones; no autorizo cambios de pauta."
      : "Devolver para corregir evidencia, denominadores o alcance del diagnóstico.";
    const note = window.prompt(decision === "Aprobar" ? "Nota de aprobación humana" : "¿Qué debe corregirse?", defaultNote) || "";
    if (note.trim().length < 8) return;
    await resolverDiagnosticoMeta(diagnostic.id, decision, note.trim());
    toast("ok", decision === "Aprobar" ? "Diagnóstico aprobado como lectura, sin ejecutar pauta." : "Diagnóstico devuelto con trazabilidad.");
    await refrescar();
  }

  return <section className="rounded-[26px] border overflow-hidden mb-6 shadow-sm" style={{ borderColor: T.border, background: T.surface }} aria-label="Resultados de Meta">
    <div className="p-4 sm:p-5 flex flex-col lg:flex-row lg:items-center justify-between gap-4 border-b" style={{ borderColor: T.border, background: T.surface, color: T.choco }}>
      <div className="flex items-start gap-3">
        <div className="w-11 h-11 rounded-2xl grid place-items-center text-xl shrink-0" style={{ background: "#E8F1E4" }}>◎</div>
        <div><div className="text-[9px] font-extrabold uppercase tracking-[.18em]" style={{ color: "#3F6B42" }}>Resultados de Meta</div><div className="display text-xl font-semibold">Qué funcionó y qué revisar</div><div className="text-xs max-w-2xl" style={{ color: T.choco2 }}>Cruza campañas, pedidos pagados y margen para convertir datos en decisiones comprensibles.</div></div>
      </div>
      <div className="grid grid-cols-2 sm:grid-cols-4 gap-2 shrink-0">
        {[["Lecturas",center.summary.snapshots],["Por revisar",center.summary.reviewing],["Alertas",center.summary.alerts],["Ingreso ligado",money(center.summary.linkedRevenue)]].map(([label,value]) => <div key={label} className="rounded-2xl border px-3 py-2 min-w-[82px] text-center" style={{ borderColor: T.border, background: T.vainilla }}><div className="display text-lg font-semibold">{value}</div><div className="text-[8px] uppercase font-extrabold" style={{ color: T.choco2 }}>{label}</div></div>)}
      </div>
    </div>
    {!db.agencyMetaReady ? <div className="px-4 py-4 text-sm font-bold" style={{ background: "#FFF2D8", color: "#7A5410" }}>Aplicá <code>observatorio-meta-v1.sql</code> después del Hito 36. Hasta entonces Meta no aporta señales al cerebro de Agencia.</div> : <>
      <div className="px-4 py-3 border-b flex flex-wrap items-center justify-between gap-2" style={{ borderColor: T.border, background: "#F4FAF1" }}>
        <div className="text-[11px]"><b>Política vigente:</b> {activePolicy ? `${activePolicy.sourceLabel} · V${activePolicy.version} · ${activePolicy.market} · ${activePolicy.currency}` : "sin política activa"}</div>
        <span className="rounded-full px-3 py-1 text-[9px] font-extrabold uppercase" style={{ background: "#DDEBD9", color: "#315B35" }}>Solo lectura · pauta protegida</span>
      </div>
      {center.snapshots.length === 0 ? <div className="px-4 py-5 text-sm" style={{ color: T.choco2 }}><b style={{ color: T.choco }}>Todavía no hay ventanas Meta.</b> El conector privado registrará snapshots inmutables; ninguna clave ni secreto vive en el navegador.</div> : <div className="p-3 grid xl:grid-cols-2 gap-3">
        {center.snapshots.slice(0, 8).map((snapshot) => {
          const preview = snapshot.preview || {}; const derived = preview.derived || {}; const diagnostic = snapshot.diagnostics?.[0];
          const open = expanded === snapshot.id; const catalogAlerts = (preview.catalogHypotheses || []).filter((item) => !item.eligible).length;
          const pixelAlerts = (preview.pixelHealth || []).filter((item) => item.alert).length;
          const tone = diagnostic?.status === "Aprobado" ? { bg: "#DDEBD9", fg: "#315B35" } : diagnostic?.status === "Devuelto" ? { bg: "#F6D4CD", fg: "#A03B2A" } : { bg: "#FFF2D8", fg: "#7A5410" };
          return <article key={snapshot.id} className="rounded-2xl border overflow-hidden momo-card-action" style={{ borderColor: open ? "#A8C5AD" : T.border, background: "#fff" }}>
            <button type="button" className="w-full text-left p-4 bg-transparent border-0" onClick={() => setExpanded(open ? null : snapshot.id)} aria-expanded={open}>
              <div className="flex items-start justify-between gap-3"><div><div className="text-[9px] uppercase tracking-wider font-extrabold" style={{ color: "#3F6B42" }}>{snapshot.entityType} · {snapshot.objective}</div><div className="display text-lg font-semibold">{snapshot.accountLabel || snapshot.accountExternalId}</div><div className="text-[10px]" style={{ color: T.choco2 }}>{snapshot.windowStart} → {snapshot.windowEnd} · {snapshot.currency}</div></div><div className="text-right"><div className="display text-xl font-semibold" style={{ color: T.coral }}>{derived.roas == null ? "—" : `${derived.roas}×`}</div><div className="text-[8px] uppercase font-extrabold" style={{ color: T.choco2 }}>ROAS atribuido</div></div></div>
              <div className="grid grid-cols-4 gap-2 mt-3">{[["Gasto",money(derived.spend)],["CTR",percent(derived.ctrPct)],["Pedidos MOMOS",snapshot.localTruth?.paidOrders || 0],["Alertas",pixelAlerts + catalogAlerts]].map(([label,value]) => <div key={label} className="rounded-xl px-2 py-2" style={{ background: "#FAF4EC" }}><div className="font-extrabold text-xs">{value}</div><div className="text-[8px] uppercase font-bold" style={{ color: T.choco2 }}>{label}</div></div>)}</div>
            </button>
            {open && <div className="px-4 pb-4 border-t" style={{ borderColor: T.border, background: "#FFFCF8" }}>
              <div className="grid sm:grid-cols-3 gap-2 my-3">{[["Meta atribuye",money(preview.whatHappened?.metaAttributedRevenue)],["MOMOS pagado",money(snapshot.localTruth?.paidRevenue)],["Brecha atribuida",money(preview.whatHappened?.attributionGap)]].map(([label,value]) => <div key={label} className="rounded-xl border p-2.5" style={{ borderColor: T.border }}><div className="text-[9px] uppercase font-extrabold" style={{ color: T.choco2 }}>{label}</div><div className="font-extrabold">{value}</div></div>)}</div>
              <div className="rounded-xl px-3 py-2 text-[10px] mb-3" style={{ background: "#E5EEF7", color: "#315A7D" }}><b>Atribución no es causalidad.</b> Meta aporta una lectura; pedidos pagados y margen vienen de MOMOS OPS.</div>
              <div className="grid sm:grid-cols-2 gap-3">
                <div><div className="text-[9px] uppercase font-extrabold mb-1" style={{ color: T.coral }}>Por qué podría pasar</div>{(preview.whyHypotheses || []).length ? preview.whyHypotheses.slice(0, 3).map((item, index) => <div key={`${item.signal}-${index}`} className="text-[10px] mb-1">• <b>{item.signal}:</b> {item.interpretation}</div>) : <div className="text-[10px]" style={{ color: T.choco2 }}>Sin hipótesis concluyentes en esta ventana.</div>}</div>
                <div><div className="text-[9px] uppercase font-extrabold mb-1" style={{ color: T.coral }}>Qué revisaríamos</div>{(preview.recommendedActions || []).slice(0, 3).map((item, index) => <div key={`${item.action}-${index}`} className="text-[10px] mb-1">• {item.action}</div>)}</div>
              </div>
              <div className="mt-3 flex flex-wrap items-center gap-2">{diagnostic ? <><span className="rounded-full px-2.5 py-1 text-[9px] font-extrabold" style={{ background: tone.bg, color: tone.fg }}>{diagnostic.status} · confianza {diagnostic.confidence}</span>{diagnostic.status === "En revisión" && <><BtnAsync small confirmar onClick={() => resolve(diagnostic, "Aprobar")}>Aprobar lectura</BtnAsync><BtnAsync small kind="ghost" onClick={() => resolve(diagnostic, "Devolver")}>Devolver</BtnAsync></>}</> : <BtnAsync small onClick={() => prepare(snapshot)}>Preparar diagnóstico 3Q</BtnAsync>}</div>
            </div>}
          </article>;
        })}
      </div>}
    </>}
    <div className="px-4 py-2.5 border-t text-[10px] font-semibold" style={{ borderColor: T.border, color: T.choco2 }}>Este panel no crea campañas, no cambia presupuesto, no pausa, no escala y no publica. Cada acción externa conserva contrato y aprobación específicos.</div>
  </section>;
}

function AgencyMetaIncrementality({ db, refrescar }) {
  const center = useMemo(() => buildMetaIncrementalityCenter(db), [db]);
  const money = (value) => fmt(Math.round(Number(value || 0)));

  async function createStudy(diagnostic) {
    const snapshot = (db.agencyMetaSnapshots || []).find((item) => String(item.id) === String(diagnostic.snapshotId));
    if (!snapshot?.localCampaignId) throw new Error("El diagnóstico debe provenir de una campaña local exacta.");
    const externalStudyId = window.prompt("ID del estudio Meta Conversion Lift", `META-LIFT-${snapshot.localCampaignId}`) || "";
    if (externalStudyId.trim().length < 3) return;
    const payload = liftStudyPayload({ studyKey: `meta-lift-${diagnostic.id}-${Date.now()}`, diagnosticId: diagnostic.id,
      design: "Meta Conversion Lift", lifecycleScope: "Todos", windowStart: snapshot.windowStart, windowEnd: snapshot.windowEnd,
      minimumPerArm: 100, randomized: true, externalStudyId: externalStudyId.trim(), assignmentMethod: "Meta Conversion Lift",
      hypothesis: "La campaña aumenta compradores pagados y beneficio frente al control aleatorio." });
    await crearEstudioIncrementalMeta(payload);
    toast("ok", "Diseño incremental preparado para revisión; no se modificó la pauta.");
    await refrescar();
  }

  async function resolveStudy(study, decision) {
    const note = window.prompt(decision === "Aprobar" ? "Nota de revisión del diseño" : "¿Qué debe corregirse?",
      decision === "Aprobar" ? "Revisé aleatorización, ventana, muestra y alcance del estudio." : "Corregir diseño, asignación o ventana antes de medir.") || "";
    if (note.trim().length < 8) return;
    await resolverEstudioIncrementalMeta(study.id, decision, note.trim());
    toast("ok", decision === "Aprobar" ? "Estudio diseñado; espera medición privada del conector." : "Estudio devuelto con trazabilidad.");
    await refrescar();
  }

  async function resolveMeasurement(measurement, decision) {
    const note = window.prompt("Nota de revisión humana", decision === "Aprobar"
      ? "Revisé muestra, aleatorización, ciclo de vida, margen y alcance causal."
      : decision === "Inconclusa" ? "La evidencia no permite una decisión causal todavía." : "Corregir la medición o su evidencia externa.") || "";
    if (note.trim().length < 8) return;
    await resolverMedicionIncrementalMeta(measurement.id, decision, note.trim());
    toast("ok", "Resultado revisado sin cambiar presupuesto, publicación ni pauta.");
    await refrescar();
  }

  return <section className="rounded-[26px] border overflow-hidden mb-6 shadow-sm" style={{ borderColor: "#D7C5B2", background: "#FFFDFC" }} aria-label="Medición incremental Meta">
    <div className="p-4 sm:p-5 flex flex-col lg:flex-row lg:items-center justify-between gap-4" style={{ background: "linear-gradient(135deg,#3D315B,#5B4779 62%,#80679B)", color: "#fff" }}>
      <div className="flex items-start gap-3"><div className="w-11 h-11 rounded-2xl grid place-items-center text-xl shrink-0" style={{ background: "rgba(255,255,255,.14)" }}>⇄</div>
        <div><div className="text-[9px] font-extrabold uppercase tracking-[.18em] opacity-75">Control vs. expuesto · nuevos vs. recurrentes</div><div className="display text-xl font-semibold">Incrementalidad Meta</div>
          <div className="text-xs opacity-85 max-w-2xl">Mide compradores y beneficio que no habrían ocurrido sin la campaña. Exige aleatorización, muestra suficiente y revisión humana.</div></div></div>
      <div className="grid grid-cols-2 sm:grid-cols-4 gap-2 shrink-0">{[["Estudios",center.summary.studies],["En revisión",center.summary.reviewing],["Causales",center.summary.causal],["Beneficio",money(center.summary.profit)]].map(([label,value]) => <div key={label} className="rounded-2xl px-3 py-2 min-w-[82px] text-center" style={{ background: "rgba(255,255,255,.12)" }}><div className="display text-lg font-semibold">{value}</div><div className="text-[8px] uppercase font-extrabold opacity-70">{label}</div></div>)}</div>
    </div>
    {!db.agencyMetaIncrementalityReady ? <div className="px-4 py-4 text-sm font-bold" style={{ background: "#FFF2D8", color: "#7A5410" }}>Aplicá <code>incrementalidad-meta-v1.sql</code> después del Hito 37. El Observatorio seguirá funcionando mientras tanto.</div> : <>
      {center.candidates.length > 0 && <div className="p-3 border-b" style={{ borderColor: T.border, background: "#F7F2FB" }}><div className="text-[9px] uppercase font-extrabold mb-2" style={{ color: "#5B4779" }}>Lecturas aprobadas listas para diseñar prueba</div><div className="grid lg:grid-cols-2 gap-2">{center.candidates.slice(0, 4).map((diagnostic) => {
        const snapshot = (db.agencyMetaSnapshots || []).find((item) => String(item.id) === String(diagnostic.snapshotId));
        return <article key={diagnostic.id} className="rounded-2xl border bg-white p-3 flex items-center gap-3" style={{ borderColor: "#D9CBE5" }}><div className="flex-1"><div className="text-[9px] uppercase font-extrabold" style={{ color: "#5B4779" }}>Diagnóstico #{diagnostic.id} · confianza {diagnostic.confidence}</div><div className="font-extrabold text-sm">{snapshot?.accountLabel || snapshot?.accountExternalId || "Ventana Meta"}</div><div className="text-[10px]" style={{ color: T.choco2 }}>Campaña {snapshot?.localCampaignId || "sin vínculo"} · atribución todavía no causal</div></div><BtnAsync small onClick={() => createStudy(diagnostic)} disabled={!snapshot?.localCampaignId}>Diseñar lift</BtnAsync></article>;
      })}</div></div>}
      {center.studies.length === 0 ? <div className="px-4 py-5 text-sm" style={{ color: T.choco2 }}><b style={{ color: T.choco }}>Aún no hay estudios.</b> Primero aprobá una lectura del Observatorio ligada a una campaña exacta.</div> : <div className="p-3 grid xl:grid-cols-2 gap-3">{center.studies.slice(0, 8).map((study) => <article key={study.id} className="rounded-2xl border p-4" style={{ borderColor: "#D9CBE5", background: "#FFFCFF" }}>
        <div className="flex items-start justify-between gap-3"><div><div className="text-[9px] uppercase tracking-wider font-extrabold" style={{ color: "#5B4779" }}>{study.design} · {study.lifecycleScope}</div><div className="display text-lg font-semibold">Campaña {study.campaignId}</div><div className="text-[10px]" style={{ color: T.choco2 }}>{study.windowStart} → {study.windowEnd} · mínimo {study.minimumPerArm} por brazo</div></div><span className="rounded-full px-2.5 py-1 text-[9px] font-extrabold" style={{ background: study.status === "Cerrado" ? "#DDEBD9" : study.status === "Devuelto" ? "#F6D4CD" : "#EEE5F4", color: study.status === "Devuelto" ? "#A03B2A" : "#5B4779" }}>{study.status}</span></div>
        <div className="rounded-xl px-3 py-2 text-[10px] my-3" style={{ background: "#F7F0E3" }}><b>Hipótesis:</b> {study.hypothesis}</div>
        {study.status === "En revisión" && <div className="flex gap-2 mb-3"><BtnAsync small confirmar onClick={() => resolveStudy(study, "Aprobar")}>Aprobar diseño</BtnAsync><BtnAsync small kind="ghost" onClick={() => resolveStudy(study, "Devolver")}>Devolver</BtnAsync></div>}
        {study.measurements.length === 0 ? <div className="text-[10px]" style={{ color: T.choco2 }}>{study.status === "Diseñado" ? "Esperando resultado agregado del conector privado de Meta." : "Todavía no existe una medición sellada."}</div> : study.measurements.slice(0, 2).map((measurement) => { const result = measurement.result || {}; return <div key={measurement.id} className="rounded-2xl border p-3 mt-2" style={{ borderColor: result.causalClaimAllowed ? "#A8C5AD" : "#E8C98B", background: result.causalClaimAllowed ? "#F4FAF1" : "#FFF8E9" }}>
          <div className="flex items-start justify-between gap-2"><div><div className="text-[9px] uppercase font-extrabold">Resultado · {result.classification || "En revisión"}</div><div className="font-extrabold text-sm">{result.controlRatePct}% control → {result.exposedRatePct}% expuesto</div></div><div className="text-right"><div className="display text-lg font-semibold" style={{ color: Number(result.incrementalProfit) >= 0 ? "#315B35" : "#A03B2A" }}>{money(result.incrementalProfit)}</div><div className="text-[8px] uppercase font-extrabold">beneficio incremental</div></div></div>
          <div className="grid grid-cols-3 gap-2 my-2">{[["Lift",result.liftPct == null ? "—" : `${result.liftPct}%`],["Muestra",result.sampleSufficient ? "Suficiente" : "Insuficiente"],["Causal",result.causalClaimAllowed ? "Sí" : "No"]].map(([label,value]) => <div key={label} className="rounded-xl bg-white px-2 py-1.5"><div className="text-[10px] font-extrabold">{value}</div><div className="text-[8px] uppercase">{label}</div></div>)}</div>
          {measurement.status === "En revisión" && <div className="flex flex-wrap gap-2"><BtnAsync small confirmar onClick={() => resolveMeasurement(measurement, "Aprobar")} disabled={!result.sampleSufficient}>Aprobar lectura</BtnAsync><BtnAsync small kind="ghost" onClick={() => resolveMeasurement(measurement, "Inconclusa")}>Marcar inconclusa</BtnAsync><BtnAsync small kind="ghost" onClick={() => resolveMeasurement(measurement, "Devolver")}>Devolver</BtnAsync></div>}
        </div>; })}
      </article>)}</div>}
    </>}
    <div className="px-4 py-2.5 border-t text-[10px] font-semibold" style={{ borderColor: T.border, color: T.choco2 }}>Una correlación o atribución nunca se presenta como causalidad. Este módulo no crea campañas, no cambia audiencias o presupuesto y no publica.</div>
  </section>;
}

function AgencyMetaInvestmentScenarios({ db, refrescar }) {
  const center = useMemo(() => buildMetaInvestmentCenter(db), [db]);
  const money = (value) => fmt(Math.round(Number(value || 0)));

  async function createScenario(measurement) {
    const payload = investmentScenarioPayload(measurement, 7);
    await crearEscenariosInversionMeta(payload);
    toast("ok", "Cuatro escenarios preparados con datos actuales; no se cambió la pauta.");
    await refrescar();
  }

  async function reviewScenario(scenario, decision) {
    const defaults = decision === "Aprobar"
      ? "Revisé beneficio incremental, inventario, capacidad, ciclo de vida y límites."
      : decision === "Devolver" ? "Actualizar evidencia operativa o supuestos antes de decidir."
        : "Descartado por decisión humana; no debe ejecutarse.";
    const note = window.prompt("Nota obligatoria de revisión humana", defaults) || "";
    if (note.trim().length < 8) return;
    await resolverEscenariosInversionMeta(scenario.id, decision, note.trim());
    toast("ok", `${decision}: la revisión quedó registrada sin ejecutar cambios.`);
    await refrescar();
  }

  return <section className="rounded-[26px] border overflow-hidden mb-6 shadow-sm" style={{ borderColor: T.border, background: T.surface }} aria-label="Opciones de inversión Meta">
    <div className="p-4 sm:p-5 flex flex-col lg:flex-row lg:items-center justify-between gap-4 border-b" style={{ borderColor: T.border, background: T.surface, color: T.choco }}>
      <div className="flex items-start gap-3"><div className="w-11 h-11 rounded-2xl grid place-items-center text-xl shrink-0" style={{ background: "#E5EEF7" }}>◫</div>
        <div><div className="text-[9px] font-extrabold uppercase tracking-[.18em]" style={{ color: "#315A7D" }}>Opciones para crecer</div><div className="display text-xl font-semibold">Comparar antes de invertir</div>
          <div className="text-xs max-w-2xl" style={{ color: T.choco2 }}>MOMOS compara alternativas para que el equipo elija. Nunca cambia la pauta automáticamente.</div></div></div>
      <div className="grid grid-cols-2 sm:grid-cols-4 gap-2 shrink-0">{[["Opciones",center.summary.scenarios],["Por revisar",center.summary.reviewing],["Aprobadas",center.summary.approved],["Con alertas",center.summary.blocked]].map(([label,value]) => <div key={label} className="rounded-2xl border px-3 py-2 min-w-[82px] text-center" style={{ borderColor: T.border, background: T.vainilla }}><div className="display text-lg font-semibold">{value}</div><div className="text-[8px] uppercase font-extrabold" style={{ color: T.choco2 }}>{label}</div></div>)}</div>
    </div>
    {!db.agencyMetaInvestmentReady ? <div className="px-4 py-4 text-sm font-bold" style={{ background: "#FFF2D8", color: "#7A5410" }}>Aplicá <code>escenarios-inversion-meta-v1.sql</code> después del Hito 38. La medición incremental seguirá disponible.</div> : <>
      {center.candidates.length > 0 && <div className="p-3 border-b" style={{ borderColor: T.border, background: "#EEF5F7" }}><div className="text-[9px] uppercase font-extrabold mb-2" style={{ color: "#245777" }}>Mediciones aprobadas listas para comparar</div><div className="grid lg:grid-cols-2 gap-2">{center.candidates.slice(0, 4).map((measurement) => <article key={measurement.id} className="rounded-2xl border bg-white p-3 flex items-center gap-3" style={{ borderColor: "#C9D9E2" }}><div className="flex-1"><div className="text-[9px] uppercase font-extrabold" style={{ color: "#245777" }}>Medición causal #{measurement.id}</div><div className="font-extrabold text-sm">Beneficio incremental {money(measurement.result?.incrementalProfit)}</div><div className="text-[10px]" style={{ color: T.choco2 }}>Horizonte operativo sugerido: 7 días · revisión humana obligatoria</div></div><BtnAsync small onClick={() => createScenario(measurement)}>Comparar 4 opciones</BtnAsync></article>)}</div></div>}
      {center.scenarios.length === 0 ? <div className="px-4 py-5 text-sm" style={{ color: T.choco2 }}><b style={{ color: T.choco }}>Aún no hay escenarios.</b> Primero aprobá una medición incremental con muestra suficiente.</div> : <div className="p-3 grid xl:grid-cols-2 gap-3">{center.scenarios.slice(0, 10).map((scenario) => {
        const evidence = scenario.evidence || {}; const operations = evidence.operations || {}; const product = evidence.product || {}; const campaign = evidence.campaign || {};
        return <article key={scenario.id} className="rounded-2xl border overflow-hidden" style={{ borderColor: scenario.status === "En revisión" ? "#9FBAC8" : T.border, background: "#FFFEFC" }}>
          <div className="p-4"><div className="flex items-start justify-between gap-3"><div><div className="text-[9px] uppercase font-extrabold tracking-wider" style={{ color: "#245777" }}>Campaña {campaign.name || scenario.campaignId} · {scenario.horizonDays} días</div><div className="display text-lg font-semibold">{product.name || "Producto foco sin identificar"}</div><div className="text-[10px]" style={{ color: T.choco2 }}>Recomendación del modelo: <b>{scenario.recommendedOption}</b> · evidencia sellada</div></div><span className="rounded-full px-2.5 py-1 text-[9px] font-extrabold" style={{ background: scenario.status === "Aprobado" ? "#DDEBD9" : scenario.status === "En revisión" ? "#DDEAF0" : "#F3E6DD", color: scenario.status === "Aprobado" ? "#315B35" : "#245777" }}>{scenario.status}</span></div>
            <div className="grid grid-cols-3 sm:grid-cols-6 gap-1.5 my-3">{[["Exacto",operations.exactAvailable],["En proceso",operations.inProcess],["Reservado",operations.reservations],["Vence pronto",operations.expiringSoon],["Cola cocina",operations.kitchenQueue],["Pendiente",operations.pendingProduction]].map(([label,value]) => <div key={label} className="rounded-xl px-2 py-2" style={{ background: "#F4F7F8" }}><div className="text-xs font-extrabold">{Number(value || 0)}</div><div className="text-[7px] uppercase font-bold" style={{ color: T.choco2 }}>{label}</div></div>)}</div>
            {evidence.stockBlocked && <div className="rounded-xl px-3 py-2 mb-3 text-[10px] font-bold" style={{ background: "#F9D8D1", color: "#A03B2A" }}>Stock operativo bloqueado: no se recomienda ampliar exposición.</div>}
            <div className="grid sm:grid-cols-2 gap-2">{(scenario.options || []).map((option) => { const recommended = option.key === scenario.recommendedOption; const projection = option.projection || {}; return <div key={option.key} className="rounded-2xl border p-3" style={{ borderColor: recommended ? "#4B8798" : T.border, background: recommended ? "#EEF7F8" : "#fff" }}><div className="flex items-start justify-between gap-2"><div><div className="font-extrabold text-sm">{option.key}</div><div className="text-[9px]" style={{ color: T.choco2 }}>{option.purpose}</div></div>{recommended && <span className="rounded-full px-2 py-1 text-[8px] font-extrabold" style={{ background: "#245777", color: "#fff" }}>SUGERIDA</span>}</div><div className="grid grid-cols-2 gap-2 my-2"><div><div className="font-extrabold text-sm">{money(option.proposedBudget)}</div><div className="text-[8px] uppercase">presupuesto simulado</div></div><div><div className="font-extrabold text-sm">{Number(option.deltaPct || 0)}%</div><div className="text-[8px] uppercase">variación</div></div></div><div className="text-[9px] rounded-lg px-2 py-1.5" style={{ background: "#FAF4EC" }}>Beneficio proyectado: {money(projection.low)} — <b>{money(projection.base)}</b> — {money(projection.high)}</div>{(option.blockers || []).slice(0, 2).map((blocker) => <div key={blocker} className="text-[9px] mt-1" style={{ color: "#A03B2A" }}>• {blocker}</div>)}</div>; })}</div>
            {scenario.status === "En revisión" && <div className="flex flex-wrap gap-2 mt-3"><BtnAsync small confirmar onClick={() => reviewScenario(scenario, "Aprobar")}>Aprobar lectura</BtnAsync><BtnAsync small kind="ghost" onClick={() => reviewScenario(scenario, "Devolver")}>Devolver</BtnAsync><BtnAsync small kind="ghost" onClick={() => reviewScenario(scenario, "Descartar")}>Descartar</BtnAsync></div>}
          </div>
        </article>;
      })}</div>}
    </>}
    <div className="px-4 py-2.5 border-t text-[10px] font-semibold" style={{ borderColor: T.border, color: T.choco2 }}>Aprobar una lectura no ejecuta nada: no cambia presupuesto, audiencia, campaña o publicación. La ejecución requiere otro contrato y otra aprobación.</div>
  </section>;
}

function AgencyMetaAuthorizationPanel({ db, refrescar }) {
  const center = useMemo(() => buildMetaAuthorizationCenter(db), [db]);
  const connector = useMemo(() => buildMetaConnectorCenter(db), [db]);
  const money = (value) => fmt(Math.round(Number(value || 0)));

  async function requestAuthorization(scenario, optionKey) {
    const audienceExternalId = window.prompt("ID exacto de la audiencia Meta", "aud_momos_principal") || "";
    if (!audienceExternalId.trim()) return;
    const validMinutes = Number(window.prompt("Vigencia de esta autorización (10 a 120 minutos)", "60") || 0);
    const justification = window.prompt("Justificación humana obligatoria", `Autorizar ${optionKey} para la campaña exacta, con presupuesto y audiencia sellados.`) || "";
    const payload = metaAuthorizationPayload({ scenario, optionKey, audienceExternalId, validMinutes, justification,
      settings: { campaignBudgetLimit: db.agencySettings?.campaignBudgetLimit, paused: db.agencySettings?.paused } });
    await solicitarAutorizacionInversionMeta(payload);
    toast("ok", "Solicitud sellada para revisión. Todavía no cambió ninguna campaña.");
    await refrescar();
  }

  async function reviewAuthorization(authorization, decision) {
    const suggested = decision === "Autorizar"
      ? "Verifiqué campaña, audiencia, presupuesto, vigencia y evidencia operativa."
      : decision === "Devolver" ? "Corregir el alcance o la evidencia antes de autorizar." : "No corresponde ejecutar esta alternativa.";
    const note = window.prompt("Nota de revisión humana", suggested) || "";
    if (note.trim().length < 16) return;
    await resolverAutorizacionInversionMeta(authorization.id, decision, note.trim());
    toast("ok", decision === "Autorizar" ? "Autorización vigente creada para simulación privada; no se tocó Meta." : `${decision} registrada con trazabilidad.`);
    await refrescar();
  }

  async function revokeAuthorization(authorization) {
    const reason = window.prompt("Motivo de revocación", "La autorización ya no corresponde al momento comercial actual.") || "";
    if (reason.trim().length < 16) return;
    await revocarAutorizacionInversionMeta(authorization.id, reason.trim());
    toast("ok", "Autorización revocada; cualquier simulación pendiente quedó cerrada.");
    await refrescar();
  }

  async function prepareMetaVerification(authorization) {
    if (!db.agencyMetaConnectorReady) throw new Error("Aplicá primero meta-conector-dry-run-v1.sql.");
    const storedAccount = (db.agencyIntegrations || []).find((item) => item.provider === "Meta")?.externalAccountId || "act_";
    const accountId = window.prompt("Cuenta publicitaria exacta de Meta (act_...)", storedAccount) || "";
    if (!accountId.trim()) return;
    const apiVersion = window.prompt("Versión Graph API sellada para esta verificación", "v25.0") || "";
    if (!apiVersion.trim()) return;
    await prepararDryRunMeta(authorization.id, accountId.trim(), apiVersion.trim());
    toast("ok", "Verificación oficial preparada: el worker solo hará tres lecturas GET y no cambiará la campaña.");
    await refrescar();
  }

  const statusStyle = (status) => status === "Autorizada" ? { background: "#DDEBD9", color: "#315B35" }
    : status === "En revisión" ? { background: "#FBE8C8", color: "#8B5A08" }
      : status === "Incierta" ? { background: "#F6D4CD", color: "#A03B2A" }
        : { background: "#F1E7E0", color: T.choco2 };

  return <section className="rounded-[26px] border overflow-hidden mb-6 shadow-sm" style={{ borderColor: "#D4B9C4", background: "#FFFDFC" }} aria-label="Autorización de inversión Meta">
    <div className="p-4 sm:p-5 flex flex-col lg:flex-row lg:items-center justify-between gap-4" style={{ background: "linear-gradient(135deg,#4C2637,#74384D 58%,#A35569)", color: "#fff" }}>
      <div className="flex items-start gap-3"><div className="w-11 h-11 rounded-2xl grid place-items-center text-xl shrink-0" style={{ background: "rgba(255,255,255,.14)" }}>✓</div>
        <div><div className="text-[9px] font-extrabold uppercase tracking-[.18em] opacity-75">Doble aprobación · alcance exacto · vigencia corta</div><div className="display text-xl font-semibold">Autorización de inversión Meta</div>
          <div className="text-xs opacity-85 max-w-2xl">H40 sella el permiso humano y H41 verifica cuenta, campaña y audiencia por Graph API. Es una comprobación oficial de solo lectura: nunca modifica pauta.</div></div></div>
      <div className="grid grid-cols-2 sm:grid-cols-4 gap-2 shrink-0">{[["Solicitudes",center.summary.requests],["En revisión",center.summary.reviewing],["Autorizadas",center.summary.authorized],["Inciertas",center.summary.uncertain]].map(([label,value]) => <div key={label} className="rounded-2xl px-3 py-2 min-w-[82px] text-center" style={{ background: "rgba(255,255,255,.12)" }}><div className="display text-lg font-semibold">{value}</div><div className="text-[8px] uppercase font-extrabold opacity-70">{label}</div></div>)}</div>
    </div>
    {!db.agencyMetaAuthorizationReady ? <div className="px-4 py-4 text-sm font-bold" style={{ background: "#FFF2D8", color: "#7A5410" }}>Aplicá <code>autorizacion-inversion-meta-v1.sql</code> después del Hito 39. Los escenarios seguirán disponibles sin permisos de ejecución.</div> : <>
      {center.candidates.length > 0 && <div className="p-3 border-b" style={{ borderColor: T.border, background: "#FBF1F4" }}><div className="text-[9px] uppercase font-extrabold mb-2" style={{ color: "#74384D" }}>Escenarios aprobados que todavía no tienen autorización</div><div className="grid xl:grid-cols-2 gap-3">{center.candidates.slice(0, 6).map((scenario) => <article key={scenario.id} className="rounded-2xl border bg-white p-3" style={{ borderColor: "#E0CAD2" }}>
        <div className="flex items-start justify-between gap-3 mb-2"><div><div className="text-[9px] uppercase font-extrabold" style={{ color: "#74384D" }}>Escenario #{scenario.id} · campaña {scenario.campaignId}</div><div className="font-extrabold text-sm">Elegí exactamente qué alternativa solicitar</div></div><span className="rounded-full px-2 py-1 text-[8px] font-extrabold" style={{ background: "#DDEBD9", color: "#315B35" }}>LECTURA APROBADA</span></div>
        <div className="grid grid-cols-2 sm:grid-cols-4 gap-2">{(scenario.options || []).map((option) => { const blocked = (option.blockers || []).length > 0 || (scenario.evidence?.stockBlocked && option.key !== "Reducir"); return <button key={option.key} type="button" disabled={blocked} title={blocked ? (option.blockers || []).join(" ") || "Bloqueada por stock" : `Solicitar ${option.key}`} onClick={() => requestAuthorization(scenario, option.key)} className="rounded-xl border px-2 py-2 text-left disabled:opacity-40" style={{ borderColor: option.key === scenario.recommendedOption ? "#A35569" : T.border, background: option.key === scenario.recommendedOption ? "#FFF2F5" : "#fff" }}><div className="text-[10px] font-extrabold">{option.key}</div><div className="text-[9px]">{money(option.proposedBudget)}</div></button>; })}</div>
        {scenario.evidence?.stockBlocked && <div className="text-[9px] mt-2 font-bold" style={{ color: "#A03B2A" }}>Sin stock operativo, la guarda solo permite solicitar Reducir.</div>}
      </article>)}</div></div>}
      {center.authorizations.length === 0 ? <div className="px-4 py-5 text-sm" style={{ color: T.choco2 }}><b style={{ color: T.choco }}>No hay permisos solicitados.</b> La aprobación analítica del Hito 39 no autoriza inversión por sí sola.</div> : <div className="p-3 grid xl:grid-cols-2 gap-3">{center.authorizations.slice(0, 12).map((authorization) => { const dryRun = connector.dryRuns.find((item) => String(item.authorizationId) === String(authorization.id)); return <article key={authorization.id} className="rounded-2xl border p-4" style={{ borderColor: authorization.status === "Incierta" || dryRun?.status === "Incierto" ? "#D88A7C" : "#E0CAD2", background: "#FFFCFD" }}>
        <div className="flex items-start justify-between gap-3"><div><div className="text-[9px] uppercase tracking-wider font-extrabold" style={{ color: "#74384D" }}>Campaña {authorization.campaignId} · audiencia {authorization.audienceExternalId}</div><div className="display text-lg font-semibold">{authorization.selectedOption} · {money(authorization.targetBudget)}</div><div className="text-[10px]" style={{ color: T.choco2 }}>Contrato #{authorization.id} · {authorization.executionMode} · vence {authorization.validUntil || "sin fecha"}</div></div><span className="rounded-full px-2.5 py-1 text-[9px] font-extrabold" style={statusStyle(authorization.status)}>{authorization.status}</span></div>
        <div className="rounded-xl px-3 py-2 text-[10px] my-3" style={{ background: "#F7F0E3" }}><b>Razón:</b> {authorization.justification}</div>
        {authorization.job && <div className="rounded-xl px-3 py-2 text-[10px] mb-3" style={{ background: authorization.job.status === "Incierto" ? "#F9D8D1" : "#EEF3F7" }}><b>Ensayo privado:</b> {authorization.job.status} · intento {authorization.job.attempt}{authorization.job.errorMessage ? ` · ${authorization.job.errorMessage}` : ""}</div>}
        {dryRun && <div className="rounded-xl px-3 py-2 text-[10px] mb-3" style={{ background: dryRun.status === "Conciliado" ? "#E5F1E1" : ["Divergente","Fallido","Incierto"].includes(dryRun.status) ? "#F9D8D1" : "#EEF3F7" }}><div className="font-extrabold">◎ Verificación oficial: {dryRun.status}</div><div>{dryRun.adAccountId} · {dryRun.apiVersion} · solo GET</div>{dryRun.status === "Conciliado" && <div>Cuenta, campaña y audiencia coinciden · cero mutaciones.</div>}{dryRun.errorMessage && <div>{dryRun.errorMessage}</div>}</div>}
        {authorization.status === "En revisión" && <div className="flex flex-wrap gap-2"><BtnAsync small confirmar onClick={() => reviewAuthorization(authorization, "Autorizar")}>Autorizar simulación</BtnAsync><BtnAsync small kind="ghost" onClick={() => reviewAuthorization(authorization, "Devolver")}>Devolver</BtnAsync><BtnAsync small kind="ghost" onClick={() => reviewAuthorization(authorization, "Rechazar")}>Rechazar</BtnAsync></div>}
        {authorization.status === "Autorizada" && <div className="flex flex-wrap gap-2">{!dryRun && db.agencyMetaConnectorReady && <BtnAsync small confirmar onClick={() => prepareMetaVerification(authorization)}>Verificar en Meta</BtnAsync>}<BtnAsync small kind="ghost" onClick={() => revokeAuthorization(authorization)}>Revocar permiso</BtnAsync></div>}
      </article>; })}</div>}
    </>}
    {db.agencyMetaAuthorizationReady && !db.agencyMetaConnectorReady && <div className="px-4 py-3 text-xs font-bold" style={{ background: "#FFF2D8", color: "#7A5410" }}>El permiso humano ya está protegido. Aplicá <code>meta-conector-dry-run-v1.sql</code> para comprobar las identidades en Meta sin tocar campañas.</div>}
    <div className="px-4 py-2.5 border-t text-[10px] font-semibold" style={{ borderColor: T.border, color: T.choco2 }}>Una autorización o lectura incierta no se reintenta. H41 solo usa ads_read + appsecret_proof; ads_management, publicaciones y cambios de presupuesto permanecen prohibidos.</div>
  </section>;
}

function AgencyActionCenter({ db, go, refrescar }) {
  const center = useMemo(() => buildAgencyActionQueue(db.agencyActionQueue, db.agencyDecisions || []), [db.agencyActionQueue, db.agencyDecisions]);
  const [selected, setSelected] = useState(null);
  const [outcomeForm, setOutcomeForm] = useState(() => agencyOutcomeDefaults(null));
  const tone = (item) => item.blocked
    ? { border: "#E6B7AE", bg: "#FFF4F1", chip: "#F6D4CD", fg: "#A03B2A" }
    : item.humanActionRequired
      ? { border: "#E6C891", bg: "#FFFBF3", chip: "#FFF0CE", fg: "#8B5A08" }
      : { border: "#C7D8E8", bg: "#F5F9FD", chip: "#E5EEF7", fg: "#315A7D" };

  function openAction(item) {
    setOutcomeForm(agencyOutcomeDefaults(item));
    setSelected(item);
  }

  function navigateAction(item) {
    const destination = agencyActionDestination(item);
    setSelected(null);
    if (destination.module !== "Crecimiento") { go(destination.module); return; }
    window.setTimeout(() => document.getElementById(destination.anchor)?.scrollIntoView({ behavior: "smooth", block: "start" }), 0);
  }

  async function completeDecision() {
    if (!selected) return;
    const error = validateAgencyOutcome(outcomeForm, selected);
    if (error) throw new Error(error);
    await registrarResultadoAccionAgencia(agencyOutcomePayload(selected, outcomeForm));
    setSelected(null); toast("ok", `Resultado verificable de decisión #${selected.decisionId} registrado`); await refrescar();
  }

  return <section id="agency-action-center" className="rounded-[26px] border overflow-hidden mb-6 shadow-sm scroll-mt-24" style={{ borderColor: T.border, background: T.surface }}>
    <div className="p-4 sm:p-5 flex flex-col lg:flex-row lg:items-center justify-between gap-4 border-b" style={{ borderColor: T.border, background: T.surface, color: T.choco }}>
      <div className="flex items-start gap-3"><div className="w-11 h-11 rounded-2xl grid place-items-center text-xl shrink-0" style={{ background: T.coralSoft }}>🧭</div><div><div className="text-[9px] font-extrabold uppercase tracking-[.18em]" style={{ color: T.coral }}>Decisiones del equipo</div><div className="display text-xl font-semibold">Qué necesita tu aprobación</div><div className="text-xs max-w-2xl" style={{ color: T.choco2 }}>Una acción clara por decisión. MOMOS abre el lugar correcto y nunca publica, contacta o gasta por sí sola.</div></div></div>
      <div className="grid grid-cols-3 gap-2 shrink-0">{[["Acciones",center.summary.total],["Para vos",center.summary.human],["Con alertas",center.summary.blocked]].map(([label,value]) => <div key={label} className="rounded-2xl border px-3 py-2 min-w-[70px] text-center" style={{ borderColor: T.border, background: T.vainilla }}><div className="display text-lg font-semibold">{value}</div><div className="text-[8px] uppercase font-extrabold" style={{ color: T.choco2 }}>{label}</div></div>)}</div>
    </div>
    {!db.agencyActionQueueReady ? <div className="px-4 py-3 text-xs font-bold" style={{ background: "#FFF2D8", color: "#7A5410" }}>Aplicá <code>centro-acciones-agencia-v1.sql</code> para mostrar los siguientes pasos protegidos dentro de MOMO OPS.</div>
      : !center.allowed ? <div className="px-4 py-4 text-sm" style={{ color: T.choco2 }}>Tu rol no opera Agencia MOMOS; la bandeja permanece privada.</div>
        : center.items.length === 0 ? <div className="px-4 py-4 text-sm" style={{ color: T.choco2 }}><b style={{ color: T.choco }}>Bandeja al día.</b> No hay decisiones aprobadas esperando un siguiente paso.</div>
          : <div className="p-3 grid md:grid-cols-2 xl:grid-cols-3 gap-3">{center.items.slice(0, 9).map((item) => { const style = tone(item); return <article key={item.decisionId} className="rounded-2xl border p-4 flex flex-col" style={{ borderColor: style.border, background: style.bg }}>
            <div className="flex items-start justify-between gap-2"><div><div className="text-[9px] uppercase tracking-wider font-extrabold" style={{ color: T.coral }}>Decisión #{item.decisionId} · {item.decisionType}</div><div className="display text-base font-semibold mt-1">{item.title}</div></div><span className="rounded-full px-2 py-1 text-[8px] font-extrabold uppercase shrink-0" style={{ background: style.chip, color: style.fg }}>{item.riskLevel}</span></div>
            {item.rationale && <p className="text-[11px] leading-relaxed my-2 line-clamp-2" style={{ color: T.choco2 }}>{item.rationale}</p>}
            <div className="rounded-xl px-3 py-2.5 my-2" style={{ background: "rgba(255,255,255,.72)", borderLeft: `3px solid ${style.fg}` }}><div className="text-[8px] uppercase tracking-wider font-extrabold" style={{ color: style.fg }}>{item.stage} · {item.area}</div><div className="text-[11px] font-extrabold mt-0.5">{item.actionLabel}</div></div>
            {item.blocked && <div className="text-[10px] font-bold mb-2" style={{ color: "#A03B2A" }}>Protegida: {item.blockerCode || "requiere resolver un bloqueo"}</div>}
            <div className="mt-auto"><Btn small kind={item.blocked ? "ghost" : "primary"} disabled={!item.humanActionRequired && !item.blocked} onClick={() => openAction(item)}>{item.humanActionRequired || item.blocked ? "Revisar acción" : "En seguimiento del sistema"}</Btn></div>
          </article>; })}</div>}
    <div className="px-4 py-2.5 border-t text-[10px] font-semibold" style={{ borderColor: T.border, color: T.choco2 }}>La tarjeta navega; no marca la decisión como ejecutada. El resultado solo se registra después de completar el trabajo real.</div>
    {selected && <Modal title={`Decisión #${selected.decisionId} · ${selected.decisionType}`} onClose={() => setSelected(null)} topLayer>
      <div className="rounded-2xl p-4 mb-3" style={{ background: "#FFF8F1", border: `1px solid ${T.border}` }}><div className="text-[9px] uppercase tracking-wider font-extrabold" style={{ color: T.coral }}>{selected.stage} · {selected.area}</div><div className="display text-lg font-semibold mt-1">{selected.title}</div>{selected.rationale && <p className="text-xs mt-2 mb-0" style={{ color: T.choco2 }}>{selected.rationale}</p>}</div>
      <div className="rounded-2xl px-3 py-3 mb-3 text-sm font-bold" style={{ background: selected.blocked ? "#F6D4CD" : "#E8F1E4", color: selected.blocked ? "#A03B2A" : "#315B35" }}>{selected.actionLabel}</div>
      {selected.blocked && <div className="rounded-xl px-3 py-2 mb-3 text-xs font-bold" style={{ background: "#FFF2D8", color: "#7A5410" }}>Bloqueo protegido: {selected.blockerCode}. Esta pantalla no puede ejecutar cambios externos.</div>}
      <div className="flex flex-wrap gap-2 mb-4"><Btn onClick={() => navigateAction(selected)}>Abrir {selected.area}</Btn><Btn kind="ghost" onClick={() => setSelected(null)}>Cerrar</Btn></div>
      {!db.agencyActionOutcomesReady ? <div className="rounded-xl px-3 py-3 text-xs font-bold" style={{ background: "#FFF2D8", color: "#7A5410" }}>Aplicá <code>resultados-verificables-agencia-v1.sql</code> para cerrar esta acción con evidencia.</div> : <div className="rounded-2xl border p-4" style={{ borderColor: T.border, background: "#FFFCF9" }}>
        <div className="text-[9px] uppercase tracking-wider font-extrabold mb-1" style={{ color: T.coral }}>Después de hacer el trabajo</div>
        <div className="display text-base font-semibold mb-3">Cerrar con evidencia verificable</div>
        <div className="grid sm:grid-cols-2 gap-3">
          <label className="text-[10px] font-bold">Cómo terminó<select className="w-full mt-1 rounded-xl border px-3 py-2 bg-white" value={outcomeForm.completionStatus} onChange={(e) => setOutcomeForm((form) => ({ ...form, completionStatus: e.target.value }))}>{AGENCY_OUTCOME_STATUSES.map((value) => <option key={value}>{value}</option>)}</select></label>
          <label className="text-[10px] font-bold">Resultado observado<select className="w-full mt-1 rounded-xl border px-3 py-2 bg-white" value={outcomeForm.observedResult} onChange={(e) => setOutcomeForm((form) => ({ ...form, observedResult: e.target.value }))}>{AGENCY_OBSERVED_RESULTS.map((value) => <option key={value}>{value}</option>)}</select></label>
          <label className="text-[10px] font-bold">Tipo de evidencia<select className="w-full mt-1 rounded-xl border px-3 py-2 bg-white" value={outcomeForm.evidenceKind} onChange={(e) => setOutcomeForm((form) => ({ ...form, evidenceKind: e.target.value, evidenceId: e.target.value === "Ninguna" ? "" : form.evidenceId }))}>{AGENCY_EVIDENCE_KINDS.map((value) => <option key={value}>{value}</option>)}</select></label>
          <label className="text-[10px] font-bold">ID exacto de MOMO OPS<input className="w-full mt-1 rounded-xl border px-3 py-2 bg-white" value={outcomeForm.evidenceId} disabled={outcomeForm.evidenceKind === "Ninguna"} placeholder="Ej. L-046, P-1060 o CRE-01" onChange={(e) => setOutcomeForm((form) => ({ ...form, evidenceId: e.target.value }))} /></label>
          <label className="text-[10px] font-bold">Costo real COP<input type="number" min="0" className="w-full mt-1 rounded-xl border px-3 py-2 bg-white" value={outcomeForm.actualCost} onChange={(e) => setOutcomeForm((form) => ({ ...form, actualCost: e.target.value }))} /></label>
          <label className="text-[10px] font-bold sm:col-span-2">Resumen del resultado<textarea maxLength={280} className="w-full mt-1 rounded-xl border px-3 py-2 bg-white min-h-20" value={outcomeForm.summary} placeholder="Qué se hizo y qué quedó comprobado" onChange={(e) => setOutcomeForm((form) => ({ ...form, summary: e.target.value }))} /></label>
        </div>
        {validateAgencyOutcome(outcomeForm, selected) && <div className="text-[10px] font-bold mt-2" style={{ color: "#A03B2A" }}>{validateAgencyOutcome(outcomeForm, selected)}</div>}
        <div className="mt-3"><BtnAsync disabled={Boolean(validateAgencyOutcome(outcomeForm, selected))} onClick={completeDecision}>Registrar resultado verificable</BtnAsync></div>
      </div>}
    </Modal>}
  </section>;
}

function AgencyCreativeFlightCenter({ db, go, refrescar }) {
  const center = useMemo(() => buildCreativeFlightCenter(db), [db]);
  const [showCompleted, setShowCompleted] = useState(false);
  const [relay, setRelay] = useState(null);
  const [relayForm, setRelayForm] = useState({ creativeId: "", postChoice: "__new__", fecha: hoyISO(), hora: "12:00", titulo: "", copyFinal: "" });
  const flights = showCompleted ? center.flights : center.active;

  function openNext(flight) {
    const step = creativeRelayStep(flight);
    if (["master", "publication"].includes(step)) {
      const creativeOptions = creativeCandidatesForFlight(flight, db);
      const postOptions = publicationCandidatesForFlight(flight, db);
      const draft = publicationDraftForFlight(flight, db, hoyISO());
      setRelay({ flight, step, creativeOptions, postOptions });
      setRelayForm({
        creativeId: creativeOptions[0]?.id || "",
        postChoice: postOptions[0]?.id || "__new__",
        fecha: draft.fecha, hora: draft.hora, titulo: draft.titulo, copyFinal: draft.copyFinal,
      });
      return;
    }
    if (["distribution", "observe"].includes(step) || flight.nextTarget === "agency-distribution-room") {
      window.sessionStorage.setItem("momos:calendar-view", "Distribución");
      go("Calendario");
      return;
    }
    document.getElementById(flight.nextTarget)?.scrollIntoView({ behavior: "smooth", block: "start" });
  }

  async function completeRelay() {
    if (!relay) return;
    try {
      if (relay.step === "master") {
        if (!relayForm.creativeId) throw new Error("Primero necesitás un creativo aprobado del producto, canal y modo exactos.");
        await prepararRelevoMasterCreativo(relay.flight.master.id, relayForm.creativeId);
        toast("ok", "Máster y creativo exactos enlazados. El archivo quedó sellado; todavía no se publicó.");
      } else {
        let postId = relayForm.postChoice;
        let created = false;
        if (postId === "__new__") {
          if (!relayForm.fecha || !relayForm.titulo.trim()) throw new Error("Completá fecha y título antes de programar.");
          const result = await crearPublicacion({
            fecha: relayForm.fecha, hora: relayForm.hora || "12:00",
            canal: relay.flight.release.lineageSnapshot?.channel || relay.flight.board?.channel,
            campaign_id: db.creatives.find((creative) => String(creative.id) === String(relay.flight.release.creativeId))?.campaignId || "",
            creative_id: relay.flight.release.creativeId, titulo: relayForm.titulo.trim(),
            copy_final: relayForm.copyFinal.trim(), estado: "Programado", url_publicacion: "",
            notas: "Preparada desde el relevo humano del vuelo creativo; sin publicación automática.",
          });
          postId = result.id;
          created = true;
        }
        try {
          await vincularPublicacionMaster(relay.flight.release.id, postId);
        } catch (error) {
          if (created) {
            toast("alert", `La publicación ${postId} quedó Programada, pero falta enlazarla. Reabrí el relevo para recuperarla sin duplicar.`);
            await refrescar();
            return;
          }
          throw error;
        }
        toast("ok", `${postId} quedó ligada al máster exacto y lista para revisión de Distribución.`);
      }
      setRelay(null);
      await refrescar();
    } catch (error) {
      toast("error", error.message || "No se pudo completar el relevo creativo.");
    }
  }

  function relayButtonLabel(flight) {
    const step = creativeRelayStep(flight);
    if (step === "master") return "Enlazar máster";
    if (step === "publication") return "Preparar publicación";
    if (step === "distribution") return "Abrir Distribución";
    if (step === "observe") return "Ver seguimiento";
    return flight.blocked ? "Revisar contrato" : "Abrir siguiente paso";
  }

  return <section id="agency-creative-flight" className="rounded-[26px] border overflow-hidden mb-6 shadow-sm" style={{ borderColor: T.border, background: T.surface }} aria-label="Contenido en curso">
    <div className="p-4 sm:p-5 flex flex-col lg:flex-row lg:items-center justify-between gap-4 border-b" style={{ borderColor: T.border, background: T.surface, color: T.choco }}>
      <div className="flex items-start gap-3">
        <div className="w-11 h-11 rounded-2xl grid place-items-center text-xl shrink-0" style={{ background: T.coralSoft }}>✦</div>
        <div><div className="text-[9px] font-extrabold uppercase tracking-[.18em]" style={{ color: T.coral }}>Contenido en curso</div><div className="display text-xl font-semibold">Del objetivo al resultado</div><div className="text-xs max-w-2xl" style={{ color: T.choco2 }}>Seguí cada contenido desde la idea hasta su resultado, con Pauta y Orgánico siempre separados.</div></div>
      </div>
      <div className="grid grid-cols-4 gap-2 shrink-0">
        {[["Activos",center.active.length],["Pauta",center.summary.pauta],["Orgánico",center.summary.organic],["Por revisar",center.summary.blocked]].map(([label,value]) => <div key={label} className="rounded-2xl border px-3 py-2 min-w-[66px] text-center" style={{ borderColor: T.border, background: T.vainilla }}><div className="display text-lg font-semibold">{value}</div><div className="text-[8px] uppercase font-extrabold" style={{ color: T.choco2 }}>{label}</div></div>)}
      </div>
    </div>
    {!db.agencyCreativeFlowReady && <div className="px-4 py-3 text-xs font-bold" style={{ background: "#FFF2D8", color: "#7A5410" }}>Aplicá <code>flujo-creativo-e2e-v1.sql</code> para sellar el relevo Máster → Creativo → Publicación → Distribución → Medición.</div>}
    <div className="p-3 sm:p-4">
      <div className="flex items-center justify-between gap-3 mb-3">
        <div className="text-[10px] font-extrabold uppercase tracking-[.14em]" style={{ color: T.choco2 }}>{showCompleted ? "Todo el contenido" : "Contenido que necesita avanzar"}</div>
        {center.completed.length > 0 && <button type="button" className="rounded-full border px-3 py-1.5 text-[10px] font-extrabold" style={{ borderColor: T.border, color: T.choco2, background: T.vainilla }} onClick={() => setShowCompleted((value) => !value)}>{showCompleted ? "Ocultar cerrados" : `Ver cerrados · ${center.completed.length}`}</button>}
      </div>
      {flights.length === 0 ? <div className="rounded-2xl px-4 py-4 text-sm" style={{ background: "#F8F0E7", color: T.choco2 }}><b style={{ color: T.choco }}>{center.flights.length ? "Todo el contenido completó su aprendizaje." : "Todavía no hay contenido aprobado para iniciar."}</b> El equipo conserva el control de cada paso.</div> : <div className="grid xl:grid-cols-2 gap-3">
        {flights.slice(0, 8).map((flight) => <article key={flight.contract.id} className="rounded-[22px] border p-4" style={{ borderColor: flight.blocked ? "#E8B7AD" : T.border, background: flight.blocked ? "#FFF6F3" : "#FFF9F2" }}>
          <div className="flex items-start justify-between gap-3">
            <div><div className="flex flex-wrap items-center gap-1.5"><span className="rounded-full px-2 py-1 text-[9px] font-extrabold" style={{ background: flight.mode === "Pauta" ? "#F6D4CD" : "#DDEBD9", color: flight.mode === "Pauta" ? "#A03B2A" : "#315B35" }}>{flight.mode}</span><span className="text-[9px] uppercase tracking-wider font-extrabold" style={{ color: T.choco2 }}>Contrato {flight.contract.id}</span></div><div className="display text-lg font-semibold mt-1">{flight.goal}</div><div className="text-[10px] font-semibold" style={{ color: T.choco2 }}>Métrica primaria: {flight.metric}</div></div>
            <div className="text-right shrink-0"><div className="display text-2xl font-semibold" style={{ color: flight.blocked ? "#A03B2A" : T.coral }}>{flight.progress}%</div><div className="text-[8px] uppercase font-extrabold" style={{ color: T.choco2 }}>{flight.completed}/10 pasos</div></div>
          </div>
          <div className="grid grid-cols-10 gap-1 mt-3" aria-label={`Progreso ${flight.progress}%`}>{flight.stages.map((item) => <div key={item.label} title={`${item.label}: ${item.detail}`} className="h-2 rounded-full" style={{ background: item.state === "done" ? "#5F8B61" : item.state === "current" ? T.coral : "#EADFD2" }} />)}</div>
          <div className="mt-3 flex flex-col sm:flex-row sm:items-center justify-between gap-2 border-t pt-3" style={{ borderColor: T.border }}>
            <div><div className="text-[9px] uppercase font-extrabold" style={{ color: flight.blocked ? "#A03B2A" : T.coral }}>{flight.blocked ? "Requiere corrección" : "Siguiente paso"}</div><div className="text-xs font-extrabold">{flight.currentStage}</div><div className="text-[10px]" style={{ color: T.choco2 }}>{flight.stages.find((item) => item.label === flight.currentStage)?.detail}</div></div>
            <Btn small kind={flight.blocked ? "ghost" : "primary"} onClick={() => openNext(flight)}>{relayButtonLabel(flight)}</Btn>
          </div>
        </article>)}
      </div>}
    </div>
    <div className="px-4 py-2.5 border-t text-[10px] font-semibold" style={{ borderColor: T.border, color: T.choco2 }}>Este centro solo orienta y verifica la cadena. No genera, publica, pauta ni gasta automáticamente.</div>
    {relay && <Modal title={relay.step === "master" ? "Enlazar el máster aprobado" : "Preparar la publicación exacta"} onClose={() => setRelay(null)} topLayer>
      <div className="rounded-2xl p-4 mb-4" style={{ background: "#F8F0E7", border: `1px solid ${T.border}` }}>
        <div className="text-[9px] uppercase tracking-wider font-extrabold" style={{ color: T.coral }}>{relay.flight.mode} · Contrato {relay.flight.contract.id}</div>
        <div className="display text-lg font-semibold mt-1">{relay.flight.goal}</div>
        <div className="text-xs mt-1" style={{ color: T.choco2 }}>Canal sellado: {relay.flight.board?.channel || relay.flight.release?.lineageSnapshot?.channel}. La acción conserva producto, marca y medición.</div>
      </div>
      {relay.step === "master" ? <>
        {relay.creativeOptions.length ? <label className="text-[10px] font-bold block">Creativo comercial aprobado
          <select className="w-full mt-1 rounded-xl border px-3 py-2.5 bg-white" value={relayForm.creativeId} onChange={(event) => setRelayForm((form) => ({ ...form, creativeId: event.target.value }))}>
            {relay.creativeOptions.map((creative) => <option key={creative.id} value={creative.id}>{creative.id} · {creative.titulo}</option>)}
          </select>
        </label> : <div className="rounded-xl px-3 py-3 text-xs font-bold" style={{ background: "#FFF2D8", color: "#7A5410" }}>No hay un creativo aprobado que coincida con producto, canal y modo. Creá una versión nueva y aprobala antes de continuar.</div>}
        <div className="rounded-xl px-3 py-3 my-4 text-xs" style={{ background: "#E8F1E4", color: "#315B35" }}>MOMOS OPS enlazará el archivo aprobado al creativo elegido. No lo publicará ni ejecutará pauta.</div>
        <div className="flex flex-wrap gap-2"><BtnAsync disabled={!relay.creativeOptions.length} onClick={completeRelay}>Enlazar máster exacto</BtnAsync>{!relay.creativeOptions.length && <Btn kind="ghost" onClick={() => { setRelay(null); go("Creativos"); }}>Abrir Creativos</Btn>}</div>
      </> : <>
        {relay.postOptions.length > 0 && <label className="text-[10px] font-bold block mb-3">Reutilizar una publicación compatible
          <select className="w-full mt-1 rounded-xl border px-3 py-2.5 bg-white" value={relayForm.postChoice} onChange={(event) => setRelayForm((form) => ({ ...form, postChoice: event.target.value }))}>
            {relay.postOptions.map((post) => <option key={post.id} value={post.id}>{post.id} · {post.fecha} {post.hora} · {post.titulo}</option>)}
            <option value="__new__">Crear una nueva programación</option>
          </select>
        </label>}
        {(relay.postOptions.length === 0 || relayForm.postChoice === "__new__") && <div className="grid sm:grid-cols-2 gap-3">
          <label className="text-[10px] font-bold">Fecha<input type="date" min={hoyISO()} className="w-full mt-1 rounded-xl border px-3 py-2 bg-white" value={relayForm.fecha} onChange={(event) => setRelayForm((form) => ({ ...form, fecha: event.target.value }))} /></label>
          <label className="text-[10px] font-bold">Hora<input type="time" className="w-full mt-1 rounded-xl border px-3 py-2 bg-white" value={relayForm.hora} onChange={(event) => setRelayForm((form) => ({ ...form, hora: event.target.value }))} /></label>
          <label className="text-[10px] font-bold sm:col-span-2">Título<input maxLength={180} className="w-full mt-1 rounded-xl border px-3 py-2 bg-white" value={relayForm.titulo} onChange={(event) => setRelayForm((form) => ({ ...form, titulo: event.target.value }))} /></label>
          <label className="text-[10px] font-bold sm:col-span-2">Copy final<textarea maxLength={2000} className="w-full mt-1 rounded-xl border px-3 py-2 bg-white min-h-24" value={relayForm.copyFinal} onChange={(event) => setRelayForm((form) => ({ ...form, copyFinal: event.target.value }))} /></label>
        </div>}
        <div className="rounded-xl px-3 py-3 my-4 text-xs" style={{ background: "#FFF2D8", color: "#7A5410" }}>Quedará en estado <b>Programado</b>. Distribución deberá revisar checklist, derechos y evidencia antes de cualquier salida externa.</div>
        <BtnAsync onClick={completeRelay}>Programar y enlazar</BtnAsync>
      </>}
    </Modal>}
  </section>;
}

function AgencyFriendlyHome({ guide, selectedGoal, onSelectGoal, onContinue, onAdvanced }) {
  const goal = FRIENDLY_AGENCY_GOALS.find((item) => item.id === selectedGoal) || FRIENDLY_AGENCY_GOALS[0];
  const recommendation = guide.recommendations[selectedGoal] || null;
  const activeContent = selectedGoal === "content" ? guide.activeFlight : null;
  const primaryLabel = selectedGoal === "content" && activeContent ? "Continuar contenido"
    : selectedGoal === "sales" ? "Preparar propuesta de venta"
      : selectedGoal === "customers" ? "Preparar activación"
        : selectedGoal === "results" ? "Ver análisis completo" : "Empezar contenido";

  return <div className="space-y-5">
    <section aria-label="Inicio guiado de Agencia MOMOS">
      <div className="mb-3"><h3 className="display text-lg font-semibold m-0">¿Qué quieres hacer hoy?</h3><p className="text-xs mt-0.5 mb-0" style={{ color: T.choco2 }}>Elegí un resultado. MOMOS organiza el trabajo y te pide solo las decisiones necesarias.</p></div>
      <div className="grid sm:grid-cols-2 xl:grid-cols-4 gap-3" role="tablist" aria-label="Objetivos de Agencia MOMOS">
        {FRIENDLY_AGENCY_GOALS.map((item) => { const active = item.id === selectedGoal; return <button key={item.id} type="button" role="tab" aria-selected={active} onClick={() => onSelectGoal(item.id)} className="text-left rounded-2xl border p-3.5 transition min-h-[104px]" style={{ borderColor: active ? "#E9A18F" : T.border, background: active ? "#FFF5F0" : T.surface, boxShadow: "0 2px 5px rgba(84,56,43,.08)" }}>
          <div className="flex items-start gap-3"><span className="w-8 h-8 rounded-xl grid place-items-center text-base shrink-0" style={{ background: active ? T.coralSoft : T.vainilla }}>{item.icon}</span><span className="min-w-0"><span className="block font-extrabold text-sm mb-1">{item.label}</span><span className="block text-[10px] leading-relaxed" style={{ color: T.choco2 }}>{item.description}</span></span></div>
        </button>; })}
      </div>
    </section>

    <section className="rounded-2xl border shadow-sm overflow-hidden" style={{ borderColor: activeContent ? "#E9A18F" : T.border, background: T.surface }} aria-label={`Recorrido ${goal.label}`}>
      <div className="p-4 sm:p-5 flex flex-col lg:flex-row lg:items-center justify-between gap-4">
        <div className="flex items-start gap-3 min-w-0"><span className="w-10 h-10 rounded-2xl grid place-items-center text-xl shrink-0" style={{ background: T.coralSoft }}>{goal.icon}</span><div className="min-w-0"><div className="flex flex-wrap items-center gap-2"><span className="text-[9px] uppercase tracking-[.16em] font-extrabold" style={{ color: T.coral }}>Agencia MOMOS</span><span className="rounded-full px-2 py-0.5 text-[8px] font-extrabold" style={{ background: activeContent ? "#DDEBD9" : T.vainilla, color: activeContent ? "#315B35" : T.choco2 }}>{activeContent ? "En curso" : "Lista para empezar"}</span></div><div className="display text-xl font-semibold mt-0.5">{goal.label}</div><div className="text-xs mt-1" style={{ color: T.choco2 }}>{activeContent ? `${activeContent.title} · ${activeContent.mode}` : recommendation?.title || goal.description}</div></div></div>
        <div className="grid grid-cols-3 gap-2 shrink-0">{[[activeContent ? `${activeContent.progress}%` : "—","Avance"],[activeContent ? activeContent.current.label : "1","Paso actual"],[activeContent ? activeContent.phases.length : "3","Pasos"]].map(([value,label]) => <div key={label} className="rounded-xl border px-3 py-2 text-center min-w-[72px]" style={{ borderColor: T.border, background: "#FFFDFC" }}><div className="display text-lg font-semibold">{value}</div><div className="text-[8px] uppercase font-extrabold" style={{ color: T.choco2 }}>{label}</div></div>)}</div>
      </div>

      {activeContent ? <div className="px-4 sm:px-5 pb-5">
        <div className="grid grid-cols-2 md:grid-cols-3 xl:grid-cols-6 gap-2 mb-3">{activeContent.phases.map((phase, index) => <div key={phase.id} className="rounded-xl border p-3" style={{ borderColor: phase.state === "current" ? "#E9A18F" : T.border, background: phase.state === "current" ? "#FFF5F0" : T.surface }}><div className="flex items-center gap-2 mb-1.5"><span className="w-5 h-5 rounded-full grid place-items-center text-[9px] font-extrabold" style={{ background: phase.state === "done" ? "#DDEBD9" : phase.state === "current" ? T.coral : T.vainilla, color: phase.state === "current" ? "#fff" : T.choco }}>{phase.state === "done" ? "✓" : index + 1}</span><span className="font-extrabold text-[11px]">{phase.label}</span></div><div className="text-[9px] leading-relaxed" style={{ color: T.choco2 }}>{phase.description}</div></div>)}</div>
        <div className="rounded-xl px-3.5 py-3 flex flex-col sm:flex-row sm:items-center justify-between gap-3" style={{ background: T.vainilla }}><div><div className="text-[9px] uppercase tracking-wider font-extrabold" style={{ color: T.coral }}>Lo siguiente</div><div className="font-extrabold text-sm">{activeContent.current.description}</div></div><Btn small onClick={onContinue}>{primaryLabel}</Btn></div>
      </div> : selectedGoal === "results" ? <div className="px-4 sm:px-5 pb-5"><div className="grid sm:grid-cols-3 gap-2 mb-3">{[["Publicaciones",guide.results.published],["Aprendizajes",guide.results.conclusive],["Ganadores",guide.results.winners]].map(([label,value]) => <div key={label} className="rounded-xl border px-3 py-2.5" style={{ borderColor: T.border, background: T.surface }}><div className="display text-xl font-semibold" style={{ color: T.coral }}>{value}</div><div className="text-[9px] font-extrabold" style={{ color: T.choco2 }}>{label}</div></div>)}</div><div className="rounded-xl px-3.5 py-3 flex flex-col sm:flex-row sm:items-center justify-between gap-3" style={{ background: T.vainilla }}><div><div className="font-extrabold text-sm">Todavía no hay una conclusión suficiente.</div><div className="text-[10px] mt-0.5" style={{ color: T.choco2 }}>Cuando exista muestra real, verás qué repetir y qué cambiar.</div></div><Btn small kind="ghost" onClick={onContinue}>{primaryLabel}</Btn></div></div>
        : <div className="px-4 sm:px-5 pb-5"><div className="grid md:grid-cols-3 gap-2 mb-3">{[["1","Contanos el objetivo","Elegís qué quieres lograr."],["2","MOMOS prepara","Cruza la información necesaria."],["3","Vos decidís","Revisás el resultado antes de usarlo."]].map(([number,title,description]) => <div key={number} className="rounded-xl border px-3 py-2.5 flex items-center gap-2.5" style={{ borderColor: T.border, background: T.surface }}><div className="w-6 h-6 rounded-full grid place-items-center text-[10px] font-extrabold shrink-0" style={{ background: number === "1" ? T.coralSoft : T.vainilla }}>{number}</div><div><div className="font-extrabold text-[11px]">{title}</div><div className="text-[9px]" style={{ color: T.choco2 }}>{description}</div></div></div>)}</div><div className="rounded-xl px-3.5 py-3 flex flex-col sm:flex-row sm:items-center justify-between gap-3" style={{ background: recommendation ? "#EDF5EA" : T.vainilla }}><div><div className="text-[9px] uppercase tracking-wider font-extrabold" style={{ color: recommendation ? "#315B35" : T.coral }}>{recommendation ? "Recomendación lista" : "Empecemos"}</div><div className="font-extrabold text-sm">{recommendation?.title || goal.description}</div>{recommendation?.rationale && <div className="text-[10px] mt-0.5 line-clamp-1" style={{ color: T.choco2 }}>{recommendation.rationale}</div>}</div><Btn small onClick={onContinue}>{primaryLabel}</Btn></div></div>}
    </section>

    <div className="flex justify-end"><button type="button" onClick={onAdvanced} className="rounded-full border px-3 py-1.5 text-[9px] font-extrabold" style={{ borderColor: T.border, background: T.surface, color: T.choco2 }}>Ver controles avanzados</button></div>
  </div>;
}

function AgenciaControl({ db, user, refrescar, go }) {
  const serverReady = Boolean(db.agencyServerReady);
  const settings = db.agencySettings || DEFAULT_AGENCY_SETTINGS;
  const intelligence = useMemo(() => buildAgencyIntelligence(db, settings, hoyISO()), [db, settings]);
  const learning = useMemo(() => buildCommercialLearning(db, hoyISO()), [db]);
  const orchestrator = useMemo(() => buildOrchestratorInbox(db), [db]);
  const [briefSource, setBriefSource] = useState(null);
  const [settingsOpen, setSettingsOpen] = useState(false);
  const [creativeOpen, setCreativeOpen] = useState(false);
  const [opportunityFilter, setOpportunityFilter] = useState("Todas");
  const [expandedOpportunity, setExpandedOpportunity] = useState(null);
  const [creativePackageBrief, setCreativePackageBrief] = useState(null);
  const [creativePackageVariant, setCreativePackageVariant] = useState(0);
  const [agencyView, setAgencyView] = useState("simple");
  const [selectedGoal, setSelectedGoal] = useState("content");
  const [advancedArea, setAdvancedArea] = useState("overview");
  const [settingsForm, setSettingsForm] = useState(settings);
  const [briefForm, setBriefForm] = useState({ title: "", objective: "Ventas", channel: "Instagram", offer: "", crmSegment: "", proposedBudget: 0, notes: "" });
  const [creativeForm, setCreativeForm] = useState({ creativeId: "", briefId: "", prompt: "", negativePrompt: "", assetUrl: "" });
  const existingKeys = new Set((db.agencyBriefs || []).map((brief) => brief.decisionKey).filter(Boolean));
  const orchestratedKeys = new Set((db.agencyAgentProposals || []).map((proposal) => proposal.proposalKey));
  const opportunityPillars = ["Todas", ...new Set(intelligence.recommendations.map((item) => item.pillar))];
  const visibleRecommendations = opportunityFilter === "Todas"
    ? intelligence.recommendations
    : intelligence.recommendations.filter((item) => item.pillar === opportunityFilter);
  const creativePackageDraft = useMemo(() => creativePackageBrief
    ? buildCreativePackage(creativePackageBrief, db, creativePackageVariant)
    : null, [creativePackageBrief, creativePackageVariant, db]);
  const creativePackageSaved = creativePackageBrief
    ? (db.agencyCreativeVersions || []).some((version) => String(version.briefId) === String(creativePackageBrief.id))
    : false;
  const friendlyGuide = useMemo(() => buildFriendlyAgencyGuide(db, intelligence, learning), [db, intelligence, learning]);

  function showAdvanced(target = "") {
    const creativeTargets = new Set(["agency-collaboration-desk", "agency-retention-lab", "agency-scene-studio", "agency-motion-experience", "agency-scene-router", "agency-quality-control", "agency-approval-center"]);
    const protectionTargets = new Set(["agency-action-center"]);
    setAdvancedArea(creativeTargets.has(target) ? "creative" : protectionTargets.has(target) ? "protection" : "overview");
    setAgencyView("advanced");
    if (target) window.setTimeout(() => document.getElementById(target)?.scrollIntoView({ behavior: "smooth", block: "start" }), 100);
  }

  function manualGoalSource(goalId) {
    if (goalId === "sales") return { id: `manual-sales-${Date.now()}`, type: "Impulsar producto", risk: "Bajo", title: "Nueva propuesta para vender más", rationale: "Elegiremos producto, mensaje y canal usando ventas y stock vigentes.", evidence: {} };
    if (goalId === "customers") return { id: `manual-crm-${Date.now()}`, type: "Contactar segmento", risk: "Bajo", title: "Nueva activación de clientes", rationale: "Definiremos el segmento y solo incluiremos clientes con permiso de contacto.", evidence: {}, crmSegment: "Clientes con permiso" };
    return { id: `manual-content-${Date.now()}`, type: "Crear contenido", risk: "Bajo", title: "Nuevo contenido MOMOS", rationale: "Definiremos producto, objetivo y canal antes de preparar la pieza.", evidence: {}, channel: "Instagram" };
  }

  function continueFriendlyGoal() {
    if (selectedGoal === "content" && friendlyGuide.activeFlight) { showAdvanced(friendlyGuide.activeFlight.current.target); return; }
    if (selectedGoal === "results") { showAdvanced(); return; }
    openBrief(friendlyGuide.recommendations[selectedGoal] || manualGoalSource(selectedGoal));
  }

  function openBrief(recommendation = null) {
    const source = recommendation || {
      id: `manual-${Date.now()}`, type: "Crear contenido", risk: "Bajo",
      title: "Nueva oportunidad comercial", rationale: "Brief iniciado manualmente por el equipo.", evidence: {},
    };
    setBriefSource(source);
    setBriefForm({
      title: source.title,
      objective: source.type === "Contactar segmento" ? "Recompra"
        : source.type === "Activar cumpleaños" ? "Cumpleaños"
          : ["Crear contenido", "Repetir creativo"].includes(source.type) ? "Contenido" : "Ventas",
      channel: source.channel || (source.type === "Contactar segmento" ? "WhatsApp" : "Instagram"),
      offer: source.suggestedOffer || "", crmSegment: source.crmSegment || "",
      proposedBudget: source.proposedBudget || 0, notes: source.rationale,
    });
  }

  async function saveBrief() {
    if (!serverReady) throw new Error("Aplicá primero la migración 16 de Agencia Comercial.");
    const created = await crearBriefAgencia({
      decision_key: briefSource.id, title: briefForm.title, objective: briefForm.objective,
      campaign_id: briefSource.campaignId || null, product_id: briefSource.productId || null,
      crm_segment: briefForm.crmSegment, offer: briefForm.offer, channel: briefForm.channel,
      deliverables: ["Crear contenido", "Repetir creativo", "Impulsar producto", "Mover inventario"].includes(briefSource.type)
        ? ["Pieza principal", "Adaptación para historias"] : [],
      insight: briefSource.rationale, evidence: briefSource.evidence || {}, proposed_budget: Number(briefForm.proposedBudget || 0), notes: briefForm.notes,
    });
    await crearDecisionAgencia({
      brief_id: created.brief_id, campaign_id: briefSource.campaignId || null, creative_id: briefSource.creativeId || null,
      type: agencyDecisionType(briefSource.type), title: briefSource.title, rationale: briefSource.rationale,
      evidence: briefSource.evidence || {}, risk_level: briefSource.risk, author: "reglas",
      proposed_action: {
        product_id: briefSource.productId || null, creative_id: briefSource.creativeId || null,
        proposed_budget: Number(briefForm.proposedBudget || 0), customer_ids: briefSource.customerIds || [],
      },
    });
    setBriefSource(null);
    toast("ok", "Brief y decisión guardados con trazabilidad");
    await refrescar();
  }

  async function saveSettings() {
    await guardarConfiguracionAgencia({
      autonomy_mode: settingsForm.autonomyMode, daily_budget_limit: Number(settingsForm.dailyBudgetLimit),
      campaign_budget_limit: Number(settingsForm.campaignBudgetLimit), scale_step_pct: Number(settingsForm.scaleStepPct),
      require_creative_approval: settingsForm.requireCreativeApproval, block_out_of_stock: settingsForm.blockOutOfStock,
      contact_only_authorized: settingsForm.contactOnlyAuthorized, paused: settingsForm.paused,
    });
    setSettingsOpen(false); toast("ok", "Guardas comerciales actualizadas"); await refrescar();
  }

  async function advanceBrief(brief) {
    const next = { "Borrador": "En revisión", "En revisión": "Aprobado", "Aprobado": "En producción", "En producción": "Completado" }[brief.status];
    if (!next) return;
    await setEstadoBriefAgencia(brief.id, next, `${next} desde Agencia MOMOS`);
    toast("ok", `Brief #${brief.id}: ${next}`); await refrescar();
  }

  async function advanceDecision(decision) {
    if (decision.status === "Propuesta") {
      await resolverDecisionAgencia(decision.id, "Aprobada", "Aprobación humana desde Agencia MOMOS");
      toast("ok", `Decisión #${decision.id} aprobada`); await refrescar(); return;
    }
    throw new Error("Las decisiones aprobadas se cierran con evidencia desde la Bandeja de acciones de Agencia.");
  }

  async function sendToOrchestrator(recommendation) {
    if (!db.agencyOrchestratorReady) throw new Error("Aplicá la migración 28 del Orquestador de Agencia.");
    await registrarRecomendacionOrquestador(orchestratorProposalPayload(recommendation));
    toast("ok", "Propuesta sellada en el Cerebro de Agencia; todavía no ejecutó ninguna acción.");
    await refrescar();
  }

  async function resolveOrchestratorProposal(proposal, decision) {
    let note = "Aprobación humana desde Agencia MOMOS";
    if (decision === "Descartar") {
      note = window.prompt("¿Por qué descartamos esta propuesta?", "No corresponde al momento comercial actual") || "";
      if (!note) return;
    }
    await resolverPropuestaOrquestador(proposal.id, decision, note);
    toast("ok", decision === "Aprobar" ? "Propuesta convertida en decisión aprobada; aún no se ejecutó." : "Propuesta descartada con trazabilidad.");
    await refrescar();
  }

  function openCreativeVersion() {
    const creative = (db.creatives || []).find((item) => !["Publicado","Ganador"].includes(item.estado)) || (db.creatives || [])[0];
    const tone = (db.brand_library?.tono || []).join(", ");
    setCreativeForm({
      creativeId: creative?.id || "", briefId: "",
      prompt: creative ? `Crear ${creative.formato} para ${creative.productoFoco || creative.titulo}. Hook: ${creative.hook || "momento MOMOS"}. Tono de marca: ${tone || "tierno, premium y cercano"}.` : "",
      negativePrompt: (db.brand_library?.palabrasNo || []).join(", "), assetUrl: creative?.assetUrl || "",
    });
    setCreativeOpen(true);
  }

  async function saveCreativeVersion() {
    if (!creativeForm.creativeId) throw new Error("Elegí el creativo que vas a versionar.");
    await crearVersionCreativaAgencia({
      creative_id: creativeForm.creativeId, brief_id: creativeForm.briefId || null,
      provider: "manual", prompt: creativeForm.prompt, negative_prompt: creativeForm.negativePrompt,
      asset_url: creativeForm.assetUrl, thumbnail_url: creativeForm.assetUrl, generation_cost: 0,
    });
    setCreativeOpen(false); toast("ok", "Versión creativa guardada con la marca usada como evidencia"); await refrescar();
  }

  function openCreativePackage(brief) {
    setCreativePackageVariant(0);
    setCreativePackageBrief(brief);
  }

  async function saveCreativePackage() {
    const brief = creativePackageBrief; const draft = creativePackageDraft;
    if (!brief || !draft) return;
    if (!["Aprobado", "En producción"].includes(brief.status)) {
      toast("alert", "El paquete puede revisarse, pero solo se guarda cuando el brief tenga aprobación humana."); return;
    }
    if (!draft.audit.passed) {
      toast("error", draft.audit.errors[0] || "El paquete no pasó el control de marca."); return;
    }
    const marker = `[AGENCY_BRIEF:${brief.id}]`;
    const existingVersion = (db.agencyCreativeVersions || []).find((version) => String(version.briefId) === String(brief.id));
    let creativeId = existingVersion?.creativeId || (db.creatives || []).find((creative) => String(creative.notas || "").includes(marker))?.id || "";
    try {
      if (!creativeId) {
        const created = await crearCreativo({
          campaign_id: draft.campaignId || null, titulo: draft.title, canal: draft.channel, formato: draft.format,
          producto_foco_id: draft.productId || null, figura: null, sabor: null, hook: draft.selectedHook,
          copy: draft.copy, guion: draft.script.join("\n"), estado: "Idea", responsable: "Marketing",
          fecha_entrega: dISO(3), asset_url: "", notas: `${marker} Borrador generado desde Agencia MOMOS; requiere revisión humana.`,
        });
        creativeId = created.id;
      }
      if (!existingVersion) {
        await crearVersionCreativaAgencia({
          creative_id: creativeId, brief_id: brief.id, provider: "momos-ops-rules",
          prompt: draft.prompt, negative_prompt: draft.negativePrompt, brand_snapshot: draft.brandSnapshot,
          asset_url: "", thumbnail_url: "", generation_cost: 0,
        });
      }
      setCreativePackageBrief(null);
      toast("ok", `Paquete guardado como creativo ${creativeId}; continúa en Idea hasta revisión humana.`);
      await refrescar();
    } catch (error) {
      toast("error", creativeId
        ? `El creativo ${creativeId} quedó guardado, pero falta completar su versión trazable. Reintentá: ${error.message}`
        : error.message);
      try { await refrescar(); } catch { /* conserva la recuperación por marcador al recargar */ }
    }
  }

  async function reviewCreativeVersion(version, status) {
    await revisarVersionCreativaAgencia(version.id, status, status === "Aprobada" ? "Aprobación humana en Agencia MOMOS" : "Lista para revisión humana");
    toast("ok", `Versión ${version.version}: ${status}`); await refrescar();
  }

  const money = (value) => fmt(Math.round(Number(value || 0)));
  const riskStyle = (risk) => risk === "Alto" ? { bg: "#F6D4CD", fg: "#A03B2A" } : risk === "Medio" ? { bg: "#FBE8C8", fg: "#96690F" } : { bg: "#DDEBD9", fg: "#3F6B42" };
  const learningStyle = (stage) => ({
    winner: { bg: "#DDEBD9", fg: "#315B35", border: "#B8D3B2" },
    funnel: { bg: "#FBE8C8", fg: "#8B5A08", border: "#EACB92" },
    spend: { bg: "#F6D4CD", fg: "#A03B2A", border: "#E6B7AE" },
    ambiguous: { bg: "#FFF2D8", fg: "#7A5410", border: "#E8C98B" },
    collecting: { bg: "#E5EEF7", fg: "#315A7D", border: "#C7D8E8" },
    promising: { bg: "#E9E4F4", fg: "#5C4C7D", border: "#D4C9E7" },
    missing: { bg: "#F5E9D8", fg: T.choco2, border: T.border },
    inconclusive: { bg: "#F3EEE8", fg: T.choco2, border: T.border },
  }[stage] || { bg: "#F3EEE8", fg: T.choco2, border: T.border });
  const pillarIcon = { Inventario: "📦", Pauta: "📣", CRM: "💗", Producto: "🍨", Contenido: "🎨", Marca: "✦", General: "◎" };
  const evidenceValue = (value) => {
    if (Array.isArray(value)) return `${value.length} registro(s)`;
    if (value && typeof value === "object") return JSON.stringify(value).slice(0, 120);
    if (typeof value === "number") return Number.isInteger(value) ? String(value) : value.toFixed(2);
    return String(value ?? "—");
  };
  const pipelineSteps = [
    ["Oportunidades", intelligence.pipeline.opportunities, "Detectadas"],
    ["Briefs", intelligence.pipeline.briefs, "En curso"],
    ["Aprobaciones", intelligence.pipeline.approvals, "Humanas"],
    ["Creativo", intelligence.pipeline.creativeReview, "En revisión"],
    ["Programado", intelligence.pipeline.scheduled, "Próx. 7 días"],
    ["Aprendizaje", learning.summary.conclusive, "Lecturas concluyentes"],
  ];
  const advancedAreas = [
    { id: "overview", icon: "⌂", label: "Resumen", description: "Qué está avanzando", count: friendlyGuide.activeFlightCount },
    { id: "strategy", icon: "✦", label: "Oportunidades", description: "Qué conviene hacer", count: intelligence.recommendations.length },
    { id: "creative", icon: "🎨", label: "Crear", description: "Del guion al archivo", count: intelligence.pipeline.briefs },
    { id: "results", icon: "📊", label: "Resultados", description: "Qué funcionó", count: learning.summary.conclusive },
    { id: "protection", icon: "✓", label: "Revisión", description: "Aprobar y proteger", count: intelligence.pipeline.approvals },
  ];
  const advancedAreaCopy = {
    overview: ["Estado general", "Revisá el trabajo en curso y abrí únicamente el siguiente paso."],
    strategy: ["Decidir qué hacer", "MOMO OPS reúne oportunidades y alternativas para que el equipo elija."],
    creative: ["Construir contenido", "Guion, escenas, movimiento y calidad organizados como una sola ruta."],
    results: ["Aprender y mejorar", "Ventas, publicaciones y pauta convertidas en decisiones comprensibles."],
    protection: ["Aprobar con seguridad", "Acciones, permisos y límites que siempre requieren una persona."],
  };
  const activeAdvancedArea = advancedAreas.find((item) => item.id === advancedArea) || advancedAreas[0];

  return (
    <section className="mb-6" aria-label="Agencia Comercial MOMOS">
      <div className="rounded-2xl overflow-hidden border shadow-sm" style={{ borderColor: T.border, background: T.surface }}>
        <div className="p-4 sm:p-5 flex flex-col lg:flex-row lg:items-center justify-between gap-4 border-b" style={{ borderColor: T.border, background: T.surface }}>
          <div className="flex items-start gap-3 min-w-0"><span className="w-10 h-10 rounded-2xl grid place-items-center text-lg shrink-0" style={{ background: T.coralSoft }}>✦</span><div><div className="flex flex-wrap items-center gap-2"><span className="text-[9px] font-extrabold tracking-[.18em] uppercase" style={{ color: T.coral }}>MOMO OPS Intelligence</span><span className="rounded-full px-2 py-0.5 text-[8px] font-extrabold" style={{ background: settings.paused ? "#F6D4CD" : "#DDEBD9", color: settings.paused ? "#A03B2A" : "#315B35" }}>{settings.paused ? "Pausada" : "Protegida"}</span></div><h2 className="display text-xl font-semibold mt-0.5 mb-0">Tu agencia comercial</h2><p className="text-xs mt-1 mb-0 max-w-2xl" style={{ color: T.choco2 }}>Elegí qué quieres lograr. MOMOS prepara una propuesta y vos aprobás el resultado.</p></div></div>
          <div className="grid grid-cols-3 gap-2 shrink-0">{[["✓","Marca"],["✓","Revisión"],["✓","Datos reales"]].map(([value,label]) => <div key={label} className="rounded-xl border px-3 py-2 text-center min-w-[72px]" style={{ borderColor: T.border, background: "#FFFDFC" }}><div className="display text-lg font-semibold" style={{ color: "#3F6B42" }}>{value}</div><div className="text-[8px] uppercase font-extrabold" style={{ color: T.choco2 }}>{label}</div></div>)}</div>
        </div>

        <div className="p-4 sm:p-5">
          {!serverReady && <div className="rounded-2xl px-4 py-3 mb-4 text-sm font-bold" style={{ background: "#FFF2D8", color: "#7A5410" }}>Vista inteligente activa · aplicá <code>agencia-comercial-v1.sql</code> para guardar briefs, aprobaciones y decisiones en el servidor.</div>}

          {agencyView === "simple" ? <AgencyFriendlyHome guide={friendlyGuide} selectedGoal={selectedGoal} onSelectGoal={setSelectedGoal} onContinue={continueFriendlyGoal} onAdvanced={() => showAdvanced()} /> : <>
          <div className="sticky top-2 z-20 rounded-2xl border p-3 mb-4 shadow-sm" style={{ borderColor: T.border, background: "rgba(255,253,250,.97)", backdropFilter: "blur(10px)" }}>
            <div className="flex items-center justify-between gap-3 mb-3"><div><div className="text-[9px] uppercase tracking-wider font-extrabold" style={{ color: T.coral }}>Centro de Agencia MOMOS</div><div className="text-xs font-bold">Elegí el área que quieres revisar</div></div><Btn small kind="ghost" onClick={() => { setAgencyView("simple"); window.scrollTo({ top: 0, behavior: "smooth" }); }}>← Inicio sencillo</Btn></div>
            <div className="grid grid-cols-2 md:grid-cols-5 gap-2" role="tablist" aria-label="Áreas del Centro de Agencia MOMOS">{advancedAreas.map((area) => { const active = area.id === advancedArea; return <button key={area.id} type="button" role="tab" aria-selected={active} onClick={() => setAdvancedArea(area.id)} className="rounded-xl border px-3 py-2.5 text-left transition" style={{ borderColor: active ? "#E9A18F" : T.border, background: active ? "#FFF5F0" : T.surface }}><div className="flex items-center justify-between gap-2"><span className="text-sm">{area.icon}</span><span className="rounded-full min-w-5 h-5 px-1 grid place-items-center text-[8px] font-extrabold" style={{ background: active ? T.coralSoft : T.vainilla }}>{area.count}</span></div><div className="text-[11px] font-extrabold mt-1">{area.label}</div><div className="text-[8px]" style={{ color: T.choco2 }}>{area.description}</div></button>; })}</div>
          </div>

          <div className="rounded-2xl border px-4 py-3 mb-4 flex items-start gap-3" style={{ borderColor: T.border, background: T.vainilla }}><span className="w-8 h-8 rounded-xl grid place-items-center shrink-0" style={{ background: T.surface }}>{activeAdvancedArea.icon}</span><div><div className="display text-base font-semibold">{advancedAreaCopy[advancedArea][0]}</div><div className="text-[10px] mt-0.5" style={{ color: T.choco2 }}>{advancedAreaCopy[advancedArea][1]}</div></div></div>

          {advancedArea === "overview" && <><div className="rounded-2xl border p-4 mb-5" style={{ borderColor: T.border, background: T.surface }}>
            <div className="flex flex-wrap items-end justify-between gap-2 mb-3">
              <div><div className="text-[10px] font-extrabold tracking-[.14em] uppercase" style={{ color: T.coral }}>Recorrido comercial</div><div className="display text-lg font-semibold">Cómo avanza el trabajo</div></div>
              <div className="text-[11px]" style={{ color: T.choco2 }}>Cada número abre una decisión del equipo.</div>
            </div>
            <div className="grid grid-cols-2 md:grid-cols-3 xl:grid-cols-6 gap-2">
              {pipelineSteps.map(([label, value, sub], index) => <div key={label} className="relative rounded-2xl border px-3 py-3" style={{ borderColor: T.border, background: index === 0 ? "#FFF" : "rgba(255,255,255,.64)" }}>
                <div className="text-[9px] font-extrabold uppercase tracking-wider" style={{ color: T.choco2 }}>{String(index + 1).padStart(2, "0")} · {label}</div>
                <div className="display text-2xl font-semibold" style={{ color: index === 0 ? T.coral : T.choco }}>{value}</div>
                <div className="text-[10px] font-semibold" style={{ color: T.choco2 }}>{sub}</div>
              </div>)}
            </div>
          </div>

          <AgencyCreativeFlightCenter db={db} go={go} refrescar={refrescar} />
          </>}
          {advancedArea === "protection" && <><AgencyActionCenter db={db} go={go} refrescar={refrescar} /><AgencyMetaAuthorizationPanel db={db} refrescar={refrescar} /></>}
          {advancedArea === "results" && <><AgencyMetaObservatory db={db} refrescar={refrescar} /><AgencyMetaIncrementality db={db} refrescar={refrescar} /></>}
          {advancedArea === "strategy" && <AgencyMetaInvestmentScenarios db={db} refrescar={refrescar} />}
          {advancedArea === "creative" && <>
            <div id="agency-collaboration-desk" className="scroll-mt-24"><AgencyCollaborationDesk db={db} refrescar={refrescar} /></div>
            <div id="agency-retention-lab" className="scroll-mt-24"><AgencyRetentionLab db={db} refrescar={refrescar} /></div>
            <AgencyLoopLearningDesk db={db} refrescar={refrescar} />
            <div id="agency-scene-studio" className="scroll-mt-24"><AgencySceneStudio db={db} refrescar={refrescar} /></div>
            <div id="agency-motion-experience" className="scroll-mt-24"><AgencyMotionExperience db={db} refrescar={refrescar} /></div>
            <div id="agency-scene-router" className="scroll-mt-24"><AgencySceneRouter db={db} refrescar={refrescar} /></div>
            <div id="agency-quality-control" className="scroll-mt-24"><AgencyQualityControl db={db} refrescar={refrescar} /></div>
          </>}

          {advancedArea === "strategy" && <><div className="rounded-[26px] border overflow-hidden mb-6 shadow-sm" style={{ borderColor: "#D7C5B2", background: "#FFFDFC" }}>
            <div className="p-4 sm:p-5 flex flex-col lg:flex-row lg:items-center justify-between gap-4" style={{ background: "linear-gradient(135deg,#4A3028,#704334)", color: "#fff" }}>
              <div className="flex items-start gap-3">
                <div className="w-11 h-11 rounded-2xl grid place-items-center text-xl shrink-0" style={{ background: "rgba(255,255,255,.14)" }}>🧠</div>
                <div><div className="text-[9px] font-extrabold uppercase tracking-[.18em] opacity-75">Orquestador protegido · MCP</div><div className="display text-xl font-semibold">Cerebro de Agencia MOMOS</div><div className="text-xs opacity-80 max-w-2xl">Recibe señales y propuestas de agentes, declara qué herramientas necesita y sella evidencia, confianza y costo. Nunca publica ni gasta por sí solo.</div></div>
              </div>
              <div className="grid grid-cols-3 gap-2 shrink-0">
                {[["Pendientes",orchestrator.summary.pending],["Externas",orchestrator.summary.externalActions],["Costo máx.",money(orchestrator.summary.estimatedCost)]].map(([label,value]) => <div key={label} className="rounded-2xl px-3 py-2 min-w-[76px] text-center" style={{ background: "rgba(255,255,255,.12)" }}><div className="display text-lg font-semibold">{value}</div><div className="text-[8px] uppercase font-extrabold opacity-70">{label}</div></div>)}
              </div>
            </div>
            {!db.agencyOrchestratorReady ? <div className="px-4 py-3 text-xs font-bold" style={{ background: "#FFF2D8", color: "#7A5410" }}>Aplicá <code>orquestador-agencia-v1.sql</code> para habilitar la bandeja gobernada y el contrato para MCP.</div> : orchestrator.pending.length === 0 ? <div className="px-4 py-4 text-sm" style={{ color: T.choco2 }}><b style={{ color: T.choco }}>Bandeja al día.</b> Enviá una oportunidad del radar o conectá un agente MCP para recibir propuestas trazables.</div> : <div className="p-3 grid lg:grid-cols-2 gap-2">
              {orchestrator.pending.slice(0, 4).map((proposal) => <article key={proposal.id} className="rounded-2xl border p-3" style={{ borderColor: T.border, background: "#FFF9F2" }}>
                <div className="flex items-start justify-between gap-2"><div><div className="text-[9px] uppercase tracking-wider font-extrabold" style={{ color: T.coral }}>{proposal.decisionType} · riesgo {proposal.riskLevel}</div><div className="font-extrabold text-sm">{proposal.title}</div></div><span className="rounded-full px-2 py-1 text-[9px] font-extrabold shrink-0" style={{ background: "#E5EEF7", color: "#315A7D" }}>{Math.round(proposal.confidence * 100)}% confianza</span></div>
                <p className="text-[11px] leading-relaxed my-2" style={{ color: T.choco2 }}>{proposal.rationale}</p>
                <div className="flex flex-wrap gap-1 mb-2">{proposal.requiredTools.map((tool) => <span key={tool} className="rounded-full px-2 py-1 text-[9px] font-bold" style={{ background: T.vainilla }}>{tool}</span>)}</div>
                <div className="rounded-xl px-2.5 py-2 mb-2 text-[10px]" style={{ background: "#F5E9D8" }}><b>{proposal.executionMode}</b> · costo máximo {money(proposal.costCapCop)} · huella {proposal.fingerprint.slice(0, 8)}</div>
                <div className="flex flex-wrap gap-2"><BtnAsync small onClick={() => resolveOrchestratorProposal(proposal, "Aprobar")}>Aprobar propuesta</BtnAsync><BtnAsync small kind="ghost" onClick={() => resolveOrchestratorProposal(proposal, "Descartar")}>Descartar</BtnAsync></div>
              </article>)}
            </div>}
            <div className="px-4 py-2.5 border-t text-[10px] font-semibold" style={{ borderColor: T.border, color: T.choco2 }}>Aprobar crea una decisión comercial aprobada, no una ejecución. Pauta, publicación, contacto y gasto conservan su confirmación y sus guardas.</div>
          </div>

          <div className="flex flex-wrap items-center justify-between gap-3 mb-3">
            <div><div className="text-[10px] font-extrabold tracking-[.14em] uppercase" style={{ color: T.coral }}>Radar de oportunidades</div><div className="display text-xl font-semibold">Qué conviene hacer ahora</div><div className="text-sm" style={{ color: T.choco2 }}>Cruza pedidos pagados, stock, CRM, contenido y pauta; cada recomendación explica su evidencia.</div></div>
            <div className="flex gap-2"><Btn kind="soft" small onClick={() => openBrief()}>＋ Brief manual</Btn>{user === "Administrador" && <Btn kind="ghost" small onClick={() => { setSettingsForm(settings); setSettingsOpen(true); }}>⚙ Guardas</Btn>}</div>
          </div>
          <div className="flex gap-2 overflow-x-auto pb-2 mb-3" role="tablist" aria-label="Filtrar oportunidades por área">
            {opportunityPillars.map((pillar) => {
              const active = opportunityFilter === pillar;
              const count = pillar === "Todas" ? intelligence.recommendations.length : intelligence.recommendations.filter((item) => item.pillar === pillar).length;
              return <button key={pillar} type="button" role="tab" aria-selected={active} onClick={() => setOpportunityFilter(pillar)} className="shrink-0 rounded-full border px-3 py-2 text-[11px] font-extrabold transition"
                style={{ borderColor: active ? T.coral : T.border, background: active ? T.coral : "#fff", color: active ? "#fff" : T.choco }}>
                {pillar === "Todas" ? "◎" : pillarIcon[pillar] || "◎"} {pillar} <span className="ml-1 opacity-75">{count}</span>
              </button>;
            })}
          </div>
          <div className="grid lg:grid-cols-2 gap-3">
            {visibleRecommendations.slice(0, 8).map((item) => {
              const guard = item.guard; const risk = riskStyle(item.risk); const created = existingKeys.has(item.id);
              const expanded = expandedOpportunity === item.id;
              return <article key={item.id} className="rounded-3xl border p-4 sm:p-5 flex flex-col shadow-sm" style={{ borderColor: guard.allowed ? T.border : "#E6B7AE", background: guard.allowed ? "linear-gradient(145deg,#FFF,#FFF8F2)" : "#FFF5F2" }}>
                <div className="flex items-start justify-between gap-3">
                  <div className="flex items-center gap-2"><span className="w-9 h-9 shrink-0 rounded-2xl grid place-items-center text-base" style={{ background: T.vainilla }}>{pillarIcon[item.pillar] || "◎"}</span><div><div className="text-[9px] uppercase tracking-[.14em] font-extrabold" style={{ color: T.choco2 }}>{item.pillar}</div><div className="text-[11px] uppercase tracking-wider font-extrabold" style={{ color: T.coral }}>{item.type}</div></div></div>
                  <div className="flex flex-wrap justify-end gap-1"><span className="px-2 py-1 rounded-full text-[9px] font-extrabold" style={{ background: T.vainilla, color: T.choco }}>Prioridad {item.priority}</span><span className="px-2 py-1 rounded-full text-[9px] font-extrabold" style={{ background: risk.bg, color: risk.fg }}>Riesgo {item.risk}</span></div>
                </div>
                <h3 className="display text-lg font-semibold mt-3 mb-1">{item.title}</h3>
                <p className="text-xs leading-relaxed mb-3" style={{ color: T.choco2 }}>{item.rationale}</p>
                <div className="flex flex-wrap gap-1.5 mb-3">{item.signals.map((itemSignal) => <span key={itemSignal} className="rounded-full px-2.5 py-1 text-[10px] font-bold" style={{ background: "#F5E9D8", color: T.choco }}>{itemSignal}</span>)}</div>
                <div className="rounded-2xl px-3 py-2.5 mb-3" style={{ background: "#F8EFE4", borderLeft: `3px solid ${T.coral}` }}><div className="text-[9px] uppercase tracking-wider font-extrabold" style={{ color: T.coral }}>Siguiente paso</div><div className="text-[11px] leading-relaxed font-semibold" style={{ color: T.choco }}>{item.nextStep}</div></div>
                <button type="button" className="self-start border-0 bg-transparent p-0 mb-3 text-[11px] font-extrabold underline" style={{ color: T.choco2 }} onClick={() => setExpandedOpportunity(expanded ? null : item.id)} aria-expanded={expanded}>{expanded ? "Ocultar evidencia" : "Ver evidencia y confianza"}</button>
                {expanded && <div className="rounded-2xl p-3 mb-3 text-[11px]" style={{ background: "#fff", border: `1px dashed ${T.border}` }}>
                  <div className="font-extrabold mb-2" style={{ color: T.choco }}>Confianza {item.confidence} · fuente interna de MOMO OPS</div>
                  <div className="grid sm:grid-cols-2 gap-1.5">{Object.entries(item.evidence || {}).map(([key, value]) => <div key={key} className="flex justify-between gap-2"><span style={{ color: T.choco2 }}>{key}</span><b className="text-right break-all">{evidenceValue(value)}</b></div>)}</div>
                </div>}
                <div className="mt-auto">
                  <div className="rounded-xl px-3 py-2 text-[11px] mb-3" style={{ background: guard.allowed ? "#E8F1E4" : "#F6D4CD", color: guard.allowed ? "#3F6B42" : "#A03B2A" }}>
                    {guard.allowed ? "✓ Pasa las guardas; requiere aprobación según el modo." : `⛔ ${guard.reasons[0]}`}
                  </div>
                  <div className="flex flex-wrap gap-2">
                    <BtnAsync small disabled={orchestratedKeys.has(`momos:${item.id}`) || !db.agencyOrchestratorReady || !guard.allowed} onClick={() => sendToOrchestrator(item)}>{orchestratedKeys.has(`momos:${item.id}`) ? "En el cerebro ✓" : "Enviar al cerebro"}</BtnAsync>
                    <Btn small kind="ghost" disabled={created || !serverReady || !guard.allowed} onClick={() => openBrief(item)}>{created ? "Brief creado ✓" : guard.allowed ? "Crear brief directo" : "Bloqueada por guardas"}</Btn>
                  </div>
                </div>
              </article>;
            })}
          </div>
          {visibleRecommendations.length === 0 && <Empty icon="✦" text="No hay oportunidades en este frente hoy. El radar seguirá cruzando operación, clientes y campañas." />}
          </>}

          {advancedArea === "results" && <><div className="mt-2 mb-3 flex flex-col sm:flex-row sm:items-end sm:justify-between gap-3">
            <div>
              <div className="text-[10px] font-extrabold tracking-[.14em] uppercase" style={{ color: T.coral }}>Sala de aprendizaje</div>
              <div className="display text-xl font-semibold">Qué aprendimos de lo publicado</div>
              <div className="text-sm max-w-3xl" style={{ color: T.choco2 }}>Cruza la publicación exacta, métricas de plataforma, gasto y pedidos pagados. Si la atribución es dudosa, MOMO OPS espera y no inventa un ganador.</div>
            </div>
            <span className="self-start sm:self-auto rounded-full px-3 py-2 text-[10px] font-extrabold uppercase tracking-wider" style={{ background: T.vainilla, color: T.choco }}>Decisiones con evidencia</span>
          </div>
          <div className="grid grid-cols-2 lg:grid-cols-5 gap-2 mb-4">
            {[
              ["Publicadas", learning.summary.published],
              ["Sin métricas", learning.summary.missingMetrics],
              ["Conclusiones", learning.summary.conclusive],
              ["Ganadoras", learning.summary.winners],
              ["Atribución pendiente", learning.summary.ambiguousAttribution],
            ].map(([label, value]) => <div key={label} className="rounded-2xl border px-3 py-3" style={{ borderColor: T.border, background: "#FFF9F1" }}>
              <div className="text-[9px] uppercase tracking-wider font-extrabold" style={{ color: T.choco2 }}>{label}</div>
              <div className="display text-2xl font-semibold" style={{ color: T.coral }}>{value}</div>
            </div>)}
          </div>
          {learning.items.length > 0 ? <div className="grid lg:grid-cols-2 gap-3 mb-6">
            {learning.items.slice(0, 6).map((item) => {
              const stageStyle = learningStyle(item.stage.key);
              const recommendation = item.recommendation;
              const guard = recommendation ? guardAgencyAction({ ...recommendation, today: hoyISO(), execute: false }, db, settings) : null;
              const created = recommendation ? existingKeys.has(recommendation.id) : false;
              return <article key={item.post.id} className="rounded-3xl border p-4 flex flex-col shadow-sm" style={{ borderColor: stageStyle.border, background: "linear-gradient(145deg,#FFF,#FFF9F2)" }}>
                <div className="flex items-start justify-between gap-3">
                  <div>
                    <div className="text-[9px] uppercase tracking-[.14em] font-extrabold" style={{ color: T.coral }}>{item.post.canal || "Canal"} · {item.post.fecha} · {item.post.id}</div>
                    <h3 className="display text-lg font-semibold mt-1 mb-0">{item.creative?.titulo || item.post.titulo || "Publicación MOMOS"}</h3>
                  </div>
                  <span className="shrink-0 rounded-full px-2.5 py-1 text-[9px] font-extrabold uppercase" style={{ background: stageStyle.bg, color: stageStyle.fg }}>{item.stage.label}</span>
                </div>
                <div className="grid grid-cols-2 sm:grid-cols-4 gap-2 my-3">
                  {[
                    ["Pedidos", item.metrics.orders],
                    ["Ventas", money(item.metrics.revenue)],
                    ["Gasto", money(item.metrics.spend)],
                    ["ROAS", item.metrics.roas == null ? "Orgánico / —" : `${item.metrics.roas.toFixed(1)}×`],
                  ].map(([label, value]) => <div key={label} className="rounded-xl px-2.5 py-2" style={{ background: "#F8EFE4" }}><div className="text-[8px] uppercase font-extrabold" style={{ color: T.choco2 }}>{label}</div><div className="text-xs font-extrabold">{value}</div></div>)}
                </div>
                <p className="text-xs leading-relaxed mb-2" style={{ color: T.choco2 }}>{item.stage.insight}</p>
                <div className="rounded-2xl px-3 py-2.5 mb-3" style={{ background: stageStyle.bg, color: stageStyle.fg }}><div className="text-[9px] uppercase tracking-wider font-extrabold">Siguiente paso</div><div className="text-[11px] leading-relaxed font-semibold">{item.stage.nextStep}</div></div>
                {item.attribution.ambiguous > 0 && <div className="text-[10px] font-bold mb-3" style={{ color: "#7A5410" }}>Hay {item.attribution.ambiguous} pedido(s) sin publicación exacta. No se usaron para decidir.</div>}
                {recommendation && <div className="mt-auto flex flex-wrap items-center justify-between gap-2">
                  <div className="text-[10px] font-bold" style={{ color: guard?.allowed ? "#3F6B42" : "#A03B2A" }}>{guard?.allowed ? "✓ Aprendizaje listo para brief humano" : `Protegido: ${guard?.reasons?.[0] || "requiere revisión"}`}</div>
                  <Btn small kind={created ? "ghost" : "primary"} disabled={created || !serverReady || !guard?.allowed} onClick={() => openBrief(recommendation)}>{created ? "Brief creado ✓" : "Convertir aprendizaje en brief"}</Btn>
                </div>}
              </article>;
            })}
          </div> : <div className="mb-6"><Empty icon="◎" text="Cuando una publicación salga al aire, aparecerá aquí para medirla sin mezclar sus pedidos con otras piezas." /></div>}

          </>}

          {advancedArea === "creative" && <><AgencyBrandStudio db={db} user={user} refrescar={refrescar} />

          {(db.agencyBriefs || []).length > 0 && <>
            <SectionTitle>Flujo de briefs</SectionTitle>
            <div className="grid md:grid-cols-2 gap-3">
              {(db.agencyBriefs || []).slice(0, 4).map((brief) => <div key={brief.id} className="rounded-2xl border p-4" style={{ borderColor: T.border, background: "#fff" }}>
                <div className="flex justify-between gap-2"><div><div className="text-[10px] font-extrabold uppercase" style={{ color: T.coral }}>BRIEF #{brief.id} · {brief.objective}</div><div className="display font-semibold">{brief.title}</div></div><Badge label={brief.status} /></div>
                <div className="text-xs mt-2" style={{ color: T.choco2 }}>{brief.channel} · presupuesto {money(brief.proposedBudget)}{brief.stockSnapshot !== null ? ` · stock foto ${brief.stockSnapshot}` : ""}</div>
                {["Borrador","En revisión","Aprobado","En producción"].includes(brief.status) && <div className="mt-3 flex flex-wrap gap-2">
                  <Btn kind="ghost" small onClick={() => openCreativePackage(brief)}>✦ Preparar paquete</Btn>
                  <BtnAsync small kind={brief.status === "En revisión" ? "primary" : "soft"} onClick={() => advanceBrief(brief)}>{({ "Borrador": "Enviar a revisión", "En revisión": "Aprobar brief", "Aprobado": "Iniciar producción", "En producción": "Marcar completado" })[brief.status]}</BtnAsync>
                </div>}
              </div>)}
            </div>
          </>}

          {(db.agencyDecisions || []).some((decision) => decision.status === "Propuesta") && <div id="agency-approval-center" className="scroll-mt-24">
            <SectionTitle>Decisiones por aprobar</SectionTitle>
            <div className="space-y-2">{(db.agencyDecisions || []).filter((decision) => decision.status === "Propuesta").slice(0, 5).map((decision) => <div key={decision.id} className="rounded-2xl border p-3 flex flex-col sm:flex-row sm:items-center gap-3" style={{ borderColor: T.border }}>
              <div className="flex-1"><div className="text-[10px] font-extrabold uppercase" style={{ color: T.coral }}>{decision.type} · riesgo {decision.riskLevel}</div><div className="font-bold text-sm">{decision.title}</div><div className="text-xs" style={{ color: T.choco2 }}>{decision.rationale}</div></div>
              <BtnAsync small onClick={() => advanceDecision(decision)}>Aprobar decisión</BtnAsync>
            </div>)}</div>
          </div>}

          {(db.creatives || []).length > 0 && <>
            <SectionTitle action={<Btn small kind="soft" disabled={!serverReady} onClick={openCreativeVersion}>＋ Nueva versión</Btn>}>Estudio creativo versionado</SectionTitle>
            <div className="rounded-2xl border overflow-hidden" style={{ borderColor: T.border }}>
              <div className="px-4 py-3 text-xs" style={{ background: T.vainilla, color: T.choco2 }}><b style={{ color: T.choco }}>Marca congelada por versión.</b> Cada pieza conserva prompt, palabras prohibidas, archivo, costo y aprobación. El generador externo podrá conectarse después sin perder control.</div>
              {(db.agencyCreativeVersions || []).length === 0 ? <div className="p-4 text-sm" style={{ color: T.choco2 }}>Todavía no hay versiones. Creá la primera sobre uno de los creativos existentes.</div> :
                (db.agencyCreativeVersions || []).slice(0, 5).map((version) => {
                  const creative = (db.creatives || []).find((item) => item.id === version.creativeId);
                  return <div key={version.id} className="p-4 border-t flex flex-col sm:flex-row sm:items-center gap-3" style={{ borderColor: T.border }}>
                    {version.thumbnailUrl ? <img src={version.thumbnailUrl} alt="" className="w-14 h-14 rounded-xl object-cover border" style={{ borderColor: T.border }} /> : <div className="w-14 h-14 rounded-xl flex items-center justify-center text-xl" style={{ background: T.rosa }}>✦</div>}
                    <div className="flex-1 min-w-0"><div className="text-[10px] uppercase tracking-wider font-extrabold" style={{ color: T.coral }}>{creative?.titulo || version.creativeId} · V{version.version}</div><div className="text-sm font-bold truncate">{version.prompt || "Versión sin prompt"}</div><div className="text-xs" style={{ color: T.choco2 }}>{version.provider} · {version.status}</div></div>
                    {version.status === "Borrador" && <BtnAsync small kind="soft" onClick={() => reviewCreativeVersion(version, "En revisión")}>Enviar a revisión</BtnAsync>}
                    {version.status === "En revisión" && <BtnAsync small disabled={!version.assetUrl} onClick={() => reviewCreativeVersion(version, "Aprobada")}>Aprobar archivo</BtnAsync>}
                  </div>;
                })}
            </div>
          </>}
          </>}
          </>}
        </div>
      </div>

      {briefSource && <Modal title="Nuevo brief comercial" onClose={() => setBriefSource(null)}>
        <div className="rounded-2xl p-3 mb-4 text-xs" style={{ background: T.vainilla }}><b>Por qué ahora:</b> {briefSource.rationale}</div>
        <Field label="Nombre del brief"><Input value={briefForm.title} onChange={(e) => setBriefForm({ ...briefForm, title: e.target.value })} /></Field>
        <div className="grid sm:grid-cols-2 gap-3"><Field label="Objetivo"><Select value={briefForm.objective} onChange={(e) => setBriefForm({ ...briefForm, objective: e.target.value })} options={["Ventas","Recompra","Lanzamiento","Cumpleaños","Tráfico WhatsApp","Branding","Contenido","Otro"]} /></Field><Field label="Canal"><Select value={briefForm.channel} onChange={(e) => setBriefForm({ ...briefForm, channel: e.target.value })} options={["Instagram","Facebook","TikTok","WhatsApp","Rappi","Referidos","Influencer","Orgánico","Multicanal"]} /></Field></div>
        <Field label="Segmento CRM"><Input value={briefForm.crmSegment} placeholder="Ej. clientes inactivos con permiso" onChange={(e) => setBriefForm({ ...briefForm, crmSegment: e.target.value })} /></Field>
        <Field label="Oferta o mensaje central"><Input value={briefForm.offer} placeholder="Qué queremos que entienda o haga la persona" onChange={(e) => setBriefForm({ ...briefForm, offer: e.target.value })} /></Field>
        <Field label="Presupuesto propuesto"><Input type="number" min="0" value={briefForm.proposedBudget} onChange={(e) => setBriefForm({ ...briefForm, proposedBudget: e.target.value })} /></Field>
        <Field label="Notas"><textarea className={inputCls} style={inputStyle} rows="3" value={briefForm.notes} onChange={(e) => setBriefForm({ ...briefForm, notes: e.target.value })} /></Field>
        <div className="flex gap-2"><BtnAsync onClick={saveBrief}>Guardar brief trazable</BtnAsync><Btn kind="ghost" onClick={() => setBriefSource(null)}>Cancelar</Btn></div>
      </Modal>}

      {creativePackageBrief && creativePackageDraft && <Modal title="Paquete creativo MOMOS" onClose={() => setCreativePackageBrief(null)} wide>
        <div className="rounded-3xl p-4 mb-4" style={{ background: "linear-gradient(135deg,#4A3028,#8C4E3B)", color: "#fff" }}>
          <div className="text-[9px] uppercase tracking-[.18em] font-extrabold opacity-70">Brief #{creativePackageBrief.id} · {creativePackageBrief.status}</div>
          <div className="display text-xl font-semibold mt-1">{creativePackageDraft.title}</div>
          <div className="text-xs opacity-80 mt-1">{creativePackageDraft.channel} · {creativePackageDraft.format} · {creativePackageDraft.objective}</div>
        </div>

        {!creativePackageDraft.audit.passed && <div className="rounded-2xl px-4 py-3 mb-3 text-xs font-bold" style={{ background: "#F6D4CD", color: "#A03B2A" }} role="alert">⛔ {creativePackageDraft.audit.errors.join(" · ")}</div>}
        {creativePackageDraft.audit.warnings.length > 0 && <div className="rounded-2xl px-4 py-3 mb-3 text-xs font-bold" style={{ background: "#FFF2D8", color: "#7A5410" }}>⚠ {creativePackageDraft.audit.warnings.join(" · ")}</div>}
        {!["Aprobado","En producción"].includes(creativePackageBrief.status) && <div className="rounded-2xl px-4 py-3 mb-4 text-xs font-bold" style={{ background: "#EAF0F7", color: "#3E5C7E" }}>Podés revisar y copiar este borrador. Para guardarlo en Creativos, primero el brief debe quedar Aprobado.</div>}

        <div className="grid md:grid-cols-3 gap-2 mb-4">
          {[["Producto",creativePackageDraft.productName],["Canal",creativePackageDraft.channel],["KPI principal",creativePackageDraft.measurement.primaryKpi]].map(([label,value]) => <div key={label} className="rounded-2xl border p-3" style={{ borderColor: T.border, background: T.soft }}><div className="text-[9px] uppercase tracking-wider font-extrabold" style={{ color: T.choco2 }}>{label}</div><div className="text-sm font-bold">{value}</div></div>)}
        </div>

        <Field label="Elegí el hook que detiene el scroll">
          <div className="grid gap-2">{creativePackageDraft.hooks.map((hook, index) => <button key={hook} type="button" onClick={() => setCreativePackageVariant(index)} className="text-left rounded-2xl border px-3 py-3 text-sm font-bold" style={{ borderColor: creativePackageDraft.hookIndex === index ? T.coral : T.border, background: creativePackageDraft.hookIndex === index ? T.coralSoft : "#fff", color: T.choco }}><span className="text-[9px] uppercase tracking-wider mr-2" style={{ color: T.coral }}>Opción {String.fromCharCode(65 + index)}</span>{hook}</button>)}</div>
        </Field>

        <div className="grid lg:grid-cols-2 gap-3 mt-4">
          <div className="rounded-2xl border p-4" style={{ borderColor: T.border }}>
            <div className="flex items-center justify-between gap-2 mb-2"><div className="text-[10px] uppercase tracking-wider font-extrabold" style={{ color: T.coral }}>Copy listo para revisar</div><CopyBtn texto={creativePackageDraft.copy} label="Copiar copy" /></div>
            <div className="text-sm whitespace-pre-line leading-relaxed">{creativePackageDraft.copy}</div>
          </div>
          <div className="rounded-2xl border p-4" style={{ borderColor: T.border }}>
            <div className="text-[10px] uppercase tracking-wider font-extrabold mb-2" style={{ color: T.coral }}>Guion de producción</div>
            <ol className="m-0 pl-5 text-sm space-y-2">{creativePackageDraft.script.map((line) => <li key={line}>{line}</li>)}</ol>
          </div>
        </div>

        <div className="rounded-2xl p-4 mt-3" style={{ background: T.vainilla }}>
          <div className="text-[10px] uppercase tracking-wider font-extrabold mb-2" style={{ color: T.coral }}>Dirección visual para generar o producir</div>
          <div className="text-xs leading-relaxed mb-2">{creativePackageDraft.prompt}</div>
          <div className="text-[11px]" style={{ color: T.choco2 }}><b>Evitar:</b> {creativePackageDraft.negativePrompt}</div>
        </div>

        <div className="rounded-2xl border p-4 mt-3 mb-4" style={{ borderColor: T.border }}>
          <div className="text-[10px] uppercase tracking-wider font-extrabold" style={{ color: T.coral }}>Cómo sabremos si funcionó</div>
          <div className="text-sm font-bold mt-1">{creativePackageDraft.measurement.primaryKpi}</div>
          <div className="text-xs mt-1" style={{ color: T.choco2 }}>{creativePackageDraft.measurement.secondaryKpi} · {creativePackageDraft.measurement.attribution}</div>
        </div>

        <div className="flex flex-wrap gap-2">
          <BtnAsync onClick={saveCreativePackage} disabled={creativePackageSaved || !creativePackageDraft.audit.passed || !["Aprobado","En producción"].includes(creativePackageBrief.status)} textoEnVuelo="Guardando paquete…">{creativePackageSaved ? "Paquete ya guardado ✓" : "Guardar como creativo en Idea"}</BtnAsync>
          <CopyBtn texto={[creativePackageDraft.selectedHook, creativePackageDraft.copy, ...creativePackageDraft.script, creativePackageDraft.prompt].join("\n\n")} label="Copiar paquete" />
          <Btn kind="ghost" onClick={() => setCreativePackageBrief(null)}>Cerrar</Btn>
        </div>
      </Modal>}

      {settingsOpen && <Modal title="Guardas de Agencia MOMOS" onClose={() => setSettingsOpen(false)}>
        <Field label="Modo de autonomía"><Select value={settingsForm.autonomyMode} onChange={(e) => setSettingsForm({ ...settingsForm, autonomyMode: e.target.value })} options={["Asesor","Copiloto","Autopiloto protegido"]} /></Field>
        <div className="grid sm:grid-cols-2 gap-3"><Field label="Límite diario"><Input type="number" min="0" value={settingsForm.dailyBudgetLimit} onChange={(e) => setSettingsForm({ ...settingsForm, dailyBudgetLimit: e.target.value })} /></Field><Field label="Límite por campaña"><Input type="number" min="0" value={settingsForm.campaignBudgetLimit} onChange={(e) => setSettingsForm({ ...settingsForm, campaignBudgetLimit: e.target.value })} /></Field></div>
        <Field label="Escalamiento máximo por paso (%)"><Input type="number" min="0" max="30" value={settingsForm.scaleStepPct} onChange={(e) => setSettingsForm({ ...settingsForm, scaleStepPct: e.target.value })} /></Field>
        {[["requireCreativeApproval","Exigir aprobación humana del creativo"],["blockOutOfStock","Bloquear pauta sin stock"],["contactOnlyAuthorized","Contactar solo clientes autorizados"],["paused","Parada de emergencia comercial"]].map(([key,label]) => <label key={key} className="flex items-center gap-2 py-2 text-sm font-bold"><input type="checkbox" checked={Boolean(settingsForm[key])} onChange={(e) => setSettingsForm({ ...settingsForm, [key]: e.target.checked })} />{label}</label>)}
        <div className="flex gap-2 mt-4"><BtnAsync onClick={saveSettings}>Guardar guardas</BtnAsync><Btn kind="ghost" onClick={() => setSettingsOpen(false)}>Cancelar</Btn></div>
      </Modal>}

      {creativeOpen && <Modal title="Nueva versión creativa" onClose={() => setCreativeOpen(false)} wide>
        <div className="rounded-2xl px-4 py-3 mb-4 text-xs" style={{ background: T.vainilla }}><b>Control de marca:</b> esta versión guardará una fotografía del tono y vocabulario vigente. Crear la versión no la aprueba ni la publica.</div>
        <Field label="Creativo base"><select className={inputCls} style={inputStyle} value={creativeForm.creativeId} onChange={(e) => setCreativeForm({ ...creativeForm, creativeId: e.target.value })}><option value="">Elegir creativo…</option>{(db.creatives || []).map((creative) => <option key={creative.id} value={creative.id}>{creative.titulo} · {creative.formato}</option>)}</select></Field>
        <Field label="Brief relacionado (opcional)"><select className={inputCls} style={inputStyle} value={creativeForm.briefId} onChange={(e) => setCreativeForm({ ...creativeForm, briefId: e.target.value })}><option value="">Sin brief</option>{(db.agencyBriefs || []).filter((brief) => !["Descartado","Completado"].includes(brief.status)).map((brief) => <option key={brief.id} value={brief.id}>#{brief.id} · {brief.title}</option>)}</select></Field>
        <Field label="Prompt maestro"><textarea className={inputCls} style={inputStyle} rows="4" value={creativeForm.prompt} onChange={(e) => setCreativeForm({ ...creativeForm, prompt: e.target.value })} /></Field>
        <Field label="Evitar"><Input value={creativeForm.negativePrompt} onChange={(e) => setCreativeForm({ ...creativeForm, negativePrompt: e.target.value })} /></Field>
        <Field label="URL del archivo o borrador (opcional)"><Input value={creativeForm.assetUrl} placeholder="Se puede agregar cuando el archivo esté listo" onChange={(e) => setCreativeForm({ ...creativeForm, assetUrl: e.target.value })} /></Field>
        <div className="flex gap-2"><BtnAsync onClick={saveCreativeVersion}>Guardar versión</BtnAsync><Btn kind="ghost" onClick={() => setCreativeOpen(false)}>Cancelar</Btn></div>
      </Modal>}
    </section>
  );
}

function Crecimiento({ db, update, user, go, refrescar }) {
  const [seccion, setSeccion] = useState("inicio");

  const TARJETAS = [
    { id: "publicar", icon: "📱", titulo: "Qué publicar hoy", desc: "Contenido listo para subir ahora" },
    { id: "grabar", icon: "🎬", titulo: "Qué grabar hoy", desc: "Guiones paso a paso para Reels" },
    { id: "escribir", icon: "💬", titulo: "A qué clientes escribirles", desc: "Con el mensaje ya escrito" },
    { id: "promo", icon: "🎁", titulo: "Qué promoción activar", desc: "Beneficios y campañas" },
    { id: "funciono", icon: "🏆", titulo: "Qué contenido funcionó mejor", desc: "Lo que más vendió" },
    { id: "pausar", icon: "⏸️", titulo: "Qué campaña pausar", desc: "Lo que no está rindiendo" },
    { id: "repetir", icon: "🔁", titulo: "Qué idea repetir", desc: "Ideas ganadoras para reusar" },
    { id: "tareas", icon: "✅", titulo: "Tareas pendientes de redes", desc: "Tu lista del día" },
  ];

  // secciones adicionales de biblioteca
  const EXTRA = [
    { id: "ideas", icon: "💡", titulo: "Ideas listas", desc: "Biblioteca de ideas aprobadas" },
    { id: "guiones", icon: "🎬", titulo: "Guiones fáciles", desc: "Paso a paso para grabar" },
    { id: "mensajes", icon: "💬", titulo: "Mensajes de WhatsApp", desc: "Plantillas listas" },
    { id: "campanas", icon: "🎯", titulo: "Campañas simples", desc: "Objetivos claros" },
    { id: "marca", icon: "🎨", titulo: "Biblioteca de marca", desc: "Frases, tono y palabras" },
    { id: "resultados", icon: "📊", titulo: "Resultados fáciles", desc: "Explicados en simple" },
  ];

  if (seccion !== "inicio") {
    return (
      <div>
        <button onClick={() => setSeccion("inicio")} className="text-sm font-bold mb-4 flex items-center gap-1" style={{ color: T.coral }}>← Volver a Crecimiento MOMOS</button>
        {seccion === "publicar" && <QuePublicar db={db} update={update} refrescar={refrescar} />}
        {seccion === "grabar" && <Guiones db={db} />}
        {seccion === "guiones" && <Guiones db={db} />}
        {seccion === "escribir" && <AQuienEscribir db={db} go={go} refrescar={refrescar} />}
        {seccion === "mensajes" && <MensajesWhatsApp db={db} customer={null} />}
        {seccion === "promo" && <QuePromo db={db} go={go} />}
        {seccion === "campanas" && <CampanasSimples db={db} update={update} user={user} refrescar={refrescar} />}
        {seccion === "funciono" && <QueFunciono db={db} />}
        {seccion === "pausar" && <QuePausar db={db} update={update} user={user} refrescar={refrescar} />}
        {seccion === "repetir" && <IdeasListas db={db} update={update} user={user} refrescar={refrescar} soloRepetir />}
        {seccion === "ideas" && <IdeasListas db={db} update={update} user={user} refrescar={refrescar} />}
        {seccion === "marca" && <BibliotecaMarca db={db} />}
        {seccion === "resultados" && <ResultadosFaciles db={db} update={update} user={user} refrescar={refrescar} />}
        {seccion === "tareas" && <TareasRedes db={db} update={update} user={user} refrescar={refrescar} />}
      </div>
    );
  }

  return <AgenciaControl db={db} user={user} refrescar={refrescar} go={go} />;
}

/* --- Qué publicar hoy: recomendación del día --- */
function QuePublicar({ db, update, refrescar }) {
  const hoy = hoyISO();
  const pubHoy = (db.content_calendar || []).filter((p) => p.fecha === hoy);
  // recomendación: ideas ganadoras/repetir primero, luego nuevas
  const recomendadas = [...(db.marketing_ideas || [])].sort((a, b) => {
    const rank = { "Ganadora": 0, "Repetir": 1, "Nueva": 2, "Usada": 3, "Descartada": 4 };
    return (rank[a.estado] ?? 5) - (rank[b.estado] ?? 5);
  }).slice(0, 3);

  async function programar(idea) {
    let res;
    try {
      res = await crearPublicacion({
        fecha: hoy, hora: "12:00", canal: idea.canal, titulo: idea.titulo,
        copy_final: idea.copy, estado: "Programado", notas: "Desde Crecimiento MOMOS",
      });
    } catch (e) { toast("error", e.message); return; }
    if (idea.estado === "Nueva") {
      if (db.agencyServerReady) await setIdeaMarketingEstado(idea.id, "Usada");
      else update((d) => { const x = d.marketing_ideas.find((y) => y.id === idea.id); if (x) x.estado = "Usada"; });
    }
    toast("ok", `Publicación ${res.id} programada`);
    try { await refrescar(); } catch { toast("error", "Programada; recargá para verla"); }
  }

  return (
    <div>
      <h2 className="display text-lg font-semibold mb-1">📱 Qué publicar hoy</h2>
      <p className="text-sm mb-4" style={{ color: T.choco2 }}>Esto es lo que te recomendamos subir hoy. Ya viene con el texto listo: solo copia y pega.</p>

      {pubHoy.length > 0 && (
        <>
          <div className="text-xs font-bold mb-2" style={{ color: T.choco2 }}>YA PROGRAMADO PARA HOY</div>
          {pubHoy.map((p) => (
            <Card key={p.id} className="p-4 mb-2">
              <div className="flex justify-between items-start gap-2">
                <div><div className="font-bold text-sm">{p.titulo}</div><div className="text-xs" style={{ color: T.choco2 }}>{p.hora} · {p.canal}</div></div>
                <Badge label={p.estado} />
              </div>
              {p.copyFinal && <div className="text-sm mt-2 p-2.5 rounded-xl" style={{ background: T.vainilla }}>{p.copyFinal}</div>}
              {p.copyFinal && <div className="mt-2"><CopyBtn texto={p.copyFinal} /></div>}
            </Card>
          ))}
        </>
      )}

      <div className="text-xs font-bold mb-2 mt-4" style={{ color: T.choco2 }}>IDEAS RECOMENDADAS PARA HOY</div>
      {recomendadas.map((idea) => (
        <Card key={idea.id} className="p-4 mb-2">
          <div className="flex justify-between items-start gap-2">
            <div className="min-w-0">
              <div className="font-bold text-sm">{idea.titulo}</div>
              <div className="text-xs mt-0.5" style={{ color: T.choco2 }}>{idea.cat} · {idea.canal} · para {idea.objetivo}</div>
            </div>
            <Badge label={idea.estado} />
          </div>
          <div className="text-sm mt-2 p-2.5 rounded-xl" style={{ background: T.vainilla }}>{idea.copy}</div>
          {idea.guionCorto && <div className="text-xs mt-2" style={{ color: T.choco2 }}>🎬 Cómo grabarlo: {idea.guionCorto}</div>}
          <div className="flex gap-2 mt-3 flex-wrap">
            <CopyBtn texto={idea.copy} />
            <BtnAsync small kind="soft" onClick={() => programar(idea)} textoEnVuelo="Programando…">📅 Programar para hoy</BtnAsync>
          </div>
        </Card>
      ))}
    </div>
  );
}

